window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["th"]={"ICON-0001":{"nm":"รอยเท้า","de":"รอยสีดินหนึ่งรอยที่ทิ้งไว้บนพื้นไม้ มีใครสักคนเดินวนอยู่นานสองนาน ก่อนจะก้าวออกไปอีกก้าวหนึ่งในที่สุด สิ่งที่รอยเท้าจารึกไว้ไม่ใช่เวลาที่เคยอยู่ แต่คือช่วงเวลานั้นที่ตัดสินใจจะจากไป"},"ICON-0002":{"nm":"โคมไฟ","de":"เมื่อเปลวไฟแตะไส้ตะเกียง ความมืดก็ค่อยๆ ถอยห่างไปทีละนิด ว่ากันว่าคนโบราณเคยเขียนคำอธิษฐานแล้วปล่อยลอยไปพร้อมไออุ่นเล็กๆ ที่ผิงปลายนิ้ว โคมไฟไม่ได้จุดขึ้นเพื่อให้แสงสว่าง แต่จุดขึ้นเพื่ออยู่เคียงข้างกันต่างหาก"},"ICON-0003":{"nm":"ริบบิ้น","de":"ปมเดียวห่อหุ้มหัวใจไว้อย่างงดงาม มือที่ส่งมอบผูกให้แก้ง่าย ส่วนมือที่รับกลับอยากจะแก้ช้าๆ สิ่งที่ริบบิ้นผูกไว้ไม่ใช่กล่อง แต่คือความตื่นเต้นที่สั่นระริกอยู่ก่อนจะยื่นให้กันนั่นเอง"},"ICON-0004":{"nm":"ตู้จดหมาย","de":"มันยืนอ้าปากสีแดงอยู่ตรงปากซอย แม้ในยุคที่จดหมายลายมือหายากเต็มที กล่องเล็กๆ ใบนี้ก็ยังคงรอคอยข่าวคราวของใครสักคนไปจนถึงที่สุด ภาชนะแสนอ่อนโยนที่จะเปล่งประกายที่สุดในวินาทีที่มันว่างเปล่า"},"ICON-0005":{"nm":"มินิแมปเกาะส่วนตัว","de":"พับแล้วใส่กระเป๋าได้พอดี คลี่ออกก็เห็นทะเลกับสันเขาทอดตัวเคียงกันอยู่บนกระดาษแผ่นเดียว สำหรับผู้ที่เพิ่งมาถึงเป็นครั้งแรก ทุกมุมยังเป็นคำสัญญาที่ยังไม่เคยเปิดดู ในวินาทีที่คลี่ออก แม้เกาะเล็กๆ ก็กลายเป็นโลกกว้างใหญ่"},"ICON-0006":{"nm":"ไมโครโฟน","de":"ครึ่งจังหวะก่อนเปล่งเสียงแรก คือช่วงเวลาที่ค่อยๆ ปรับลมหายใจให้เรียบ พอรู้ว่าสายตาของผู้ชมกำลังรอคำพูดของเรา ปลายนิ้วก็สั่นขึ้นมาโดยไม่รู้ตัว ไมโครโฟนไม่ได้มีไว้ขยายเสียง แต่มีไว้พาความสั่นไหวนั้นไปจนสุดทาง"},"ICON-0007":{"nm":"นาฬิกา","de":"เข็มวินาทีไม่เคยหยุดพัก แต่ก็ไม่มีใครมาเร่งรัดเธอเลย อีกกี่คืนกว่าจะเดบิวต์ อีกกี่นาทีกว่าจะขึ้นเวที บนหน้าปัดนั้น การรอคอยกับความตื่นเต้นหมุนไปด้วยความเร็วเดียวกัน การดูเวลาจึงเป็นเหมือนการปลอบโยนหัวใจ"},"ICON-0008":{"nm":"สมุดโน้ต","de":"สิ่งของที่มีช่องว่างมากที่สุด ทั้งเส้นทางการเต้น คำมั่นสัญญายามเช้ามืด และคำพูดที่ไม่เคยได้ส่งออกไป ล้วนถูกสะสมไว้ที่นี่ ในวินาทีที่เปิดออก ตัวเราของเมื่อวานก็ค่อยๆ ทักทายตัวเราของวันนี้อย่างเงียบๆ"},"ICON-0009":{"nm":"ตราประทับ","de":"จุ่มหมึกแดงแล้วกดลงไปแรงๆ เพียงครั้งเดียว คำสัญญาก็ถูกสลักไว้อย่างชัดเจน เป็นรอยที่หนักแน่นกว่าตัวอักษรและแจ่มชัดกว่าคำพูด ท้ายเอกสารทุกฉบับ ผู้คนต่างฝากใจไว้กับตราประทับเล็กๆ นี้แทนการเขียนชื่อของตน"},"ICON-0010":{"nm":"แท่นรอง","de":"มันโน้มตัวลงต่ำที่สุดเพื่อค้ำจุนสิ่งอื่นเอาไว้ เป็นตำแหน่งที่อยู่ล่างสุด คอยยืนหยัดอย่างเงียบงันเพื่อไม่ให้สิ่งที่วางอยู่ด้านบนสั่นไหว แม้จะไม่เปล่งประกาย แต่ความอ่อนโยนที่ไม่ยอมให้สิ่งใดพังทลายก็อยู่ตรงนี้เอง"},"ICON-0011":{"nm":"แสตมป์","de":"ภาพเล็กๆ ที่เคยเลียมุมหนึ่งแล้วแปะติดลงไปแน่น เป็นราคาที่ซื่อตรงที่สุดที่ตั้งไว้ให้กับหัวใจที่ส่งไปไกลแสนไกล ทิวทัศน์สี่เหลี่ยมเพียงแผ่นเดียวจับมือจดหมายเดินทางข้ามทะเลไปด้วยกัน"},"ICON-0012":{"nm":"หมุดธง","de":"ปักลงบนแผนที่เพียงจุดเดียวก็กลายเป็นคำว่า \"ฉันมาถึงตรงนี้แล้วนะ\" ไม่ใช่การพิชิต แต่เป็นบันทึก และเป็นกำลังใจให้ใครสักคนที่จะตามมาในภายหลัง เครื่องหมายที่ผลักหลังใครสักคนอย่างไร้เสียง บอกให้ก้าวต่ออีกสักก้าวเมื่อเห็นธงผืนนี้"},"ICON-0013":{"nm":"กิ่งไม้","de":"กิ่งที่เคยโค้งงอมาแล้วสักครั้งจะลืมวิธีการหักไป ทุกจุดที่เคยโน้มเอียงต่อสายลมจะมีปุ่มไม้ฝังแน่นอยู่ และป่าเก่าแก่ก็กระซิบผ่านสายลมว่า ความแข็งแกร่งที่แท้จริงนั้นมาจากรอยแผลของการอดทนผ่านมันมาได้ต่างหาก"},"ICON-0014":{"nm":"กระดุม","de":"มันหลุดแล้วก็ถูกกลัดใหม่ซ้ำแล้วซ้ำเล่า คอยรวบปกเสื้อให้เรียบร้อย วงกลมเล็กๆ วงเดียวช่วยกันทั้งความหนาวยามเช้ามืดและความอายที่ผุดขึ้นมาโดยไม่ทันตั้งตัว ต้องรอให้มันหลุดหายไปเสียก่อน ถึงจะรู้ว่าที่ตรงนั้นสำคัญเพียงใด"},"ICON-0015":{"nm":"ซองจดหมาย","de":"วินาทีที่ปิดผนึกปากซองลง มันจึงกลายเป็นความลับอย่างแท้จริง มีเพียงผู้รับเท่านั้นที่รู้ว่าข้างในบรรจุอะไรไว้ กระดาษเพียงชั้นเดียวที่วางคั่นอยู่ระหว่างหัวใจกับโลกภายนอก คือประตูที่บางที่สุดและอ่อนโยนที่สุดบานหนึ่ง"},"ICON-0016":{"nm":"กล่อง","de":"มุมทั้งสี่เที่ยงตรงจึงโอบรับสิ่งใดก็ได้อย่างกว้างขวาง ฤดูย้ายบ้านก็บรรจุความทรงจำ วันเทศกาลก็บรรจุของขวัญ วันธรรมดาก็บรรจุข้าวของจุกจิก ภายในฝาที่ปิดอยู่เสมอเต็มไปด้วยคำว่า \"ไว้ทีหลัง\" ของใครสักคน"},"ICON-0017":{"nm":"มือจับ","de":"ระหว่างประตูกับผู้คน มันคือสิ่งแรกที่ยื่นมือออกมาหา ต้องดึงมันสักครั้งเท่านั้น ข้างในกับข้างนอกจึงจะเชื่อมถึงกัน การตัดสินใจทุกครั้งที่จะเข้าไปหรือออกมา ล้วนต้องกำมือเย็นๆ นี้ไว้สักครู่ก่อนผ่านไป"},"ICON-0018":{"nm":"ช้อน","de":"ด้วยปากเว้าโค้ง มันตักน้ำซุปอุ่นๆ ขึ้นมาอย่างแผ่วเบา เป็นเครื่องมือที่จดจำไออุ่นของช้อนแรกที่แม่เป่าให้เย็นแล้วยื่นให้ก่อนใคร บนโต๊ะอาหาร มันคือมือที่อ่อนโยนที่สุด แตะริมฝีปากเราบ่อยที่สุด"},"ICON-0019":{"nm":"รองเท้าแตะ","de":"วินาทีที่ก้าวข้ามธรณีประตูเข้ามา เท้าจะถอนหายใจโล่งอกเป็นสิ่งแรก ถอดทิ้งเสียงคลิกๆ ของทั้งวันแล้วเดินย่ำเบาๆ เป็นเสียงของยามเย็น รองเท้าแตะคู่หนึ่งที่วางเรียงไว้อย่างเป็นระเบียบตรงหน้าประตูบอกกับเราว่า \"ถึงบ้านแล้วนะ\""},"ICON-0020":{"nm":"กุญแจ","de":"มันเรียนรู้วิธีเปิดก่อนวิธีล็อกเสียอีก ชิ้นโลหะเล็กๆ ที่อุ่นขึ้นในอุ้งมือ แล้ววันหนึ่งก็หยุดนิ่งอยู่หน้าประตูใหม่ที่ไม่คุ้นเคย สิ่งของที่เก็บรักษาไออุ่นของผู้จากไปได้นานที่สุด"},"ICON-0021":{"nm":"แก้ว","de":"ยามว่างเปล่าดูสง่างาม ยามเต็มเปี่ยมกลับอบอุ่นเหลือประมาณ ในเสียงกริ๊งใสของสองใบที่ชนกันเมื่อยกประสานกัน คำสัญญาที่ไร้ถ้อยคำก็ถูกบรรจุไว้ ภาชนะที่เกิดมาเพื่อเปล่งประกายเมื่ออยู่คู่กันสองใบ มากกว่าอยู่เพียงใบเดียว"},"ICON-0022":{"nm":"จาน","de":"ภายในขอบวงกลมนั้นบรรจุความตั้งใจของวันหนึ่งไว้เต็มเปี่ยม เทออก เช็ดถู แล้วบรรจุใหม่ไปตลอดชีวิต ของใช้ในบ้านที่เปล่งประกายบ่อยที่สุดและถูกลืมบ่อยที่สุด เวทีของโต๊ะอาหารถูกจัดวางอยู่บนสิ่งนี้เสมอ"},"ICON-0023":{"nm":"โคมไฟส่องสว่าง","de":"เพียงสวิตช์เดียว สีหน้าของห้องก็เปลี่ยนไป สว่างจ้าคือชีวิตประจำวัน แสงนวลคือการปลอบประโลม แสงจุดหนึ่งที่เปิดทิ้งไว้จนสุดท้ายเพื่อใครสักคนที่กลับบ้านดึก กลายเป็นการต้อนรับที่อบอุ่นที่สุดในโลก"},"ICON-0024":{"nm":"ช้อนชา","de":"หมุนวนบนผิวน้ำชาช้าๆ เพียงรอบเดียว ใบชากับน้ำก็ค่อยๆ ซึมซาบเข้าหากัน การขยับมืออย่างไม่เร่งรีบ การรอคอยเล็กๆ จนกลิ่นหอมกระจายไป มือสีเงินมือหนึ่งค่อยๆ ชะลอความเร็วของยามบ่ายลงอย่างอ่อนโยน"},"ICON-0025":{"nm":"ที่คั่นหนังสือ","de":"คำสัญญาที่แทรกไว้เงียบๆ ตรงจุดที่อ่านค้างไว้ คำมั่นว่า \"หยุดตรงนี้แล้วจะกลับมาแน่นอน\" หลับใหลอยู่ระหว่างหน้ากระดาษ แม้เรื่องราวจะปิดลง แต่หัวใจก็ยังคงถูกทำเครื่องหมายไว้อย่างชัดเจนบนบรรทัดนั้น"},"ICON-0026":{"nm":"เบาะรองนั่ง","de":"มันรองรับหลังและเข่าที่ต้องการที่พิงไว้อย่างเงียบงัน ยุบตัวลงลึกแล้วค่อยๆ ฟูขึ้นอีกครั้ง ดูดซับความเหนื่อยล้าของทั้งวันเอาไว้ สิ่งของที่อนุญาตให้ท่านั่งขี้เกียจที่สุดได้อย่างใจกว้างที่สุด"},"ICON-0027":{"nm":"กรอบรูป","de":"ขอบสี่เหลี่ยมผูกทิวทัศน์หนึ่งไว้กับความเป็นนิรันดร์ เพียงชั่วขณะที่ก้าวเข้ามาอยู่ในนั้น ต่อให้เวลาผ่านไปเท่าใดก็ไม่มีวันจางหาย เป็นทางเลือกอันอ่อนโยนที่ไม่ใช่เรื่องว่าจะบรรจุอะไร แต่เป็นเรื่องว่าตัดสินใจจะเก็บอะไรไว้ต่างหาก"},"ICON-0028":{"nm":"แผนที่","de":"ทุกรอยพับซึมซาบด้วยร่องรอยของการหลงทางแล้วค้นพบเส้นทางอีกครั้ง เมื่อคลี่ออก แม้แต่สถานที่ที่ไม่เคยไปมาก่อนก็สามารถเดินสำรวจด้วยปลายนิ้วได้ก่อนใคร การผจญภัยทุกครั้งเริ่มต้นจากความกล้าเล็กๆ ที่จะคลี่กระดาษแผ่นนี้ออกมา"},"ICON-0029":{"nm":"โปสการ์ด","de":"ด้านหลังครึ่งหนึ่งเป็นรูปภาพ อีกครึ่งหนึ่งเป็นช่องว่าง ผู้ที่จากไปไกลส่งคำว่า \"สบายดีไหม\" มาพร้อมกับทิวทัศน์ของที่นั่น กระดาษที่ซื่อตรงที่สุดแผ่นหนึ่ง ซึ่งแม้ไม่มีซองห่อหุ้ม ข่าวคราวก็ไม่รู้สึกอายเลยสักนิด"},"ICON-0030":{"nm":"บัตรผ่านเข้า","de":"วินาทีที่แขวนไว้ที่คอ เราจึงจะได้ก้าวเข้าสู่โลกด้านในอย่างแท้จริง ชื่อของเราที่เขียนอยู่บนบัตรใบเล็กๆ อนุญาตอย่างเงียบๆ ว่า \"ตรงนี้แหละ ที่ของเธอ\" ไม่ใช่คุณสมบัติในการผ่านเข้าไป แต่เป็นหลักฐานว่าเราเป็นส่วนหนึ่งของที่ใดที่หนึ่ง"},"ICON-0031":{"nm":"ตัวอักษร B","de":"อักษรที่ถูกเรียกใช้บ่อยที่สุดตรงกลางคำ ต้องหุบริมฝีปากแล้วเปิดออกอย่างเบาๆ เสียงจึงจะเกิดขึ้นได้ แม้จะไม่ใช่จุดเริ่มต้นหรือจุดสิ้นสุด แต่ก็เป็นตำแหน่งที่สองอันมั่นคงที่คอยจับจังหวะไว้"},"ICON-0032":{"nm":"นามบัตร","de":"ยื่นให้ด้วยสองมือ รับด้วยสายตาที่สบตากัน วันคืนและความภาคภูมิใจของคนคนหนึ่งถูกอัดแน่นไว้ในกระดาษแผ่นเดียวอย่างเงียบสงบ ในช่องว่างแคบๆ ระหว่างชื่อกับตำแหน่ง ความประทับใจแรกของวันนั้นแฝงตัวอยู่อย่างแผ่วเบา"},"ICON-0033":{"nm":"ปกหนังสือ","de":"อยู่ด้านนอกสุดของเรื่องราว มันรับลมฝนแทนก่อนใคร มุมของมันสึกกร่อนไปทีละน้อยเพราะคอยปกป้องตัวอักษรข้างใน ความตื่นเต้นช่วงสั้นๆ ก่อนจะเปิดออกเริ่มต้นที่แผ่นนี้ก่อนเสมอ"},"ICON-0034":{"nm":"ตำราเรียน","de":"การต่อสู้ดิ้นรนของคนคนหนึ่งถูกเขียนไว้แน่นขนัดด้วยเส้นใต้และปากกาเน้นข้อความ ตอนเป็นหนังสือเล่มใหม่รู้สึกมืดมน แต่พออ่านจบกลับกลายเป็นเพื่อนที่ไว้ใจได้ที่สุด ร่องรอยของการได้รู้ในสิ่งที่ไม่เคยรู้ถูกพับไว้อย่างประณีตในทุกหน้า"},"ICON-0035":{"nm":"บัตรผ่านห้องซ้อมเต้น","de":"กระดาษแผ่นนี้เปิดประตูห้องซ้อมออกกว้าง ห้องที่เต็มไปด้วยกระจก เสียงย่ำเท้า จังหวะแปดบีตแรกที่ได้เรียนรู้ กระดาษแผ่นเล็กๆ ค่อยๆ ผลักหลังที่สั่นระริกให้ก้าวไป บอกว่าต่อให้เต้นยังไม่เก่งก็ไม่เป็นไร"},"ICON-0036":{"nm":"แฟ้มเอกสาร","de":"กระดาษหลายแผ่นที่เคยล่องลอยอย่างไร้ระเบียบถูกร้อยเรียงไว้บนสันเดียวกันอย่างเป็นระเบียบ จึงได้ลำดับขึ้นมาในที่สุด เมื่อมีลำดับก็กลายเป็นเรื่องราว และยิ่งหนาขึ้นเท่าไร ก็ยิ่งเป็นหลักฐานอันอ่อนโยนว่าใครสักคนได้ใช้ชีวิตอย่างทุ่มเทมามากเท่านั้น"},"ICON-0037":{"nm":"กระดาษข้อสอบ","de":"ปลายนิ้วสั่นเล็กน้อยเหนือบรรทัดว่างเปล่า สิ่งที่น่ากลัวยิ่งกว่าคำตอบที่ผิดคือการเผชิญหน้ากับสิ่งที่ไม่รู้อย่างตรงไปตรงมา เมื่อตรวจเสร็จแล้ว ทุกจุดที่ผิดจะเหลือพื้นที่ว่างไว้อย่างเงียบๆ สำหรับการเติบโตในครั้งต่อไป"},"ICON-0038":{"nm":"ตัวอักษร A","de":"เสียงแรกที่จะออกมาได้ก็ต่อเมื่ออ้าปากกว้าง มันมักยืนอยู่หัวแถว หรือตัวแรกสุดของชื่อ เพราะไม่ว่าจะเริ่มต้นสิ่งใดก็ต้องเริ่มจากตัวอักษรนี้ก่อน มันจึงกล้าหาญกว่าเสมอสักนิดหนึ่ง"},"ICON-0039":{"nm":"ตัวอักษร D","de":"ด้วยสันหลังที่โค้งมนอ่อนโยน มันช่วยประคองคำศัพท์ไว้อย่างแผ่วเบา ด้านโค้งมนของมันห้อยอยู่อย่างเรียบร้อยที่ท้ายชื่อของใครสักคน ไม่หรูหราแต่ขาดไปแล้วก็รู้สึกว่างเปล่า เป็นเพื่อนเงียบๆ คนหนึ่งท่ามกลางตัวอักษรทั้งหมด"},"ICON-0040":{"nm":"กระดาษฝึกซ้อม","de":"กระดาษเพียงแผ่นเดียวในโลกที่ผิดพลาดได้โดยไม่เป็นไร มันยอมให้เราเขียนท่าเดิม ประโยคเดิม ซ้ำแล้วซ้ำเล่านับสิบครั้ง จำนวนแผ่นที่ยับยู่ยี่แล้วถูกทิ้งไปมากเท่าไร ก็หมายความว่าใครบางคนกำลังพัฒนาขึ้นอย่างแน่นอนมากเท่านั้น"},"ICON-0041":{"nm":"กระดาษเขียนโน้ตเพลง","de":"ตีสองยามดึก เสียงฮัมเบาๆ ปลุกให้ตื่นจากหลับใหล ดินสอที่ลังเลอยู่บนบรรทัดห้าเส้นก็เพราะทำนองไปเร็วกว่ามือ ในทุกรอยที่ลบแล้วเขียนใหม่ บทเพลงที่ยังไม่มีชื่อกำลังค่อยๆ เติบโตขึ้นทีละนิด"},"ICON-0042":{"nm":"บัตรผ่านเข้าพื้นที่","de":"วินาทีที่แขวนไว้ที่คอ ทางเดินธรรมดาก็เปลี่ยนเป็นอีกโลกหนึ่งทันที สายเคเบิลพาดผ่านความมืดราวกับงู และเบื้องหลังเวทีก็เริ่มนับถอยหลังที่ไม่มีใครได้ยิน สิทธิ์ในการก้าวเข้ามาที่นี่ กระดาษแผ่นนี้พูดแทนเราได้"},"ICON-0043":{"nm":"คอนแทกต์ชีต","de":"ในแต่ละช่องเล็กๆ มีสีหน้าต่างกันหยุดนิ่งอยู่ ยิ้ม หันกลับมอง หลับตา เมื่อชี้ไปทีละภาพ ความตื่นเต้นในวันที่กดชัตเตอร์ก็กลับคืนมาสู่ปลายนิ้วอีกครั้ง แม้แต่การเลือกเพียงหนึ่งภาพก็ถือเป็นบันทึกไปแล้ว"},"ICON-0044":{"nm":"ตารางนัดหมายกองถ่าย","de":"พรุ่งนี้กี่โมง ที่ไหน ทำอะไร กระดาษแผ่นเดียวร่างเส้นทางของวันหนึ่งไว้ล่วงหน้า ท่ามกลางช่องตารางที่แน่นขนัดในหน่วยนาที ใครสักคนก้าวเดินไปทีละก้าวสู่ความฝัน ตามลำดับที่จดไว้ที่นี่"},"ICON-0045":{"nm":"ป้ายห้อย","de":"ด้านหลังป้ายราคาแขวนเวลาของผู้สร้างสรรค์ไว้อย่างเงียบๆ กระดาษเล็กๆ ที่จะกลายเป็นของเราอย่างแท้จริงก็ต่อเมื่อดึงมันขาดออกด้วยมือในชั่วพริบตา สิ่งที่หลงเหลืออยู่ตรงรอยตัดคือกลิ่นของใหม่และความตื่นเต้นอีกเล็กน้อย"},"ICON-0046":{"nm":"พอร์ตโฟลิโอ","de":"เปิดปกออก เส้นทางที่ผ่านมาก็คลี่ออกมาพร้อมกันทั้งหมด ข้างๆ ผลงานที่มั่นใจ มีความพยายามครั้งแรกที่ยังไม่ชำนาญวางเรียงอยู่อย่างเขินอาย เมื่อต้องยื่นตัวตนให้ใครสักคนเป็นครั้งแรก ไม่มีการแนะนำตัวใดจะซื่อตรงไปกว่านี้อีกแล้ว"},"ICON-0047":{"nm":"สมุดแพลนเนอร์","de":"เขียนวันนี้ วาดสัปดาห์หน้า และบางครั้งก็ระบายช่องหนึ่งให้ดำสนิท แม้จะไม่เคยเป็นไปตามแผนเลยสักครั้ง แต่มือที่คอยเติมเต็มช่องต่างๆ ก็ไม่เคยหยุด เปรียบเหมือนพิธีกรรมเล็กๆ ที่ได้ลองใช้ชีวิตในอนาคตล่วงหน้าสักครั้งหนึ่ง"},"ICON-0048":{"nm":"เพลย์ลิสต์","de":"ระหว่างเพลงช้ากับจังหวะเร็ว เราจัดเรียงเพลงเป็นแถวเดียวให้เข้ากับสภาพอากาศของหัวใจในวันนั้น หากคิดว่าวันหนึ่งของใครสักคนไหลผ่านไปตามลำดับนี้พอดี แม้แต่ความเงียบระหว่างเพลงก็ยังรู้สึกอ่อนโยน"},"ICON-0049":{"nm":"บัตรนักเรียน","de":"ชื่อ รูปถ่าย และตัวเลขไม่กี่ตัว บัตรใบเดียวที่พิสูจน์ช่วงเวลาที่เดินไปมาระหว่างห้องเรียนกับห้องซ้อม บัตรที่มุมสึกกร่อนจากการเข้าออกกระเป๋าซ้ำแล้วซ้ำเล่า ฝังไว้ด้วยทุกวันอันสดใสที่ไม่มีวันหวนคืนมาอีก"},"ICON-0050":{"nm":"สายรัดข้อมือ","de":"จำวินาทีที่ผูกสีของวันนั้นไว้ที่ข้อมือได้ไหม เสียงร้องตะโกนพร้อมกัน ค่ำคืนคอนเสิร์ตที่เปียกปอนไปด้วยกัน ต่อให้เชือกสึกและสีจางไป ก็ยังไม่ยอมแก้มันออก เพราะอยากให้ฤดูร้อนวันนั้นยังคงมีชีวิตอยู่บนข้อมือนี้ต่อไป"},"ICON-0051":{"nm":"ปลอกแขน","de":"วินาทีที่สวมไว้ที่แขน น้ำหนักที่เรียกว่าความรับผิดชอบก็ค่อยๆ เพิ่มเข้ามาโดยไม่รู้ตัว เป็นเครื่องหมายของผู้ที่ยืนหัวแถวและเป็นคนสุดท้ายที่ออกจากที่นั่น ผ้าเพียงชิ้นเดียวทำให้ใครสักคนเติบโตขึ้นอีกนิดหนึ่ง"},"ICON-0052":{"nm":"แหวน","de":"เส้นวงกลมหนึ่งที่ต่อเนื่องกันโดยไม่มีจุดขาด เพราะจุดเริ่มต้นกับจุดสิ้นสุดบรรจบกัน ผู้คนจึงมองเห็นรูปทรงของความเป็นนิรันดร์อยู่ในนั้น เพียงประสานสองมือเข้าหากันเบาๆ คำสัญญาก็ปรากฏเป็นรูปทรงก่อนคำพูดใดๆ"},"ICON-0053":{"nm":"เหรียญเกียรติยศ","de":"ชิ้นโลหะเล็กๆ ที่ติดไว้บนอกสลักไว้ด้วยวันเวลาที่อดทนผ่านมาได้ สิ่งที่เปล่งประกายไม่ใช่โลหะ แต่คือค่ำคืนแห่งการฝึกซ้อมนับไม่ถ้วนที่ซ่อนอยู่เบื้องหลัง สิ่งที่พลุ่งพล่านขึ้นมาก่อนความภาคภูมิใจคือความรู้สึกขอบคุณอย่างประหลาดใจ"},"ICON-0054":{"nm":"ผ้ากันเปื้อน","de":"ผูกเชือกที่คอแล้วสองมือก็เป็นอิสระ เป็นสัญญาณว่าพร้อมจะดำดิ่งลงไปในสิ่งใดสิ่งหนึ่ง ไม่ว่าจะเป็นแป้งหรือสี ยิ่งรอยเปื้อนเพิ่มขึ้นทีละจุด ความตั้งใจที่ทุ่มเทลงไปในวันนั้นก็ยิ่งเข้มข้นขึ้นตามไปด้วย"},"ICON-0055":{"nm":"ที่ครอบหูกันหนาว","de":"เมื่อโอบหูไว้มิดชิด เสียงจากภายนอกก็ถอยห่างออกไปหนึ่งก้าว บนทางไปโรงเรียนที่สายลมพัดดั่งมีดกรีด มันคือที่หลบภัยเล็กๆ ให้แอบซ่อนตัวในความนุ่มนวลด้านใน ความอบอุ่นของฤดูหนาวบางครั้งก็เริ่มต้นจากปลายหูอย่างนี้เอง"},"ICON-0056":{"nm":"ชุดแสดง","de":"ก่อนม่านจะเปิด ชุดหนึ่งแขวนอยู่บนไม้แขวนเสื้ออย่างกลั้นลมหายใจ ในทุกตะเข็บพับซ่อนท่าเต้นเอาไว้ วินาทีที่สอดแขนเข้าไป คนคนหนึ่งก็กลายเป็นตัวละคร และเวทีก็กลายเป็นผิวหนังชั้นที่สองของชุดนั้น"},"ICON-0057":{"nm":"มงกุฎ","de":"วินาทีที่สวมไว้บนศีรษะ หลังที่เคยโค้งงอก็ยืดตรงขึ้นเองโดยไม่รู้ตัว แสงสีทองกระซิบเรื่องความรับผิดชอบก่อนอำนาจเสียอีก น้ำหนักเย็นเยียบที่แตะหน้าผากบอกเราว่า ยิ่งตำแหน่งเปล่งประกายมากเท่าไร ก็ยิ่งหนักอึ้งมากเท่านั้น"},"ICON-0058":{"nm":"เสื้อคลุม","de":"คลุมไว้ที่บ่าแล้วสายลมก็พลิ้วไหวอยู่ด้านหลัง ความรู้สึกที่ผืนผ้าโบกสะบัดตามหลังทุกครั้งที่วิ่ง มันไม่ใช่เครื่องหมายของฮีโร่มากนัก แต่ใกล้เคียงกับหัวใจเด็กๆ ที่แค่อยากดูเท่มากกว่า"},"ICON-0059":{"nm":"หน้ากาก","de":"เมื่อปิดบังใบหน้ากลับยิ่งซื่อสัตย์ต่อตัวเองมากขึ้น เหมือนการละเล่นพื้นบ้านโบราณที่หัวเราะและร้องไห้ได้อย่างเต็มที่หลังหน้ากาก เหนือสีหน้าที่ซ่อนไว้นั้น เสียงจริงที่มักจะกลืนไว้ในยามปกติกลับรั่วไหลออกมาดังยิ่งกว่าเดิม"},"ICON-0060":{"nm":"ลิปสติก","de":"หมุนฝาออกแล้วป้ายเส้นเดียว ความตั้งใจเล็กๆ ก็ปรากฏขึ้นที่ริมฝีปาก การตรวจสอบครั้งสุดท้ายหน้ากระจก เส้นสีแดงที่แต่งแต้มทับความลังเล ในช่วงเวลาสั้นๆ ที่สีเคลือบลงไปนั้น ความกลัวก็ค่อยๆ เลื่อนหลบไปอย่างเงียบเชียบ"},"ICON-0061":{"nm":"แจ็กเก็ต","de":"เมื่อเส้นบ่าพอดีเป๊ะ คนเราก็จะแข็งแกร่งขึ้นอีกนิด พับแขนเสื้อขึ้นคือใจที่พร้อมทำงาน ตั้งปกเสื้อขึ้นคือใจที่พร้อมออกไปข้างนอก เสื้อผ้าชุดเดียวกำหนดท่าทีของทั้งวันไว้อย่างเงียบๆ"},"ICON-0062":{"nm":"สายคาดเทควันโด","de":"ทุกครั้งที่สีเปลี่ยนไปอีกขั้น ปริมาณเหงื่อที่สั่งสมอยู่เบื้องล่างก็เปลี่ยนไปด้วย เช้าวันที่โดโจที่รัดปมให้แน่นแล้วก้มคำนับ ผ่านปลายนิ้วที่ผูกสายคาด จิตใจที่กระจัดกระจายก็รวมตัวกันอีกครั้ง"},"ICON-0063":{"nm":"แว่นกันลม","de":"สวมไว้ที่ดวงตาแล้วโลกก็คมชัดขึ้นอีกหนึ่งระดับ เหนือโล่วงกลมที่กันทั้งลมและฝุ่นได้นี้ แม้แต่เส้นทางธรรมดาที่เดินอยู่ทุกวันก็ดูเปล่งประกายราวกับเส้นสตาร์ทไม่รู้เพราะเหตุใด"},"ICON-0064":{"nm":"ถุงมือ","de":"สวมไว้ที่มือแล้วความกล้าที่จะจับสิ่งใดให้มั่นก็พลุ่งขึ้นมา นิ้วมือที่เคยหดตัวเพราะกลัวจะทำหล่นก็คลี่ออกอย่างเต็มที่ในที่สุด สิ่งที่ปกป้องคือมือ แต่สิ่งที่แท้จริงถูกปกป้องไว้คือความท้าทายที่จะมาถึงในภายหลัง"},"ICON-0065":{"nm":"หน้ากากอนามัย","de":"เมื่อปิดปากไว้ ดวงตากลับพูดมากขึ้น บนถนนที่ผู้คนพลุกพล่าน มันคืออิสรภาพเล็กๆ แห่งการไม่ระบุตัวตนที่ได้เพลิดเพลินขณะปิดบังบางส่วนไว้ ด้วยเหตุนี้ รอยยิ้มที่ปรากฏขึ้นในตอนที่ถอดมันออกจึงยิ่งเปล่งประกายสดใสกว่าเดิม"},"ICON-0066":{"nm":"หมวก","de":"กดปีกหมวกลงมาสักนิด แสงแดดและสายตาผู้คนก็เบี่ยงหลบไปหนึ่งช่วง ใต้หลังคาเล็กๆ ที่วางไว้บนศีรษะ อย่างน้อยวันนี้เราก็เดินด้วยสีหน้าสบายๆ ได้ การแปลงกายที่เบาที่สุดมักเริ่มต้นที่นี่เสมอ"},"ICON-0067":{"nm":"เสื้อเชิ้ต","de":"กรอบแกรบ ปกเสื้อที่เพิ่งรีดเสร็จส่งกลิ่นยามเช้า ขณะที่ค่อยๆ กลัดกระดุมจากบนลงล่างทีละเม็ด หัวใจที่ยุ่งเหยิงก็ค่อยๆ เรียบร้อยขึ้นทีละช่อง เสื้อขาวเพียงตัวเดียวเปิดประโยคแรกของวัน"},"ICON-0068":{"nm":"ผ้าพันคอ","de":"พันรอบคอเพียงรอบเดียว เส้นทางของสายลมก็ถูกปิดกั้น ขณะที่ชายผ้าพลิ้วไหวอยู่ที่บ่า ความหนาวก็ไม่อาจเอื้อมถึงข้างในได้อีกต่อไป ผืนผ้าหนึ่งที่วางอยู่ตรงกลางระหว่างความสวยงามกับความอบอุ่น"},"ICON-0069":{"nm":"ถุงมือกันหนาว","de":"เมื่อถูกโอบไว้จนถึงปลายนิ้ว แม้ความเย็นก็ไม่น่ากลัวอีกต่อไป มือที่เคยเป่าลมอุ่นก็ค่อยๆ อบอุ่นขึ้นเอง คือความหรูหราเล็กๆ ของฤดูหนาว ถุงมือข้างหนึ่งที่ถอดออกยื่นให้ ก็สามารถทำให้มือของใครอีกคนอุ่นขึ้นได้เช่นกัน"},"ICON-0070":{"nm":"ป้ายประจำตัวทหาร","de":"แผ่นป้ายบางสองแผ่นเผชิญหน้ากันอยู่อย่างเงียบๆ ชื่อสามพยางค์และตัวเลขไม่กี่ตัว สิ่งนั้นทำให้ใครสักคนถูกจดจำไปจนถึงที่สุด แม้เป็นโลหะเย็นเยียบ แต่กลับคล้ายกับคำสัญญาที่อบอุ่นที่สุดอย่างประหลาด"},"ICON-0071":{"nm":"แหวนจับมือถือ","de":"สอดนิ้วเข้าไปแล้วความกังวลว่าจะทำหล่นก็ค่อยๆ มลายหายไป เป็นความอุ่นใจเล็กๆ ที่ถือและโบกด้วยมือเดียวได้อย่างสบาย เมื่อยื่นแขนออกไปไกลเพื่อเก็บภาพสักภาพ มันคอยประคองฝ่ามือไว้อย่างเงียบๆ"},"ICON-0072":{"nm":"มงกุฎดอกไม้","de":"สวมไว้บนศีรษะแล้วฤดูใบไม้ผลิทั้งกำมือก็ตามมาด้วย ดอกไม้ที่เด็ดมาจากทุ่งแล้วสานเป็นวงกลมโอบรอบหน้าผากไว้อย่างแผ่วเบา เหนือรอยยิ้มสดใสในภาพถ่าย กลิ่นหญ้าอ่อนๆ ยังคงหลงเหลืออยู่นานแสนนาน"},"ICON-0073":{"nm":"ผ้าปิดตา","de":"ปิดดวงตาแล้วทั้งแสงไฟและเสียงรบกวนก็ห่างไกลออกไปพร้อมกัน เมื่อมองไม่เห็น สิ่งที่ได้ยินก็มีเพียงเสียงลมหายใจของตัวเอง เมื่อปิดโลกภายนอกไปชั่วครู่แล้วก้าวเข้าสู่ความเงียบสงบภายใน ประตูบานเล็กๆ ก็ปิดลงอย่างเงียบๆ ที่ด้านหลัง"},"ICON-0074":{"nm":"ผ้าพันคอไหมพรม","de":"หนึ่งรอบ สองรอบ ทุกครั้งที่พันรอบคอ ฤดูหนาวก็อ่อนโยนลงทีละนิด บางทีท่ามกลางเส้นไหมพรมอาจมีหัวใจที่ใครสักคนถักทอไว้แทรกปนอยู่ก็ได้ ฝังหน้าลงไปจนถึงปลายจมูก โลกก็รู้สึกอบอุ่นขึ้นอีกระดับ"},"ICON-0075":{"nm":"หน้ากากครึ่งหน้า","de":"ปิดบังใบหน้าไว้เพียงครึ่งเดียว ค่ำคืนแห่งงานเต้นรำก็เริ่มต้นขึ้น ริมฝีปากที่เผยออกยิ้มอยู่ ส่วนดวงตาที่ซ่อนไว้เก็บความลับ ช่องว่างแคบๆ ที่รู้สึกเหมือนจะรู้ว่าเป็นใครแต่ก็ไม่แน่ใจนั้น ทำให้บรรยากาศเที่ยงคืนตื่นเต้นระริกไหว"},"ICON-0076":{"nm":"หมวกเบเร่ต์","de":"สวมเอียงเล็กน้อยแล้ว วันธรรมดาก็มีเสน่ห์แฝงขึ้นมาโดยไม่รู้ตัว ผ้าแผ่นกลมแบนแผ่นเดียวค่อยๆ สวมบทศิลปินให้กับบ่าของเรา แม้แต่ช่วงเวลาสั้นๆ ที่เลือกมุมเอียงหน้ากระจกก็ยังรู้สึกสนุกสนาน"},"ICON-0077":{"nm":"ช็อคเกอร์","de":"พันรอบคอให้พอดีแล้วสายตาก็มุ่งไปด้านบนโดยธรรมชาติ สายเล็กๆ เพียงเส้นเดียวเปลี่ยนบรรยากาศทั้งหมดไปอย่างสิ้นเชิง เล็กแต่ชัดเจน เหมือนตัวล็อกที่เติมเต็มความมั่นใจของวันนี้"},"ICON-0078":{"nm":"เสื้อกันหนาวปาร์ก้า","de":"รูดซิปขึ้นจนสุดแล้ว แม้แต่พายุหิมะก็ยังต้องถอยห่างไปหนึ่งก้าว สอดมือลึกเข้าไปในความหนานุ่มด้านใน ความวุ่นวายทั้งโลกก็สงบเงียบลง บ้านหลังเล็กๆ หลังหนึ่งที่ยังคงอบอุ่นแม้ท่ามกลางลมแรง"},"ICON-0079":{"nm":"กางเกง","de":"สอดเท้าเข้าไปแล้วรัดเอวให้เรียบร้อย เพียงเท่านี้การเตรียมพร้อมออกไปข้างนอกก็เสร็จสิ้น ทุกก้าวที่เดินออกไป ผืนผ้าก็เคลื่อนไหวไปตามลายอย่างนุ่มนวล วันหนึ่งเริ่มต้นขึ้นที่ไหนสักแห่งระหว่างความสบายกับความเรียบร้อย"},"ICON-0080":{"nm":"ต่างหูเจาะ","de":"แม้แต่การเพิ่มจุดเล็กๆ เพียงจุดเดียวก็ต้องใช้ความกล้าอยู่บ้าง โลหะเปล่งประกายชิ้นเดียวประทับจุดจบที่ชัดเจนไว้ที่ใบหูธรรมดาๆ เล็กมากแต่คือแสงที่สะท้อนตัวตนของวันนี้ที่เปลี่ยนไปอย่างแน่ชัด"},"ICON-0081":{"nm":"คลื่นเสียง","de":"สำหรับวิศวกรเสียง เพลงไม่ใช่สิ่งที่ได้ยิน แต่เป็นสิ่งที่มองเห็น จากสันเขาที่ขึ้นลงบนหน้าจอ พวกเขาอ่านออกว่าลมหายใจสั่นไหวตรงจุดใดในวันนั้น เสียงที่เคยมองไม่เห็นนอนทอดตัวราวกับทิวเขา คลี่ภูมิประเทศของบทเพลงหนึ่งออกมาให้เห็น"},"ICON-0082":{"nm":"เครื่องจูนเสียง","de":"ก่อนการแสดงจะเริ่ม เราลูบสายทั้งหกเส้นทีละเส้น ปรับโน้ตที่เพี้ยนไปให้กลับเข้าที่ แม้จะคลาดเคลื่อนไปเพียง 0.5 องศา ผู้ชมก็จับได้เหมือนมีตาทิพย์ การปรับให้แม่นยำจนไม่มีใครสังเกตเห็นได้เลย นั่นแหละคือความอ่อนโยนที่มีต่อเวที"},"ICON-0083":{"nm":"สายคล้องข้อมือ","de":"พันรอบข้อมือเพียงรอบเดียว ความกังวลว่าจะทำของหล่นก็คลายลงไปเอง สิ่งที่น่ากลัวที่สุดบนเวทีคือการทำสิ่งใดหลุดจากมือ ด้วยเชือกเล็กๆ เส้นนี้เพียงเส้นเดียว หัวใจจึงจะรู้สึกโล่งอกได้ในที่สุด"},"ICON-0084":{"nm":"ฉาบ","de":"ในวินาทีที่กระทบกันเพียงครั้งเดียว ประโยคสุดท้ายของบทเพลงก็ถูกประทับจุดจบไว้อย่างชัดเจน แผ่นทองกลมใบนี้รู้วิธีที่จะสั่นสะเทือนสั้นที่สุดแต่ทิ้งเสียงก้องยาวนานที่สุด ราวกับจะบอกว่าตอนจบต้องปิดฉากลงอย่างสดใสเช่นนี้เท่านั้น"},"ICON-0085":{"nm":"กีตาร์","de":"เมื่อปลายนิ้วไถลไปบนสายทั้งหกเส้น ห้องแคบๆ ก็กลายเป็นเวทีทั้งห้อง ทั้งทำนองแรกของใครสักคน และคำพูดคนเดียวในยามเช้ามืดที่นอนไม่หลับ ล้วนได้ลมหายใจแรกภายในตัวไม้ทรงกลมใบนี้"},"ICON-0086":{"nm":"เมฆเสียงเพลง","de":"มุมหนึ่งของท้องฟ้า ตัวโน้ตต่างๆ จับกลุ่มกันเป็นก้อนคล้ายปุยฝ้ายล่องลอยอยู่ ว่ากันว่าเมื่อสายลมพัดผ่านไปครั้งหนึ่ง ทำนองเพลงจะโปรยลงมาแทนหยดฝน เด็กๆ บนเกาะจึงพากันออกไปต้อนรับโดยไม่ต้องกางร่มเลยด้วยซ้ำ"},"ICON-0087":{"nm":"สเต็ปเต้น","de":"เส้นทางบนเวทีคือเลขคณิตที่ไขด้วยปลายเท้า ก้าวหนึ่งตรงนี้ ครึ่งจังหวะตรงนั้น ผิดได้ไม่เป็นไร ค่อยๆ ทำไป ช่องต่างๆ ที่ย่ำซ้ำเป็นร้อยครั้งจนสลักไว้ในร่างกาย เมื่อรวมกันแล้วจึงเป็นแผนที่ของบทเพลงหนึ่งที่สมบูรณ์"},"ICON-0088":{"nm":"เครื่องขยายเสียง","de":"กล่องที่เปลี่ยนเสียงกระซิบให้กลายเป็นเสียงโห่ร้อง กระนั้นก่อนจะเร่งระดับเสียงขึ้นอีกหนึ่งขั้น มือก็มักจะหยุดชะงักเสมอ กล่องใบนี้รู้ดีว่าเสียงที่แม่นยำกว่าต่างหากที่ไปถึงแถวสุดท้ายของผู้ชม ไม่ใช่เสียงที่ดังกว่า"},"ICON-0089":{"nm":"ปุยโน้ตเพลง","de":"หัวโน้ตกลมๆ มารวมกันเป็นก้อนปุยจนนุ่มราวกับหมอน ว่ากันว่าถ้าเอนหลังหนุนไว้เงียบๆ จะได้ยินเพลงกล่อมเด็กแผ่วเบาราวกับจะได้ยินแต่ไม่ได้ยินไหลออกมา นี่คือข่าวลือที่อ่อนโยนที่สุดบนเกาะแห่งนี้"},"ICON-0090":{"nm":"เทปคาสเซ็ต","de":"กดปุ่มย้อนกลับแล้วเสียงเอี๊ยด เทปก็ค่อยๆ หมุนกลับไปยังเพลงแรกของฤดูร้อนนั้น ภายในกล่องเล็กๆ ที่ม้วนเก็บช่วงเวลาทั้งหมดไว้ เวลาที่ไม่อาจแตะต้องได้อีกแล้วยังคงหลับใหลอยู่อย่างครบถ้วนสมบูรณ์"},"ICON-0091":{"nm":"ส้อมเสียง","de":"เคาะโลหะสองง่ามเบาๆ แล้วเสียงมาตรฐานเสียงหนึ่งก็ถือกำเนิดขึ้นกลางอากาศ เครื่องดนตรีทุกชิ้นค่อยๆ ปรับตัวให้เข้ากับการสั่นสะเทือนเล็กๆ นี้อย่างเงียบๆ ไม่ว่าจะเป็นสิ่งใด จุดเริ่มต้นล้วนมาจากการสั่นไหวแผ่วเบาเช่นนี้เอง"},"ICON-0092":{"nm":"ชิปคลื่นเสียง","de":"เสียงชิ้นเล็กๆ ถูกกักเก็บไว้อย่างแผ่วเบาในชิปขนาดเท่าเล็บมือ ทั้งเสียงร้องรับที่ไม่เคยตั้งใจอัดไว้ และเสียงหัวเราะของใครสักคนที่เคยคิดว่าสูญหายไปแล้ว ยังคงมีชีวิตและหายใจอย่างอบอุ่นอยู่ภายในนี้เสมอ"},"ICON-0093":{"nm":"แผ่นเสียง LP","de":"เมื่อเข็มก้าวแรกไปตามร่องแผ่นเสียง เสียงลมหายใจแผ่วเบาที่แตกพร่าจะดังขึ้นมาก่อนสิ่งใด แม้แต่เสียงรบกวนเล็กๆ นั้นก็ยังเป็นที่รัก บางคนจึงไม่อาจปล่อยแผ่นสีดำใบนี้จากมือได้เลยจนถึงที่สุด"},"ICON-0094":{"nm":"กระเป๋าเสื้อ","de":"สิ่งที่รักที่สุดมักถูกเก็บไว้ใกล้หัวใจที่สุดเสมอ ถุงผ้าขนาดเท่าฝ่ามือใบเดียวบางวันก็กลายเป็นเครื่องอุ่นมือ บางวันก็เป็นเครื่องรางของขลัง และบางวันก็เป็นที่เก็บความลับ"},"ICON-0095":{"nm":"พลาสเตอร์ปิดแผล","de":"ในค่ำคืนที่ฝึกซ้อมยาวนาน เหรียญเกียรติยศเล็กๆ จะติดอยู่ที่ส้นเท้าแต่ละข้าง แผ่นหนึ่งที่แปะไว้เพื่อกลืนคำว่า \"เจ็บ\" เก็บไว้ในใจ เป็นคำสัญญาเงียบๆ ที่ไม่มีใครรู้ว่าพรุ่งนี้ก็จะยังคงเต้นต่อไปให้ได้อย่างแน่นอน"},"ICON-0096":{"nm":"หมอน","de":"สถานที่ที่วางเวทีของทั้งวันลงได้อย่างสมบูรณ์ก็คือผืนสี่เหลี่ยมนุ่มนิ่มแผ่นนี้ในที่สุด เมื่อวางศีรษะลงเบาๆ เสียงปรบมือที่ยังก้องอยู่ในหูก็ค่อยๆ เงียบหายไป และค่ำคืนก็ตกลงมาสู่เกาะแห่งนี้ในที่สุด"},"ICON-0097":{"nm":"กระดิ่ง","de":"กริ๊งกร๊าง เสียงสั้นๆ เพียงครั้งเดียว ใครสักคนก็ผลักประตูเข้ามา เป็นสัญญาณว่ามีลูกค้ามา และเป็นคำทักทายว่าวันใหม่ได้เปิดขึ้นแล้ว ชิ้นโลหะเล็กๆ เพียงชิ้นเดียวส่งเสียงต้อนรับอย่างยินดีตลอดทั้งวัน"},"ICON-0098":{"nm":"เคส","de":"ยิ่งเป็นสิ่งที่มีค่ามากเท่าไร ก็ยิ่งสร้างบ้านที่แข็งแรงไว้ให้ต่างหากมากเท่านั้น มือที่เปิดปิดจึงระมัดระวังทุกครั้ง เพราะสิ่งที่บรรจุอยู่ข้างในไม่ใช่เพียงข้าวของ แต่คือหัวใจที่ไม่อาจปล่อยให้สูญเสียไปได้"},"ICON-0099":{"nm":"แปรง","de":"กวาดไปตามลายจนถึงเส้นขนสุดท้าย ฝุ่นที่ติดแน่นอยู่ตามมุมก็ค่อยๆ ถอยห่างออกไป เพราะมีสัมผัสที่ไม่ปฏิเสธแม้แต่จุดที่มองไม่เห็น ห้องจึงได้ต้อนรับเช้าวันใหม่ทุกวัน"},"ICON-0100":{"nm":"ภาพร่าง","de":"เส้นสายก่อนจะเสร็จสมบูรณ์ไม่จำเป็นต้องปิดบังความลังเลเลยสักนิด ในทุกรอยที่ลบแล้วขีดใหม่ ร่องรอยของสิ่งที่อยากจะเป็นยังคงหลงเหลืออยู่โดยไม่มีเท็จ จุดเริ่มต้นที่งุ่มง่ามยิ่งซื่อตรงที่สุด"},"ICON-0101":{"nm":"ตุ๊กตา","de":"มีบางสิ่งที่ปลอบใจเราได้เพียงแค่กอดมันไว้ในอ้อมแขนโดยไม่ต้องพูดอะไร เพื่อนตัวนุ่มที่สั่นอยู่ข้างหมอนในคืนที่มือของเราสั่นอยู่หลังเวที—ทุกคนต่างมีเพื่อนแบบนี้ซุกซ่อนอยู่สักตัวในใจ"},"ICON-0102":{"nm":"ระฆัง","de":"ระฆังวัดบนภูเขาสั่นเพียงครั้งเดียวก็ข้ามหุบเขาทั้งหุบได้ มันคือหัวใจของโลหะที่ปรารถนาจะไปให้ไกล ไกลออกไปอีก จึงร้องเป็นเสียงยาว เสียงนั้นจึงค่อยๆ จมลงในอกของผู้ฟังอย่างช้าๆ"},"ICON-0103":{"nm":"ร่ม","de":"กางร่มด้วยกันแล้วไหล่ข้างหนึ่งย่อมเปียกอยู่เสมอ ใต้ร่มที่เอียงเล็กน้อยอย่างแอบแฝงนั้น ไหล่ที่เปียกคือหลักฐานความอ่อนโยนที่ชัดเจนที่สุด ทางสั้นๆ ที่แบ่งปันหลังคาเดียวกันจึงฝังอยู่ในใจไปอีกนาน"},"ICON-0104":{"nm":"เสื่อรองพื้น","de":"ปูแผ่นเดียวลงบนพื้นเปล่าก็กลายเป็นห้องซ้อมได้ทันที มันคือที่ที่รองรับเราไว้อย่างเงียบๆ เมื่อเราหมุนตัวและล้มลง—ท่วงท่านับไม่ถ้วนได้เริ่มฝึกฝนร่างกายให้คุ้นเคยเป็นครั้งแรกบนผืนนี้"},"ICON-0105":{"nm":"กระดิ่งเล็ก","de":"เขย่าเบาๆ เสียงใสกรุ๊งกริ๊งก็กลิ้งออกมาในอุ้งมือ ความสนุกกลมเล็กๆ ที่เด็กๆ สมัยก่อนเคยผูกไว้ที่ชายเสื้อสีรุ้งแล้ววิ่งเล่นทั่วลานบ้าน ตื่นขึ้นอีกครั้งบนฝ่ามือของเรา"},"ICON-0106":{"nm":"งูของเล่น","de":"รูปทรงยาวเหยียดของมันทำให้คนตกใจได้อย่างซุกซน ตกใจ วิ่งหนี แล้วสุดท้ายก็หัวเราะคิกคักออกมา—การล้อเล่นแบบนี้ก็เป็นความอ่อนโยนอีกแขนงหนึ่งที่มีต่อกัน"},"ICON-0107":{"nm":"ของเล่น","de":"ทุกคนมีกล่องใบหนึ่งที่แม้โตเป็นผู้ใหญ่แล้วก็ยังทิ้งไม่ลง ข้างในนั้นเสียงหัวเราะแห่งวันเวลาที่เจิดจ้าที่สุดยังคงขดแน่นอยู่เหมือนลานนาฬิกาที่ยังไม่คลาย"},"ICON-0108":{"nm":"โต๊ะอาหาร","de":"กางขาที่พับไว้ออก ที่ไหนก็กลายเป็นที่นั่งของครอบครัวได้ในทันที เสียงช้อนกระทบกันตอนทุกคนนั่งล้อมวง คือการบรรเลงเพลงเรียบง่ายที่ดังก้องอบอุ่นที่สุดในบรรดาเพลงทั้งวัน"},"ICON-0109":{"nm":"สบู่","de":"มันค่อยๆ เล็กลงในมือทีละนิด แต่ก็ทำให้ใครสักคนสะอาดขึ้นอย่างเงียบๆ การสึกกร่อนตัวเองเพื่อชำระล้างผู้อื่น—ต้องรอให้ฟองสบู่จางหายไปนานแล้วเท่านั้น หัวใจอันเงียบงันนั้นจึงจะปรากฏให้เห็น"},"ICON-0110":{"nm":"หวี","de":"เหมือนกับที่มันคลี่ผมที่พันกันออกทีละเส้น วันอันยุ่งเหยิงก็ค่อยๆ เรียบร้อยขึ้นเช่นกัน สัมผัสสั้นๆ ที่ยื่นให้หน้ากระจกบานหนึ่ง แอบซ่อมแซมไม่เพียงเส้นผม แต่ยังรวมถึงทรวดทรงของหัวใจด้วย"},"ICON-0111":{"nm":"กรงนก","de":"มีนกบางตัวที่ร้องเพลงโดยไม่บินหนีไป แม้ประตูจะเปิดกว้างอยู่ก็ตาม หัวใจที่อยู่ต่อไม่ใช่เพราะถูกขัง แต่เพราะปรารถนาจะอยู่—ความแตกต่างเล็กน้อยนั้น กรงใบนี้รับรู้ได้ก่อนใคร"},"ICON-0112":{"nm":"กระเป๋าไฟผิง","de":"ในแถวรอคิวหน้าเวทีคอนเสิร์ตยามหนาว ความอบอุ่นเล็กๆ ในกระเป๋าค่อยๆ ละลายนิ้วมือที่แข็งเกร็ง มันคือความอ่อนโยนขนาดเท่าฝ่ามือที่ใครสักคนเขย่าให้อุ่นล่วงหน้า ด้วยคิดถึงเธอที่กำลังสั่นอยู่ในความหนาว"},"ICON-0113":{"nm":"ผ้าเช็ดหน้า","de":"ผ้าผืนเดียวที่รับทั้งน้ำตาและเหงื่อไว้โดยไม่บ่นสักคำ ลายปักเล็กๆ ที่มุมผ้ายังคงงดงามอยู่ตรงนั้น ราวกับคำอำลาสุดท้ายที่คนซึ่งจากไปก่อนทิ้งไว้ให้ ว่าอย่าลืมกันเลย"},"ICON-0114":{"nm":"สเปรย์","de":"ฉีดพรวดเดียวเนื้อสัมผัสของอากาศก็เปลี่ยนไปในพริบตา ทั้งหมอกที่ลอยฟุ้งเหนือเวที ทั้งต้นไม้ริมหน้าต่างยามเช้า ต่างกลายเป็นอีกโลกหนึ่งที่ระยิบระยับอยู่ชั่วครู่ในหยดน้ำเล็กจิ๋วเหล่านี้"},"ICON-0115":{"nm":"กระดาษทดกลิ่น","de":"การเลือกกลิ่นหอมนั้นคล้ายกับการเลือกความทรงจำอย่างประหลาด กลิ่นเพียงเส้นเดียวที่แตะปลายกระดาษบางๆ ค่อยๆ พาฤดูกาลที่คิดว่าลืมไปแล้วกลับมาสู่ปลายจมูกอีกครั้ง"},"ICON-0116":{"nm":"โต๊ะกินข้าว","de":"ในลายไม้ที่สึกทุกเส้น มีจำนวนมื้ออาหารที่เคยแบ่งปันกันสลักอยู่อย่างเงียบๆ ทั้งค่ำคืนที่เสียงหัวเราะดังสนั่น ทั้งดึกดื่นที่ต้องนั่งอยู่คนเดียว—โต๊ะสี่เหลี่ยมนี้รับไว้ทั้งหมดโดยไม่ปริปาก จนเป็นเงางาม"},"ICON-0117":{"nm":"ไจด้าย","de":"ดึงปลายด้ายเบาๆ มันก็คลายออกอย่างลื่นไหล เพียงเข็มเดียวก็ต่อกันได้อีกครั้ง การซ่อมแซมสิ่งที่ขาดสะบั้นมักเริ่มต้นอย่างเงียบๆ จากเส้นด้ายบางๆ เพียงเส้นเดียวเช่นนี้เสมอ"},"ICON-0118":{"nm":"เสื้อกันฝน","de":"แม้ในวันที่ฝนตกกระหน่ำ สิ่งที่ทำให้เรากล้าออกไปข้างนอกได้ในที่สุดก็คือเสื้อตัวนี้ มีเพียงคนที่รู้จักความสนุกของการเดินลุยฝนกระจายเป็นฟองเท่านั้น ที่จะไม่อ้างฝนเป็นข้ออ้างให้อยู่บ้าน"},"ICON-0119":{"nm":"ถุงผ้า","de":"รวบปากถุงให้เป็นวงกลม สิ่งที่อยู่ข้างในจึงปลอดภัยในที่สุด ในถุงเล็กๆ ที่มีรอยมือคุ้นเคยใบเดียว ทั้งเหรียญ ทั้งความทรงจำของวันหนึ่ง ทั้งคำพูดที่ไม่เคยพูดออกไปจนจบ ต่างแกว่งไกวอยู่ด้วยกัน"},"ICON-0120":{"nm":"ชั้นหนังสือ","de":"ลูบปลายนิ้วช้าๆ ไปตามสันหนังสือที่เรียงราย ฤดูกาลที่ผ่านมาก็สัมผัสได้ที่ปลายนิ้ว เหตุผลที่ทิ้งหนังสือเล่มที่อ่านจบแล้วไม่ลงคือ เพราะตัวเราในตอนนั้นยังคงมีชีวิตอยู่ที่นั่น"},"ICON-0121":{"nm":"กองหนังสือ","de":"หนังสือที่อ่านจบแล้วนอนตะแคงอยู่ข้างๆ ส่วนเล่มที่ยังไม่ได้อ่านก็ถูกวางซ้อนขึ้นไปเรื่อยๆ แม้คำสัญญาว่าสักวันจะอ่านให้หมดจะแกว่งไกวอยู่ใกล้เพดานเล็กน้อย แต่เพราะรักแม้กระทั่งความแกว่งไกวนั้น วันนี้จึงวางเพิ่มอีกเล่มหนึ่ง"},"ICON-0122":{"nm":"วงล้อวิ่ง","de":"แม้จะวิ่งสุดแรงแต่ดูเหมือนอยู่กับที่ ทว่าเท้าเล็กๆ นั้นกำลังฝึกจังหวะที่ปลายเท้าไปก่อนแล้ว วันวานที่ไม่เคยหยุดพักมารวมกัน แล้ววันหนึ่งก็จะส่องแสงเจิดจ้าบนเส้นทางจริง"},"ICON-0123":{"nm":"ผ้าคลุม","de":"เพื่อไม่ให้ฝุ่นจับ เพื่อไม่ให้แดดทำให้ซีดจาง—แม้แต่การคลุมผ้าไว้ก็ต้องใช้ความพิถีพิถันจากปลายนิ้ว ยิ่งเป็นสิ่งที่รักมากเท่าไร ก็ยิ่งได้รับการปกป้องอย่างอ่อนโยนในที่ที่มองไม่เห็นมากเท่านั้น"},"ICON-0124":{"nm":"ไหมพรม","de":"เส้นด้ายเส้นเดียวที่คลี่ออกกลิ้งมาจากตักคุณยาย แม้ดูเหมือนพันกันยุ่งเหยิง แต่พอหาปลายเจอแล้วดึงเบาๆ มันก็ตามมาไม่มีพลาด คืนฤดูหนาวจึงยาวขึ้นทีละฝีเข็มเช่นนั้น"},"ICON-0125":{"nm":"กระเป๋าใส่ของ","de":"ลิปบาล์ม ยางรัดผม จดหมายที่พับไว้อย่างเรียบร้อยหนึ่งฉบับ—แม้ดูเล็ก แต่ข้างในนั้นบรรจุหัวใจของทั้งวันเอาไว้ พร้อมกับเสียงซิปที่รูดปิด ของกระจุกกระจิกอันมีค่าทั้งหมดก็ปลอดภัยไปพร้อมกัน"},"ICON-0126":{"nm":"ที่วางแขน","de":"บ่ายวันที่หลับไปกลางคันขณะอ่านหนังสือ ค่ำคืนที่เดินวนไปมาระหว่างคุยโทรศัพท์ ในจุดที่ยิ่งนั่งนานยิ่งมีร่องรอยการใช้งานลึกขึ้น การพักผ่อนทุกครั้งที่ข้อศอกจดจำได้ก็ค่อยๆ สะสมอยู่อย่างเงียบสงบเท่าฝ่ามือ"},"ICON-0127":{"nm":"ซอง","de":"ก่อนจะฉีกออก มันยังไม่เป็นของใคร ในซองที่ปิดผนึกไว้เต็มไปด้วยความคาดหวังที่ยังไม่เปิดออก จนปลายนิ้วที่จับมุมซองสั่นไหวเบาๆ นั่นแหละคือความตื่นเต้นของการเปิดกล่อง"},"ICON-0128":{"nm":"กระดาษห่อของขวัญ","de":"หัวใจที่มาถึงก่อนของขวัญหนึ่งก้าวเสมอ ระหว่างที่พับมุมกระดาษให้เข้ากันแล้วผูกด้วยริบบิ้น ใบหน้ายิ้มของคนที่จะได้รับก็ค่อยๆ คลี่บานสดใสอยู่ในมือล่วงหน้าแล้ว"},"ICON-0129":{"nm":"เกมแพด","de":"ปุ่มกดที่นิ้วโป้งจดจำได้ก่อนสมองเสียอีก แพ้แล้วก็ยังขออีกตาหนึ่ง—และตานั้นแหละที่ทำให้ตื่นอยู่ทั้งคืนในที่สุด น้ำหนักที่พอดีมือยกการผจญภัยของค่ำคืนนี้ขึ้นอย่างเงียบๆ"},"ICON-0130":{"nm":"สัญญาณไฟจราจร","de":"สีแดงคือหยุดสักครู่ สีเขียวคือไปได้แล้วตอนนี้ ด้วยคำสัญญาง่ายๆ เพียงข้อเดียว ถนนนับไม่ถ้วนจึงไหลไปโดยไม่พันกันยุ่งเหยิง แม้แต่การรอคอยก็มีลำดับของมัน ไฟที่กะพริบบอกเราอย่างอ่อนโยน"},"ICON-0131":{"nm":"ลูกศร","de":"รูปทรงที่อ่อนโยนที่สุดสำหรับคนที่หลงทาง เมื่อไม่รู้จะไปทางไหนจนใจว้าวุ่น ทิศทางหนึ่งที่ใครสักคนขีดไว้ก่อนหน้า ทำให้ย่างก้าวที่หยุดชะงักกลับมามั่นคงอีกครั้ง"},"ICON-0132":{"nm":"พิกัด","de":"แค่ตัวเลขสองตัวก็ชี้จุดใดในโลกก็ได้ ทั้งจุดนัดพบ ทั้งชายหาดที่ฝังสมบัติเอาไว้ เพื่อไม่ให้คำสัญญาหลงทาง จุดเล็กๆ จุดหนึ่งจะยึดมันไว้จนถึงที่สุด"},"ICON-0133":{"nm":"กระเบื้อง","de":"อยู่ตามลำพังมันก็เป็นแค่ชิ้นสี่เหลี่ยมชิ้นหนึ่ง แต่เมื่อนอนเรียงชิดไหล่กัน มันก็กลายเป็นพื้นและเป็นผนัง สิ่งเล็กๆ มารวมกัน สร้างที่ที่ใครสักคนจะวางเท้าได้อย่างสบายใจ"},"ICON-0134":{"nm":"นาฬิกาทราย","de":"เมื่อช่องบนว่างเปล่า ช่องล่างก็ค่อยๆ เต็มขึ้นช้าๆ มองเม็ดทรายไหลรินลงมาอย่างแผ่วเบา เราจึงเชื่อว่าเวลากำลังเคลื่อนไป พลิกกลับก็เริ่มต้นใหม่อีกครั้ง—นั่นคือคำโกหกอันอ่อนโยนของเม็ดทราย"},"ICON-0135":{"nm":"ลูกบอล","de":"โยนไปก็กลับมา เตะไปก็กลิ้งออก ความกลมที่ไม่มีใครรู้ว่าจะเด้งไปทางไหนคือเสน่ห์ที่สุดของมัน กลางสนามเด็กเล่น เสียงหัวเราะเริ่มต้นเป็นวงกลมจากทรงกลมเล็กๆ นี้เสมอมา"},"ICON-0136":{"nm":"สวิตช์","de":"คลิก เปิดในทีเดียว ปิดในทีเดียว เสียงเล็กๆ ที่กดตอนก้าวเข้าห้องมืดนั้น แบ่งจุดเริ่มต้นและจุดจบของวันที่กระจัดกระจายให้เป็นเส้นเดียวที่ชัดเจน"},"ICON-0137":{"nm":"เครื่องหมายคำถาม","de":"การไม่รู้คำตอบไม่ใช่เรื่องน่าอาย เพราะมันคือหลักฐานอันน่ายินดีว่าความอยากรู้ยังมีชีวิตอยู่ เมื่อตะขอเล็กๆ นี้เคาะเบาๆ ในหัว การเรียนรู้ก็เพิ่งจะก้าวเท้าแรกออกไป"},"ICON-0138":{"nm":"ไม้ขีดไฟ","de":"ไม้ขีดไฟก้านหนึ่งที่ขีดตัวเองเพื่อส่งต่อไฟให้ แม้จะลุกไหม้เพียงสั้นๆ แล้วดับหายไปอย่างเงียบเชียบ แต่ในช่วงเวลาสั้นๆ นั้น เทียนก็ถูกจุดและเตาไฟก็อุ่นขึ้น การให้เล็กๆ นี้กลายเป็นกระดุมเม็ดแรกของความอบอุ่น"},"ICON-0139":{"nm":"ม้านั่งบันได","de":"ขึ้นไปเพียงก้าวเดียวมือก็เอื้อมถึงชั้นวางที่เคยเอื้อมไม่ถึง มันคือการยืดความสูงของใครสักคนไว้ชั่วขณะ ที่แห่งนี้ก้มตัวต่ำอย่างอ่อนโยนเพื่อยกเราให้สูงขึ้น"},"ICON-0140":{"nm":"นาฬิกาข้อมือ","de":"สิ่งแรกที่คาดข้อมือในวันที่ตั้งใจจะออกกำลังกาย โค้ชตัวจิ๋วที่นับจังหวะหัวใจและก้าวเดินให้เรา เคาะเบาๆ บอกเราว่าวันนี้เดินมากกว่าเมื่อวานอีกนิดหน่อยแล้ว"},"ICON-0141":{"nm":"นาฬิกาปลุก","de":"เพื่อนที่ซื่อสัตย์ที่สุดที่ถูกเกลียดทุกเช้า ด้วยที่มันคอยต่อสู้กับสิ่งล่อใจแค่ห้านาทีใต้ผ้าห่มแทนเราทุกครั้ง ทั้งนัดหมายและความฝันจึงไม่มาสาย เสียงที่ดังแสนใจร้ายนั้น แท้จริงแล้วคือเสียงเชียร์"},"ICON-0142":{"nm":"แก่นกลาง","de":"ส่วนในสุดที่หลงเหลืออยู่จนถึงที่สุด เมื่อลอกเปลือกนอกออกจนหมด เมล็ดของแอปเปิล ความจริงใจของหัวใจ—ไม่ว่าจะเป็นสิ่งใด ตรงกลางที่สุดของมันคือสิ่งที่แข็งแกร่งที่สุดเสมอ เป็นจุดเดียวที่หลงเหลืออยู่ในที่สุด แม้จะถูกเขย่าก็ตาม"},"ICON-0143":{"nm":"ปากกา","de":"รอยเปื้อนที่แผ่เลอะสันมือก่อนหมึกจะแห้ง ไม่ว่าจะเขียนลื่นหรือเขียนฝืด เส้นแรกที่ลากลงบนกระดาษขาวย่อมต้องใช้ความกล้าเล็กๆ เสมอ มันคือสะพานที่ความคิดข้ามมาสู่ปลายนิ้ว"},"ICON-0144":{"nm":"พู่กัน","de":"เมื่ออมหมึกแล้วเคลื่อนผ่านกระดาษฮันจี แม้แต่ความสั่นไหวลังเลเพียงครั้งเดียวก็ยังคงอยู่ครบถ้วน หากโลภอยากเขียนให้เร็วก็จะถูกจับได้ทันที พู่กันคือสิ่งแรกที่รู้ถึงความซื่อสัตย์ที่สถิตอยู่ในปลายนิ้ว"},"ICON-0145":{"nm":"บอลลูนคำพูด","de":"ก่อนคำพูดจะหลุดออกจากปากไป มันคือที่ที่ลอยขึ้นเป็นวงกลมเหนือศีรษะก่อน คำพูดที่อยากบอกถูกบรรจุไว้ตรงนี้ เมื่อยังว่างเปล่าอยู่ นั่นแปลว่ากำลังเลือกอยู่ว่าจะเติมคำอะไรลงไป"},"ICON-0146":{"nm":"ช่องกาเครื่องหมาย","de":"ขีดเส้นสองเส้นลงในช่องสี่เหลี่ยมว่างเปล่า ใจก็เบาขึ้นทันที มันคือเหรียญตราเล็กๆ ที่มอบให้ตัวเองสำหรับงานที่เสร็จสิ้น ปลายวัน มองช่องที่ถูกกาเต็มแล้ว เราก็อุ่นใจว่าวันนี้ก็ใช้ชีวิตได้ดีอีกวันหนึ่ง"},"ICON-0147":{"nm":"แท็บเล็ต","de":"ภาพวาดแผ่ขยายและตัวอักษรไหลลื่นไปตามที่นิ้วสัมผัส วางไว้เงียบๆ บนตัก โลกทั้งใบก็สว่างไสวขึ้น แม้จะเบา แต่ความเป็นไปได้ที่บรรจุอยู่ข้างในนั้นไม่เคยบางเบาเลย"},"ICON-0148":{"nm":"รีโมทคอนโทรล","de":"มันมีพรสวรรค์ในการซ่อนตัวตามซอกโซฟา อำนาจในการเปลี่ยนช่องเป็นของคนที่ถือมันไว้เสมอ การทะเลาะกันเล็กๆ ที่น่ารักที่สุดในครอบครัวมักเกิดขึ้นบนพื้นที่ขนาดเท่าฝ่ามือนี้เอง"},"ICON-0149":{"nm":"ลูกตุ้มถ่วง","de":"น้ำหนักที่ลดตัวเองลงไปอยู่ต่ำที่สุดเพื่อพยุงสิ่งที่แกว่งไกว ต่อให้ด้านบนโคลงเคลงแค่ไหน แต่ถ้าด้านล่างหนักแน่น สุดท้ายมันก็จะไม่ล้มลง ความสมดุลยืนหยัดอยู่ในที่ที่มองไม่เห็นเสมอ"},"ICON-0150":{"nm":"จิ๊กซอว์","de":"คืนที่ล้วงมือหาแม้กระทั่งใต้โซฟาเพื่อตามหาชิ้นสุดท้าย ความสุขไร้เสียงในวินาทีที่มันสวมพอดิบพอดี เมื่อสิ่งที่กระจัดกระจายกลับมาอยู่ในที่ของตัวเอง ภาพนั้นก็สมบูรณ์ในที่สุด"},"ICON-0151":{"nm":"ไม้บรรทัด","de":"การวัดความยาวก็เป็นการรักษาสัญญาอย่างหนึ่งเช่นกัน เพื่อให้หนึ่งคืบเท่ากันสำหรับทุกคน ขีดสเกลจึงเรียงแถวกันอย่างซื่อสัตย์ เส้นตรงเพียงเส้นเดียวสามารถทำให้แม้แต่หัวใจที่บิดเบี้ยวเรียบตรงขึ้นได้"},"ICON-0152":{"nm":"ผ้าใบ","de":"พื้นผิวสีขาวที่ไม่มีอะไรเลยนั้นน่ากลัวที่สุด และก็ตื่นเต้นที่สุดในเวลาเดียวกัน เพราะก่อนจุดแรกจะถูกวาดลง มันสามารถกลายเป็นอะไรก็ได้ ความว่างเปล่าไม่ใช่จุดจบ แต่เป็นอีกชื่อหนึ่งของจุดเริ่มต้น"},"ICON-0153":{"nm":"คิวบ์","de":"คนที่นอนดึกทั้งคืนเพื่อจัดให้ครบทั้งหกด้านมีไม่น้อยเลย ความมุ่งมั่นดื้อรั้นของปลายนิ้วที่หมุนแล้วหมุนอีก ในวินาทีที่สีที่สับสนวุ่นวายกลับไปอยู่ในตำแหน่งของมัน จักรวาลเล็กๆ ก็เรียบร้อยเป็นระเบียบ"},"ICON-0154":{"nm":"เครื่องเกมพกพา","de":"จอเล็กๆ ที่เคยก้มหน้าก้มตามองพร้อมกับญาติพี่น้องในวันปิดเทอม โลกแห่งการผจญภัยที่พอดีอยู่ในฝ่ามือ เพียงได้ยินเสียงเปิดเครื่องท่อนเดียวก็เหมือนได้ฤดูร้อนของช่วงเวลานั้นกลับคืนมาทั้งหมด"},"ICON-0155":{"nm":"ที่จับ","de":"ความรู้สึกที่มันแนบสนิทเข้ากับมือเมื่อกำแน่น ค่อยๆ มอบความมั่นใจให้เราอย่างเงียบๆ เพื่อไม่ให้ลื่นไถล เพื่อไม่ให้หลุดมือ ในวินาทีที่สำคัญที่สุด มันคือจุดเชื่อมที่ผูกมือและเครื่องมือให้เป็นหนึ่งเดียวอย่างมั่นคง"},"ICON-0156":{"nm":"ปากกาหมึกซึม","de":"ขณะเติมหมึกแล้วเขียน แม้แต่ลายมือก็ยังดูเรียบร้อยขึ้นอีกนิด สงบใจไปกับเสียงปลายปากกาที่ขูดเสียดสี มันคล้ายกับความพิถีพิถันในการเริ่มบรรทัดแรกของจดหมายที่เขียนด้วยลายมืออย่างช้าๆ"},"ICON-0157":{"nm":"จานสี","de":"สีแดงข้างสีน้ำเงิน สีเขียวเหนือสีเหลือง บนแผ่นเล็กๆ ที่สีต่างๆ นอนเรียงกันเป็นระเบียบนี้ ภาพวาดจึงได้รับสีหน้าเป็นครั้งแรก การผจญภัยของการผสมและแต้มสีทั้งหมดเริ่มก้าวแรกที่นี่"},"ICON-0158":{"nm":"ชุด","de":"แต่ละชิ้นอาจดูธรรมดา แต่เมื่อมารวมกันเป็นแถวก็กลายเป็นเรื่องราวหนึ่งเรื่อง ความอุ่นใจเมื่อครบถ้วนไม่ขาดชิ้นใดไป การรวบรวมสิ่งที่กระจัดกระจายไว้ในที่เดียวนั้น แฝงไปด้วยความสุขเล็กๆ ของความสมบูรณ์"},"ICON-0159":{"nm":"ลูกขนไก่","de":"เสียงลมแผ่วนุ่มที่ขนนกส่งเสียงตอนพุ่งขึ้นจากไม้แร็กเกต แม้ดูเบาจนคิดว่าคงไปได้ไม่ไกล แต่ถ้าตีด้วยความตั้งใจ มันจะพุ่งตรงไปจนสุดขอบสนาม ความเบานั้นก็เป็นพลังอย่างหนึ่งเช่นกัน"},"ICON-0160":{"nm":"เสาอากาศ","de":"มันยืนนิ่งหันหน้าสู่ท้องฟ้าเพื่อจับสัญญาณที่มองไม่เห็น ความอดทนที่ดึงแม้แต่เสียงจากที่ไกลแสนไกลเข้ามาได้ในที่สุด วันที่รับสัญญาณไม่ค่อยชัด แค่ปรับมุมนิดหน่อยมันก็ชัดเจนขึ้นอีกครั้ง"},"ICON-0161":{"nm":"หูฟังแพทย์","de":"ปลายกลมเย็นเฉียบที่แนบอก และลมหายใจที่หยุดนิ่งชั่วครู่ รวมสมาธิที่หูไปกับเสียงกลองเล็กๆ เพียงจังหวะเดียว จังหวะที่เก่าแก่ที่สุดของการมีชีวิตอยู่ก็ส่งผ่านมาถึงปลายนิ้ว เครื่องมือที่การฟังมาก่อนสิ่งใด"},"ICON-0162":{"nm":"เบี้ยหมากรุก","de":"หมากตัวเล็กที่เดินช้าๆ ทีละช่องเท่านั้น แต่เมื่อถึงแถวสุดท้ายมันสามารถกลายเป็นอะไรก็ได้ กระดานหมากรุกเก่าเฝ้ามองอย่างเงียบๆ กับการเดินหมากเพียงตาเดียวที่พลิกทั้งกระดานด้วยย่างก้าวอันเชื่องช้านั้น"},"ICON-0163":{"nm":"จอยเกม","de":"จำคืนที่ท่องจักรวาลด้วยนิ้วโป้งสองนิ้วได้ไหม ด้ามจับที่มีรอยมือคุ้นเคยที่เคยโยนทิ้งตอนแพ้แล้วเก้อเขินหยิบกลับมาอีกครั้ง บทสนทนาที่ยาวนานและอบอุ่นที่สุดที่แบ่งปันกับใครสักคนข้ามหน้าจอโดยไม่ต้องพูดสักคำ"},"ICON-0164":{"nm":"เครื่องเกมคอนโซล","de":"เปิดสวิตช์แล้วเสียงบูตเล็กๆ ก็ดังขึ้นราวกับคำทักทาย กล่องสี่เหลี่ยมที่เปิดปิดอยู่ใต้ผ้าห่มตลอดวันปิดเทอม การผจญภัยครั้งแรกในวัยเด็กเริ่มต้นจากแสงของจอนี้เสมอ"},"ICON-0165":{"nm":"เส้นเวลา","de":"ปลายซ้ายคือจุดเริ่มต้น ปลายขวาคือวันที่ยังมาไม่ถึง ลากจุดหนึ่งไปวางไว้ตรงไหนก็ได้ระหว่างนั้น ช่วงเวลาที่คิดว่าลืมไปแล้วก็คลี่กลับมาอีกครั้ง มันคือที่ที่วางเวลาให้นอนเรียงเป็นเส้นเดียว"},"ICON-0166":{"nm":"ปริซึม","de":"ใครจะคิดว่าแสงที่ดูใสสะอาดนั้น แท้จริงแล้วซ่อนสีทั้งเจ็ดไว้ในตัว ความลับที่คลี่คลายเป็นสายรุ้งในวินาทีที่ผ่านแก้วชิ้นเล็กๆ ยิ่งสิ่งใดดูเรียบง่าย ยิ่งซ่อนสีสันมากมายไว้ข้างในมากเท่านั้น"},"ICON-0167":{"nm":"ทีกอล์ฟ","de":"แท่นเล็กๆ แท่นหนึ่งสำหรับวางลูกบอลไว้เงียบๆ ยิ่งอยากส่งลูกไปไกลเท่าไร ก็ยิ่งต้องการบางสิ่งที่รองรับมันไว้อย่างมั่นคงก่อนเสมอ หมุดเล็กจิ๋วบนสนามหญ้านี้ค้ำจุนก้าวแรกเอาไว้"},"ICON-0168":{"nm":"เข็มถักไหมพรม","de":"หนึ่งฝีเข็ม แล้วอีกหนึ่งฝีเข็ม พลาดไปเพียงเข็มเดียวก็ต้องคลายออกทั้งหมดแล้วเริ่มใหม่ตั้งแต่ต้น ผ้าพันคอที่ค่อยๆ ยาวขึ้นบนตักตลอดฤดูหนาว คือที่ที่ความอดทนของปลายนิ้วถูกถักทอเป็นความอบอุ่น"},"ICON-0169":{"nm":"ท่อนทำนอง","de":"ก่อนเนื้อเพลงจะถูกใส่ลงไป ท่อนสั้นๆ ที่รั่วไหลออกจากริมฝีปากเป็นเสียงฮัมเบาๆ ในทำนองพร่าเลือนที่ยังไม่มีตัวอักษรติดอยู่นั้น มีใบหน้าแรกที่จริงใจที่สุดของบทเพลงซ่อนอยู่"},"ICON-0170":{"nm":"เรดาร์","de":"มันยิงสัญญาณไปสู่ความมืดที่มองไม่เห็น แล้วรอคอยจุดที่จะสะท้อนกลับมาอย่างเงียบๆ แม้จะมองไม่เห็นอะไรเลย แต่ก็เชื่อว่ามีบางสิ่งอยู่ตรงนั้น ความอดทนของแสงสีเขียวทรงกลม"},"ICON-0171":{"nm":"แผ่นจังหวะ","de":"แตะเบาๆ แสงและเสียงก็กระเด้งขึ้นพร้อมกันในทันที มันคือที่ที่ทำให้มือจดจำจังหวะได้ก่อนหัวจะทันคิด เวทีที่เล็กที่สุดและอ่อนโยนที่สุดที่กางกว้างอยู่บนฝ่ามือ"},"ICON-0172":{"nm":"สีวาดภาพ","de":"ช่างวาดในสมัยก่อนบดหินและดินเพื่อให้ได้สีสัน สีครามได้จากพืช สีแดงได้จากดิน แม้แต่หยดสีที่บีบออกมาที่ปลายนิ้วในตอนนี้ ก็ยังไหลเวียนไปด้วยความพิถีพิถันโบราณที่เคยถ่ายทอดธรรมชาติลงในภาชนะอย่างทะนุถนอม"},"ICON-0173":{"nm":"เส้น","de":"สิ่งที่เกิดขึ้นในวินาทีที่ตัดสินใจเชื่อมจุดหนึ่งเข้ากับอีกจุดหนึ่งเท่านั้น ไม่ว่าสั้นหรือยาว โค้งหรือตรง มันคือร่องรอยที่เรียบง่ายที่สุดที่ความปรารถนาจะไปที่ไหนสักแห่งทิ้งเอาไว้ จุดเริ่มต้นของภาพทุกภาพ"},"ICON-0174":{"nm":"ชัตเตอร์","de":"แชะ ความมืดสั้นๆ เพียงครั้งเดียวนั้นกักฉากหนึ่งไว้ตลอดกาล แม้แต่สีหน้าที่เกือบจะปล่อยผ่านไปในพริบตา ก็ยังถูกตัดแสงเล็กน้อยและตกผลึกเป็นความทรงจำ มันคือใบมีดเล็กๆ"},"ICON-0175":{"nm":"เชือกนิรภัย","de":"เชือกที่ถูกผูกไว้อย่างแน่นหนาล่วงหน้าก่อนคนที่กำลังปีนขึ้นที่สูงเสมอ มันยึดหัวใจที่หวาดหวั่นว่าจะตกลงมาไว้แทนเรา คอยเฝ้าข้างกายเราโดยไม่ให้เห็น สายเชือกแห่งคำสัญญาที่อยู่ข้างหลังเราเสมอ"},"ICON-0176":{"nm":"กุญแจล็อก","de":"กุญแจเหล็กหนักอึ้งที่เคยล็อกไว้ที่ยุ้งฉาง มันไม่ใช่เพื่อกักขังสิ่งใด แต่เป็นความปรารถนาที่จะเก็บของมีค่าไว้อย่างอุ่นใจ แม้แต่มือที่ล็อกก็ยังแฝงความพิถีพิถัน ความมั่นคงของบ้านเก่า"},"ICON-0177":{"nm":"ตาชั่ง","de":"ด้านหนึ่งหนักขึ้น อีกด้านก็เบาลงเองโดยธรรมชาติ ในวินาทีที่ลังเลว่าจะวางอะไรลงไปเท่าไร คนเราจึงเรียนรู้ความเป็นธรรม แขนทั้งสองข้างที่โคลงเคลงไปมาสอนเรื่องความสมดุล"},"ICON-0178":{"nm":"เครื่องมือผ่า","de":"แม้สิ่งที่เชื่อมติดกันแน่น หากตามแนวเสี้ยนไปก็แตกออกได้ในที่สุด มันคือเครื่องมือเล็กๆ ที่แบ่งสิ่งใดก็ตามออกเป็นสองส่วนเพื่อมองเข้าไปข้างใน ปลายนิ้วที่อยากรู้อยากเห็นที่ปรารถนาจะแยกสิ่งที่ประกอบกันแล้วออกมาดูอีกครั้ง"},"ICON-0179":{"nm":"เครื่องนับ","de":"หนึ่ง สอง สาม เพื่อนตัวเล็กที่นับตัวเลขแทนนิ้วมือเราอย่างเงียบๆ เพื่อนคู่ใจในการนับเลขที่เปลี่ยนหัวใจที่กังวลว่าจะนับตกไปให้กลายเป็นความอุ่นใจทีละคลิก"},"ICON-0180":{"nm":"เคอร์เซอร์","de":"ลูกศรเล็กๆ ที่กะพริบอยู่ตรงไหนสักแห่งบนหน้าจอ รอคำสั่งถัดไป แม้ในตอนที่เรายังลังเล มันก็ไม่เคยละจากตำแหน่งนั้น ปลายแสงที่กวักมือเรียกอย่างเงียบๆ ว่าเริ่มกันเถอะตอนนี้"},"ICON-0181":{"nm":"จุดจับปีนผา","de":"จุดสุดท้ายที่คว้าไว้ก่อนแรงที่ปลายนิ้วจะหมดลง มีบางช่วงเวลาที่เราอดทนอยู่ได้ด้วยใจเดียวที่ไม่ยอมปล่อยมือ ปุ่มเล็กๆ บนกำแพงบอกเราอย่างเงียบๆ ว่าเป็นเช่นนั้นจริง"},"ICON-0182":{"nm":"หินก้อนกลม","de":"หินที่กลิ้งอยู่ในลำธารมาเนิ่นนาน จนสละมุมเหลี่ยมทั้งหมดของตัวเองไป ความกลมมนคืออีกชื่อหนึ่งของกาลเวลาที่ถูกกัดเซาะไป กำไว้เบาๆ ในฝ่ามือ ก็สัมผัสได้ถึงความอดทนของสายน้ำที่เคยไหลผ่าน"},"ICON-0183":{"nm":"ตราประจำตระกูล","de":"ตระกูลเก่าแกะสลักสัตว์และดวงดาวลงบนธงผืนหนึ่งเพื่อบอกให้รู้จักตัวตน มันคือภาพที่ส่งมอบหัวใจก่อนคำพูดเสียอีก เครื่องหมายโบราณที่บีบอัดศักดิ์ศรีของคนคนหนึ่งไว้อย่างประณีตในกรอบเล็กๆ"},"ICON-0184":{"nm":"โล่","de":"การยืนกั้นขวางไว้เสมอเป็นเรื่องเพื่อคนที่อยู่ข้างหลังเรา รับลูกธนูที่พุ่งเข้ามาแทน เพื่อปกป้องวันธรรมดาของใครสักคนไว้ กำแพงที่หนักอึ้งแต่แฝงไว้ด้วยความอ่อนโยน"},"ICON-0185":{"nm":"การคืนชีพ","de":"มีหัวใจบางดวงที่ดับไปแล้วก็สว่างขึ้นมาใหม่ได้ วิธีลุกขึ้นยืนอีกครั้งเป็นสิ่งที่จะเข้าใจได้ก็ต่อเมื่อเคยล้มลงมาแล้วเท่านั้น ลมหายใจครั้งที่สองที่ค่อยๆ พวยพุ่งขึ้นอย่างเงียบๆ ในที่ที่คิดว่าคือจุดจบนั่นเอง"},"ICON-0186":{"nm":"ธนู","de":"มือที่ตั้งใจจะส่งไปให้ไกลจะดึงสายธนูกลับมาจนสุดก่อนเสมอ หากจะปล่อยไป ก็ต้องกอดมันไว้ใกล้ตัวมากเท่านั้นก่อน คันธนูที่โค้งตึงบอกเราอย่างเงียบๆ โดยไม่ต้องพูดสักคำ"},"ICON-0187":{"nm":"รูปหัวใจ","de":"คำว่าชอบมักหดเล็กลงเรื่อยๆ จนกลายเป็นรูปทรงเล็กๆ ทั้งที่ปลายไฟแท่งเชียร์ ทั้งระหว่างนิ้วที่แตะประกบกัน รูปทรงนี้ถูกวาดขึ้นอย่างแอบแฝงเสมอ มันคือคำย่อที่ธรรมดาและจริงใจที่สุดของหัวใจ"},"ICON-0188":{"nm":"ก้อนเมฆ","de":"ล่องลอยไปทางลมพัดอย่างช้าๆ กลายเป็นใบหน้าที่ต่างกันไปในทุกครั้ง เป็นกระต่ายบ้าง เป็นปุยฝ้ายบ้าง ไม่ยึดติดสิ่งใดไว้นาน ปล่อยทุกสิ่งให้ผ่านไป มันคือหัวใจที่เบาที่สุดของท้องฟ้า"},"ICON-0189":{"nm":"เขาวงกต","de":"ที่ที่เราเรียนรู้วิธีหันหลังกลับจากกำแพงตัน แม้ในระหว่างที่หลงทาง ย่างก้าวของเราก็ค่อยๆ เติบโตไปสู่ทางออกทีละนิด ต้องหลงทางสักครั้งเท่านั้นถึงจะมีสัญชาตญาณในการหาทาง"},"ICON-0190":{"nm":"ฟันน้ำนม","de":"เคยมีธรรมเนียมที่โยนฟันที่หลุดขึ้นไปบนหลังคาบ้าน เป็นคำอธิษฐานเล็กๆ ให้ฟันซี่ใหม่ขึ้นมาตรงๆ คำสัญญาอันอ่อนโยนแห่งวัยเด็กที่ว่าต้องสูญเสียบางสิ่งไปสักครั้งขณะเติบโต จึงจะได้สิ่งที่แข็งแกร่งกว่ามา"},"ICON-0191":{"nm":"ดาวเคราะห์","de":"ร่างกลมที่โคจรรอบดวงดาวโดยไม่เคยหลุดออกจากวิถีของตัวเองเลยสักครั้ง แม้ดูโดดเดี่ยว แต่แรงโน้มถ่วงของมันก็ทำให้มีบางสิ่งหมุนอยู่เคียงข้างเสมอ การรักษาตำแหน่งของตัวเองอย่างเงียบๆ กลายเป็นโลกใบหนึ่งในตัวมันเอง"},"ICON-0192":{"nm":"ดวงดาว","de":"ในคืนที่หลงทาง ผู้คนเงยหน้ามองจุดที่สว่างที่สุดเสมอ แสงที่ไกลเกินเอื้อมถึง แต่ก็บอกทิศทางได้อย่างชัดเจน คำสัญญาที่ยิ่งมั่นคงขึ้นเพราะเหตุผลที่ว่ามันอยู่ไกลแสนไกล"},"ICON-0193":{"nm":"เงาดำ","de":"ยืนหันหลังให้แสง คนเราก็เหลือเพียงเส้นรอบนอก รูปทรงสีดำหนึ่งรูปที่ทั้งชื่อและสีหน้าถูกลบเลือนไป พื้นที่ที่ไม่ถูกเติมเต็มกลับยิ่งทำให้จินตนาการล่องลอยไปได้ไกลกว่า เพราะความว่างเปล่านั้นเอง"},"ICON-0194":{"nm":"หู","de":"จะร้องเพลงเก่งได้ต้องฟังเก่งก่อน ทั้งจังหวะและหัวใจ สุดท้ายแล้วล้วนเริ่มต้นจากการฟังทั้งสิ้น ประตูเล็กๆ ที่เปิดเป็นวงกลม ที่เสียงทุกเสียงในโลกมาถึงและพักพิงเป็นแห่งแรก"},"ICON-0195":{"nm":"ใบไม้ร่วง","de":"มีใบไม้บางใบที่เปล่งประกายงดงามที่สุดในวินาทีที่ร่วงหล่นลงมา ความเบาสบายของการเผาความเขียวขจีแห่งฤดูกาลหนึ่งให้เป็นสีแดงจนหมดแล้ววางลงอย่างแผ่วเบา ฤดูใบไม้ร่วงแสดงให้เห็นว่าแม้แต่การจบลงก็งดงามได้ถึงเพียงนี้"},"ICON-0196":{"nm":"พระจันทร์","de":"เคยมีคืนที่พนมมือทั้งสองอธิษฐานใต้แสงกลมของวันเพ็ญเดือนแปด ใบหน้าที่ไม่เคยเหมือนเดิมสักครั้งแม้จะขึ้นเต็มดวงและแหว่งเว้าซ้ำแล้วซ้ำเล่า โคมไฟที่แม้จะเปลี่ยนแปลง แต่ก็ยังส่องสว่างที่จุดเดิมเสมอ"},"ICON-0197":{"nm":"หัวใจ","de":"แม้บนเวที สิ่งที่ซื่อสัตย์ที่สุดสุดท้ายแล้วก็คือการเต้นของหัวใจดวงนี้ แม้สั่นไหวก็ไม่เคยหยุด ยิ่งซาบซึ้งก็ยิ่งเต้นแรงขึ้น กลองสีแดงเล็กๆ ที่เต้นตุบตับแทนคำเชียร์ที่คำพูดบอกไม่หมด"},"ICON-0198":{"nm":"เงา","de":"เพื่อนร่วมทางที่ไม่เคยหลุดจากไป ตราบใดที่ยังมีแสงอยู่ ยิ่งสว่างก็ยิ่งเข้ม ยิ่งมัวก็ยิ่งจาง มันคืออีกตัวตนหนึ่งของฉันที่ติดตามฉันมายาวนานที่สุด คนคนเดียวที่ยืนเคียงข้างแม้ในวันที่โดดเดี่ยว"},"ICON-0199":{"nm":"หาง","de":"ดีใจก็แกว่งไปเอง กลัวก็ค่อยๆ หดม้วนเข้า แม้ปากจะปิดสนิท แต่ปลายหางที่ซื่อสัตย์นี้ก็ไม่อาจซ่อนหัวใจได้ในที่สุด มันคือความในใจที่ร่างกายรั่วไหลออกมาก่อนใคร"},"ICON-0200":{"nm":"เชือกผูกปลายหาง","de":"เชือกเส้นเล็กๆ ที่ผูกไว้ตรงปลายเพื่อปิดท้าย เหมือนกับแพรผูกผม หัวใจที่ผูกปมให้แน่นอีกครั้งเพื่อไม่ให้หลุดออก การผูกรัดที่อ่อนโยนซึ่งรวบรวมสิ่งที่มักกระจัดกระจายไว้ด้วยกันอย่างปลอบประโลม"},"ICON-0201":{"nm":"ลูกตาดำ","de":"คำพูดยังเลือกได้ แต่แสงตากลับซ่อนไม่ได้ ตรงจุดที่หัวใจซึ่งถูกจับได้รั่วไหลออกมาก่อนสิ่งใด คือวงกลมสีดำเล็ก ๆ นั้นเอง แม้จะกลืนคำว่า “ฉันชอบเธอ” เอาไว้ ลูกตาดำก็สั่นไหวมุ่งไปทางเธอเสียแล้ว"},"ICON-0202":{"nm":"เกือกม้า","de":"ชิ้นเหล็กที่แข็งแกร่งขึ้นทุกครั้งที่ปลายเท้าสึกกร่อนจากการวิ่งทางไกล เขาว่ากันว่าถ้าแขวนคว่ำไว้เหนือประตู โชคที่ผ่านไปมาจะขังอยู่ข้างใน มันคอยประคับประคองการกลับบ้านอย่างปลอดภัยของใครสักคนอยู่เงียบ ๆ"},"ICON-0203":{"nm":"หินสลักตรา","de":"แม้ลมฝนจะกัดกร่อนตัวอักษรจนเลือนราง แต่เมื่อสัมผัสด้วยปลายนิ้ว ร่องรอยที่แกะสลักไว้ก็กลับมามีชีวิตชัดเจนอีกครั้ง คือน้ำหนักของหัวใจดวงหนึ่งที่ไม่อยากถูกลืมเลือน หินก้อนนั้นจึงโอบอุ้มชื่อหนึ่งชื่อไว้ยาวนานเช่นนี้"},"ICON-0204":{"nm":"เท้าพังผืด","de":"ด้วยเยื่อบาง ๆ เพียงชั้นเดียวที่เชื่อมนิ้วเท้าเข้าด้วยกัน มันเรียนรู้วิธีพายน้ำ คือไม้พายเล็ก ๆ ที่ธรรมชาติแอบยื่นให้กับผู้ที่ว่ายน้ำไม่เก่ง แม้จะช้า แต่ก็เป็นการออกแบบอันอ่อนโยนที่พาไปถึงฝั่งตรงข้ามแม่น้ำได้ในที่สุด"},"ICON-0205":{"nm":"กากเพชร","de":"ทุกคนบ่นว่าถ้าติดมือแล้วจะติดตามไปอีกหลายวัน แต่พอถึงวันงานเลี้ยงกลับเป็นสิ่งแรกที่ทุกคนเอื้อมมือไปหยิบเม็ดแสงเล็ก ๆ นี้ โปรยผงดาวสักกำมือ กระดาษธรรมดาก็ระยิบระยับ และวันนี้ก็กลายเป็นวันพิเศษขึ้นมาทันที"},"ICON-0206":{"nm":"กรงเล็บ","de":"สัตว์ป่าในผืนป่าใช้กรงเล็บขีดข่วนดินเพื่อทิ้งเส้นทางของตัวเอง ไม่ใช่การข่มขู่ แต่เป็นร่องรอย ลายเซ็นเงียบ ๆ ที่บอกว่าเคยผ่านมาทางนี้ ปลายแหลมคมของมันบางครั้งก็กลายเป็นป้ายบอกทางอันอ่อนโยนสำหรับใครบางคน"},"ICON-0207":{"nm":"สายฟ้า","de":"ในชั่ววินาทีที่ท้องฟ้าคลี่เส้นลายมือออกมาชั่วครู่ แสงมาถึงก่อนเสียงฟ้าร้อง ราวกับบอกให้สูดลมหายใจสักครั้งก่อนเสียงดังจะมาถึง ความกลัวและความตื่นตะลึงเกิดขึ้นพร้อมกันเสมอจากแสงวาบเดียวกัน"},"ICON-0208":{"nm":"ยันต์","de":"หนึ่งบรรทัดแห่งคำอธิษฐานที่กดเขียนด้วยหมึกลงบนกระดาษสีแดงอย่างหนักแน่น เชื่อกันว่าถ้าสอดไว้ใต้หมอน ฝันร้ายจะเบี่ยงเบนออกไป หัวใจที่ภาวนาให้ใครสักคนปลอดภัย อบอุ่นได้ถึงเพียงนี้แม้เพียงกระดาษบาง ๆ แผ่นเดียว"},"ICON-0209":{"nm":"ปีกพู่กัน","de":"มีบางช่วงเวลาที่ปลายพู่กันกลายเป็นปีก ความเบาบางที่ร่อนลื่นไถลไปบนกระดาษเมื่อลากเส้นเพียงเส้นเดียว การเขียนตัวอักษรก็คือการบินไปในตัว มือเก่าแก่ที่เคยฝนหมึกคงรู้สึกได้ลาง ๆ ถึงเรื่องนี้"},"ICON-0210":{"nm":"กระดูก","de":"สิ่งที่หลงเหลืออยู่หลังเนื้อหนังสลายไปจนหมด โครงสีขาวที่ทนทานที่สุดจนถึงวินาทีสุดท้ายเพราะมันแข็งแกร่งที่สุด แม้เวลาจะพรากทุกสิ่งไปหมด แต่สุดท้ายมันยังจดจำรูปร่างไว้ได้ เป็นหลักฐานเงียบ ๆ เพียงชิ้นเดียว"},"ICON-0211":{"nm":"จมูก","de":"กลิ่นคือทางลัดที่เร็วที่สุดสู่ความทรงจำ กลิ่นน้ำมันในครัวยามเทศกาล อากาศเย็นของเช้าวันหลังหิมะแรกตก ปลายจมูกรับรู้ได้ก่อน แล้วหัวใจจึงตามมาช้ากว่าหนึ่งจังหวะ"},"ICON-0212":{"nm":"ขนมปังปิ้ง","de":"มื้อที่คว้าได้เร็วที่สุดในเช้าวันวุ่น ๆ กัดผิวขนมปังที่ปิ้งจนเหลืองกรอบ แล้วความกล้าของทั้งวันก็แตกกรอบออกมา สิ่งที่ไม่หรูหราแต่อิ่มท้อง คือสิ่งที่ทำให้คนลุกขึ้นยืนได้อีกครั้ง"},"ICON-0213":{"nm":"คุกกี้","de":"คนที่รอหน้าเตาอบนานที่สุดจะได้กัดคำแรก ความอุ่นของขอบคุกกี้ที่เพิ่งอบเสร็จ ความหวานสั้น ๆ ยิ่งอบไปพร้อมกับคิดถึงใครสักคน ยิ่งหวานขึ้นอย่างประหลาด"},"ICON-0214":{"nm":"ของว่าง","de":"ในบ่ายที่การซ้อมยืดยาว ถุงเล็ก ๆ ที่หยิบออกมาจากก้นกระเป๋า แบ่งครึ่งแล้วความอิ่มท้องกลับเพิ่มเป็นสองเท่าอย่างน่าประหลาด ความอ่อนโยนกำมือหนึ่งที่เติมเต็มหัวใจก่อนความหิว"},"ICON-0215":{"nm":"แคปซูล","de":"ไม่มีใครรู้ได้จนกว่าจะบิดเปิดออกดู สิ่งที่อยู่ในเปลือกกลม ๆ นั้นคือความตื่นเต้นแบบเดียวกันเสมอ เป็นความตื่นเต้นที่ซื่อสัตย์ที่สุดในโลก ที่ซื้อขายกันด้วยโอกาสเล็ก ๆ"},"ICON-0216":{"nm":"ลูกบิดประตู","de":"จุดที่มือนับไม่ถ้วนที่เปิดปิดประตูสัมผัสก่อนใคร คำทักทายแรกของบ้าน ที่เริ่มต้นเย็นเฉียบแล้วอุ่นขึ้นในฝ่ามือ ยิ่งคราบมือสะสมมากเท่าไร ห้องนั้นก็ค่อย ๆ กลายเป็นบ้านของใครสักคนมากขึ้นเท่านั้น"},"ICON-0217":{"nm":"การเดินเล่น","de":"แม้จะเดินโดยไม่มีจุดหมาย ก็ยังมีเหตุผลของมัน คือเวลาที่คลี่ความคิดที่พันกันออกทีละเส้นไปกับฝีเท้า เดินวนกลับมาแม้คำตอบจะยังเหมือนเดิม แต่หัวใจกลับเบาสบายขึ้นมาก"},"ICON-0218":{"nm":"สกู๊ตเตอร์","de":"สองล้อที่แล่นตัดผ่านตรอกแคบ ๆ แม้จะไม่เร็ว แต่ก็รับสายลมไว้เต็มตัว ต่อให้ไปได้ไม่ไกลก็ไม่เป็นไร วันนี้แค่อยากขี่ให้สดชื่นเท่านั้น มันมีวันแบบนั้นอยู่บ้าง"},"ICON-0219":{"nm":"บาร์นิรภัย","de":"ก่อนขึ้นนั่ง คานเหล็กแท่งหนึ่งที่เลื่อนลงมากอดอกอย่างมั่นคง คำสัญญาที่มั่นใจได้ว่าจะอยู่เคียงข้างจนผ่านพ้นช่วงเวลาที่น่ากลัวไปด้วยกัน มันบอกอย่างเงียบ ๆ เย็นชา ว่าจับให้แน่นได้เลย ไม่เป็นไร"},"ICON-0220":{"nm":"บันได","de":"ปีนขึ้นไปทีละขั้น แล้วไม่ทันรู้ตัวว่าทิวทัศน์เปลี่ยนไปแล้ว ฝ่าเท้าเรียนรู้ก่อนใครว่าไม่มีความสูงใดที่ไปถึงได้ในก้าวเดียว การขึ้นลงนั้นเอง คือฝีก้าวหนึ่งวันของใครบางคน"},"ICON-0221":{"nm":"เทอร์แรเรียม","de":"ไม่ใช่การขังป่าไว้ในแก้ว แต่คือการทะนุถนอมเลี้ยงดูโลกทั้งใบด้วยใจ จักรวาลขนาดเท่าฝ่ามือที่มอสส์แผ่ขยายและหยดน้ำเกาะพราว ยิ่งจ้องมองนานเท่าไร หัวใจก็ค่อย ๆ ถูกย้อมเป็นสีเขียวช้า ๆ"},"ICON-0222":{"nm":"แท่นยืน","de":"ปีนขึ้นไปยืนบนที่สูงขึ้นเพียงคืบเดียว ทิวทัศน์ที่เห็นก็เปลี่ยนไป คือที่ที่ความกลัวและความภาคภูมิใจมาบรรจบกันที่ระดับความสูงเดียวกัน ขึ้นอยู่กับว่าใครเป็นคนยืน ขั้นเดียวนั้นก็กลายเป็นเวทีที่แตกต่างกันไปทุกครั้ง"},"ICON-0223":{"nm":"เครื่องบิน","de":"วินาทีที่เมฆลาดอยู่ใต้ฝ่าเท้า ที่ที่จากมาจึงเริ่มเป็นที่คิดถึงในที่สุด ไม่ใช่การห่างไกลออกไป แต่โลกกำลังกว้างขึ้น แม้แต่ความฝันที่เติบโตบนเกาะเล็ก ๆ ก็ข้ามฟ้าไปได้เช่นนี้"},"ICON-0224":{"nm":"สเก็ตบอร์ด","de":"สิ่งของที่ต้องเรียนรู้วิธีล้มก่อน จึงจะขี่ได้จริง ทุกครั้งที่หัวเข่าถลอก การทรงตัวก็ค่อย ๆ สลักลงในร่างกายทีละนิด ล้อทั้งสี่ที่ซื่อสัตย์ ยิ่งล้มได้ดีเท่าไร ก็ยิ่งกลิ้งไปได้ไกลเท่านั้น"},"ICON-0225":{"nm":"พาสปอร์ต","de":"เปิดปกออกมาก็เจอหน้ากระดาษว่างเปล่าเต็มไปหมด ตราประทับแต่ละดวงที่จะถูกเติมเต็มลงไป คือหลักฐานของชีวิตที่ได้ใช้จริง หนังสือเล่มเล็กที่บรรจุความเป็นไปได้ที่จะไปได้ทุกที่ มากกว่าที่จะบอกว่าเคยไปที่ไหนมาแล้วบ้าง"},"ICON-0226":{"nm":"แผนที่มือวาด","de":"ไม่มีระยะทางหรือสัดส่วนที่แม่นยำ แต่เพราะเป็นเส้นทางที่วาดด้วยมือ จึงไม่ต้องกลัวหลงทางเลย กระดาษที่ตรอกซอกซอยและชื่อร้านค้าพันกันอย่างอบอุ่น คำแนะนำที่ใส่หัวใจลงไปนั้นอุ่นกว่าตัวถนนเองเสมอ"},"ICON-0227":{"nm":"ผังการเคลื่อนไหวบนเวที","de":"กระดาษที่วาดฝีก้าวบนเวทีแต่ละก้าวเป็นเส้น จะหยุดตรงไหน จะหมุนตรงไหน ลูกศรได้สัญญาไว้ล่วงหน้า แม้แต่การเต้นที่ดูอิสระ แท้จริงแล้วก็เริ่มต้นจากกระดาษแผ่นนี้แผ่นเดียว"},"ICON-0228":{"nm":"ใบนำทางที่นั่ง","de":"ในพื้นที่ที่ไม่คุ้นเคย สิ่งแรกที่คลำหาคือที่นั่งของตัวเอง ตามแถวและหมายเลขไปจนกระทั่งถึงช่องนั้นในที่สุด กระดาษแผ่นเดียวจัดวางความตื่นเต้นนับพันให้เรียบร้อยเข้าที่ทีละคน"},"ICON-0229":{"nm":"การ์ดนำทางตรอก","de":"คำแนะนำที่ใครสักคนเขียนด้วยลายมือของตัวเองเพื่อคนที่อาจหลงทางในตรอกที่ซับซ้อนราวเขาวงกต ลายมืออ่อนโยนที่บอกให้เลี้ยวตรงมุมที่เท่าไหร่ น้ำใจของย่านนั้นถูกจารึกไว้อย่างเรียบร้อยในการ์ดใบเล็ก ๆ เพียงใบเดียว"},"ICON-0230":{"nm":"บัตรรักษาความปลอดภัย","de":"ต้องแขวนบัตรนี้ไว้ที่คอเท่านั้น ประตูสู่โลกด้านในจึงจะเปิดออก คือสิทธิ์เล็ก ๆ ที่อนุญาตให้เข้าไป และเป็นเครื่องยืนยันเงียบ ๆ ว่าเป็นส่วนหนึ่งของที่นี่ มีเพียงคนที่รู้เวลาที่ใช้ไปกว่าจะได้มันมาเท่านั้นที่รู้ถึงน้ำหนักของมัน"},"ICON-0231":{"nm":"สายรัดข้อมือเข้างาน","de":"รัดที่ข้อมือเพียงครั้งเดียว ก็เป็นส่วนหนึ่งของวันนั้นจนกว่าจะถอดออก สายกระดาษเส้นเดียวแบ่งข้างในกับข้างนอก และกลายเป็นเครื่องหมายว่าได้ใช้วันเดียวกันร่วมกัน แม้จะตัดขาดออกไปแล้ว รอยนั้นก็ยังหลงเหลืออยู่อีกนาน"},"ICON-0232":{"nm":"ป้ายชื่อแขก","de":"ด้วยป้ายชื่อเล็ก ๆ ติดที่หน้าอกเพียงใบเดียว ที่แปลกหน้าก็กลายเป็นที่ของฉัน เมื่อคำว่า “ยินดีต้อนรับ” ถูกส่งมาบนกระดาษแผ่นเดียว แม้แต่คนที่มาครั้งแรกก็กลายเป็นแขกในที่สุด"},"ICON-0233":{"nm":"กระบอกใส่โปสเตอร์","de":"กระบอกทรงกระบอกที่แข็งแรงคอยปกป้องโปสเตอร์ที่ม้วนไว้ไม่ให้ยับแม้แต่รอยเดียว เพราะยิ่งภาพที่มีค่ามากเท่าไร ยิ่งต้องส่งไปในสภาพเหยียดตรง แม้มองไม่เห็นข้างในแต่มันก็ออกเดินทางพร้อมโอบอุ้มความตั้งใจของใครสักคนไว้"},"ICON-0234":{"nm":"ปกแฟ้มเอกสาร","de":"หน้าแรกที่ห่อหุ้มมัดเอกสารหนา ๆ เอาไว้ คือใบหน้าที่มือสัมผัสก่อนเนื้อหาข้างใน เมื่อปกเรียบร้อย ทัศนคติภายในก็ดูเรียบร้อยตามไปด้วย จุดเริ่มต้นอันอ่อนโยนของพิธีการเล็ก ๆ"},"ICON-0235":{"nm":"โปสการ์ดที่ระลึก","de":"เขียนคำทักทายลงบนเศษทิวทัศน์แดนไกลแล้วส่งออกไป พอถึงเวลาที่มันมาถึง ใจที่ส่งไปก็แก่ตัวลงเล็กน้อยไปพร้อมกัน กลับยิ่งน่ารักขึ้น ความอบอุ่นอันเชื่องช้าของจดหมายลายมือที่ข้อความในหน้าจอไม่มีวันตามทัน"},"ICON-0236":{"nm":"ป้ายห้อยของขวัญ","de":"กระดาษแผ่นเล็ก ๆ ที่ผูกติดไว้บนของขวัญ เพียงคำว่า “ให้เธอ” สามพยางค์ ก็ทำให้การห่อของสมบูรณ์แล้ว จดหมายที่สั้นที่สุดในโลก ที่เขียนไม่ใช่ว่าให้อะไร แต่คือคิดถึงใคร"},"ICON-0237":{"nm":"ม้วนสติกเกอร์ห่อของ","de":"ทุกครั้งที่ดึงออกมาใช้ทีละแผ่น การเก็บงานก็เรียบร้อยขึ้นอีกขั้น ปมเล็ก ๆ ที่จับปลายที่กำลังจะคลายตัวให้เรียบร้อย ท่าไม้ตายสุดท้ายของการห่อของอย่างตั้งใจ มักมาจากแถบม้วนกลม ๆ นี้เสมอ"},"ICON-0238":{"nm":"ซองใสใส่จดหมาย","de":"ชั้นใสบาง ๆ ที่ห่อหุ้มจดหมายลายมือไม่ให้ซีดจางไปตามกาลเวลา ให้ตัวอักษรยังมองเห็นได้ชัด แต่ไม่ให้คราบมือแตะต้องถึง เยื่อบางที่มองไม่เห็นเฝ้าปกป้องหัวใจที่ใครสักคนถนอมไว้อย่างเงียบ ๆ"},"ICON-0239":{"nm":"ตราปิดผนึกสี","de":"จุดสุดท้ายที่ปิดซองจดหมาย ยิ่งสีสดใสมากเท่าไร หัวใจก็ยิ่งไม่รั่วไหลออกมา คำสัญญาว่าไม่มีมือใครแตะต้องจนกว่าจะฉีกเปิด แม้แต่ความลับก็ยังต้องการปมที่สวยงามเช่นนี้"},"ICON-0240":{"nm":"สมุดรวมข้อความ","de":"สมุดเล่มเล็กที่มัดรวมข้อความสั้น ๆ เข้าด้วยกัน ทุกหน้าคือคำหนึ่งคำที่จะส่งให้ใครสักคน เก็บรวบรวมคำที่พูดไม่ทันไว้ทีละคำ สักวันความกล้าที่จะส่งมันออกไปให้ได้ก็จะเติบโตขึ้นมาแน่นอน"},"ICON-0241":{"nm":"ป้ายพับได้","de":"“ทางนี้ค่ะ” เมื่อกางออก “วันนี้แค่นี้ก่อน” เมื่อพับเก็บ มันยืนกางขาอยู่ที่ปากตรอกทั้งวัน เพื่อใครสักคนที่อาจหลงทาง เย็นที่มันพับเก็บ คือการพักผ่อนที่อ่อนโยนที่สุดสำหรับฉัน"},"ICON-0242":{"nm":"แถบรัดจดหมาย","de":"โอบกอดโปสการ์ดกองใหญ่ไว้รอบเอว คำทักทายที่กำลังจะกระจัดกระจายก็กลายเป็นมัดเดียวของหัวใจในที่สุด แถบเบา ๆ เส้นเดียวมัดรวมถ้อยคำที่จะเดินทางไปแดนไกลไว้อย่างเรียบร้อย และส่งหลังที่กำลังออกเดินทางไปอย่างเงียบ ๆ"},"ICON-0243":{"nm":"มัดข้อความขอบคุณ","de":"เพราะคำว่าขอบคุณมักลื่นหลุดออกจากปากไปเรื่อย ๆ จึงเขียนลงบนกระดาษขนาดเท่าฝ่ามือแล้วมัดเก็บไว้อย่างเงียบ ๆ ยิ่งมัดหนาขึ้นเท่าไร ความรู้สึกเป็นหนี้บุญคุณที่มีต่อใครสักคนก็หนาขึ้นตามไปด้วยเช่นกัน"},"ICON-0244":{"nm":"ใบตัวอย่างคำเชียร์","de":"แผ่นตัวอย่างที่เขียนว่า “ตะโกนแบบนี้นะ” คำเชียร์ที่ยังไม่มีเสียงมาสวมทับ กักเก็บไว้เพียงความตื่นเต้นเงียบ ๆ เหมือนโน้ตเพลงเปล่าที่รอจังหวะแรก"},"ICON-0245":{"nm":"โน้ตขอจองบันทึกล่วงหน้า","de":"โน้ตที่เขียนขอจองคิวบันทึกล่วงหน้ามักวนเวียนอยู่ที่ช่องตีห้าเสมอ กระดาษแผ่นเล็ก ๆ จดบันทึกหัวใจที่ยอมตัดการนอนเพื่อจับจองที่นั่งไว้อย่างเงียบ ๆ ราวกับเข้าใจทุกอย่างดี"},"ICON-0246":{"nm":"บัตรคิวแฟนไซน์","de":"กระดาษแผ่นเดียวที่กำหนดว่าจะได้ทักทายเป็นคิวที่เท่าไร การต่อแถวไม่ใช่การรอคอยลำดับ แต่คือการยืมลำดับมาใช้ชั่วคราว เพราะไม่อาจใส่หมายเลขให้กับความรักที่มีได้"},"ICON-0247":{"nm":"สายรัดข้อมือหมายเลขคิว","de":"ตัวเลขเพียงตัวเดียวตัดสินลำดับการต่อแถวของวันนี้ ไม่ว่าจะอยู่แถวหน้าหรือแถวหลัง คนที่สวมสายรัดเล็ก ๆ เบา ๆ นี้ที่ข้อมือ ต่างก็เป็นเพื่อนร่วมใจเดียวกันที่มารวมตัวกันเพื่อดูเวทีเดียวกันในที่สุด"},"ICON-0248":{"nm":"ตารางจัดโฟโต้การ์ด","de":"แม้จะเป็นหน้าเดียวกันแต่ก็ต่างกันหมด จึงแบ่งเขียนไว้ทีละช่อง ยิ่งตารางเต็มมากเท่าไร หัวใจก็ยิ่งเป็นระเบียบมากเท่านั้น และช่องว่างที่เหลืออยู่ก็ทำให้หัวใจเต้นตึกตักด้วยความตื่นเต้นที่อยากเติมให้เต็มในวันนี้"},"ICON-0249":{"nm":"ใบเช็คลิสต์อัลบั้ม","de":"เวอร์ชัน โฟโต้การ์ด ไปจนถึงสถานะซีล คือรายการความรักที่จดไว้ด้วยตัวเลข วาดฝันถึงความภาคภูมิใจในวันที่เติมเต็มทุกช่องไว้ล่วงหน้า วันนี้ก็วาดวงกลมลงบนบรรทัดหนึ่งอย่างประณีตอีกครั้ง"},"ICON-0250":{"nm":"กระดาษวิธีเชียร์","de":"ท่ามือ จังหวะตะโกน ไปจนถึงจุดที่ต้องหายใจ เพื่อให้แม้แต่คนที่มาครั้งแรกก็ผสานเป็นเสียงเดียวกันได้อย่างรวดเร็ว กระดาษแผ่นเล็ก ๆ จึงกลายเป็นไกด์ใจดีที่ส่งต่อจากมือสู่มือ"},"ICON-0251":{"nm":"สมุดโน้ตส่วนตัว","de":"เลือกเขียนแต่ประโยคที่จะไม่แสดงให้ใครเห็นลงไว้ตรงนี้เท่านั้น ว่าหน้ากระดาษที่ไม่เคยเปิดคือหน้าที่ซื่อสัตย์ที่สุด สมุดเล่มนี้เฝ้าปกป้องความจริงข้อนั้นไว้อย่างเงียบ ๆ โดยปิดปกเอาไว้เสมอ"},"ICON-0252":{"nm":"ใบสแตมป์วันครบรอบ","de":"กดลงไป แล้ววันหนึ่งก็กลายเป็นวันพิเศษขึ้นมาอีกครั้ง ด้วยตราประทับเล็ก ๆ ที่กดแต้มลงบนวันที่ธรรมดา “วันนี้” ก็แอบเข้าไปมีชื่ออยู่ในทำเนียบวันที่อยากจดจำเรียบร้อยแล้ว"},"ICON-0253":{"nm":"ปกคลิปบอร์ด","de":"ต่อให้ลมพัดแรง ต่อให้ฝนสาดเข้ามา แต่กระดาษที่หนีบไว้ก็ยังปลอดภัยจนถึงที่สุด ฉันผู้รับหน้าที่เป็นเกราะให้กระดานเอง คือบอดี้การ์ดที่ไว้ใจได้ของตัวอักษรที่จดไว้"},"ICON-0254":{"nm":"แถบดัชนีแฟ้ม","de":"เพื่อไม่ให้หลงทางท่ามกลางเอกสารหนา ๆ มันแลบลิ้นเล็ก ๆ ออกมาแล้วบอกว่า “ตรงนี้” แถบสีสันแผ่นเดียวควบคุมหน้ากระดาษเป็นร้อยหน้าได้ในสายตาเดียว"},"ICON-0255":{"nm":"ป้ายแท็บจัดหมวดหมู่","de":"อันนี้ช่องนี้ อันนั้นช่องนั้น หน้าที่ของฉันคือจัดระเบียบความยุ่งเหยิงของโลกให้เรียบร้อยทีละบรรทัด ทันทีที่ป้ายถูกติดลงไป สิ่งที่เคยกระจัดกระจายก็หาที่ทางของตัวเองพบในที่สุด"},"ICON-0256":{"nm":"กระดานอนุมัติจิ๋ว","de":"วินาทีที่ประทับตราลงไปเพียงแป๊ก รู้สึกราวกับกลายเป็นผู้ใหญ่ตัวจริงขึ้นมาอย่างประหลาด แม้ขนาดจะเล็กแต่ก็มีอำนาจกระฉับกระเฉง เพียงตราประทับผ่านครั้งเดียว งานที่กองสุมไว้ก็เสร็จสิ้นลงอย่างรวดเร็ว"},"ICON-0257":{"nm":"ซองเอกสารใส","de":"ข้างในมองเห็นชัดเจนจึงไม่มีอะไรต้องปิดบัง โอบอุ้มกระดาษสำคัญไว้ กลัวเปียกฝนกลัวยับ จึงห่อหุ้มด้วยร่างกายใสของตัวเองและพาไปจนถึงที่นัดหมาย"},"ICON-0258":{"nm":"แถบเช็คชื่อเข้าเรียน","de":"มาแล้ว เติมอีกหนึ่งช่อง เมื่อรอยเท้าของแต่ละวันสะสมเรียงต่อกันไปตามแถบ ความขยันที่มองไม่เห็นก็กลายเป็นลวดลายที่มองเห็นได้ในพริบตาในที่สุด"},"ICON-0259":{"nm":"สมุดจดข้อผิด","de":"การจดสิ่งที่ทำผิดไม่ใช่การสะสมความอับอาย เพื่อไม่ให้สะดุดล้มซ้ำที่เดิมสองครั้ง มันคือการเขียนความผิดพลาดของเมื่อวานใหม่ให้เป็นไกด์นำทางของวันนี้"},"ICON-0260":{"nm":"กระดานสแตมป์ตารางนัด","de":"ประทับตราลงบนตารางนัดที่ว่างเปล่าเพียงครั้งเดียว “นัดหมาย” ก็เกิดขึ้น มนตร์วิเศษที่กำหนดวันได้ด้วยการสะบัดข้อมือเพียงครั้งเดียว แท้จริงแล้วมนตร์นั้นคือชื่ออีกชื่อของความขยันที่เตรียมพร้อมล่วงหน้านั่นเอง"},"ICON-0261":{"nm":"ป้ายสันหนังสือ","de":"ป้ายชื่อของหนังสือที่ยืนหันสันเข้าหาชั้น ตัวอักษรสั้น ๆ ที่เขียนไว้บนสันแคบ ๆ กวักมือเรียกเล่มที่กำลังตามหาท่ามกลางหนังสือนับร้อยเล่มออกมาได้ในทันที"},"ICON-0262":{"nm":"แผ่นกันรอยรูปภาพ","de":"มือเปล่าห้ามแตะ ไม่ให้เหลือรอยนิ้วมือแม้แต่จุดเดียว มันแผ่ตัวคลุมทับภาพถ่ายอันมีค่าไว้เบา ๆ ความรักที่มีให้จะยาวนานได้ก็ด้วยการสัมผัสอย่างระมัดระวังเช่นนี้"},"ICON-0263":{"nm":"แผ่นดัชนีฟิล์ม","de":"เมื่อติดหมายเลขให้ฟิล์มแต่ละแถบทีละเส้น ช่วงเวลาที่กระจัดกระจายก็ได้คืนลำดับของเรื่องราวอีกครั้ง คือไกด์เล็ก ๆ ที่คอยดูแลความทรงจำที่จารึกด้วยแสงไม่ให้สับสน"},"ICON-0264":{"nm":"ซองใส่รูปถ่าย","de":"บ้านใสที่ประดิษฐานความสุขสี่เหลี่ยมไว้ทีละแผ่น ไม่ต้องกังวลว่ามุมจะบุบ ใบหน้าที่รักที่สุดจึงเปล่งประกายอย่างเรียบร้อยอยู่ในนี้ตลอดทั้งสี่ฤดู"},"ICON-0265":{"nm":"ซองอัดรูปจิ๋ว","de":"ก่อนที่ไออุ่นของรูปถ่ายที่เพิ่งอัดเสร็จจะเย็นลง ซองเล็ก ๆ ก็กางแขนทั้งสองข้างออกรับไว้ ภาพหนึ่งภาพที่เข้าไปทางปากซองขนาดเท่าฝ่ามือ ไม่ทันรู้ตัวก็กลายเป็นสมบัติในกระเป๋าของใครสักคน"},"ICON-0266":{"nm":"ปกการ์ดเลนติคูลาร์","de":"ภารกิจของฉันคือปกป้องภาพถ่ายจอมเรื่องมากที่เอียงแล้วสีหน้าเปลี่ยนไปโดยไม่ให้มีรอยขีดข่วนแม้แต่รอยเดียว ต้องคอยปกป้องใบหน้าที่ต่างกันในทุกมุมมอง ฉันเองก็ต้องขยันไม่แพ้กันเลยทีเดียว"},"ICON-0267":{"nm":"ป้ายจัดคัตภาพ","de":"ในสี่คัต คัตไหนดีที่สุด ป้ายนี้ช่วยชี้ให้แทน งานเล็ก ๆ น้อย ๆ ที่แยกภาพที่ถ่ายออกมาสวยกับภาพที่ตลกให้อยู่เคียงข้างกันนี้เอง คือเคล็ดลับที่ทำให้ได้เพลิดเพลินกับความทรงจำถึงสองเท่า"},"ICON-0268":{"nm":"แถบเก็บรูปสี่คัต","de":"มันพันรอบความทรงจำสี่ช่องแคบยาวให้เรียบร้อยเป็นระเบียบ กอดเสียงหัวเราะของวันนั้นที่กำลังจะกระจัดกระจายไว้ให้แน่นเป็นมัดเดียว แล้วพามันไปยังก้นกระเป๋าอย่างปลอดภัย"},"ICON-0269":{"nm":"สติกเกอร์มุมรูปภาพ","de":"เวลาติดรูปถ่ายลงในอัลบั้ม มือเล็ก ๆ ที่จับมุมทั้งสี่ของรูปไว้เบา ๆ แม้ไม่ทากาวจนเลอะเทอะก็ไม่หลุด ความละเอียดอ่อนเริ่มต้นจากมุมเล็ก ๆ เช่นนี้เอง"},"ICON-0270":{"nm":"ตารางปรับสีภาพพิมพ์","de":"อุ่นขึ้นอีกนิด สว่างน้อยลงอีกหน่อย ตารางแผ่นเดียวที่ปรับตัวเลขไปเรื่อย ๆ จนกว่าสีที่ถูกใจจะปรากฏ ค่อย ๆ เปลี่ยนภาพธรรมดาให้กลายเป็นงานศิลปะอย่างเงียบ ๆ"},"ICON-0271":{"nm":"คลิปหนีบใบเสร็จ","de":"มันคาบใบเสร็จที่ยับยู่ยี่ไว้อย่างเรียบร้อยไม่ปล่อยมือ ด้วยปากเล็ก ๆ มันจัดการรายจ่ายของวันนั้นไว้อย่างเรียบร้อย การสรุปยอดปลายเดือนจึงเบาสบายขึ้นมาก"},"ICON-0272":{"nm":"ใบยืนยันการจอง","de":"“จองเรียบร้อยแล้ว” เพียงบรรทัดเดียว หัวใจก็ค่อย ๆ ผ่อนคลายลง กระดาษแผ่นเดียวกลายเป็นหลักฐานของคำสัญญา เก็บความตื่นเต้นไว้ทีละนิดจนถึงวันที่รอคอย"},"ICON-0273":{"nm":"ใบยืนยันการคืน","de":"หลักฐานเล็ก ๆ แต่เชิดหน้าชูตาได้ว่าได้นำสิ่งที่ยืมมาคืนไว้ที่เดิมแล้ว วินาทีที่กระดาษแผ่นนี้อยู่ในมือ หนี้ก้อนหนึ่งที่แบกไว้มุมหนึ่งของหัวใจก็ถูกลบล้างไปอย่างเบาสบาย"},"ICON-0274":{"nm":"ที่เก็บบัตรฝากของ","de":"เพื่อไม่ให้ทำบัตรรับของที่ฝากไว้หายไป ฉันจะช่วยจับไว้ให้แน่นแทนเธอเอง เพราะที่อยู่ของกระดาษแผ่นเล็ก ๆ เพียงแผ่นเดียวก็อาจส่งผลต่อปลายวันของใครสักคนได้"},"ICON-0275":{"nm":"หางป้ายยืมของ","de":"ป้ายเล็ก ๆ ที่แกว่งไกวอยู่กับของที่ถูกยืมไปแต่ละชิ้น ตามหางนี้ไปก็จะรู้ทันทีว่าใครเอาอะไรไป ปริศนาของหายจึงคลี่คลายได้อย่างรวดเร็ว"},"ICON-0276":{"nm":"ใบเช็คตรวจสอบ","de":"ตรวจดูทีละชิ้นด้วยสายตาว่าไม่มีอะไรตกหล่น เมื่อเครื่องหมายเช็คถูกเติมเรียงกันเป็นแถว ความละเอียดรอบคอบที่มองไม่เห็นก็ได้ชื่อว่าความไว้วางใจในที่สุด"},"ICON-0277":{"nm":"ซองโน้ตสรุปยอด","de":"เขียนเงินที่เข้ามาและเงินที่ออกไปลงบนซอง ตัวเลขที่ยุ่งเหยิงก็เรียงแถวเป็นระเบียบอย่างสงบ ปลายทางของการสรุปยอดมักจบลงด้วยโน้ตเล็ก ๆ นี้ที่ค่อย ๆ ปิดจุดสุดท้ายให้เสมอ"},"ICON-0278":{"nm":"ป้ายจ่าหน้าพัสดุ","de":"มันออกเดินทางโดยจดไว้บนตัวเองว่าจะไปที่ไหน จะไปถึงใคร วินาทีที่ป้ายนี้ถูกติดลงไป กล่องก็กลายเป็นนักเดินทางที่มีจุดหมายและออกเดินทางด้วยความตื่นเต้น"},"ICON-0279":{"nm":"แถบยืนยันการรับของ","de":"มันมัดคำว่า “ได้รับเรียบร้อยแล้ว” ไว้ในแถบเดียวแล้วส่งกลับไป ความโล่งใจของผู้รับและความอุ่นใจของผู้ส่ง มาจับมือกันอย่างเงียบ ๆ บนเชือกเส้นเล็กนี้"},"ICON-0280":{"nm":"ห่วงบัตรคำศัพท์","de":"คำศัพท์ที่จะหายไปถ้ากระจัดกระจายเป็นแผ่นเดี่ยว ๆ ห่วงเล็ก ๆ วงหนึ่งร้อยรวมกันจับไว้แน่น พลิกแล้วพลิกอีก คำที่เคยแปลกหน้าก็กลายเป็นเพื่อนคุ้นปากไปโดยไม่ทันรู้ตัว"},"ICON-0281":{"nm":"แถบโน้ตออกเสียง","de":"แขวนป้ายเล็ก ๆ ไว้ตรงจุดที่ปลายลิ้นลื่นไถลอยู่บ่อย ๆ แม้แต่เสียงแปลกหน้าที่หลงทางอยู่ในปาก ก็หาการออกเสียงที่ถูกต้องของตัวเองพบได้ในไม่ช้าเมื่อตามโน้ตนี้ไป หน้าแรกของการค่อย ๆ ฝึกฝนเสียงที่ยังไม่คล่องให้เชื่อง"},"ICON-0282":{"nm":"กล่องโน้ตแปลภาษา","de":"สะพานเล็ก ๆ ที่ข้ามระหว่างคำพูดกับคำพูดถูกพับเก็บไว้อย่างประณีตทีละช่อง เขียนคำที่เลือกมาอย่างยากลำบากแล้วยื่นให้อย่างแอบ ๆ แม้หัวใจที่เคยสื่อสารกันไม่ได้ก็ใกล้ชิดกันขึ้นด้วยโน้ตแผ่นเดียวที่คั่นกลาง"},"ICON-0283":{"nm":"แผ่นตัดเก็บประโยค","de":"ประโยคที่แตะโดนใจต้องคัดลอกด้วยมือจึงจะอยู่ได้นาน ติดบรรทัดหนึ่งที่ตัดมาจากมุมหนังสือไว้หน้าโต๊ะ ตัวอักษรเหล่านั้นก็ค่อย ๆ ค้ำจุนวันที่กำลังจมดิ่งไว้อย่างเงียบ ๆ"},"ICON-0284":{"nm":"แถบดัชนีจดบันทึก","de":"ธงเล็ก ๆ หลากสีที่สอดไว้เพื่อไม่ให้หลงทางในหนังสือเล่มหนา จะเดินหลงไปได้ไกลกว่าก็ต่อเมื่อรู้ที่ที่จะกลับมา แท็บที่โผล่ออกมาบอกเช่นนั้นอย่างเงียบ ๆ จากระหว่างหน้ากระดาษ"},"ICON-0285":{"nm":"ชิปเช็คท่องจำ","de":"เครื่องหมายจุดหนึ่งที่แต้มไว้ข้างสิ่งที่จำได้แล้ว เป็นสมอเล็ก ๆ ที่ยึดสิ่งที่แวะเข้ามาในหัวชั่วครู่แล้วพยายามจะหายไปเอาไว้ ทุกช่องที่ถูกแต้มดำสนิทจึงแฝงความพยายามที่หลั่งไหลออกมาเมื่อคืนไว้อย่างเงียบ ๆ"},"ICON-0286":{"nm":"ซองคำถามควิซ","de":"ก่อนจะฉีกซองออก ไม่มีใครรู้ว่าจะเจออะไร ไม่กี่วินาทีที่นิ้วปลายมือคลำอยู่ที่รอยผนึก คือมัดความตื่นเต้นที่บรรจุคำถามหนึ่งข้อพับไว้อย่างประณีต พร้อมผนึกความใจเต้นตึกตักไว้ด้วยกัน"},"ICON-0287":{"nm":"สมุดแท็บไวยากรณ์","de":"กฎเกณฑ์ไม่ใช่สิ่งที่ท่องจำด้วยหัว แต่เป็นสิ่งที่ฝึกให้คุ้นมือ ตั้งแต่แท็บสีของหน้าที่เปิดบ่อยที่สุดไปจนถึงสมุดที่ค่อย ๆ นุ่มและสึกไป มุมที่สึกนั้นเองที่กลายเป็นวงปีของเวลาที่เธออดทนผ่านมา"},"ICON-0288":{"nm":"ตารางฝึกพูด","de":"ตารางแผ่นเดียวสำหรับคนที่การเอ่ยปากเป็นเรื่องยากที่สุดในโลก ค่อย ๆ ชี้นิ้วไล่ลงไปทีละช่อง แม้แต่คำแรกที่สั่นเครือในลำคอก็หาเสียงของตัวเองพบได้โดยไม่ทันรู้ตัว เพราะแม้แต่ความกล้าก็ยังมีลำดับก่อนหลัง"},"ICON-0289":{"nm":"แผ่นร่างสี","de":"สีสันก่อนจะเสร็จสมบูรณ์นอนเกลื่อนกลาดหยาบ ๆ กำลังปรับลมหายใจ ไม่ใช่คำตอบที่ถูกต้อง แต่ยังเป็นเพียงความเป็นไปได้ บนแผ่นกระดาษที่ยังไม่ขัดเกลานี้ พรุ่งนี้มากมายกว่าสิ่งใดถูกบรรจุไว้และแกว่งไกว"},"ICON-0290":{"nm":"ชิ้นส่วนมู้ดบอร์ด","de":"รวบรวมความประทับใจที่กระจัดกระจายมาแปะไว้ในที่เดียวกัน บรรยากาศที่จับต้องได้ยากก็ค่อย ๆ เผยเค้าโครงลาง ๆ ออกมา ความรู้สึกบางอย่างที่ยังไม่มีชื่อ ชิ้นส่วนต่าง ๆ พิงพากันชี้ไปทางนั้นอย่างเงียบ ๆ"},"ICON-0291":{"nm":"สมุดตัวอย่างลวดลาย","de":"ลายตารางของผ้าห่อของและลายสานของซี่กรงหน้าต่างถูกจัดเรียงไว้อย่างเป็นระเบียบทีละหน้าในเล่มเดียว ที่ที่ลวดลายเดียวกันซ้ำไปจนสุดทาง ไม่ใช่ความเกียจคร้านแต่คือคำสัญญา หัวใจที่มั่นคงในการรักษาลายเส้นเดียวไว้ให้ครบ"},"ICON-0292":{"nm":"แผ่นตัวอย่างผ้าคอสตูม","de":"แม้จะเป็นแสงเดียวกัน แต่เนื้อผ้าและเงาที่จับบนผ้าแต่ละชิ้นกลับแตกต่างกัน ก่อนจะเลือกชุดแสดงบนเวที คืนที่ลังเลใจ ลูบผ้าซ้ำแล้วซ้ำเล่าด้วยปลายนิ้ว ถูกเก็บรักษาไว้ทั้งหมดในตัวอย่างผ้าชิ้นเล็ก ๆ เพียงชิ้นเดียว"},"ICON-0293":{"nm":"ใบแนวทางห้ามใช้โลโก้","de":"กระดาษที่จดสิ่งที่ห้ามทำไว้อย่างชัดเจนเป็นอันดับแรก ในกรอบที่ถูกกากบาทสีแดงขีดไว้ อิสรภาพกลับชัดเจนขึ้นมาแทน ทางใหม่จึงเปิดออกในที่ที่คิดว่าเป็นทางตันเสียอีก"},"ICON-0294":{"nm":"ชิปอ้างอิงสี","de":"ชิ้นตัวอย่างที่สร้างขึ้นแยกต่างหาก เพราะสีไม่อาจอธิบายด้วยคำพูดได้เลย มันขังชั่ววินาทีที่แสงตะวันยามเย็นแดงที่สุดไว้บนฝ่ามือเล็ก ๆ เพื่อให้ส่งต่อให้คนต่อไปได้อย่างแม่นยำว่า “สีนี้แหละ”"},"ICON-0295":{"nm":"การ์ดร่างผังจัดวาง","de":"ภาพร่างแรกที่ขีดเบา ๆ ว่าจะวางอะไรไว้ตรงไหน การตัดสินใจเรื่องตำแหน่งก็คือการตัดสินใจเรื่องหัวใจไปในตัว ท่ามกลางเส้นที่กระจัดกระจายอย่างไม่คล่องแคล่ว ความสมดุลของภาพรวมก็ค่อย ๆ ลืมตาขึ้นอย่างช้า ๆ"},"ICON-0296":{"nm":"กระดานโน้ตวัสดุ","de":"ไม้ ดิน หิน ชื่อของสิ่งที่จับต้องได้ถูกจดไว้อย่างแน่นขนัด ความลับที่มีเพียงคนที่เริ่มต้นด้วยการอ่านลายเนื้อด้วยมือก่อนเท่านั้นที่รู้ ว่าจะสร้างด้วยอะไรนั้น กำหนดไว้ล่วงหน้าแล้วครึ่งหนึ่งว่าจะกลายเป็นอะไร"},"ICON-0297":{"nm":"กระดาษลอกลาย","de":"วางกระดาษบาง ๆ ทับลงบนภาพร่างแล้วค่อย ๆ ลากเส้นตาม ระหว่างที่ยืมเส้นทางของคนอื่นมาชั่วคราว มือของตัวเองก็เรียนรู้เส้นทางนั้นไปด้วย และท่ามกลางเส้นที่ลอกมา เส้นที่เป็นของตัวเองก็ค่อย ๆ งอกงามขึ้นมาเองโดยไม่ทันรู้ตัว"},"ICON-0298":{"nm":"แถบทางเดินเข้างาน","de":"ผู้คนเรียงแถวเดินเข้าไปตามแถบที่ติดยาวอยู่บนพื้น เส้นเดียวที่นำทางอย่างเงียบ ๆ ไม่ให้ฝีก้าวที่ตื่นเต้นพันกัน เป็นมือที่มองไม่เห็นแต่อ่อนโยนที่คอยประคับประคองความตื่นเต้นไม่ให้พังทลาย"},"ICON-0299":{"nm":"ป้ายนำทางงาน","de":"“ทางนี้ค่ะ” ป้ายที่ยืนถือคำพูดนี้แทนคน ความกรุณาเล็ก ๆ ที่ตั้งไว้ทุกทางแยกเพื่อไม่ให้ใครหลงทาง จูงมือวันที่ไม่คุ้นเคยของคนที่มาครั้งแรกให้เดินไปอย่างเงียบ ๆ"},"ICON-0300":{"nm":"ป้ายหมายเลขบูธ","de":"หมายเลขหนึ่งตัวที่กำหนดให้แต่ละบูธ ระบุเจ้าของพื้นที่ช่องนั้นอย่างชัดเจน แม้จะเป็นตัวเลขเล็ก ๆ แต่ก็เป็นคำสัญญาว่า “ที่นี่คือที่ของเธอ” จึงทำให้มีที่ให้กลับมาในงานที่ไม่คุ้นเคย"},"ICON-0301":{"nm":"ใบยินยอมทีมงาน","de":"ลายเซ็นหนึ่งบรรทัดที่หลงเหลือไว้ ณ จุดที่หัวใจตกลงจะทำงานร่วมกัน กระดาษบางเพียงแผ่นเดียว แต่กลับแบกรับน้ำหนักของการเลือกที่จะเชื่อใจกันไว้ในนั้น และทุกฝีมือที่ช่วยเหลือในงานนี้ล้วนเริ่มต้นขึ้นตรงนี้เอง"},"ICON-0302":{"nm":"มัดบัตรทดลอง","de":"มัดบัตรทดลองหนาพอดีมือ มัดไว้ให้กำได้กระชับในมือเดียว ยิ่งแจกออกไปมากเท่าไรก็ไม่ได้ยิ่งเล็กลง แต่กลับยิ่งเพิ่ม 'ครั้งแรก' ให้ใครสักคนมากขึ้นเรื่อยๆ เป็นมัดน้ำใจที่ยิ่งสัมผัสก็ยิ่งอุ่น"},"ICON-0303":{"nm":"ป้ายบอกแนวคิว","de":"'กรุณาต่อแถวจากตรงนี้' พื้นกระซิบบอกอย่างแผ่วเบา เมื่อหัวใจที่รักษาลำดับของตนมารวมกัน แถวยาวก็กลายเป็นทิวทัศน์หนึ่ง ป้ายเล็กๆ เพียงแผ่นเดียวเปลี่ยนความใจร้อนให้กลายเป็นความสงบนิ่ง"},"ICON-0304":{"nm":"ป้ายรับสินค้าหน้างาน","de":"ป้ายเล็กๆ ที่ห้อยเบาๆ ตรงจุดที่มารับสิ่งที่สั่งไว้ล่วงหน้าด้วยตนเอง ทันทีที่กำไว้ในมือ ความโล่งอกที่ค่อยๆ คลายจากบ่าลงมานั้นช่างเบาสบาย เป็นปมที่หัวใจซึ่งรอคอยมานานได้ก่อร่างเป็นรูปเป็นร่างเสียที"},"ICON-0305":{"nm":"บัตรกล่องสุ่ม","de":"ความสนุกของการเลือกหนึ่งชิ้นโดยไม่รู้ว่าข้างในมีอะไร เขย่าแล้วเสียงกุกกักในนั้นทำให้หัวใจเต้นก่อนใคร และช่วงเวลาสั้นๆ ก่อนเปิดออกนั้นเองคือช่วงเวลาที่พองฟูไปด้วยความหวังมากที่สุดในหนึ่งวัน"},"ICON-0306":{"nm":"สติกเกอร์แลกเปลี่ยนสำเร็จ","de":"ตราประทับกลมเล็กๆ ที่ประกาศว่าการแลกเปลี่ยนเสร็จสิ้นลงอย่างราบรื่น เป็นจุดจบที่เรียบเนียนซึ่งหลงเหลืออยู่ระหว่างมือที่ให้และมือที่รับ เมื่อแปะแต๊ะลงไปครั้งเดียว การซื้อขายนั้นก็เพิ่งจะกลมกลืนอบอุ่นขึ้นมา"},"ICON-0307":{"nm":"แถบผนึกบันทึก","de":"กล่องล้ำค่าถูกพันรอบด้วยแถบหนึ่งรอบแล้วผนึกไว้เงียบๆ เป็นทั้งคำขอร้องไม่ให้เปิดออกโดยพลการ และเป็นมารยาทที่เงียบที่สุดในการให้คุณค่ากับสิ่งที่อยู่ข้างในมากเพียงนั้น ทั้งหมดบรรจุไว้ในแถบเพียงเส้นเดียว"},"ICON-0308":{"nm":"แคปซูลข้อความลับ","de":"คำพูดหนึ่งคำที่อยากบอก ถูกเก็บซ่อนไว้อย่างประณีตในกระบอกเล็กๆ ปิดผนึกไว้แน่นราวกับฝังความรู้สึกที่ส่งออกไปไม่ได้ไว้ใต้ดิน ตู้เซฟจิ๋วบนฝ่ามือจึงเฝ้าคอยรักษาเวลาไว้จนกว่าจะถึงวันที่ได้เปิดมันอีกครั้ง"},"ICON-0309":{"nm":"การ์ดสแครปจิ๋ว","de":"ชิ้นส่วนที่ตัดแปะไว้เก็บกลิ่นอายอารมณ์ของวันนั้นไว้อย่างจางๆ เบากว่าไดอารีและมีรอยมือมากกว่ารูปถ่าย กระดาษขนาดเท่าฝ่ามือจึงกุมวันเวลาที่พร้อมจะลอดหลุดผ่านง่ามนิ้วไว้ให้แน่น"},"ICON-0310":{"nm":"ใบบันทึกการมาเยือนครั้งแรก","de":"ความสั่นไหวของวันที่ก้าวเท้าลงบนเกาะแห่งนี้เป็นครั้งแรก หลงเหลืออยู่ในบรรทัดสั้นๆ เพียงบรรทัดเดียว ก่อนที่ความแปลกหน้าจะแปรเปลี่ยนเป็นความคุ้นเคย กระดาษแผ่นนี้ได้โอบอุ้มหัวใจแรกที่ใสสะอาดที่สุดไว้แทนเรา และเก็บรักษามันไว้ได้นาน"},"ICON-0311":{"nm":"ตารางจัดหมวดความทรงจำ","de":"ตารางที่แบ่งความทรงจำตามลายเส้นและกิ่งก้านแล้วจดบันทึกไว้ทีละอย่าง หากกองความทรงจำทั้งหมดไว้ในลิ้นชักเดียวอย่างไร้ระเบียบ แม้แต่วันที่ทะนุถนอมที่สุดก็อาจถูกฝังจมหายไป ยิ่งเป็นสิ่งล้ำค่าเท่าไร ก็ยิ่งควรกำหนดที่ทางให้มันอย่างประณีต"},"ICON-0312":{"nm":"ชิปโน้ตบอลลูนคำพูด","de":"คำพูดที่อยากบอกพองกลมขึ้นราวลูกโป่งและลอยอยู่บนกระดาษ แม้แต่คำที่พูดออกจากปากไม่ได้ ก็ยังแอบรวบรวมความกล้าอยู่ภายในกรอบกลมนั้น เป็นทางออกเล็กๆ ที่อบอุ่นให้หัวใจได้ลอดออกมา"},"ICON-0313":{"nm":"ที่ตั้งวันที่","de":"ที่ตั้งเล็กๆ ที่ยกวันนี้ขึ้นตรงให้หันหน้ามาเผชิญกัน หยิบวันเดียวออกมาจากวันเวลาที่ไหลผ่านไปเรื่อยๆ แล้วให้มันนั่งอยู่ตรงกลาง แม้แต่วันธรรมดาก็มีไออุ่นที่ควรค่าแก่การเฉลิมฉลองซ่อนอยู่"},"ICON-0314":{"nm":"ป้ายหมายเลขสะสม","de":"หมายเลขเฉพาะที่กำหนดให้กับสิ่งที่รักไว้ทีละชิ้น การสะสมคือคำสัญญาว่าจะเรียกสิ่งนั้นว่าเป็นหนึ่งเดียวในโลกใบนี้ ตัวเลขบนป้ายเล็กๆ จึงสลักน้ำหนักของหัวใจไว้อย่างชัดเจน"},"ICON-0315":{"nm":"ซองเก็บถาวร","de":"ซองบางๆ ที่สอดสิ่งที่อยากเก็บไว้ดูนานๆ เข้าไปทีละแผ่น การวางบางสิ่งให้ห่างจากแสงและกาลเวลาเพียงชั้นเดียว การรักสิ่งใดสักอย่าง ท้ายที่สุดแล้วก็คือการเก็บรักษามันไว้ให้ดีนั่นเอง"},"ICON-0316":{"nm":"สายห้อยท็อปโหลดโฟโต้การ์ด","de":"สายเล็กบางที่ต่อให้ท็อปโหลดเดอร์คล้องคอได้ เป็นวิถีของการเป็นแฟนคลับ ที่พาไบแอสไว้ใกล้อกเดินไปตลอดวัน สายเส้นบางๆ เส้นนี้จึงผูกมัดการเดินทางที่อ่อนโยนไว้ทั้งวัน"},"ICON-0317":{"nm":"พินตั้งโฟโต้การ์ด","de":"เพียงพินเล็กๆ เพียงตัวเดียว โฟโต้การ์ดก็ยืนตรงอยู่บนโต๊ะได้ วางราบไว้ก็เป็นเพียงกระดาษแผ่นหนึ่ง แต่ตั้งขึ้นแล้วกลับกลายเป็นความสัมพันธ์ที่สบตากันได้ สร้างที่ทางให้สายตาได้เนิ่นนานอยู่เงียบๆ"},"ICON-0318":{"nm":"ฟิล์มโฮโลแกรมโฟโต้การ์ด","de":"ฟิล์มบางชั้นเดียวที่สายรุ้งไหลรินไปตามมุมมอง ชั้นฟิล์มที่กักแสงไว้เล็กน้อยแต่งแต้มแสงดาวให้การ์ดธรรมดา เป็นเวทมนตร์เล็กๆ ที่สีหน้าต่างออกไปตื่นขึ้นวาบทุกครั้งที่สะบัดข้อมือ"},"ICON-0319":{"nm":"ฝาครอบป้องกันโฟโต้การ์ด","de":"เพียงกดมุมเดียว ก็รู้สึกราวกับหัวใจที่ทะนุถนอมจะพับยับไปด้วย มันคือชุดเกราะใสที่กอดกระดาษล้ำค่าแผ่นเดียวไว้แน่น การถนอมรักษาด้วยใจจริงมักมาพร้อมกับความระมัดระวังเช่นนี้เสมอ"},"ICON-0320":{"nm":"ถาดจัดเรียงโฟโต้การ์ด","de":"ถาดตื้นที่ให้โฟโต้การ์ดนับสิบแผ่นนอนเรียงเป็นระเบียบไปตามลายเส้น กระจัดกระจายก็เป็นเพียงกองหนึ่ง แต่เรียงเป็นแถวแล้วกลับกลายเป็นคอลเลกชัน ลำดับของความรักถูกสลักไว้ทีละนิดในทุกครั้งที่มือจัดเรียง"},"ICON-0321":{"nm":"ซองแลกเปลี่ยนโฟโต้การ์ด","de":"ตอนที่ใส่โฟโต้การ์ดหนึ่งแผ่นลงในซองเพื่อยื่นให้ ปลายนิ้วเผลอลังเลอยู่ครู่หนึ่ง มันไม่ใช่การส่งลาจากไป แต่เป็นการขอร้องให้กลายเป็นไบแอสของใครสักคน ในวินาทีที่พับปิดปากซอง สายสัมพันธ์เล็กๆ หนึ่งเส้นก็เปลี่ยนมือไปอย่างเงียบๆ"},"ICON-0322":{"nm":"ปากกาแต่งโฟโต้การ์ด","de":"สิ่งที่เติมเต็มพื้นที่ว่างไม่ใช่ตัวหนังสือ แต่คือหัวใจ ทุกจุดที่ปลายปากกาผ่านไป หัวใจดวงเล็กๆ และดวงดาวก็ผลิบาน กระดาษธรรมดาแผ่นหนึ่งตื่นขึ้นเป็นกำลังใจหนึ่งเดียวในโลก การตกแต่งก็คือชื่ออีกชื่อหนึ่งของคำสารภาพนั่นเอง"},"ICON-0323":{"nm":"ห่วงหนีบโฟโต้การ์ด","de":"เสียงล็อกของที่หนีบดังแต๊ะ เพียงล็อกเล็กๆ นั้นเดียว การ์ดที่เกือบกระจัดกระจายก็รวมกันเป็นแถวเดียว แม้จะถูกเขย่าทั้งวันอยู่ในกระเป๋าก็ไม่มีมุมไหนบุบสักนิด ความมั่นคงเงียบขนาดนี้เอง"},"ICON-0324":{"nm":"กระเป๋าใส่โฟโต้การ์ด","de":"มือที่รูดซิปเปิดปิดอยู่เสมอกลายเป็นความเคยชินโดยไม่รู้ตัว แม้เจอฝนโปรยหรือถูกฝูงชนเบียดเสียด ข้างในก็ยังแห้งอยู่เสมอ การเก็บสิ่งที่รักที่สุดไว้ในที่ลึกที่สุด นั่นแหละคือแรงงานอันอ่อนโยนที่เรียกว่าการพกพา"},"ICON-0325":{"nm":"สายรัดข้อมือแฟนมีตติ้ง","de":"มือของสตาฟที่ผูกสายไว้บนข้อมือช่างอบอุ่น แฟนคลับคนหนึ่งจดจำไว้ได้นาน ปมเดียวคือเครื่องหมายว่าเป็นส่วนหนึ่งของที่นี่ในวันนี้ สายที่พันไว้สองรอบเพื่อไม่ให้หลุดนั้นเก็บกักความตื่นเต้นของทั้งวันไว้แน่น"},"ICON-0326":{"nm":"สายรัดข้อมือเข้างาน","de":"ในวินาทีที่ผ่านทางเข้าไปนั่นเอง ข้างในและข้างนอกจึงแยกออกจากกันอย่างชัดเจนเสียที สวมไว้ทั้งวันไม่นานก็คุ้นเคยกับผิวหนัง พอถึงเวลาถอดออกก็เหลือรอยจางๆ ไว้ ราวกับหลักฐานของที่ที่เคยอยู่มา"},"ICON-0327":{"nm":"ชิปมุมพูดคุย","de":"เมื่อมุมพูดคุยเปิดขึ้น ชิปหนึ่งเม็ดก็กลิ้งไป ใครจะพูดก่อน คำถามไหนจะถูกจับได้ ความบังเอิญเล็กๆ นั้นเปลี่ยนบรรยากาศไปทั้งหมด ความเอาแน่เอานอนไม่ได้ของชิปเม็ดเดียวน่ารักยิ่งกว่าบทที่เขียนไว้เสียอีก"},"ICON-0328":{"nm":"บัตรคิวงานเซ็นชื่อ","de":"กำกระดาษที่มีตัวเลขเขียนไว้แล้วต่อแถว หมายเลข 142 ระหว่างที่นับคนตรงหน้าอีก 141 คน หัวใจกลับนับลำดับของตัวเองก่อนใคร การรอคอยนั้นยาวนาน แต่เพราะกระดาษแผ่นนี้ แม้เวลานั้นก็กลายเป็นส่วนหนึ่งของความตื่นเต้น"},"ICON-0329":{"nm":"ถุงมือไฮทัช","de":"ในเสี้ยววินาทีที่ฝ่ามือแตะกัน ถุงมือรับไออุ่นสั้นๆ นั้นไว้แทนเรา มือที่อุ่นมาทั้งวันเพื่อการสัมผัสเพียง 0.5 วินาที แม้จะสวมผ้ากั้นไว้ก็ยังกันความสั่นไหวนั้นไม่ได้ ทุกคนต่างรู้ก็ตอนนั้นเอง"},"ICON-0330":{"nm":"พินถ่ายภาพที่ระลึก","de":"เสียงชัตเตอร์ดังแค่ก๊อกเดียว วันนี้ก็ถูกเก็บรักษาไว้ตามที่เป็น ในกรอบที่ตรึงไว้ด้วยพิน แม้แต่รอยยิ้มเก้ๆ กังๆ ก็ยังกลายเป็นฉากที่คิดถึงที่สุดในวันข้างหน้า การบันทึกคือความโลภที่อ่อนโยนที่สุดในการยึดกุมช่วงเวลาไว้"},"ICON-0331":{"nm":"ป้ายริบบิ้นเก้าอี้","de":"ริบบิ้นเล็กๆ ที่แขวนอยู่บนพนักเก้าอี้แกว่งไกวแม้ไม่มีลม เป็นเครื่องหมายที่ใครสักคนผูกไว้ ร่องรอยว่ามีคนเคยอยู่ตรงนี้ แม้ในที่นั่งว่างเปล่าหลังการแสดงจบลง มีเพียงริบบิ้นเท่านั้นที่ดูเหมือนยังจดจำจังหวะนั้นได้"},"ICON-0332":{"nm":"ป้ายตรวจสอบของขวัญ","de":"ป้ายหนึ่งแปะบนของขวัญทุกชิ้น ส่งแล้วหรือยัง ตรวจแล้วหรือยัง มีอะไรขาดหายไปไหม แม้แต่การรับหัวใจของใครสักคนก็ยังต้องมีการดูแลจัดการ สติกเกอร์เล็กๆ แผ่นนี้จึงเชื่อมความใส่ใจกับความใส่ใจไว้โดยไม่มีช่องว่าง"},"ICON-0333":{"nm":"ใบบันทึกที่ระลึก","de":"กระดาษแผ่นหนึ่งที่จดไว้เพื่อเก็บดูไว้นานๆ อากาศของวันนั้น หมายเลขที่นั่ง แม้กระทั่งชื่อเพลงสุดท้าย ความทรงจำอาจเลือนราง แต่มีเพียงใบนี้เท่านั้นที่ไม่มีวันเลือนหาย แม้แต่การเก็บรักษาความทรงจำก็ยังต้องมีรูปแบบเล็กๆ"},"ICON-0334":{"nm":"ห่วงผ้าเช็ดหน้าเชียร์","de":"สอดห่วงเข้าที่ปลายผ้าเช็ดหน้า แล้วมันก็จะไม่ไหลลื่นตกจากบ่า ระหว่างการเช็ดเหงื่อ หมุนเหนือศีรษะ แล้วคล้องกลับไว้ที่คอ การเชื่อมต่อเล็กๆ หนึ่งจุดทำให้ท่าทางแห่งการเชียร์ไม่ขาดตอน"},"ICON-0335":{"nm":"คลิปหนีบสโลแกน","de":"คลิปยึดปลายทั้งสองข้างของสโลแกนไว้แน่น เพื่อให้แม้ยกแขนทั้งสองข้างขึ้นสูง ตัวอักษรก็จะไม่พับงอหรือปลิวไสว นี่คือตัวประกอบที่เงียบที่สุด คอยยืดข้อความให้ตรงอยู่ในที่ที่มองไม่เห็น"},"ICON-0336":{"nm":"กระเป๋ากันเสียง","de":"ซิปรูดอย่างช้าๆ ไร้เสียง เป็นความเงียบที่ถูกออกแบบมาไม่ให้เสียงรบกวนแม้แต่นิดเดียวรั่วไหลออกไปในที่ที่สัญญากันว่าจะเงียบ ความใส่ใจบางครั้งคือการทำให้ตนเองไม่ถูกได้ยิน กระเป๋าใบนี้พูดอย่างเงียบๆ เช่นนั้น"},"ICON-0337":{"nm":"ชิปจังหวะปรบมือ","de":"ทุกครั้งที่ฝ่ามือกระทบกัน ชิปจะนับจังหวะ ปรบ ปรบ ปรบ เสียงปรบมือที่กระจัดกระจายในชั่วขณะหนึ่งก็รวมกันเป็นจังหวะเดียว เวทมนตร์ที่เสียงปรบมือนับพันกลายเป็นลมหายใจเดียวกันนั้น ชิปเล็กๆ ช่วยเสริมไว้อย่างเงียบๆ"},"ICON-0338":{"nm":"โฟลเดอร์วิธีเชียร์","de":"เปิดออกมาก็จะเห็นวิธีเชียร์เขียนไว้เป็นขั้นตอน ท่อนไหนถือสีอะไร เมื่อไรควรตะโกน แม้แต่คนมาครั้งแรกก็กลายเป็นครอบครัวเดียวกันได้ทันทีด้วยโฟลเดอร์เล่มนี้เพียงเล่มเดียว คู่มือเล็กๆ สำหรับแบ่งปันคำสัญญา"},"ICON-0339":{"nm":"สายพัดข้อมือที่นั่ง","de":"ผูกสายไว้กับด้ามพัด แม้หลุดจากมือก็ไม่ตกหาย วันที่ร้อนพัดโบกไปมาแล้วสองมือเป็นอิสระเพื่อโห่ร้อง มันก็แกว่งเล้งอยู่ที่ข้อมือ สายเส้นเดียวช่วยคลายความร้อนและความตื่นเต้นไปพร้อมกัน"},"ICON-0340":{"nm":"ชิ้นฟิล์มประกาย","de":"เมื่อกระทบแสง แต่ละชิ้นก็สะท้อนแสงออกมาคนละมุม วางไว้บนฝ่ามือก็มีสายรุ้งเล็กๆ ริบหรี่ ยิ่งเขย่าสีก็ยิ่งมีชีวิตเคลื่อนไหว บางทีความแวววาวก็คือการแบ่งปันแสงให้เป็นชิ้นเล็กชิ้นน้อยนั่นเอง"},"ICON-0341":{"nm":"ไม้แบนเนอร์จิ๋ว","de":"กางไม้เล็กๆ ออก ผ้าก็รับลมตึงขึ้นมา ยกสองมือขึ้นสูง ตัวอักษรก็ไปถึงพ้นที่นั่ง พับเก็บก็ใส่ลงในมุมกระเป๋าได้พอดี ขนาดของหัวใจไม่ได้วัดจากความยาวของไม้"},"ICON-0342":{"nm":"แพ็กสติกเกอร์เชียร์","de":"สติกเกอร์แต่ละแผ่นสลักข้อความเชียร์ไว้ บนไดอารี บนโทรศัพท์ บนมุมโน้ตบุ๊ก ไม่ว่าจะแปะที่ไหน ชีวิตประจำวันก็ถูกแต่งแต้มด้วยกำลังใจ หัวใจที่ชื่นชอบทิ้งร่องรอยไว้ทุกหนแห่งเช่นนี้เอง"},"ICON-0343":{"nm":"ปกป้องกันอัลบั้ม","de":"มือที่ห่ออัลบั้มด้วยปกอย่างระมัดระวัง เพื่อไม่ให้มุมสึกหรอ ไม่ให้ซีดจางเพราะแสงแดด เพลงฟังด้วยหู แต่แผ่นนี้มือคือสิ่งที่จดจำ มันคือชุดเกราะแห่งหัวใจที่อยากเก็บสิ่งที่รักไว้ใกล้ตัวไปนานๆ"},"ICON-0344":{"nm":"ห่วงซองแผ่นดิสก์","de":"ใส่แผ่นดิสก์ลงในซองแล้วรวมด้วยห่วง ก็กลายเป็นสมุดอัลบั้มหนึ่งเล่ม เสียงกรอบแกรบทุกครั้งที่พลิกไปทีละหน้าช่างไพเราะ การรวบรวมเพลงที่กระจัดกระจายให้เรียบร้อยอยู่ในมือ นั่นคือความสุขเงียบๆ ของนักสะสม"},"ICON-0345":{"nm":"ที่กั้นเก็บกู๊ดส์","de":"เพียงที่กั้นเดียว กู๊ดส์ที่เกือบปะปนกันก็หาที่ทางของตัวเองเจอ ตรงนี้โฟโต้การ์ด ตรงนั้นพวงกุญแจ ข้างๆ นั้นไฟแท่ง การจัดระเบียบคือการสร้างบ้านให้กับสิ่งของ ในวินาทีที่ช่องแบ่งออกจากกัน ความยุ่งเหยิงก็เปลี่ยนเป็นระเบียบ"},"ICON-0346":{"nm":"เชือกผนึกแพ็กสุ่ม","de":"มัดปากแพ็กสุ่มด้วยเชือกให้แน่น ชะตากรรมของใครก็ยังไม่ถูกกำหนดจนกว่าจะแก้ออก ก่อนคลายปม ทุกคนคือพระเอกของความหวังของตัวเอง ความสั่นของปลายนิ้วที่แก้ผนึกออกนั่นแหละคือความสนุกที่เชือกเส้นนี้เฝ้ารักษามาตลอด"},"ICON-0347":{"nm":"กล่องจัดของพิเศษ","de":"ของพิเศษเรียงแถวตามประเภทอยู่ในกล่อง โปสการ์ดอยู่กับโปสการ์ด ที่คั่นหนังสืออยู่กับที่คั่นหนังสือ มองช่องที่แน่นขึ้นเรื่อยๆ เมื่อของเพิ่มขึ้น ก็เห็นเวลาที่สะสมมาตลอดในสายตาเดียว การจัดระเบียบก็คือบัญชีรายการความทรงจำนั่นเอง"},"ICON-0348":{"nm":"ป้ายแยกเวอร์ชัน","de":"มีสิ่งที่ดูเหมือนกันแต่ไม่เหมือนกัน ป้ายเดียวแยกเวอร์ชัน A กับเวอร์ชัน B แยกพิมพ์ครั้งแรกกับพิมพ์ซ้ำ ด้วยเครื่องหมายเล็กๆ ความสับสนก็หายไป และโลกแห่งการสะสมก็ได้ป้ายชื่อที่ชัดเจนอีกหนึ่งใบ"},"ICON-0349":{"nm":"โน้ตเช็กยอดขายสัปดาห์แรก","de":"สัปดาห์แรกของการวางจำหน่าย ตัวเลขเพียงตัวเดียวทำให้หัวใจไหวหวั่น เครื่องหมายเช็กที่เขียนไว้เป็นระเบียบบนกระดาษโน้ต เมื่อบันทึกหลายวันรวมกันก็กลายเป็นสมุดพกแห่งกำลังใจเล็กๆ นิสัยอันประณีตที่แปลความรักให้เป็นตัวเลข"},"ICON-0350":{"nm":"ฝาล็อกโปสเตอร์","de":"สวมฝาที่ปลายโปสเตอร์ม้วนกลม มันก็คลี่คงรูปนิ่งสงบ ระหว่างลังเลว่าจะแขวนผนังหรือใส่กรอบดี ก็ไม่ยับย่นเสียก่อน เป็นจุกเล็กๆ ที่รักษาฉากที่ชอบที่สุดให้เรียบตรงอยู่เสมอ"},"ICON-0351":{"nm":"ฐานตั้งรูปถ่าย","de":"รูปถ่ายยืนเอียงอยู่บนฐาน อยู่มุมหนึ่งของโต๊ะ ในมุมที่พอดีกับระดับสายตา สิ่งประดิษฐ์ที่ทำให้สายตาสบกันทุกครั้งที่เดินผ่าน วิธีง่ายที่สุดในการนำใบหน้าที่รักเข้ามาอยู่ในทิวทัศน์ของทุกวัน"},"ICON-0352":{"nm":"ม้วนเทปซ้อมการแสดง","de":"แปะเทปบนพื้นเพื่อทำเครื่องหมายจุดที่ต้องยืน หนึ่งช่อง สองช่อง ตรงนี้พอดี เหยียบรอยเดิมซ้ำนับสิบครั้ง เส้นทางการเคลื่อนไหวก็สลักลงในร่างกาย ใต้เวทีอันตระการตานั้นมีรอยเทปซื่อตรงเหล่านี้ปูรองอยู่"},"ICON-0353":{"nm":"พินกำหนดจุดยืนบนเวที","de":"พินเล็กๆ หนึ่งตัวที่ปักลงบนพื้นเวทีบอกก้าวต่อไป แม้ในความมืด ปลายเท้าก็ยังหาจุดนั้นเจอก่อนสิ่งใด เส้นทางที่แม่นยำแม้มองไม่เห็น เป็นแผนที่ล่องหนที่การซ้อมนับครั้งไม่ถ้วนวาดไว้"},"ICON-0354":{"nm":"หูฟังกันเสียงสตาฟ","de":"สวมหูฟังแล้ว เสียงโห่ร้องของผู้ชมก็เบาลงไปหนึ่งชั้น เหลือเพียงเสียงที่ส่งคิวเท่านั้นที่ชัดเจน หูของสตาฟหลังเวทีได้ยินสองโลกไปพร้อมกันเสมอ เป็นเครื่องมือเล็กๆ สำหรับเลือกจับสัญญาณท่ามกลางความอึกทึก"},"ICON-0355":{"nm":"ป้ายไม้แขวนเสื้อห้องพัก","de":"ป้ายชื่อแขวนอยู่บนไม้แขวนเสื้อทุกอัน ชุดที่ 1 ชุดที่ 2 ชุดอังกอร์ มองตารางที่เขียนลำดับการเปลี่ยนชุดไว้เรียงกัน ก็เห็นเวทีของวันนี้ถูกร่างไว้ล่วงหน้าด้วยลำดับของเสื้อผ้า ระเบียบเงียบๆ ที่ควบคุมความวุ่นวายไว้ได้"},"ICON-0356":{"nm":"แท็กตรวจสอบพร็อพ","de":"ก่อนขึ้นเวที แท็กจะถูกติดไว้กับพร็อพทุกชิ้น มีอะไรขาดหายไปไหม ยังใช้งานได้ดีไหม ผู้ชมไม่รู้ แต่การตรวจสอบเล็กๆ นี้ป้องกันอุบัติเหตุได้ หลังเวทีที่ดูสมบูรณ์แบบมักมีมือที่พิถีพิถันคอยอยู่เสมอ"},"ICON-0357":{"nm":"ชิปสัญญาณคิว","de":"ชิปสัญญาณคิวส่งต่อจากมือสู่มือ ตอนนี้ เข้าไปได้เลย ช่วงเวลาที่จังหวะถูกส่งต่อโดยไม่มีคำพูดสักคำ ในความมืดข้างเวที สัญญาณเล็กๆ นี้เองที่ยึดจังหวะของทุกคนไว้ไม่ให้พลาด"},"ICON-0358":{"nm":"แพตช์แบ็กสเตจ","de":"มีประตูที่มีเพียงผู้สวมแพตช์นี้เท่านั้นที่ผ่านไปได้ หลังเวที ที่เสียงโห่ร้องลอดผ่านกำแพงเข้ามา ผ้าชิ้นเล็กๆ เพียงชิ้นเดียวแบ่งด้านหน้าที่ตระการตากับด้านหลังที่วุ่นวายออกจากกัน เป็นเครื่องหมายของผู้คนที่ค้ำจุนเวทีไว้"},"ICON-0359":{"nm":"แผ่นบังแสงพรอมป์เตอร์","de":"แผ่นบังคอยกันไม่ให้แสงจากพรอมป์เตอร์รั่วไหลไปถึงที่นั่งผู้ชม ให้เฉพาะคนบนเวทีเห็น ส่วนคนดูไม่รู้ตัว เป็นผู้เฝ้ารักษาความลับอันสุภาพของเวที ที่ปิดบังความช่วยเหลือซึ่งไม่ควรถูกจับได้ไว้อย่างเงียบๆ"},"ICON-0360":{"nm":"ผ้าคลุมกระจกห้องพัก","de":"ห้องพักหลังการแสดงจบลง กระจกถูกคลุมด้วยผ้า กระจกที่สะท้อนสีหน้านับไม่ถ้วนตลอดทั้งวันก็หลับตาลงชั่วขณะ ใบหน้าเปล่าเปลือยที่ล้างเครื่องแต่งหน้าออกแล้วเผชิญหน้าเป็นครั้งสุดท้าย ไม่ใช่กระจก แต่คือความมืดอันเงียบสงบ"},"ICON-0361":{"nm":"สายรัดข้อมือเข้าชมบันทึกล่วงหน้า","de":"แถบเล็กๆ ที่เมื่อรัดแล้วจะไม่หลุดออกจนกว่าจะถูกตัด เพื่อคุณสมบัติเพียงหนึ่งเดียวในการเข้าไปนั่งชมการบันทึกล่วงหน้า บางคนขึ้นรถไฟเที่ยวแรกในยามเช้ามืดสนิท น้ำหนักบนข้อมือจึงกลายเป็นความตื่นเต้นของทั้งวันนั้น"},"ICON-0362":{"nm":"ป้ายรอบันทึกภาพ","de":"ก่อนไฟแดงจะติดขึ้น หน้าที่ของฉันคือมัดลมหายใจของทุกคนไว้เป็นแถวเดียว ในความเงียบที่รอสัญญาณคิว ฉันทนอยู่เงียบๆ จนถึงวินาทีสุดท้าย พอถูกลอกออก ม่านของการถ่ายทอดสดจึงเปิดขึ้นเสียที"},"ICON-0363":{"nm":"ชิปกำหนดตำแหน่งกล้อง","de":"เครื่องหมายเล็กๆ ที่ประทับบนพื้นเพียงจุดเดียวกำหนดเส้นทางของกล้องหกตัวไว้อย่างแม่นยำ ตรงไหนที่ถ่ายแล้วสว่างที่สุด ผู้กำกับรู้ตั้งแต่ก่อนซ้อมแล้ว มือที่ร่างสิ่งที่อยู่ในจอไว้ล่วงหน้าจากนอกจอ"},"ICON-0364":{"nm":"ป้ายเช็กเสียง","de":"เคาะไมโครโฟนเบาๆ ไปยังที่นั่งที่ว่างเปล่า หากเสียงสะท้อนนานเกินไป ก็เพิ่มแผ่นดูดซับเสียงบนเพดานอีกชั้น ความใส่ใจในการปรับแต่งลายเนื้อของเสียงโดยที่ผู้ชมไม่มีวันรู้ เริ่มต้นขึ้นอย่างเงียบๆ จากป้ายเล็กๆ ใบนี้"},"ICON-0365":{"nm":"สมุดแสตมป์หน้างาน","de":"ทุกครั้งที่ผ่านไปยังงานอีเวนต์ ก็เก็บตราประทับไว้ทีละช่อง ในรอยหมึกที่เปื้อนไปทุกจุด อากาศของวันนั้นและความตื่นเต้นถูกประทับไว้ด้วย หน้ากระดาษที่เต็มแล้วกลายเป็นแผนที่รอยเท้าที่ไม่มีใครลอกเลียนได้ เป็นของฉันเพียงคนเดียว"},"ICON-0366":{"nm":"สายบัตรผู้เยี่ยมชมสถานีโทรทัศน์","de":"หากไม่มีสายเส้นนี้ ประตูล็อบบี้จะไม่มีวันเปิดออก ระหว่างที่คล้องคอเดินไปตามทางเดินทีละก้าว โลกที่เคยเห็นแค่ผ่านหน้าจอจนถึงเมื่อวาน ก็ค่อยๆ เข้ามาใกล้จนแตะต้องได้"},"ICON-0367":{"nm":"แพ็กถุงคลุมเท้าสตูดิโอ","de":"พื้นสตูดิโอเย็นและลื่นอยู่เสมอ ถอดรองเท้าแล้วสวมถุงคลุมเท้าบางๆ เสียงฝีเท้าก็เงียบหายไป เพราะกล้องบันทึกท่าเต้นไม่ใช่ฝีเท้า การลบเสียงจึงเป็นมารยาทอย่างหนึ่งที่มีต่อเวที"},"ICON-0368":{"nm":"ป้ายขนมห้องพัก","de":"ระหว่างการซ้อมกับการแสดงจริง ความหิวมาเยือนอย่างซื่อตรงที่สุด ป้ายชื่อเล็กๆ ที่เขียนไว้บนขนมแต่ละชิ้นมุมห้องพักบอกว่าเป็นของใคร ความอ่อนโยนที่คอยเตรียมไว้ให้นั้นแหละที่ทำให้ผ่านวันอันยาวนานไปได้จนถึงที่สุด"},"ICON-0369":{"nm":"แถบโน้ตมอนิเตอร์","de":"ดูภาพย้อนกลับแล้วจดบันทึก ตรงนี้ต้องมองไปทางไหน ตรงนั้นต้องช้าไปครึ่งจังหวะ ลายมือที่แน่นเต็มแผ่นคือจดหมายลับส่งถึงตัวเองในวันพรุ่งนี้ แถบที่แปะไว้ตอนท้ายคือคำสัญญาเงียบๆ ว่าจะดีขึ้นกว่าเมื่อวานอีกนิดหนึ่ง"},"ICON-0370":{"nm":"ใบเชิญโชว์เคส","de":"กระดาษแผ่นเดียวอาจกลายเป็นการรอคอยเต็มหนึ่งปีสำหรับใครสักคน ประโยคสั้นๆ ที่เชิญไปร่วมโชว์เคส ถือกำเนิดเป็นบัตรเชิญที่เล็กที่สุดในโลก พร้อมเก็บแม้กระทั่งความสั่นของปลายนิ้วที่เปิดซองไว้ด้วย"},"ICON-0371":{"nm":"สายคล้องคอสื่อมวลชน","de":"คล้องคอทีมข่าวไว้ พาลัดเลาะไปกลางเสียงชัตเตอร์ดังกระหึ่ม ฝีเท้าที่รีบวิ่งหามุมที่ดีที่สุด ความเร็วนั้นเองกลายเป็นทางผ่านที่นำความร้อนแรงของเวทีออกไปสู่โลกภายนอก"},"ICON-0372":{"nm":"ตารางลำดับกล่าวคำอำลาบนเวที","de":"เพื่อไม่ให้ใครสับสนแม้ในวินาทีที่เสียงปรบมือหลั่งไหลลงมา ใครก่อนใครหลังถูกเขียนไว้เป็นแถวเดียว การจัดลำดับคำอำลาสุดท้ายถูกวางไว้อย่างพิถีพิถันไม่ต่างจากการปรากฏตัวครั้งแรกเลย"},"ICON-0373":{"nm":"เครื่องหมายพื้นโฟโต้วอลล์","de":"ที่พื้นหน้าโฟโต้วอลล์มีจุดวางปลายเท้าสลักไว้ล่วงหน้า เพียงเยื้องไปก้าวเดียวโลโก้ฉากหลังก็จะถูกตัดขาด ความลับของตำแหน่งที่ถ่ายออกมาสว่างที่สุดถูกทำเครื่องหมายไว้อย่างเงียบๆ ใต้ฝ่าเท้า"},"ICON-0374":{"nm":"สายรัดข้อมือรอบพรีวิว","de":"แถบเล็กๆ ที่รัดข้อมือก่อนไฟโรงภาพยนตร์จะดับลง เมื่อม่านเปิดขึ้น ทุกคนต่างพบฉากเดียวกันเป็นครั้งแรกในชีวิตท่ามกลางความมืดเดียวกัน เป็นเครื่องหมายเล็กๆ ของการได้ร่วมอยู่ในวินาทีแรกนั้นด้วยกัน"},"ICON-0375":{"nm":"ชิ้นผ้าม่านที่ระลึก","de":"วันสุดท้ายของการแสดง หลังคำอำลาครั้งสุดท้าย ม่านค่อยๆ เลื่อนลงมา ชิ้นส่วนที่ตัดจากผืนผ้านั้นถูกใส่กรอบเก็บไว้ ในผืนผ้ายังคงมีไอร้อนของแสงไฟและแรงสั่นสะเทือนของเสียงปรบมือหลงเหลืออุ่นๆ ยังไม่ทันเย็นลง"},"ICON-0376":{"nm":"ตราประทับเปิดตัวครั้งแรก","de":"วันที่เผยโฉมสู่โลกเป็นครั้งแรก ตราที่สลักไว้เพื่อครั้งเดียวนั้นโดยเฉพาะ ไม่มีการเปิดตัวครั้งแรกครั้งที่สอง แม้แต่ช่วงเวลาสั้นๆ ที่หมึกแห้งตัวก็เป็นเวลาที่ไม่มีวันหวนคืนมาอีก"},"ICON-0377":{"nm":"การ์ดฉากเวที","de":"ฉากที่เปล่งประกายที่สุดฉากหนึ่งบนเวทีถูกตัดใส่ลงในการ์ด แม้เพลงและแสงไฟจะหยุดลงแล้ว แต่ทันทีที่กำไว้ในมือ เสียงโห่ร้องของวันนั้นก็พองขึ้นในหูอีกครั้ง เวทมนตร์เล็กๆ ที่ฉากซึ่งหยุดนิ่งไว้กลับมีชีวิตขึ้นมาอีกครั้ง"},"ICON-0378":{"nm":"โน้ตท่าจบเพลง","de":"ในเสี้ยววินาทีที่เสียงสุดท้ายจบลง โน้ตที่ร่างมุมของปลายนิ้วและสายตาที่ต้องหยุดนิ่งไว้ มีเพียงผู้ที่รู้ว่าฉากจบเพียงฉากเดียวสามารถส่งผลถึงหลายวันเท่านั้น จึงพับภาพวาดเล็กๆ นี้เก็บไว้อย่างทะนุถนอม"},"ICON-0379":{"nm":"พินเมืองทัวร์","de":"บนแผนที่ ทุกเมืองที่เคยไปเยือนถูกปักด้วยพินหนึ่งตัว ทั้งลมทะเลของปูซานและแดดเที่ยงของควังจูล้วนติดอยู่ที่ปลายตะปูเล็กๆ นี้ เชื่อมจุดต่างๆ เข้าด้วยกันเงียบๆ ก็จะเห็นเส้นทางการเดินทางอันยาวไกลที่ตัดผ่านหนึ่งฤดูกาล"},"ICON-0380":{"nm":"คลิปเขตที่นั่ง","de":"แบ่งที่นั่งนับหมื่นที่ออกเป็นเขตๆ แล้วนำทางให้ เพื่อไม่ให้หลงทาง เพื่อไม่ให้ชนกัน ตามฉันไปแล้วใครก็ไปถึงที่นั่งของตัวเองได้ เพราะระเบียบท้ายที่สุดแล้วก็คือความกรุณาเล็กๆ เพื่อทุกคนนั่นเอง"},"ICON-0381":{"nm":"แท็กประตูทางเข้า","de":"หน้าประตู ผ่านการตรวจสอบทีละคนตามลำดับ เป็นด่านสุดท้ายที่รับมือที่กำตั๋วไว้และหัวใจที่เต้นแรงเข้าไปข้างใน ในวินาทีที่ผ่านฉันไป การรอคอยอันยาวนานก็สิ้นสุดลง และเวทีของวันนี้ก็เริ่มต้นขึ้น"},"ICON-0382":{"nm":"แคปซูลเก็บสายรัดข้อมือ","de":"แม้สีจะซีดจางไป แต่เสียงโห่ร้องของวันนั้นยังคงถูกผนึกไว้เหมือนเดิม ไม่อาจทิ้งแถบที่เคยรัดข้อมือไปได้ จึงม้วนเก็บไว้อย่างประณีตในแคปซูลเล็กๆ เพราะอยากมอบพื้นที่สักช่องหนึ่งให้ความทรงจำล้ำค่าได้พักพิงร่างกายของมัน"},"ICON-0383":{"nm":"ไม้แลกเปลี่ยนหน้างาน","de":"ระหว่างแฟนคลับกับเวที บางสิ่งถูกส่งผ่านจากมือสู่มือ อาจเป็นจดหมาย อาจเป็นของขวัญเล็กๆ ฉันเปิดทางให้หัวใจดวงนั้นเดินทางไปถึงอย่างปลอดภัย เป็นสะพานที่วุ่นที่สุดในงาน"},"ICON-0384":{"nm":"ซีลวันที่การแสดง","de":"วันที่ของวันนั้นถูกประทับไว้ในซีลกลมและหยุดนิ่งไปตลอดกาล ปฏิทินพลิกหน้าไปเรื่อยๆ แต่มีเพียงวงกลมเล็กๆ นี้เท่านั้นที่ยังคงอยู่ในวันนั้นเสมอ เมื่อเป็นวันที่ไม่อยากลืม ผู้คนจึงมักผนึกบางสิ่งเก็บไว้เสมอ"},"ICON-0385":{"nm":"แพตช์กระเป๋าทัวร์","de":"กระเป๋าที่ร่วมทัวร์ไปด้วยกันมีแพตช์เพิ่มขึ้นทีละแผ่นในทุกเมือง ชื่อสถานที่ที่เย็บไว้บนผ้ากลายเป็นประวัติการทำงานโดยไม่รู้ตัว แม้แต่มุมที่สึกหรอเปื่อยยุ่ยก็ยังเหลือไว้เป็นหลักฐานว่าเคยไปด้วยกันทุกที่"},"ICON-0386":{"nm":"เชือกป้ายตั๋ว","de":"ป้ายที่แกว่งไกวอยู่ปลายแถวเข้างาน ปลายของมันถูกผูกแน่นด้วยเชือกเส้นหนึ่ง ท่ามกลางทิวทัศน์ของมือที่ถือตั๋วชูสูงเรียงยาว ฉันทำเครื่องหมายหัวขบวนของแถวความตื่นเต้นที่เรียงต่อกันไว้อย่างเงียบๆ"},"ICON-0387":{"nm":"ชิ้นริบบิ้นอังกอร์","de":"คืนที่เสียงตะโกนขออังกอร์ดังที่สุด ริบบิ้นที่ประดับเวทีชิ้นหนึ่งหลุดร่วงลงมา เหมือนเพลงที่ร้องยาวขึ้นเพราะเสียดายที่จะจบลง ชิ้นส่วนนี้ก็ผูกปมความไม่อยากจากลาไว้เช่นกัน"},"ICON-0388":{"nm":"ขวดแคปซูลข้อความ","de":"คำพูดหนึ่งคำที่พับเก็บไว้อย่างประณีตในขวดแก้ว เหมือนเรือลำเล็กที่ปล่อยลอยไปด้วยหวังว่าสักวันจะไปถึง ฉันโอบอุ้มหัวใจไว้แล้วล่องลอยไปตามกาลเวลาอย่างช้าๆ จนถึงวันที่ถูกเปิดออก คำสัญญานั้นหลับใหลอยู่ข้างในอย่างเงียบๆ"},"ICON-0389":{"nm":"ป้ายคำสารภาพเล็กๆ","de":"คำที่พูดออกจากปากไม่ได้ ถูกเขียนลงบนป้ายเล็กๆ แล้วสอดไว้อย่างเงียบๆ ลายมือสั่นไหว แต่มีเพียงความจริงใจเท่านั้นที่ชัดเจน บางครั้งกระดาษที่เล็กที่สุดก็บรรจุความกล้าหาญที่ยิ่งใหญ่ที่สุดไว้ได้"},"ICON-0390":{"nm":"กล่องข้อความให้กำลังใจนิรนาม","de":"แม้ไม่เขียนชื่อ หัวใจก็ยังส่งถึงกันได้ ในทุกข้อความที่หย่อนลงกล่อง กำลังใจของใครสักคนสะสมทีละแผ่นอย่างไม่ระบุชื่อ แม้ไม่รู้ว่าใครเขียน แต่มีเพียงความอบอุ่นเท่านั้นที่ชัดเจน เป็นชุมนุมความอ่อนโยนที่ไร้ใบหน้า"},"ICON-0391":{"nm":"กระดาษพับหัวใจ","de":"กระดาษสี่เหลี่ยมกลายเป็นนกกระเรียน กลายเป็นดวงดาว ตามปลายนิ้วที่พับไป ทุกครั้งที่พับ ความปรารถนาก็ซ้อนทับกันเพิ่มขึ้นอีกชั้นหนึ่ง ในรูปทรงที่พับด้วยความตั้งใจนั้นมีความจริงใจที่คงอยู่นานกว่าคำพูดซ่อนอยู่"},"ICON-0392":{"nm":"ขี้ผึ้งปิดผนึกริบบิ้น","de":"หยดขี้ผึ้งลงแล้วกดตราประทับลงไปให้แน่น จดหมายจึงถูกผนึกเสียที ยังคงเป็นวิธีเก่าแก่ที่ใช้ตรึงหัวใจให้มั่นคง บนขี้ผึ้งสีแดงที่ค่อยๆ เย็นลง ความลับหนึ่งข้อถูกล็อกไว้อย่างเงียบสงบ"},"ICON-0393":{"nm":"กระดาษกันกระแทกของขวัญ","de":"เกรงว่าของขวัญจะบอบช้ำ จึงห่อหุ้มรอบตัวมันไว้อย่างนุ่มนวล ในทุกรอยย่นซึมซาบคำขอร้องไม่ให้แตกหักไว้ เป็นชั้นหัวใจอันระมัดระวังในที่ที่มองไม่เห็น ซึ่งผู้รับตัวจริงอาจไม่มีวันรู้และผ่านเลยไป"},"ICON-0394":{"nm":"เชือกจดหมายสี","de":"แม้แต่เชือกที่มัดจดหมายก็ยังมีสี สีเหลืองคือกำลังใจ สีฟ้าคือความคิดถึง ความรู้สึกที่คำพูดบอกไม่หมดถูกเลือกด้วยเฉดสีแล้วผูกเป็นปม ก่อนจะแก้ปมออกด้วยซ้ำ อุณหภูมิของหัวใจก็มาถึงปลายนิ้วก่อนแล้ว"},"ICON-0395":{"nm":"แถบปิดลายมือ","de":"แถบหนึ่งเส้นที่ปิดบังลายมือไว้จนถึงวินาทีสุดท้ายก่อนส่งมอบ มันเฝ้ารักษาคำสารภาพที่หวาดผวาว่าจะถูกจับได้จนถึงวินาทีสุดท้าย ความจริงใจที่ปรากฏออกมาเมื่อเปิดเผยเพียงนิดเดียว น้ำหนักของความสั่นไหวนั้นฉันรู้ใกล้ที่สุด"},"ICON-0396":{"nm":"ชิปประโยคเชียร์","de":"ในคืนที่ไฟแท่งไหวระริก ประโยคเดียวที่จะตะโกนเป็นเสียงเดียวกันถูกสลักไว้ในชิป คำสัญญาที่รวบรวมหัวใจที่กระจัดกระจายให้เป็นแถวเดียวกัน เมื่อร้องพร้อมกันทุกคน ประโยคนั้นก็เปล่งประกายที่สุด"},"ICON-0397":{"nm":"พวงกุญแจห้องซ้อมเก่า","de":"พวงกุญแจที่เปิดปิดประตูห้องซ้อมมานับร้อยครั้ง สีลอกและห่วงหลวมคลอน แต่ในนั้นยังหลงเหลือเหงื่อของวันเวลาที่งุ่มง่ามที่สุดเป็นคราบมือ ความเก่าหมายถึงการอยู่ที่นั่นมานานเพียงนั้นเอง"},"ICON-0398":{"nm":"ชิ้นดินสอเมกอัพเวที","de":"เมกอัพสำหรับเวทีจะสมบูรณ์ก็ต่อเมื่ออยู่ใต้แสงไฟเท่านั้น ชิ้นสีเข้มชิ้นนั้น ในรอยที่ทาไว้อย่างหนาแน่นเพื่อไม่ให้เลอะแม้จะมีเหงื่อ ซึมซาบความตั้งใจที่อยากส่งสีหน้าไปให้ถึงที่นั่งไกลๆ ไว้เต็มเปี่ยม"},"ICON-0399":{"nm":"เคสใส่จุกหูฟัง","de":"จุกหูฟังเล็กๆ ที่ทำให้ได้ยินเสียงของตัวเองบนเวที เมื่อการแสดงจบลงก็วางนอนไว้อย่างประณีตในเคส ยิ่งเป็นสิ่งที่นำพาเสียงเพลงมาให้ใกล้ที่สุด ก็ยิ่งอยากเก็บรักษาไว้อย่างพิถีพิถันมากขึ้น"},"ICON-0400":{"nm":"ป้ายล็อกเกอร์ส่วนตัว","de":"ปลายทางเดินหอพัก ป้ายชื่อติดอยู่บนล็อกเกอร์ทุกช่อง ลายมือเล็กๆ ที่บอกว่าเป็นที่ของใครเปลี่ยนพื้นที่แปลกหน้าให้กลายเป็นบ้าน การได้มีช่องของตัวเองคือการอนุญาตอันอ่อนโยนว่าให้อยู่ที่นี่ได้"},"ICON-0401":{"nm":"ขวดดูแลลำคอพกพา","de":"ระหว่างพักซ้อม เธอค่อยๆ กลืนน้ำอุ่นสักอึกหนึ่งลงคอ ลำคอคือเครื่องดนตรีที่นักร้องยืมมาใช้ชั่วคราว ขวดใบเล็กนี้จึงถูกเติมไว้ก่อนน้ำจะเย็น เพื่อปกป้องโน้ตแรกของวันพรุ่งนี้ล่วงหน้า หัวใจที่ทะนุถนอมมักเงียบงันเช่นนี้เสมอ"},"ICON-0402":{"nm":"เข็มหมุดแจ้งเตือนตารางงาน","de":"บนวันหนึ่งที่แน่นขนัดไปด้วยนาทีต่างๆ เข็มหมุดเล่มหนึ่งชี้ไปยังช่องถัดไป ท่ามกลางแถวอันแน่นขนัดนั้น สิ่งที่น่ายินดีที่สุดคือช่องว่างเพียงหนึ่งช่อง เวลาที่จะได้มองออกไปนอกหน้าต่างสักครู่ ซ่อนตัวอยู่ตรงนั้นอย่างเล็กจ้อย"},"ICON-0403":{"nm":"คลิปหนีบผ้าห่มห้องพักรอ","de":"บ่ายวันหนึ่งที่แต่งหน้าเสร็จแล้วเผลอสัปหงกพิงเก้าอี้ มีใครสักคนค่อยๆ คลุมผ้าห่มไว้บนบ่าให้อย่างแผ่วเบา คลิปหนีบเล็กๆ ที่กัดผ้าไว้ไม่ให้ลื่นไถลนี้ เก็บกักไออุ่นจากสัมผัสนั้นไว้อย่างเงียบงัน จนกว่าจะถึงเวลาก้าวขึ้นเวที"},"ICON-0404":{"nm":"ตัวอย่างน้ำหอมขวดจิ๋ว","de":"แตะเบาๆ ที่ข้อมือด้านใน กลิ่นหอมจะโชยฟุ้งเพียงในระยะแค่ฝ่ามือเท่านั้น ไม่ต้องแผ่ไปไกลก็ไม่เป็นไร เพราะเป็นร่องรอยที่มีเพียงคนที่เข้ามาใกล้เท่านั้นจะรับรู้ได้ จึงลึกลับกว่า และนั่นทำให้เป็นตัวฉันมากกว่า"},"ICON-0405":{"nm":"ป้ายซักชุดซ้อม","de":"ไม่ว่าจะซักกี่ครั้ง กลิ่นเหงื่อที่ซึมลึกเข้าเนื้อผ้าก็ไม่มีวันจางหายไปหมด ระหว่างพับชุดซ้อมที่ตากแดดจนแห้งฟูนุ่ม เธอคิดว่า—รอยที่ลบไม่ออกนั้น แท้จริงแล้วคือร่องรอยที่ซื่อตรงที่สุด"},"ICON-0406":{"nm":"ฟิล์มเจลปรับแสงไฟ","de":"เพียงสอดฟิล์มสีบางๆ แผ่นเดียว แสงไฟสีขาวก็เอ่อล้นเป็นสีแสงอาทิตย์ตก หากซ้อนอีกแผ่นหนึ่ง รุ่งอรุณก็ลาดลงมา หลังม่านเวที มีมือที่กลั้นลมหายใจ กำลังตัดสินใจว่าจะแต่งแสงให้เป็นฤดูกาลใด แม้กระทั่งแสงก็ยังต้องสวมเสื้อผ้า"},"ICON-0407":{"nm":"ฝาปิดเลนส์สปอตไลต์","de":"แม้ในยามที่กล้องดับ ก็ยังมีใครบางคนเปิดฝาเล็กๆ นี้เพื่อเช็ดเลนส์ เพื่อฉากถัดไปที่ยังไม่ได้ถ่าย เหนือช่วงเวลาที่ไม่ปรากฏอยู่บนจอ มือที่ยุ่งที่สุดกำลังปรับโฟกัสไว้ล่วงหน้า"},"ICON-0408":{"nm":"แผ่นสะท้อนแสงเวที","de":"แม้จะไม่เปล่งประกายด้วยตัวเอง แต่ก็มีแผ่นหนึ่งที่ส่งแสงที่ได้รับกลับไปยังใบหน้าที่อยู่ในเงามืด กลางเวทีจึงสว่างไสวเช่นนี้ เพราะที่ริมขอบมีแขนของใครบางคนกำลังจัดมุมและสะท้อนแสงกลับไปอย่างเงียบเชียบ"},"ICON-0409":{"nm":"ปลอกฟิลเตอร์สี","de":"สอดแสงสีฟ้าลงในปลอกใส แล้วที่นั่งผู้ชมทั้งหมดก็กลายเป็นท้องทะเล เปลี่ยนเป็นแสงสีแดง แล้วตะวันก็ลับขอบฟ้าลง ณ ที่นั้น เวทีเดียวกันแปรเปลี่ยนเป็นฤดูกาลอื่นด้วยสีเพียงสีเดียว มนตร์นั้นเริ่มต้นจากชั้นบางๆ เพียงชั้นเดียวนี้เอง"},"ICON-0410":{"nm":"เข็มหมุดหมายเลขไฟ","de":"ไฟทุกดวงล้วนมีหมายเลขกำกับไว้ เลขไหนจะสว่างขึ้น เลขไหนจะดับหลับใหล การไหลของการแสดงคืนนี้ถูกจัดวางไว้ล่วงหน้าตามลำดับของตัวเลขเหล่านี้ เบื้องหลังม่านอันตระการตา มักมีรายการที่จดไว้อย่างละเอียดถี่ถ้วนเสมอ"},"ICON-0411":{"nm":"เทปไฟเรืองแสงบอกจุด","de":"บนพื้นเวทีที่มืดสนิท เทปเรืองแสงส่องสว่างจุดที่เท้าจะต้องหยุดอย่างเงียบงัน แม้ผู้ชมในที่นั่งจะมองไม่เห็น แต่ปลายเท้าของผู้แสดงคลำหาแสงอันริบหรี่นี้เพื่อค้นหาตำแหน่งของตน แม้ในความมืดก็ยังมีผู้นำทางที่อ่อนโยนอยู่เสมอ"},"ICON-0412":{"nm":"แผ่นกั้นเงา","de":"แผ่นกั้นที่บังแสงที่รั่วไหลเข้ามา เพื่อให้เงาตกลงมาอย่างคมชัด การจัดการความมืดนั้น ที่สุดแล้วก็คือการจัดการแสงนั่นเอง สิ่งที่จะเผยให้เห็นนั้น ถูกกำหนดขึ้นก่อนโดยสิ่งที่จะปิดบังไว้อย่างเงียบๆ"},"ICON-0413":{"nm":"ชิปวัดความสว่าง","de":"ชิปเล็กๆ ที่วัดความสว่างของพื้นที่ อ่านค่าตัวเลขอยู่บนฝ่ามือ เพราะสว่างเกินไปหรือมืดเกินไปล้วนทำให้ดวงตาไม่สบาย เส้นแบ่งที่พอเหมาะซึ่งมองไม่เห็นนี้ ที่ทำให้คนรู้สึกสบายที่สุดเมื่ออยู่ในนั้น ถูกชิปนี้เฝ้าปกป้องไว้อย่างเงียบเชียบ"},"ICON-0414":{"nm":"บังไฟสปอตพิน","de":"แผ่นบังที่ติดไว้ไม่ให้แสงพินสปอตรั่วไหลไปผิดที่ การรวมแสงไว้ให้กับคนเพียงคนเดียวคือความใส่ใจอันอ่อนโยน วินาทีที่ก้าวเท้าเข้าไปในวงแสงกลมนั้น โลกทั้งใบจะจับจ้องมองเพียงคนคนเดียวชั่วขณะหนึ่ง"},"ICON-0415":{"nm":"ชุดจุกหูฟัง","de":"จุกหูฟังคู่หนึ่งที่พอดีกับหูแนบสนิท เพียงขนาดคลาดเคลื่อนไปนิดเดียว เสียงก็รั่วไหล และเมื่อรั่วไหลก็พลาดจังหวะไปทันที เพลงที่ไร้การสั่นไหวแม้แต่น้อยบนเวที บางครั้งก็เริ่มต้นจากยางเล็กๆ คู่นี้เอง"},"ICON-0416":{"nm":"สายรัดตีนตุ๊กแกจัดสาย","de":"สายรัดตีนตุ๊กแกที่มัดสายไฟที่พันกันยุ่งให้เป็นระเบียบเป็นเส้นเดียว ยิ่งเป็นหลังเวทีที่ไม่มีใครมองเห็น ความเป็นระเบียบก็ยิ่งเปล่งประกาย ความเรียบร้อยของมัดสายไฟหนึ่งมัด ค้ำจุนเสียงที่ไหลลื่นไม่สั่นไหวอยู่ด้านหน้าเวทีไว้อย่างเงียบเชียบ"},"ICON-0417":{"nm":"ป้ายเช็คสายสัญญาณ","de":"ป้ายชื่อที่เขียนด้วยลายมือติดไว้บนสายนับสิบเส้นว่าเป็นเครื่องดนตรีชิ้นใด ตัวอักษรที่เอียงกระเท่เร่แต่ละตัวนั้น ต้องอยู่ในตำแหน่งของมัน เสียงที่เคยเล่นแยกกันจึงจะไหลมารวมเป็นเพลงเดียวได้ในที่สุด"},"ICON-0418":{"nm":"แผ่นรองเก็บเสียง","de":"แผ่นรองเก็บเสียงแผ่นหนึ่งที่กลืนทั้งเสียงฝีเท้าและการสั่นสะเทือนไว้อย่างเงียบงัน มันถูกปูไว้ในที่ที่ความเงียบเป็นสิ่งจำเป็นจริงๆ เสียงที่ใสที่สุดบางครั้งก็เพิ่งถือกำเนิดขึ้นบนพื้นอันเงียบสงบนี้ ที่ไม่มีเสียงรบกวนใดรั่วไหลออกมาเลย"},"ICON-0419":{"nm":"โทเคนเช็คเสียง","de":"โทเคนที่อุ่นขึ้นในมือระหว่างปรับเสียงก่อนการแสดง ทุกครั้งที่ตรวจไมค์เสร็จหนึ่งตัว ลำโพงเสร็จหนึ่งตัว ก็เปลี่ยนมือถือใหม่ ความสมบูรณ์แบบของเวทีจริงถูกหล่อหลอมขึ้นทีละก้าวภายในการซ้อมอันเงียบสงบนี้"},"ICON-0420":{"nm":"ฝาครอบหัวไมค์","de":"เพราะเป็นจุดที่เสียงนับไม่ถ้วนเคยสัมผัส เธอจึงเช็ดฝาที่ห่อหุ้มปลายไมค์นี้อย่างพิถีพิถันยิ่งขึ้น มันคือภาชนะที่บรรจุบทเพลงไว้ สำหรับนักร้องแล้วมันก็เหมือนมืออีกข้างหนึ่ง ระหว่างเช็ดอยู่นั้น เธอวาดภาพท่อนแรกของพรุ่งนี้ไว้ล่วงหน้าในใจ"},"ICON-0421":{"nm":"คลิปฟิลเตอร์กันลมปาก","de":"ตาข่ายบางๆ ชั้นหนึ่งที่กั้นระหว่างริมฝีปากกับไมโครโฟน ด้วยคลิปเล็กๆ ที่ยึดแผ่นกั้นนั้นไว้ ลมหายใจที่เคยรั่วไหลออกมาแข็งกร้าวจึงถูกขัดเกลาจนกลายเป็นเสียงที่กลมกล่อมนุ่มนวลไหลออกมาโดยไม่รู้ตัว"},"ICON-0422":{"nm":"ป้ายแท็กแร็คเครื่องเสียง","de":"หลังเวทีอันมืดมิด ท่ามกลางชั้นวางอุปกรณ์ที่เรียงซ้อนกันเป็นชั้นๆ ป้ายเล็กๆ ถูกแขวนไว้เพื่อไม่ให้หลงทาง ต้นกำเนิดของเสียงอันตระการตาที่เติมเต็มที่นั่งผู้ชมนั้น มักถูกจัดเก็บอย่างเป็นระเบียบเรียบร้อยในที่มืดสลัวเช่นนี้เสมอ"},"ICON-0423":{"nm":"เข็มหมุดตะแกรงลำโพง","de":"เข็มหมุดที่ยึดตะแกรงลำโพงให้แน่นหนา หน้าต่างที่เสียงลอดออกมานั้นเป็นจุดแรกที่ฝุ่นละอองจะจับ ตาข่ายบางๆ ชั้นเดียวจึงปกป้องเสียงไว้ ทุกสิ่งที่มาถึงหูล้วนมีชั้นปกป้องที่มองไม่เห็นห่อหุ้มไว้เสมอ"},"ICON-0424":{"nm":"สติกเกอร์บอกจุดยืน","de":"สติกเกอร์บอกทางเดินที่แปะไว้เป็นจุดๆ บนพื้น ความลับที่ทำให้ท่าเต้นหมู่เข้าจังหวะกันเป๊ะราวกับมีดคมนั้น แท้จริงซ่อนอยู่ใต้ฝ่าเท้า บนรอยที่นัดหมายกันไว้นับไม่ถ้วน ที่คนหลายสิบคนเหยียบจุดเดียวกัน แยกย้าย แล้วกลับมารวมกันอีกครั้ง"},"ICON-0425":{"nm":"แผ่นหมุนฝึกเทิร์น","de":"แผ่นฝึกซ้อมที่หมุนวนอยู่กับที่ หากจะเอาชนะอาการเวียนหัว ต้องเริ่มเรียนรู้จากการตรึงสายตาไว้ที่จุดเดียวก่อน ไม่ว่าจะหมุนเร็วแค่ไหนก็ไม่ปล่อยจุดนั้นไป นี่คือความสมดุลที่ค่อยๆ สลักลงในร่างกาย"},"ICON-0426":{"nm":"ม้วนเทปพันเข่า","de":"เทปม้วนหนึ่งที่พันหัวเข่าให้แน่นหนา ข้อต่อที่กระโดดและลงพื้นมานับพันครั้งเงียบงันจนถึงที่สุด แต่ชั้นเดียวนี้ค้ำจุนความเงียบนั้นไว้อย่างแผ่วเบา เบื้องหลังร่างกายที่ยืนหยัดจนถึงวินาทีสุดท้ายเสมอมีการดูแลของใครบางคน"},"ICON-0427":{"nm":"แผ่นจัดแนวปลายเท้า","de":"แผ่นที่จัดมุมปลายเท้าให้เรียบร้อย เพราะเขาว่ากันว่าการเต้นสมบูรณ์แบบที่ปลายเท้ายิ่งกว่าปลายนิ้ว ปลายเท้านับสิบคู่ที่เหยียดไปในทิศทางเดียวกันมารวมกัน สร้างมนตร์ขลังที่ทำให้หลายคนดูราวกับเป็นคนเดียวกัน"},"ICON-0428":{"nm":"แผ่นกันลื่นห้องซ้อม","de":"แผ่นกันลื่นที่ปูไว้บนพื้นห้องซ้อม หากจะกระโดดได้อย่างเต็มที่ ต้องปลอดภัยเสียก่อน มีเพียงบนพื้นที่กลิ้งตัวได้อย่างสบายใจโดยไม่ต้องกังวลว่าจะล้มเท่านั้น ท่าทางที่กล้าหาญและไม่หวั่นเกรงที่สุดจึงจะผลิบานขึ้นได้ในที่สุด"},"ICON-0429":{"nm":"การ์ดแยกท่าเต้น","de":"การ์ดที่แยกท่าเต้นออกเป็นชิ้นเล็กๆ ทีละจังหวะ ไม่ว่าท่าจะยากแค่ไหน หากแบ่งทีละช่องก็ไล่ตามได้โดยไม่รู้ตัว การไหลลื่นราวกับสายน้ำบนเวทีนั้น เกิดจากภาพที่แบ่งย่อยและท่องจำไว้เช่นนี้มารวมกัน"},"ICON-0430":{"nm":"เข็มหมุดม่านบังกระจก","de":"เข็มหมุดที่ยึดม่านที่บังกระจกในห้องซ้อมไว้ชั่วคราว บางครั้งก็จำเป็นต้องเต้นด้วยประสาทสัมผัสของร่างกายเพียงอย่างเดียว โดยไม่มีภาพสะท้อนใดๆ วินาทีที่กระจกถูกปิดคลุมไว้ เธอรู้ดีว่าดนตรีจะซึมซาบเข้าถึงผิวหนังในที่สุด"},"ICON-0431":{"nm":"ลูกปัดนับจังหวะ","de":"กริ๊ก นับจังหวะไปพร้อมกับดันลูกปัดทีละเม็ดด้วยปลายนิ้วในทุกจังหวะ จับต้องได้เหมือนวิธีนับแบบโบราณ จังหวะซึ่งเป็นโครงสร้างของดนตรีนั้น ต้องเรียนรู้ผ่านสิ่งที่สัมผัสได้เช่นนี้เท่านั้น จึงจะฝังแน่นลงในร่างกายอย่างมั่นคง"},"ICON-0432":{"nm":"สายเช็คการวอร์มอัพ","de":"สายเช็คที่บันทึกไว้ว่ายืดเส้นยืดสายครบหรือยัง ก่อนการซ้อมจริงจังจะมาถึง มักมีการเตรียมตัวอย่างใจเย็นมาก่อนเสมอ แทนที่จะเสียใจภายหลังจากบาดเจ็บ การผูกสายเส้นหนึ่งแล้วค่อยๆ ปลุกร่างกายให้ตื่นตัว ท้ายที่สุดแล้วกลับทำให้เต้นได้นานขึ้น"},"ICON-0433":{"nm":"คลิปหมายเลขชุด","de":"คลิปที่กัดหมายเลขติดไว้ไม่ให้ชุดหลายชุดปะปนกัน ในช่วงเปลี่ยนชุดที่หายใจไม่ทัน แม้เพียงชุดเดียวสับสนก็เป็นเรื่องใหญ่ เสื้อผ้าทุกตัวจึงมีลำดับของตนเขียนไว้อย่างชัดเจน แม้แต่ความวุ่นวายก็งดงามได้เมื่อมีระเบียบค้ำจุน"},"ICON-0434":{"nm":"หมอนปักเข็มห้องซ่อมเสื้อ","de":"หมอนปักเข็มที่วางอยู่มุมหนึ่งของห้องซ่อมเสื้อ มือที่เย็บตะเข็บที่ขาดและกระดุมที่หลุดอย่างเงียบเชียบพักอยู่ที่นี่ เบื้องหลังเครื่องแต่งกายที่เรียบร้อยไร้ที่ติบนเวทีนั้น ซ่อนความตั้งใจของฝีเข็มที่ไม่เคยได้เห็นเวทีแม้แต่ครั้งเดียว"},"ICON-0435":{"nm":"ห่วงเก็บเศษผ้า","de":"ห่วงที่ร้อยเศษผ้าสำรองไว้ด้วยกัน เผื่อไว้สำหรับเวลาที่ชุดหลักเสียหาย จึงเก็บผ้าชนิดเดียวกันไว้ล่วงหน้า การเตรียมตัวเล็กๆ นี้ที่เก็บไว้ด้วยความหวังว่าจะไม่มีเรื่องอะไรเกิดขึ้น กลับช่วยชุดเวทีไว้ได้ในวินาทีที่เรื่องใหญ่มาถึงจริงๆ"},"ICON-0436":{"nm":"ชุดกระดุมติดด่วน","de":"ชุดกระดุมที่ติดได้ทันทีในยามเร่งด่วน ก่อนการแสดงไม่นาน หากกระดุมเม็ดหนึ่งหลุดปุ๊บ ห้องแต่งตัวทั้งห้องก็จะโกลาหลขึ้นทันที นี่คือชุดปฐมพยาบาลเล็กๆ แต่น่าเชื่อถือที่สุด ที่ระงับสถานการณ์ฉุกเฉินอันสั้นและชวนวูบวาบนั้นได้ในพริบตา"},"ICON-0437":{"nm":"ตัวยึดเข็มขัดเวที","de":"ตัวยึดที่จับเข็มขัดของชุดเวทีไว้อย่างแน่นหนา เพื่อไม่ให้ชุดหลุดลุ่ยแม้จะกระโดดและหมุนตัวอย่างรุนแรง อิสรภาพที่ได้เพลิดเพลินอย่างเต็มที่บนเวทีนั้น ท้ายที่สุดแล้วมาจากการรัดส่วนที่มองไม่เห็นให้แน่นหนาเรียบร้อย"},"ICON-0438":{"nm":"ไม้ปัดฝุ่นขนนก","de":"เพราะใต้แสงไฟ แม้แต่ขุยผ้าเล็กๆ เพียงชิ้นเดียวก็ยังโดดเด่นสะดุดตา จึงใช้ไม้ปัดขนนกปัดชุดอย่างแผ่วเบา ก่อนที่จะก้าวเท้าขึ้นเวทีเพียงชั่วครู่ สัมผัสอันอ่อนโยนที่ปรับแต่งเสื้อผ้าเป็นครั้งสุดท้ายนั้น เป็นหน้าที่ของขนนกนุ่มๆ นี้เสมอ"},"ICON-0439":{"nm":"ป้ายชื่อรองเท้าแตะห้องพักรอ","de":"ป้ายชื่อที่ติดอยู่บนรองเท้าแตะทุกคู่ในห้องพักรอ ในป้ายเล็กๆ ที่เขียนว่าเป็นของใครนั้น แฝงความอุ่นใจอย่างเงียบๆ ว่าเราคือทีมเดียวกัน ห้องที่ได้ถอดรองเท้าและเหยียดเท้าออกไปนั้น กลายเป็นบ้านที่แสนสบายที่สุดหลังเวที"},"ICON-0440":{"nm":"แผ่นคลิปหนีบจัดแต่งทรงผม","de":"แผ่นคลิปที่แบ่งเส้นผมเป็นส่วนๆ ระหว่างจัดแต่งทรงผม ขณะที่ปรับแต่งผมทีละเส้น นิ้วมือจะฝากเส้นผมที่อยากจะกระจัดกระจายไว้กับคลิปนี้ชั่วครู่ ความเรียบร้อยนั้น ท้ายที่สุดแล้วเกิดจากการหยุดชะงักเล็กๆ เช่นนี้มารวมกัน"},"ICON-0441":{"nm":"แคปซูลเก็บเข็มกลัด","de":"รุ่งเช้าวันหนึ่งที่ตะเข็บขาด เปิดฝาแคปซูลออก สีเงินเล็กๆ เย็นวาบนอนเรียงรายอยู่อย่างเป็นระเบียบ มือที่ยึดชุดไว้แน่นหนาที่สุดจากด้านในที่มองไม่เห็น เข็มกลัดนี้ทำงานอย่างเงียบเชียบอยู่หลังเวทีเสมอ"},"ICON-0442":{"nm":"ผ้าเช็ดเลนส์","de":"ฮะ พ่นลมหายใจครั้งหนึ่งแล้วเช็ดเป็นวงกลม โลกที่เคยพร่ามัวก็กลับใสชัดขึ้นมา เพราะชอบช่วงเวลาสั้นๆ นั้น จึงเช็ดเลนส์ซ้ำแล้วซ้ำเล่า ผ้าเช็ดชิ้นเล็กราวแสงแดดฤดูใบไม้ผลิที่ช่วยแจ่มใสสายตาของใครบางคนแทนตัวเขาเอง"},"ICON-0443":{"nm":"ขายางขาตั้งกล้อง","de":"เพียงสวมยางเข้าที่ปลายทั้งสามขา พื้นไม้ก็ไม่ร้องเสียงเอี๊ยดอีกต่อไป ขณะที่จุดเล็กๆ กลืนกินความสั่นไหวไว้ ทิวทัศน์ในจอภาพก็สงบนิ่งราวกับเป็นเรื่องโกหก ความมั่นคงเริ่มต้นอย่างเงียบๆ ที่ใต้ฝ่าเท้าเสมอ"},"ICON-0444":{"nm":"ผ้าคลุมกล้องกันฝน","de":"แม้เม็ดฝนจะไหลรินลงมา เลนส์ก็ยังคงแห้งสนิทและบันทึกภาพโลกไว้ได้ ในบ่ายฟ้าครึ้มของการถ่ายทำกลางแจ้ง เสื้อกันฝนใสถูกสวมคลุมกล้องไว้อย่างแผ่วเบา เพราะสิ่งล้ำค่านั้นต้องห่อหุ้มไว้ก่อนที่จะเปียก"},"ICON-0445":{"nm":"เทปบอกจุดถ่ายทำ","de":"ยืนตรงนี้ หมุนไปทางโน้น รอยสีสั้นๆ หลากสีชี้บอกเส้นทางอย่างชัดเจนโดยไม่ต้องพูดสักคำ แม้เมื่อการแสดงจบลงจะถูกลอกออกไปโดยไม่เสียดาย แต่ปลายเท้าที่คุ้นเคยจะยังจดจำจุดนั้นได้อีกนานแสนนาน"},"ICON-0446":{"nm":"คลิปแยกฉากถ่าย","de":"คลิปเล็กๆ ที่กัดกระดาษที่กำลังจะกระจัดกระจายไว้ในคำเดียว แค่เสียงคลิกกรุบใสหนึ่งเสียง เมื่อวานและวันนี้ก็ถูกมัดรวมไว้อย่างเรียบร้อย การจัดระเบียบคือนิสัยอันอ่อนโยนของการค่อยๆ ยึดสิ่งที่เกือบจะสูญหายไปไว้"},"ICON-0447":{"nm":"แผ่นปรับสมดุลแสงขาว","de":"ยกแผ่นสีขาวส่องเข้าจอ สีสันต่างๆ ก็ค่อยๆ กลับเข้าที่ของมัน ทั้งแสงตะวันตกสีเหลือง ทั้งรุ่งอรุณสีฟ้า ล้วนปราศจากความเท็จ แผ่นเดียวที่รู้จักสีขาวแท้จริงนี้ ทำให้สีอื่นๆ ที่เหลือพูดความจริงออกมาได้อย่างซื่อตรง"},"ICON-0448":{"nm":"กระป๋องเก็บความทรงจำ","de":"ในกระป๋องสังกะสีเล็กๆ ชิปแห่งความทรงจำหลับใหลอยู่อย่างสงบ เปิดฝาออกด้วยเสียงคลิก ฉากต่างๆ ของฤดูกาลที่ผ่านมาก็หลั่งไหลลงสู่ฝ่ามือ ความทรงจำพักพิงอยู่ในกระป๋องแข็งแรงใบเดียวเช่นนี้อย่างอบอุ่น"},"ICON-0449":{"nm":"ฝาบังแดดจอมอนิเตอร์","de":"เพียงพันร่มเงาสีดำรอบมอนิเตอร์ แสงสะท้อนก็หยุดลงทันที แม้อยู่ริมหน้าต่างที่แสงแดดสาดส่อง จอภาพก็ไม่สูญเสียสีของตัวเอง ฮู้ดบอกอย่างเงียบๆ ว่าหากอยากมองเห็นชัด ต้องบังแสงรบกวนเสียก่อน"},"ICON-0450":{"nm":"เข็มหมุดกันเสียงกองถ่าย","de":"เข็มหมุดเล็กๆ ที่สอดไว้ในช่องประตูตัดเสียงรบกวนจากภายนอกอย่างแผ่วเบา ทั้งเสียงฝีเท้าในทางเดินและเสียงหัวเราะจากห้องข้างๆ ก็ไปไม่ถึงตรงนี้ เพราะการจะบันทึกเสียงที่ใสได้ ต้องสร้างความเงียบขึ้นก่อน"},"ICON-0451":{"nm":"ชุดฟองน้ำแต่งหน้า","de":"ฟองน้ำนุ่มๆ วางเรียงกันเป็นมัดหนึ่ง เพียงแตะแป้งเบาๆ ด้วยปลายนิ้ว ใบหน้าก็สว่างขึ้นหนึ่งโทน เบื้องหลังรอยยิ้มอันแจ่มใสบนเวทีนั้น มักซ่อนสัมผัสอันอ่อนโยนเหล่านี้ไว้เสมอ"},"ICON-0452":{"nm":"กล่องเก็บกิ๊บติดผม","de":"บ้านอันเป็นระเบียบของกิ๊บเล็กๆ ที่หายง่าย เปิดฝาออก สีเงินก็เรียงแถวต้อนรับ กระจัดกระจายแล้วมองไม่เห็น แต่รวมกันแล้วอุ่นใจ แม้แต่สิ่งเล็กๆ ก็ยังต้องการบ้านของตัวเอง"},"ICON-0453":{"nm":"กล่องฆ่าเชื้อแปรง","de":"แปรงที่อมสีไว้ตลอดวันได้อาบแสงยูวีอยู่ในกล่องนี้ ขณะที่แสงมองไม่เห็นชะล้างสิ่งเก่าออกไป ปลายขนแปรงของวันพรุ่งนี้ก็ฟูนุ่มราวกับใหม่อีกครั้ง ความสะอาดก็เป็นชั้นหนึ่งของความใส่ใจเช่นกัน"},"ICON-0454":{"nm":"ถุงตาข่ายเก็บพัฟแป้ง","de":"พัฟกลมๆ พักหายใจอย่างสงบอยู่ในถุงตาข่าย เมื่อลมพัดผ่านเข้าออกตามช่องตาข่าย ความนุ่มก็คงอยู่ได้นานขึ้น พัฟที่แห้งสนิทหนึ่งลูกเก็บความสดใสของเช้าวันพรุ่งนี้ไว้ล่วงหน้า"},"ICON-0455":{"nm":"ฝาสเปรย์ล็อคทรงผม","de":"ชิ่ก—พ่นเพียงครั้งเดียว แม้แต่ลมพัดก็ไม่ทำให้เส้นผมสักเส้นหลุดรุ่ย ฝาเล็กๆ ที่ยึดทรงผมที่ตั้งใจจัดไว้ให้อยู่ทนตลอดคืน แสงไฟอันเจิดจ้าสาดกระจายลงมาเหนือเส้นผมที่ยึดแน่นหนา"},"ICON-0456":{"nm":"ฝาครอบแปรงลิปสติก","de":"ฝาเล็กๆ ที่ห่อหุ้มปลายขนแปรงบางๆ ไว้อย่างแผ่วเบา แม้ถูกเขย่าไปมาในกระเป๋า แปรงก็ยังคงตรงและสะอาด หัวใจที่ทะนุถนอมแปรงเล็กๆ เพียงด้ามเดียว ทำให้สีสันหนึ่งขีดบนริมฝีปากสมบูรณ์แบบ"},"ICON-0457":{"nm":"กระจกพร้อมป้ายหมายเลขคิว","de":"ข้างตัวเลขที่บอกคิวของฉัน มีกระจกเล็กๆ ติดอยู่อย่างแผ่วเบา ก่อนก้าวขึ้นเวทีเพียงเสี้ยววินาที นี่คือจุดที่แต่งผมหน้าม้าที่ยุ่งเหยิงเป็นครั้งสุดท้าย แม้แต่ความตื่นเต้นก็เบาลงบ้าง เมื่อได้ส่องกระจกดูตัวเองสักครั้ง"},"ICON-0458":{"nm":"ผ้าเช็ดเหงื่อรัดข้อมือ","de":"แถบผ้านุ่มๆ ที่เช็ดเหงื่อบนหน้าผากออกได้ด้วยการปาดข้อมือเพียงครั้งเดียว ยิ่งท่าเต้นดุเดือดมากเท่าไหร่ มือก็ยิ่งเอื้อมไปหามันบ่อยขึ้น สายผ้าเล็กๆ บนข้อมือที่คอยปลอบโยนอยู่เคียงข้างในทุกวินาทีที่หายใจไม่ทัน"},"ICON-0459":{"nm":"ป้ายกระเป๋าอุปกรณ์","de":"แม้กระเป๋าเหมือนกันสิบใบจะเรียงแถวอยู่ในห้องแต่งตัว ก็ไม่มีทางสับสน เพราะป้ายชื่อที่ติดอยู่บนกระเป๋าแต่ละใบบอกเจ้าของไว้อย่างชัดเจน การเขียนว่า \"ของฉัน\" นั้นเป็นเครื่องหมายเล็กๆ แต่แสนอ่อนโยน"},"ICON-0460":{"nm":"เข็มหมุดจองห้องซ้อม","de":"วันนี้ใครจะได้ใช้ห้องซ้อมนี้บ้าง เข็มหมุดเล็กๆ ที่ปักไว้บนบอร์ดหน้าประตูแบ่งเวลาให้โดยไม่พูดอะไร หัวใจที่รอคอยลำดับถัดไปพากันเข้าแถวอย่างเงียบๆ อยู่หลังเข็มหมุดเล่มนี้"},"ICON-0461":{"nm":"ห่วงฝาครอบนาฬิกาแขวนผนัง","de":"ฝาใสวางลงเบาๆ เหนือนาฬิกาแขวนผนังเพื่อกันฝุ่น เข็มที่เดินติ๊กต่อกไม่เคยพร่ามัว และเวลาก็ไหลผ่านไปอย่างใสสะอาด สิ่งล้ำค่ามักต้องการชั้นปกป้องที่มองไม่เห็นเสมอ"},"ICON-0462":{"nm":"แผ่นกันรอยพื้น","de":"แผ่นบางๆ ที่ติดใต้ขาเก้าอี้ป้องกันรอยขีดข่วนบนพื้นไม้ไว้ล่วงหน้า ลากก็ไม่เป็นรอย ย้ายก็ไม่มีร่องรอยหลงเหลือ หัวใจที่ทะนุถนอมพื้นโดยไม่มีใครมองเห็นนั้น คือเคล็ดลับที่ทำให้ใช้ได้นาน"},"ICON-0463":{"nm":"ชิปป้ายห้ามเครื่องดื่ม","de":"ช่วยวางเครื่องดื่มไว้ตรงนี้สักครู่นะ ชิปเล็กๆ ขอร้องอย่างอ่อนโยน เพราะทั้งโน้ตเพลงและอุปกรณ์จะเดือดร้อนหากเปียกน้ำ แม้แต่คำว่า \"ห้าม\" เมื่อสื่อสารด้วยวิธีนี้ ก็กลายเป็นความใส่ใจอันอบอุ่นได้โดยไม่รู้ตัว"},"ICON-0464":{"nm":"ป้ายปุ่มระบายอากาศ","de":"เมื่ออยากเปลี่ยนอากาศที่อึดอัด ให้กดตรงนี้นะ ป้ายเล็กๆ ข้างปุ่มบอกทางไว้ให้ การได้หายใจโล่งขึ้นนั้น น่าแปลกที่มักเริ่มต้นอย่างเงียบๆ จากเครื่องหมายเล็กจ้อยเช่นนี้เอง"},"ICON-0465":{"nm":"ยางรองลำโพง","de":"ยางรองที่ปูอยู่ใต้ลำโพงกลืนกินการสั่นสะเทือนอันหนักหน่วงไว้อย่างแผ่วเบา เมื่อเสียงเบสไม่แผ่ซ่านไปตามพื้นอีกต่อไป เสียงก็ยิ่งชัดเจนขึ้น เสียงก้องที่ไพเราะจะใสกระจ่างได้ก็ต่อเมื่ออยู่บนฐานที่มั่นคงเท่านั้น"},"ICON-0466":{"nm":"แม่เหล็กหมายเลขล็อกเกอร์","de":"แม่เหล็กตัวเลขเล็กๆ ที่ติดแน่นบนประตูล็อกเกอร์ วันนี้ของของฉันจะหลับใหลอยู่ในช่องหมายเลขไหนกันนะ แม้ตำแหน่งจะเปลี่ยนไปทุกวัน แต่แค่แม่เหล็กหนึ่งชิ้นก็ทำให้ช่องนั้นเป็นของฉันได้ในพริบตา ความรู้สึกเป็นส่วนหนึ่งมาจากเครื่องหมายเล็กๆ เบาๆ เช่นนี้เอง"},"ICON-0467":{"nm":"ที่ปาดฝ้ากระจก","de":"ปาดผ่านกระจกเพียงครั้งเดียว ฝ้าไอน้ำก็จางหายไปหมดจด วินาทีที่ใบหน้าอันพร่ามัวของฉันปรากฏขึ้นอย่างชัดเจน หากอยากมองเห็นตัวเองอย่างแท้จริง ต้องเริ่มจากค่อยๆ เช็ดสิ่งที่ทำให้พร่ามัวออกไปก่อน"},"ICON-0468":{"nm":"แผ่นกันกระแทกประตู","de":"วัสดุกันกระแทกนุ่มๆ ที่สอดไว้ในช่องประตูที่ปิดแรง รับทั้งเสียงปังและการหนีบมือได้อย่างนุ่มนวล ความปลอดภัยเล็กๆ ที่แอบสอดความอ่อนโยนชั้นหนึ่งเข้าไปท่ามกลางการปะทะอันหยาบกระด้าง"},"ICON-0469":{"nm":"บล็อกครอบสายไฟ","de":"ฝาครอบแข็งแรงทอดตัวเป็นสะพานอย่างมั่นคงเหนือสายไฟที่พาดผ่านพื้น ไม่มีเท้าสะดุด ไม่มีสายถูกเหยียบ ความสงบนิ่งของบล็อกหนึ่งชิ้นที่ปกป้องทางเดินโดยไม่ปิดกั้นทางเดิน"},"ICON-0470":{"nm":"กรวยเตือนพื้นลื่น","de":"กรวยสีเหลืองยืนอยู่โดดเดี่ยวบนพื้นเปียก เตือนอย่างเงียบงัน ให้ระมัดระวังและก้าวเท้าอย่างช้าๆ หลังเวทีอันสว่างไสว มีผู้พิทักษ์ตัวน้อยเช่นนี้ยืนเฝ้าปกป้องทุกฝีก้าวอย่างเงียบเชียบ"},"ICON-0471":{"nm":"แท่งไฟฉุกเฉิน","de":"แสงสว่างเส้นหนึ่งวาบขึ้นในทางเดินที่ไฟดับ เพื่อไม่ให้หลงทางแม้ในความมืด แสงไฟฉุกเฉินถูกวางไว้ในมือ แน่นอนว่ามีบางสิ่งบนโลกนี้ที่ส่องสว่างที่สุดในช่วงเวลาที่มืดมิดที่สุด"},"ICON-0472":{"nm":"ฝาครอบราวกันตก","de":"ฝาปิดทรงกลมที่สวมไว้ปลายราวบันไดห่อหุ้มมุมแหลมคมไว้อย่างนุ่มนวล แม้มือจะเผลอสัมผัสก็ไม่บาดเจ็บ การปิดคลุมความคมกริบไว้อย่างเงียบๆ นั้น ก็เป็นความใส่ใจที่มีต่อใครสักคนเช่นกัน"},"ICON-0473":{"nm":"เบาะกันกระแทกขอบเวที","de":"เบาะนุ่มๆ ห่อหุ้มรอบขอบปลายเวที เพื่อไม่ให้ปลายเท้าฟกช้ำแม้จะสัมผัสในระหว่างท่าเต้นอันดุเดือด เบื้องหลังท่วงท่าอันตระการตาทุกท่วงท่า มีการปกป้องที่มองไม่เห็นเต้นรำร่วมไปด้วยกัน"},"ICON-0474":{"nm":"แผ่นวงกลมบอกจุดยืน","de":"แผ่นวงกลมที่วางอยู่บนพื้นบอกอย่างเงียบๆ ว่า \"ยืนตรงนี้\" ทั้งคนที่ต่อแถวและคนที่กำลังหาที่ยืน ต่างหยุดที่จุดนี้อย่างสงบนิ่ง ระเบียบเติบโตขึ้นจากเครื่องหมายเล็กๆ เช่นนี้เอง"},"ICON-0475":{"nm":"สายคล้องไฟฉาย","de":"เพียงพันสายที่ห้อยจากปลายไฟฉายรอบข้อมือหนึ่งรอบ ก็ไม่พลาดแสงไฟแม้ในความมืด ทั้งสองมือเป็นอิสระโดยไม่ต้องกังวลว่าจะทำหล่น ห่วงเล็กๆ แต่น่าเชื่อถือเพียงรอบเดียวนี้"},"ICON-0476":{"nm":"เชือกกั้นทางเดิน","de":"ได้โปรดอย่าเข้ามาเกินจากตรงนี้ เชือกเส้นหนึ่งขีดเส้นแบ่งไว้อย่างอ่อนโยน เขตแดนอันแสนอ่อนโยนที่แบ่งพื้นที่อันตรายออกจากพื้นที่ปลอดภัยอย่างเงียบเชียบ การกั้นไว้ก็เป็นวิธีหนึ่งในการปกป้องใครสักคนเช่นกัน"},"ICON-0477":{"nm":"เข็มหมุดยืนยันความปลอดภัย","de":"ทุกจุดที่ตรวจสอบเสร็จแล้ว เข็มหมุดเล็กๆ จะทิ้ง \"ยืนยันแล้ว\" ไว้ จุดหนึ่งเปรียบดั่งตราประทับของจิตใจที่มองรอบด้านโดยไม่ตกหล่น ความปลอดภัยไม่ใช่เรื่องใหญ่โต แต่คือผลรวมของร่องรอยที่ตรวจสอบไว้ทีละจุดเช่นนี้"},"ICON-0478":{"nm":"กระดานปรบมือขนาดเล็ก","de":"แชะ—เสียงกรุบใสที่ตัดจังหวะแรกให้ทุกคนในกองถ่ายหายใจเข้าจังหวะเดียวกันในทันที แม้จะมีขนาดเล็ก แต่เส้นเริ่มต้นของทุกฉากคือจังหวะนี้เสมอ จุดเริ่มต้นอันน่าตื่นเต้นของการถ่ายทำเปิดฉากขึ้นที่นี่"},"ICON-0479":{"nm":"ฝาครอบไมค์ตั้งโต๊ะ","de":"ฝาครอบนุ่มๆ สวมทับไมโครโฟนบนโต๊ะไว้อย่างแผ่วเบา แม้ลมหายใจจะพวยพุ่งออกมาแรงก็ยังคงส่งผ่านไปอย่างไพเราะปราศจากเสียงรบกวน สิ่งที่ห่อหุ้มเสียงพูดไว้อย่างอบอุ่นที่สุดคือชั้นเล็กๆ นุ่มนวลนี้เอง"},"ICON-0480":{"nm":"ชิ้นแผงดูดซับเสียง","de":"แผงดูดซับเสียงชิ้นหนึ่งที่ฝังอยู่บนผนังเก็บเสียงสะท้อนไปอย่างเงียบเชียบ เมื่อเสียงไม่กระทบกระจัดกระจายอีกต่อไป บทเพลงก็ขังตัวอยู่อย่างใสกระจ่างยิ่งขึ้น เสียงก้องที่ไพเราะเริ่มต้นจากการขัดเกลาความเงียบอย่างพิถีพิถัน"},"ICON-0481":{"nm":"ตะขอแขวนหูฟัง","de":"การแขวนหูฟังไว้ที่นี่คือคำมั่นสัญญาเล็กๆ คลี่สายให้เรียบร้อยเพื่อให้คนต่อไปหยิบใช้ได้ทันที ตะขอเพียงตัวเดียวนำระเบียบอันเงียบสงบมาสู่บูธที่วุ่นวาย"},"ICON-0482":{"nm":"ไฟแสดงสถานะกำลังอัดเสียง","de":"วินาทีที่ไฟสีแดงติดขึ้น ลมหายใจทุกครั้งในบูธหยุดนิ่ง แม้แต่เสียงฝีเท้านอกประตูก็หยุดลงด้วยสัญญาณนั้น การบันทึกเสียงเริ่มต้นจากการรักษาความเงียบอันลึกซึ้งนี้ไว้"},"ICON-0483":{"nm":"กล่องจัดปิ๊กกีตาร์","de":"ปิ๊กกีตาร์ที่แบ่งใส่ช่องตามสี ความหนาและน้ำหนักหล่อหลอมความเคยชินของปลายนิ้ว ก่อนขึ้นเวทีเพียงชั่วครู่ ความแม่นยำที่หยิบชิ้นที่ใช่ได้ในทันทีโดยไม่ต้องมองนั้น เติบโตขึ้นจากที่นี่"},"ICON-0484":{"nm":"เครื่องติดป้ายสายไฟ","de":"หากไม่อยากหลงทางท่ามกลางสายนับสิบเส้นที่พันกันยุ่งเหยิงบนพื้น ต้องเขียนชื่อไว้ที่ปลายทั้งสองข้าง มีเพียงคนที่จดไว้ว่ามาจากไหนและไปยังที่ใดเท่านั้น ที่มือจะไม่หลงทางแม้ในความมืด"},"ICON-0485":{"nm":"ปุ่มหมุนมิกเซอร์ขนาดเล็ก","de":"เพียงหมุนไปเท่าปลายนิ้วมือหนึ่งข้อ พื้นผิวของเสียงก็เปลี่ยนไป เร่งขึ้นก็หยาบกร้าน ลดลงก็จมหาย คลำหาจุดเดียวระหว่างนั้น สัมผัสที่ละเอียดอ่อนที่สุดกลับสร้างความเปลี่ยนแปลงที่ยิ่งใหญ่ที่สุด"},"ICON-0486":{"nm":"แหวนล็อคขาตั้ง","de":"สิ่งที่ค้ำจุนเวทีไว้ไม่ใช่แสงไฟอันตระการตา แต่คือห่วงเล็กๆ นี้ ยึดความสั่นไหวให้แน่นหนา ยืนหยัดอยู่ในตำแหน่งของตนอย่างเงียบเชียบโดยไม่มีสายตาใครมองเห็น"},"ICON-0487":{"nm":"ป้ายรื้อฉาก","de":"แม้แต่การค่อยๆ วางทุกสิ่งที่เคยตั้งไว้ให้นอนลงอีกครั้ง ก็ยังมีลำดับขั้นตอนที่ชัดเจน กระดาษแผ่นหนึ่งที่จดไว้ว่าจะคลายตรงไหนและย้ายไปที่ใด มือที่เก็บกวาดก็มั่นคงพอๆ กับมือที่สร้างขึ้นมา"},"ICON-0488":{"nm":"ชิปซองของหาย","de":"สิ่งของที่ใครสักคนทำตกไว้ล้วนมีเรื่องราวเป็นของตัวเอง การใส่ไว้ในซองเล็กๆ เพื่อรอชื่อเจ้าของนั้น คือความอ่อนโยนที่รับฝากแม้แต่หัวใจของคนที่ทำของหายไว้ชั่วขณะหนึ่ง"},"ICON-0489":{"nm":"เครื่องหมายเส้นทางทำความสะอาด","de":"ตามลูกศรที่ขีดไว้บนพื้นไป แล้วจะทำความสะอาดได้อย่างไม่มีจุดตกหล่น แม้แต่ไม้กวาดก็ต้องมีเส้นทาง ไม่เช่นนั้นจะกวาดวนไปมาโดยเปล่าประโยชน์ จุดที่เปล่งประกายที่สุดอยู่ที่ปลายฝีก้าวที่ร่างไว้ดีที่สุด"},"ICON-0490":{"nm":"แท่งนำทางออก","de":"เมื่อเสียงปรบมือครั้งสุดท้ายค่อยๆ เงียบลง แท่งนี้จะเปิดทางให้ มือที่ค่อยๆ พาหัวใจที่ยังคงลอยฟุ้งออกไปโดยไม่ให้ช้ำใจ แม้แต่การนำทางสู่จุดจบก็ยังแฝงความใส่ใจอันอบอุ่นไว้"},"ICON-0491":{"nm":"ลูกบอลเทปเศษเหลือ","de":"ม้วนเศษเทปที่เหลือใช้ให้เป็นก้อนกลม แล้วมันก็มีประโยชน์ขึ้นมาอีกครั้ง เหมือนปลายเศษที่เกือบถูกทิ้งไปรวมกันจนกลายเป็นลูกบอลแข็งแรง หัวใจที่รู้จักทะนุถนอมเติบโตขึ้นจากปลายนิ้วเล็กๆ"},"ICON-0492":{"nm":"ฝาหมายเลขที่นั่ง","de":"เก้าอี้ที่นั่งผู้ชมทุกตัวต้องมีตัวเลขติดไว้ เพื่อไม่ให้ใครหลงทาง หมวกเล็กๆ ที่กำหนดที่นั่งให้เพียงใบเดียว เปลี่ยนความประหม่าของคนที่มาครั้งแรกให้กลายเป็นความอุ่นใจ"},"ICON-0493":{"nm":"เข็มหมุดแยกขยะ","de":"เข็มหมุดเล็กๆ ที่แยกกระดาษและพลาสติกออกจากกัน หากปะปนกันก็เป็นเพียงขยะ แต่หากแยกไว้ก็กลายเป็นทรัพยากรที่นำกลับมาใช้ได้อีกครั้ง การแยกประเภทคืองานอันอ่อนโยนที่คืนชีวิตครั้งที่สองให้กับสิ่งของ"},"ICON-0494":{"nm":"ป้ายคืนอุปกรณ์","de":"สิ่งที่ยืมมาต้องกลับคืนสู่ที่เดิมเสมอ ทุกปลายนิ้วที่ติดป้ายและส่งคืน ความไว้วางใจก็เพิ่มพูนขึ้นทีละชั้น คนที่คืนของได้ดีย่อมยืมได้อย่างสบายใจในครั้งต่อไปเช่นกัน"},"ICON-0495":{"nm":"กุญแจเช็คเอาต์ห้องพักรอ","de":"ถอดทั้งการแต่งหน้าและชุดของวันนี้ออกจนหมด แล้วส่งคืนกุญแจดอกนี้เป็นสิ่งสุดท้าย การคืนสิ่งที่ได้รับมาตอนเข้ากลับไปเมื่อออกไป จุดเริ่มต้นและจุดสิ้นสุดของวันหนึ่งถูกเก็บไว้ในมือเดียวกัน"},"ICON-0496":{"nm":"กล่องเก็บพัฟคุชชั่น","de":"พัฟนุ่มๆ จะสูญเสียเนื้อสัมผัสไปหากถูกกดทับ นั่นคือเหตุผลที่มันถูกวางนอนพักไว้อย่างทะนุถนอมในบ้านทรงกลมใบหนึ่ง หากอยากรักษาความนุ่มนวลไว้ได้นาน ต้องเริ่มจากการทะนุถนอมมันอย่างนุ่มนวลเสียก่อน"},"ICON-0497":{"nm":"ชิปอายแชโดว์","de":"จุดสีเพียงจุดเดียวที่แต้มบนเปลือกตาเปลี่ยนสีหน้าไปทั้งหมด สีที่หลับใหลอยู่ในชิปเล็กๆ นั้น จะตื่นขึ้นก็ต่อเมื่ออยู่ใต้แสงไฟ เพิ่มความลึกให้กับสายตาที่มุ่งสู่เวที"},"ICON-0498":{"nm":"ฝาครอบแปรงบลัชออน","de":"หากปลายขนแปรงเสียหาย การให้สีก็พังทลายลงไปด้วย การสวมหมวกเล็กๆ เพื่อปกป้องเนื้อขนไว้นั้น เป็นนิสัยอันเงียบสงบของคนที่อยากเก็บเครื่องมือดีๆ ไว้ข้างกายไปนานๆ"},"ICON-0499":{"nm":"พาเลตต์ลิปทรงบาง","de":"พาเลตต์หนาเทอะทะครองพื้นที่ในกระเป๋าจนหมด มือที่รู้ว่าเส้นบางๆ เพียงเส้นเดียวก็เพียงพอแล้ว วินาทีที่การตัดทอนกลายเป็นการจัดเตรียมอย่างดีเยี่ยมนั่นเอง"},"ICON-0500":{"nm":"การ์ดกันเลอะมาสคาร่า","de":"เพื่อไม่ให้ขนตาที่จัดทรงไว้ทีละเส้นเลอะเทอะ การ์ดเล็กๆ ปกป้องเส้นโค้งนั้นไว้อย่างแผ่วเบา สิ่งที่ยกขึ้นด้วยความตั้งใจต้องปกป้องด้วยความตั้งใจเช่นกัน เวลาที่อยู่หน้ากระจกบอกเช่นนั้น"},"ICON-0501":{"nm":"กล่องเก็บก้านสำลี","de":"บ้านหลังเล็กที่เก็บก้านสำลีสีขาวไม่ให้กระจัดกระจายไปทั่ว สัมผัสที่เก็บไว้ใกล้ตัวเสมอเพื่อการแต่งแต้มครั้งสุดท้าย การเตรียมพร้อมเล็กๆ น้อยๆ เติมเต็มช่องว่างของเวทีอันยิ่งใหญ่"},"ICON-0502":{"nm":"ยางหนีบขนตาสำรอง","de":"เมื่อยางแข็งตัว การหนีบขนตาก็จะเจ็บแปลบๆ การเตรียมยางสำรองไว้ล่วงหน้าเกิดจากความอ่อนโยนที่ใส่ใจแม้กระทั่งความเจ็บปวดเล็กๆ น้อยๆ"},"ICON-0503":{"nm":"แปรงคอนซีลเลอร์","de":"ปลายขนแปรงบางๆ ค่อยๆ ลบเงามืดออกไปทีละนิด เป็นการนำความสว่างไปสู่จุดที่แสงไม่เคยส่องถึง มือที่เติมแสงแทนการปกปิดข้อบกพร่องนั้นทำให้ทุกอย่างจบลงอย่างงดงามยิ่งขึ้น"},"ICON-0504":{"nm":"ที่ร่อนแป้ง","de":"ร่อนแป้งเนื้อละเอียดสักครั้งแล้วมันจะเกลี่ยเรียบเนียนไม่จับตัวเป็นก้อน ความยากลำบากของการร่อนผ่านตะแกรงอีกสักครั้ง ความใส่ใจในที่สุดแล้วก็ปรากฏอยู่ในปลายนิ้วที่ยอมก้าวไปอีกขั้นหนึ่งเสมอ"},"ICON-0505":{"nm":"กิ๊บม้วนหน้าม้า","de":"กิ๊บที่ม้วนหน้าม้าให้เป็นวงกลมแล้วยึดไว้ชั่วครู่ ระหว่างรอคอย ทรงผมก็ค่อยๆ เข้าที่อย่างสงบ ความเรียบร้อยผลิบานขึ้นในที่ที่รู้จักรอคอยโดยไม่เร่งรีบ"},"ICON-0506":{"nm":"ช้อนตักแว็กซ์ผม","de":"ก่อนที่แว็กซ์จะเปื้อนมือ ช้อนเล็กๆ นี้จะตักมันขึ้นมาก่อน ความยับยั้งชั่งใจที่ตักออกมาเพียงเท่าที่จำเป็น มือที่รู้จักใช้อย่างพอดีไม่เกินเลยนั้นสร้างสัมผัสที่เป็นธรรมชาติที่สุด"},"ICON-0507":{"nm":"แผ่นรองที่หนีบผมร้อน","de":"จะวางที่หนีบผมที่ร้อนจัดลงบนพื้นตามใจชอบไม่ได้ แผ่นรองเพียงแผ่นเดียวปกป้องทั้งโต๊ะและมือ สถานที่ที่ต้องรับมือกับความร้อนย่อมต้องการที่พักพิงอันปลอดภัยเสมอ"},"ICON-0508":{"nm":"ออยล์บำรุงผมขนาดทดลอง","de":"ความเงางามเพียงหยดเดียวก็เพียงพอ จึงบรรจุลงในขวดตัวอย่างเล็กๆ อย่างประณีตแล้วสอดไว้ในมุมกระเป๋า ขวดเล็กๆ กลับได้สัมผัสมือบ่อยกว่าขวดใหญ่เสียอีก"},"ICON-0509":{"nm":"ที่สางทำความสะอาดแปรง","de":"หวีเส้นผมที่พันกันอยู่ในขนแปรงออกอย่างช้าๆ ด้วยที่สางนี้ เวลาที่ใช้ดูแลเครื่องมือคือพิธีกรรมอันเงียบสงบหลังงานเสร็จสิ้น แปรงที่ได้รับการดูแลอย่างดีจะปั้นแต่งสัมผัสของวันพรุ่งนี้ให้งดงาม"},"ICON-0510":{"nm":"หลอดพันหนังยางมัดผม","de":"เพียงแค่พันรอบแกนหลอดก็มองเห็นได้ในพริบตา ห่อเล็กๆ ที่ม้วนเก็บอย่างเป็นระเบียบนี้คือความผ่อนคลายอันอ่อนโยนที่มอบให้เช้าวันวุ่นวาย ที่เคยมีแต่หนังยางกลิ้งไปทั่วทุกทิศทาง"},"ICON-0511":{"nm":"ถุงมือย้อมสี","de":"ถุงมือบางๆ ที่สวมไว้เพื่อไม่ให้มือที่แต้มสีเปื้อน คือความปรารถนาที่จะต้อนรับสิ่งต่อไปด้วยมือที่สะอาดแม้งานจะเสร็จสิ้นแล้ว การปกป้องก็คือชื่ออีกชื่อหนึ่งของการเตรียมพร้อมเช่นนั้นเอง"},"ICON-0512":{"nm":"ซองใส่ตาข่ายคลุมผม","de":"ถุงเล็กๆ ที่พับตาข่ายซึ่งคอยรักษาทรงผมเก็บไว้อย่างเรียบร้อย สิ่งที่ไร้ปริมาตรยิ่งง่ายต่อการหายไป ดังนั้นสัมผัสอันใส่ใจที่กำหนดบ้านให้มันจึงน่าขอบคุณยิ่งนัก"},"ICON-0513":{"nm":"ปากกาเซ็ตผมเส้นปลิว","de":"ปากกาที่แตะเบาๆ จัดเส้นผมที่ปลิวไม่เข้าที่ให้เรียบร้อย เป็นการแตะครั้งสุดท้ายหลังจากจัดแต่งใหญ่เสร็จสิ้น การเก็บงานคือการโอบอุ้มจุดเล็กที่สุดเสมอ"},"ICON-0514":{"nm":"ฝาทดลองน้ำหอม","de":"เมื่อเลือกกลิ่นหอม อย่านำไปจ่อที่ปลายจมูกโดยตรง ต้องหยดลงบนฝาเล็กๆ แล้วปล่อยให้ฟุ้งกระจายในอากาศจึงจะเผยลายเนื้อแท้ออกมา แม้แต่กลิ่นหอมก็ซื่อตรงก็ต่อเมื่อสูดดมในระยะห่างสักก้าวหนึ่ง"},"ICON-0515":{"nm":"ขวดน้ำหอมโรลออน","de":"ลูกกลิ้งกลมๆ หมุนกลิ้งวาดกลิ่นหอมลงบนข้อมือ ต่างจากขวดน้ำหอมแบบแตะสมัยก่อน เป็นเส้นสายเดียวที่ไหลลื่นและแผ่กระจาย กลิ่นหอมทิ้งเรื่องราวที่แตกต่างกันไปตามวิธีที่มันสัมผัส"},"ICON-0516":{"nm":"ฝาบอดี้มิสต์","de":"ฝาเล็กๆ ที่กักเก็บกลิ่นหอมซึ่งแผ่กระจายดั่งหมอก เป็นการปิดและรักษาสิ่งที่จะฟุ้งกระจายไปก็ต่อเมื่อเปิดออก หัวใจที่รู้จักเก็บออมไว้บ้างนั้นทำให้กลิ่นหอมนั้นอยู่เคียงข้างได้นานยิ่งขึ้น"},"ICON-0517":{"nm":"พวงกุญแจครีมทามือ","de":"ผูกห่วงเข้ากับครีมทามือเล็กๆ แล้วมันก็ไปด้วยกันทุกที่ เพื่อนคู่ใจที่แขวนแกว่งไกวอยู่นอกกระเป๋ากลายเป็นคำทักทายอันอ่อนโยนที่ส่งถึงปลายนิ้วที่แห้งกร้าน"},"ICON-0518":{"nm":"ตะขอแขวนใยขัดตัว","de":"หลังจากตีฟองจนฟูฟ่องแล้วต้องผึ่งให้แห้งดี ลูกตาข่ายที่แขวนไว้บนตะขอมุมห้องน้ำสะบัดหยดน้ำอย่างเบาๆ รอคอยเช้าวันใหม่ที่สดชื่น"},"ICON-0519":{"nm":"ซองลูกบอลนวด","de":"ถุงเล็กๆ ที่บรรจุลูกบอลแข็งซึ่งช่วยคลายบ่าที่เกร็งตึง เวลาพักสั้นๆ หลังเวที เวลาที่เยียวยาร่างกายที่แข็งเกร็งอย่างเงียบๆ การดูแลตัวเองเริ่มต้นจากตัวเราเองเสมอ"},"ICON-0520":{"nm":"กระปุกแผ่นแปะเย็น","de":"กระปุกที่รวบรวมแผ่นแปะซึ่งเย็นฉ่ำทันทีที่ติดลงไป ในคืนที่เวทีอันร้อนแรงจบลง ความปลอบโยนเล็กๆ นอนหลับอยู่ข้างในนั้น ค่อยๆ ปลอบให้ร่างกายและหัวใจที่ร้อนผ่าวสงบลง"},"ICON-0521":{"nm":"ปากกาออยล์บำรุงเล็บ","de":"กด ถู แล้วก็เปล่งประกาย ปลายนิ้วที่แห้งกร้านต้องการเพียงหยดเดียวก็เพียงพอ ไม่จำเป็นต้องมีสูตรหรูหราใดๆ ความเงางามอ่อนโยนที่แผ่ออกจากปลายปากกาเล็กๆ พันรอบเล็บอย่างงดงาม การดูแลเริ่มต้นจากหยดเล็กๆ เช่นนี้เอง"},"ICON-0522":{"nm":"คลิปถุงหอม","de":"ปมเล็กๆ ที่ผูกกลิ่นหอมไว้บนกระดาษ ทุกครั้งที่เปิดลิ้นชัก กลิ่นอันแผ่วเบาก็ทักทายก่อนมือเสียอีก ความอ่อนโยนที่อยู่ใกล้แม้มองไม่เห็น คลิปเพียงตัวเดียวเก็บความปลอบโยนของวันหนึ่งไว้อย่างเงียบๆ"},"ICON-0523":{"nm":"ถาดวางปลายเล็บปลอม","de":"เวทีเล็กๆ ที่เรียงสีของนิ้วทั้งสิบไว้ล่วงหน้า โทนไหนจะเข้ากับวันนี้ดีนะ การออดิชันอันเงียบงันเกิดขึ้นบนถาดใบนี้ ช่วงเวลาสั้นๆ ของการเลือกนั้นตื่นเต้นอย่างประหลาด และวันของปลายนิ้วก็เริ่มต้นที่นี่"},"ICON-0524":{"nm":"ฝาไม้ดันหนังกำพร้าเล็บ","de":"แม้แต่ในการผลักออกก็ยังมีความอ่อนโยนอยู่ หนังส่วนเกินเพียงเส้นเดียว ค่อยๆ ดันด้วยปลายมนอย่างไม่รีบร้อน มือที่เร่งรีบมักพลาดอะไรบางอย่างเสมอ การจัดระเบียบจึงใกล้เคียงกับหัวใจที่มองอย่างช้าๆ มากกว่า"},"ICON-0525":{"nm":"ตะไบขัดเล็บมินิ","de":"ด้านหยาบและด้านเนียน สองใบหน้าที่กุมไว้ในมือเดียวกัน การตะไบส่วนที่ขรุขระให้เรียบเนียนเป็นเรื่องเล็กน้อย แต่ความสมบูรณ์แบบก็มาจากสัมผัสเล็กๆ เช่นนี้เสมอ บทสุดท้ายในที่สุดก็เป็นของความอ่อนโยน"},"ICON-0526":{"nm":"แผ่นสติกเกอร์แต่งเล็บ","de":"ดาว ดอกไม้ หัวใจ เพียงเลือกแผ่นหนึ่งที่เข้ากับอารมณ์วันนี้แล้วแปะลงไปก็เพียงพอ บนแผ่นที่เรียงรายด้วยลวดลายเล็กๆ ขนาดเท่าเล็บ สติกเกอร์หนึ่งชิ้นเปล่งประกายราวลายเซ็นอันอ่อนโยนที่ทิ้งไว้บนปลายนิ้ว"},"ICON-0527":{"nm":"แผ่นบังแสงเจลแลมป์","de":"แผ่นบางๆ ที่กักแสงไว้ชั่วครู่ ระหว่างที่เจลแข็งตัว ดวงตาก็ได้พัก มีเพียงปลายนิ้วเท่านั้นที่ค่อยๆ แข็งตัวอย่างเงียบๆ แม้แต่การรอคอยก็ต้องการร่มเงาสักผืน ในเวลาที่ไม่เร่งรีบนั้น ปลายนิ้วของวันนี้จึงเสร็จสมบูรณ์"},"ICON-0528":{"nm":"กระปุกอุปกรณ์แต่งเล็บ","de":"ชิ้นส่วนแวววาวนอนหลับอยู่ในแต่ละช่อง คริสตัล ไข่มุก ผงดาว เปิดฝาด้วยความตื่นเต้นราวกับเปิดกล่องเพชรพลอยที่ไร้ป้ายชื่อ จะวางแสงแบบไหนลงบนเล็บดี ช่วงเวลาแห่งการเลือกนั้นแวววาวที่สุด"},"ICON-0529":{"nm":"ถุงมือบำรุงมือ","de":"วันหยุดสั้นๆ ที่มือได้รับระหว่างที่เรานอนหลับ ผิวที่แห้งกร้านค่อยๆ ชุ่มชื้นขึ้นตลอดคืนภายในถุงมือ การดูแลในที่สุดแล้วก็คือสิ่งที่เกิดขึ้นในที่ที่มองไม่เห็น พอถึงเช้า ปลายนิ้วจะเป็นคนแรกที่รู้ถึงความอ่อนโยนนั้น"},"ICON-0530":{"nm":"ขวดปั๊มน้ำยาล้างเล็บ","de":"กดหนึ่งครั้งได้พอดีตามที่ต้องการ กลิ่นเย็นซึมเข้าไปในสำลีแล้วลบเมื่อวานบนเล็บให้สะอาดหมดจด แม้แต่การทำให้ว่างเปล่าก็มีจังหวะของมัน การปั๊มเพียงครั้งเดียวเผยพื้นที่ว่างสำหรับทาสีใหม่อย่างเงียบๆ"},"ICON-0531":{"nm":"คีมคีบคริสตัล","de":"การหยิบอัญมณีที่เล็กกว่าปลายนิ้วต้องการมือที่ละเอียดยิ่งกว่า ปลายคีมที่เคลื่อนย้ายจุดหนึ่งโดยไม่สั่นไหว ความประณีตนั้นเป็นหน้าที่ของเครื่องมือพอๆ กับหัวใจ แสงเล็กๆ หนึ่งดวงจึงพบที่ทางของมัน"},"ICON-0532":{"nm":"แผ่นเก็บต่างหู","de":"เพื่อไม่ให้ต่างหูที่พลัดคู่กลายเป็นเด็กหลงในลิ้นชักอีกต่อไป เสียบไว้ทีละคู่ในที่ของมัน แล้วเวลาเลือกในเช้าอันวุ่นวายก็เบาลงมาก การจัดระเบียบคือความกรุณาเล็กๆ ที่มอบให้ตัวเราในอนาคต"},"ICON-0533":{"nm":"ห่วงวัดขนาดแหวน","de":"ห่วงเล็กๆ ชุดหนึ่งที่แปลงเส้นรอบวงนิ้วให้เป็นตัวเลข การลองสวมแต่ละขนาดทีละอันคล้ายกับการค่อยๆ ทำความรู้จักสิ่งที่เหมาะกับตัวเราพอดี เหมือนความโล่งใจในยามที่มันพอดิบพอดี"},"ICON-0534":{"nm":"หมุดสายนาฬิกา","de":"เมื่อสายนาฬิกาหลวม หมุดเล็กๆ เพียงตัวเดียวนี้จะยึดเวลากลับมาไว้บนข้อมืออีกครั้ง ชิ้นส่วนที่ซ่อนลึกที่สุดกลับทนทานที่สุด สิ่งที่นาฬิกาที่สวมมานานรู้ดีโดยไม่ต้องพูดออกมา"},"ICON-0535":{"nm":"แผ่นกันสร้อยพันกัน","de":"แบ่งช่องไว้เพื่อไม่ให้สร้อยเส้นเล็กพันกันเอง เช้าที่ปราศจากความพันกันเริ่มต้นจากช่องกั้นเล็กๆ ที่แบ่งไว้ล่วงหน้าตั้งแต่เมื่อคืน ความสบายใจในที่สุดแล้วคือหัวใจที่จัดระเบียบไว้ก่อนที่มือจะแตะถึง"},"ICON-0536":{"nm":"หัวล็อกหลังเข็มกลัด","de":"ยิ่งด้านหน้าอลังการเท่าไร ด้านหลังก็ยิ่งเงียบงันเท่านั้น หัวล็อกเล็กๆ ที่ยึดเข็มกลัดซึ่งปักอยู่บนชายเสื้อไว้อย่างมั่นคง เบื้องหลังแสงที่เปล่งประกายมักมีมือไร้นามคอยยึดมั่นเสมอ เป็นตำแหน่งที่มั่นคงยิ่งขึ้นเพราะมองไม่เห็น"},"ICON-0537":{"nm":"ซองใส่แว่นกันแดด","de":"ผ้านุ่มโอบกอดเลนส์ที่ปกป้องแสงแดดฤดูร้อนไว้อย่างอ่อนโยน ถุงเล็กๆ ที่ปกป้องมุมมองหนึ่งคู่จากการกระแทกในกระเป๋า หัวใจที่ทะนุถนอมสิ่งใดสิ่งหนึ่งมักมาในรูปของชั้นนุ่มๆ เช่นนี้เสมอ"},"ICON-0538":{"nm":"ที่เจาะรูเข็มขัด","de":"ไม่ว่าเอวจะเล็กลงไปหนึ่งช่อง หรือฤดูกาลจะเปลี่ยนไปหนึ่งช่วง เพียงเจาะรูเพิ่มอีกหนึ่งรู เข็มขัดก็พอดีกับร่างกายอีกครั้ง สิ่งที่เปลี่ยนแปลงเสมอคือตัวเรา ส่วนสิ่งที่ปรับให้เข้ากับเราอย่างเงียบๆ คือหน้าที่ของเครื่องมือเล็กๆ ชิ้นนี้"},"ICON-0539":{"nm":"คลิปห่วงผ้าพันคอ","de":"คลิปที่รวบผ้าพันคอที่ไหลลื่นให้มารวมกันที่จุดเดียวแล้วยึดไว้ ความสง่างามที่คลายตัวเพราะสายลมในที่สุดก็เข้าที่ แม้แต่ความหรูหราบางครั้งก็ต้องพึ่งพาคีมเล็กๆ นี้ ทำให้วันที่เกือบจะยุ่งเหยิงกลับเรียบร้อยขึ้นมา"},"ICON-0540":{"nm":"ชุดห่วงชาร์ม","de":"ห่วงเล็กๆ ที่จะแขวนไว้ข้างกระเป๋ามาเป็นชุด หัวใจของการพกพาสิ่งที่รักไว้ใกล้ตัว การแขวนอารมณ์ของวันนั้นไว้บนชาร์มหนึ่งชิ้นเป็นเหมือนพิธีกรรมเล็กๆ ที่มีเพียงเราเท่านั้นที่รู้ ซึ่งกลับกลายเป็นความสุขอย่างประหลาด"},"ICON-0541":{"nm":"กระบอกกำจัดขนแตก","de":"เมื่อเสื้อสเวตเตอร์ดูแก่ลงในชั่วข้ามคืนเพราะขนแตก เพียงกลิ้งกระบอกนี้เบาๆ มันก็กลับมามีสีหน้าของความใหม่อีกครั้ง เสียงหึ่งๆ แผ่วเบาที่ปัดเอาความเก่าออกไปนั้นช่างอุ่นใจอย่างประหลาด เสื้อผ้าที่รักจึงได้มีชีวิตขึ้นมาอีกครั้งเช่นนี้"},"ICON-0542":{"nm":"การ์ดหอมสำหรับผ้า","de":"สอดไว้ลึกๆ ในตู้เสื้อผ้าแล้วมันจะเติมกลิ่นหอมให้วันเวลาอย่างเงียบๆ นานหลายวัน จดหมายที่เขียนด้วยกลิ่นแทนตัวอักษร หน้ากระดาษที่อ่านได้โดยไม่ต้องคลี่ออก ทุกเช้าที่หยิบเสื้อผ้าออกมา ความอ่อนโยนที่เขียนไว้เมื่อวานก็แผ่กระจายออกมาก่อนสิ่งอื่นใด"},"ICON-0543":{"nm":"เข็มกลัดกันไฟฟ้าสถิต","de":"ในเช้าฤดูหนาวที่ชายกระโปรงเกาะติดขา หมุดเพียงตัวเดียวค่อยๆ คลายความเกาะติดนั้นออก ความสงบเล็กๆ ที่ปลอบประโลมแม้แต่แรงเสียดทานที่มองไม่เห็น เมื่อความรำคาญเล็กๆ หนึ่งอย่างหายไป วันนั้นก็ราบรื่นขึ้นมาก"},"ICON-0544":{"nm":"แปรงปัดเสื้อพกพา","de":"ก่อนจะก้าวออกจากประตูเพียงครู่เดียว ฝุ่นเส้นหนึ่งที่เกาะบนบ่าอย่างเงียบเชียบ กางแปรงที่พับไว้ออกแล้วปัดเพียงครั้งเดียว ความประทับใจแรกก็เรียบร้อยอีกครั้ง การเก็บงานเกิดขึ้นที่หน้าประตูเสมอ และความเรียบร้อยก็เสร็จสมบูรณ์ด้วยสัมผัสเพียงครั้งเดียวนั้น"},"ICON-0545":{"nm":"ป้ายถุงซักผ้า","de":"ขังสิ่งที่ไม่ควรปะปนกันไว้ในตาข่าย แล้วป้ายก็เขียนชื่อของมันไว้อย่างเงียบๆ แม้แต่ผ้าที่ซักก็ยังมีที่ทางของมัน และที่ทางก็มักมาพร้อมเครื่องหมายเล็กๆ ระเบียบของวันที่ยุ่งเหยิงง่ายเติบโตขึ้นจากป้ายชื่อเล็กๆ นี้"},"ICON-0546":{"nm":"ปากกาลบรอยเปื้อน","de":"แม้แต่รอยที่กาแฟหยดเดียวทิ้งไว้บนเสื้อเชิ้ต เพียงจิ้มเบาๆ ก็จะค่อยๆ จางหายไป ปากกาที่ไม่ปกปิดความผิดพลาด แต่ค่อยๆ ลบมันออกไปอย่างสงบ ทุกคนต้องการโอกาสสักครั้งเพื่อเริ่มต้นวันใหม่ให้สะอาดอีกครั้ง"},"ICON-0547":{"nm":"ผ้าขัดรองเท้าหนัง","de":"เพียงเช็ดด้วยผ้าครั้งเดียว หนังก็ได้ประกายกลับคืนมา ยิ่งรองเท้าคู่เก่าใส่มานาน ความเงางามก็ยิ่งลึกล้ำ ความเป็นเงาคือรางวัลของเวลาที่เดินเคียงข้างกันมา รองเท้าจารึกปีเดือนเหล่านั้นไว้อย่างเงียบงันบนหลังเท้า"},"ICON-0548":{"nm":"ฝาครอบปลายเชือกรองเท้า","de":"หมวกเล็กๆ ที่สวมไว้ที่ปลายเชือกที่คลายออก เพื่อไม่ให้เหม่อมองทางอื่นก่อนถึงเส้นชัย ปลายเชือกจึงถูกปิดผนึกไว้อย่างแน่นหนา เชือกที่ผูกไว้ดีเพียงเส้นเดียวส่งก้าวเดินให้ไปได้ไกลขึ้นอีกก้าว ความระมัดระวังเล็กๆ กลายเป็นความกล้าที่จะวิ่งจนถึงที่สุด"},"ICON-0549":{"nm":"ชิปชื่อไม้แขวนเสื้อ","de":"ท่ามกลางไม้แขวนเสื้อที่หน้าตาคล้ายกัน ชิปเล็กๆ ตัวนี้เพียงตัวเดียวบอก \"ที่ของฉัน\" ไว้อย่างเงียบๆ เป็นเข็มทิศเงียบงันที่ลดความสับสนในเช้าอันวุ่นวาย ยิ่งเสียเวลาค้นหาน้อยลง จุดเริ่มต้นของวันก็ยิ่งเบาสบายขึ้น"},"ICON-0550":{"nm":"กระปุกคีมคีบคอนแทคเลนส์","de":"บางครั้งเราต้องการปลายที่แม่นยำยิ่งกว่าปลายนิ้ว คีมที่หยิบเลนส์เล็กๆ ขึ้นมาโดยไม่สั่นไหวรอคิวอยู่ภายในกระปุก ความแม่นยำนอนพักรออย่างเงียบสงบเสมอ หลับใหลจนกว่าจะถูกเรียก แล้วก็ตื่นขึ้นทันที"},"ICON-0551":{"nm":"สำลีแผ่นมินิแพ็ค","de":"ห่อเล็กๆ ที่บรรจุไว้พอดีสำหรับใช้เพียงครั้งเดียว ลดปริมาตรในกระเป๋าลงแต่ความนุ่มยังคงเดิม การพกพาแต่น้อยก็เป็นความอ่อนโยนอีกแบบหนึ่ง ในที่ว่างที่ลดลงนั้น วันอันเบาสบายก็เข้ามาแทนที่"},"ICON-0552":{"nm":"ตลับกระดาษซับมัน","de":"กดซับความมันวาวที่แผ่บนจมูกยามเที่ยงวันด้วยกระดาษบางๆ แผ่นเดียว กระดาษที่นอนหลับเรียงเป็นแถวอย่างเป็นระเบียบในตลับ ในช่วงเวลาที่หยิบแผ่นหนึ่งออกมานั้น ใครก็ตามล้วนหยุดมองตัวเองในกระจกอย่างอ่อนโยนสักครู่"},"ICON-0553":{"nm":"กระจกหวีพับ","de":"พับแล้วเป็นฝ่ามือ กางออกแล้วเป็นกระจกและหวี อุปกรณ์อเนกประสงค์เล็กๆ ที่รับผิดชอบการแต่งตัวอย่างเร่งด่วนจากมุมกระเป๋า ความเรียบร้อยไม่ใช่เรื่องใหญ่โต แต่ใกล้เคียงกับหัวใจที่กางออกเพื่อจัดแต่งได้ทุกที่ทุกเวลา"},"ICON-0554":{"nm":"ฝาครอบมีดโกนพกพา","de":"ทำให้ใบมีดคมกริบในกระเป๋าเดินทางนอนหลับอย่างปลอดภัย ด้วยฝาครอบที่ดูทู่แต่แข็งแรงนี้ แม้แต่ปลายนิ้วที่คลำหาในเช้าอันวุ่นวายก็ไม่บาดเจ็บ การเอาใจใส่คือการปกคลุมอันตรายไว้ล่วงหน้าเสมอ"},"ICON-0555":{"nm":"ห่วงลิปบาล์ม","de":"เกราะป้องกันเล็กๆ ที่แกว่งไกวอยู่ที่สายกระเป๋า ไม่ต้องกังวลว่าจะกลิ้งไปมาในกระเป๋าเสื้อจนแตก ริมฝีปากที่แห้งกร้านจึงอยู่ในระยะเอื้อมถึงเสมอ การพกพาในที่สุดแล้วก็คือหัวใจที่วางสิ่งจำเป็นไว้ในระยะใกล้ที่สุด"},"ICON-0556":{"nm":"ที่แขวนเจลล้างมือ","de":"กดด้วยมือเดียวแล้วความสะอาดหนึ่งกำมือก็หยดลงมา แขวนไว้หน้าประตู บนโต๊ะ ที่ไหนก็ได้ นิสัยการล้างมือก็ยิ่งใกล้ตัวขึ้นเท่านั้น นิสัยที่ดีไม่ใช่เรื่องใหญ่โต แต่เริ่มต้นในระยะเอื้อมมือถึง"},"ICON-0557":{"nm":"ซองทิชชูสลิม","de":"รูปทรงเพรียวบางที่โอบอุ้มทิชชูไว้หนึ่งกำมือ แม้ไม่ทำให้กระเป๋าโป่งพอง แต่ก็พร้อมรับมือกับน้ำมูกหรือน้ำตาที่มาแบบไม่ทันตั้งตัวอยู่เสมออย่างเงียบๆ กระดาษหนึ่งแผ่นที่ยื่นให้ใครสักคนอย่างแนบเนียน ยิ่งเรียวบางเท่าไร ความพร้อมก็ยิ่งดูดีเท่านั้น"},"ICON-0558":{"nm":"ขวดน้ำยาบ้วนปากมินิ","de":"ในวันที่ต้องไปพบใครสักคนหลังกินราเมงรสเผ็ด ขวดเล็กๆ นี้จะรับผิดชอบความสดชื่นในปากอย่างเงียบๆ ความสดชื่นเพียงจิบเดียวบางครั้งกลายเป็นความมั่นใจอันยิ่งใหญ่ ทำให้คำทักทายที่ลังเลกลายเป็นเรื่องเบาสบายขึ้นมาก"},"ICON-0559":{"nm":"ชิปแป้งชิมเมอร์","de":"แตะปลายนิ้วเบาๆ แล้วแต้มลงบนแก้ม มันจะแผ่กระจายราวกับผงดาวที่ปลิวว่อนใต้แสงไฟ แก้มธรรมดากลายเป็นประกายในพริบตาด้วยเวทมนตร์ของชิปเล็กๆ ชิ้นเดียวนี้ แสงมักมาเยือนเช่นนี้เสมอ ผ่านผงที่เปื้อนอยู่บนปลายนิ้ว"},"ICON-0560":{"nm":"สติกเกอร์ลดประกายกลิตเตอร์","de":"บนจุดที่แวววาวเกินไปจนรู้สึกอึดอัด สติกเกอร์นี้จะค่อยๆ กดแสงนั้นให้ลดลง การลดความอลังการลงสักชั้นก็เป็นส่วนหนึ่งของการแต่งแต้มเช่นกัน ความละเมียดละไมที่หลงเหลืออยู่ในที่ว่างนั้น บางครั้งกลายเป็นสัมผัสอีกแบบหนึ่งไปเลย"},"ICON-0561":{"nm":"ปากกาหยิบสโตน","de":"ก้อนหินเล็กๆ ก้อนหนึ่งที่เกี่ยวปลายเท้าขณะเดินไปตามถนน คือปากกาที่ก้มลงหยิบมันขึ้นมาโดยตั้งใจ หัวใจที่ค่อยๆ เก็บสิ่งที่อาจจะเดินผ่านไปเฉยๆ ด้วยปลายนิ้ว ความอ่อนโยนเริ่มต้นจากการหยุดยืนเสมอ"},"ICON-0562":{"nm":"แผ่นเก็บขนตาปลอม","de":"แผ่นเล็กๆ ที่วางขนตาให้นอนเรียงกันอย่างเป็นระเบียบทีละเส้น แม้หลังจากถอดออกแล้ว เส้นโค้งอันงดงามนั้นก็ไม่เคยผิดรูป ความปลอบโยนอันเงียบสงบและเรียบร้อยของการจัดเก็บที่บอกว่าแม้แต่สิ่งที่วางลงชั่วคราวก็ยังจดจำที่ทางของตัวเองได้"},"ICON-0563":{"nm":"ฝาตัดเทปตาสองชั้น","de":"ใบมีดสองด้านสบกันตัดปมขาดในคราวเดียว รอยตัดยิ่งสะอาดเท่าไร ปมต่อไปก็ยิ่งเรียบร้อยเท่านั้น จากปลายนิ้วที่ผูกเก่งและตัดเก่ง แม้แต่การเริ่มต้นใหม่ก็คลี่คลายออกไปอย่างเบาสบายยิ่งขึ้น"},"ICON-0564":{"nm":"เทปกระชับเส้นหน้า","de":"แปะเป็นเส้นเดียวไปตามแนวขากรรไกร กลั้นหายใจติดอย่างระมัดระวัง โครงหน้าไม่ใช่การวาดเส้นที่ไม่เคยมีอยู่ แต่เป็นการชี้ให้เห็นจุดที่งดงามอยู่แล้ว เป็นสัมผัสที่ตามรอยลายเส้นที่มีอยู่แต่เดิมอย่างอ่อนโยน"},"ICON-0565":{"nm":"แป้งสะท้อนแสง","de":"ผงแป้งที่ดูดกลืนแสงไว้เต็มที่แล้วส่งคืนกลับมาอย่างงดงาม แม้ไม่เปล่งประกายด้วยตัวเอง แต่ก็สว่างไสวขึ้นด้วยการกระจายแสงที่ได้รับมาให้เป็นชิ้นเล็กชิ้นน้อย ราวกับส่งต่อความอ่อนโยนที่ได้รับมาให้ใครอีกคน ประกายแสงยิ่งแบ่งปันก็ยิ่งเติบโต"},"ICON-0566":{"nm":"พัดลมเซ็ตเมกอัพ","de":"สายลมจากพัดที่ยึดการแต่งหน้าอันประณีตไว้จนถึงปลายวัน เพื่อไม่ให้พังทลาย เพื่อไม่ให้ไหลย้อย มันเป่าเย็นและตรึงให้แข็งตัวอย่างเงียบๆ เพื่อให้ใบหน้าที่ตกแต่งมาอย่างตั้งใจยังคงชัดเจนจนกว่าม่านเวทีจะปิดลง"},"ICON-0567":{"nm":"ชิปพาเลตแก้สีผิว","de":"ชิ้นส่วนเล็กๆ ที่ปลอบและแก้ไขสีที่คลาดเคลื่อนทีละช่อง แม้แต่สีที่เคว้งคว้างอยู่คนเดียวก็สว่างไสวขึ้นในที่สุดเมื่อมีสีที่เข้ากันอยู่เคียงข้าง สีกับสีต้องจับมือกันเท่านั้นจึงจะกลายเป็นภาพหนึ่งที่ใสสะอาด"},"ICON-0568":{"nm":"ผ้าพันคอสำหรับซ้อม","de":"พันรอบคอแล้วอากาศเย็นของห้องซ้อมยามรุ่งสางก็อ่อนลงมาก อบอุ่นราวกับมือของคุณยายที่พันผ้าพันคอรอบคอหลาน ความหนาวมักมาเยือนจุดที่บางที่สุดก่อนเสมอ จึงต้องโอบกอดต้นคอไว้ก่อนเป็นอันดับแรก"},"ICON-0569":{"nm":"ซองผ้าปิดตาอุ่น","de":"ซองเล็กๆ ที่บรรจุผ้าปิดตาที่อุ่นไว้ ทันทีที่เปิดฝาซอง ความอุ่นอ่อนล้าก็ค่อยๆ แผ่ซ่านไปทั่วเปลือกตา พิธีกรรมอันอ่อนโยนก่อนนอนที่ผนึกวันอันเหนื่อยล้าไว้ชั่วครู่แล้วค่อยปลดปล่อยออกมา"},"ICON-0570":{"nm":"ไส้กรองเครื่องเพิ่มความชื้นพกพา","de":"เยื่อกรองเล็กๆ ที่คืนความชื้นให้ห้องที่แห้งผาก จากภายในที่มองไม่เห็น มันกรองสิ่งขุ่นมัวออกไปอย่างเงียบๆ ความชุ่มชื้นที่เต็มห้องคือความใสสะอาดที่ได้รับการปกป้องด้วยความพยายามอันมองไม่เห็นของใครสักคน"},"ICON-0571":{"nm":"กล่องจัดวิตามิน","de":"กล่องที่แบ่งยาเม็ดของแต่ละวันไว้เป็นช่องๆ การทานอย่างสม่ำเสมอคือคำสัญญาว่าจะขึ้นเวทีอีกครั้งในวันพรุ่งนี้ ในแต่ละช่องเล็กๆ นั้น หัวใจที่ทะนุถนอมตัวเองถูกจัดเรียงไว้อย่างเป็นระเบียบเรียบร้อย"},"ICON-0572":{"nm":"ตลับที่อุดหูสำหรับนอน","de":"บ้านของที่อุดหูที่ปิดกั้นเสียงของโลกไว้ชั่วคราว แม้แต่ความเงียบก็ยังต้องการการดูแล จึงนอนอย่างเรียบร้อยอยู่ในตลับ คืนที่หลับสนิทเท่านั้นที่จะทำให้เสียงของวันถัดไปตื่นขึ้นมาอย่างใสกังวาน สิ่งที่การพักผ่อนรู้ดี"},"ICON-0573":{"nm":"คลิปหนีบผ้าเย็น","de":"คีมที่กัดยึดผ้าเย็นไว้บนไหล่อย่างแน่นหนาไม่ให้ลื่นไหล ในวันที่ร้อนอบอ้าว ความเย็นเส้นหนึ่งที่สัมผัสต้นคอช่วยให้ผ่านบ่ายอันยาวนานไปได้ แม้แต่ความเย็นเล็กๆ หากยึดไว้ให้มั่นก็อยู่ได้นาน"},"ICON-0574":{"nm":"ถุงลูกบอลยืดเหยียด","de":"ถุงสำหรับเก็บลูกบอลที่ผ่อนคลายร่างกายกลับเข้าที่ การยืดขยายเต็มที่แล้วค่อยเก็บให้เล็กลงอีกครั้งคล้ายกับลมหายใจเข้าและออก ระหว่างการคลี่ออกและการเก็บกลับนั้น ทั้งกายและใจค่อยๆ แข็งแรงขึ้น"},"ICON-0575":{"nm":"ม้วนผ้าพันแผลรัดกล้ามเนื้อ","de":"แถบผ้าที่โอบพันข้อเท้าที่เคล็ดไว้รอบแล้วรอบเล่า ไม่ใช่การรัดแน่น แต่เป็นการประคองไว้อย่างเงียบๆ ยิ่งจุดที่บอบช้ำมากเท่าไร ยิ่งต้องการมือที่อดทนอยู่เคียงข้างอย่างเงียบงันมากเท่านั้น ม้วนผ้ากระซิบบอกเช่นนั้นขณะที่มันพันตัวรอบๆ"},"ICON-0576":{"nm":"ป้ายเช็คสภาพร่างกาย","de":"ป้ายที่เขียนสภาพร่างกายวันนี้ไว้เพียงบรรทัดเดียวแล้วแขวนไว้ การบอกความดีและความแย่อย่างตรงไปตรงมาคือความกล้าเล็กๆ แทนที่จะแสร้งทำเป็นไม่เป็นไร เขียนตัวเองในวันนี้ไว้ แล้วใครสักคนจะอ่านบรรทัดนั้นแล้วคอยดูแลเราอย่างเงียบๆ"},"ICON-0577":{"nm":"แคปซูลหอมใส่รองเท้า","de":"แคปซูลกลิ่นหอมที่ใส่ไว้ในรองเท้าเบาๆ เป็นความปลอบโยนเล็กๆ อันแผ่วเบาที่มอบให้เท้าที่เดินตะลุยเวทีมาทั้งวัน กลิ่นหอมที่ดีที่สุดมอบให้จุดที่เหนื่อยล้าที่สุด ความอ่อนโยนเข้าถึงทุกจุดจนถึงปลายเท้าโดยไม่เว้นแม้แต่ที่เดียว"},"ICON-0578":{"nm":"แผ่นบอกขนาดพื้นรองเท้า","de":"แม้แต่บนพื้นรองเท้าก็ยังสลักขนาดเท้าไว้อย่างชัดเจนบนแผ่นนี้ รองเท้าคู่หนึ่งที่พอดีเป๊ะทำให้ก้าวเดินบนเวทีเบาสบาย การคำนึงถึงความยาวก้าวที่แตกต่างกันไปของแต่ละคน ความพอดีในที่สุดแล้วคือหัวใจที่มองผู้อื่นอย่างลึกซึ้ง"},"ICON-0579":{"nm":"พวงกุญแจช้อนสวมรองเท้า","de":"พวงกุญแจที่ย่อช้อนสวมรองเท้าให้เล็กพอขนาดฝ่ามือ ความใส่ใจเล็กๆ ที่ช่วยให้ช่วงเวลาสั้นๆ ของการสวมรองเท้าราบรื่นขึ้น เท้าที่ก้าวออกสู่ถนนมักมีมือที่อ่อนโยนของใครสักคนแขวนอยู่เคียงข้างอย่างเงียบๆ เสมอ"},"ICON-0580":{"nm":"ผ้าคลุมกันฝุ่นกระเป๋า","de":"ผ้าที่คลุมกระเป๋าที่รักไว้จากฝุ่นละอองอย่างแผ่วเบา แม้ในยามไม่ได้ใช้งาน มันก็ยังทำให้กระเป๋าหลับใหลอย่างงดงามและปกป้องผิวสัมผัสไว้ สิ่งที่หัวใจเราผูกพันแม้จะไม่ได้แตะต้องบ่อยนัก ก็ยังมีการดูแลอันเงียบสงบเช่นนี้แฝงอยู่"},"ICON-0581":{"nm":"หมุดปรับสายรัด","de":"หมุดที่ปรับสายที่หย่อนคลายให้กระชับพอดีกับร่างกาย หลวมเกินไปไหล่ก็จะไหล ตึงเกินไปก็จะหายใจไม่ทัน ในการปรับเพียงช่องเล็กๆ เพื่อค้นหาความพอดีนั้น ทั้งชุดแสดงบนเวทีและหัวใจต่างพบความสบายในที่สุด"},"ICON-0582":{"nm":"ปากกาหล่อลื่นซิป","de":"ลากผ่านซิปที่ฝืดเพียงครั้งเดียวมันก็รูดลื่นไหลอีกครั้ง เสียงของสิ่งที่ติดขัดคลายตัวออกอย่างลื่นไหลนั้นช่างสดชื่นเหลือเกิน สิ่งที่ทำให้จุดที่หยุดนิ่งไหลลื่นอีกครั้งคือความลื่นไหลเพียงเส้นเดียว"},"ICON-0583":{"nm":"หัวแปรงทำความสะอาดรองเท้าผ้าใบ","de":"ปลายขนแปรงที่เช็ดรองเท้าผ้าใบที่เปื้อนฝุ่นดินให้สะอาดทีละจุดทีละจุด นอกเวที มันค่อยๆ ลบร่องรอยการซ้อมที่มองไม่เห็นออกไปอย่างตั้งใจ เมื่อเห็นปลายรองเท้ากลับมาขาวสะอาดอีกครั้ง ดูเหมือนพรุ่งนี้จะวิ่งได้ด้วยหัวใจที่สดใหม่อีกครั้ง"},"ICON-0584":{"nm":"ฝาสเปรย์กันน้ำ","de":"ฝากันน้ำที่ทำให้เม็ดฝนกลิ้งเป็นทรงกลมแล้วหล่นตกลงไป การเคลือบชั้นหนึ่งไว้ล่วงหน้าเพื่อไม่ให้เปียกคือความอ่อนโยนที่มองการณ์ไกล เพราะรู้ว่าวันฝนตกจะมาถึง จึงคลุมฟิล์มบางๆ ไว้บนวันแจ่มใสวันนี้ก่อนล่วงหน้า"},"ICON-0585":{"nm":"ผ้าปกป้องหนัง","de":"ผ้าที่คลุมไว้เบาๆ บนหนังเพื่อป้องกันรอยยับย่น ปกป้องผิวสัมผัสราวกับมือในอดีตที่ห่อฉากกั้นด้วยกระดาษฮันจี ยิ่งสิ่งใดจะอยู่เคียงข้างนานเท่าไร ยิ่งต้องค่อยเป็นค่อยไป การทำให้เข้าที่เข้าทางก็เป็นเพียงชื่ออีกชื่อของเวลาที่ใช้ดูแลเอาใจใส่"},"ICON-0586":{"nm":"สายคาดชื่อกระเป๋าเดินทาง","de":"สายคาดชื่อที่ทำให้จำกระเป๋าของเราได้ในทันทีท่ามกลางกระเป๋านับไม่ถ้วน ท่ามกลางสัมภาระที่วนเวียนอยู่บนสายพาน มันยกมือขึ้นด้วยตัวอักษรเพียงตัวเดียว ไม่ว่าจะเดินทางไปไกลแค่ไหน ชื่อเพียงชื่อเดียวก็เป็นความอุ่นใจว่าจะได้พบกันอีกครั้ง"},"ICON-0587":{"nm":"คลิปถุงสูญญากาศ","de":"คีมที่กดสัมภาระที่พองฟูให้แบนราบแล้วปิดผนึกไว้ มันไม่ได้ทำให้ว่างเปล่าลง แต่เป็นการพับเก็บอย่างเป็นระเบียบมากกว่า จากปลายนิ้วที่ตัดทอนข้าวของให้เรียบร้อย แม้แต่ความโลภก็เล็กลงไปด้วย สัมภาระที่ถูกกดแน่นบอกเราอย่างเงียบๆ เช่นนั้น"},"ICON-0588":{"nm":"แผ่นผงซักฟอกสำหรับเดินทาง","de":"แผ่นผงซักฟอกที่ทำให้อ่างล้างหน้ากลายเป็นที่ซักผ้าได้ด้วยแผ่นเดียว มันคล้ายกับภูมิปัญญาของนักเดินทางที่ซักผ้าด้วยมือในดินแดนแปลกถิ่น การเดินทางแบบเบาสบายแต่ยังพกความเรียบร้อยติดตัวไปด้วยเสมอ คือทัศนคติที่นักเดินทางบนเส้นทางยึดถือมาช้านาน"},"ICON-0589":{"nm":"ปลอกหมอนรองคอ","de":"ปลอกที่สะอาดสดใหม่ที่เปลี่ยนใส่หมอนที่รองรับต้นคอ ที่พิงมักต้องสะอาดเสมอจึงจะรู้สึกสบายใจ การเว้นที่ไว้ให้นุ่มและสะอาดเพื่อให้ใครสักคนได้พิงอย่างสบายใจ การต้อนรับเริ่มต้นที่นั่นเอง"},"ICON-0590":{"nm":"สายชั่งน้ำหนักกระเป๋าเดินทาง","de":"สายที่ยกกระเป๋าขึ้นเพื่อกะน้ำหนัก ก่อนออกเดินทาง เราอุ้มน้ำหนักของสัมภาระไว้ในมือล่วงหน้า ระหว่างสิ่งที่จะพาไปและสิ่งที่จะทิ้งไว้ เป็นช่วงเวลาที่ชั่งแม้แต่น้ำหนักของหัวใจไปพร้อมกันอย่างเงียบๆ"},"ICON-0591":{"nm":"คู่ซองใส่รองเท้า","de":"ซองคู่หนึ่งที่บรรจุรองเท้าสองข้าง ซ้ายและขวา ไว้เคียงกัน แยกกันไว้ก็ง่ายต่อการหาย แต่จับคู่กันไว้ก็อุ่นใจ สิ่งที่ไปด้วยกันเสมอย่อมมีพลังที่คอยเฝ้าดูแลกันและกันอย่างเงียบๆ"},"ICON-0592":{"nm":"ห่วงแขวนกระเป๋าสำรอง","de":"ในวันที่มือข้างเดียวไม่พอ ห่วงเล็กๆ ที่แขวนกระเป๋าไว้ชั่วครู่ เป็นช่องว่างสำรองสำหรับวันที่มีของมากเกินกว่าจะถือไหวทั้งหมด เพียงมีที่ให้แขวนไว้สักครู่ก็ทำให้บ่าเบาลงไปมาก"},"ICON-0593":{"nm":"ชิปกำหนดการเดินทาง","de":"จารึกเส้นทางของวันไว้บนชิปหนึ่งชิ้นอย่างชัดเจน จะพบกันที่ไหนและจะไปทางไหนต่อ เส้นนำทางที่ขีดไว้ล่วงหน้าสำหรับก้าวเดินที่ไม่ค่อยชำนาญทาง เส้นทางที่ออกเดินไปด้วยกันหากจดไว้ทีละช่องก็แทบจะไม่หลงทาง"},"ICON-0594":{"nm":"ฝาปลั๊กแปลงสากล","de":"ฝาที่เข้าล็อกพอดีแม้กับปลั๊กไฟของประเทศที่แปลกถิ่น แม้รูปร่างจะต่างกัน แต่ในที่สุดก็เชื่อมต่อเป็นหนึ่งเดียว การเชื่อมสิ่งที่มาจากที่ต่างกันเข้าด้วยกัน ความกลมกลืนเริ่มต้นอย่างเงียบๆ จากการแปลงเล็กๆ เพียงหนึ่งครั้ง"},"ICON-0595":{"nm":"ซองใส่บัตรโดยสาร","de":"แผ่นใสแผ่นเดียวที่ปกป้องบัตรทุกครั้งที่แตะผ่านประตูกั้น การเดินทางไปทำงานทุกวัน แม้แต่รอยที่แตะจนสึกกร่อนก็ยังห่อหุ้มไว้อย่างงดงาม แม้แต่เส้นทางธรรมดาก็กลายเป็นความทรงจำได้หากทะนุถนอมไว้ ชั้นบางๆ นี้เป็นเครื่องพิสูจน์"},"ICON-0596":{"nm":"คลิปหนีบตั๋วโดยสาร","de":"คีมที่คาบตั๋วแผ่นเดียวที่ยับง่ายเหลือเกินไว้อย่างเรียบร้อย หากทำตั๋วหายกลางทาง แม้แต่หัวใจก็สั่นคลอนไปด้วย กระดาษยิ่งเล็กยิ่งต้องยึดไว้ให้แน่น ความอุ่นใจของการเดินทางมาจากช่องเล็กๆ นั้นเอง"},"ICON-0597":{"nm":"ชิปโน้ตเปลี่ยนสาย","de":"ชิปเล็กๆ ที่จดไว้บรรทัดเดียวว่าจะเปลี่ยนสายที่ไหน ในทุกทางแยกที่สับสน คำเดียวที่จดไว้ล่วงหน้าเปิดทางให้สว่างไสว โน้ตคือคำใบ้อันอ่อนโยนที่แอบส่งให้ตัวเราในอนาคตที่อาจหลงทาง"},"ICON-0598":{"nm":"แท็กผ่านประตู","de":"ป้ายผ่านที่ถูกจดจำอย่างเงียบๆ ขณะเดินผ่านประตู แม้แต่เส้นทางที่ดูเหมือนถูกปิดกั้นก็เปิดออกอย่างลื่นไหลเมื่อมีคุณสมบัติของตัวเอง การส่งผ่านอย่างเปิดเผยคือการก้าวไปสู่ช่องต่อไปอย่างเบาสบายโดยไม่ลังเล"},"ICON-0599":{"nm":"ที่เก็บใบเสร็จแท็กซี่","de":"กระดาษเล็กๆ แต่ละแผ่นประทับร่องรอยของเส้นทางที่ไปมาในวันนั้นไว้อย่างชัดเจน รวบรวมใบเสร็จที่เคยกลิ้งไปทั่วทุกทิศให้มาเรียงกันอย่างเป็นระเบียบ แล้ววันธรรมดาที่ดูไม่มีอะไรก็ค่อยๆ สะสมกลายเป็นการเดินทางอันสมบูรณ์"},"ICON-0600":{"nm":"แถบสะท้อนแสงจักรยาน","de":"แถบที่รับแสงไฟที่ผ่านไปมาบนถนนมืดแล้วเปล่งประกายอย่างเงียบๆ แม้ไม่ส่องแสงด้วยตัวเอง แต่ก็สว่างไสวขึ้นด้วยแสงของใครสักคน การทำให้ตัวเองมองเห็นได้คือคำขอร้องอันอ่อนโยนของถนนยามค่ำคืนที่ขอให้กลับบ้านอย่างปลอดภัย"},"ICON-0601":{"nm":"ปลอกล้อกระเป๋าเดินทาง","de":"เหตุผลที่มุมกระเป๋าเดินทางยังคงสมบูรณ์แม้กลิ้งผ่านสายพานสนามบินมานับพันครั้ง ก็เพราะปลอกเล็กๆ ที่ห่อหุ้มล้อไว้นี่เอง ส่วนที่สัมผัสเส้นทางขรุขระที่สุดเป็นด่านแรกเสมอ—การปกป้องใครสักคนอย่างเงียบๆ มักซ่อนอยู่ในจุดที่ไม่มีใครสังเกตเห็นแบบนี้"},"ICON-0602":{"nm":"ปลอกหุ้มพนักพิงศีรษะ","de":"บนรถบัสระยะไกล เธอสวมปลอกทับพนักพิงศีรษะแล้วเอนตัวพิงหน้าต่าง กลิ่นของผู้โดยสารคนก่อนหรือความเหนื่อยล้าของเมื่อวานไม่อาจแผ่มาถึงตรงนี้ได้ การมีที่พักศีรษะที่สะอาดคือความอุ่นใจที่ยิ่งใหญ่เกินคาดบนเส้นทางที่แสนแปลกหน้า"},"ICON-0603":{"nm":"หมุดปักตำแหน่งที่จอดรถ","de":"\"ชั้นไหนช่องไหนนะ\" ใครก็ตามที่เคยหลงวนอยู่ในลานจอดรถที่ว่างเปล่ารู้ดีว่าหมุดนี้อุ่นใจแค่ไหน สัญลักษณ์เล็กๆ ที่ปักไว้แทนความทรงจำที่กำลังจะเลือนราง กำหนดจุดหมายที่จะกลับมาไว้ล่วงหน้า"},"ICON-0604":{"nm":"สายคล้องกุญแจห้องพัก","de":"กุญแจห้องพักหายไปง่ายดายเหลือเกินได้อย่างไรกัน ร้อยเชือกคล้องข้อมือไว้ แล้วห้องที่จะกลับไปในคืนนี้ก็ไม่มีวันถูกลืม แม้ในเมืองแปลกหน้า ความอุ่นใจเล็กๆ ที่รู้ว่าที่ของตัวเองถูกกำหนดไว้แล้ว ก็ห้อยอยู่ที่ข้อมือนั่นเอง"},"ICON-0605":{"nm":"ป้ายแขวนประตูซ้อมเต้น","de":"เมื่อการซ้อมเริ่มขึ้น ป้ายชิ้นเล็กๆ จะถูกแขวนไว้ที่ประตู ห้ามรบกวน—เวลานี้คือเวลาแห่งสมาธิล้วนๆ ความเงียบสงบลึกๆ หลังเวทีนั้น ถูกปกปักรักษาไว้อย่างเงียบงันด้วยสัญญาณเล็กๆ แบบนี้เอง"},"ICON-0606":{"nm":"กระเป๋าใส่ของใช้อาบน้ำ","de":"แปรงสีฟัน โฟมล้างหน้า ผ้าเช็ดตัวขนาดเท่าฝ่ามือ ไม่ว่าจะไปที่ไหน แค่พกกระเป๋าใบนี้ใบเดียว จุดเริ่มต้นและจุดสิ้นสุดของวันก็ยังคงถูกจัดเรียงด้วยมือที่คุ้นเคยเสมอ กำมือเล็กๆ ของการดูแลบ้าน ที่ทำให้เตียงนอนแปลกหน้ากลายเป็นที่คุ้นเคยโดยไม่รู้ตัว"},"ICON-0607":{"nm":"คลิปหนีบผ้าเช็ดตัวสำรอง","de":"ข้างอ่างล้างหน้า ผ้าเช็ดตัวสำรองที่ไม่มีที่ให้แขวนมักจะชื้นแฉะอยู่เสมอ พอหนีบด้วยคลิปแล้วแขวนไว้ ในที่สุดมันก็พบที่ของตัวเอง การมอบที่ให้แห้งสักแห่ง—ความอ่อนโยนมักมีขนาดพอๆ กับสิ่งนี้เอง"},"ICON-0608":{"nm":"กระเป๋าใส่ปลั๊กพ่วง","de":"ทุกครั้งที่เปิดกระเป๋า สายชาร์จมักพันกันเป็นก้อนเดียว พอม้วนปลั๊กพ่วงทั้งเส้นใส่เข้าไป ข้างในก็เป็นระเบียบขึ้นทันที สายไฟที่คลี่ออกได้ ก็หมายความว่ามุมหนึ่งในใจก่อนออกเดินทางก็คลายปมลงอย่างเงียบๆ เช่นกัน"},"ICON-0609":{"nm":"ป้ายเลขเตียงสองชั้น","de":"ป้ายเลขที่ติดอยู่บนเตียงสองชั้นแต่ละเตียงในหอพักรวม ด้วยป้ายเพียงแผ่นเดียวที่บอกว่าที่ไหนคือของเรา แม้ห้องแปลกหน้าที่เพิ่งมาถึงก็กลายเป็นบ้านของเราได้ในคืนนั้นเอง จุดเริ่มต้นมักเล็กจิ๋วแบบนี้เสมอ"},"ICON-0610":{"nm":"ราวตากผ้าจิ๋ว","de":"แขวนปลายทั้งสองข้างไว้ระหว่างกรอบหน้าต่าง มันก็กลายเป็นราวตากผ้า ในวันที่แดดดี ถุงเท้าไม่กี่คู่ที่ซักด้วยมือแกว่งไกวฟูนุ่มไปตามสายลม แม้อยู่ไกลจากบ้าน ชีวิตประจำวันก็ยังแห้งอยู่บนเส้นราวแบบนี้"},"ICON-0611":{"nm":"ป้ายชี้เจ้าของรองเท้าแตะ","de":"เมื่อรองเท้าแตะกองสุมอยู่หน้าประตู ก็ไม่มีทางรู้เลยว่าคู่ไหนเป็นของใคร แค่ติดป้ายเล็กๆ สักอัน แม้แต่รองเท้าก็จำเจ้าของตัวเองได้ การอยู่ร่วมกันอย่างแออัดหลายคนนั้น ต้องการเครื่องหมายแสนอ่อนโยนแบบนี้เสมอ"},"ICON-0612":{"nm":"ที่เก็บคูปองอาหารเช้า","de":"ที่ไว้สอดบัตรอาหารเช้า ยามเช้าตรู่ที่ท้องหิว บัตรเพียงใบเดียวนี้ก็รับประกันซุปร้อนๆ หนึ่งชามได้ วันหนึ่งของการเดินทางมักค่อยๆ เปิดขึ้นด้วยมื้ออาหารอุ่นๆ เสมอ"},"ICON-0613":{"nm":"แถบสะท้อนแสงข้อเท้า","de":"พันรอบข้อเท้าแล้วมันจะสะท้อนแสงกลับในความมืด บนเส้นทางเดินยามค่ำคืน มันโบกมือให้รถที่แล่นเข้ามาแต่ไกลอย่างเงียบๆ ว่า \"มีคนอยู่ตรงนี้นะ\" ความปลอดภัยเปล่งประกายอย่างเรียบง่ายเช่นนี้เอง"},"ICON-0614":{"nm":"ฝาปิดกระดาษเปียกพกพา","de":"ฝาที่สวมพอดีกับปากถุงกระดาษเปียก ดึงออกมาทีละแผ่นได้นุ่มนวล และแผ่นที่เหลือก็ไม่แห้งกรัง แม้ดูเป็นเรื่องเล็กน้อย แต่ของที่มือเราเอื้อมไปหาทุกวันนั้น ล้วนมีเหตุผลที่ซ่อนอยู่เสมอ"},"ICON-0615":{"nm":"สายรัดเสื่อปิกนิก","de":"ม้วนเสื่อเป็นวงกลมแล้วมัดด้วยสาย ริมแม่น้ำฮัน ใต้ร่มเงาดอกซากุระ ไม่ว่าที่ไหนก็ตาม ทันทีที่ปูออก ที่ตรงนั้นก็กลายเป็นที่ของเรา สายที่พาอาณาเขตขนาดเท่าฝ่ามือบนสนามหญ้าติดตัวไปได้ทุกที่"},"ICON-0616":{"nm":"กล่องใส่แผ่นแปะกันยุง","de":"ของจำเป็นในคืนฤดูร้อน กล่องที่ใส่แผ่นแปะกันยุง ความใส่ใจที่เตรียมไว้ก่อนจะเริ่มคันนั้น บรรจุอยู่ในช่องเล็กๆ นี้เอง แถวหลังของเวทีกลางแจ้งมักอุ่นใจได้เสมอด้วยการเตรียมพร้อมเล็กๆ แบบนี้"},"ICON-0617":{"nm":"ตะขอแขวนขวดน้ำสำหรับเดินเล่น","de":"ตะขอสำหรับแขวนขวดน้ำไว้กับกระเป๋าตอนออกเดินเล่น การมีน้ำอยู่ใกล้มือในยามที่กระหาย หมายความว่าจะเดินได้ไกลขึ้นเท่านั้น การเชื่อมโยงเล็กๆ ที่ไม่ทำให้คนเดินต้องหยุดเดิน"},"ICON-0618":{"nm":"ตะกร้าจ่ายตลาดพับได้","de":"กางออกก็เป็นตะกร้า พับเก็บก็พอดีฝ่ามือ เหมาะเจาะสำหรับใส่ผักหนึ่งกำที่เก็บมาด้วยความเอ็นดูระหว่างเดินเล่นตามตรอกตลาด ภูมิปัญญาการดูแลบ้านมักเติบโตไปในทิศทางที่ลดขนาดลง และพกพาได้เบาขึ้นเสมอ"},"ICON-0619":{"nm":"คลิปกันลม","de":"ในวันลมแรง มันหนีบชายผ้าเต็นท์ที่ปลิวไปมาให้แน่นหนา คลิปเพียงชิ้นเดียวกดสิ่งที่สั่นไหวอยู่ตลอดให้อยู่กับที่ สิ่งที่พึ่งพาได้มากที่สุดกลางแจ้ง กลับเป็นของเล็กเท่านิ้วมือแบบนี้อย่างไม่น่าเชื่อ"},"ICON-0620":{"nm":"หมุดบังแดด","de":"หมุดที่ปักไว้กับหน้าต่างเพื่อเบี่ยงแสงแดดให้เฉียงไป เมื่อแสงยามเที่ยงจ้าเกินไป มันแอบทอดร่มเงากำมือหนึ่งให้เงียบๆ การช่วยลดแสงจ้าก็อาจเป็นสัมผัสที่อ่อนโยนที่สุดสำหรับใครบางคน"},"ICON-0621":{"nm":"ฝาครอบนกหวีดฉุกเฉิน","de":"ฝาที่ครอบปากนกหวีดฉุกเฉินไว้ ไม่ให้ฝุ่นเข้า เพื่อให้ในยามที่จำเป็นจริงๆ มันดังขึ้นได้ในลมหายใจเดียว บางสิ่งก็ให้ความอุ่นใจได้เพียงแค่อยู่ใกล้ๆ แม้เราจะหวังว่าไม่มีวันต้องได้ใช้มันเลยก็ตาม"},"ICON-0622":{"nm":"ฝาครอบปลายร่ม","de":"ฝาเล็กๆ ที่สวมไว้ที่ปลายแหลมของร่ม เมื่อปลายแหลมนั้นทู่ลง ทั้งคนข้างกายและกระเป๋าของเราก็ไม่ต้องบาดเจ็บ มารยาทในวันฝนตกเริ่มต้นอย่างเงียบๆ จากการห่อหุ้มปลายแหลมให้กลมมนแบบนี้เอง"},"ICON-0623":{"nm":"ถุงเก็บเสื้อกันฝน","de":"ถุงสำหรับม้วนเสื้อกันฝนที่พับไว้แล้วเก็บใส่เข้าไป มันรอคอยอย่างเงียบๆ อยู่มุมหนึ่งของกระเป๋าจนกว่าฝนห่าต่อไปจะโปรยลงมา การเตรียมพร้อมท้ายที่สุดแล้วก็คือเศษเสี้ยวของหัวใจ ที่เก็บสิ่งซึ่งอาจไม่ได้ใช้เลยไว้ล่วงหน้า"},"ICON-0624":{"nm":"ปลอกหุ้มรองเท้ากันน้ำ","de":"สวมทับรองเท้าแล้วน้ำฝนก็ไม่อาจซึมเข้าไปได้อีก แม้บนทางไปโรงเรียนที่ฝนตกหนักในฤดูมรสุม ถุงเท้าก็ยังคงแห้งสนิท วันที่ปลายเท้าไม่เปียกชื้นนั้น เปลี่ยนอารมณ์ได้มากกว่าที่คิดไว้เยอะเลย"},"ICON-0625":{"nm":"แผ่นกันลื่นหิมะ","de":"แปะไว้ใต้รองเท้าแล้วถนนน้ำแข็งก็น่ากลัวน้อยลงมาก ฤดูหนาวปีนั้นที่ต้องรีบก้าวเท้าข้ามตรอกที่เต็มไปด้วยหิมะ แผ่นนี้คอยจับยึดไว้ไม่ให้ลื่นล้มอย่างเงียบๆ ความมั่นคงที่ซ่อนอยู่ใต้ย่างก้าวที่ระมัดระวัง"},"ICON-0626":{"nm":"ห่วงเย็นรอบคอ","de":"พันรอบคอแล้วความเย็นสบายจะแผ่วนเวียนอยู่เงียบๆ ภูมิปัญญาแห่งฤดูร้อนที่พาความเย็นสายหนึ่งพาดบ่าไปด้วยแม้ในวันที่ร้อนอบอ้าวที่สุด วิธีทนความร้อนก็ค่อยๆ ประณีตขึ้นทีละนิดในทุกๆ ปี"},"ICON-0627":{"nm":"ขาตั้งพัดลมมือถือ","de":"ขาตั้งสำหรับตั้งพัดลมมือถือให้ยืนได้ เมื่อสองมือเป็นอิสระ ก็พลิกหน้าหนังสือได้ เขียนหนังสือแทนการโบกพัด สายลมเบาบางสายหนึ่งช่วยให้ฤดูร้อนอันยาวนานหน้าโต๊ะพอจะทนได้อยู่บ้าง"},"ICON-0628":{"nm":"กระเป๋าใส่แผ่นความร้อน","de":"กระเป๋าสำหรับพกแผ่นให้ความร้อน เมื่อสอดปลายนิ้วที่เย็นเฉียบเข้าไปในกระเป๋าเพื่อให้ละลาย ความอุ่นเล็กๆ ก็รอคอยอยู่ตรงนั้นก่อนแล้ว การออกไปข้างนอกในฤดูหนาวทนได้ด้วยความอุ่นกำมือเดียวนี้เอง"},"ICON-0629":{"nm":"กล่องเก็บที่ปิดหูกันหนาว","de":"กล่องสำหรับเก็บที่ปิดหูไว้ เป็นที่เก็บรักษาอย่างทะนุถนอมจนกว่าความหนาวครั้งต่อไปจะมาเยือน สิ่งของที่แม้ฤดูกาลจะเปลี่ยนไปแต่ก็ยังทิ้งไม่ลงนั้น แฝงไว้ด้วยความเชื่อมั่นอันเงียบงันว่าจะได้พบฤดูหนาวอีกครั้ง"},"ICON-0630":{"nm":"ชิปวัดรังสียูวี","de":"แค่แตะเบาๆ กับแสง ชิปนี้ก็จะบอกความแรงของรังสียูวีวันนี้ผ่านสีสัน มันทำให้ความเข้มของแสงแดดที่มองไม่เห็นกลายเป็นสิ่งที่มองเห็นได้ในที่สุด เท่ากับติดดวงตาเล็กๆ ที่อ่านท้องฟ้าเอาไว้ที่ข้อมืออย่างเงียบๆ"},"ICON-0631":{"nm":"แผ่นสะสมตราประทับตรอกซอย","de":"แผ่นที่เก็บสะสมตราประทับจากร้านค้าปากตรอกทีละร้าน ทุกครั้งที่ประทับตราลงไปอีกช่อง แผนที่ย่านนั้นก็ค่อยๆ ชัดเจนขึ้นในใจ ความทรงจำที่เก็บสะสมด้วยสองเท้าจะยังคงเหลือรอดในรอยตราประทับแบบนี้เอง"},"ICON-0632":{"nm":"บอร์ดปักหมุดสถานที่ที่ไปมา","de":"บอร์ดเล็กๆ ที่ปักหมุดไว้ทุกที่ที่เคยไปเยือน ยิ่งจุดเพิ่มขึ้นทีละจุดสองจุด ขอบเขตของโลกของเราก็ยิ่งกว้างขึ้นตามไปด้วย หมุดแต่ละอันคือร่องรอยที่กระซิบเบาๆ ว่า \"ฉันเคยอยู่ที่นี่\""},"ICON-0633":{"nm":"สายเข็มทิศเล็ก","de":"แม้จะหลงทางอยู่นานแค่ไหน ทิศเหนือเพียงอย่างเดียวก็ยังคงอยู่ที่เดิมไม่เคยเปลี่ยนแปลง เข็มทิศเล็กๆ ที่ห้อยอยู่ตรงหน้าอก เมื่อไม่รู้เลยว่าจะไปทางไหน จะค่อยๆ ปลอบประโลมหัวใจที่สั่นไหวให้สงบลงก่อนเป็นอันดับแรก"},"ICON-0634":{"nm":"ห่วงโน้ตนำทาง","de":"ร้อยกระดาษโน้ตที่จดไว้ระหว่างหาทางเข้าห่วงเก็บไว้ด้วยกัน \"เลี้ยวซ้ายที่ตู้ไปรษณีย์สีแดง\" ลายมือที่เขียนไม่สวยของใครบางคนคอยนำทางตรอกแปลกหน้าอย่างเงียบๆ เส้นทางที่หลงเหลืออยู่บนกระดาษนั้นไม่ค่อยจะเลือนรางง่ายๆ"},"ICON-0635":{"nm":"สมุดสติกเกอร์แลนด์มาร์ก","de":"สมุดที่เติมเต็มด้วยสติกเกอร์หนึ่งแผ่นที่ซื้อมาจากแต่ละจุดหมายปลายทาง หอคอย สะพาน กำแพงป้อมปราการเก่าแก่ ค่อยๆ ซ้อนทับกันหน้าแล้วหน้าเล่า การเก็บสะสมสถานที่ที่เคยไปมานั้นคล้ายกับการสัมผัสเวลาที่ผ่านมาแล้วด้วยปลายนิ้วอีกครั้งหนึ่ง"},"ICON-0636":{"nm":"ชิปเปลี่ยนสายรถไฟใต้ดิน","de":"ชิปที่กำแน่นในมือ ณ สถานีเปลี่ยนสายที่เส้นทางแยกออกจากกัน ช่วงเวลาสั้นๆ ของการตัดสินใจว่าจะเปลี่ยนไปทางไหนนั้น บางครั้งก็เปลี่ยนทิศทางของทั้งวันไปโดยสิ้นเชิง ด้วยการตัดสินใจเล็กๆ เพียงครั้งเดียว เมืองก็แสดงใบหน้าที่แตกต่างออกมา"},"ICON-0637":{"nm":"การ์ดผจญภัยย่านบ้าน","de":"\"วันนี้ไปถึงร้านขนมปังแถวนี้กันเถอะ\" จั่วการ์ดขึ้นมาหนึ่งใบ จุดหมายของการผจญภัยวันนี้ก็ถูกกำหนดไว้ แม้ตรอกที่คุ้นเคยที่เดินผ่านอยู่เสมอ ก็กลายเป็นเส้นทางใหม่ได้เมื่อมีภารกิจเกิดขึ้น การ์ดที่บอกเราว่าการผจญภัยไม่ได้อยู่ไกลเลย"},"ICON-0638":{"nm":"ที่เก็บนามบัตรร้านค้า","de":"ที่ไว้เสียบนามบัตรที่ได้จากร้านประจำ ร้านที่อาหารอร่อย เจ้าของร้านที่ทักทายด้วยความอบอุ่น ค่อยๆ สะสมกันทีละช่อง การผูกพันกับเมืองสักเมืองหนึ่งเริ่มต้นจากกระดาษแผ่นเล็กๆ แบบนี้เอง"},"ICON-0639":{"nm":"บอร์ดเหรียญตรารางเดินครบเส้นทาง","de":"บอร์ดที่จะได้เหรียญตรามาเติมเต็มเมื่อเดินครบเส้นทางเดินเล่นจนจบ ความภาคภูมิใจของการเดินจนสุดทางกลายเป็นชิ้นโลหะกลมๆ ที่ยังคงอยู่ในมือ ความปลื้มใจที่มีแต่คนที่เดินจนสุดทางเท่านั้นจะเข้าใจ ถูกฝังไว้อย่างชัดเจนที่นี่"},"ICON-0640":{"nm":"พวงกุญแจล็อกกระเป๋า","de":"กุญแจเล็กๆ พร้อมพวงกุญแจที่ล็อกซิปกระเป๋าไว้ มันปกป้องของมีค่าไว้อย่างแน่นหนา ในขณะที่แกว่งไกวส่งเสียงกรุ๊งกริ๊งที่ปลายกระเป๋า เพื่อนร่วมทางที่ค่อนข้างฉลาดของนักเดินทาง ที่ความปลอดภัยและความสวยงามหลอมรวมเป็นหนึ่งเดียว"},"ICON-0641":{"nm":"แท็กกันของหาย","de":"มันหมอบซ่อนอยู่ในความมืดลึกที่สุดของกระเป๋า แล้วก็กะพริบแสงเบาๆ ในวินาทีที่ทุกคนยอมแพ้แล้ว \"อยู่ตรงนี้เอง\" เสียงของสิ่งที่คิดว่าสูญหายไปแล้วกำลังกลับคืนสู่ปลายนิ้ว แม้จะเล็ก มันก็ยังคงเฝ้าอยู่ข้างเจ้าของจนถึงที่สุด"},"ICON-0642":{"nm":"ห่วงล็อกซิป","de":"คลิก แค่ล็อกไปครั้งเดียว มือธรรมดาทั่วไปก็เปิดไม่ได้อีก ความดื้อรั้นที่ปิดกั้นทั้งเล็บที่รีบร้อนและนิ้วที่แอบย่องเข้ามาไว้เหมือนกันหมด ความปลอดภัยบอกเราด้วยน้ำหนักอันหนักแน่นว่า บางครั้งการฝืดสักหน่อยก็ไม่เป็นไร"},"ICON-0643":{"nm":"สายกริ่งกันขโมย","de":"ผู้เฝ้าประตูที่มองไม่เห็น คอยดูแลไม่ให้สินค้าบนชั้นแอบออกไปเที่ยวก่อนจ่ายเงิน เมื่อมือที่ซื่อสัตย์แตะผ่าน มันก็เงียบสนิทจนถึงที่สุด กระดิ่งที่ไม่ดังคือกระดิ่งที่สงบสุขที่สุด"},"ICON-0644":{"nm":"ป้ายปิดข้อมูลติดต่อ","de":"มันแอบวางชั้นบางๆ ทับไว้เหนือชื่อและเบอร์โทรที่เขียนบนกล่องพัสดุ ใครอยู่ที่ไหน จะไปที่ไหน—เป็นเรื่องที่ผู้รับเท่านั้นจำเป็นต้องรู้ การปิดบังให้ดีก็เป็นความอ่อนโยนอีกแบบหนึ่ง มันบอกเช่นนั้นพลางเฝ้ารักษาตำแหน่งของตัวเองอย่างเงียบๆ"},"ICON-0645":{"nm":"แถบรัดปกหนังสือเดินทาง","de":"สนามบินแปลกหน้า ปกหนังสือเดินทางเหมือนกันหลายสิบเล่มหมุนวนบนสายพานยามรุ่งสาง ท่ามกลางสิ่งเหล่านั้น มันโบกมือด้วยสีที่มีเพียงเราคนเดียวรู้จักว่า \"ทางนี้นะ\" เสื้อคลุมตัวเล็กๆ ที่สวมให้กับเอกสารที่กำลังออกเดินทางไกล แม้ปกจะสึกหรอ การเดินทางก็ยังคงสดใส"},"ICON-0646":{"nm":"กระเป๋าแยกช่องเงินสด","de":"ธนบัตรอยู่ซ้าย เหรียญอยู่ขวา เงินฉุกเฉินอยู่ในช่องที่ไม่มีใครรู้ เป็นจุดแรกที่มือซึ่งเพิ่งกลับจากตลาดจะเอื้อมไปหา แม้วันที่ยุ่งเหยิงก็ยังจัดเรียงเป็นระเบียบและส่งเสียงกรุ๊งกริ๊งหาที่ของมันได้ในกระเป๋าใบนี้"},"ICON-0647":{"nm":"สติกเกอร์ผนึกความปลอดภัย","de":"ลอกออกครั้งเดียวรอยก็ยังคงอยู่ มโนธรรมเล็กๆ ที่ซื่อสัตย์และไม่มีวันซ่อน \"มีใครเปิดมันแล้ว\" ได้จนถึงที่สุด ใต้กล่องทุกกล่องที่ผนึกแน่นและมาถึงอย่างปลอดภัยนั้น ล้วนมีความเงียบที่ไม่เคยเปลี่ยนแปลงของเพื่อนคนนี้ปูรองอยู่"},"ICON-0648":{"nm":"ชิปข้อมูลติดต่อฉุกเฉิน","de":"ในกระเป๋าของเด็กที่หลงทาง ด้านในกระเป๋าโน้ตบุ๊ก ปลายสายจูงสุนัข แม้ในยามที่พูดไม่ออก มันจะร้องบอกเบอร์โทรแทนอย่างชัดถ้อยชัดคำ ชิปเล็กๆ เพียงชิ้นเดียวบรรจุคำว่า \"ช่วยพาฉันกลับบ้านที\" ไว้ทั้งหมด"},"ICON-0649":{"nm":"ฝาครอบรีโมทไม้เซลฟี่","de":"ภาพถ่ายหมู่ที่มักมีใครสักคนถูกตัดขาดออกไปเพราะแขนไม่ยาวพอ ตอนนี้แค่กดปุ่มที่ปลายเบาๆ ทั้งครอบครัวก็เข้าเฟรมเดียวกันได้ ในชั่วขณะที่ทุกคนยิ้มพร้อมกันนั้น ฉันแอบกดชัตเตอร์แล้วกระโดดเข้าไปอยู่ในนั้นด้วย"},"ICON-0650":{"nm":"สายรัดถุงเลนส์","de":"สายที่โอบกอดเลนส์สำรองไว้แน่นหนาไม่ให้กระทบกันในกระเป๋า เพราะกระจกหนึ่งชิ้นคือทิวทัศน์หนึ่งภาพ จึงไม่เขย่าน้ำหนักนั้นอย่างประมาท ความระมัดระวังของช่างภาพถูกผูกไว้ในทุกปมเชือก"},"ICON-0651":{"nm":"ห่วงกล่องใส่ฟิลเตอร์","de":"แผ่นบางๆ เพียงแผ่นเดียวเปลี่ยนท้องฟ้าเดียวกันให้เป็นแสงที่แตกต่างออกไป ที่เก็บมนตร์เล็กๆ เหล่านั้นไว้เรียงรายอย่างเป็นระเบียบในรังกลมๆ นี้ ทุกครั้งที่เปิดกล่อง ปลายนิ้วก็แอบตื่นเต้นชั่วครู่ว่าวันนี้จะเก็บภาพพระอาทิตย์ตกแบบไหนดี"},"ICON-0652":{"nm":"กระเป๋าขาตั้งกล้อง","de":"พับแล้วเหลือแค่คืบเดียว กางออกแล้วขาทั้งสามมั่นคงไม่สั่นไหว ม้วนเพื่อนที่จะช่วยจับภาพทิวทัศน์ไว้แทนมือที่สั่นเทาใส่ไว้อย่างประณีต อุปกรณ์ยิ่งหนักเท่าไร ก็ยิ่งควรได้นอนบนผ้าที่นุ่มขึ้นเท่านั้น เป็นมารยาทที่ควรมี"},"ICON-0653":{"nm":"แผ่นรองสายคล้องกล้อง","de":"เดินทั้งวันแล้วก็ถึงเวลาที่กล้องเริ่มกดทับบ่า ตอนนั้นเองที่แผ่นรองชิ้นหนึ่งค่อยๆ รับน้ำหนักนั้นไปแบ่งเบา ความสบายเล็กๆ นุ่มฟูที่วางไว้บนบ่าที่เดินทางไกลเพื่อภาพถ่ายดีๆ เพียงภาพเดียว"},"ICON-0654":{"nm":"การ์ดแยกหมวดความทรงจำ","de":"คืนที่สับสนว่าความทรงจำหลายร้อยภาพหลับใหลอยู่ในการ์ดใบไหน เครื่องหมายหลากสีจะชี้ทางให้ ทริปฤดูใบไม้ผลิเป็นสีฟ้า เวทีแรกเป็นสีเหลือง บรรณารักษ์เล็กๆ ผู้แสนใจดีที่แบ่งช่องให้แม้แต่กับความทรงจำ"},"ICON-0655":{"nm":"ที่ม้วนเก็บสายชาร์จ","de":"ก่อนที่สายเคเบิลจะเริ่มแสดงโชว์พันกันยุ่งเหยิงในกระเป๋า ก็ม้วนเป็นวงกลมแล้วเก็บให้หลับนิ่งเรียบร้อย พอจัดสายเส้นหนึ่งให้เป็นระเบียบ เส้นหนึ่งในใจก็คลายปมตามไปด้วยอย่างประหลาด รูปทรงที่ม้วนกลมๆ นั้นมองแล้วรู้สึกสงบใจ"},"ICON-0656":{"nm":"ป้ายสำรองข้อมูลภาพ","de":"\"รูปพวกนี้สำรองไว้แล้วใช่ไหมนะ\" โน้ตเล็กๆ ที่ตอบคำถามความกังวลใจที่ผุดขึ้นมาในค่ำคืนดึกๆ ไว้ล่วงหน้า ยิ่งเป็นช่วงเวลาที่มีค่ามากเท่าไร ก็ยิ่งต้องมีสำเนาอยู่มากกว่าหนึ่งที่ ป้ายนี้เขียนบอกไว้อย่างชัดเจน"},"ICON-0657":{"nm":"กรอบจัดองค์ประกอบภาพ","de":"มองโลกผ่านหน้าต่างสี่เหลี่ยม แล้วจะเห็นทันทีว่าจะเก็บอะไรและจะเว้นอะไรไว้ ภาพถ่ายที่ดีไม่ใช่การใส่เพิ่มเข้าไป แต่เป็นการตัดออกให้ดี กรอบที่ว่างเปล่านี้สอนเรื่องนั้นเป็นสิ่งแรกเสมอ"},"ICON-0658":{"nm":"จี้กระเป๋าเหรียญ","de":"ห้อยแกว่งไกวอยู่ปลายกระเป๋า บรรจุเหรียญไม่กี่เหรียญไว้ในตัว คลังสมบัติเล็กๆ ที่เปิดเป็นแห่งแรกหน้าตู้ขายของอัตโนมัติ หรือหน้าแผงขนมโอยากิที่ควันโขมงร้อนๆ เสียงกรุ๊งกริ๊งนั้นคือเสียงประกอบของความสุขเล็กๆ น้อยๆ"},"ICON-0659":{"nm":"แกนเสียบใบเสร็จ","de":"เศษกระดาษที่เกือบจะถูกทิ้งถูกเสียบร้อยเรียงกันไปทีละใบ วันนี้กินอะไร ซื้ออะไรไปบ้าง ใบเสร็จคือสมุดบันทึกที่ซื่อสัตย์ยิ่งกว่าบัญชีรายรับรายจ่ายเสียอีก เก็บสะสมไว้เดือนหนึ่งก็กลายเป็นบันทึกชีวิตที่หนาพอสมควรเลยทีเดียว"},"ICON-0660":{"nm":"ป้ายห้อยตะกร้าจ่ายตลาด","de":"ห้อยอยู่ที่ข้อมือที่ออกไปจ่ายตลาด ท่องไปตามตรอกตลาดด้วยกัน เต้าหู้หนึ่งก้อน ต้นหอมหนึ่งกำ รวมถึงความเอื้อเฟื้อที่แถมมาให้ด้วยความรัก มันรับน้ำหนักทั้งหมดนั้นไว้โดยไม่บ่นสักคำ เพื่อนที่ตื่นเต้นตอนเติมเต็มมากกว่าตอนที่ว่างเปล่า"},"ICON-0661":{"nm":"แผ่นแม่เหล็กที่ระลึก","de":"เลือกมาอย่างละชิ้นจากแต่ละจุดหมายปลายทางแล้วติดไว้ที่ประตูตู้เย็น ครัวก็กลายเป็นแผนที่โลกเล็กๆ เมืองต่างๆ ที่เคยไปเยือนแขวนเรียงกันกระซิบว่า \"ไปกันอีกนะ\" แม้แผ่นเหล็กธรรมดาๆ ก็ยังมีพลังในการเก็บรักษาความทรงจำไว้ได้"},"ICON-0662":{"nm":"สมุดตราประทับท้องถิ่น","de":"หนึ่งหน้าหนึ่งตราประทับ ตรอกซอยที่เคยเดินผ่านกลับมามีชีวิตอีกครั้งด้วยหมึก รอยสีแดงที่สะสมจากการเที่ยวทั่วประเทศคือแผนที่รอยเท้าของเรา ยิ่งช่องว่างเหลือน้อยลงเท่าไร การเดินทางครั้งต่อไปก็ยิ่งกวักมือเรียกเงียบๆ มากขึ้นเท่านั้น"},"ICON-0663":{"nm":"ม้วนเชือกห่อของขวัญ","de":"ความอดทนอันยาวนานที่คลี่ออกมาไม่รู้จบเพื่อผูกกล่องของขวัญเพียงกล่องเดียว มันมอบปมที่เรียบร้อยให้กับมือที่รู้จักตัดให้พอดีเท่านั้น มันม้วนตัวเองรอคอยเงียบๆ จนถึงคราวถัดไป"},"ICON-0664":{"nm":"ถุงกันกระแทกของขวัญ","de":"มันโอบอุ้มหัวใจที่แตกหักง่ายไว้อย่างนุ่มนวล แม้ในช่องพัสดุที่สั่นสะเทือน มันก็ยังคงยืนหยัดอย่างนุ่มฟูว่า \"ไม่เป็นไร ฉันรองรับให้เอง\" เท่ากับปกป้องรอยยิ้มสดใสของคนที่จะเปิดกล่องไว้ล่วงหน้าด้วยเช่นกัน"},"ICON-0665":{"nm":"สติกเกอร์ปิดป้ายราคา","de":"คำโกหกเล็กๆ ที่อ่อนโยน แอบปิดราคาของของขวัญไว้ \"ไม่ต้องรู้ก็ได้ว่าเท่าไร แค่รับความรู้สึกไปก็พอ\" มันพูดเช่นนั้นพลางนั่งลงเบาๆ ทับป้ายราคา ไม่ใช่การปิดบัง แต่เป็นการทำให้ความรู้สึกนั้นเปล่งประกายมากขึ้นต่างหาก"},"ICON-0666":{"nm":"ชิปรถเข็นช้อปปิ้งจิ๋ว","de":"แม้เข็นรถเข็นจริงไม่ได้ แต่เพื่อนตัวจิ๋วที่แกว่งไกวอยู่ปลายนิ้วนี้ก็บรรจุความตื่นเต้นของการไปเดินห้างไว้ครบถ้วน แม้จะเล็ก แต่ความตื่นเต้นที่คิดว่า \"วันนี้จะซื้ออะไรดีนะ\" นั้นก็หนักแน่นไม่แพ้ของจริงเลย"},"ICON-0667":{"nm":"คลิปเรืองแสงติดรองเท้า","de":"ประกายวาบที่ปลายรองเท้าผ้าใบยามออกเดินเล่นตอนกลางคืน ส่งสัญญาณให้รถที่แล่นผ่านว่า \"มีคนอยู่ตรงนี้นะ\" แสงเล็กๆ ที่ออกมาต้อนรับเป็นสิ่งแรกในตรอกมืด ความปลอดภัยเริ่มต้นอย่างเงียบๆ จากปลายเท้าเสมอ"},"ICON-0668":{"nm":"ฝาครอบไฟฉายจิ๋ว","de":"สวมไว้ที่หัวไฟฉายแล้วแสงจะกระจายไปได้ไกลขึ้นและนุ่มนวลขึ้น นักมายากลตัวน้อยที่วาดกลุ่มดาวไว้บนเพดานเต็นท์มืดสนิท ในคืนที่ความมืดน่ากลัวไปสักหน่อย ไม่มีเพื่อนคนไหนดีไปกว่านี้อีกแล้ว"},"ICON-0669":{"nm":"ปุ่มแจ้งเตือนถึงบ้านปลอดภัย","de":"กดเบาๆ แล้วข้อความ \"ถึงบ้านอย่างปลอดภัยแล้วนะ\" จะบินไปหาครอบครัวที่อยู่ไกล แทนที่จะได้ยินเสียงประตูหน้าบ้านยามค่ำคืน ปุ่มเล็กๆ เพียงปุ่มเดียวก็ส่งข่าวคราวไปให้แทน ใครบางคนหลับไปพร้อมกับรอคอยสัญญาณนี้"},"ICON-0670":{"nm":"ม้วนสติกเกอร์สะท้อนแสง","de":"ตัดแปะไว้หนึ่งช่องบนกระเป๋า จักรยาน หรือร่ม ถนนยามค่ำคืนก็อันตรายน้อยลงทันที นักนอนหลับที่ตื่นสว่างขึ้นทันทีที่พบไฟหน้ารถ มันม้วนตัวรอคอยความมืดครั้งต่อไปที่จะมาถึง"},"ICON-0671":{"nm":"บัตรเรียกแท็กซี่ฉุกเฉิน","de":"สอดไว้ในช่องกระเป๋าสตางค์แล้วแม้ป้ายรถที่ว่างเปล่ายามค่ำคืนก็รู้สึกไม่หมดหนทางนัก เบอร์โทรหนึ่งเบอร์ ที่อยู่หนึ่งบรรทัด เขียนไว้เหมือนคำสัญญาว่า \"จะพากลับบ้านให้เอง\" ใครจะรู้ว่าคำว่าฉุกเฉินจะอุ่นใจได้ถึงเพียงนี้"},"ICON-0672":{"nm":"แถบแผนที่ทางกลางคืน","de":"พันรอบข้อมือแล้วเดินไปตามถนนที่ไฟถนนเบาบาง ตรอกไหนสว่าง ที่ไหนมืดสนิท มันแอบบอกทางลัดที่มีเพียงกลางคืนเท่านั้นที่รู้ แถบที่ผูกตัวเองไว้ข้างกาย ไม่ให้หลงทิศทางแม้ในความมืด"},"ICON-0673":{"nm":"กระเป๋ากริ่งฉุกเฉินอุ่นใจ","de":"ดึงในยามฉุกเฉินแล้วมันจะร้องดังจนทั้งตรอกต้องสะดุ้ง ยามปกติมันซ่อนตัวเงียบๆ อยู่ในกระเป๋า เก็บออมเสียงไว้เพื่อวินาทีเดียวนั้นเท่านั้น เสียงร้องที่ดังที่สุดที่ซ่อนอยู่ในกระเป๋าใบเล็กที่สุด"},"ICON-0674":{"nm":"พวงกุญแจไฟส่องหน้าประตู","de":"ลาก่อนแล้วค่ำคืนที่ต้องคลำหากุญแจที่ปลายทางเดินมืดมิด มันแขวนอยู่หน้าประตูต้อนรับมือที่กลับบ้านด้วยแสงกลมๆ \"เหนื่อยหน่อยนะ ถึงบ้านแล้ว\" พวงกุญแจทักทายเป็นคนแรกเสมอ"},"ICON-0675":{"nm":"โน้ตกลับที่พัก","de":"\"อย่าลืมร่ม ปิดไฟก่อนออกไปด้วยนะ\" คำเตือนสั้นๆ ที่ติดไว้บนตู้เย็นเฝ้าที่พักที่ว่างเปล่าไว้ โน้ตเล็กๆ สำหรับคนที่จะกลับมา ความอ่อนโยนที่บรรจุอยู่ในกระดาษแผ่นเดียวเดินตามไปจนถึงประตูหน้าอย่างเงียบๆ"},"ICON-0676":{"nm":"หวีจัดระเบียบสายเคเบิล","de":"หวีสายไฟที่พันกันยุ่งให้เรียบเนียนราวกับหวีผมเบาๆ ป่าสายเคเบิลที่รกรุงรังหลังโต๊ะกลายเป็นระเบียบเรียบร้อยด้วยการหวีไม่กี่ครั้ง ไม่ใช่แค่เส้นผมเท่านั้นที่พันกันยุ่งได้ หวีเล็กๆ นี้เตือนเราอย่างเงียบๆ"},"ICON-0677":{"nm":"ตัวแบ่งช่องที่เสียบปากกา","de":"ดินสออยู่ทางนี้ ปากกาเน้นข้อความอยู่ทางนั้น กรรไกรอยู่ช่องสุดท้าย มันแบ่งหมู่บ้านเล็กๆ ไว้ในกระบอกเดียว กำหนดที่ให้ปากกาแต่ละแท่ง เมื่อมีช่อง มือก็ไม่ต้องหลงหาอีกต่อไป จุดเริ่มต้นของระเบียบเล็กๆ บนโต๊ะทำงาน"},"ICON-0678":{"nm":"คลิปติดโน้ตข้างจอ","de":"ห้อยอยู่ข้างจอมอนิเตอร์ ยื่น \"สิ่งที่ต้องทำวันนี้\" มาไว้ตรงระดับสายตาพอดี บอร์ดแจ้งเตือนเล็กๆ ที่มองเห็นตรงหน้าเสมอ ไม่มีช่องว่างให้ลืม คลิปเพียงชิ้นเดียวคอยจับมือใจที่มักจะผัดวันประกันพรุ่งไว้อย่างแนบเนียน"},"ICON-0679":{"nm":"ถาดจัดระเบียบลิ้นชัก","de":"คลิปหนีบกระดาษและยางรัด เข็มหมุดและยางลบ มันมอบห้องของตัวเองให้กับเผ่าพันธุ์เล็กๆ ในลิ้นชักแต่ละกลุ่ม เมื่อมือเอื้อมไปถึงช่องที่แบ่งไว้เป็นระเบียบ เวลาที่ใช้ค้นหาก็ลดลง และมุมหนึ่งในใจก็เบาสบายขึ้น"},"ICON-0680":{"nm":"กระบอกแปรงปัดฝุ่น","de":"ฝุ่นเพียงเม็ดเดียวที่เกาะอยู่บนเลนส์ก็กลายเป็นรอยเปื้อนขนาดมหึมาในภาพถ่ายได้ ดังนั้นแปรงจึงเตรียมพร้อมอยู่ในกระบอกอย่างสะอาดหมดจดเสมอเพื่อรอคอย ปลายนิ้วที่ขยันขันแข็งซึ่งคอยรักษาความสะอาดที่ไม่มีใครสังเกตเห็น"},"ICON-0681":{"nm":"มุมแผ่นรองโต๊ะ","de":"ความนุ่มนวลขนาดเท่าฝ่ามือที่ปูไว้มุมหนึ่งของโต๊ะ ปากกาไม่กลิ้งตก และแทนกระจกที่เย็นเฉียบ ผิวสัมผัสที่อบอุ่นรองรับข้อมือไว้แทน พื้นผิวแสนอ่อนโยนที่มอบที่ของตัวเองให้ก่อนใคร เพื่อให้ลายมือในคืนอันยาวนานไม่สั่นไหว"},"ICON-0682":{"nm":"ที่จับสายเมาส์","de":"เมื่อสายพันกัน ใจก็เหมือนพันกันไปด้วยไม่รู้ทำไม สัมผัสที่จับเส้นสายที่กำลังจะยุ่งเหยิงไว้ล่วงหน้าแล้ววางให้เรียบร้อย แทบไม่มีใครสังเกตเห็น แต่มันค่อยๆ จัดระเบียบผิวสัมผัสของโต๊ะทำงานอย่างเงียบๆ ความประณีตเล็กๆ ที่ขยันขันแข็ง"},"ICON-0683":{"nm":"ฐานตั้งชาร์จ","de":"ยกอุปกรณ์ที่นอนราบขึ้นให้เอียงตั้งขึ้นมา แล้วหน้าจอก็ได้สบตากับเราในที่สุด แม้แต่การรอคอยระหว่างชาร์จก็กลายเป็นเวลาที่เรียบร้อยขึ้นมา การรองรับสิ่งใดสิ่งหนึ่งไว้ คือการดูแลท่าทางแม้กระทั่งของสิ่งที่กำลังพักผ่อนอยู่"},"ICON-0684":{"nm":"ป้ายถังขยะจิ๋ว","de":"แม้ถังเล็กที่สุดก็ยังมีชื่อของตัวเอง คำว่า \"ทิ้งที่นี่นะ\" เพียงบรรทัดเดียวเรียกระเบียบอันเงียบสงบมาสู่โต๊ะที่รกรุงรัง ท้ายที่สุดแล้วป้ายคือคำทักทายเล็กๆ ที่บอกสิ่งของว่าประโยชน์ของเธออยู่ตรงนี้นะ"},"ICON-0685":{"nm":"หมุดบอร์ดกั้นห้อง","de":"มันกดกระดาษแผ่นหนึ่งไว้แน่นบนบอร์ด เป็นการฝากความรู้สึกที่ไม่อยากลืมไว้กับผนังชั่วคราว ความตั้งใจของวันนี้ที่ห้อยอยู่ปลายหมุดแกว่งไหวเบาๆ ตามสายลม คอยจับใจเราไว้ทุกครั้งที่เดินผ่าน"},"ICON-0686":{"nm":"ชิปกรอบป้ายชื่อ","de":"กรอบสี่เหลี่ยมเพียงกรอบเดียวเปลี่ยนตัวหนังสือธรรมดาให้กลายเป็นประโยคที่ชัดเจนหนึ่งประโยค ชิปที่ห่อหุ้มศักดิ์ศรีอันเรียบร้อยให้กับโน้ตที่กระจัดกระจายได้ง่าย ไม่ใช่การกักขัง แต่เป็นการโอบกอดคำสำคัญไว้ไม่ให้สูญหาย"},"ICON-0687":{"nm":"ที่จับลิ้นชักใส","de":"ติดที่จับไว้กับลิ้นชักที่มองทะลุได้ แล้วเราจะเห็นว่าข้างในมีอะไรโดยไม่เปิดออกอย่างไม่ระมัดระวัง ระยะห่างขนาดหนึ่งคืบที่มองเห็นได้แต่ไม่เข้าใกล้ แม้ความโปร่งใสก็ยังต้องการมารยาท ลิ้นชักกระซิบบอกเช่นนั้น"},"ICON-0688":{"nm":"คลิปล็อกฝา","de":"ปล่อยทิ้งไว้แบบเปิดอยู่ กลิ่นและสีสันก็จะแอบเลือนหายไปทีละน้อย ด้วยคีมหนีบเล็กๆ ที่กัดฝาให้ปิดสนิท สีสันของเมื่อวานก็ยังคงอยู่ครบถ้วนจนถึงพรุ่งนี้ การล็อกไว้ที่จริงแล้วก็คือการปกป้องสิ่งที่เรารักไว้นั่นเอง"},"ICON-0689":{"nm":"ที่เก็บสารกันชื้น","de":"ผู้พิทักษ์เล็กๆ ที่เกลียดความชื้นและเฝ้าประจำการอยู่อย่างเงียบๆ การเก็บอากาศแห้งไว้ใกล้ตัวคือเงื่อนไขแรกของการเก็บรักษาในระยะยาว ที่เก็บอันเรียบร้อยนี้กระซิบบอกอย่างเงียบๆ ความแห้งสนิทถูกรักษาไว้ด้วยวิธีนี้เอง"},"ICON-0690":{"nm":"ป้ายตะกร้าจัดระเบียบ","de":"ป้ายชื่อเล็กๆ ติดไว้ทุกตะกร้า เมื่อกำหนดไว้ว่าช่องไหนเก็บอะไร เวลาที่เคยใช้ค้นหาก็กลายเป็นเวลาพักผ่อนได้ทันที การจัดระเบียบคือโน้ตแสนอ่อนโยนที่ส่งมอบให้ตัวเองในอนาคตไว้ล่วงหน้า"},"ICON-0691":{"nm":"แผ่นกั้นมินิ","de":"ฉากกั้นเล็กๆ ที่สร้างห้องเล็กๆ อบอุ่นขึ้นบนโต๊ะได้ในพริบตา ด้วยแผ่นเดียวนี้ มุมเงียบสงบที่หันหลังให้โลกภายนอกเล็กน้อยก็ปรากฏขึ้น ที่แสนสบายเพียงหนึ่งเดียวที่เหมาะสำหรับให้สมาธิเข้ามาอาศัยอยู่"},"ICON-0692":{"nm":"ขาตั้งซองเก็บของ","de":"ฐานที่ค่อยๆ พยุงหลังซองที่คอยล้มระเนระนาดให้ยืนตั้งขึ้น แค่เรียงกันตั้งอยู่เป็นแถวเท่านั้น การเลือกหยิบใช้ก็ง่ายขึ้นมาก การตั้งของให้ตรงคือการเอาใจใส่มือที่จะมาถึงในครั้งถัดไปไว้ล่วงหน้า"},"ICON-0693":{"nm":"ชิปทำเครื่องหมายช่องว่าง","de":"ชิปที่ตั้งใจทำเครื่องหมายบอกว่าตรงนี้ว่างอยู่ การเหลือที่ไว้ให้ต้องเติมเต็มก็ถือเป็นแผนการอย่างหนึ่งเช่นกัน ช่องว่างไม่ใช่ความขี้เกียจ แต่เป็นพื้นที่ว่างขนาดหนึ่งคืบที่ตั้งใจเว้นไว้อย่างสุภาพ เพื่อรอสิ่งที่กำลังจะมาถึงในไม่ช้า"},"ICON-0694":{"nm":"ฝาครอบแปรงสีฟัน","de":"เราใส่ใจมากขึ้นกับขนแปรงที่สัมผัสปาก หมวกเล็กๆ ใบหนึ่งที่กันฝุ่นแม้เพียงเม็ดเดียวออกไป การดูแลความสะอาดที่มองไม่เห็นนั้นแหละ คือความใส่ใจเล็กๆ ที่เปิดเช้าวันใหม่ให้สดชื่นทุกวัน"},"ICON-0695":{"nm":"ตะแกรงรองสบู่","de":"ตะแกรงที่ยกสบู่ให้ลอยเบาๆ ไม่ให้แช่น้ำจนเปื่อยยุ่ย หลักการที่ว่าปล่อยให้น้ำไหลออกไปจะทำให้อยู่ได้นานขึ้นนั้น มันพิสูจน์ให้เห็นอย่างเงียบๆ ทุกวันจากมุมที่ต่ำและเล็กที่สุดของห้องน้ำ"},"ICON-0696":{"nm":"คลิปหัวปั๊มแชมพู","de":"มันจับหัวปั๊มไว้เบาๆ ให้กดครั้งเดียวแล้วไหลออกมาพอดีปริมาณที่เหมาะสมเท่านั้น นิสัยมือที่ใช้อย่างประหยัดคือรากฐานของการดูแลบ้านที่ยั่งยืน คลิปเล็กๆ เพียงชิ้นเดียวคอยควบคุมความสิ้นเปลืองไว้อย่างอ่อนโยน"},"ICON-0697":{"nm":"ฝาแขวนมีดโกน","de":"สิ่งที่มีคมย่อมมีบ้านเล็กๆ ของตัวเองแยกต่างหาก สอดมีดโกนเข้าไปในฝาแล้วแขวนไว้ ทั้งความชื้นและอันตรายก็ไหลลงไปพร้อมกัน วิธีจัดการความคมอย่างระมัดระวังนั้น ก็คือวิธีทะนุถนอมตัวเองเช่นกัน"},"ICON-0698":{"nm":"ห่วงผ้าขนหนูอาบน้ำ","de":"ผ้าขนหนูที่ยืดยาวประกอบกันเป็นห่วง พาไปถึงหลังส่วนที่มือเอื้อมไม่ถึง ตามลายเส้นที่ฟองสบู่ไหลลื่นไป ความอบอุ่นอ่อนโยนของการถูหลังตัวเองได้แม้อยู่คนเดียว แผ่ซ่านอบอุ่นไปทั่วห้องน้ำ"},"ICON-0699":{"nm":"ถุงตะแกรงกรองท่อระบายน้ำ","de":"ตะแกรงเล็กๆ ที่ปล่อยให้น้ำไหลผ่านแต่จับเศษต่างๆ ไว้ ในที่ที่มองไม่เห็น มันคอยป้องกันการอุดตันอย่างเงียบๆ สิ่งที่ทำงานอยู่ในตำแหน่งต่ำที่สุดต่างหากที่รักษาการไหลเวียนของบ้านไว้ ท่อระบายน้ำบอกเราเช่นนั้นโดยไม่ต้องพูดสักคำ"},"ICON-0700":{"nm":"บอร์ดตะขอดูดติดผนัง","de":"มันสร้างที่ใหม่บนผนังได้โดยไม่ต้องตอกตะปูสักตัว กดติดแล้วดึงออก ก็ไม่เหลือแม้แต่ร่องรอย วิธีการอยู่ชั่วคราวโดยไม่ทิ้งรอยไว้—ตัวดูดสูญญากาศเข้าใจมารยาทแสนเบาบางนี้เป็นอย่างดี"},"ICON-0701":{"nm":"ป้ายรองเท้าแตะห้องน้ำ","de":"รองเท้าแตะคู่หนึ่งวางเรียงอย่างเป็นระเบียบตรงหน้าธรณีประตู ความใส่ใจของบ้านที่ต้องถอดรองเท้าก่อนเข้านั้นทอดยาวมาจนถึงหน้าประตูห้องน้ำอย่างอ่อนโยน ป้ายชื่อเล็ก ๆ เงียบ ๆ กำหนดที่ทางให้กับการต้อนรับเล็ก ๆ ที่ช่วยอุ่นปลายเท้าที่เย็นเยียบนี้"},"ICON-0702":{"nm":"แก้วบ้วนปากใบจิ๋ว","de":"แก้วกลมใบเล็กที่จุน้ำได้พอสำหรับการแปรงฟันหนึ่งครั้ง ในช่วงเวลาสั้น ๆ ของการบ้วนปาก มันเงียบ ๆ รองรับทั้งจุดเริ่มต้นและจุดสิ้นสุดของวัน ไม่หรูหรา แต่อยู่เคียงข้างทุกวัน—ความเรียบง่ายคือการดูแลบ้านที่ยืนยาวที่สุด"},"ICON-0703":{"nm":"ปลอกไม้ปัดฝุ่น","de":"ปลอกที่สวมคลุมขนแปรงที่ปัดฝุ่นออกอย่างแผ่วเบาราวกับลูบไล้ เหมือนนกที่พับปีกลงอย่างอ่อนโยนยามไม่ได้บิน เครื่องมือที่รู้จักที่พักของตัวเองจึงอยู่เคียงข้างเราไปได้นาน"},"ICON-0704":{"nm":"ไส้เทปกาวม้วนขนสัตว์","de":"ลอกออกหนึ่งชั้น พื้นผิวใหม่สะอาดสะอ้านก็ผุดขึ้นมาด้านล่าง ชั้นเหนียวที่เก็บขนและเส้นผมซ้อนกันเป็นชั้น ๆ ในไส้ม้วนกลมที่เติมเต็มใหม่ได้เมื่อใช้หมด คุณธรรมแห่งความขยันหมั่นเพียรซ้ำแล้วซ้ำเล่าถูกม้วนเก็บไว้ในนั้น"},"ICON-0705":{"nm":"คีมหนีบผ้าถูพื้น","de":"คีมที่คาบผ้าถูพื้นไว้แน่นแทนมือของเรา รักษาระยะห่างหนึ่งฝ่ามือระหว่างพื้นเย็นเยียบกับปลายนิ้ว ด้ามจับเพียงชิ้นเดียวที่รับงานสกปรกแทนเรา ทำให้การทำความสะอาดอันแสนเหนื่อยเบาสบายขึ้นมาก"},"ICON-0706":{"nm":"ฝาครอบแปรงซอกมุม","de":"หมวกเล็ก ๆ ที่ปกป้องปลายอันบอบบางของแปรงเรียวที่มุ่งลอดเข้าไปในซอกแคบ หัวใจดวงหนึ่งที่เอาใจใส่แม้กระทั่งมุมที่มือเอื้อมไม่ถึง ผู้ที่ทำความสะอาดพื้นที่ที่มองไม่เห็น คือผู้ที่ขยายอ้อมกอดของบ้านให้กว้างขึ้นอีกหนึ่งฝ่ามือ"},"ICON-0707":{"nm":"ห่วงป้ายขวดสเปรย์","de":"ป้ายชื่อเล็ก ๆ เกาะอยู่แผ่วเบาบนบ่าของขวดสเปรย์ ไม่ว่าข้างในจะเป็นน้ำใสหรือน้ำยาทำความสะอาด มันบอกให้เรารู้อย่างชัดเจนในบรรทัดเดียว ป้ายที่ลบความสับสนไว้ล่วงหน้าเช่นนี้ คือนิสัยที่ติดตัวแม่บ้านมือไวมานาน"},"ICON-0708":{"nm":"แถบรัดไส้ทิชชู่","de":"แถบที่สอดม้วนใหม่เข้าไปแทนที่ม้วนที่ใช้หมดแล้วและรัดให้แน่นหนา สัมผัสที่เรียบง่ายที่สุดที่เชื่อมสิ่งที่ขาดตอนให้กลับมาต่อกัน หัวใจของใครสักคนที่คอยเติมให้ก่อนที่ของจะหมด ถูกพันไว้เป็นวงกลมในห่วงเล็ก ๆ นี้"},"ICON-0709":{"nm":"ตะขอแขวนถุงมือทำความสะอาด","de":"ตะขอที่แขวนถุงมือเปียกให้แห้งทันทีหลังจากงานเปียก ๆ เสร็จสิ้น มันมอบที่พักผ่อนชั่วครู่ให้กับมือที่ตรากตรำ ระหว่างที่ความชื้นค่อย ๆ แห้งไป คือช่วงเวลาพักหายใจเงียบ ๆ เพื่อเตรียมพร้อมสำหรับงานต่อไป"},"ICON-0710":{"nm":"หมุดแขวนไม้กวาด","de":"แขวนไม้กวาดกลับหัวไว้ ขนแปรงก็จะไม่งอ คงความตรงอยู่เสมอ ท่วงท่าที่ห้อยตัวตรงรอคอยลานหน้าบ้านครั้งต่อไป จุดเล็ก ๆ แต่มั่นคงที่ช่วยให้มันคงรูปทรงไว้ได้แม้หลังเสร็จสิ้นภารกิจ"},"ICON-0711":{"nm":"คลิปหนีบถุงขยะ","de":"มันคาบปากถุงไว้แน่น ปิดผนึกอย่างมิดชิดไม่ให้มีอะไรรั่วไหลออกมา สัมผัสเพียงครั้งเดียวที่รวบปลายให้แน่นหนาทำให้การเก็บกวาดเรียบร้อยขึ้นมาก การจบสิ่งใดสิ่งหนึ่งอย่างสมบูรณ์ แท้จริงแล้วเริ่มต้นจากการปิดให้ดี"},"ICON-0712":{"nm":"กระปุกไม้หนีบผ้า","de":"กระปุกที่เป็นบ้านให้ไม้หนีบผ้าที่มักหายง่ายเมื่อกระจัดกระจายได้อยู่รวมกัน มันมอบบ้านร่วมกันให้กับสิ่งเล็ก ๆ เหล่านั้น เมื่อรวบรวมเหล่าทหารตัวจิ๋วปลายนิ้วไว้ในที่เดียว เราก็จะหาเจอได้ในพริบตาเมื่อต้องการ"},"ICON-0713":{"nm":"ห่วงจับคู่ถุงเท้า","de":"ถุงเท้าที่พลัดหลงมักหายลับไปไหนสักแห่งเสมอ หากผูกคู่ไว้ด้วยห่วงก่อนซัก แม้แห้งฟูนุ่มแล้วทั้งคู่ก็จะไม่พลัดพรากจากกัน การจัดหมวดหมู่คือคำสัญญาเล็ก ๆ ที่กันการหายไปไว้ล่วงหน้า"},"ICON-0714":{"nm":"ถุงลูกบอลซักผ้า","de":"มันกลิ้งไปมาอยู่ในเครื่องซักผ้า เคาะปลุกคราบสกปรกที่ซึมอยู่ในเนื้อผ้าให้ตื่นขึ้น จังหวะที่ลูบไล้ผ้าด้วยร่างกายกลม ๆ ท่ามกลางกระแสน้ำที่ไหลเชี่ยว มันบรรจุสัญชาตญาณเก่าแก่ของการซักผ้า—การเคาะ—ไว้ในถุงและกลิ้งไปพร้อมกัน"},"ICON-0715":{"nm":"ฝาตวงน้ำยาซักขนสัตว์","de":"เสื้อผ้าที่บอบบางต้องการปริมาณที่ละเอียดอ่อนเท่ากัน ฝาตวงที่ตวงน้ำยาซักขนสัตว์ให้พอดีเพียงหนึ่งฝา ในขีดเล็ก ๆ เพียงขีดเดียวนั้นบรรจุสัมผัสอันระมัดระวังในการดูแลผ้าขนสัตว์ไว้ การลดความเกินพอดีก็คือความใส่ใจเช่นกัน"},"ICON-0716":{"nm":"แผ่นปะซ่อมผ้า","de":"แผ่นปะเล็ก ๆ ที่แปะทับลงบนรอยขาดอย่างแผ่วเบา หัวใจปลายนิ้วที่ทะนุถนอมจุดที่สึกหรอแทนที่จะโยนทิ้งไปอย่างไม่ใยดี ทุกรอยปะชุนล้วนเก็บลวดลายของกาลเวลาที่เคียงข้างเสื้อผ้าชิ้นนั้นไว้อย่างงดงาม"},"ICON-0717":{"nm":"หมุดยึดราวตากผ้า","de":"หมุดที่จับราวตากผ้าไว้อย่างเงียบ ๆ ไม่ให้ผ้าถูกลมพัดปลิวหายไป แม้ในวันที่ผ้าซักพลิ้วไหวอยู่ใต้แสงแดด มันก็ช่วยให้ทุกอย่างอยู่กับที่ท่ามกลางการโยกไหว หน้าที่ของตุ้มถ่วงเล็ก ๆ แต่ไว้ใจได้เพียงหนึ่งเดียว"},"ICON-0718":{"nm":"ป้ายถุงตาข่ายซักชุดชั้นใน","de":"ชุดชั้นในบอบบางจะถูกซักแยกไว้ในตาข่าย ตาข่ายที่โอบอุ้มสิ่งนุ่มนวลไว้อย่างมิดชิดจากกระแสน้ำที่ไหลเชี่ยว ถุงเล็ก ๆ ที่มีป้ายติดอยู่บอกให้เรารู้ว่าการปกป้องสิ่งบอบบางอย่างระมัดระวังก็คืองานบ้านเช่นกัน"},"ICON-0719":{"nm":"ตะขอแขวนช้อนตักผงซักฟอก","de":"แขวนช้อนตักผงซักฟอกไว้บนผนังอย่างเป็นระเบียบ ไม่ต้องยุ่งยากทำมือเปียกจากการทำช้อนหล่นลงในถัง นิสัยเรียบร้อยที่วางเครื่องมือชิ้นเดิมไว้ที่เดิมเสมอนั้น ถูกบรรจุไว้อย่างมั่นคงในตะขอเล็ก ๆ นี้"},"ICON-0720":{"nm":"ตัวล็อกปลายราวตากผ้า","de":"มันคาบปลายราวตากผ้าไว้แน่น แม้แบกน้ำหนักผ้าซักหนัก ๆ ก็ไม่คลายหลุดออกมา ปมสุดท้ายที่ยืนหยัดจนถึงที่สุด ไม่ให้เส้นที่ตึงเปี๊ยะหย่อนยาน การจบงานอย่างเรียบร้อยแขวนอยู่กับสิ่งนี้"},"ICON-0721":{"nm":"ป้ายปลอกหมอน","de":"จุดที่แก้มสัมผัสเป็นสิ่งแรกทุกค่ำคืน มีป้ายขนาดเท่าเล็บมือเย็บซ่อนอยู่ด้านใน ใครจะอ่านตัวอักษรจิ๋วที่เขียนอุณหภูมิการซักนั้นครบทุกคำ แต่ถึงอย่างนั้น มันก็คือคำแนะนำที่อยู่ใกล้ที่สุด คอยเฝ้าอยู่ข้างใบหน้าที่หลับใหล"},"ICON-0722":{"nm":"คีมหนีบผ้าห่ม","de":"คืนที่เปิดหน้าต่างไว้ แม้ลมจะพัดเข้ามา ผ้าห่มก็ไม่หนีหายไปไหน เพราะคีมที่หุบปากแน่นสนิทกำลังกัดมุมผ้าไว้ มือที่ไร้เสียงคอยจับปลายผ้าแทนคนที่หลับใหล"},"ICON-0723":{"nm":"แผ่นบังไฟโคมนอน","de":"\"ถ้าแสงส่องถึงตา การนอนหลับจะหนีไป\" ด้วยแผ่นบังหนึ่งแผ่นที่ใครสักคนตั้งไว้เงียบ ๆ แสงจึงถอยหลังกลับ เหลือเพียงแสงจาง ๆ รดชุ่มปลายเตียง ฉากกั้นเล็ก ๆ ที่ยืมความมืดมาให้หนึ่งฝ่ามือ"},"ICON-0724":{"nm":"กระเป๋าซอกข้างเตียง","de":"ลองนึกถึงช่องว่างระหว่างที่นอนกับผนังที่มือของเราไม่เคยเอื้อมถึง รีโมตที่กลิ้งหาย แว่นตาที่หล่นหาย ตอนนี้มารวมกันอยู่ที่นี่ กระเป๋าที่เตียงแอบกางออกมารองรับสิ่งที่เกือบจะสูญหายไป"},"ICON-0725":{"nm":"ถาดเก็บแว่นตา","de":"ถอดเลนส์ออก โลกก็เบลอนุ่มนวล และจานตื้น ๆ ใบหนึ่งรองรับความไร้เกราะป้องกันชั่วขณะนั้นไว้ พอตกเช้า แม้ไม่ต้องคลำหา แว่นตาก็ยังคงรอคอยอยู่ที่เดิมเสมอ"},"ICON-0726":{"nm":"ฐานวางนาฬิกาปลุก","de":"ตีหกยามเช้า บนฐานที่มั่นคงซึ่งเสียงที่คนเกลียดที่สุดดังขึ้น มันรองรับนาฬิกาไว้อย่างไม่สั่นไหว และในที่สุดก็เปิดวันใหม่ให้ใครสักคน มันแบกรับคำสัญญาอันห้วนแข็งของการตื่นนอนไว้อย่างเงียบงัน"},"ICON-0727":{"nm":"ที่ยึดสายชาร์จข้างเตียง","de":"สายชาร์จที่เคยไหลลื่นลงมาจากหัวเตียงไม่ตกลงพื้นอีกต่อไป เพราะที่ยึดเล็ก ๆ จับปลายสายไว้อย่างแผ่วเบา ในระยะที่เอื้อมมือถึง สัมผัสที่จัดระเบียบเส้นทางของค่ำคืนให้เรียบร้อย"},"ICON-0728":{"nm":"แถบรัดชุดนอน","de":"แถบที่พันรอบชุดนอนที่พับเรียบร้อยไว้หนึ่งรอบแล้วผูกไว้ แม้ความนุ่มนิ่มที่ยับง่ายก็ยังต้องการความเรียบร้อย เพื่อฉันของคืนพรุ่งนี้ ฉันของวันนี้จึงม้วนมันไว้อย่างเป็นระเบียบ นี่คือการเตรียมพร้อมเล็ก ๆ น้อย ๆ"},"ICON-0729":{"nm":"ที่ตั้งการ์ดกลิ่นหอม","de":"ตั้งการ์ดกลิ่นหอมหนึ่งแผ่นเอียง ๆ ไว้ แล้วเหมือนพลิกหน้าหนังสือ เราก็พลิกฤดูกาลด้วยปลายจมูก จากลาเวนเดอร์สู่ซิตรัส—มันกลายเป็นสมุดบันทึกประจำวันที่เขียนด้วยกลิ่นหอม"},"ICON-0730":{"nm":"แผ่นรองจานวางกุญแจ","de":"มุมหนึ่งข้างประตูทางเข้าที่กุญแจเคยตกกระทบดังกรุ๊งกริ๊ง จานที่ปูด้วยแผ่นรองนุ่ม ๆ กลืนเสียงแหลมนั้นไว้ แผ่นรองเล็ก ๆ เงียบ ๆ รองรับการเคลื่อนไหวแรกของคนที่กลับมาถึงบ้าน"},"ICON-0731":{"nm":"ฝาครอบรองน้ำร่ม","de":"หยดน้ำฝนไหลริน ๆ จากปลายร่มที่ถือเข้ามา ฝาใบหนึ่งรองหยดน้ำนั้นไว้อย่างเรียบร้อย จึงเท่ากับว่ามีใครสักคนคาดการณ์และป้องกันแอ่งน้ำเล็ก ๆ ที่จะแผ่ขยายบนพื้นไม้ไว้ล่วงหน้าแล้ว"},"ICON-0732":{"nm":"ชิปแขวนแมสก์","de":"ชิปขนาดเท่าเล็บมือติดอยู่บนผนังข้างประตูทางเข้า เหมือนพิธีกรรมสุดท้ายก่อนออกจากบ้าน แมสก์ถูกแขวนไว้ที่นี่ อุปกรณ์ความจำเล็ก ๆ ที่รักษาระดับสายตาไว้หน้าประตู เพื่อไม่ให้ลืมสิ่งที่ต้องพกไป"},"ICON-0733":{"nm":"ปลอกใบมีดตัดพัสดุ","de":"ปลอกป้องกันที่สวมไว้บนใบมีดที่ใช้กรีดเปิดกล่องพัสดุ มันปกปิดอันตรายจากบาดแผลที่ซ่อนอยู่หลังความตื่นเต้นของการแกะกล่องไว้อย่างเงียบ ๆ ความใส่ใจที่มองไม่เห็นซึ่งเปิดปลายทางของการรอคอยอย่างปลอดภัย"},"ICON-0734":{"nm":"ที่วางแปรงขัดรองเท้า","de":"จุดที่แปรงขัดรองเท้าซึ่งใช้งานเสร็จแล้ววางอยู่ทั้งที่ยังเปียกอยู่ แม้อุ้มความชื้นไว้ พื้นก็ยังคงแห้งสนิท แม้แต่เครื่องมือที่สร้างความสะอาดก็ต้องการที่พัก ที่วางเล็ก ๆ บอกเราเช่นนั้น"},"ICON-0735":{"nm":"กระดานโน้ตผู้มาเยือน","de":"\"แวะมาแป๊บนึงแล้วไปนะ\" ข้อความสั้น ๆ บรรทัดหนึ่งที่ทิ้งไว้บนกระดานโน้ตหน้าประตู ลานเล็ก ๆ ที่ผู้คนซึ่งพลาดกันไปมาได้แบ่งปันข้ามช่วงเวลากัน บนกระดาษช่องเดียว คำทักทาย คำขอร้อง และหัวใจดวงหนึ่งซ้อนทับกันอยู่"},"ICON-0736":{"nm":"ม้วนกันลมโคนประตู","de":"ลมโกรกที่เคยแทรกซึมเข้ามาทางช่องว่างขนาดเท่านิ้วมือใต้ประตู ตัวกันลมที่ม้วนไว้จะปิดกั้นทางผ่านนั้นอย่างเงียบ ๆ มันช่วยกักไอความอบอุ่นที่เคยรั่วไหลออกไปโดยไม่มีใครเห็น ให้อยู่ในห้องเพิ่มอีกหนึ่งชั้น"},"ICON-0737":{"nm":"จี้ดันประตู","de":"จี้เล็ก ๆ ที่ค้ำโคนประตูที่เปิดกว้างไว้ไม่ให้ปิดกลับมาอีก มันรักษาน้ำหนักไว้อย่างมั่นคงเพื่อสายลมและเสียงฝีเท้าที่ผ่านเข้าออก ความดื้อรั้นอันอ่อนโยนที่ทำให้ประตูเปิดค้างไว้ได้เสมอ"},"ICON-0738":{"nm":"ฝาครอบสวิตช์ไฟหน้าประตู","de":"สวิตช์หน้าประตูที่เคยคลำหาในค่ำคืนดึกดื่น ฝาครอบเรืองแสงบอกตำแหน่งของมันอย่างนุ่มนวลในความมืด เพื่อไม่ให้มือหลงทาง มันคือผู้นำทางเล็ก ๆ ที่ส่องแสงก่อนที่ไฟจะติดเสียอีก"},"ICON-0739":{"nm":"แผ่นรองแก้ว","de":"วินาทีที่แก้วซึ่งวางบนโต๊ะอาหารเริ่มลื่นไถล แผ่นรองใบหนึ่งจับเท้าของมันไว้อย่างแผ่วเบา ที่รองที่รักษาตำแหน่งของตัวเองอย่างสงบนิ่ง ไม่ทิ้งรอยแม้แต่หยดเดียวแม้หยดน้ำจะเกาะจับ"},"ICON-0740":{"nm":"คลิปน้ำหอมติดรถ","de":"คลิปน้ำหอมเล็ก ๆ ที่แขวนไว้ในรถ ล่องลอยไปตามลมจากช่องแอร์ กลิ่นหอมอ่อน ๆ ค่อย ๆ เติมเต็มพื้นที่แคบ ๆ นั้น แม้ความน่าเบื่อของการรอไฟแดงก็ยังถูกทำให้อบอุ่นด้วยกลิ่นหอม—ความปลอบโยนอันอ่อนโยนของเบาะคนขับ"},"ICON-0741":{"nm":"ปลอกหุ้มเข็มขัดนิรภัย","de":"ปลอกนุ่มที่สวมทับบนเข็มขัดที่พาดผ่านบ่า ความสากที่เคยสัมผัสต้นคอค่อย ๆ หายไป แม้แต่สายที่มีไว้เพื่อความปลอดภัยก็เพิ่มความอ่อนโยนเข้าไปได้ ผ้าผืนเล็กเท่าฝ่ามือนี้บอกเช่นนั้น"},"ICON-0742":{"nm":"แผ่นบังหมายเลขที่จอดรถ","de":"แผ่นที่บดบังป้ายหมายเลขบอกช่องจอดของเราในลานจอดรถใต้ดินไว้อย่างเงียบ ๆ ก่อนถ่ายรูป ทุกคนล้วนมีข้อมูลที่ไม่อยากทิ้งร่องรอยไว้ ชั้นหนึ่งที่ลบออกอย่างระมัดระวังจากฉากหนึ่งของชีวิตประจำวัน"},"ICON-0743":{"nm":"ฝาครอบกระดิ่งจักรยาน","de":"กริ๊งกริ๊ง คำทักทายอันแจ่มใสที่จักรยานส่งให้ตรงหัวมุมตรอก ฝาที่ครอบไว้บนกระดิ่งปกป้องเสียงนั้นไว้แม้ยามฝนตก ด้วยเสียงกระดิ่งเบา ๆ เพียงครั้งเดียว ผู้คนก็ยิ้มและก้าวหลบให้ทาง"},"ICON-0744":{"nm":"ห่วงหุ้มมือจับแฮนด์","de":"ห่วงที่ห่อหุ้มสัมผัสของแฮนด์ที่แนบกับฝ่ามือไว้อย่างนุ่มนวล แม้กำแน่นขี่ไปนานมือก็ไม่ชา ยิ่งเส้นทางไกลเท่าไร ความสบายของจุดที่จับไว้ก็ยิ่งย่นระยะทางนั้นให้สั้นลง"},"ICON-0745":{"nm":"สติกเกอร์ป้ายชื่อหมวกกันน็อค","de":"สติกเกอร์ชื่อที่ติดไว้ด้านในหมวกกันน็อค ท่ามกลางหมวกนิรภัยที่หน้าตาเหมือนกันหมด มันร้องบอกเบา ๆ ว่า \"นี่ของฉัน\" เครื่องหมายส่วนตัวที่สุดที่จารึกไว้บนความแข็งแกร่งที่ปกป้องศีรษะ"},"ICON-0746":{"nm":"ฝาครอบสะท้อนแสงล้อ","de":"ฝาที่เพิ่งเริ่มทำงานของตัวเองเมื่อพระอาทิตย์ตกดิน มันรับแสงที่ผ่านมาแล้วสะท้อนล้อให้เห็นชัดเจน ในความมืด มันส่งสัญญาณเล็ก ๆ ด้วยแสงว่า \"มีคนอยู่ตรงนี้\""},"ICON-0747":{"nm":"ซองหุ้มกุญแจรถ","de":"กุญแจรถที่เคยเสียดสีจนเป็นรอยขีดข่วนกับกุญแจอื่นในกระเป๋า ซองนุ่มที่โอบหุ้มผิวนั้นไว้อย่างมิดชิด สิ่งที่ยิ่งใช้ทุกวันก็ยิ่งอยากให้ปราศจากรอยขีดข่วนและอยู่ทนนาน ความปรารถนานั้นถูกบรรจุอยู่ตรงนี้"},"ICON-0748":{"nm":"หมุดชั้นวางแบบดูดติด","de":"หมุดชั้นวางแบบดูดติดผนังได้โดยไม่ต้องตอกตะปูสักตัวเดียว แม้ผนังที่ไม่อยากให้มีรอยก็ยังได้ช่องเก็บของเพิ่มขึ้นหนึ่งช่อง ฝีมือที่ไร้ร่องรอย ในการแขวนข้าวของบ้านไว้ในห้องที่พักอาศัยเพียงชั่วคราว"},"ICON-0749":{"nm":"แผ่นตะขอไม่เจาะผนัง","de":"แค่คิดว่าจะแขวนอะไรได้โดยไม่ต้องเจาะผนังก็ดีแล้ว แผ่นตะขอไม่เจาะผนังรับภาระของหนักเบา ๆ ไว้อย่างเงียบ ๆ ความปรารถนาที่ไม่อยากทำร้ายพื้นที่ที่ยืมมา ถูกบรรจุไว้อย่างงดงามในตะขอเล็ก ๆ เพียงตัวเดียว"},"ICON-0750":{"nm":"แท่งแม่เหล็กจัดระเบียบ","de":"เสียงโลหะดังป๊อกติดเข้าที่ เมื่อรวบรวมเครื่องมือชิ้นเล็ก ๆ ที่กระจัดกระจายอยู่ทั่วด้วยแม่เหล็กเพียงปาดเดียว โต๊ะทำงานที่วุ่นวายก็เรียงเป็นแถวเดียวอย่างเป็นระเบียบ ความพอใจเล็ก ๆ ตามมาด้วย"},"ICON-0751":{"nm":"แท่งเก็บของช่องแคบ","de":"ลองนึกถึงช่องแคบที่ถูกทอดทิ้งระหว่างตู้เย็นกับผนัง แท่งเรียวเล็กเติมเต็มช่องนั้นด้วยประโยชน์ใช้สอย ความคิดประหยัดที่ดึงพื้นที่เก็บของออกมาจากพื้นที่ที่เคยคิดว่าไร้ค่า"},"ICON-0752":{"nm":"แผ่นแปะกาวสองหน้า","de":"แผ่นแปะกาวที่เมื่อติดแล้วรองรับของหนักได้อย่างสบาย ๆ ลอกออกก็แปลกที่ไม่เหลือรอยแม้แต่นิดเดียว พลังอันเงียบสงบและดื้อรั้นที่แบกน้ำหนักไว้ในที่ที่มองไม่เห็น"},"ICON-0753":{"nm":"ตะขอแขวนบนขอบประตู","de":"ฝาตะขอที่แค่เกี่ยวไว้เบา ๆ บนขอบประตูก็ใช้ได้แล้ว กระเป๋าและผ้าเช็ดตัวห้อยอยู่ในระดับที่มือเอื้อมถึง ตะขอที่เกิดขึ้นโดยไม่ต้องตอกตะปูแม้แต่ตัวเดียว เพิ่มพื้นที่หายใจอีกหนึ่งช่องให้ห้องแคบ ๆ"},"ICON-0754":{"nm":"คลิปติดผนังจัดสายไฟ","de":"คลิปที่รวบสายไฟที่ห้อยระโยงระยางตามผนังให้เป็นเส้นเดียวเรียบร้อย ปมสายพันกันหลังโต๊ะคลี่ออกเป็นเส้นตรงสะอาดตา ความเป็นระเบียบที่มองไม่เห็นทำให้อากาศในห้องเบาสบายขึ้น"},"ICON-0755":{"nm":"แผ่นรองฐานโคมไฟตั้งโต๊ะ","de":"แผ่นรองที่ปูไว้แผ่วเบาใต้ฐานโคมไฟตั้งโต๊ะ ไม่ทิ้งรอยขีดข่วนบนโต๊ะ และสงบแม้แต่การสั่นสะเทือนที่แผ่วเบาที่สุด แม้แต่การตั้งแสงสว่างก็ต้องเริ่มจากพื้นที่ไม่สั่นไหวเสียก่อน"},"ICON-0756":{"nm":"แผ่นกันลื่นแบบกาว","de":"เสื่อที่เคยเลื่อนหนีใต้ฝ่าเท้าอย่างเงียบเชียบในที่สุดก็หยุดนิ่งอยู่กับที่ เพราะแผ่นกาวกัดพื้นไว้แน่น ตาข่ายนิรภัยที่มองไม่เห็นซึ่งเก็บกวาดช่วงเวลาที่เกือบจะล้มไว้ล่วงหน้าอย่างเงียบ ๆ"},"ICON-0757":{"nm":"ฝาครอบไขควงแม่นยำ","de":"\"สกรูตัวจิ๋วตัวนี้ไม่ยอมคลาย\" ฝาที่สวมไว้บนปลายไขควงแม่นยำปกป้องคมของมัน เครื่องมือปลายนิ้วที่ละเอียดอ่อนที่สุด ซึ่งเปิดโลกขนาดเท่าฝ่ามือภายในเครื่องจักรออกมา"},"ICON-0758":{"nm":"ห่วงประแจหกเหลี่ยม","de":"ห่วงที่ร้อยประแจหกเหลี่ยมหลายตัวเข้าด้วยกันเป็นวงเดียว โลหะที่เรียงตามขนาดกางออกฉับพลันราวกับพัด จังหวะอันเป็นระเบียบของมือที่เลือกด้ามที่ต้องการได้ในทีเดียว"},"ICON-0759":{"nm":"จี้ตลับเมตรจิ๋ว","de":"จี้ที่ติดอยู่กับตลับเมตรจิ๋วที่พอดีในฝ่ามือ ห้อยอยู่กับพวงกุญแจติดตามไปทุกที่ เพื่อนตัวน้อยที่วัดและตอบความยาวที่จู่ ๆ เราก็อยากรู้ขึ้นมาได้ทันทีตรงนั้นเอง"},"ICON-0760":{"nm":"กล่องแยกสกรู","de":"กล่องแยกที่สกรูแต่ละแบบหาช่องของตัวเองเจอในแต่ละช่อง แม้แต่ชิ้นส่วนเล็ก ๆ ที่เคยกลิ้งปะปนกันก็เกิดความเป็นระเบียบขึ้น มือที่เรียนรู้จะจัดระเบียบก่อนที่จะซ่อมแซมสิ่งใด"},"ICON-0761":{"nm":"ฝาหัวฉีดกาว","de":"ปิดไว้ก็ไม่แข็งตัว เปิดทิ้งไว้ก็แห้งไป—ฉันมีชีวิตอยู่ในช่องว่างระหว่างสองสิ่งนั้น ทุกครั้งที่หยดหนึ่งหยดลง ที่ไหนสักแห่งสิ่งที่แตกหักก็กำลังถูกเชื่อมต่อกันอีกครั้ง ฝาเล็ก ๆ เพียงชิ้นเดียวเฝ้ารักษาเส้นแบ่งระหว่างความหยุดนิ่งกับการไหลอย่างเงียบ ๆ"},"ICON-0762":{"nm":"พวงกุญแจไม้วัดระดับ","de":"ความซื่อตรงขนาดเท่าฝ่ามือที่แกว่งไกวอยู่ปลายพวงกุญแจ ฟองอากาศเล็ก ๆ นี้เองที่มักเป็นสิ่งแรกที่สังเกตเห็นชั้นวางที่เอียง ฉันพกเพื่อนที่บอกเราอย่างเงียบ ๆ ว่าโลกเอียงไปนิดหน่อยไว้ในกระเป๋า"},"ICON-0763":{"nm":"ฝาครอบปลายปากคีบ","de":"ยิ่งแหลมคมมากเท่าไร ก็ยิ่งต้องการเสื้อผ้าที่ทำให้มันสงบลง ครอบปลายไว้อย่างแผ่วเบา มือและชิ้นส่วนก็ไม่บาดเจ็บ มารยาทข้อแรกในการจัดการกับความแหลมคมคือการปิดปลายมันไว้อย่างนุ่มนวล—ฝาเล็ก ๆ นี้รับหน้าที่แห่งความอ่อนโยนนั้นไว้"},"ICON-0764":{"nm":"แผ่นรองตัดชิ้นเล็ก","de":"แผ่นรองที่แผลเป็นสมานเองได้แม้ใบมีดจะผ่านไปนับพันครั้ง งานใหม่วางซ้อนลงบนรอยที่ถูกกรีดอีกครั้ง แล้วก็สมานอีกครั้ง พื้นที่เงียบงันที่ยอมสละเนื้อตัวเองเพื่อให้สิ่งอื่นถูกตัดออกมาสวยงาม"},"ICON-0765":{"nm":"ถุงเก็บชิ้นส่วนซ่อม","de":"ถุงที่หุบปากไว้เพื่อไม่ให้สกรูตัวหนึ่ง สปริงตัวหนึ่งหายไปตลอดกาล ชิ้นส่วนเล็ก ๆ ที่เหลือหลังซ่อมเสร็จรอคอยรอบต่อไปอยู่ที่นี่อย่างเงียบ ๆ สิ่งที่ป้องกันการสูญหายเสมอมาก็คือช่องเล็ก ๆ ที่ดูไม่สำคัญเช่นนี้"},"ICON-0766":{"nm":"คลิปหนีบถุงขนม","de":"การรักษาความกรอบของถุงที่เปิดไว้แล้ว สุดท้ายก็ขึ้นอยู่กับการหนีบอย่างเด็ดขาดเพียงครั้งเดียว คำสัญญาเล็ก ๆ ที่จะไม่ปล่อยให้มีช่องว่างให้มันเหนียวชื้น นิสัยที่หนีบปลายให้แน่นหนานี้ช่วยรักษาขนมของวันพรุ่งนี้ไว้"},"ICON-0767":{"nm":"ถ้วยแบ่งเยลลี่","de":"จะแบ่งขนมหนึ่งถุงให้หลายคน ต้องแบ่งอย่างเท่าเทียมกันก่อนเป็นอันดับแรก หัวใจที่ตักส่วนแบ่งเท่ากันใส่ในถ้วยแต่ละใบ การแบ่งปันเชื่อว่าเริ่มต้นจากปริมาณที่เท่ากันเป๊ะ เพื่อไม่ให้ใครรู้สึกน้อยใจ"},"ICON-0768":{"nm":"เศษกระดาษฟอยล์ช็อกโกแลต","de":"สีเงินที่เคยห่อความหวานไว้ยับง่ายในปลายนิ้ว คลี่ออกก็เปล่งประกายชั่วครู่ พับเก็บก็กลายเป็นความทรงจำ เศษแสงชิ้นหนึ่งที่สวยที่สุดหลังจากกินหมดแล้ว ก่อนจะทิ้งลองมองดูอีกสักครั้ง"},"ICON-0769":{"nm":"แถบป้ายขนม","de":"ข้างในมีอะไร อยู่ได้นานแค่ไหน—ฉันพูดแทนถุงที่เงียบงันนั้น วินาทีที่แถบหนึ่งเส้นถูกแปะติด แม้แต่ขนมก็มีชื่อและคำสัญญาเกิดขึ้น การจัดหมวดหมู่แท้จริงแล้วคือวิธีจดจำที่อ่อนโยนที่สุด"},"ICON-0770":{"nm":"กล่องแยกลูกอม","de":"อย่าใส่ลูกอมรสเปรี้ยวกับรสหวานไว้ในช่องเดียวกัน งานแบ่งแยกไว้ล่วงหน้าเพื่อไม่ให้มือลังเล เมื่อกล่องเล็ก ๆ เรียงแถวกันเป็นระเบียบ ความสนุกของการเลือกก็เพิ่มขึ้นเป็นสองเท่าโดยไม่รู้ตัว"},"ICON-0771":{"nm":"กระดาษกันกระแทกคุกกี้","de":"กระดาษบาง ๆ ที่สอดแทรกระหว่างชิ้นคุกกี้เพื่อไม่ให้ช้ำระหว่างเดินทาง สิ่งที่แตกหักง่ายยิ่งต้องการเพื่อนร่วมทางที่อ่อนโยนกว่า บางครั้งความนุ่มนวลปกป้องได้ดีกว่าความแข็งแกร่งเสียอีก"},"ICON-0772":{"nm":"เชือกผูกกล่องโดนัท","de":"ปมไขว้เพียงปมเดียวรับผิดชอบความปลอดภัยของเค้กในกล่อง มันเป็นทั้งหูหิ้ว เป็นตราปิดผนึก และเป็นสัญลักษณ์ของการรอคอยอันตื่นเต้น วินาทีที่เชือกเส้นนี้คลายออก คือวันเกิดของใครสักคน"},"ICON-0773":{"nm":"ที่รัดถุงขนมปัง","de":"บิดหนึ่งครั้ง พับ แล้วสอดฉันเข้าไป ความชุ่มชื้นของขนมปังก็ถูกผนึกไว้จนถึงเช้าพรุ่งนี้ ความดื้อรั้นเล็ก ๆ แต่มั่นคงที่กันไม่ให้อากาศเข้า การรักษาสิ่งที่นุ่มนวลไว้ให้นานเสมอเป็นหน้าที่ของสิ่งที่แข็งแรง"},"ICON-0774":{"nm":"ป้ายแลกขนม","de":"ส่วนของเธอให้ฉัน ส่วนของฉันให้เธอ จำความตื่นเต้นในวันที่เขียนชื่อลงบนป้ายเล็ก ๆ แล้วแลกขนมกันได้ไหม กระดาษที่ติดอยู่กับหัวใจที่แบ่งปันเสมอมีชื่อเพื่อนเขียนไว้อย่างเป็นระเบียบ"},"ICON-0775":{"nm":"ฝาจุกหลอด","de":"เมื่อหยุดพักจิบสักครู่ ก็ปิดฉันไว้ เพื่อไม่ให้หกเลอะ ไม่ให้เย็นชืด ให้มันรอคอยอยู่ตรงนั้นอย่างสงบนิ่ง หน้าที่ของจุกเล็ก ๆ ที่เฝ้าปากหลอดไว้เพื่อวินาทีที่ริมฝีปากจะกลับมาแตะอีกครั้ง"},"ICON-0776":{"nm":"ห่วงป้ายชื่อกระบอกน้ำ","de":"ห่วงเล็ก ๆ ที่บอกว่า \"อันนี้ของฉัน\" ท่ามกลางกระบอกน้ำหลายใบที่เรียงกันอยู่ สีเพียงสีเดียวก็คลายความสับสนออกไปได้ เครื่องหมายว่าเป็นของเราชัดเจนได้เพียงห่วงนี้ห่วงเดียว"},"ICON-0777":{"nm":"ปลอกกระดาษหุ้มแก้ว","de":"กระดาษลูกฟูกชั้นหนึ่งที่แทรกตัวเข้ามาระหว่างแก้วร้อนกับฝ่ามือ ความใส่ใจที่สอดแทรกไว้เพื่อไม่ให้ลวกมือหรือหลุดมือ การรักษาระยะห่างตรงกลางคือสิ่งที่ทำให้แก้วหนึ่งใบสมบูรณ์และปลอดภัย"},"ICON-0778":{"nm":"ป้ายถาดทำน้ำแข็ง","de":"มีคนที่เขียนวันที่ทำน้ำแข็งแต่ละก้อนไว้ ด้วยความเชื่อว่าแม้แต่ความเย็นก็มีลำดับก่อนหลัง ป้ายเล็ก ๆ แผ่นเดียวทำให้เวลาในช่องแช่แข็งไหลไปอย่างซื่อตรงและเป็นลำดับ"},"ICON-0779":{"nm":"คีมคีบถุงชา","de":"เฝ้ามองเวลาที่ชากำลังชง แล้วยกขึ้นในจังหวะที่พอดี ฝีมือชั้นเชิงที่รู้จักหยุดก่อนที่จะเข้มเกินไป ความเข้มข้นของชาไม่ได้ถูกกำหนดด้วยเวลาที่แช่ไว้ แต่ด้วยจังหวะที่ดึงขึ้นมาต่างหาก"},"ICON-0780":{"nm":"ที่ตั้งฟิลเตอร์ดริป","de":"มันยกฟิลเตอร์ไว้และยืนเงียบสงบเพื่อให้น้ำร้อนไหลลงอย่างช้า ๆ มันรู้ดีว่าความเร่งรีบจะทำให้กลิ่นหอมจางลง แม้แต่งานรองรับการรอคอยก็ยังต้องการท่าทีที่ไม่สั่นไหว"},"ICON-0781":{"nm":"สายคล้องขวดน้ำ","de":"สายที่แขวนขวดน้ำไว้กับข้อมือหรือบ่าเพื่อเดินไปด้วยกัน วิธีการเป็นเพื่อนร่วมทางที่ทำให้มันอยู่ใกล้เราเสมอโดยไม่ต้องตั้งใจพกพา บางครั้งการผูกไว้เบา ๆ ก็เป็นวิธีที่อ่อนโยนที่สุดที่จะไม่ลืม"},"ICON-0782":{"nm":"ฝาครอบปากกระป๋อง","de":"มันปิดปากกระป๋องที่ดื่มค้างไว้เพื่อกันฝุ่นและกันซ่า หมวกเล็ก ๆ ที่รับผิดชอบความสดใหม่จนถึงจิบต่อไป แม้แต่การปิดสิ่งที่เปิดไว้ชั่วครู่อย่างเงียบ ๆ ก็ยังแฝงความใส่ใจไว้"},"ICON-0783":{"nm":"ที่เก็บบัตรสะสมแต้มเครื่องดื่ม","de":"แก้วที่สิบฟรีหนึ่งแก้ว—มันโอบอุ้มบัตรแสตมป์ไว้เพื่อไม่ให้คำสัญญานั้นสูญหาย เพื่อไม่ให้วันเวลาที่เติมเต็มไปทีละช่องต้องยับยู่ยี่ ในที่เก็บนี้สะสมฝีเท้าอันขยันขันแข็งของขาประจำเอาไว้"},"ICON-0784":{"nm":"สายรัดกล่องข้าว","de":"สายที่โอบรัดกล่องข้าวไว้หนึ่งรอบเพื่อไม่ให้ฝาเปิดออก ความอุ่นใจเล็ก ๆ ว่าน้ำแกงจะไม่รั่วไหลในกระเป๋า ความปลอดภัยจนถึงมื้อเที่ยงฝากไว้กับรอบที่แน่นหนานี้เพียงรอบเดียว"},"ICON-0785":{"nm":"ชุดถ้วยกับข้าว","de":"ให้กับข้าวแต่ละอย่างมีที่ทางของตัวเอง รสชาติก็จะไม่ปะปนกัน กิมจิก็เป็นกิมจิ ผักก็เป็นผัก แยกกันอย่างชัดเจน การแบ่งช่องที่ถ้วยเล็ก ๆ สร้างขึ้นคือระเบียบของกล่องข้าว และความอ่อนโยนที่เติมเต็มฝีมือการทำอาหาร"},"ICON-0786":{"nm":"กล่องตะเกียบ","de":"บ้านเล็ก ๆ ที่ห่อหุ้มตะเกียบซึ่งร่วมทานอาหารสามมื้อของวันไว้อย่างสะอาดหมดจด เพื่อนร่วมทางเงียบ ๆ ที่รักษาความเรียบร้อยไว้ได้แม้ในกระเป๋านักเรียน หัวใจที่พกพามันไปด้วยนั้น สุดท้ายแล้วคือสิ่งที่สร้างมื้ออาหารอันเรียบร้อย"},"ICON-0787":{"nm":"ป้ายขวดซอส","de":"ซีอิ๊วหรือน้ำส้มสายชู? มันให้ความชัดเจนกับขวดที่เคยสับสน วินาทีที่แถบหนึ่งเส้นถูกแปะ ความลังเลของปลายนิ้วก็หายไป ความเร็วของครัวที่วุ่นวายถูกสร้างขึ้นอย่างเงียบ ๆ ด้วยเครื่องหมายเล็ก ๆ เช่นนี้"},"ICON-0788":{"nm":"แผ่นสาหร่ายม้วนคิมบับ","de":"แผ่นสาหร่ายบาง ๆ ที่ม้วนข้าวและไส้ให้เป็นเนื้อเดียวกัน ต้องห่อให้แน่นเพื่อไม่ให้กระจัดกระจายตอนหั่น ความตื่นเต้นของเช้าวันไปปิกนิกม้วนออกมาเป็นวงกลมจากชั้นเดียวนี้เอง"},"ICON-0789":{"nm":"กระบอกปักไม้จิ้ม","de":"ตั้งไม้เสียบและไม้จิ้มฟันไว้ในที่เดียวกัน มือก็จะไม่ลังเลเมื่อถึงเวลาที่ต้องการ การให้บ้านที่แน่นอนแม้แต่กับสิ่งที่แหลมคม การจัดระเบียบสุดท้ายแล้วคือความเมตตาเล็ก ๆ สำหรับมือที่จะเอื้อมมาต่อไป"},"ICON-0790":{"nm":"ปลอกหุ้มถุงเก็บความเย็น","de":"ห่อถุงเก็บความเย็นไว้อีกชั้นหนึ่งเพื่อรักษาความเย็นไว้ให้นานขึ้นอีกนิด พร้อมกันนั้นก็ป้องกันไม่ให้กระเป๋าเปียกจากหยดน้ำที่เกาะตัว การรักษาความเย็นไว้จนถึงที่สุดเป็นหน้าที่ของชั้นหนาชั้นนี้เสมอมา"},"ICON-0791":{"nm":"ที่กั้นช่องกล่องข้าว","de":"กำแพงเล็ก ๆ ที่สร้างไว้เพื่อไม่ให้ข้าวและกับข้าวรุกล้ำที่ของกันและกัน ความสงบของหนึ่งช่องที่น้ำแกงไม่ล้นข้ามไปมา กล่องข้าวที่แบ่งเป็นช่อง ๆ นั้นบรรจุหัวใจอันละเอียดอ่อนของคนทำไว้อย่างครบถ้วน"},"ICON-0792":{"nm":"การ์ดลำดับมื้ออาหาร","de":"เริ่มจากซุปหรือข้าวก่อนดี? การ์ดที่แนะนำคอร์สของวันนี้อย่างแผ่วเบา คำแนะนำอันอ่อนโยนที่บอกว่ากินตามลำดับแล้วจะอร่อยกว่า มันบอกเราอย่างเงียบ ๆ ว่าแม้แต่มื้ออาหารก็มีลำดับเรื่องราวเหมือนนิทาน"},"ICON-0793":{"nm":"สติกเกอร์ขีดตวง","de":"สติกเกอร์เล็ก ๆ ที่ติดข้างขีดบอกว่า \"แค่นี้พอ\" อย่างชัดเจน เครื่องหมายที่ทำให้ปริมาณที่เคยสับสนทุกครั้งถูกต้องได้ในคราวเดียว ความแม่นยำเริ่มต้นจากเส้นบอกแนวเล็ก ๆ เช่นนี้เอง"},"ICON-0794":{"nm":"ที่จับฝาหม้อซิลิโคน","de":"ที่จับเล็ก ๆ ที่ทำให้เรายกฝาที่ร้อนขึ้นได้โดยไม่ลวกนิ้ว มันยืมความกล้าให้เราเปิดหม้อที่มีไอกำลังพวยพุ่งขึ้นมาอย่างแผ่วเบา ความปลอดภัยเกิดจากการเตรียมจุดจับไว้ล่วงหน้าเสมอ"},"ICON-0795":{"nm":"ตะขอหนีบเล็ก","de":"คีมเล็ก ๆ ที่ให้ที่ทางกับผ้าขี้ริ้วหรือถุงพลาสติกที่ไม่เคยมีที่แขวน มันเปลี่ยนผนังมุมหนึ่งที่รกรุงรังให้เป็นภาพที่เป็นระเบียบ นิสัยการแขวนของเพียงอย่างเดียวทำให้ครัวรู้สึกเบาสบายขึ้นมาก"},"ICON-0796":{"nm":"ฝาครอบแปรงทาน้ำมัน","de":"ปิดปลายแปรงทาน้ำมันไว้ ทั้งฝุ่นและการแข็งตัวก็ผ่านเลยไป หมวกที่รักษาความนุ่มนวลนั้นไว้จนถึงมื้ออาหารต่อไป ความใส่ใจเล็ก ๆ ต่อเครื่องมือ สุดท้ายแล้วคือสิ่งที่รักษารสชาติไว้ได้ยาวนาน"},"ICON-0797":{"nm":"กระปุกเกลือมีช้อน","de":"ช้อนเล็ก ๆ ที่อาศัยอยู่ในกระปุกเกลือ มันตักความแม่นยำของหนึ่งหยิบมืออย่างพิถีพิถันในทุกครั้ง ฝีมือชั้นเชิงในการปรุงรสคือหัวใจที่ช้อนเล็ก ๆ นี้จดจำไว้เท่านั้นเอง"},"ICON-0798":{"nm":"แผ่นแม่เหล็กจับเวลา","de":"ติดอยู่บนประตูตู้เย็น นับเวลาสามนาทีของบะหมี่กึ่งสำเร็จรูป และจับเวลาสามสิบวินาทีของการออกกำลังกาย ด้วยแม่เหล็กแผ่นเดียว เวลาที่กำลังจะผ่านไปหยุดอยู่ตรงหน้าเรา วงกลมขยันขันแข็งที่ตรึงสิ่งที่กำลังผ่านเลยไว้บนผนังชั่วครู่"},"ICON-0799":{"nm":"ปลอกหุ้มด้ามหม้อ","de":"ชั้นหนึ่งที่ห่อหุ้มไว้เพื่อไม่ให้จับด้ามที่ร้อนจัดด้วยมือเปล่า โล่เล็ก ๆ ที่ยืนขวางระหว่างความร้อนกับฝ่ามือ การยกหม้อไปอย่างปลอดภัยเริ่มต้นจากการห่อหุ้มอันอ่อนโยนนี้เสมอ"},"ICON-0800":{"nm":"ยางรองเขียง","de":"เมื่อฉันปูอยู่ใต้พื้น เขียงก็จะไม่ลื่นไถลอีกต่อไป ยางชิ้นหนึ่งที่ค้ำยันอยู่ด้านล่างทุกครั้งที่การหั่นสั่นคลอน ความมั่นคงคืองานของการกัดยึดไว้แน่นในที่ที่มองไม่เห็น"},"ICON-0801":{"nm":"คลิปหนีบถุงมือครัว","de":"มุมที่มือซึ่งเคลื่อนไหวไม่หยุดหน้าเตาไฟได้พักสักครู่ แขวนถุงมือข้างที่สะบัดพลิ้วไว้กับผนัง แล้วการหายใจสั้นๆ ก่อนมื้อถัดไปก็เริ่มต้นขึ้น การจัดเก็บคือชื่ออีกชื่อหนึ่งของความอ่อนโยน"},"ICON-0802":{"nm":"ที่ใส่ไม้คนกาแฟ","de":"ข้างเคาน์เตอร์ มุมที่แท่งเรียวยาวพิงบ่ากันเรียงซ้อนกันอย่างเป็นระเบียบ พร้อมจะวาดวงกลมในแก้วยามเช้าของใครสักคน แถวที่เรียงกันนั้นราวกับคณะนักร้องประสานเสียงก่อนจะเปล่งเสียงพร้อมกัน"},"ICON-0803":{"nm":"แถบรัดชุดรองแก้ว","de":"แถบที่ค่อยๆ รองรับเสียงกึกเบาๆ ยามแก้วแตะโต๊ะ มัดรองแก้วทรงกลมไว้ด้วยกัน แล้วการต้อนรับแขกก็พร้อมสรรพ การต้อนรับมักเริ่มต้นจากมุมเล็กๆ เช่นนี้เสมอ"},"ICON-0804":{"nm":"ป้ายชื่อขวดไซรัป","de":"ชื่อหนึ่งบรรทัดที่ติดอยู่บนขวด หวาน เข้มข้น—คำสั้นๆ เพียงคำเดียวนั้นช่วยปลอบโยนเช้าอันวุ่นวายให้เป็นระเบียบขึ้นอีกนิด ป้ายชื่อคือกระดาษที่จดคำสัญญาเล็กๆ ไว้ล่วงหน้า"},"ICON-0805":{"nm":"กระปุกไม้จิ้มขนม","de":"กระปุกที่รวมแท่งปลายแหลมซึ่งใช้เสียบผลไม้ชิ้นเล็กๆ ไว้ด้วยกัน ก่อนจะถูกปักลงบนจานขนมราวกับธงเล็กๆ พวกมันรอคอยตาอย่างเงียบๆ อยู่ที่นี่ก่อน แม้แต่ความหวานก็ยังมีลำดับก่อนหลัง"},"ICON-0806":{"nm":"ปลอกกระดาษหุ้มไม้คน","de":"เสื้อกระดาษที่โอบกอดไม้คนเครื่องดื่มไว้ในอ้อมแขน มันซับความชื้นที่เครื่องดื่มเย็นทิ้งไว้แทนเรา คอยปกป้องปลายนิ้วที่จับแก้วให้แห้งสบาย ความใส่ใจที่มองไม่เห็นมักมาจากขอบเสมอ"},"ICON-0807":{"nm":"ห่วงหิ้วแก้วกลับบ้าน","de":"ยามที่สองมือไม่พอ ด้ามจับเล็กๆ นี้จะช่วยถือแก้วแทนเรา มันยึดความอบอุ่นที่ห่อไว้ไม่ให้หกแม้แต่หยดเดียว ส่งความอบอุ่นนั้นไปจนถึงปากตรอกบ้านของใครสักคน"},"ICON-0808":{"nm":"ปลอกกันกระแทกเบลล์แจ้งเตือนคาเฟ่","de":"เสื้อคลุมที่โอบกอดการรอคอยจนกว่าเสียงสั่นจะดังขึ้นอย่างเงียบๆ มันเฝ้าคุ้มครองตั๋วคิวที่ส่องแสงอยู่มุมหนึ่งของร้านกาแฟ พร้อมทั้งเก็บความตื่นเต้นที่ว่าเลขของเราจะถูกเรียกในไม่ช้าไว้ด้วยกัน"},"ICON-0809":{"nm":"ห่วงคูปองสะสมแต้ม","de":"กระดาษที่เมื่อเติมเต็มสิบช่องแล้วจะได้เครื่องดื่มฟรีหนึ่งแก้ว ทุกครั้งที่ตราประทับเพิ่มขึ้นทีละดวง ชื่อ \"ขาประจำ\" ก็เติบโตขึ้นทีละนิดเช่นกัน ความสุขเรียบง่ายที่สุดร้อยอยู่บนห่วงเล็กๆ วงหนึ่ง"},"ICON-0810":{"nm":"ถุงตัวอย่างเมล็ดกาแฟ","de":"ถุงที่บรรจุเมล็ดกาแฟหนึ่งกำมือแล้วมอบกลิ่นหอมให้ก่อนสิ่งอื่นใด รสเปรี้ยวและกลิ่นหวานที่ผ่านปลายจมูก ความประทับใจแรกนั้นเองที่กำหนดชะตาของกาแฟหนึ่งแก้ว กลิ่นหอมมาถึงเร็วกว่าคำอธิบายใดๆ"},"ICON-0811":{"nm":"แม่เหล็กป้ายชื่อตู้เย็น","de":"ป้ายชื่อแม่เหล็กเล็กๆ ที่แปะติดประตูตู้เย็นเบาๆ จดไว้ว่าอะไรเข้ามาเมื่อไหร่ แล้วแม้แต่กับข้าวที่เกือบถูกลืมก็ได้คืนคิวของตัวเอง การดูแลบ้านคืองานที่ยึดความทรงจำอันไหลเลื่อนไว้ให้มั่นคง"},"ICON-0812":{"nm":"ป้ายวันที่จัดเก็บ","de":"ชิ้นเล็กๆ ที่สลักวันที่บรรจุไว้อย่างชัดเจน พยานตัวจ้อยที่คอยบอกอย่างเงียบๆ ว่าถึงจะผ่านไปหลายวันแล้ว นี่ก็ยังใช้ได้อยู่ ความสดใหม่ถูกรักษาไว้ด้วยปลายนิ้วที่จดจำวันที่ไว้"},"ICON-0813":{"nm":"แถบรัดกล่องแบ่งอาหาร","de":"แถบที่โอบรอบเอวของกล่องที่แบ่งใส่ไว้ มันรัดฝาที่โยกคลอนให้แน่นหนา รักษาระเบียบเล็กๆ ในตู้เย็นไว้ได้ การผูกมัดสิ่งใดสักอย่างนั้นคล้ายกับการจัดระเบียบหัวใจ"},"ICON-0814":{"nm":"คลิปหนีบปิดปากถุงสีสัน","de":"คลิปหลากสีที่กัดปากถุงไว้แน่นสนิท สีแดงคือของเผ็ด สีเหลืองคือของหวาน—แค่มองสีมือก็รู้ก่อนแล้ว สัญญาณไฟจราจรของครัวนำทางไปโดยไม่ต้องพูดสักคำเช่นนี้"},"ICON-0815":{"nm":"ป้ายชื่อถุงแช่แข็ง","de":"ป้ายชื่อที่วางแผ่วเบาไว้บนสิ่งที่ถูกแช่แข็ง มันปลอบโยนถุงที่เกาะไปด้วยเกล็ดน้ำแข็งไม่ให้ลืมว่าตัวเองเคยเป็นอะไร คำทักทายเล็กๆ ที่ส่งถึงวัตถุดิบที่หลับใหลในฤดูหนาว"},"ICON-0816":{"nm":"ตาข่ายเก็บผัก","de":"ตาข่ายโปร่งที่โอบรับผักเปื้อนดินไว้อย่างใจกว้าง ครัวของคุณยายรู้มานานแล้วว่าต้องให้ช่องหายใจ ผักจึงจะอยู่ได้นาน การระบายอากาศคือช่องว่างอันอ่อนโยนที่มอบให้แก่ผัก"},"ICON-0817":{"nm":"ฝาจัดหมวดหมู่ฝาขวด","de":"ฝาจัดหมวดหมู่ที่จับคู่ฝาขวดแต่ละขนาดให้เข้าคู่กันทีละใบ การตามหาคู่ที่พลัดหลงกลับคืนมานั้นอ่อนโยนกว่าที่คิด เมื่อจับคู่ที่เข้ากันได้แล้ว ครัวก็เป็นระเบียบขึ้นอีกขั้น"},"ICON-0818":{"nm":"ป้ายถาดไข่","de":"เครื่องหมายที่ติดไว้อย่างเป็นระเบียบในรังเล็กๆ ทั้งสิบช่อง ภูมิปัญญาการดูแลบ้านที่บอกให้ใช้ไข่เก่าก่อน แม้แต่ไข่ดาวหนึ่งฟองยามเช้าก็ยังแฝงหัวใจที่ใส่ใจลำดับก่อนหลัง"},"ICON-0819":{"nm":"สติกเกอร์อาหารเหลือ","de":"เขียนว่า \"นี่ของฉัน!\" แล้วแปะไว้ แม้แต่ตู้เย็นก็ยังได้พักสงบชั่วครู่ คำประกาศสงครามน่ารักๆ ที่จองเจ้าของของว่างยามดึกไว้ล่วงหน้า ครอบครัวหมุนไปได้ในแต่ละวันก็ด้วยข้อตกลงเล็กๆ น้อยๆ แบบนี้แหละ"},"ICON-0820":{"nm":"ที่วางช้อนตะเกียบ","de":"ชิ้นเล็กๆ ที่รองรับช้อนกับตะเกียบไม่ให้แตะโต๊ะโดยตรงอย่างแผ่วเบา ความเรียบร้อยจิ๋วนี้ค่อยๆ ยกระดับเกียรติของมื้ออาหาร มารยาทบนโต๊ะอาหารเติบโตอย่างเงียบๆ ในมุมเล็กๆ เช่นนี้"},"ICON-0821":{"nm":"ห่วงยึดกระดาษเช็ดปาก","de":"ห่วงที่สอดยึดกระดาษเช็ดปากซึ่งจะปลิวไปตามลมไว้อย่างสงบ รวบกระดาษสีขาวที่รอคอยตาจะได้คลี่ออกไว้อย่างเรียบร้อย จารึกระเบียบเล็กๆ ลงบนโต๊ะอาหารอย่างชัดเจน"},"ICON-0822":{"nm":"ที่กดมุมผ้ารองโต๊ะ","de":"ชิ้นส่วนที่กดปลอบมุมผ้ารองโต๊ะที่งอนขึ้นอย่างแผ่วเบา โต๊ะอาหารสอนทุกวันว่าต้องจับปลายด้านหนึ่งไว้ให้ได้ก่อน ทั้งผืนจึงจะเรียบเสมอกัน แม้แต่มุมก็ยังมีความรับผิดชอบส่วนของตัวเอง"},"ICON-0823":{"nm":"ถาดเครื่องปรุงจิ๋ว","de":"ถาดเล็กๆ ที่วางถ้วยซีอิ๊วและเกลือหยิบมือเรียงกันไว้ อ้อมกอดอันกว้างขวางของโต๊ะอาหารที่ให้ที่ทางแก่แม้แต่เครื่องเคียงชิ้นเล็ก อาหารเกาหลีลึกซึ้งขึ้นจากหัวใจที่ใส่ใจของประกอบเล็กๆ น้อยๆ"},"ICON-0824":{"nm":"ป้ายเลขโต๊ะ","de":"ตัวเลขที่ถูกเรียกว่า \"โต๊ะที่เท่าไหร่!\" ในร้านอาหารที่วุ่นวาย มันจัดลำดับการรอคอยเพื่อความยุติธรรมของทุกคน สิ่งที่บรรจุอยู่ในป้ายเพียงแผ่นเดียวคือคำสัญญาเล็กๆ และอาหารร้อนๆ ที่กำลังจะมาถึง"},"ICON-0825":{"nm":"แถบทำเครื่องหมายแก้วน้ำ","de":"แถบที่พันรอบแก้วน้ำเพื่อบอกเบาๆ ว่าเป็นของใคร ธงเล็กๆ ที่ทำเครื่องหมายที่นั่งของฉันท่ามกลางแก้วที่หน้าตาเหมือนกัน บนโต๊ะที่นั่งล้อมวงกันนั้น ความใส่ใจเช่นนี้ช่วยป้องกันความเข้าใจผิดที่ไม่จำเป็น"},"ICON-0826":{"nm":"เข็มกลัดจัดหมวดจานรอง","de":"เข็มกลัดที่แบ่งจานรองสำหรับตักแบ่งด้วยสี ขีดเส้นแบ่งระหว่างของฉันกับของเธออย่างอ่อนโยน ทำให้ความสุขของการแบ่งปันกันสะอาดขึ้นอีกขั้น แบ่งปันความรักได้ แต่รักษาความสะอาดอย่างเคร่งครัด"},"ICON-0827":{"nm":"แผงบังเมนู","de":"ช่วงเวลาแห่งการครุ่นคิดที่แอบซ่อนอยู่หลังเมนูที่เปิดกางออก แม้แต่ความลังเลสั้นๆ ว่าจะกินอะไรดีนั้น แท้จริงแล้วก็เป็นส่วนหนึ่งของมื้ออาหาร วันนี้จะเอาอะไรดีนะ—มันปิดบังความตื่นเต้นนั้นไว้อย่างเงียบๆ"},"ICON-0828":{"nm":"ที่ตั้งป้ายชื่อโต๊ะ","de":"แท่นเล็กๆ ที่ตั้งป้ายชื่อให้ตรงขึ้น ไม่ว่าจะเป็นที่นั่งในงานอีเวนต์หรือโต๊ะงานเลี้ยง มันประกาศอย่างชัดเจนว่าที่นี่คือที่ของคุณ การต้อนรับจะสมบูรณ์ก็ต่อเมื่อชื่อถูกเอ่ยขึ้นเท่านั้น"},"ICON-0829":{"nm":"ปลอกกระดาษหุ้มมัฟฟิน","de":"เสื้อกระดาษที่โอบรอบเอวอวบอิ่มของมัฟฟินที่เพิ่งอบเสร็จ มันรองรับตัวอุ่นๆ ไม่ให้ลื่นหลุดจากมือ รักษาความอบอุ่นไว้อย่างทะนุถนอมจนถึงวินาทีที่กัดคำแรก แม้แต่ขนมหวานก็ยังต้องการเสื้อคลุม"},"ICON-0830":{"nm":"ฝาปิดถุงบีบครีม","de":"จุกที่ปิดปลายถุงบีบครีมให้แน่นสนิท มันปิดปากไว้อย่างมิดชิดไม่ให้หยดแม้แต่หยดเดียวรั่วไหลออกมาระหว่างพัก ดอกไม้ดอกเล็กๆ บนเค้กบานขึ้นจากความยับยั้งชั่งใจนี้เอง"},"ICON-0831":{"nm":"ห่วงพิมพ์คุกกี้","de":"ชุดพิมพ์ทรงกลมที่ตัดแป้งให้เป็นรูปดาว รูปหมี แป้งสาลีชนิดเดียวกันตื่นขึ้นเป็นสีหน้านับสิบผ่านปลายนิ้ว ไม่ว่าจะอบอะไร สิ่งที่สัมผัสแป้งเป็นอันดับแรกเสมอคือความตั้งใจ"},"ICON-0832":{"nm":"จี้เครื่องขูดแป้ง","de":"มือแบนที่กวาดรวบแป้งอย่างประหยัดและแบ่งแยกอย่างเรียบร้อย ความขยันที่เก็บแม้แต่แป้งกำมือเล็กๆ ที่ติดชามนั้นเองที่กำหนดปริมาตรของขนมปังหนึ่งก้อน การทำขนมอบคืองานของมือที่รู้จักประหยัด"},"ICON-0833":{"nm":"แผ่นวางช้อนตวง","de":"ช้อนชาหนึ่งช้อน ช้อนโต๊ะครึ่งช้อน—แผ่นไม้ที่วางช้อนตวงเรียงไว้อย่างมั่นคงไม่โคลงเคลง ช้อนตวงที่แม่นยำหนึ่งช้อนตั้งสมดุลของรสชาติให้ตรงเป๊ะ เบื้องหลังคำว่า \"ฝีมือ\" นั้นแท้จริงซ่อนการตวงอย่างพิถีพิถันไว้"},"ICON-0834":{"nm":"ตะขอแขวนถุงมือโอเวน","de":"ตะขอสำหรับแขวนถุงมือที่เคยยืนเฝ้าอยู่หน้าเตาอบร้อนๆ มือหนาที่ป้องกันแผลไหม้ยังคงอยู่ในระยะเอื้อมถึงแม้ในยามพัก ความปลอดภัยเริ่มต้นเสมอจากสิ่งที่อยู่ในที่ของมัน"},"ICON-0835":{"nm":"คลิปตะแกรงพักขนม","de":"คีมหนีบที่กัดตะแกรงพักขนมที่เพิ่งอบเสร็จไว้อย่างเรียบร้อย รั้งไว้ไม่ให้เคลื่อนขณะไอน้ำระเหยออก รอคอยความกรอบให้สมบูรณ์ไปด้วยกัน แม้แต่การพักให้เย็นก็ยังต้องการความอดทนสักกำมือ"},"ICON-0836":{"nm":"ไม้ปักท็อปเปอร์เค้ก","de":"ไม้ปักที่ยกตัวอักษรคำว่า \"สุขสันต์วันเกิด\" ให้ตั้งอยู่บนเค้ก ก่อนเทียนจะดับลงไม่กี่วินาที ธงเล็กๆ นี้เองที่ทำให้วันของใครคนหนึ่งสว่างที่สุด การเฉลิมฉลองต้องยกให้สูงจึงจะเห็นได้ชัด"},"ICON-0837":{"nm":"กระปุกโรยน้ำตาลไอซิ่ง","de":"กระปุกที่บรรจุการโรยเบาๆ ครั้งสุดท้าย มันโปรยลงบนขนมที่เพิ่งอบเสร็จราวหิมะขาวโพลนกองเป็นชั้นบาง เปลี่ยนขนมชิ้นธรรมดาให้กลายเป็นของขวัญเล็กๆ การเก็บงานสุดท้ายมาจากมือที่แผ่วเบาที่สุดเสมอ"},"ICON-0838":{"nm":"ป้ายข้าวห่อสาหร่ายสามเหลี่ยม","de":"ลอกพลาสติกตามลำดับ 1, 2, 3 แล้วสาหร่ายก็ฟื้นคืนความกรอบบนรูปสามเหลี่ยมนั้น หนึ่งบรรทัดที่ทำให้จำเพื่อนแท้ยามรุ่งสางในร้านสะดวกซื้อได้แต่ไกล คืนหิวๆ หลังเลิกเรียนพิเศษถูกแปะไว้ที่นี่แหละ"},"ICON-0839":{"nm":"ที่กดฝาบะหมี่ถ้วย","de":"ที่รองที่กดไว้อย่างเงียบๆ ไม่ให้ฝาเปิดขึ้นระหว่างรอสามนาที มันแทนที่ตะเกียบที่เคยวางไว้ด้านบนเพื่อกันไอน้ำหนีออกไป ช่วงเวลาสั้นๆ ที่เส้นบะหมี่กำลังสุกนั้นคือช่วงตื่นเต้นที่สุดของของว่างยามดึก"},"ICON-0840":{"nm":"ฝาจับไม้เสียบฮอตบาร์","de":"ฝาเล็กๆ ที่จับปลายไม้เสียบไว้แน่นหนา ปกป้องให้กัดกินได้ง่ายโดยไม่ให้ซอสเปื้อนมือแม้แต่หยดเดียว ความสนุกของการกินจุกจิกหน้าร้านบุนซิกมักสมบูรณ์ด้วยสิ่งเล็กๆ แบบนี้เสมอ"},"ICON-0841":{"nm":"ที่จับถุงพลาสติก","de":"คล้องนิ้วแล้วถุงพลาสติกก็ส่งเสียงกรอบแกรบร้องแผ่วเบา น้ำหนักของของที่ซื้อมาเอนไปด้านหนึ่ง และทางเดินกลับบ้านทิ้งรอยแดงไว้บนฝ่ามือ ในเสียงเบาๆ นั้น ภาระงานบ้านของวันนี้ห้อยแกว่งอยู่อย่างหนักอึ้ง"},"ICON-0842":{"nm":"คลิปพับใบเสร็จ","de":"พับใบเสร็จที่คลี่ยาวออกมาเป็นครึ่งแล้วหนีบให้แน่น เงินที่ใช้ไปในวันนี้ก็กลายเป็นมัดเรียบร้อยหนึ่งมัด ขณะที่กระดาษกลิ่นหมึกซ้อนทับกันขึ้นเรื่อยๆ ความทรงจำเล็กๆ ของการดูแลบ้านก็ถูกจัดเรียงไว้อย่างเป็นระเบียบเช่นกัน"},"ICON-0843":{"nm":"ป้ายตั้งเวลาไมโครเวฟ","de":"ก่อนเสียง \"ติ๊ง\" จะดังขึ้น ป้ายนี้นับเวลาที่จะอุ่นไว้อย่างเงียบๆ ป้ายบอกทางเล็กๆ ที่จดไว้กี่นาทีกี่วินาที และชื่อของสิ่งที่จะอุ่น แม้แต่หัวใจที่รอคอยคิวจะอบอุ่นก็ยังมีขีดวัดเช่นนี้"},"ICON-0844":{"nm":"ม้วนสติกเกอร์ลดราคา","de":"ทุกครั้งที่ลอกออกทีละแผ่น เสียงเหนียวหนึบเบาๆ ก็จี้ปลายนิ้ว เมื่อตัวเลขสีแดงคลี่คลายออกมาเรียงแถว ตะกร้าจ่ายตลาดของใครสักคนก็เบาลงอีกนิด ม้วนความใจดีเล็กๆ ที่ขดกลมรอคอยอยู่"},"ICON-0845":{"nm":"ห่วงพวงซองซอส","de":"รสเปรี้ยวแตกฉ่ำที่มุมปาก แล้ววันธรรมดาก็หวานขึ้นอีกนิด เมื่อซองที่ห้อยจากห่วงกลมแกว่งไกวตามจังหวะก้าวเดิน ความหวานเล็กๆ หนึ่งอย่างก็ติดตามฉันไปทั้งวันในกระเป๋า"},"ICON-0846":{"nm":"ป้ายตะกร้าร้านสะดวกซื้อ","de":"จับไว้ในมือแล้วพลาสติกก็โยกเบาๆ ร้านที่สว่างไสวยามดึก ลึกพอจะใส่ข้าวห่อสาหร่ายสามเหลี่ยมสักสองสามชิ้นกับเครื่องดื่มหนึ่งขวด ภาชนะอบอุ่นสำหรับมื้อเดียวพอดี ที่แม้อยู่คนเดียวก็ไม่เหงา"},"ICON-0847":{"nm":"แถบรัดกล่องมาการอง","de":"แถบเดียวโอบกอดกล่องไว้อย่างแผ่วเบา ไม่ให้มาการองหลากสีกระจัดกระจาย คนที่เคยได้รับของขวัญรู้ด้วยปลายนิ้วว่าความตื่นเต้นก่อนแก้ริบบิ้นออกนั้นแท้จริงคือช่วงที่หวานที่สุด"},"ICON-0848":{"nm":"คลิปหนีบตาข่ายผลไม้","de":"รวบปากตาข่ายแล้วหนีบให้แน่น กลิ่นหอมของแอปเปิลก็ลอดผ่านตาข่ายออกมาแผ่วเบา มือเล็กๆ หนึ่งมือที่ยึดไว้ไม่ให้กลิ้งหล่น คำเตือนอ่อนโยนไร้เสียงที่บอกให้รีบกินก่อนจะนิ่มเกินไป"},"ICON-0849":{"nm":"ผ้าคลุมฝาขวดแยม","de":"ชวนให้นึกถึงครัวหน้าร้อนของคุณยาย ที่คลุมฝาขวดด้วยผ้ากลมแล้วมัดด้วยหนังยาง ผ้าลายตารางผืนเดียวปิดผนึกเวลาหวานๆ ที่แยมค่อยๆ สุกไว้พร้อมกับความตั้งใจ ฝีมือถูกเก็บรักษาไว้ด้วยการปิดคลุมเช่นนี้แหละ"},"ICON-0850":{"nm":"ริบบิ้นผูกถุงคุกกี้","de":"ห่อคุกกี้ที่เพิ่งอบเสร็จด้วยเซลโลเฟนแล้วบิดริบบิ้นผูกไว้ กลิ่นเนยก็ซึมไปจนถึงปลายริบบิ้น มือที่ยื่นของทำเองให้ใครสักคนมักสั่นเบาๆ เสมอ ปมที่ผูกไว้นั้นผูกใจไปด้วยกัน"},"ICON-0851":{"nm":"แผ่นแบ่งช่องช็อกโกแลต","de":"ทีละช่อง ทีละช่อง มันกำหนดที่ทางไม่ให้ช็อกโกแลตแตะกัน ไม่ให้ละลาย ไม่ให้แตกหัก สิ่งที่แผ่นกั้นเล็กๆ ปกป้องไว้จนถึงที่สุดคือหัวใจที่สมบูรณ์หนึ่งเม็ดที่จะมอบให้ใครสักคน"},"ICON-0852":{"nm":"ป้ายของขวัญถุงชา","de":"บนป้ายที่พันรอบถุงชา ชื่อที่เขียนด้วยลายมือเรียบร้อย กระดาษแผ่นเล็กกระซิบบอกล่วงหน้าว่าเมื่อชงแล้วกลิ่นใบไม้จะลอยขึ้นมาพร้อมไอน้ำ แก้วที่ทำให้มืออุ่นก่อนจะได้ดื่มด้วยซ้ำ"},"ICON-0853":{"nm":"สร้อยคอขวดลูกอม","de":"สร้อยคอที่ทำจากเชือกพันรอบคอขวดที่บรรจุลูกอมหลากสี ทุกก้าวเดิน เสียงเหมือนลูกปัดเล็กๆ กลิ้งอยู่ข้างในก็ดังกรุ๋งกริ๋ง สมบัติแสนภูมิใจของวัยเด็กที่แขวนความหวานไว้รอบคอ"},"ICON-0854":{"nm":"จี้ช้อนของขวัญ","de":"ด้วยจี้เล็กๆ หนึ่งชิ้นที่ห้อยปลายด้าม ช้อนธรรมดาก็กลายเป็นของขวัญโดยไม่ทันรู้ตัว เสียงกระทบกันเบาใสทุกครั้งที่ตักขึ้น เครื่องประดับจิ๋วที่เพิ่มลีลาเล็กๆ ให้กับหัวใจที่ยื่นให้"},"ICON-0855":{"nm":"ป้ายขอบคุณของว่าง","de":"ความปรารถนาที่อยากตอบแทนแม้เพียงเล็กน้อยเท่าที่ได้รับมา ป้ายขอบคุณแผ่นหนึ่งที่แขวนไว้เบาๆ บนถุงของว่าง แทนคำว่า \"ขอบคุณ\" ที่พูดไม่จบ คำทักทายเล็กๆ ส่งต่อจากมือสู่มืออย่างเงียบๆ"},"ICON-0856":{"nm":"ห่วงตัวอย่างเทปมาสกิ้ง","de":"ลวดลายที่ตัดแปะไว้ทีละคืบเรียงเป็นแถบเล็กๆ ต่อกัน ขณะเลือกสีที่ชอบด้วยปลายนิ้วอย่างช้าๆ แค่คิดว่าจะแต่งอะไรวันนั้นก็สีสันขึ้นทั้งวัน แม้แต่การครุ่นคิดก็ยังเป็นความสุข บนสวอตช์แถวเดียวนี้"},"ICON-0857":{"nm":"ฝาปลายแหนบสติกเกอร์","de":"สวมฝาที่ปลายแหนบแหลม แม้สติกเกอร์เล็กเท่าเล็บก็ไม่บอบช้ำ มือที่แม่นยำหยิบยกมุมที่นิ้วเอื้อมไม่ถึงขึ้นมาอย่างแผ่วเบา การดูแลสิ่งที่รักมักมาพร้อมความระมัดระวังเสมอ"},"ICON-0858":{"nm":"สติกเกอร์มุมไดอารี่","de":"แปะสติกเกอร์ทั้งสี่มุมของไดอารี่ แล้วหน้ากระดาษที่สะบัดพลิ้วก็สงบนิ่งราวมีเวทมนตร์ สัมผัสของกระดาษที่ถูกกดเบาๆ พิธีกรรมเล็กๆ ที่ปิดผนึกวันนี้ไว้อย่างเรียบร้อย บันทึกจะแน่นหนาขึ้นเริ่มจากมุม"},"ICON-0859":{"nm":"แผ่นนำเจาะรู","de":"แผ่นที่บอกตำแหน่งที่จะเจาะรูไว้ล่วงหน้า จัดวางตามเส้นประอย่างสงบก็ไม่มีทางพลาด หัวใจที่วัดซ้ำอีกครั้งโดยไม่รีบร้อน ความแม่นยำมักมาอย่างเงียบๆ จากจังหวะพักเล็กๆ นั้นเสมอ"},"ICON-0860":{"nm":"ถาดเศษกระดาษ","de":"เศษกระดาษที่เหลือจากการตัดกรรไกรไหลรวมลงถาดอย่างแผ่วเบา ที่พักชั่วคราวของเศษชิ้นเล็กๆ เพื่อไม่ให้โต๊ะรก ผลพวงจากงานประดิษฐ์ถูกจัดเก็บอย่างเงียบเชียบเช่นนี้แหละ"},"ICON-0861":{"nm":"แท่นหมึกสี","de":"กดแผ่นหมึกเบาๆ แล้วยกขึ้น สีก็เปื้อนชื้นบนปลายนิ้ว แดง เหลือง น้ำเงิน สายรุ้งเล็กๆ ที่ติดมากับตราประทับเดียว มุมนุ่มๆ ที่ปลูกสีสันลงบนกระดาษขาวทีละจุด"},"ICON-0862":{"nm":"ม้วนเทปตกแต่ง","de":"ลวดลายที่คลี่ออกม้วนแล้วม้วนเล่าไม่มีที่สิ้นสุด ลอกออกทีละช่วงแล้วแปะลง มุมที่เคยจืดชืดก็ผลิดอกไม้ขึ้นมา ยิ่งมือขยับยิ่งสวยขึ้น ม้วนเวทมนตร์เล็กๆ ที่ขดกลมรอคอยอยู่"},"ICON-0863":{"nm":"ฝาครอบตราประทับธีม","de":"หมวกเล็กๆ ที่หุ้มหัวตราประทับไว้แน่นสนิทไม่ให้หมึกแห้ง มันเฝ้าคุ้มครองอย่างเงียบๆ เพื่อให้ลวดลายครั้งต่อไปยังคงชัดเจน สีที่เก็บรักษาไว้อย่างดีจะบานสะพรั่งสดใสไม่เปลี่ยนแปลงบนกระดาษแผ่นถัดไปเช่นกัน"},"ICON-0864":{"nm":"เศษเจาะลายตกแต่ง","de":"เศษชิ้นเล็กที่เครื่องเจาะทิ้งไว้เมื่อกดลง เศษกระดาษสีที่ถูกตัดเป็นรูปดาว หัวใจ และกลีบดอกไม้กองรวมกันเป็นเนินเล็กๆ บนฝ่ามือ อัญมณีจิ๋วที่สวยเกินกว่าจะทิ้งไป จนต้องเอาไปแปะไว้ที่ไหนสักแห่งอีกครั้ง"},"ICON-0865":{"nm":"ห่วงป้ายชื่อหลอดด้าย","de":"ป้ายเล็กๆ ที่เขียนชื่อสีของด้ายไว้บนหลอดด้ายแต่ละหลอด เครื่องหมายอ่อนโยนที่บอกที่ทางไว้ก่อนที่มันจะพันกันยุ่งเหยิง ทั้งด้ายที่พันกัน และหัวใจที่พันกัน คลี่คลายง่ายขึ้นมากด้วยป้ายชื่อเพียงแผ่นเดียว"},"ICON-0866":{"nm":"ปกสมุดปักเข็ม","de":"ปกนุ่มที่คลุมหน้าสมุดสักหลาดที่ปักเข็มไว้แน่นเป็นแถว เปิดออกแล้วอุปกรณ์เย็บปักวางเรียงต้อนรับฉันอย่างเป็นระเบียบ สมุดเล่มเล็กที่ให้สิ่งแหลมคมนอนหลับอย่างอ่อนโยน เพื่อไม่ให้ปลายนิ้วบาดเจ็บ"},"ICON-0867":{"nm":"ห่วงตัวอย่างผ้า","de":"หยาบหรือนุ่ม เวลาอันเชื่องช้าที่ค่อยๆ สัมผัสลายผ้าทีละผืนด้วยปลายนิ้วเพื่อเลือก ท่ามกลางเศษผ้าที่จัดเรียงตามสีไว้อย่างเป็นระเบียบ ก่อนจะกลายเป็นเสื้อผ้าหนึ่งชุด ผ้าเงียบๆ รอคอยให้ถูกสัมผัสก่อนเสมอ"},"ICON-0868":{"nm":"ห่วงบ่วงปักผ้า","de":"สอดผ้าเข้ากับห่วงกลมแล้วขันให้แน่น ผ้าก็ตึงราวหน้ากลอง สัญญาณเล็กๆ ที่บอกว่าพร้อมจะปักทีละฝีเข็มแล้ว สิ่งที่ห่วงยึดไว้แน่นนั้นไม่ใช่ผืนผ้า แต่คือหัวใจที่จดจ่อ"},"ICON-0869":{"nm":"แคปซูลจัดหมวดกระดุม","de":"กระดุมที่เคยกลิ้งไปมาต่างพากันเข้านั่งเรียบร้อยแยกตามสีในแต่ละช่องแคปซูล ภูมิปัญญาการดูแลบ้านที่แบ่งเก็บเป็นส่วนเล็กๆ เพื่อไม่ให้หายไปไหน แม้แต่การรวบรวมสิ่งที่กระจัดกระจายก็ยังต้องใช้ความตั้งใจมากเพียงนี้"},"ICON-0870":{"nm":"ที่จับชอล์กตัดเย็บ","de":"ที่จับที่กำชอล์กสำหรับขีดเส้นบนผ้าให้ถือถนัดมือ มันประคองสิ่งที่แตกหักง่ายไว้อย่างมั่นคง ความตั้งใจสงบก่อนหยิบกรรไกร ที่ว่าเส้นแรกต้องตรงจึงจะทำให้เสื้อผ้าตรงตามไปด้วย"},"ICON-0871":{"nm":"ขวดเข็มหมุด","de":"ในขวดใสเข็มหมุดกระทบกันดังกรุ๊งกริ๊ง ส่องกับแสงแดดแล้วปลายเข็มแต่ละอันก็เปล่งประกายเล็กๆ ภาชนะกะทัดรัดที่รวบรวมสิ่งอันตรายเมื่อกระจัดกระจายให้มาอยู่ที่เดียวกัน แล้วให้หลับใหลอย่างสงบ"},"ICON-0872":{"nm":"ม้วนเทปปะซ่อม","de":"แถบมนตร์วิเศษที่แนบติดทันทีเมื่อรีดทับรอยขาด เสื้อผ้าที่ชำรุดก็หายเป็นปกติโดยไม่ต้องเย็บแม้แต่ฝีเข็มเดียว หัวใจที่ปะชุนแทนการทิ้งไปนั้นถูกม้วนเก็บซ้อนกันเป็นชั้นๆ ไว้ในม้วนกลมนี้"},"ICON-0873":{"nm":"กระดาษแบบแพทช์","de":"กระดาษแบบแผ่นหนึ่งที่วาดรูปทรงแพทช์ไว้ล่วงหน้า เส้นประนำทางที่กรรไกรจะผ่านไปอย่างอ่อนโยน การร่างโครงร่างของสิ่งที่อยากทำก่อนเสมอ ความตื่นเต้นเริ่มต้นจากภาพร่างจางๆ นี้เสมอ"},"ICON-0874":{"nm":"ฝาขวดน้ำสีน้ำ","de":"ครอบไว้ที่ปากขวด น้ำสีจะกระเพื่อมแรงแค่ไหนก็ไม่หกแม้แต่หยดเดียว มันปกปิดแม้แต่ความกังวลที่น้ำล้างพู่กันขุ่นๆ จะกระเซ็นเปื้อนโต๊ะ จุกเงียบๆ ที่เฝ้ามุมวาดรูปไว้อย่างสงบ"},"ICON-0875":{"nm":"แถบห่อพาสเทล","de":"พันแถบรอบแท่งพาสเทลที่มีผงสีขาวติดเปื้อน นิ้วก็สกปรกน้อยลง กระดาษที่ห่อสีอ่อนละมุนไว้อย่างแผ่วเบาไม่ให้แตกร่วน ยิ่งเปราะบางเท่าไหร่ยิ่งต้องจับอย่างอ่อนโยนเท่านั้น สีบนกระดาษจึงจะละมุนตามไปด้วย"},"ICON-0876":{"nm":"ฝาต่อความยาวดินสอสี","de":"สวมฝาที่ปลายดินสอสีที่สั้นกุดแล้ว แท่งดินสอก็ยาวขึ้นมาอีกครั้ง หัวใจที่ไม่ทิ้งง่ายๆ เพียงเพราะมันสั้นลง จากปลายนิ้วที่ใช้จนถึงที่สุด สีของภาพวาดก็เข้มขึ้นสมบูรณ์แบบจนถึงช่องสุดท้าย"},"ICON-0877":{"nm":"ตะขอแขวนถ้วยล้างพู่กัน","de":"แขวนถ้วยล้างไว้กับตะขอ หยดน้ำที่หล่นจากพู่กันก็ไหลรินลงมา ก่อนจะระบายสีถัดไป ความเงียบสงบใสกระจ่างสั้นๆ ของการล้างพู่กัน แม้แต่ในเสียงที่ค่อยๆ สะอาดขึ้นนั้นก็ยังมีจังหวะอันเงียบสงบไหลผ่าน"},"ICON-0878":{"nm":"ฝาปลายมีดพาเลท","de":"ฝาเล็กๆ ที่หุ้มใบมีดที่ใช้ป้ายและขูดสีไว้แน่นสนิท เฝ้าคุ้มครองปลายคมไม่ให้ทื่อลงอย่างเงียบๆ พื้นผิวสีที่ป้ายหนาเกิดจากคมมีดที่ได้รับการดูแลอย่างดีเล่มนี้เอง"},"ICON-0879":{"nm":"คลิปหนีบผ้าใบ","de":"คลิปหนีบที่แน่นหนา ดึงผ้าใบให้ตึงยึดกับกรอบไว้ กัดแน่นแล้วพื้นผิวสำหรับวาดก็ตึงเรียบ มีเพียงพื้นฐานที่ไม่โคลงเคลงเท่านั้น ฝีแปรงที่วิ่งอยู่บนนั้นจึงจะเป็นอิสระได้อย่างเต็มที่"},"ICON-0880":{"nm":"สายสะพายกระดานวาดภาพ","de":"สะพายสายไว้ที่บ่า กระดานก็ตามมาด้านหลัง นั่งลงตรงไหนก็ได้ ที่นั่นก็กลายเป็นสตูดิโอส่วนตัวของฉันทันที สตูดิโอเล็กๆ ที่แบกไว้บนหลัง ออกเดินทางเบาๆ เพื่อตามหาทิวทัศน์ที่อยากวาด"},"ICON-0881":{"nm":"หลอดสีอะคริลิก","de":"เติมน้ำหนึ่งหยดก็กลายเป็นรุ่งอรุณ เติมน้อยลงหนึ่งหยดก็กลายเป็นเที่ยงคืน สีน้ำเงินเดียวกันแต่เปิดท้องฟ้าที่แตกต่างกันทุกครั้งบนปลายนิ้ว วินาทีที่บีบหลอดออกมา สีแห่งหัวใจของวันนี้ก็แผ่ซ่านลงบนกระดาษ"},"ICON-0882":{"nm":"แผ่นตัวอย่างไล่สี","de":"กระดาษแผ่นนี้รู้มาก่อนแล้วว่าท้องฟ้ายามเย็นไม่แดงขึ้นในคราวเดียว บันไดเล็กๆ ที่ค่อยๆ ข้ามจากสีจางไปสู่สีเข้ม สายตาเดินอย่างช้าๆ ระหว่างช่วงนั้น เฝ้าติดตามเวลาที่สีค่อยๆ สุกงอมอย่างแผ่วเบา"},"ICON-0883":{"nm":"ฝาปลายไม้โครเชต์","de":"เกราะป้องกันเล็กเท่าปลอกนิ้วที่สวมไว้ก่อนที่เส้นด้ายจะบาดนิ้ว มือที่ถักไหมมานานย่อมรู้ดี ต้องไม่บาดเจ็บก่อน จึงจะพาไปถึงฝีเข็มสุดท้ายได้อย่างอ่อนโยน"},"ICON-0884":{"nm":"ห่วงมาร์กเกอร์ถักไหม","de":"เครื่องหมายเดียวก็ทำให้ชัดเจนอีกครั้งว่าถักมาถึงไหนแล้ว ความอุ่นใจที่ไม่ต้องนับฝีเข็มเดิมซ้ำสองครั้ง หัวใจก็เช่นกัน ต่อเมื่อทำเครื่องหมายจุดที่ผ่านมาไว้เบาๆ เท่านั้นจึงจะไม่หลงทาง"},"ICON-0885":{"nm":"จี้นับแถวถักไหม","de":"หลักฐานเงียบๆ ว่าถักครบหนึ่งแถวแล้วซ้อนกันขึ้นทีละช่อง แม้งานที่ดูเหมือนไม่มีวันจบ เมื่อนับทีละอย่างก็ผ่านครึ่งทางไปโดยไม่รู้ตัว การนับเล็กๆ ช่วยพยุงหัวใจของวันนี้ให้ทนไปจนถึงที่สุด"},"ICON-0886":{"nm":"เข็มกลัดจัดปลายด้าย","de":"ปล่อยปลายด้ายที่คลายออกทิ้งไว้เฉยๆ ก็ไม่รู้ว่าปมต่อไปจะพันกันตรงไหน สัมผัสที่จัดการล่วงหน้าในที่ที่มองไม่เห็น ความอ่อนโยนมักเคลื่อนไหวก่อนในที่ที่ไม่มีใครเห็นเช่นนี้เสมอ"},"ICON-0887":{"nm":"เชือกฝึกผูกปม","de":"ปมเงื่อนกระตุก ปมโบว์ ปมแหวน มัดแล้วคลายเชือกเส้นเดิมซ้ำแล้วซ้ำเล่าจนมือจดจำรูปทรงได้ เมื่อปลายนิ้วที่เคยงุ่มง่ามพลันคล่องแคล่วขึ้นในคืนหนึ่ง เชือกเส้นนั้นเองที่รู้ก่อนใคร"},"ICON-0888":{"nm":"แถบป้ายไหมพรม","de":"แถบเล็กๆ ที่จดไว้ว่าไหมพรมแต่ละไจหนาแค่ไหนสีอะไร นิสัยที่เกิดจากคืนที่หาไหมพรมสีเดียวกันไม่เจอหลังจากใช้หมดไปแล้ว บันทึกคือโน้ตอ่อนโยนที่เขียนถึงตัวเองในอนาคต"},"ICON-0889":{"nm":"ไม้บรรทัดวัดเกจ","de":"สิบเซนติเมตรมีกี่ฝีเข็ม—ตัวเลขน้อยนิดนั้นกำหนดขนาดของเสื้อผ้าทั้งชุด การที่ชิ้นเล็กเท่าฝ่ามือถือครองขนาดของทั้งหมดไว้นั้น เมื่อยกขึ้นมาดูก็รู้สึกหนักหน่วงพอสมควร"},"ICON-0890":{"nm":"เครื่องหมายรังกระดุม","de":"ก่อนติดกระดุม จุดหนึ่งจุดถูกทำเครื่องหมายไว้ก่อนว่าจะเจาะตรงไหน ด้วยเครื่องหมายที่จะหายไปในไม่ช้านี้เอง สาบเสื้อจึงไม่เบี้ยว ความตั้งใจมักหลงเหลืออยู่อย่างเงียบๆ ในที่ที่ไม่มีใครเห็นในที่สุดเสมอ"},"ICON-0891":{"nm":"ห่วงพู่จิ๋ว","de":"เหมือนพู่ที่ปลายโนรีแก ห่วงเล็กๆ หนึ่งวงสร้างการแกว่งไกว สายตามักเฝ้ามองสิ่งที่ห้อยอยู่และไหวเบาๆ อย่างสงบเสมอ ลายผิวที่ค่อยๆ มีชีวิตขึ้นอย่างเงียบๆ ทุกครั้งที่ลมพัดผ่าน"},"ICON-0892":{"nm":"ขวดสีจิ๋ว","de":"ไม่ใช่การประหยัด แต่การใช้อย่างแม่นยำต่างหากคือวิธีจัดการสีที่ถูกต้อง สีที่หยดเดียวก็เพียงพอ มือที่คะเนไว้ข้างขวดเล็ก ความสุขุมมาจากการวางความโลภลงสักครั้งหนึ่ง"},"ICON-0893":{"nm":"แท่งกระดาษทรายจิ๋ว","de":"เริ่มจากด้านหยาบแล้วค่อยๆ ย้ายไปด้านละเอียด ไม่มีพื้นผิวใดในโลกที่เรียบลื่นได้ในครั้งเดียว จากปลายนิ้วที่ลดเกรนลงทีละขั้น จุดที่เคยหยาบก็ค่อยๆ นุ่มนวลขึ้น"},"ICON-0894":{"nm":"ที่รองคีบชิ้นส่วนโมเดล","de":"ถือชิ้นส่วนที่ทากาวไว้ด้วยมือก็ทิ้งรอยนิ้วมือไว้ หนีบไว้กับคีมอย่างแผ่วเบา มือก็เป็นอิสระ และการแห้งก็จบลงอย่างเงียบๆ ด้วยตัวมันเอง แม้แต่การรอคอยก็เบาลงเมื่อมีใครสักคนคอยประคองไว้"},"ICON-0895":{"nm":"แผ่นรองงานกาว","de":"หยดกาวหยดหนึ่งตกลงบนโต๊ะ รอยเปื้อนก็อยู่ไปอีกนาน นิสัยที่ปูแผ่นรองไว้ก่อนเสมอ บางทีครึ่งหนึ่งของงานอาจเริ่มต้นจากความปรารถนาที่ไม่อยากทำให้ที่นั่นสกปรกนั่นเอง"},"ICON-0896":{"nm":"ช่องแยกชิ้นส่วน","de":"ผสมชิ้นส่วนรูปทรงเดียวกันหลายสิบชิ้นเข้าด้วยกัน การประกอบก็กลายเป็นเขาวงกตในพริบตา สัมผัสที่แบ่งเก็บไว้ทีละช่องช่วยลดเวลาที่จะหลงทางไว้ล่วงหน้า การจัดระเบียบคือความใจดีที่มอบให้ตัวเองในอนาคต"},"ICON-0897":{"nm":"ชิปลำดับการประกอบ","de":"ชิปเล็กๆ ที่จดไว้ว่าจะใส่ชิ้นส่วนหมายเลขไหนก่อน รักษาลำดับไว้แล้วก็ไม่พังทลายง่ายๆ ทั้งโมเดล และวันไหนก็ตามที่ค่อยๆ สร้างขึ้นทีละขั้นอย่างระมัดระวัง ล้วนแข็งแกร่งขึ้นบนคำสัญญาอันเงียบงันนั้น"},"ICON-0898":{"nm":"ตะขอแขวนพู่กันจิ๋ว","de":"วางพู่กันที่ใช้แล้วนอนราบ ขนพู่กันก็ถูกกดจนงอ ที่แขวนกลับหัวเพื่อระบายความชื้นออก คนที่เก็บรักษาเครื่องมือไว้ข้างกายนานๆ กลับยิ่งวุ่นวายและอ่อนโยนมากขึ้นหลังงานเสร็จสิ้นเสียอีก"},"ICON-0899":{"nm":"กระปุกเศษพลาสติกโมเดล","de":"กระปุกที่เศษชิ้นส่วนที่ตัดออกจากเฟรมมารวมกันอย่างเงียบๆ แม้ดูเหมือนถูกทิ้งขว้าง แต่สักวันหนึ่งมันจะกลับมาเป็นรายละเอียดเล็กๆ กระปุกรู้ดีว่าแม้แต่สิ่งที่เหลืออยู่ก็ยังมีคิวของตัวเอง มันจึงรอคอยอย่างเงียบเชียบ"},"ICON-0900":{"nm":"ฝาสเปรย์เคลือบเงา","de":"ชั้นสุดท้าย ถ้าฉีดใกล้เกินไปก็จะไหลย้อยลงมาทันที จากระยะห่างหนึ่งคืบ เบาๆ เบาๆ การเคลือบเงาบางทีก็เป็นการฝึกวางความโลภของหัวใจลงสักครั้งหนึ่งเช่นกัน"},"ICON-0901":{"nm":"ตลับไส้ดินสอกด","de":"ไส้ดินสอกดบางเฉียบมักหักง่ายเมื่ออยู่ในกระเป๋า เมื่อวางเรียงในตลับเล็ก ๆ อย่างเป็นระเบียบ ไส้แม้แต่แท่งเดียวก็ไม่สูญเปล่า การจัดระเบียบท้ายที่สุดแล้วคือหัวใจอันเงียบงันที่ถนอมตัวเองในวันพรุ่งนี้ไว้ล่วงหน้า"},"ICON-0902":{"nm":"ปลอกยางลบ","de":"เสื้อกระดาษเล็ก ๆ ที่สวมให้ยางลบ ยิ่งดำคล้ำด้วยรอยมือมากเท่าไร ก็ยิ่งสะสมร่องรอยของการแก้ไขไว้มากเท่านั้น การลบก็เป็นการอนุญาตอันอ่อนโยนให้กลับไปเริ่มต้นใหม่ได้เสมอ"},"ICON-0903":{"nm":"กระบอกเก็บหัวปากกา","de":"หัวปากกาแห้งแล้วจะแตก กระแทกแล้วจะโค้งงอ กระบอกเล็ก ๆ ใบเดียวที่ใช้วางเก็บแยกไว้ต่างหาก ช่วยรักษาลายเส้นลายมือให้คงอยู่ได้นาน เครื่องมือที่ถูกทะนุถนอมก็จะลื่นไหลอย่างอ่อนโยนตอบแทนกลับมาเสมอ"},"ICON-0904":{"nm":"ตัวอย่างหมึกปากกาหมึกซึม","de":"หมึกที่หยดทดลองทีละหยด สีที่เคยคิดว่าเป็นสีเขียวอมฟ้ากลับกลายเป็นทะเลลึกเมื่อลงบนกระดาษ สีสันเป็นสิ่งที่ต้องพบเจอด้วยตัวเองเสมอ เพราะสีที่วาดไว้ในใจมักคลาดเคลื่อนไปจากความจริงอยู่บ่อยครั้ง"},"ICON-0905":{"nm":"กระป๋องคั่นหนังสือรูปธง","de":"ธงเล็ก ๆ ที่แทรกไว้เบา ๆ ตรงจุดที่อ่านค้างไว้ เมื่อเปิดหนังสือครั้งต่อไป ตัวเราของเมื่อวานก็โบกมือรอคอยอยู่ตรงนั้น แม้แต่จุดที่หยุดพักก็กลายเป็นคำสัญญา นี่คืองานอันอ่อนโยนของเครื่องหมายเล็ก ๆ ชิ้นนั้น"},"ICON-0906":{"nm":"แพ็กธงกระดาษโน้ต","de":"ฉีกแปะไปหนึ่งแผ่น เรื่องราวก็เริ่มต้นใหม่จากตรงนั้นได้ทันที เมื่อธงเล็ก ๆ เรียงรายอยู่ริมหนังสือ ความคิดที่เคยกระจัดกระจายก็ค่อย ๆ รวมกันเป็นแผนที่หนึ่งเล่มอย่างเป็นระเบียบ"},"ICON-0907":{"nm":"แม่เหล็กรวมคลิป","de":"แม่เหล็กเล็ก ๆ ที่กวาดรวมคลิปที่กระจัดกระจายไว้ในคราวเดียว ยิ่งของชิ้นเล็กก็ยิ่งหายง่าย พลังแห่งการรวบรวมเพียงหนึ่งเดียวจึงช่วยกอบกู้โต๊ะทำงานที่ยุ่งเหยิงไว้อย่างเงียบ ๆ แม้แต่แรงดึงดูดก็ยังมีความอ่อนโยนซ่อนอยู่"},"ICON-0908":{"nm":"เซตฝาครอบดินสอ","de":"หมวกเล็ก ๆ ที่สวมปลายดินสอไว้เพื่อปกป้องข้างในกระเป๋า สิ่งที่แหลมคมมักจะทิ่มแทงอะไรสักอย่างเสมอ จึงต้องการมือที่คอยปิดคลุมไว้อย่างอ่อนโยน ให้คมอยู่เสมอ แต่ไม่ทำร้ายใคร"},"ICON-0909":{"nm":"สติกเกอร์ป้ายชื่อโต๊ะ","de":"ในวินาทีที่เขียนชื่อแล้วแปะไว้หน้าโต๊ะ พื้นที่ตรงนั้นก็กลายเป็นของใครสักคนอย่างแท้จริงเป็นครั้งแรก แม้แต่พื้นที่เล็กเท่าฝ่ามือก็มีเจ้าของ ท่าทีที่วางใจลงตรงนั้นก็เปลี่ยนไปโดยสิ้นเชิง"},"ICON-0910":{"nm":"ฝาครอบด้ามจับเชือกกระโดด","de":"ฝาที่สวมไว้ก่อนปลายด้ามจับจะสึกจนแตกร้าว จังหวะของเชือกที่หมุนมาแล้วนับพันครั้งนั้น ฝ่ามือจดจำได้ก่อนสมองเสียอีก จังหวะที่สลักไว้ในร่างกายไม่ใช่สิ่งที่ลืมเลือนได้ง่าย ๆ"},"ICON-0911":{"nm":"สายรัดห่วงโยคะ","de":"จับห่วงแล้วค่อย ๆ เปิดร่างกายออก ยิ่งสายดึงตึงมากเท่าไร ไหล่ที่เกร็งแข็งก็ยิ่งคลายออกทีละชั้น การยืดกล้ามเนื้อไม่ใช่การฝืนดึง แต่ใกล้เคียงกับการรอคอยอย่างสงบจนกว่าร่างกายจะเปิดออกเองมากกว่า"},"ICON-0912":{"nm":"กล่องใส่ลูกปิงปอง","de":"ลูกสีขาวที่เบาจนกลิ้งไปไกล แต่แค่เหยียบก็บุบทันที กล่องเล็ก ๆ ใบเดียวปกป้องลูกที่เปราะบางที่สุดนั้นไว้จนถึงการแข่งขันครั้งต่อไป ความแข็งแกร่งมักมาจากการถูกห่อหุ้มไว้อย่างอ่อนโยน"},"ICON-0913":{"nm":"เทปพันด้ามแบดมินตัน","de":"พันหนึ่งชั้นอย่างประณีตรอบด้ามจับที่ลื่นด้วยเหงื่อ บนแกร็ปที่พันไว้อย่างดี ไม้แร็กเกตก็กลายเป็นส่วนหนึ่งของมือ เคล็ดลับของการตีด้วยความรู้สึกมากกว่าแรง ซ่อนอยู่ในชั้นบาง ๆ ชั้นเดียวนี้เอง"},"ICON-0914":{"nm":"ชิปคะแนนตัวจิ๋ว","de":"หนึ่งแต้ม แล้วอีกหนึ่งแต้ม เลื่อนชิปเล็ก ๆ สะสมคะแนนขึ้นทีละน้อย เมื่อมองเห็นตัวเลขชัดเจน เกมก็ยิ่งเข้มข้นขึ้น และความกล้าที่จะไล่ตามให้ทันในแต้มที่ห่างกันเพียงหนึ่งก็ค่อย ๆ ผุดขึ้นมาอย่างเงียบ ๆ"},"ICON-0915":{"nm":"คลิปจัดทิศรองเท้าผ้าใบ","de":"ปลายรองเท้าที่วางเรียงไว้อย่างเป็นระเบียบหันหน้าไปทิศเดียวกันเสมอ มือที่หมุนเล็กน้อยตอนถอดรองเท้า การจัดระเบียบเล็ก ๆ เพียงเรื่องเดียวทำให้ก้าวเดินในเช้าวันพรุ่งนี้เบาสบายขึ้นอีกนิด"},"ICON-0916":{"nm":"สายคล้องนกหวีด","de":"แขวนนกหวีดไว้ที่คอ ก็มีสิทธิ์บอกให้ทุกคนหยุดได้ ภาพของสนามทั้งสนามหยุดนิ่งพร้อมกันด้วยเสียงสั้น ๆ เพียงครั้งเดียว หัวใจที่เชื่อในเสียงเล็ก ๆ นั้นมารวมกันจนกลายเป็นคำสัญญา"},"ICON-0917":{"nm":"กระบอกเก็บเข็มสูบลม","de":"แม้แต่ลูกบอลที่ลมแฟบก็ตึงกลับมาได้ด้วยเข็มเล็ก ๆ เพียงเล่มเดียว เข็มที่เก็บรักษาไว้อย่างดีในกระบอกเล็ก ๆ นั้น หากหายไปเมื่อไรที่สูบทั้งอันก็ไร้ประโยชน์ทันที เมื่อสิ่งเล็กที่สุดกลับสำคัญที่สุด"},"ICON-0918":{"nm":"กรวยจิ๋วปักเขต","de":"จากตรงนี้ถึงตรงนั้น กรวยเล็ก ๆ วาดเส้นแบ่งเขตที่มองไม่เห็นให้ปรากฏขึ้น แม้ไม่มีเส้นใด ๆ ผู้คนก็ยังต่อแถวตามเครื่องหมายนั้นได้เองอย่างเป็นธรรมชาติ ความเป็นระเบียบเติบโตขึ้นอย่างเงียบ ๆ จากสัญญาณเล็ก ๆ เช่นนี้"},"ICON-0919":{"nm":"ถุงใส่โทเคน","de":"ถุงที่รวบรวมโทเคนที่ดังกรุ๊งกริ๊งไว้ในที่เดียว รูดปากถุงให้แน่นก็ไม่มีวันกระจัดกระจาย แม้แต่สิ่งเล็กน้อยที่สุดก็ต้องมีที่ให้บรรจุอยู่ ถึงจะทำหน้าที่ของตัวเองได้อย่างสมบูรณ์ ถุงใบนี้แสดงให้เห็นโดยไม่ต้องพูดอะไรเลย"},"ICON-0920":{"nm":"แผ่นรองสับไพ่","de":"บนโต๊ะที่ลื่น ไพ่มักจับได้ไม่ถนัดมือ แผ่นรองเพียงแผ่นเดียวทำให้ทั้งการสับและการหยิบไพ่ราบรื่นขึ้นมาก แม้แต่การเล่นให้สนุกก็ยังมีการเตรียมพื้นผิวไว้ล่วงหน้าอย่างอ่อนโยน"},"ICON-0921":{"nm":"ที่ปกป้องมุมกระดานเกม","de":"เมื่อคืนเล่นบอร์ดเกมจบลง ใครสักคนก็จะเงียบ ๆ เก็บมุมทั้งสี่ของกระดานก่อนใคร เพราะรู้ว่ารอยพับที่ลึกขึ้นจะทำให้รอบต่อไปบิดเบี้ยว ปลายนิ้วที่คลี่มุมให้เรียบนั้นแฝงความปรารถนาให้ได้เล่นด้วยกันอีกครั้งในวันพรุ่งนี้"},"ICON-0922":{"nm":"ฝาถ้วยเขย่าลูกเต๋า","de":"ช่วงเวลาสั้น ๆ ที่ทุกคนเขย่า กลิ้ง และกลั้นหายใจไปพร้อมกัน มันคือเพดานเล็ก ๆ ที่คอยกันไม่ให้ลูกเต๋ากระโดดออกไป ใต้ฝานั้น โชคของวันนี้พักหายใจอยู่ชั่วครู่ ก่อนจะกลิ้งออกมาพร้อมเสียงดังกึกก้อง"},"ICON-0923":{"nm":"แผ่นจัดเรียงกระเบื้อง","de":"ยิ่งใครสนุกกับการเล่นมากเท่าไร แถวก็ยิ่งเบี้ยวมากเท่านั้น การค่อย ๆ ดันกระเบื้องที่เอียงให้กลับมาเรียงตรงอย่างเงียบ ๆ การจัดเรียงคือมือที่รับเอาความเร่งรีบตื่นเต้นของใครบางคนไว้อย่างอ่อนโยน"},"ICON-0924":{"nm":"กระป๋องชิปคะแนน","de":"ยิ่งชิปในกระป๋องเต็มขึ้นเท่าไร บรรยากาศของเกมก็ยิ่งร้อนแรงขึ้นตามไปด้วย เมื่อคะแนนกลม ๆ กระทบกันดังกึกก้องอยู่ในฝ่ามือ เสียงนั้นเองที่กลายเป็นความสนุกก่อนเรื่องแพ้ชนะเสียอีก"},"ICON-0925":{"nm":"แหวนบอกตาเดิน","de":"แหวนเล็ก ๆ ที่บอกว่าถึงตาของเธอแล้ว เพียงชั่วขณะที่เลื่อนสวมไปอีกช่อง สายตาของทุกคนก็มารวมอยู่ที่ฉันอย่างเงียบสงบ มันคือวงแหวนที่หมุนช้า ๆ อยู่ระหว่างการรอคอยและความตื่นเต้น"},"ICON-0926":{"nm":"ฐานรองหมากเกม","de":"หมากที่ล้มง่ายยิ่งต้องมีฐานที่มั่นคง ฐานเพียงชิ้นเดียวช่วยยึดตำแหน่งไว้ได้แม้บนกระดานที่โคลงเคลงเล็กน้อย สิ่งเล็ก ๆ ต้องยืนหยัดไว้ให้ได้ สิ่งใหญ่ที่อยู่ข้างบนจึงจะตั้งตระหง่านได้"},"ICON-0927":{"nm":"คลิปหนีบคู่มือ","de":"คู่มือที่เปิดค้างไว้มักพลิกหน้าเผลอไผลอยู่เสมอ ก่อนที่ลมจะพัดพาหน้ากระดาษหนีไป คลิปนี้จะกัดหน้าหนึ่งไว้อย่างเงียบ ๆ ต้องยึดกฎกติกาไว้ให้มั่น การเล่นจึงจะดำเนินไปได้จนจบ"},"ICON-0928":{"nm":"สายคล้องกล่องปิ๊กกีตาร์","de":"ปิ๊กกีตาร์มักหลุดจากนิ้วในช่วงที่สนุกที่สุดเสมอ สายเดียวที่ห้อยจากกล่องช่วยกันไม่ให้มันหนีหายไปเช่นนั้น มีเพียงผู้ที่เคยผ่านค่ำคืนที่ดนตรีต้องหยุดชะงักเท่านั้นที่จะซาบซึ้งกับสายเส้นนี้"},"ICON-0929":{"nm":"กระบอกเก็บลิ้นเครื่องเป่า","de":"ลิ้นเครื่องเป่าจะสูญเสียเสียงของตัวเองทันทีที่แห้ง ในกระบอกที่ชุ่มชื้น เศษต้นอ้อบาง ๆ ชิ้นหนึ่งรอคอยการบรรเลงครั้งต่อไป ที่แห่งนี้คือที่พักลมหายใจไว้ก่อน ก่อนจะเป่าลมหายใจกลับเข้าไปอีกครั้ง"},"ICON-0930":{"nm":"ที่หมุนพันสายเครื่องดนตรี","de":"เมื่อสายหย่อนลง เสียงก็ค่อย ๆ ตกต่ำตามไปด้วยอย่างเงียบ ๆ การค่อย ๆ หมุนที่จับเพื่อดึงความตึงกลับคืนมา ความใส่ใจนั้นมาจากปลายข้อมือเสมอ เสียงที่เรียบร้อยเริ่มต้นจากการจัดระเบียบเล็ก ๆ เช่นนี้เอง"},"ICON-0931":{"nm":"ผ้าเช็ดเครื่องดนตรี","de":"เมื่อการบรรเลงจบลง หยาดเหงื่อจาง ๆ ก็ยังคงหลงเหลืออยู่บนเครื่องดนตรีเช่นกัน ปาดผ้านุ่ม ๆ ลงไปครั้งหนึ่ง ความเงางามก็กลับคืนมาพร้อมกับเสียงเพลงของวันนี้ที่ค่อย ๆ สงบลง หัวใจที่ทะนุถนอมมักปรากฏให้เห็นในขั้นตอนสุดท้ายเสมอ"},"ICON-0932":{"nm":"ฝาครอบหมุดจูนสาย","de":"หากปล่อยหมุดจูนไว้เปล่าเปลือย สนิมก็จะจับโดยไม่ทันรู้ตัว ฝาครอบเล็ก ๆ เพียงชิ้นเดียวช่วยชะลอฤดูกาลของโลหะให้ช้าลงหนึ่งจังหวะ คนที่ดูแลมุมที่มองไม่เห็นก่อนใครนั่นแหละคือคนที่บรรเลงได้ยาวนาน"},"ICON-0933":{"nm":"ไฟหนีบโน้ตเพลง","de":"หลังเวทีอันมืดมิด มีบางช่วงเวลาที่ต้องให้มีเพียงโน้ตเพลงเท่านั้นที่สว่างไสว มันคือโคมไฟเล็ก ๆ ที่หนีบติดขาตั้งโน้ต ค่อย ๆ ปล่อยแสงลงมาอย่างแผ่วเบา แสงสว่างเพียงหยิบมือที่ส่องทางใต้เท้าไม่ให้ตัวโน้ตหลงทาง"},"ICON-0934":{"nm":"ฝาปิดเสียงซ้อมดนตรี","de":"การซ้อมยามเช้ามืดมักปะทะกับการนอนหลับของเพื่อนบ้านอย่างเงียบ ๆ เสมอ สวมฝาเพียงชิ้นเดียว เสียงดังกึกก้องก็ลดเหลือเพียงเสียงกระซิบ ดนตรีบางบทเติบโตขึ้นได้ก็ด้วยการปกป้องหลับใหลอันหอมหวานของใครสักคน"},"ICON-0935":{"nm":"สติกเกอร์แผ่นกลองซ้อม","de":"เครื่องหมายเล็ก ๆ ที่ติดอยู่บนแผ่นกลอง ตีตรงไหนจะได้เสียงแบบไหน ดวงตาเรียนรู้เส้นทางก่อนที่มือจะจดจำได้เสียอีก จังหวะถูกสลักลงในร่างกายอย่างช้า ๆ เช่นนี้เอง"},"ICON-0936":{"nm":"ชิปจดทำนองเพลง","de":"ทำนองที่ฮัมเพลงอยู่จะเลือนหายไปอย่างรวดเร็วหากไม่รีบจับไว้ ไม่กี่ห้องเพลงที่รีบจดลงบนชิปในบางครั้งก็เติบโตขึ้นเป็นเพลงเต็มเพลงในภายหลัง แรงบันดาลใจมักย้อนกลับมาหามือที่หมั่นจดบันทึกอยู่เสมอ"},"ICON-0937":{"nm":"แถบรัดปกหนังสือ","de":"มันน่ารำคาญเมื่อหนังสือที่อ่านค้างไว้เปิดกางออกเองในกระเป๋าอย่างไร้ระเบียบ แถบเพียงเส้นเดียวรัดหน้าหนังสือให้อยู่นิ่ง ๆ หน้ากระดาษก็สงบเรียบร้อยขึ้น มันคือคำสัญญาที่จะพับเก็บทุกอย่างให้เรียบร้อยไว้สำหรับหน้าถัดไป"},"ICON-0938":{"nm":"แหวนช่วยเปิดหน้าหนังสือ","de":"วันที่อยากถือหนังสือเปิดค้างด้วยมือเดียวพร้อมจิบกาแฟอุ่น ๆ ห่วงที่สวมนิ้วจะช่วยจับหน้ากระดาษแทนมือให้ ความสบายเล็ก ๆ น้อย ๆ เริ่มต้นจากสิ่งประดิษฐ์เล็ก ๆ เช่นนี้เอง"},"ICON-0939":{"nm":"ชิปจับเวลาอ่านหนังสือ","de":"ตั้งใจว่าจะอ่านแค่บทเดียว แต่พอนั่งลงกลับกลายเป็นดึกดื่นโดยไม่รู้ตัว กดชิปเพื่อกำหนดเวลาไว้ การอ่านหนังสือก็มีจุดพักเช่นกัน ยิ่งเป็นสิ่งที่รักมากเท่าไร ก็ยิ่งต้องการความกล้าอันอ่อนโยนที่จะรู้จักหยุดพักมากเท่านั้น"},"ICON-0940":{"nm":"ฝาครอบมุมหนังสือ","de":"ยิ่งหนังสือเล่มไหนเป็นที่รัก มุมของมันก็ยิ่งสึกกร่อนไปก่อนอย่างเงียบ ๆ สวมฝาเพียงชิ้นเดียว มุมของปกก็ถูกปกป้องให้โค้งมนอยู่เสมอ มันคือชุดเกราะเล็ก ๆ ที่สวมใส่ไว้เพื่อความปรารถนาที่อยากเก็บมันไว้ข้างกายไปอีกนานแสนนาน"},"ICON-0941":{"nm":"แถบจดบันทึกความรู้สึก","de":"มีบางช่วงเวลาที่ประโยคเพียงบรรทัดเดียวทำให้หัวใจหล่นวูบลงไป ความรู้สึกที่คัดลอกลงบนแถบกระดาษยังคงอยู่ในหน้านั้นราวกับที่คั่นหนังสือ นี่คืออุณหภูมิอันอบอุ่นของเส้นใต้ที่มีเพียงคนที่อ่านแล้วเท่านั้นจะรู้จัก"},"ICON-0942":{"nm":"ป้ายกำหนดคืนหนังสือห้องสมุด","de":"วันกำหนดคืนมักมาถึงเร็วกว่าที่คิดอยู่เสมอสักวัน เมื่อวันที่เขียนไว้บนป้ายค่อย ๆ ผลักดันหลังเราอย่างเงียบ ๆ แม้แต่หนังสือที่ยืมมาก็ยังมีมารยาทของการจบลงอย่างสมบูรณ์ ห้องสมุดรอคอยเช่นนั้นเพื่อมือของคนคนต่อไป"},"ICON-0943":{"nm":"ไฟหนีบอ่านหนังสือ","de":"คืนที่ตื่นอยู่คนเดียวอ่านหนังสือข้างครอบครัวที่หลับใหล เพียงแสงเล็ก ๆ ที่หนีบไว้ตรงขอบหนังสือก็เพียงพอแล้ว ไม่จำเป็นต้องผลักไล่ความมืดออกไปทั้งหมด แค่หนึ่งหน้าก็เพียงพอสำหรับช่วงเวลาอันเงียบสงบนั้น"},"ICON-0944":{"nm":"การ์ดกลิ่นหนังสือ","de":"หนังสือเก่ามีกลิ่นหอมของแสงแดดปะปนกับกระดาษ การ์ดที่ว่ากันว่าเก็บกลิ่นนั้นไว้ในแผ่นเดียว เมื่อเปิดออกก็ทำให้ตรอกร้านหนังสือเก่ากลับมามีชีวิตอยู่ที่ปลายจมูกชั่วครู่ ความทรงจำก็ปักที่คั่นหนังสือไว้ด้วยกลิ่นได้เช่นกัน"},"ICON-0945":{"nm":"หมุดปักบอกหน้าที่อ่านถึง","de":"อ่านถึงไหนแล้วนะ หมุดเล็ก ๆ ที่ลบคำถามอันคลุมเครือนั้นออกไป ปักไว้ที่ประโยคสุดท้าย ตัวเราของวันพรุ่งนี้ก็จะไม่หลงทางอีกต่อไป มันคือเครื่องหมายอันอ่อนโยนที่จดจำจุดที่หยุดพักไว้แทนเรา"},"ICON-0946":{"nm":"จี้ห่วงสายคล้องมือถือ","de":"จี้เพียงชิ้นเดียวที่ห้อยบนสายคล้องมือถือทำให้คนดูแตกต่างไปเล็กน้อย สีที่ชอบ รูปทรงที่ชอบ รสนิยมเล็ก ๆ ที่ถือไว้ในมือช่วยเขย่าอารมณ์ของวันนั้นให้แผ่วไหวเบา ๆ"},"ICON-0947":{"nm":"ฝาครอบป้องกันเลนส์กล้อง","de":"ชะตากรรมของภาพถ่ายในทริปเดินทางฝากไว้กับเลนส์เพียงชิ้นเดียว ชั่วขณะที่ถอดฝาครอบออกคือความพร้อมของหัวใจที่จะกดชัตเตอร์ มันคือพิธีกรรมเล็ก ๆ ที่เบิกตาก่อนสิ่งอื่นใด ก่อนจะบันทึกทัศนียภาพลงไป"},"ICON-0948":{"nm":"จุกอุดพอร์ตชาร์จ","de":"ฝุ่นในกระเป๋ามักเล็งเป้าไปที่ช่องชาร์จเป็นอันดับแรกเสมอ อุดช่องเล็ก ๆ นั้นไว้ด้วยจุกเพียงชิ้นเดียว ขั้วต่อก็สะอาดอยู่ได้นาน นี่คือความขยันหมั่นเพียรที่ดูแลไปถึงช่องว่างที่มองไม่เห็น"},"ICON-0949":{"nm":"ห่วงป๊อปตั้งมือถือ","de":"ตั้งมือถือเอียงไว้เพียงเพื่อดูวิดีโอสักคลิปให้สบายขึ้น กางห่วงป๊อปที่ติดอยู่ด้านหลังออก มือและหน้าจอก็ผ่อนคลายขึ้นอีกนิด ฐานเล็ก ๆ ที่ผุดขึ้นมาเพียงชิ้นเดียวช่วยยืดช่วงเวลายามเย็นให้เนิบช้าลง"},"ICON-0950":{"nm":"แผ่นเช็ดหน้าจอ","de":"หน้าจอที่เต็มไปด้วยรอยนิ้วมือทำให้ใจพลอยพร่ามัวไปด้วยไม่รู้ทำไม เช็ดปาดด้วยแผ่นแปะเพียงครั้งเดียว โลกก็กลับมาชัดเจนอีกครั้ง ความสะอาดบางครั้งก็เป็นเพียงงานสั้น ๆ เพียงปลายนิ้วเดียว"},"ICON-0951":{"nm":"กล่องเข็มจิ้มซิม","de":"เข็มจิ้มซิมคือนางฟ้าที่หายตัวไปเฉพาะในตอนที่ต้องการมันที่สุด เก็บไว้ในช่องเดียวของกล่อง ก็ไม่ต้องเที่ยวควานหากิ๊บติดผมไปทั่วบ้านอีกต่อไป ความเป็นระเบียบเล็ก ๆ ช่วยกอบกู้ช่วงเวลาเร่งด่วนไว้อย่างเงียบ ๆ"},"ICON-0952":{"nm":"สติกเกอร์แผ่นชาร์จไร้สาย","de":"คืนที่วางไว้เฉย ๆ บนแผ่นชาร์จแล้วพลังงานก็เติมเต็มขึ้นเอง สติกเกอร์ที่แปะไว้ช่วยทำเครื่องหมายจุดที่มือถือควรวางนอนลงเล็กน้อย กระแสไฟฟ้าที่มองไม่เห็นเติมพลังของวันหนึ่งวันให้เต็มโดยไร้เสียง"},"ICON-0953":{"nm":"สติกเกอร์ปิดบังการแจ้งเตือน","de":"การแจ้งเตือนที่ไม่อยากเห็นปิดบังไว้เสียก็สบายใจกว่า สติกเกอร์เพียงแผ่นเดียวช่วยกล่อมแสงเรืองรองเล็ก ๆ ยามรุ่งสางให้สงบลง บางครั้งการไม่มองก็เป็นวิธีอันอ่อนโยนในการปกป้องตัวเองเช่นกัน"},"ICON-0954":{"nm":"ห่วงป้องกันเลนส์","de":"ในชั่วขณะที่เลนส์กล้องแตะพื้น หัวใจก็วูบหล่นฮวบลงไปด้วย ห่วงที่ล้อมรอบไว้เพียงวงเดียวช่วยกันการตกกระแทกเล็กน้อยนั้นไว้ได้อย่างแนบเนียน มันคือขอบที่ปกป้องดวงตาที่เก็บบันทึกความทรงจำเป็นสิ่งแรก"},"ICON-0955":{"nm":"ป้ายชื่อสายเคเบิล","de":"การคัดแยกสายของตัวเองออกมาจากกองสายเคเบิลที่พันกันยุ่งเหยิงในที่สุด ป้ายเพียงชิ้นเดียวก็ทำให้สายชาร์จมีชื่อเป็นของตัวเองเสียที มันคือธงเล็ก ๆ ที่ชี้ทางท่ามกลางสายที่สับสนวุ่นวาย"},"ICON-0956":{"nm":"กระเป๋าใส่ที่ชาร์จ","de":"เครื่องชาร์จในกระเป๋าเดินทางมักพันกันทะเลาะเบาะแว้งอยู่เสมอ รวบรวมไว้อย่างเป็นระเบียบในกระเป๋าใบเดียว ในที่สุดพวกมันก็คืนดีกัน ศิลปะของการจัดเก็บของอยู่ที่การเรียกสิ่งที่กระจัดกระจายให้มารวมกันในที่เดียวอย่างอ่อนโยน"},"ICON-0957":{"nm":"ป้ายชื่อปลั๊กพ่วง","de":"รูของปลั๊กพ่วงล้วนหน้าตาเหมือนกันจนสับสนทุกครั้งไป แปะป้ายกำหนดว่าช่องไหนเป็นของใคร เช้าที่วุ่นวายก็ราบรื่นขึ้นมาก ป้ายชื่อเล็ก ๆ ช่วยลดการทะเลาะกระจุกกระจิกในชีวิตประจำวันลงได้"},"ICON-0958":{"nm":"ที่ม้วนเก็บสายไฟ","de":"คลี่ออกใช้แล้วม้วนเก็บกลับ วันหนึ่งวันของสายไฟที่เป็นระเบียบเรียบร้อย ม้วนเก็บบนรอกเดียวทีละชั้น ความพันกันยุ่งเหยิงก็หายไปอย่างหมดจด มือที่คืนของกลับที่เดิมหลังใช้เสร็จช่วยให้วันพรุ่งนี้เบาสบายขึ้น"},"ICON-0959":{"nm":"ฝาครอบขั้วต่อแม่เหล็ก","de":"ขั้วต่อแม่เหล็กดึงดูดผงเหล็กละเอียดเข้ามาเกาะโดยไม่รู้ตัว ปิดคลุมด้วยฝาไว้ ฝุ่นเหนียวก็ไม่มาเกาะติด อุปกรณ์ที่ได้รับการดูแลด้วยมืออีกครั้งจะอยู่เคียงข้างเราไปได้นานขึ้น"},"ICON-0960":{"nm":"แถบรัดพาวเวอร์แบงก์","de":"แบตสำรองกับสายชาร์จถ้าแยกกันไว้ ต้องมีอันใดอันหนึ่งหายไปเสมอ มัดรวมกันด้วยแถบยาง ทั้งสองจึงกลายเป็นคู่กันในที่สุด มันคือปมเล็ก ๆ ที่ผูกไว้เบา ๆ ก่อนออกจากบ้าน บอกให้ทั้งคู่เดินทางไปด้วยกัน"},"ICON-0961":{"nm":"ฝาครอบกันฝุ่นปลั๊ก","de":"รูปลั๊กที่ว่างเปล่าเพียงไม่กี่วันฝุ่นก็แอบเข้ามาตั้งรกรากอย่างเงียบ ๆ เมื่อฝาเล็ก ๆ ชิ้นนี้เฝ้าดูแลตำแหน่งนั้นแทน เครื่องชาร์จที่จะเสียบเข้ามาครั้งต่อไปก็ได้สูดลมหายใจแรกที่สะอาดบริสุทธิ์ มันคือยามที่คอยรักษาช่วงเวลาว่างเปล่าให้สะอาดหมดจดอยู่เสมอ"},"ICON-0962":{"nm":"ห่วงสีบอกสายเคเบิล","de":"คืนที่คลำหาสายของตัวเองอยู่ในกองสายที่พันกันยุ่งเหยิง ใครสักคนเอ่ยขึ้นว่าให้เราติดสีกันเถอะ สีฟ้าคือเธอ สีเหลืองคือฉัน ด้วยห่วงเล็ก ๆ เพียงวงเดียว เราก็ไม่สับสนกันอีกต่อไป มันคือร่องรอยของคำสัญญาอันอบอุ่นที่หลงเหลืออยู่ในมุมหนึ่งของห้องซ้อม"},"ICON-0963":{"nm":"ชิปแยกประเภทอะแดปเตอร์","de":"ขาปลั๊กกลมและขาปลั๊กแบน 110 โวลต์และ 220 โวลต์ มันคือชิปที่เงียบ ๆ จดจำใบหน้าของปลั๊กไฟที่แตกต่างกันไปในแต่ละประเทศ ในมุมหนึ่งของกระเป๋าเดินทางครั้งแรกที่ข้ามทะเลไปสู่เวที ป้ายจำแนกเล็ก ๆ ชิ้นนี้มักแอบซ่อนอยู่เสมอ"},"ICON-0964":{"nm":"ถาดจัดเรียงจุกหูฟัง","de":"ว่ากันว่ารูหูของแต่ละคนลึกและกว้างไม่เหมือนกัน วางจุกไซส์ใหญ่ กลาง เล็ก เรียงกันไว้ แล้วเลือกคู่ที่พอดีกับหูของตัวเอง มันคือขั้นตอนอันอ่อนโยนที่ปรับร่างกายให้เข้าที่ก่อน ก่อนที่จะฟังเสียง"},"ICON-0965":{"nm":"ห่วงซิลิโคนหุ้มเคส","de":"ชุดการแสดงบนเวทีถูกดูแลไปถึงทุกตะเข็บ แต่มุมเคสกลับต้องกระแทกกับความเปล่าเปลือยอยู่เสมอ เมื่อขอบซิลิโคนบาง ๆ นี้โอบล้อมรอบไว้เบา ๆ แม้ในยามรุ่งสางที่มันหลุดจากมือ หน้าจอก็ยังคงต้อนรับเช้าวันใหม่ได้อย่างปลอดภัย"},"ICON-0966":{"nm":"สติกเกอร์ตัดเสียงรบกวน","de":"มีบางวันที่อยากปิดเสียงของโลกไว้สักพัก สติกเกอร์เล็ก ๆ ที่แปะไว้ที่หูฟังนี้คือเครื่องหมายที่เปิดความเงียบขึ้นมา ทั้งเสียงเชียร์จากที่นั่งผู้ชมและเสียงอึกทึกในรถไฟใต้ดิน มันคือเครื่องรางที่พาสิ่งเหล่านั้นออกไปไกล ๆ เพียงจนกว่าเพลงหนึ่งเพลงจะจบลง"},"ICON-0967":{"nm":"เซตตะขอเกี่ยวหูฟัง","de":"พอเต้นไปเต้นมา หูฟังข้างหนึ่งก็มักหลุดหนีไปก่อนเสมอ สวมห่วงที่โอบกอดใบหูไว้เบา ๆ นี้ แม้ในท่วงท่าเต้นที่รุนแรง ดนตรีเพียงอย่างเดียวก็ยังคงอยู่ในหูจนจบ มันคือการค้นพบเล็ก ๆ ที่คนในห้องซ้อมส่งต่อกันมา"},"ICON-0968":{"nm":"ฝาครอบแปรงทำความสะอาด","de":"หมวกเล็ก ๆ ที่สวมไว้ไม่ให้ฝุ่นที่ติดปลายขนแปรงฟุ้งกระจายอีกครั้ง แม้แต่เครื่องมือทำความสะอาดก็ยังต้องการการทำความสะอาดเช่นกัน มือที่เคยตั้งไม้กวาดกลับหัวไว้หลังกวาดพื้นเสร็จเข้าใจเรื่องนี้มาตั้งแต่นานแล้ว"},"ICON-0969":{"nm":"แผ่นรองก้นแท่นชาร์จ","de":"ที่แท่นชาร์จลื่นไถลอยู่บนโต๊ะตลอดก็เพราะมันไม่มีเท้า เมื่อแผ่นบาง ๆ ที่ปูไว้ด้านล่างนี้ทำหน้าที่เป็นเท้าแทน อุปกรณ์ก็อยู่นิ่งกับที่ และเติมพลังงานไปอย่างเงียบสงบตลอดคืน"},"ICON-0970":{"nm":"เครื่องหมายแยกซ้ายขวา","de":"ซ้ายคือ L ขวาคือ R จุดเพิ่มอีกจุดหนึ่งถูกทำเครื่องหมายไว้เพื่อให้รู้ได้แม้คลำหาในความมืด ความปรารถนาที่จะไม่สับสนเท้าซ้ายเท้าขวาบนเวทีแม้แต่ครั้งเดียวนั้นถูกประทับตราไว้อย่างครบถ้วนบนเครื่องหมายเล็ก ๆ ชิ้นนี้"},"ICON-0971":{"nm":"ฝาครอบแจ็คแบ่งสัญญาณเสียง","de":"แจ็คที่เคยแบ่งเสียงหนึ่งสายให้หลายคนฟังพร้อมกันนั้น ต้องปิดปลายไว้ในยามพัก เพื่อไม่ให้ฝุ่นแทรกซึมเข้าไปในวงจร มันคือมือเล็ก ๆ ที่ระมัดระวัง ปรารถนาให้เพลงที่เคยฟังด้วยกันไหลลื่นใสในครั้งต่อไปเช่นเดิม"},"ICON-0972":{"nm":"ที่ม้วนสายหูฟัง","de":"ราวกับท่วงท่ามือเก่าแก่ที่ม้วนกลุ่มด้าย สายหูฟังเมื่อม้วนเป็นวงกลมที่นี่ก็เรียบร้อยขึ้นมาทันที ช่วงเวลาที่ดนตรีซึ่งเคยกลิ้งพันกันยุ่งเหยิงในกระเป๋าถูกจัดให้เป็นระเบียบ วันพรุ่งนี้ที่จะคลี่ออกใช้ก็จะเบาสบายขึ้นอีกมาก"},"ICON-0973":{"nm":"สายคล้องฝาปิดเลนส์","de":"ทุกครั้งที่เปิดเลนส์ ฝาก็มักหาที่ไปไม่เจอเสมอ ผูกไว้กับสายที่มัดติดข้างกล้อง ก็ไม่ต้องคลำหากระเป๋าอย่างไร้ผลอีกต่อไป การจะไม่ทำของหายก็แค่ผูกมันไว้ข้างกาย มือเรียนรู้เรื่องนี้ก่อนใคร"},"ICON-0974":{"nm":"จี้ปิดช่องฮอตชูกล้อง","de":"ในช่องฮอตชูที่ว่างเปล่าบนกล้อง สอดของประดับเล็ก ๆ ชิ้นหนึ่งเข้าไปอย่างแนบเนียน จี้ที่ไม่มีหน้าที่การใช้งานใด ๆ ชิ้นนั้นเองที่ทำให้อุปกรณ์อันหนักอึ้งและแข็งกระด้างดูอบอุ่นราวกับเป็นของรักของตัวเองโดยไม่รู้ตัว นี่คือการผูกพันความรักไว้กับเครื่องมือ"},"ICON-0975":{"nm":"หัวเข็มขัดปรับสายกระเป๋า","de":"ทุกครั้งที่สายกระเป๋ากดทับไหล่ ก็ค่อย ๆ คลายและรัดหัวเข็มขัดนี้ทีละนิด ปลายนิ้วเพียงครั้งเดียวเพื่อเลือกความยาวที่พอดีกับร่างกายของตัวเอง แม้แต่การแบกสัมภาระก็คือการดูแลตัวเองในที่สุด หัวเข็มขัดนี้บอกกล่าวเราไว้อย่างเงียบ ๆ"},"ICON-0976":{"nm":"กล่องเก็บฟิลเตอร์","de":"บ้านเล็ก ๆ หลังหนึ่งที่วางเรียงชิ้นกระจกที่แบ่งแยกแสงไว้ทีละชั้น หมอกและความใส พระอาทิตย์ตกและกลางคืน ราวกับลิ้นชักที่เลือกและเก็บสภาพอากาศไว้ล่วงหน้า ช่างภาพจึงมักเปิดกล่องใบนี้ก่อนสิ่งอื่นใดเสมอก่อนออกเดินทาง"},"ICON-0977":{"nm":"ฝาปิดหัวเป่าลม","de":"ลูกยางที่พ่นลมไล่ฝุ่นนั้น ปากของมันเองก็อ่อนแอต่อฝุ่นไม่ต่างกัน ในยามพัก สวมฝานี้ครอบไว้ มีบางอย่างที่อบอุ่นในเครื่องมือที่คอยเช็ดสิ่งอื่นให้สะอาด แต่กลับปิดปากของตัวเองไว้อย่างเงียบ ๆ ก่อนใคร"},"ICON-0978":{"nm":"ฝาครอบปุ่มชัตเตอร์","de":"ชัตเตอร์ที่ถูกกดโดยไม่ตั้งใจในกระเป๋าจนถ่ายท้องฟ้าว่างเปล่าไปนับร้อยภาพ เป็นเรื่องที่ทุกคนต้องเคยเจอสักครั้ง ฝาครอบเล็ก ๆ นี้ที่สวมไว้บนปุ่มช่วยป้องกันความเหนื่อยเปล่านั้น มันคือกลอนล็อกเล็ก ๆ ที่จะเก็บไว้เฉพาะช่วงเวลาที่อยากเก็บไว้จริง ๆ เท่านั้น"},"ICON-0979":{"nm":"สติกเกอร์แยกประเภทแบตเตอรี่","de":"มันวุ่นวายเสมอเมื่อแบตที่หมดแล้วกับที่เต็มปะปนกันอยู่ในกระเป๋าเดียว สติกเกอร์สีที่แปะไว้บนแบตแต่ละก้อนช่วยจัดการความสับสนนั้นได้อย่างเงียบ ๆ สีแดงคือหมดแล้ว สีเขียวคือพร้อมใช้งาน มันคือสัญญาณไฟจราจรไร้เสียงที่เปิดไว้ในสถานที่ถ่ายทำ"},"ICON-0980":{"nm":"แผ่นกั้นในกระเป๋ากล้อง","de":"แบ่งช่องในกระเป๋าเพื่อไม่ให้เลนส์ ตัวกล้อง และแบตสำรองกระแทกกันเอง เป็นการสร้างห้องเล็ก ๆ หลายห้องไว้ในภาระเดียว แต่ละที่มีเจ้าของกำหนดไว้แล้ว จึงไม่มีวันเสียตำแหน่งแม้จะถูกเขย่า"},"ICON-0981":{"nm":"ถุงมือแผ่นรองถ่ายภาพ","de":"การถ่ายภาพกลางแจ้งในฤดูหนาว ปลายนิ้วที่กดชัตเตอร์เท่านั้นที่ห้ามหนาวเย็น แผ่นรองหนานุ่มไว้ที่ฝ่ามือ และถุงมือที่ยังเหลือความรู้สึกไว้ที่ปลายนิ้ว คือทางออกอันอ่อนโยนของหน้างานที่พยายามถือทั้งความอบอุ่นและความแม่นยำไว้ในมือเดียวกัน"},"ICON-0982":{"nm":"กระบอกเก็บหัวปากกาแท็บเล็ต","de":"หัวปากกาสึกกร่อนได้เหมือนไส้ดินสอ เรื่องนี้คนที่ถือแท็บเล็ตมานานเท่านั้นจะรู้ กระบอกเล็ก ๆ ที่รวบรวมหัวปากกาสำรองไว้กลิ้งอยู่ในนี้ ราวกับเงินสำรองฉุกเฉินของปลายนิ้วที่เติมเส้นที่ต้องไม่ขาดตอนไว้ล่วงหน้า"},"ICON-0983":{"nm":"ถาดวางคีย์แคปคีย์บอร์ด","de":"วันที่ถอดคีย์แคปออกทีละอันไปล้างแล้วใส่กลับ ถาดนี้กลายเป็นหาดโคลนเล็ก ๆ ทัศนียภาพของพยัญชนะและสระที่นอนเรียงกันเป็นช่อง ๆ ผึ่งให้แห้งน้ำ มีความใส่ใจบางอย่างที่จะมองเห็นได้ก็ต่อเมื่อได้ถอดแยกชิ้นส่วนออกมาแล้วเท่านั้น"},"ICON-0984":{"nm":"แพ็กเท้าเมาส์","de":"เคล็ดลับที่ทำให้เมาส์เลื่อนไถลไปบนโต๊ะอย่างลื่นไหลอยู่ที่เท้าเล็ก ๆ เหล่านี้ที่ติดอยู่ด้านล่าง หนึ่งชุดที่เปลี่ยนใหม่เมื่อสึกหรอ ความเหนื่อยยากของสิ่งที่ค้ำจุนความลื่นไหลอยู่อย่างเงียบ ๆ ในตำแหน่งที่มองไม่เห็น"},"ICON-0985":{"nm":"แผ่นยางรองแล็ปท็อป","de":"หน้าตาคล้ายสมุดโน้ต แต่แท้จริงแล้วมันคือแผ่นยางที่ค้ำยกแล็ปท็อปขึ้น ยกหน้าจอให้สูงถึงระดับสายตาเล็กน้อยเพื่อยืดคอที่งอไว้ให้ตรง มันคือความใส่ใจที่จัดท่าทางให้ถูกต้อง สำหรับผู้ที่เขียนและจ้องมองอยู่นาน ๆ"},"ICON-0986":{"nm":"สไลด์ปิดกล้องเว็บแคม","de":"ดันนิ้วเพื่อปิดเลนส์ แล้วดันอีกครั้งเพื่อเปิด ความปรารถนาที่จะให้ใครเห็นก็ต่อเมื่ออยากให้เห็นเท่านั้น ในสไลด์เล็ก ๆ ชิ้นเดียวนี้แฝงความอุ่นใจอันยิ่งใหญ่ที่เรียกว่าความเป็นส่วนตัว เสียงปิดนั้นให้ความรู้สึกมั่นคงอย่างบอกไม่ถูก"},"ICON-0987":{"nm":"ป้ายแยกประเภท USB","de":"แท่งดำห้าแท่งที่หน้าตาคล้ายกัน ไม่มีทางรู้เลยว่าแท่งไหนเก็บอะไรไว้บ้าง แปะป้ายเล็ก ๆ แล้วตั้งชื่อให้ ตอนนั้นเองที่มันกลายเป็นคนในครอบครัวอย่างแท้จริง ต้องมีชื่อให้เรียกเสียก่อนถึงจะหาเจอได้ง่ายขึ้น"},"ICON-0988":{"nm":"มุมยึดแผ่นรองโต๊ะ","de":"เมื่อมุมของแผ่นรองโต๊ะม้วนงอขึ้นเรื่อย ๆ แม้แต่ลายมือก็ยังเบี้ยวตามไปด้วย ชิ้นส่วนเล็ก ๆ เหล่านี้ที่กดมุมทั้งสี่ไว้เบา ๆ คอยปกป้องความสงบราบเรียบบนโต๊ะไว้ พื้นผิวต้องนิ่งสงบ ปลายนิ้วจึงจะสงบตามไปด้วย"},"ICON-0989":{"nm":"คลิปตั้งฮับ","de":"คลิปที่ตั้งฮับซึ่งเป็นจุดรวมของสายไฟหลายเส้นไว้เอียงตรงขอบโต๊ะ ภาพของสายที่เคยยุ่งเหยิงมารวมกันเป็นจุดเดียวอย่างเป็นระเบียบ ฝีมือของการรวบรวมสิ่งที่พันกันยุ่งเหยิงให้เป็นสายเดียวยังคงมีชีวิตอยู่ที่นี่เช่นกัน"},"ICON-0990":{"nm":"ฝาสเปรย์ทำความสะอาดหน้าจอ","de":"สเปรย์ที่ลบรอยนิ้วมือบนหน้าจอออก มีจุกเล็ก ๆ ปิดปากของมันไว้ ปิดให้แน่นเสมอเพื่อไม่ให้น้ำยารั่วไหลหรือระเหยแห้ง เพื่อจะมองเห็นชัดเจน ต้องรู้จักถนอมเครื่องมือทำความสะอาดไว้ก่อนเป็นอันดับแรก นี่คือลำดับอันเรียบง่ายของงานบ้าน"},"ICON-0991":{"nm":"กระเป๋าใส่การ์ดความจำ","de":"ภาพการแสดงบนเวทีหลายวันหลับใหลอยู่อย่างสงบในการ์ดเพียงแผ่นเดียวที่เล็กเท่าปลายเล็บ หากทำหายไป วันทั้งวันนั้นก็จะสูญหายไปทั้งหมด จึงรวบรวมมันไว้อย่างทะนุถนอมในกระเป๋าเล็ก ๆ ใบหนึ่ง มันคือบ้านที่บรรจุความทรงจำที่เล็กที่สุดแต่ยิ่งใหญ่ที่สุดไว้"},"ICON-0992":{"nm":"ป้ายติดฮาร์ดดิสก์ภายนอก","de":"ฮาร์ดดิสก์ภายนอกสีดำห้าตัวหลับใหลอยู่ในลิ้นชักด้วยใบหน้าที่เหมือนกันทุกประการ การแปะป้ายแล้วตั้งชื่อว่า 'ฤดูร้อนปีนั้น' 'คลิปที่ยังไม่เผยแพร่' คืองานที่ติดดัชนีอันชัดเจนลงบนความทรงจำที่เลือนราง"},"ICON-0993":{"nm":"ชิปเช็กสถานะแบ็กอัป","de":"แบ็กอัปเสร็จแล้วหรือยังไม่เสร็จ ความแตกต่างเพียงเส้นบาง ๆ นั้นทำให้ใจหวั่นไหว ชิปเล็ก ๆ ที่แทรกไว้ตรงจุดที่เสร็จแล้วนี้บอกเราว่า 'ปลอดภัยจนถึงตรงนี้แล้ว' ความอุ่นใจเกิดขึ้นจากการทิ้งเครื่องหมายไว้เสมอ"},"ICON-0994":{"nm":"โทเคนโน้ตคลาวด์","de":"โทเคนที่ลอยส่งบันทึกหนึ่งบรรทัดขึ้นไปยังคลังเก็บที่ลอยอยู่ในท้องฟ้าที่ไหนสักแห่ง เวทมนตร์เล็ก ๆ ที่ไม่ว่าจะเปิดเครื่องที่ไหน ข้อความนั้นก็จะออกมาต้อนรับเสมอ ท้องฟ้ายามค่ำคืนที่เคยปล่อยว่าวเขียนคำอธิษฐานไว้ ดูราวกับค่อย ๆ ลอยลงมาอยู่บนฝ่ามือในตอนนี้"},"ICON-0995":{"nm":"เซตฝาครอบป้องกัน USB","de":"หากปล่อยให้ขั้วต่อเปิดโล่งกลิ้งอยู่ในกระเป๋า จุดสัมผัสย่อมสึกหรอเป็นธรรมดา สวมหมวกเล็ก ๆ ครอบไว้ทุกปลายแล้วเก็บไว้เป็นชุดเดียวกัน มันคือการวางช่วงเวลาที่ไม่ได้ใช้งานให้หลับพักอย่างอ่อนโยน คือการเตรียมพร้อมที่เงียบที่สุดสำหรับการเชื่อมต่อครั้งต่อไป"},"ICON-0996":{"nm":"แถบรัดเคสข้อมูล","de":"แถบที่โอบรัดอุปกรณ์ที่บรรจุข้อมูลอันมีค่าไว้แน่นหนา พันรอบหนึ่งรอบแล้วมัดให้แน่นเพื่อไม่ให้กระแทกกันในกระเป๋าที่โคลงเคลง มือที่เคยผูกห่อของด้วยความประณีตในอดีต ยังคงมีชีวิตอยู่ในโลกดิจิทัลเช่นเดิม"},"ICON-0997":{"nm":"แท็กจัดระเบียบไฟล์","de":"เมื่อไฟล์นับร้อยกองรวมกันโดยไร้ชื่อ การค้นหาก็กลายเป็นการหลงทาง ในชั่วขณะที่ติดแท็กหลากสีแล้วแยกกิ่งก้านออกจากกัน เส้นทางก็ปรากฏขึ้นท่ามกลางกองที่ยุ่งเหยิงนั้น การจัดระเบียบท้ายที่สุดแล้วก็คืองานเปิดเส้นทางนั่นเอง"},"ICON-0998":{"nm":"การ์ดคำใบ้รหัสผ่าน","de":"เขียนรหัสผ่านไว้ทั้งหมดก็อันตราย ไม่เขียนไว้เลยก็ลืม จึงเหลือไว้เพียงเบาะแสที่มีเพียงตัวเราเท่านั้นที่เข้าใจ อย่างเช่น 'เมืองนั้นของเวทีแรก' วิธีการจดจำอันชาญฉลาดและอ่อนโยนที่จดเส้นทางไว้ ไม่ใช่คำตอบ"},"ICON-0999":{"nm":"สติกเกอร์บอกวันที่จัดเก็บ","de":"หากไม่จดวันที่เก็บไว้ การจัดเก็บก็จะกลายเป็นการหลงลืมในไม่ช้า สติกเกอร์วันที่ที่แปะไว้บนกล่องแต่ละใบสลักคำว่า 'ตั้งแต่เมื่อไร' ไว้อย่างชัดเจน หัวใจของยุ้งฉางเก่าแก่ที่เคยจดวันหมักถั่วเหลืองไว้ ยังคงสืบทอดมาอยู่บนกระดาษเล็ก ๆ แผ่นนี้"},"ICON-1000":{"nm":"ฝาครอบไฟวงแหวนจิ๋ว","de":"ฝาที่ปิดรูแสงของโคมไฟเล็ก ๆ ที่เปล่งแสงเป็นวงกลม พักแสงไว้ชั่วครู่เพื่อไม่ให้เลนส์ถูกขีดข่วนในกระเป๋า การถนอมความมืดไว้อย่างประณีตก่อนเปิดใช้งานก็เป็นอีกวิธีหนึ่งของการทะนุถนอมความสว่างไสวเช่นกัน"},"ICON-1001":{"nm":"สกรูขันขาตั้ง","de":"หมุนอีกรอบเดียวเท่านั้น ช่องว่างที่หลวมคลอนก็หายไป และความอุ่นใจหนักแน่นก็ลงมาทับอยู่ใต้ฝ่ามือ เบื้องหลังเวทีที่ไม่สั่นไหวนั้น มักมีข้อมือใครสักคนที่บิดแน่นไว้อย่างเด็ดขาดเสมอ สิ่งที่สกรูตัวเล็ก ๆ ค้ำอยู่ คือความมั่นคงที่มองไม่เห็น"},"ICON-1002":{"nm":"ชิปป้ายกำลังออกอากาศ","de":"ในวินาทีที่ไฟสีแดงสว่างขึ้น เสียงฝีเท้าในทางเดินก็ค่อย ๆ เขย่งขึ้นโดยไม่รู้ตัว ต่อหน้าคำว่า \"กำลังออกอากาศ\" ทุกคนต่างกลั้นลมหายใจ แม้แต่ความเงียบหลังประตูก็ยังเป็นหัวใจที่มุ่งไปหาใครสักคน นี่คือสิ่งที่ชิปเล็ก ๆ นี้เงียบ ๆ ประกาศให้รู้"},"ICON-1003":{"nm":"สมุดจดข้อความแชท","de":"จับกำลังใจที่กำลังจะไหลผ่านหน้าจอไปไว้ด้วยปลายนิ้ว ช่วงเวลาที่ถ้อยคำแต่ละคำซึ่งเคยล่องลอยหายไป กลับหยุดอยู่บนกระดาษอย่างเรียบร้อยชัดเจน การจดบันทึกคือที่พักพิงของความอ่อนโยนที่แม้จะช้าไปบ้าง ก็ยังอยากไปให้ถึง"},"ICON-1004":{"nm":"ฝาครอบคีย์บอร์ดไร้เสียง","de":"ตีสองของคืนหนึ่ง เสียงกดแป้นพิมพ์หายไปราวกับโกหก แผ่นฟิล์มบาง ๆ แผ่นเดียวที่ไม่อยากปลุกลมหายใจของเพื่อนร่วมห้องที่หลับสนิท ความใส่ใจที่เงียบที่สุด มักเริ่มต้นในที่ที่ไร้เสียงเสมอ"},"ICON-1005":{"nm":"คลิปยึดขาไมโครโฟน","de":"ระหว่างริมฝีปากกับไมโครโฟน คือระยะพอดีที่ทำให้เสียงเพลงไม่สั่นคลอน คลิปเล็ก ๆ ตัวนี้แหละที่ยึดคำมั่นสัญญานั้นไว้ให้มั่น หลังเวทีเสมอมีมือเช่นนี้ ที่มาถึงก่อนใครเพื่อประคองทุกอย่างให้มั่นคง"},"ICON-1006":{"nm":"คีบผ้าฉากหลัง","de":"แม้ลมจะพัด ผ้าฉากหลังก็ไม่ไหวติง เพราะขากรรไกรเล็ก ๆ อันหนึ่งกัดมุมผ้าไว้แน่น จนยึดทั้งฉากไว้ได้ เบื้องหลังทิวทัศน์ที่ไม่สั่นไหว มักมีใครสักคนกัดฟันแน่นอยู่ในมุมที่มองไม่เห็น"},"ICON-1007":{"nm":"ป้ายชื่อสตรีมเด็ก","de":"บนปุ่มนับสิบ ป้ายชื่อเล็ก ๆ ช่วยไม่ให้มือหลงทาง ป้ายเพียงบรรทัดเดียวช่วยลบข้อผิดพลาดหนึ่งครั้งของการถ่ายทอดสดไปล่วงหน้า ความสงบนิ่งนั้นมาจากตัวอักษรที่เขียนไว้ก่อนที่มือจะสั่น"},"ICON-1008":{"nm":"ปุ่มประทับเวลา","de":"กดลงไปเบา ๆ ธงเล็ก ๆ ก็ปักลงบนสายธารเวลาที่ไหลผ่าน คือการประทับตราลงบนปัจจุบันที่จะไม่มีวันหวนกลับมาอีก เมื่อมองย้อนกลับไปในภายหลัง เครื่องหมายนั้นก็กลายเป็นประตูที่นำไปสู่ความทรงจำ"},"ICON-1009":{"nm":"พวงกุญแจแท็กรีดเดอร์","de":"แตะเข้าไปเบา ๆ ก็มีเสียง \"ติ๊ด\" แล้วข้อมูลก็ตื่นขึ้นมา เพื่อนตัวเล็กที่ห้อยอยู่บนพวงกุญแจ ส่งเสียงกรุ๊งกริ๊งอยู่ในกระเป๋า วันธรรมดา ๆ ดำเนินไปอย่างปลอดภัยได้ก็ด้วยเสียงสัญญาณเล็ก ๆ เช่นนี้"},"ICON-1010":{"nm":"ป้ายปลั๊กอัจฉริยะ","de":"หากติดชื่อไว้ที่ปลั๊กไฟแต่ละอัน ก็จะไม่หลงอีกต่อไปว่าสายไหนคือสายอะไร หัวใจที่มอบชื่อให้แม้แต่กระแสไฟฟ้าที่มองไม่เห็น ความเป็นระเบียบคือใบหน้าอีกด้านที่ความอ่อนโยนแอบสวมใส่ชั่วคราว"},"ICON-1011":{"nm":"ขาตั้งเซนเซอร์วัดอุณหภูมิความชื้น","de":"ยามเฝ้าตัวจิ๋วขนาดเท่าฝ่ามือ ที่คอยจับตาดูอุณหภูมิและความชื้นในห้องอย่างเงียบเชียบ ความสบายไม่เคยเอ่ยปาก แต่ขาตั้งนี้คอยดูแลสภาพของเธออยู่ทุกขณะอย่างเงียบ ๆ ความสุขสบายถูกปกป้องไว้อย่างเงียบงันเช่นนี้เอง"},"ICON-1012":{"nm":"ฝาครอบเซนเซอร์ประตู","de":"ดวงตาเล็ก ๆ ที่ไม่พลาดแม้เสี้ยววินาทีที่ประตูแง้มเปิดออกเบา ๆ มันส่งสัญญาณอย่างเงียบ ๆ ว่ามีใครกลับมาแล้ว สิ่งที่เฝ้าบ้านให้ในยามว่างเปล่านั้น เป็นสิ่งไร้ถ้อยคำเช่นนี้เสมอมา"},"ICON-1013":{"nm":"ที่เก็บรีโมทคอนโทรล","de":"รีโมตที่เคยกลิ้งอยู่ทั่วบ้าน ในที่สุดก็ได้พบที่ทางของตัวเองสักที ที่เล็ก ๆ ที่เงียบ ๆ ยึดสิ่งที่เกือบสูญหายไว้ให้มั่น เป็นมือที่แกะสลักคำมั่นว่าจะได้พบกันอีกไว้ล่วงหน้า"},"ICON-1014":{"nm":"โทเคนแอปการนอนหลับ","de":"ทุกคืนที่หลับสนิท เหรียญกลม ๆ แห่งความภาคภูมิใจก็กลิ้งมาสะสมทีละอัน แม้แต่การนอนก็สะสมไปทีละนิดเหมือนการฝึกฝน แอปกระซิบบอกอย่างอ่อนโยนเช่นนั้น รางวัลที่เล็กที่สุดในโลก มอบให้กับเธอผู้พักผ่อนมาอย่างดี"},"ICON-1015":{"nm":"ฐานลูกบาศก์จับเวลา","de":"ขณะที่สามนาทีไหลผ่านไปอย่างเที่ยงตรง ลูกบาศก์นับเวลาของตัวเองโดยไม่สั่นไหว ที่เล็ก ๆ ขนาดเท่าฝ่ามือหนึ่งอันที่ค้ำมันไว้อย่างเงียบเชียบจากด้านล่าง แม้แต่การรอคอยก็ยังต้องการพื้นที่ให้วางใจเหยียบยืนได้"},"ICON-1016":{"nm":"ฝาครอบไฟแจ้งเตือน","de":"เพื่อไม่ให้สว่างจ้าเกินไป มันห่อหุ้มแสงไว้อย่างนุ่มนวลด้วยชั้นบาง ๆ หนึ่งชั้น แม้การแจ้งเตือนจะเร่งด่วน แต่ขอให้ดวงตายังคงสบาย ความใส่ใจคือหัวใจที่คำนึงถึงแม้กระทั่งความแรงของแสงอย่างเงียบ ๆ"},"ICON-1017":{"nm":"การ์ดแจ้งเปลี่ยนแบตเตอรี่","de":"เมื่อการ์ดใบนี้ปรากฏขึ้น หมายความว่าถึงเวลาต้องเปลี่ยนหัวใจดวงเล็ก ๆ ในเครื่องแล้ว คำกระซิบอย่างอ่อนโยนที่บอกให้ดูแลก่อนที่มันจะหยุดทำงาน เคล็ดลับของการอยู่ด้วยกันไปนาน ๆ อยู่ที่การเอาใจใส่ที่เร็วกว่าเสมอหนึ่งจังหวะ"},"ICON-1018":{"nm":"ชุดฝาครอบจอยสติ๊ก","de":"หมวกจิ๋ว ๆ ที่สวมไว้เบา ๆ เพื่อไม่ให้นิ้วโป้งลื่นไถล สัมผัสที่ปลายนิ้วชัดเจนขึ้นอีกระดับ ฝาเล็ก ๆ อันนี้เพียงอันเดียว บางครั้งก็ตัดสินแพ้ชนะของเกมหนึ่งรอบที่มือเปียกเหงื่อได้เลย"},"ICON-1019":{"nm":"ฝาครอบด็อกเครื่องเล่นเกม","de":"ปกคลุมที่พักของเครื่องคอนโซลไว้เบา ๆ ให้พ้นจากฝุ่นละออง เพราะแม้แต่เครื่องที่หลับใหลอยู่ชั่วคราวก็ยังต้องการผ้าห่มสักผืน ความรักและความหวงแหนกลับปรากฏชัดขึ้น ในยามที่ไม่ได้ใช้งานนั่นเอง"},"ICON-1020":{"nm":"ซองใส่เครื่องเล่นเกมพกพา","de":"เวลาเดินทางต้องใส่ไว้ในนี้เท่านั้น ถุงที่โอบกอดเครื่องเกมพกพาไว้อย่างนุ่มนวล เพื่อให้มันไม่เป็นอะไรแม้จะถูกกระแทกไปมาในกระเป๋า สิ่งล้ำค่าควรได้รับการห่อหุ้มไว้อีกชั้นเสมอ"},"ICON-1021":{"nm":"ชุดสติกเกอร์ปุ่มกด","de":"เพียงแค่วางภาพเล็ก ๆ หนึ่งภาพลงบนปุ่มที่เคยดูธรรมดา ในวินาทีนั้นมันก็กลายเป็นของฉันโดยสมบูรณ์ การทิ้งรอยประทับเฉพาะตัวไว้บนอุปกรณ์ที่เหมือนกันทุกเครื่อง ความเป็นตัวเองมักผลิบานอย่างเงียบ ๆ จากมุมเล็ก ๆ เช่นนี้เสมอ"},"ICON-1022":{"nm":"กล่องใส่ตลับเกม","de":"เกมหนึ่งรอบที่เคยดื่มด่ำจนลืมเวลาทั้งคืน หลับใหลอยู่ในกล่องเล็ก ๆ นี้อย่างสงบ เมื่อเปิดฝาอีกครั้ง คืนนั้นก็ตื่นขึ้นมาอย่างครบถ้วนเหมือนเดิม ความทรงจำมักถูกเก็บไว้ในกล่องขนาดเท่าฝ่ามือได้อย่างน่าประหลาดใจ"},"ICON-1023":{"nm":"ขาตั้งพัดลมระบายความร้อน","de":"ขณะที่สายลมทำให้ความร้อนเย็นลง ที่วางนี้เอียงเครื่องขึ้นเบา ๆ เพื่อรองรับไว้ มันสร้างช่องให้ร่างกายที่ร้อนจัดได้พักหายใจสักครู่ หากอยากวิ่งไปได้ไกล ก็ต้องรู้จักหยุดพักเพื่อทำให้ตัวเองเย็นลงบ้างเช่นกัน"},"ICON-1024":{"nm":"หมุดสายรัดข้อมือ","de":"พันไว้รอบข้อมือแล้วกลัดหมุดให้แน่น ไม่ว่าจะเคลื่อนไหวรุนแรงแค่ไหน คอนโทรลเลอร์ก็จะไม่หลุดจากมือไปไหน สายเล็ก ๆ ที่ดูเหมือนเกะกะนี้ แท้จริงแล้วคือความอุ่นใจที่ทำให้เล่นได้อย่างสุดเหวี่ยงโดยไม่ต้องกังวล"},"ICON-1025":{"nm":"ฝาครอบก้านอนาล็อก","de":"สวมเสื้อผ้าใหม่ให้กริปที่เรียบมันเงาจากการจับใช้มานาน ปล่อยให้สัมผัสที่มือคุ้นเคยยังคงเดิม เปลี่ยนเพียงพื้นผิวให้ดูใหม่ เป็นช่วงเวลาที่ความคุ้นเคยกับความตื่นเต้นเล็ก ๆ พักอยู่เคียงข้างกันในมือข้างเดียว"},"ICON-1026":{"nm":"ป้ายช่องบันทึกเกม","de":"ในแต่ละช่องเซฟ เขียนไว้อย่างชัดเจนว่าเป็นการผจญภัยของใคร ป้ายเพียงบรรทัดเดียวเฝ้าปกป้องเส้นทางของวันเวลาที่ผ่านมาอย่างเงียบ ๆ ความทรงจำที่มีค่า ควรมีชื่อสลักไว้เพื่อไม่ให้ถูกเขียนทับ"},"ICON-1027":{"nm":"ซองใส่เครื่องบันทึกเสียง","de":"เครื่องที่บรรจุเสียงไว้ ยิ่งมีค่ามากขึ้นเพราะสิ่งที่อยู่ข้างในนั้น พกพาใส่ไว้ในถุงนุ่ม ๆ ที่ปกป้องจากแรงกระแทกอย่างประณีต เพราะไม่รู้ว่าเสียงของใครสักคนอาจกำลังหลับใหลอยู่ข้างใน จึงต้องระมัดระวังยิ่งกว่าเดิม"},"ICON-1028":{"nm":"ฝากันลมไมโครโฟน","de":"กวาดเสียงลมออกไป เหลือไว้เพียงเสียงพูดเท่านั้น หมวกฟูนุ่มที่สวมไว้เบา ๆ บนไมโครโฟนสำหรับบันทึกเสียงกลางแจ้ง เป็นตะแกรงเล็ก ๆ ที่คัดเลือกเฉพาะความจริงใจ ท่ามกลางเสียงรบกวนที่วุ่นวาย"},"ICON-1029":{"nm":"ป้ายบันทึกเสียงเมโม","de":"อันนี้คือเนื้อเพลงที่นึกขึ้นได้ อันนี้คือทำนองที่ฮัมเล่น ติดป้ายชื่อหลากสีลงบนบันทึกเสียงแต่ละอัน เศษเสี้ยวของแรงบันดาลใจที่กระจัดกระจายอยู่ทั่วทุกทิศ ในที่สุดก็ได้พบที่ทางของตัวเองและเรียงแถวกัน"},"ICON-1030":{"nm":"ชิปปุ่มแซมปลิ้งเสียง","de":"กดลงไปเบา ๆ เสียงที่เก็บไว้ล่วงหน้าเสี้ยวหนึ่งก็ผุดออกมา หยดฝน เสียงปรบมือ เสียงหัวเราะของใครสักคน เศษเสี้ยวของโลกตื่นขึ้นที่ปลายนิ้ว ดนตรีคือบทประสานเสียงอันอ่อนโยนของชิปเล็ก ๆ เหล่านี้"},"ICON-1031":{"nm":"ซองเก็บเสียง","de":"เก็บเสียงที่บังเอิญเก็บได้ระหว่างเดินทางไว้ในซองนี้อย่างเบามือ ทั้งลายของสายลม แม้แต่ความเงียบงันในตรอกยามรุ่งสาง วัตถุดิบที่สักวันจะกลายเป็นบทเพลง มักรวมตัวกันอย่างเรียบง่ายเช่นนี้เสมอ"},"ICON-1032":{"nm":"ขาตั้งกล้องมินิ","de":"ขาสามข้างกางออกเป็นเวทีเล็ก ๆ บนโต๊ะ แทนที่จะเป็นมือที่สั่นไหว มันยืนหยัดมั่นคงและยึดฉากไว้ได้ ภาพหนึ่งช็อตที่คมชัด ถือกำเนิดขึ้นในที่สุดจากขาทั้งสามที่ยืนนิ่งอย่างเงียบเชียบ"},"ICON-1033":{"nm":"แท็กไฟล์บันทึกเสียง","de":"ติดป้ายสั้น ๆ ทีละอันลงบนไฟล์บันทึกเสียงนับร้อย เพื่อให้เห็นได้ในทันทีว่าท่อนแรกที่ไหลออกมาครั้งแรกในวันไหน เป็นป้ายบอกทางเล็ก ๆ ที่ช่วยตามหาเสียงที่กระจัดกระจายให้กลับมาพบกันอีกครั้ง"},"ICON-1034":{"nm":"แถบสติกเกอร์คลื่นเสียง","de":"แถบลายคลื่นที่จำลองรูปทรงของเสียงไว้อย่างแท้จริง พันรอบสมุดหรือเคสแล้ว ราวกับว่าดนตรีปรากฏให้เห็นตรงหน้า เป็นภาพลวงตาอันอ่อนโยนที่ทำให้สิ่งที่ได้ยินกลายเป็นสิ่งที่มองเห็นได้"},"ICON-1035":{"nm":"หมุดแขวนหูฟัง","de":"เมื่อซ้อมเสร็จ มันเตรียมที่พักให้หูฟังที่เหนื่อยล้าไว้อย่างเงียบ ๆ ตะขอเล็ก ๆ อันหนึ่งที่ปักไว้ที่มุมโต๊ะ โต๊ะที่เป็นระเบียบ คือสถานที่ที่แขวนความมุ่งมั่นของวันพรุ่งนี้ไว้ล่วงหน้า"},"ICON-1036":{"nm":"แถบผูกกล่องของขวัญมินิ","de":"รอบสุดท้ายที่พันรอบเอวของกล่องของขวัญ ด้วยแถบเพียงเส้นเดียวนี้ หัวใจก็สมบูรณ์ในที่สุด ความตั้งใจมักถูกส่งต่อจากมือที่ลูบไล้พื้นผิวภายนอก มากกว่าสิ่งที่อยู่ข้างในเสียอีก"},"ICON-1037":{"nm":"ฝาครอบปลายริบบิ้น","de":"ห่อปลายริบบิ้นไว้เบา ๆ เพื่อไม่ให้คลายออก รายละเอียดเล็ก ๆ ที่แทบไม่มีใครสังเกตเห็น กลับเปลี่ยนความประทับใจแรกของของขวัญไปอย่างเงียบ ๆ เมื่อการปิดท้ายงดงาม หัวใจก็ไปถึงอย่างงดงามเช่นกัน"},"ICON-1038":{"nm":"ขี้ผึ้งปิดผนึกจดหมาย","de":"หยดร้อนหยดหนึ่งตกลงมาปิดผนึกซองจดหมาย เหมือนจดหมายในสมัยก่อน คำมั่นสัญญาอันหนักแน่นว่าอย่าเปิดออกโดยพลการ พิธีการบางครั้งก็โอบอุ้มน้ำหนักแห่งความอบอุ่นเช่นนี้ไว้เช่นกัน"},"ICON-1039":{"nm":"ที่ตั้งการ์ดขอบคุณ","de":"ประคองการ์ดที่เขียนคำขอบคุณไว้ให้ยืนตรง ไม่ให้ยับยู่ยี่ เพื่อให้หัวใจยืนหยัดอย่างเที่ยงตรงในขณะที่ถูกส่งต่อ ความขอบคุณจะอยู่ในใจได้นานขึ้น เมื่อแม้แต่รูปลักษณ์ของมันก็เรียบร้อยงดงาม"},"ICON-1040":{"nm":"กระดาษกันกระแทกรูปดาว","de":"กระดาษที่ตัดเป็นรูปดาวเติมเต็มช่องว่างในกล่องอย่างฟูนุ่ม สำลีแห่งหัวใจที่หวังว่าแม้จะถูกเขย่า ก็ขออย่าให้บอบช้ำ แม้ในความมืดภายในหีบห่อ ก็ยังมีดาวดวงเล็ก ๆ ลอยอยู่เสมือนหนึ่ง"},"ICON-1041":{"nm":"แท็กรายชื่อผู้รับของขวัญ","de":"หน้าช่องชื่อผู้รับ ปากกาหยุดนิ่งอยู่นาน ระหว่างเขียนชื่อสามพยางค์ ใบหน้าที่ผุดขึ้นมาในใจ ฤดูกาลที่เคยใช้ร่วมกัน ในวินาทีที่ผูกติดกัน กระดาษเล็ก ๆ ใบนี้ก็กลายเป็นความลับที่ไม่มีใครอ่านได้จนกว่าจะแก้มันออก"},"ICON-1042":{"nm":"แหวนตราปั๊มแสดงความยินดี","de":"กดลงไปเบา ๆ คำแสดงความยินดีทรงกลมก็ปรากฏขึ้นอย่างชัดเจน ระหว่างรอหมึกแห้งอยู่ครู่หนึ่ง หัวใจที่นึกถึงว่าจะมอบให้ใครนั้นอบอุ่นที่สุด หากจะมีข้อเสียบ้าง ก็คงเป็นเพราะอยากปั๊มซ้ำอีกครั้งนั่นเอง"},"ICON-1043":{"nm":"หลอดด้ายเชือกผูกของขวัญ","de":"ม้วนไว้อย่างประณีต ก่อนจะคลายออกอย่างสนุกสนานที่ปลายนิ้วที่ตื่นเต้นของใครสักคน ในช่วงเวลาสั้น ๆ ระหว่างการม้วนกับการคลาย หัวใจดวงหนึ่งที่ผูกติดอยู่กับเส้นด้าย ก็กลายเป็นของขวัญในที่สุด"},"ICON-1044":{"nm":"จี้ปมเชือก (ไม่ใช่ดอกไม้)","de":"ไม่ใช่การเลียนแบบดอกไม้ แต่เป็นรูปทรงที่เส้นด้ายเส้นเดียวโอบกอดตัวเองซ้ำแล้วซ้ำเล่าจนผลิบานขึ้นมาเอง ความอดทนของปลายนิ้วที่เลือกสรรปมเชือกตลอดทั้งคืน หลงเหลืออยู่เป็นดอกตูมเล็ก ๆ เพียงดอกเดียวเช่นนี้"},"ICON-1045":{"nm":"ถุงเหรียญนำโชค","de":"หัวใจที่แอบใส่เหรียญไม่กี่เหรียญลงในกระเป๋าของผู้ที่กำลังจะออกเดินทางไกล ไม่ใช่การเติมน้ำหนัก แต่เป็นการเติมความอ่อนโยน เสียงกรุ๊งกริ๊งในทุกย่างก้าว แทนคำอวยพรให้เดินทางปลอดภัย"},"ICON-1046":{"nm":"จี้แคปซูลอธิษฐาน","de":"ในเปลือกกลม ๆ มีคำอธิษฐานที่พับไว้หลับใหลอย่างสงบ คำที่ว่าเปิดออกแล้วจะสมหวังนั้นเป็นเรื่องโกหก แต่การเก็บมันไว้โดยไม่เปิดออก แล้วความปรารถนานั้นจะมีชีวิตอยู่ตลอดไป นั่นคือความจริง"},"ICON-1047":{"nm":"เชือกปมปกป้อง","de":"เชือกที่ถักทอด้วยด้ายห้าสีอย่างแน่นหนา หันพลังชั่วร้ายกลับไปไว้ข้างหลัง เหมือนมือของคุณยายที่เคยผูกปมรอบข้อมือให้ตอนเด็ก ๆ ในทุกจุดที่ผูกไว้ มีคำอธิษฐานของใครสักคนฝังอยู่อย่างประณีต"},"ICON-1048":{"nm":"กล่องเก็บนกกระเรียนกระดาษตัวเล็ก","de":"บ้านเล็ก ๆ ที่เก็บนกกระเรียนกระดาษเพียงตัวเดียวไว้ไม่ให้บอบช้ำ จากพันตัวที่ต้องพับเพื่อให้กลายเป็นคำอธิษฐาน เพราะแม้แต่ปีกข้างเดียวยับยู่ยี่ ความตั้งใจที่ทุ่มเทไปในคืนนั้นก็จะคลายหลุดไปด้วย"},"ICON-1049":{"nm":"ถุงเก็บเศษกากเพชร","de":"เศษแสงระยิบระยับเล็ก ๆ ที่หลุดร่วงจากชุดแสดงบนเวที ที่ที่กวาดเก็บไว้เพราะทิ้งไม่ลง แม้แสงระยิบระยับที่เคยติดตามไปทั้งสัปดาห์เมื่อเปื้อนตัวครั้งหนึ่ง ที่นี่มันก็หลับใหลอย่างเชื่องเชื่อเหมือนอยู่บนฝ่ามือ"},"ICON-1050":{"nm":"ชิปตราปั๊มลางดี","de":"เบี้ยเล็ก ๆ ที่แอบเติมเข้าไปตอนเลือกวันดี ไม่ใช่ที่ธรณีประตูร้านดูดวง แต่บนโต๊ะของฉันเอง เศษความเชื่อโชคลางอันน่ารักที่ปั๊มลงไปเบา ๆ ขอเพียงให้วันนี้มีแต่เรื่องดี ๆ เกิดขึ้น"},"ICON-1051":{"nm":"การ์ดกำไลอธิษฐาน","de":"กระดาษแผ่นเดียวที่พิมพ์เป็นรูปกำไล บรรจุคำอธิษฐานเงียบ ๆ ของใครสักคนไว้ข้างใน แม้จะสวมรอบข้อมือไม่ได้ แต่หากซุกไว้ลึก ๆ ในกระเป๋าสตางค์ หัวใจดวงนั้นก็ยังผูกติดอยู่ข้างกาย เดินไปด้วยกันเสมอ"},"ICON-1052":{"nm":"ขวดเกลือหน้าประตู","de":"บรรจุเกลือเม็ดหยาบลงในขวดเล็ก ๆ วางไว้เงียบ ๆ หน้าประตู วิธีคิดแต่โบราณที่ไล่พลังชั่วร้ายกลับไป และต้อนรับเพียงแขกที่น่ายินดีเข้ามา เม็ดเกลือแต่ละเม็ดคือยามเฝ้าประตูเล็ก ๆ ที่คอยปกป้องบ้านของเรา"},"ICON-1053":{"nm":"แผ่นปิดตัวเลขนำโชค","de":"ก่อนจะขูด ทุกคนต่างเป็นที่หนึ่งได้สักครู่หนึ่ง แผ่นปิดนี้ที่บดบังตัวเลขนำโชคไว้เบา ๆ ปกป้องวินาทีสุดท้ายที่ความหวังพองโตที่สุดเอาไว้ แม้ปลายนิ้วที่ขูดจะสั่น มันก็แสร้งไม่รู้ไม่เห็นและหลับตาให้"},"ICON-1054":{"nm":"ฝาเก็บเทียนวันเกิด","de":"หัวใจเรียบร้อยที่เก็บรักษาแม้แต่เทียนที่จุดไปแล้วครั้งหนึ่งไว้อย่างดีจนถึงวันเกิดปีถัดไป หากคำอธิษฐานของปีที่แล้วยังไม่สมหวัง ปีนี้ก็เพียงแค่อธิษฐานต่อจากจุดเดิมได้เลย เป็นวิธีคิดที่อ่อนโยนเช่นนั้น"},"ICON-1055":{"nm":"แหวนนับถอยหลังวันครบรอบ","de":"ของชิ้นหนึ่งที่กล้าสวมวันดีเดย์ไว้ที่นิ้วมือ ทุกครั้งที่ตัวเลขวันที่เหลืออยู่หมุนถอยลงทีละขั้น หัวใจก็ถูกดึงเข้ามาใกล้ขึ้นเท่านั้น มันยืนกรานเอาเองว่าเมื่อถึงเลข 0 มันจะเปล่งประกายขึ้นมาเอง"},"ICON-1056":{"nm":"สายรัดหมวกปาร์ตี้","de":"สายเล็ก ๆ ที่ยึดหมวกทรงกรวยไว้บนศีรษะอย่างมั่นคง แม้เจ้าของงานตัวจริงจะบ่นว่าอึดอัดและถอดออกในไม่ช้า แต่ในภาพถ่าย ภาพนั้นยังคงสวมมันไว้ตลอดไป เพียงเท่านี้ก็ถือว่าทำหน้าที่สำเร็จแล้ว"},"ICON-1057":{"nm":"ป้ายปักเค้กชิ้นเล็ก","de":"เครื่องหมายเล็ก ๆ ที่ปักลงบนเค้กขนาดเท่าสองข้อนิ้ว แม้บนความหวานที่จะหายไปในคำเดียว การเฉลิมฉลองก็ยังยืนหยัดอย่างสง่างาม เล็กแค่ไหนวันเกิดก็ยังคงเป็นวันเกิด และวันนี้เธอคือดาวเด่นของงาน"},"ICON-1058":{"nm":"สติกเกอร์ประทัดฉลอง","de":"แม้จะไม่มีเสียงปัง แต่มองดูแล้วคือประทัดกระดาษที่หรูหราที่สุด ในวินาทีที่ติดลงบนซองจดหมาย จดหมายธรรมดาก็แปลงร่างเป็นจดหมายที่ส่งมาจากงานเลี้ยง หลายคนเสียดายจนไม่ยอมแกะออก ปล่อยมันติดไว้อย่างนั้น"},"ICON-1059":{"nm":"คีบแขวนรูปถ่าย","de":"กลัวว่าจะทำความทรงจำที่แขวนอยู่บนเส้นเชือกหล่นหาย ฉันจึงปิดปากแน่นสนิทอยู่เสมอ ตราบใดที่รูปถ่ายแต่ละภาพยังถูกกัดไว้ในปาก แม้แต่ลมที่พัดผ่านช่องหน้าต่างก็ไม่อาจทำให้วันเหล่านั้นร่วงหล่นไปได้"},"ICON-1060":{"nm":"แพตช์ลูกโป่งตัวเลขวันที่","de":"แพตช์รูปลูกโป่งที่มีตัวเลขเขียนไว้ ติดลงบนเสื้อผ้าแล้วทั้งย่านก็จะรู้ว่าวันนี้เป็นวันพิเศษวันที่เท่าไหร่ แกะออกแล้วจะเหลือรอย แต่แม้แต่รอยเลือน ๆ นั้นก็กลายเป็นของที่ระลึกอีกชิ้นหนึ่งได้เช่นกัน"},"ICON-1061":{"nm":"ป้ายแลกเปลี่ยนของขวัญ","de":"เครื่องหมายซุกซนที่ทำให้มือที่รับกับมือที่ให้สับสนกันเล็กน้อย เป็นกฎเล็ก ๆ ที่อ่อนโยนของวงแลกของขวัญ ที่ขอให้จดจำว่าอะไรถูกส่งต่อไปมา มากกว่าจะจำว่าใครเป็นคนให้"},"ICON-1062":{"nm":"ป้ายเลขโต๊ะงานฉลอง","de":"ตัวเลขเล็ก ๆ ที่ตั้งไว้ในแต่ละโต๊ะของงานเลี้ยง การกำหนดล่วงหน้าว่าใครนั่งตรงไหน เพื่อไม่ให้ใครต้องรู้สึกอึดอัดใจต่อกัน บรรจุปัญญาอันอบอุ่นของผู้ที่เคยจัดงานเลี้ยงมาหลายครั้งไว้ในนั้น"},"ICON-1063":{"nm":"ถุงของขวัญแขวนลูกบิดประตู","de":"วิธีส่งต่อหัวใจโดยไม่ต้องกดกริ่งประตู แขวนไว้ที่ลูกบิดเบา ๆ แล้วหายตัวไปราวกับหลบหนี ใบหน้าประหลาดใจของคนที่พบมันเข้า คือของขวัญชิ้นใหญ่ที่สุดที่ย้อนกลับไปหาผู้ให้"},"ICON-1064":{"nm":"ป้ายจัดส่งลับ","de":"ไม่มีอะไรเขียนไว้บนหน้าซองเลย การปิดบังผู้ส่งไว้จนถึงที่สุด คือความภาคภูมิใจเล็ก ๆ ของป้ายนี้ ยิ่งผู้รับเอียงหัวสงสัยและยิ้มออกมานานเท่าไหร่ ภารกิจลับนั้นก็ยิ่งสมบูรณ์แบบมากขึ้นเท่านั้น"},"ICON-1065":{"nm":"ชิปข้อความติดกริ่งประตู","de":"กระดาษโน้ตเล็ก ๆ ที่ติดไว้แทนเมื่อไม่มีความกล้าจะเคาะประตู ประโยคสั้น ๆ เช่น \"แวะมาเยี่ยมสักครู่นะ\" อยู่ในความทรงจำได้นานกว่าเสียงกริ่งประตูเสียอีก เพราะลายมือที่เขียนเบี้ยว ๆ นั้นมีสีหน้าเป็นของตัวเอง"},"ICON-1066":{"nm":"ฝาครอบนิรภัยคัตเตอร์แกะพัสดุ","de":"ยามที่ใบมีดคัตเตอร์แกะพัสดุเล็งไปที่นิ้วโดยไม่ทันระวัง ฮีโร่ตัวเล็ก ๆ จะเข้ามาขวางไว้อย่างเงียบ ๆ มันปกป้องปลายนิ้วที่เร่งรีบด้วยความตื่นเต้นต่อของชิ้นใหม่ ไว้อย่างปลอดภัยจนถึงรอยตัดสุดท้าย"},"ICON-1067":{"nm":"ชิ้นบับเบิลกันกระแทก","de":"ฉันเกิดมาเพื่อให้ถูกกด เสียง \"ป๊อก\" ที่แตกออกนั้น ไม่รู้ทำไมความตึงเครียดของวันก็คลายหายไปด้วย บางวันฉันกลับเป็นที่รักนานกว่าสิ่งของที่ห่อหุ้มอยู่ข้างในเสียอีก"},"ICON-1068":{"nm":"หมุดเวลารับพัสดุ","de":"หมุดที่ปักระบุชัดเจนว่าจะมาถึงกี่โมง แม้การรอคอยที่คลุมเครือ เมื่อมีพิกัดหนึ่งจุด ก็ทนได้ง่ายขึ้นมาก ส่วนจะแอบมองหน้าประตูกี่ครั้งจนกว่าจะถึงเวลานั้น ก็เป็นเรื่องของตัวเธอเองล้วน ๆ"},"ICON-1069":{"nm":"พวงกุญแจตู้รับพัสดุอัตโนมัติ","de":"เพื่อนเล็ก ๆ สำหรับคนที่ลืมรหัสตู้พัสดุอยู่เสมอ ห้อยกรุ๊งกริ๊งอยู่บนพวงกุญแจ ความสามารถแอบแฝงของเพื่อนคนนี้คือการดึงคำว่า \"อ๋อ ใช่\" ออกมาในวินาทีชี้ขาด"},"ICON-1070":{"nm":"ป้ายตะกร้าหน้าบ้าน","de":"ป้ายชื่อที่ติดอยู่บนตะกร้ามุมหนึ่งของทางเข้าบ้าน มีคำมั่นสัญญาไร้เสียงเขียนไว้ว่า \"วางไว้ตรงนี้นะ\" แม้จะว่างเปล่า แต่ที่ที่รอคอยหัวใจของใครสักคนอยู่นั้น ไม่เคยเดียวดาย"},"ICON-1071":{"nm":"สติกเกอร์ปิดที่อยู่","de":"บนกล่องที่กำลังจะทิ้ง เหลือชื่อไว้แต่ลบที่อยู่ออกไป ชื่อนั้นให้ทุกคนรู้ได้ แต่ที่อยู่คือความลับส่วนตัวเท่านั้น ในวินาทีที่ลอกแล้วแปะชั้นบาง ๆ นี้ลงไป ความอุ่นใจเล็ก ๆ ก็เกิดขึ้น"},"ICON-1072":{"nm":"ป้ายกระปุกขนม","de":"ป้ายที่บอกให้รู้ในทันทีว่าข้างในกระปุกมีอะไรอยู่ แต่กับดักคือ พอเขียนว่า \"ขนม\" แล้ว แม้ไม่เปิดฝาก็รู้สึกอุ่นใจอย่างประหลาด ป้ายไม่สามารถรับผิดชอบความอยากอาหารได้หรอกนะ"},"ICON-1073":{"nm":"จี้สร้อยคอเล็ก","de":"เม็ดเล็ก ๆ หนึ่งเม็ดที่แบ่งปันอุณหภูมิร่างกายอย่างเงียบ ๆ อยู่ใต้เสื้อผ้า อยู่ในตำแหน่งที่ไม่มีสายตาใครมองเห็น จึงยิ่งน่ารักน่าเอ็นดูมากขึ้น เป็นเพื่อนที่ใกล้ที่สุดที่เดินไปพร้อมกันตรงหน้าอก"},"ICON-1074":{"nm":"แผ่นประทับรอยเท้า","de":"ประทับลงที่อุ้งเท้าแล้วรอยเท้าเล็ก ๆ ก็เรียงแถวหลงเหลืออยู่ บันทึกการเดินเล่นประจำวันที่จดไว้อย่างเรียบร้อยบนกระดาษว่าใครเดินไปทางไหน ก้าวแรกที่เปื้อนหมึกมักชัดเจนที่สุดเสมอ"},"ICON-1075":{"nm":"ฝาครอบแปรงขนสัตว์","de":"ฝาเล็ก ๆ ที่รับผิดชอบเก็บขนที่พันอยู่ในแปรงให้เรียบร้อย ในฤดูเปลี่ยนผ่านที่แปรงหนึ่งครั้งได้ขนเต็มกำมือ หากไม่มีฝานี้ ทั้งบ้านคงกลายเป็นทุ่งหิมะฟูนุ่มไปหมด เป็นนักทำความสะอาดที่ขยันโดยไม่แสดงตัว"},"ICON-1076":{"nm":"กล่องใส่ถุงเดินเล่น","de":"บ้านเล็ก ๆ ที่พกพาถุงที่ต้องเตรียมไว้สำหรับเส้นทางเดินเล่นอย่างเรียบร้อย มีแต่ผู้ที่เตรียมตัวไว้ล่วงหน้าเท่านั้นที่จะเดินได้อย่างสบายใจ กล่องนี้พิสูจน์เรื่องนี้อย่างเงียบ ๆ ทุกวัน ถุงใบเดียวที่หากลืมแล้วจะเดือดร้อนแน่"},"ICON-1077":{"nm":"แท็กปิดชื่อจริง","de":"แท็กที่แอบปิดชื่อจริงไว้และเหลือไว้แต่ชื่อเล่น บนโลกใบนี้มีความอ่อนโยนบางอย่างที่ไม่อยากเปิดเผยให้ใครก็ได้เห็น การเรียกขานที่มีแต่คนสนิทเท่านั้นที่รู้ ซ่อนตัวอยู่เบา ๆ ที่นี่"},"ICON-1078":{"nm":"แผ่นรองชามน้ำ","de":"ปูอยู่ใต้ชามน้ำ ฉันจึงเปียกชื้นอยู่เสมอ รับหยดน้ำที่กระเซ็นไปทั่วทุกทิศแทน เพื่อรักษาพื้นไม้ให้แห้งฟูอยู่เสมอ ไม่มีใครชมฉัน แต่ฉันเองก็ไม่เคยบ่นสักคำ"},"ICON-1079":{"nm":"ด้ายปะซ่อมของเล่น","de":"ตุ๊กตาที่ตะเข็บหลุดลุ่ยไม่ใช่ของที่ต้องทิ้ง แต่คือของที่ต้องเย็บใหม่ ทุกจุดที่เย็บซ่อมทีละฝีเข็ม เวลาที่ใช้ร่วมกับเจ้าตัวเล็กนั้นก็แน่นหนาขึ้นมาอีกครั้ง ท้ายที่สุดแล้วการซ่อมแซมคือการเลื่อนการจากลาออกไปอย่างเงียบ ๆ"},"ICON-1080":{"nm":"สร้อยคอรูปถ่ายที่ระลึก","de":"หัวใจที่พกพาภาพที่ยิ้มสดใสที่สุดไว้ห้อยคอ วันนั้นในภาพถ่าย แทนที่จะถูกตรึงไว้นิ่ง ๆ กลับแกว่งไกวไปพร้อมกับทุกย่างก้าว และเชื่อมต่อมาจนถึงวันนี้ ช่วงเวลาดี ๆ นั้นไม่เคยหยุดนิ่งเลย"},"ICON-1081":{"nm":"ชิปสีอารมณ์ประจำวัน","de":"ถ้าหัวใจก็มีสีสันเช่นกัน วันนี้สีของเธอจะเป็นสีอะไร ในวินาทีที่เลือกชิปหนึ่งอันมาวางไว้บนโต๊ะ ความรู้สึกที่พูดออกมาเป็นคำไม่ได้ทั้งหมด ก็ค่อย ๆ แผ่ซ่านออกมาอย่างเงียบ ๆ สีตะวันยามเย็นก็ดี สีรุ่งอรุณก็ได้ เพราะมันคือกระจกเล็ก ๆ ที่สะท้อนตัวตนของเธอในวันนั้นอย่างอ่อนโยน"},"ICON-1082":{"nm":"ลูกแก้วบันทึกวันนี้","de":"เมื่อวันเวลาจวนจะสิ้นสุดลง วันนี้ก็ก่อตัวเป็นวงกลมอยู่ในลูกแก้ว ทั้งเรื่องที่ทำได้ดีและเรื่องที่ยังงุ่มง่าม ต่างม้วนตัวเก็บงำและกลิ้งไปด้วยกัน วางไว้บนฝ่ามือ ตัวเธอเมื่อวานก็อุ่นขึ้นเล็กน้อย ตบหลังบอกว่าวันนี้ก็ใช้ชีวิตมาได้ดีแล้ว"},"ICON-1083":{"nm":"ขวดโน้ตคำชม","de":"คำพูดดี ๆ กระจัดกระจายหายไปได้ง่ายเกินไป จึงพับใส่ขวดนี้ไว้ทีละแผ่น เมื่อคำชมสะสมเหมือนกลิ่นหอม ก็เปิดฝาในคืนที่หัวใจรู้สึกโหวงเหวง หยิบความอ่อนโยนที่ใครสักคนเคยมอบให้ออกมาอ่านอีกครั้ง ความอบอุ่นของวันนั้นก็กลับมามีชีวิตอีกครั้ง"},"ICON-1084":{"nm":"เชือกริบบิ้นคืนดี","de":"หัวใจที่พันกันยุ่งเหยิงคล้ายปม การคลี่คลายก็ต้องใช้ความตั้งใจเช่นกัน เมื่อสองคนจับปลายเชือกทั้งสองข้างแล้วค่อย ๆ ดึง ในไม่ช้าก็กลายเป็นริบบิ้นสวยงามหนึ่งเส้น การคืนดีไม่ใช่การตัดขาด แต่คือการผูกกันใหม่ เชือกเส้นนี้บอกไว้อย่างเงียบ ๆ"},"ICON-1085":{"nm":"โทเคนแห่งความขอบคุณ","de":"ในวันที่คำว่า \"ขอบคุณ\" ไม่ยอมหลุดออกจากปาก ก็แอบยื่นโทเคนหนึ่งชิ้นให้แทน มือที่รับไว้อ่านหัวใจได้ทั้งหมดจากน้ำหนักเล็ก ๆ นั้น ความจริงใจที่มาถึงก่อนคำพูด ความรักถูกส่งข้ามไปในเม็ดกลม ๆ เพียงเม็ดเดียว"},"ICON-1086":{"nm":"ป้ายบอกเวลาพัก","de":"แม้แต่ห้องซ้อมที่วิ่งไม่หยุดตลอดทั้งวัน ก็ยังต้องการจังหวะหนึ่งเพื่อหายใจเข้าออก แขวนป้ายนี้ไว้ที่ประตู เวลาก็ช้าลงชั่วขณะ คนที่เคยผ่านวันที่หายใจไม่ทันมาแล้วต่างรู้ดีว่า เพลงต้องมีจังหวะพักถึงจะหายใจได้"},"ICON-1087":{"nm":"ลิ้นชักความรู้สึกลับ","de":"มีบางวันที่ไม่อาจเปิดเผยความในใจออกมาทั้งหมด ในวันเช่นนั้น เก็บทั้งความเศร้าและความตื่นเต้นลงในลิ้นชักเล็ก ๆ ในใจแล้วปิดไว้เงียบ ๆ ตอนนี้จะปล่อยไว้ก็ไม่เป็นไร เพราะสักวันจะมีเวลาเปิดออกมาจัดเรียงอย่างช้า ๆ เอง"},"ICON-1088":{"nm":"ม้วนสติกเกอร์รอยยิ้ม","de":"ฉีกออกทีละดวง เครื่องหมายยิ้มก็ติดอยู่ที่ปลายนิ้ว ความร่าเริงเล็ก ๆ ที่แปะไว้เบา ๆ ที่มุมสมุด หรือที่ล็อกเกอร์ของเพื่อน เมื่อดวงอาทิตย์ดวงน้อยขึ้นบนกระดาษ วันของคนที่พบมันเข้าก็สว่างขึ้นเล็กน้อย"},"ICON-1089":{"nm":"จี้กระดิ่งถามข่าว","de":"ความปรารถนาที่อยากไปให้ถึงเธอผู้อยู่ไกล ก่อตัวเป็นกระดิ่งใบเดียว เขย่าแล้วเสียงใสก็ส่งความคิดถึงแทนคำพูด ในวันที่ไม่กล้าถามว่า \"สบายดีไหม\" เสียงกังวานเล็ก ๆ นี้ล่องลอยไปกับสายลมและไปถึงก่อนใคร"},"ICON-1090":{"nm":"หมุดปิดปกกันฝนฤดูใบไม้ผลิ","de":"ในวันที่ฝนฤดูใบไม้ผลิโปรยลงมา ยิ่งของที่หวงแหนก็ยิ่งเปียกได้ง่าย รัดปกด้วยหมุดนี้แล้วหยดฝนก็จะไถลผ่านไปเฉียง ๆ หัวใจที่โอบกอดหนังสือเล่มหนึ่งที่มีค่าไว้แนบอก หมุดเล็ก ๆ อันเดียวช่วยทำหน้าที่แทนความอ่อนโยนนั้น"},"ICON-1091":{"nm":"สติกเกอร์เย็นฤดูร้อน","de":"แปะเบา ๆ หนึ่งแผ่นบนหลังมือที่เหนื่อยล้าจากความร้อนกลางฤดูร้อน ความเย็นสบายแผ่ซ่านราวกับมินต์ เหงื่อก็ค่อย ๆ จางหายไป ความเย็นสบายจากการนอนพัดวีอยู่บนระเบียงไม้ กระดาษขนาดเท่าฝ่ามือใบนี้เลียนแบบได้อย่างประณีต"},"ICON-1092":{"nm":"เศษผ้าลายสก็อตฤดูใบไม้ร่วง","de":"เศษผ้าลายตารางหนึ่งชิ้นที่คล้ายทุ่งนาในฤดูใบไม้ร่วง เป็นร่องรอยของใครสักคนที่แปะปะจุดที่ขาดไว้อย่างตั้งใจ หัวใจที่เย็บซ่อมแทนการทิ้งขว้าง ผ้าชิ้นเล็ก ๆ รวมตัวกันฟื้นคืนความอบอุ่นให้สิ่งที่สึกหรอกลับมาอีกครั้ง"},"ICON-1093":{"nm":"คลิปหนีบถุงมือฤดูหนาว","de":"ถุงมือฤดูหนาวไม่รู้ทำไมมักหนีหายไปทีละข้างเสมอ ผูกทั้งคู่ไว้ด้วยกันด้วยคลิปนี้แล้ว มือที่หนาวเหน็บก็จะไม่หลงทาง ความปรารถนาที่ไม่อยากทำหาย ฝังอยู่ในโลหะชิ้นเล็ก ๆ นี้ คอยปกป้องทั้งคู่ให้อยู่เคียงข้างกัน"},"ICON-1094":{"nm":"แท็กกันน้ำฤดูฝน","de":"ในฤดูฝน แม้แต่ป้ายชื่อก็ยังเลอะเลือนไปกับสายฝน แท็กเคลือบกันน้ำนี้ปกป้องตัวอักษรไว้ได้แม้ท่ามกลางฝนที่กระหน่ำลงมา บรรทัดหนึ่งที่ยังคงชัดเจนแม้หลังฝนหยุด เพื่อไม่ให้ลืมจนถึงที่สุดว่านี่เป็นของใคร"},"ICON-1095":{"nm":"ขวดเก็บหิมะแรก","de":"หิมะแรกละลายหายไปในทันทีที่สัมผัสมือ จึงเก็บอย่างน้อยความตื่นเต้นนั้นไว้ในขวดนี้ สิ่งที่ถูกกักไว้ในแก้วไม่ใช่หิมะ แต่คือหัวใจที่เต้นตุบตับในวันนั้น เขย่าแล้วฤดูหนาวหนึ่งฤดูก็ปลิวว่อนอีกครั้ง พาไปสู่เช้าวันนั้น"},"ICON-1096":{"nm":"แถบซองเงินเทศกาล","de":"แถบสีแดงเส้นหนึ่งที่พันรอบซองเงินในวันเทศกาล ทุกคนต่างรู้ว่าความรักจากมือที่ยื่นให้นั้นยิ่งใหญ่กว่าสิ่งที่อยู่ข้างในเสียอีก หัวใจที่ห่อคำอวยพรให้อยู่ดีมีสุขไว้ด้วยกัน ผูกอยู่อย่างงดงามในแถบเล็ก ๆ เส้นนี้"},"ICON-1097":{"nm":"แถบรัดภาชนะปิกนิก","de":"ปูเสื่อและเปิดกล่องอาหารกลางแจ้ง สายลมก็มักจะยกฝาขึ้นอยู่เรื่อย ๆ รัดภาชนะให้แน่นหนาด้วยแถบนี้ แล้วปิกนิกก็จะไม่ยุ่งเหยิง หัวใจที่ตั้งใจปกป้องมื้ออาหารที่เตรียมมาจนถึงวินาทีสุดท้าย บรรจุอยู่ในแถบเล็ก ๆ เส้นเดียว"},"ICON-1098":{"nm":"การ์ดตัวอย่างกลิ่นฤดูกาล","de":"เพื่อให้รู้ฤดูกาลได้แม้ไม่เปิดออกดู กลิ่นหอมของฤดูนั้นถูกบรรจุไว้ในการ์ดเพียงใบเดียว ฤดูใบไม้ผลิคือกลิ่นดอกไม้ ฤดูใบไม้ร่วงคือกลิ่นใบไม้แห้ง ในวินาทีที่สัมผัสปลายจมูก ฤดูกาลนั้นก็ผุดขึ้นมาทั้งหมด นี่แหละคืออากาศของเดือนเมษายน"},"ICON-1099":{"nm":"คลิปบอร์ดป้ายราคา","de":"คลิปบอร์ดเพียงอันเดียวนี้ระงับปัญหาป้ายราคาที่ปลิวหายไปเรื่อย ๆ ของแผงขายของได้ มันกัดตัวเลขไว้อย่างมั่นคงและยื่นตรงไปให้ลูกค้าเห็นอย่างเที่ยงตรง คำทักทายแรกของการค้าขายเริ่มต้นจากบรรทัดที่ซื่อตรงและไม่บิดเบี้ยว"},"ICON-1100":{"nm":"ป้ายพลิกเปิด-ปิดร้าน","de":"พลิกป้ายนี้แขวนไว้หน้าประตู ร้านก็ตื่นขึ้นในที่สุด จาก \"กำลังเตรียมตัว\" เป็น \"ยินดีต้อนรับ\" สัญญาณเล็ก ๆ ที่ประกาศจุดเริ่มต้นของวัน คือจุดที่มือของเจ้าของร้านแตะถึงเป็นที่แรกทุกเช้า"},"ICON-1101":{"nm":"แผ่นปั๊มตราคูปองสะสมแต้ม","de":"เมื่อประทับตราจนครบสิบช่อง ราวกับจะมีเรื่องดีๆ เกิดขึ้นเสมอ ตราปั๊มแต่ละดวงคือรอยเท้าของลูกค้าประจำ คือความผูกพันที่ค่อยๆ สั่งสมมา ทุกรอยที่กดจนหมึกแห้งคาแผ่น คือคำสัญญาเล็กๆ ว่าจะกลับมาอีกครั้ง ซึ่งยังมีลมหายใจอยู่ในนั้น"},"ICON-1102":{"nm":"ฝาครอบหูจับถุงกระดาษ","de":"หูจับของถุงกระดาษมักอ่อนแอเมื่อต้องแบกน้ำหนัก แต่เมื่อสวมฝาครอบนี้เข้าไป เชือกที่เหมือนจะขาดก็กลับแข็งแรงขึ้นมา หัวใจที่อยากพาสิ่งที่บรรจุอยู่ไปถึงบ้านอย่างปลอดภัย ชิ้นส่วนเล็กๆ เพียงชิ้นเดียวช่วยประคับประคองเส้นทางนั้นไปจนสุดทาง"},"ICON-1103":{"nm":"ถาดวางเหรียญหน้าแคชเชียร์","de":"จานใบนี้ช่วยปัดเป่าความลังเลในวินาทีที่ต้องส่งเงินทอนจากมือสู่มือไปอย่างเงียบๆ เสียงเหรียญกรุ๊งกริ๊งเมื่อตกลงในที่ของมัน การให้และการรับกลายเป็นเรื่องอบอุ่นขึ้นมาได้ ก็เพราะความใส่ใจกลมๆ ใบนี้เอง"},"ICON-1104":{"nm":"ชิปสะสมแต้ม","de":"ก้าวเท้าที่เหยียบย่ำในวันนี้ค่อยๆ สะสมอยู่ในชิปเพียงชิ้นเดียว วิธีนับที่แปลกประหลาด ยิ่งสะสมมากใจก็ยิ่งเบาสบาย ความสุขจากการเติมเต็มไปทีละนิด คล้ายกับความปีติที่ได้เฝ้ามองโหลเปล่าค่อยๆ เต็มขึ้นโดยไม่ทันรู้ตัว"},"ICON-1105":{"nm":"ป้ายเข็มหมายเลขชั้นวาง","de":"บนชั้นวางแต่ละชั้นมีตัวเลขเล็กๆ ปักอยู่อย่างอ่อนโยน เป็นเข็มทิศเงียบๆ ที่บอกว่าอะไรอยู่ตรงไหน หัวใจที่คอยบอกตำแหน่งล่วงหน้าเพื่อไม่ให้ใครหลงทาง แม้แต่ความเป็นระเบียบก็ยังแฝงไออุ่นเช่นนี้ได้"},"ICON-1106":{"nm":"ถ้วยไม้เสียบชิมอาหาร","de":"ถ้วยเล็กๆ ที่เสียบคำชิมยื่นออกมาให้ แม้ลูกค้าที่ลังเลก็ยังแง้มใจให้กับคำเดียวนี้ได้ ความมีน้ำใจที่ชวนว่า \"ลองสักคำสิ\" ห้อยอยู่ที่ปลายไม้เสียบ คอยดึงรั้งฝีเท้าของผู้มาเยือนครั้งแรกเอาไว้"},"ICON-1107":{"nm":"ที่ตั้งรายชื่อจอง","de":"ชื่อของแขกที่จะมาในวันนี้เรียงรายอยู่อย่างเป็นระเบียบในที่ตั้งนี้ คำสัญญาแสนอ่อนโยนที่ว่าแม้แต่การรอคอยก็ยังมีลำดับก่อนหลัง การตั้งกระดาษเพียงแผ่นเดียวให้ยืนตรง คือการเตรียมพร้อมขั้นแรกที่จะต้อนรับวันของใครสักคนอย่างตั้งใจ"},"ICON-1108":{"nm":"คลิปหนีบรูปแขวนผนัง","de":"ขึงเชือกไว้บนผนังแล้วหนีบรูปถ่ายทีละใบด้วยคลิป ช่วงเวลาแห่งรอยยิ้มห้อยเรียงกันตากแห้งราวกับผ้าซักอยู่บนราวตากผ้า แขวนความทรงจำไว้ตรงมุมที่แดดส่องถึง ทุกครั้งที่เดินผ่าน เสียงหัวเราะของวันนั้นก็โบกสะบัดขึ้นมาอีกครั้ง"},"ICON-1109":{"nm":"พรมผืนเล็กมุมห้อง","de":"พรมผืนเล็กที่ปูอยู่ริมห้อง คือจุดที่แผ่ไออุ่นให้พื้นเย็นๆ เป็นที่แรก ฝ่าเท้าเปล่าที่แตะถึงเป็นระยะแรกนั้น คือปลายเท้าของคนที่กลับมาถึงบ้านแล้วในที่สุดก็ได้พักผ่อนใจและเมื่อยล้าอย่างอุ่นสบายตรงนี้เอง"},"ICON-1110":{"nm":"ผ้าคลุมป้ายชื่อหน้าบ้าน","de":"ผืนผ้าที่ปิดบังป้ายชื่อไว้อย่างแผ่วเบา การซ่อนชื่อไว้สักพักก็เป็นเสน่ห์อย่างหนึ่งของการดูแลบ้าน ผ้าผืนหนึ่งที่พาดกั้นเขตแดนระหว่างข้างในกับข้างนอกอย่างงดงาม แขวนไว้อย่างอ่อนโยนด้วยความรู้สึกว่าวันนี้อยากพักผ่อนอย่างเงียบๆ"},"ICON-1111":{"nm":"คลิปหนีบสายไฟไฟประดับ","de":"คลิปตัวนี้จับสายไฟที่ห้อยระโยงระยางให้เรียบร้อย มือที่คอยยืดเส้นทางให้ตรงเพื่อไม่ให้แสงกระจัดกระจาย เมื่อค่ำคืนใกล้เข้ามาแล้วรวบสายที่ยุ่งเหยิงเส้นหนึ่งให้เข้าที่ ทั้งแสงในห้องและใจก็สงบขึ้นเช่นกัน"},"ICON-1112":{"nm":"ฝาแม่เหล็กติดโปสเตอร์","de":"ฝาแม่เหล็กเล็กๆ สำหรับติดโปสเตอร์บนผนัง กระดาษยึดอยู่กับที่ได้โดยไม่ต้องเจาะรูหมุดแม้แต่รูเดียว มือที่ทะนุถนอมสิ่งที่รักมักอ่อนโยนเสมอ หัวใจที่ไม่อยากให้สิ่งนั้นเสียหายถูกบรรจุไว้ตรงนี้"},"ICON-1113":{"nm":"เชือกพู่รวบผ้าม่าน","de":"เชือกพู่ที่รวบชายผ้าม่านไปไว้ข้างหนึ่ง เปิดเส้นทางอันงดงามให้แสงแดดยามเช้าเล็ดลอดเข้ามา เพียงดึงเชือกพู่เพียงครั้งเดียว วันอันสดใสก็ทะลักเข้ามาเต็มห้องและอยู่ที่นั่นต่อไป"},"ICON-1114":{"nm":"ป้ายฐานเทียนหอม","de":"ป้ายเล็กๆ ที่แปะบนฐานเทียนหอม จดไว้อย่างเรียบร้อยว่ากลิ่นไหนกำลังลุกไหม้ จุดขึ้นครั้งแรกเมื่อไหร่ การตั้งชื่อให้กับกลิ่นหอมที่รัก ความประณีตนี้เองที่ทำให้อากาศในห้องอ่อนโยนขึ้นอีกนิด"},"ICON-1115":{"nm":"ขาลูกยางกันโยกชั้นวางของ","de":"ขาลูกยางสี่จุดที่คอยค้ำชั้นวางไม่ให้โคลงเคลง แบกรับน้ำหนักอย่างเงียบเชียบจากมุมที่ไม่มีใครมองเห็น เล็กและต่ำจนไม่สะดุดตา แต่สิ่งที่ยืนหยัดอยู่ล่างสุดนั้นเองคือสิ่งที่อยู่ทนนานที่สุดในท้ายที่สุด"},"ICON-1116":{"nm":"จี้ป้ายลูกศรบอกทาง","de":"สำหรับคนที่ลังเลว่าจะไปทางไหนดี ลูกศรดวงหนึ่งชี้ทิศทางให้อย่างเงียบๆ ท่าทีอ่อนโยนที่บอกว่าอย่าหลงทางเลยนะ ด้วยหัวใจของใครสักคนที่ตั้งไว้ล่วงหน้าที่ทางแยกทุกแห่ง วันนี้เราจึงเดินหน้าต่อไปได้โดยไม่หลงทาง"},"ICON-1117":{"nm":"พวงกุญแจเชิญสู่เกาะ","de":"พวงกุญแจที่ถูกส่งมาไว้ในมือของผู้เชิญชวนให้มาที่เกาะ รับมันไว้แล้วเธอก็เป็นครอบครัวของที่นี่แล้ว การต้อนรับที่โอบรับแขกแปลกหน้าเข้าสู่ความอบอุ่นภายใน ถูกบรรจุไว้อย่างมั่นคงในคำสัญญาเล็กๆ ที่ห้อยอยู่ปลายเชือก"},"ICON-1118":{"nm":"ชิปวัดอุณหภูมิความสัมพันธ์","de":"ชิปเพียงชิ้นเดียวแอบบอกอุณหภูมิระหว่างคนสองคนให้รู้ ว่ายังเป็นสีฟ้าเขินอายอยู่ หรือกลายเป็นสีแดงอมส้มอันอบอุ่นไปแล้วโดยไม่ทันรู้ตัว ความเร็วที่ความผูกพันลึกซึ้งขึ้นนั้นวัดได้ยาก แต่ฝ่ามือกลับสัมผัสได้ถึงไอความอบอุ่นนั้นก่อนใคร"},"ICON-1119":{"nm":"กล่องตัวอย่างของโปรด","de":"ยามที่ยังไม่รู้ว่าใครชอบอะไร ก็รวบรวมตัวอย่างเล็กๆ ใส่กล่องแล้วยื่นให้ ท่ามกลางความสนุกของการเลือก รสนิยมก็ค่อยๆ เติบโตขึ้นทีละน้อย จะมีชิ้นไหนที่กลายเป็นของเธอบ้างนะ ในกล่องนั้นเต็มไปด้วยความเป็นไปได้ที่น่าตื่นเต้น"},"ICON-1120":{"nm":"เข็มหมุดจองคิวดูแล","de":"คำสัญญาว่าจะดูแลใครสักคนถูกปักลงไว้อย่างชัดเจนในเข็มหมุดเพียงตัวเดียวนี้ เขียนชื่อและเวลากำกับไว้ หัวใจก็จะไม่หลงทาง การผลัดกันดูแลลูกของกันและกันอย่างอบอุ่นในสมัยก่อนนั้น ยังมีลมหายใจอยู่ตรงนี้เอง"},"ICON-1121":{"nm":"แคปซูลบันทึกการเติบโต","de":"เหมือนรอยวัดส่วนสูงที่ค่อยๆ สะสมทีละขีดบนกรอบประตู แคปซูลใบนี้ผนึกตัวตนของเธอเมื่อวานเก็บไว้อย่างเงียบๆ วันหนึ่งในอนาคตอันไกลโพ้น เมื่อเปิดฝาออกเธอจะได้รู้ว่าก้าวเท้าเล็กๆ นั้นได้เดินมาไกลแค่ไหนแล้ว"},"ICON-1122":{"nm":"ริบบิ้นเก็บความทรงจำวันแรกพบ","de":"ความสั่นไหวในวันที่จับมือกันครั้งแรก ถูกผูกไว้อย่างแผ่วเบาในริบบิ้นเพียงเส้นเดียว ปมที่ผูกไว้ไม่ได้มีไว้เพื่อคลายออก แต่อยู่ตรงนั้นเพื่อให้ไออุ่นของวันนั้นยังมีชีวิตอยู่ที่ข้อมือต่อไป"},"ICON-1123":{"nm":"ป้ายของตกแต่งมายรูม","de":"\"ตรงนี้คือที่ของฉัน\" ในวินาทีที่ป้ายเล็กๆ ใบเดียวถูกแปะไว้ที่มุมโต๊ะ ห้องที่เคยแปลกหน้าก็หายใจได้ในที่สุดและกลายเป็นมายรูม ป้ายชื่อคือที่แรกที่หัวใจได้ลงหลักปักฐาน"},"ICON-1124":{"nm":"กระปุกลูกแก้ววัดความสนิทสนม","de":"เขย่าแล้วก็จะได้ยินเสียงกลิ้งกรุ๊งกริ๊ง เสียงของความสัมพันธ์ที่ขยับใกล้กันอีกหนึ่งขั้น เมื่อกระปุกใบนี้เต็มขึ้นเรื่อยๆ แค่เอ่ยชื่อเธอ เสียงหัวเราะก็คงออกมาต้อนรับก่อนใครแล้วล่ะ"},"ICON-1125":{"nm":"สติกเกอร์ปิดผนึกเตรียมเดบิวต์","de":"แผ่นสุดท้ายที่ปิดผนึกซองจดหมาย มาถึงตรงนี้คือการเตรียมตัว พลิกหน้าถัดไปก็คือเวทีแล้ว เด็กฝึกกดปลายนิ้วลงอย่างหนักแน่นพร้อมกับปรับลมหายใจให้เรียบ ในที่สุดก็จะเริ่มต้นแล้วสินะ"},"ICON-1126":{"nm":"น้ำ","de":"สิ่งที่ธรรมดาที่สุดกลับล้ำค่าที่สุด ในห้องซ้อมยามรุ่งสางที่ไฟดับ น้ำเพียงอึกเดียวช่วยพยุงคนที่ทรุดตัวลงให้ลุกขึ้นยืนอีกครั้ง ความอ่อนโยนที่ไร้รูปทรงของตัวเองแทรกซึมเข้าไปในภาชนะใดก็ได้"},"ICON-1127":{"nm":"น้ำใส","de":"ความใสที่สะท้อนก้อนกรวดใต้พื้นได้อย่างแจ่มชัด บ่อน้ำในหุบเขาไม่เคยอวดความใสของตัวเองสักครั้ง หัวใจที่ไม่มีอะไรต้องปิดบัง ก็มักมองทะลุถึงก้นบึ้งได้เช่นนี้เสมอ"},"ICON-1128":{"nm":"น้ำทะเล","de":"วินาทีที่แตะปลายลิ้น คลื่นจากแดนไกลก็ซัดโถมเข้ามา ในรสเค็มเพียงอึกเดียว เส้นขอบฟ้าและนกนางนวลและท่าเรือที่จากมา ล้วนละลายรวมกันอยู่ในนั้นทั้งหมด ทะเลมักหลงเหลืออยู่ในความทรงจำด้วยรสเค็มเสมอ"},"ICON-1129":{"nm":"น้ำแข็ง","de":"มันค่อยๆ เล็กลงบนฝ่ามือ หายไปมากเท่าที่กำไว้ แม้ดูแข็งแกร่งแต่ก็รู้ดีว่าสุดท้ายแล้วจะกลับคืนสู่สายน้ำ น้ำแข็งคือสายน้ำที่หยุดหายใจไว้ชั่วครู่"},"ICON-1130":{"nm":"ก้อนหิมะ","de":"ก้อนที่ปั้นแน่นก้อนหนึ่งพุ่งขาวโพลนตัดผ่านตรอกซอย เสียงหัวเราะคิกคักและแก้มที่แดงก่ำด้วยความหนาว ของเล่นขาวที่สุดที่ฤดูหนาวแอบยื่นให้เด็กๆ ถือไว้ในมือ"},"ICON-1131":{"nm":"ดิน","de":"มันโอบอุ้มเมล็ดพันธุ์ ดื่มน้ำฝน และรับรอยเท้าที่เดินผ่านไว้อย่างเงียบงัน ผิวสีดำที่โอบกอดทุกสิ่งไว้ ณ จุดเริ่มต้นของทุกสิ่งที่เติบโต มีดินกำมือนี้อยู่เสมอ"},"ICON-1132":{"nm":"ดินอุดมสมบูรณ์","de":"จุ่มนิ้วลงไปแล้วความมันเยิ้มสีดำก็โอบรัดมาอย่างนุ่มนวล ความลับที่ทำให้แปลงผักของคุณยายเขียวชอุ่มทุกปีอยู่ตรงนี้เอง ดินที่บ่มมานานกระซิบถึงฤดูเก็บเกี่ยวอันอุดมด้วยกลิ่นปุ๋ยหมัก"},"ICON-1133":{"nm":"ดินเหนียว","de":"วินาทีที่ดูดซับความชื้น มันยอมรับรูปทรงใดๆ ก็ได้อย่างว่านอนสอนง่าย เนื้อดินอ่อนโยนที่กลายเป็นนกและกลายเป็นชามตามการสัมผัส ระหว่างที่แป้นหมุนหมุนไป ดินกำมือหนึ่งก็เริ่มฝันขึ้นมาในที่สุด"},"ICON-1134":{"nm":"ทราย","de":"เม็ดทรายละเอียดที่ไหลลอดผ่านง่ามนิ้วไปอย่างเงียบเชียบ ยิ่งพยายามกำไว้ยิ่งไหลเร็วขึ้น ราวกับพยายามเลียนแบบเวลาอยู่เสมอ ในทรายชายหาดกำมือหนึ่งมีวันวานนับไม่ถ้วนหลับใหลอยู่"},"ICON-1135":{"nm":"กรวด","de":"ก้อนหินที่สึกกลมมนอยู่ริมลำธาร คือร่องรอยที่สายน้ำลูบไล้อย่างยาวนานจนมุมคมหายไปหมด ยิ่งเคยกลิ้งไปไกลเท่าไหร่ ก็ยิ่งซุกตัวอยู่ในมือได้อย่างนุ่มนวลเท่านั้น"},"ICON-1136":{"nm":"ก้อนหิน","de":"ก้อนหินที่วางทิ้งไว้เฉยๆ ริมทาง บางคนเตะผ่านไปเฉยๆ บางคนหยิบขึ้นมาเงียบๆ แล้วก่อเป็นเจดีย์หิน หินก้อนเดียวกันกลายเป็นภาระหรือคำอธิษฐานก็ได้ ขึ้นอยู่กับหัวใจของผู้นั้น"},"ICON-1137":{"nm":"แผ่นหินปูพื้น","de":"แผ่นหินแบนกว้างที่ปูขวางลานพระราชวังเก่า รองเท้านับร้อยปีเหยียบย่ำผ่านจนตรงกลางเป็นแอ่งบุ๋มลงไป ทุกคนที่ก้าวเท้าลงไปทีละก้าว ต่างเติมชั้นของกาลเวลาลงไปอีกชั้นหนึ่งเสมอ"},"ICON-1138":{"nm":"หินปูน","de":"เปลือกหอยจากวันที่ยังเป็นทะเลแข็งตัวซ้อนทับกันจนกลายเป็นหินสีขาว เมื่อเข้าเตาเผาก็คลายตัวเป็นปูนขาวทาผนังให้ขาวโพลน แม้ดูสงบนิ่งแต่ก็เป็นหินที่โอบอุ้มยุคสมัยหนึ่งไว้ทั้งยุค"},"ICON-1139":{"nm":"ถ่านหิน","de":"ป่าเก่าแก่ที่หลับใหลไปอย่างดำมืด เฟิร์นจากหลายร้อยล้านปีก่อนที่จับตัวแน่นอยู่ลึกใต้ดิน จุดไฟให้มันติด แสงแดดที่ฝังไว้นานแสนนานก็ตื่นขึ้นมาลุกโชนอีกครั้ง"},"ICON-1140":{"nm":"ถ่าน","de":"มันเก็บไฟไว้แต่กลืนควันไว้อย่างเงียบๆ ไม้ที่ถูกอัดจนดำสนิทในเตาเผา ผลิบานเป็นสีแดงอย่างไร้คำพูดบนเตาไฟ สิ่งที่นิ่งเงียบยิ่งเท่าไหร่ ก็ยิ่งอบอุ่นได้นานเท่านั้น"},"ICON-1141":{"nm":"กิ่งไม้","de":"กิ่งไม้ที่โค้งงออย่างเงียบๆ เพื่อไม่ให้หัก รู้จักวิถีของการยอมโอนอ่อน ทุกจุดที่ทนต่อลมแรงมาได้ กลายเป็นปุ่มปม และความแข็งแกร่งที่แท้จริงนั้น ในที่สุดก็คือรอยแห่งการโอนอ่อนได้อย่างดีนั่นเอง"},"ICON-1142":{"nm":"ท่อนซุง","de":"ในวงปีที่ถูกตัดขาด มีฤดูใบไม้ผลิและฤดูหนาวนับร้อยครั้งซ้อนทับกันเป็นวงกลม กาลเวลาที่ต้นไม้ต้นหนึ่งใช้ชีวิตผ่านมาทั้งหมดนอนราบอยู่ตรงนี้ รอคอยอย่างเงียบๆ ที่จะกลายเป็นเสาบ้านในลำดับต่อไป"},"ICON-1143":{"nm":"ไม้แปรรูป","de":"ทุกครั้งที่กบไสไม้ผ่านไป ลายไม้หอมกรุ่นก็ปรากฏขึ้นทีละชั้น ระหว่างที่ไม้หยาบกร้านค่อยๆ เรียบเนียนขึ้น ขี้เลื่อยก็กองอยู่บนพื้นราวหิมะสีเหลือง มือที่ตกแต่งไม้คือมือที่ปลุกคุณค่าของมันให้ตื่นขึ้น"},"ICON-1144":{"nm":"แผ่นไม้กระดาน","de":"มันปูเป็นพื้นห้อง กรุเป็นแคร่ ล้อมเป็นรั้ว เมื่อแผ่นไม้ที่เลื่อยไว้เป็นเหลี่ยมมุมมาชุมนุมกันทีละแผ่น ในที่สุดที่อยู่อาศัยของผู้คนก็ตั้งขึ้นได้ สิ่งธรรมดาสามัญเมื่อสะสมกันจึงกลายเป็นบ้าน"},"ICON-1145":{"nm":"ไม้ไผ่","de":"ข้างในกลวงเปล่าแต่ยังยืนตรงต้านลมได้ ความเด็ดเดี่ยวที่ขาดแล้วแตกหน่อใหม่ในทุกข้อปล้องนั้น นักปราชญ์สมัยก่อนล้วนปรารถนาจะเลียนแบบ ตรงนี้มีสิ่งที่ยิ่งกลวงเปล่ากลับยิ่งยืนหยัดได้อย่างน่าทึ่ง"},"ICON-1146":{"nm":"ไม้ก๊อก","de":"กดลงแล้วปล่อยมือก็พองคืนสู่ความหนาเดิมได้อีกครั้ง มองลายเนื้อที่เบาแต่เหนียวแน่นนี้แล้วจะรู้ว่าความอ่อนนุ่มไม่ใช่ความอ่อนแอเลยสักนิด ตั้งแต่จุกขวดไปจนถึงบอร์ดติดประกาศ มันคอยค้ำจุนอย่างเงียบๆ เสมอ"},"ICON-1147":{"nm":"หญ้า","de":"แม้ถูกเหยียบย่ำแต่พอฝนตกครั้งถัดไปก็ลุกขึ้นยืนได้อีก ความเหนียวแน่นสีเขียวที่ปกคลุมทุ่งกว้างทั้งผืนโดยไม่มีแม้แต่ชื่อของตัวเอง อย่าดูแคลนความเล็กของมันนะ สิ่งที่ประกาศฤดูใบไม้ผลิเป็นอันดับแรกเสมอ ก็คือที่ต่ำต้อยแห่งนี้เอง"},"ICON-1148":{"nm":"ฟาง","de":"สิ่งที่หลงเหลือเป็นสีเหลืองอยู่ในท้องนาหลังฤดูเก็บเกี่ยวสิ้นสุด สานเข้าด้วยกันก็เป็นหลังคา ปูรองก็เป็นที่นอนอันอบอุ่น เป็นหัวใจที่มอบเมล็ดข้าวทุกเมล็ดออกไปจนหมดแล้ว แต่ยังคงคลุมกายมนุษย์ไว้จนถึงวินาทีสุดท้าย"},"ICON-1149":{"nm":"ต้นกก","de":"เมื่อลมพัดผ่าน เสียงกรอบแกรบก็ดังขึ้น ริมฝั่งแม่น้ำทั้งผืนขับขานเป็นบทเพลง ก้านที่กลวงเปล่าข้างในกลับร่ำไห้ไปได้ไกลกว่าใคร การโอนเอนไหวไปมานั้นเองคือบทเพลงของตัวมัน ต้นกกไม่เคยอับอายกับสิ่งนี้แม้แต่นิดเดียว"},"ICON-1150":{"nm":"ฝ้าย","de":"เมื่อฝักที่สุกงอมแตกออกด้วยเสียงป๊อก ดอกเมฆน้อยๆ ดอกหนึ่งก็ผลิบาน ปุยนุ่มเบาแผ่วนี้กลายเป็นเส้นด้ายและกลายเป็นเสื้อผ้า คอยให้ความอบอุ่นแก่บ่าของใครสักคนอย่างแผ่วเบาในค่ำคืนหนาวเหน็บ"},"ICON-1151":{"nm":"ขนแกะ","de":"เมื่อสัมผัสด้วยมือจะรู้สึกถึงความมันเยิ้มและไออุ่นที่หลงเหลืออยู่อย่างเงียบๆ เสื้อคลุมที่แกะห่มไว้บนตัวเองเพื่อทนความหนาวของภูเขา ความอบอุ่นที่ถูกตัดออกมานั้น บัดนี้ได้ย้ายมาสู่ฤดูหนาวของมนุษย์แล้ว"},"ICON-1152":{"nm":"เส้นด้าย","de":"แม้บางจนแทบมองไม่เห็น แต่สิ่งที่เชื่อมชายผ้าสองข้างที่หลุดออกจากกันให้กลับมาติดกันเสมอก็คือสิ่งนี้ เส้นเดียวอาจอ่อนแอ แต่เมื่อสานทอกันแล้วก็กลายเป็นผืนผ้าได้ทั้งผืน ในงานเชื่อมโยงนั้น ความหนาไม่ใช่เรื่องสำคัญเลย"},"ICON-1153":{"nm":"ผืนผ้า","de":"เส้นพุ่งและเส้นยืนไขว้กันนับครั้งไม่ถ้วนจนเกิดเป็นผืนผ้าหนึ่งผืน คือผลลัพธ์ของเส้นด้ายที่แม้อยู่ลำพังจะคลี่คลายหลุดออก แต่กลับยึดเกาะกันไว้แน่น ยิ่งทอถี่เท่าไหร่ก็ยิ่งอบอุ่นเท่านั้น ระหว่างคนกับคนก็เช่นเดียวกัน"},"ICON-1154":{"nm":"หนัง","de":"ยิ่งใช้งานมากเท่าไหร่ ร่องรอยการสัมผัสก็ยิ่งซึมเข้าไป ค่อยๆ คล้ายกับเจ้าของขึ้นทุกที ระหว่างที่ความแข็งกระด้างในตอนแรกค่อยๆ นุ่มลง สีก็เข้มขึ้นและลายก็อ่อนนุ่มขึ้น ความเงางามที่กาลเวลาแกะสลักไว้นั้น ไม่มีสิ่งใดเลียนแบบได้"},"ICON-1155":{"nm":"ขนนก","de":"เบาจนแทบไม่รู้สึกถึงน้ำหนักแม้จะวางอยู่บนฝ่ามือ เส้นขนเส้นเดียวที่ยังคงบรรจุความทรงจำแห่งการโบยบินกลางท้องฟ้าไว้อย่างครบถ้วน อย่าได้ลืมเลยว่า สิ่งที่เบาที่สุดนั้นแหละคือสิ่งที่เคยลอยขึ้นไปสูงที่สุด"},"ICON-1156":{"nm":"เปลือกหอย","de":"คำพูดของคุณยายที่บอกให้แนบหูฟังดูสิ ผุดขึ้นมาในใจโดยไม่ทันตั้งตัว บนผิวมุกสีรุ้งด้านในมีทะเลที่จากมาสลักไว้ทั้งผืน แม้เป็นเพียงเปลือกที่ว่างเปล่าก็ยังได้ยินเสียงคลื่นซัดของยุคสมัยหนึ่งดังก้องอยู่"},"ICON-1157":{"nm":"ปะการัง","de":"แม้แข็งราวกับหิน แต่ครั้งหนึ่งก็เคยเป็นกลุ่มสิ่งมีชีวิตที่หายใจได้อย่างแน่นอน ในท้องทะเลอันเชื่องช้า มันใช้เวลาหลายร้อยปีค่อยๆ แผ่กิ่งก้านออกไป กิ่งที่แข็งแกร่งที่สุดนั้นเติบโตขึ้นได้ก็ต่อเมื่อรอคอยมานานที่สุดเท่านั้น"},"ICON-1158":{"nm":"ไข่มุก","de":"เมื่อทนความระคายเคืองของเม็ดทรายเม็ดหนึ่งไม่ไหวอีกต่อไป หอยจึงห่อหุ้มมันไว้ด้วยแสงอย่างเงียบๆ หากโอบกอดความเจ็บปวดให้กลมมนได้ มันก็จะเปล่งประกายงดงามเช่นนี้ นี่คือคำปลอบโยนเล็กๆ ที่ทะเลมอบให้"},"ICON-1159":{"nm":"สาหร่ายทะเล","de":"แถบสีเขียวที่พาดลื่นอยู่บนโขดหินยามน้ำลด เมื่อจับด้วยมือกลิ่นคาวทะเลก็โชยแรงขึ้นมาทันที ไร้แม้แต่รากที่จะยึด มอบกายทั้งหมดให้กระแสน้ำพัดพา ทะเลเพาะปลูกสวนของตัวเองอย่างเงียบๆ เช่นนี้เอง"},"ICON-1160":{"nm":"สาหร่ายแผ่น","de":"ลนแผ่นสีดำแผ่นหนึ่งไฟอ่อนๆ สักครู่ก็เขียวขึ้นและกลิ่นหอมกรุ่นก็โชยกระจาย เช้าวันนั้นที่ห่อข้าวสวยร้อนๆ ม้วนกิน แม้บางเฉียบแต่ก็โอบกอดความสุขของมื้ออาหารหนึ่งมื้อไว้ได้อย่างเต็มเปี่ยม"},"ICON-1161":{"nm":"เกลือ","de":"ฉันคือผลึกสีขาวที่ทะเลทิ้งไว้ให้แดดตาก หยิบเพียงหยิบมือเดียวก็ทำให้ซุปจืดชืดกลมกล่อมขึ้นได้ แต่หากมือลื่นไปหน่อยก็กลบรสทุกอย่างจนหมดสิ้น มีเพียงปลายนิ้วที่รู้จักความพอดีเท่านั้นที่จะใช้ฉันได้อย่างถูกต้อง"},"ICON-1162":{"nm":"เศษแก้ว","de":"ก็ต่อเมื่อแตกออก ณ จุดนั้นเองมันจึงหักเหแสงจนเกิดเป็นสายรุ้งขึ้นมาได้ เป็นความสามารถที่ไม่เคยรู้ตัวเลยตอนที่ยังสมบูรณ์ แม้แต่สิ่งที่แตกหักก็ยังมีส่วนแบ่งแสงแดดเหลืออยู่ให้มอบต่อ เศษแก้วที่นอนอยู่ริมหน้าต่างกระซิบบอกอย่างเงียบๆ เช่นนั้น"},"ICON-1163":{"nm":"กระจก","de":"ความใสไม่ได้แปลว่าไม่มีอะไรต้องปิดบังเสมอไป มันเพียงลบเลือนรูปลักษณ์ของตัวเองไปเพื่อให้แสงผ่านทะลุได้อย่างครบถ้วน แม้จะดำรงอยู่ตรงนั้นโดยไม่มีใครมองเห็น แต่เมื่อมือแตะสัมผัส ก็ยังมีความเรียบร้อยเย็นชืดอยู่ในนั้น"},"ICON-1164":{"nm":"ขวดแก้ว","de":"ต้องว่างเปล่าอยู่ข้างในเสียก่อนจึงจะบรรจุอะไรได้ ไม่ว่าจะเป็นแยม หรือดอกไม้ป่ากำมือหนึ่ง หรือจดหมายที่พับใส่เข้าไป ชื่อของมันเปลี่ยนไปตามสิ่งที่บรรจุอยู่ข้างใน ภาชนะที่ไม่หวาดกลัวความว่างเปล่านั้นแหละคือภาชนะที่เอื้อเฟื้อที่สุด"},"ICON-1165":{"nm":"ขวดเปล่า","de":"ฉันชอบความเงียบสงบที่มาเยือนหลังจากดื่มจนหมดแล้ว บางคนก็ทิ้งฉันไป บางคนก็ล้างแล้ววางไว้บนขอบหน้าต่างเติมแสงแดดใส่จนเต็ม การได้กลับมามีประโยชน์อีกครั้งในจุดที่จบสิ้นไปแล้ว นั่นคือชีวิตครั้งที่สองของสิ่งที่ถูกทำให้ว่างเปล่า"},"ICON-1166":{"nm":"กระดาษ","de":"ฉันแผ่ตัวขาวโพลนพร้อมจะจดบันทึกอะไรก็ได้เสมอ คนที่จ้องมองลึกที่สุดเข้าไปในใจของผู้ที่ลังเลกับบรรทัดแรกนั้น มักเป็นฉันเสมอ ความอดทนของกระดาษเปล่านั้นลึกซึ้งยิ่งกว่าหมึกอีกหนึ่งช่วงกำมือ"},"ICON-1167":{"nm":"กระดาษเก่า","de":"สีเหลืองซีดที่จางลงนั้นไม่ใช่ความแก่ชรา แต่คือการอดทนอยู่ให้ผ่านพ้นมา ในทุกรอยพับมีไออุ่นของมือที่คลี่อ่านแล้วอ่านเล่าซึมซาบอยู่ กระดาษเก่าเขียนบันทึกเวลาที่ล่วงเลยไปด้วยสีสันของตัวเอง เพื่อไม่ให้ถูกลืมเลือน"},"ICON-1168":{"nm":"หมึก","de":"เริ่มต้นจากหยดเดียวแล้วกลายเป็นประโยค เมื่อแห้งแล้วก็หลงเหลืออยู่ดั่งคำสัญญา หากเปื้อนก็คือรอยเปื้อนของวันนั้นอย่างที่มันเป็น หน้าที่ของฉันคือทำให้สิ่งต่างๆ ย้อนกลับไม่ได้ ผู้คนจึงกดฉันลงอีกครั้งอย่างระมัดระวังเสมอ"},"ICON-1169":{"nm":"แร่เหล็ก","de":"มันคือก้อนหินที่หลับใหลสีแดงอยู่ใต้พื้นดิน ต้องผ่านกองไฟเพียงครั้งเดียวเท่านั้นจึงจะยอมมอบเหล็กในตัวออกมา ความแข็งแกร่งไม่ได้แข็งแกร่งมาตั้งแต่แรก แต่เป็นชื่อที่ได้รับหลังจากผ่านความร้อนแรงมาแล้วต่างหาก"},"ICON-1170":{"nm":"แท่งเหล็ก","de":"ก็ต่อเมื่อแร่ทนไฟผ่านมาได้แล้วจึงเย็นตัวลงเป็นก้อนเดียว รูปทรงที่เย็นและหนักนี้กลายเป็นได้ทั้งสะพาน มีด และจอบ เพราะยังไม่ถูกกำหนดประโยชน์ใช้สอย ฉันจึงเป็นอะไรก็ได้ทั้งนั้น"},"ICON-1171":{"nm":"แร่ทองแดง","de":"ฉันโผล่ออกมาจากดินพร้อมสวมสนิมสีเขียวอ่อนราวแอปเปิลดิบ หลอมฉันแล้วระฆังก็ดังกังวาน รูปปั้นก็ตั้งตระหง่าน สายไฟก็นำกระแส แม้ในยามหลับใหลอยู่ในความมืดมิดใต้ดิน ฉันก็รอคอยเสมอที่จะถูกเรียกให้กลายเป็นอะไรสักอย่าง"},"ICON-1172":{"nm":"แท่งทองแดง","de":"หากอยู่เคียงข้างกันนานพอ มันจะตัดเย็บเสื้อสีน้ำเงินให้ตัวเองสวมใส่ด้วยมือของตัวเอง บางคนเรียกสีนั้นว่าตำหนิ บางคนกลับลูบไล้มันด้วยความรักในฐานะลวดลายแห่งกาลเวลา โลหะที่ไม่อับอายกับสีสันที่เปลี่ยนไปของตัวเองนั้น เป็นที่รักยาวนานที่สุดเสมอ"},"ICON-1173":{"nm":"แร่ทองคำ","de":"มันคือจุดเล็กๆ ที่พบเจอจากการร่อนทรายในแม่น้ำครั้งแล้วครั้งเล่า มันมีค่าไม่ใช่เพราะหายาก แต่เพราะไม่เคยเปลี่ยนแปลง คนสมัยก่อนจึงกำมันไว้ในมือมอบเป็นของที่ระลึก บอกให้จดจำหัวใจที่ไม่มีวันเป็นสนิม"},"ICON-1174":{"nm":"แท่งทองคำ","de":"มันนอนอยู่เป็นก้อนเดียวโดยไม่หมองมัวและไม่เป็นสนิมเลยแม้แต่น้อย มันได้ยินความโลภของผู้คนมากที่สุด แต่ตัวฉันเองกลับไม่ได้โลภอยากได้อะไรเลย เป็นเพียงความเงียบอันหนักแน่นที่ซื่อสัตย์ต่อการเปล่งประกายเพียงอย่างเดียว"},"ICON-1175":{"nm":"เศษเหล็ก","de":"มันไม่ได้หมดประโยชน์ไปแล้ว เพียงแต่กำลังรอคอยประโยชน์ครั้งต่อไปอยู่ต่างหาก ตะปูที่หักและกระป๋องที่บุบมารวมตัวกัน แล้วพบเจอเปลวไฟร้อนแรงอีกครั้ง คำว่าถูกทิ้งขว้างสำหรับฉันแล้วหมายถึงการได้พักผ่อนอยู่สักพักเท่านั้นเอง"},"ICON-1176":{"nm":"สกรู","de":"ลำพังตัวเดียวทำอะไรไม่ได้เลย ต้องหมุนเข้าไปยึดแผ่นสองแผ่นให้แนบสนิทกันเท่านั้นจึงจะทำหน้าที่ของตัวเองได้อย่างสมบูรณ์ ความสามารถของร่างเล็กๆ ที่ยึดสิ่งใหญ่ไว้ได้นั้น แม้แต่แรงบิดขันแน่นก็ยังแฝงความตั้งใจไว้"},"ICON-1177":{"nm":"ตะปู","de":"เมื่อตอกลงไปครั้งหนึ่งแล้วก็แทบไม่มีวันถอยกลับ ทุกครั้งที่ค้อนกระแทกลงมา สิ่งที่ลึกขึ้นไม่ใช่บาดแผลแต่เป็นคำสัญญา หากเป็นเรื่องของการเชื่อมสิ่งใดให้แน่นหนา ฉันก็ยินดีมอบหัวของตัวเองให้เสมอ"},"ICON-1178":{"nm":"เฟือง","de":"ฉันดันฟันของเพื่อนบ้านข้างๆ ให้หมุนไปด้วยกัน ไม่พยายามวิ่งไปคนเดียวให้เร็ว แต่รู้จักปรับจังหวะให้เข้ากับความเร็วของข้างเคียง เหมือนนาฬิกาที่เวลาจะเดินได้ก็ต่อเมื่อฟันเฟืองประสานกันเท่านั้น ฉันเชื่อว่าความกลมกลืนนั่นแหละคือการเคลื่อนไหว"},"ICON-1179":{"nm":"สปริง","de":"ยิ่งถูกกดมากเท่าไหร่ ก็ยิ่งสะสมแรงที่จะดีดกลับไว้ข้างในมากเท่านั้น การโค้งงอไม่ใช่การยอมแพ้ แต่เป็นการเตรียมพร้อมที่จะคลี่ตัวออกอีกครั้ง เกลียวเล็กๆ ที่ดีดตัวกลับมากพอๆ กับแรงกระแทกที่รับไว้ ที่ซึ่งความยืดหยุ่นนั้นก็คือความแข็งแกร่งในตัวเอง"},"ICON-1180":{"nm":"สายไฟ","de":"ภายนอกเป็นเปลือกที่นิ่งสงบ ภายในกลับเป็นเส้นทางที่ไหลไปอย่างไม่หยุดพัก มันลำเลียงแสงและเสียงจากมุมที่มองไม่เห็น เหมือนมือที่คอยเชื่อมโยงหลังเวทีอย่างเงียบๆ เป็นเส้นทางที่น่าเชื่อถือยิ่งขึ้นเพราะไม่ปรากฏให้เห็น"},"ICON-1181":{"nm":"แบตเตอรี่","de":"มันเก็บสะสมแสงสว่างของครึ่งวันไว้ทีละนิดในร่างเล็กๆ ของตัวเอง ใช้หมดแล้วก็แค่เติมใหม่ก็พอ ไม่เคยมองว่าความว่างเปล่าคือจุดจบ มันโอบอุ้มค่ำคืนเล็กๆ เอาไว้เพื่อจุดประกายคืนอันยาวนานของใครสักคน"},"ICON-1182":{"nm":"หลอดไฟ","de":"เส้นใยบางเบาเส้นหนึ่งลุกแดงและผลักความมืดให้ถอยห่างออกไป มันไม่ได้เผาตัวเองเพื่อให้ความอบอุ่นแก่ห้อง แต่เพื่อให้แสงสว่างต่างหาก ร้อนที่สุดในวินาทีที่เปิดสวิตช์ และสว่างที่สุดในตอนนั้นเอง มันคือดวงอาทิตย์ดวงเล็กแห่งชั่วขณะหนึ่ง"},"ICON-1183":{"nm":"เลนส์","de":"มันรวบรวมแสงที่กระจัดกระจายให้มาตกกระทบเป็นจุดเดียวอย่างคมชัด เรียกดวงดาวไกลโพ้นและตัวอักษรจิ๋วบนฝ่ามือให้มาปรากฏได้อย่างเงียบๆ เหมือนกัน มันช่วยเหลือการมองเห็นทั้งที่ซ่อนรูปลักษณ์ของตัวเองไว้ เป็นแม่สื่อใสกลมที่คอยจับคู่อย่างเงียบๆ"},"ICON-1184":{"nm":"ยาง","de":"ไม่ว่าจะกดหรือดึงยืด สุดท้ายมันก็กลับคืนสู่รูปเดิมเสมอ แม้คนที่เคยตำหนิว่ามันอ่อนนุ่มไป ก็ยังเลือกสวมมันในวันฝนตกอยู่ดี การรับแรงกระแทกอันหนักหน่วงไว้อย่างนุ่มนวลนั้น ในความอ่อนนุ่มนี้เองก็มีความเหนียวแน่นซ่อนอยู่"},"ICON-1185":{"nm":"เศษพลาสติก","de":"มันคือเศษชิ้นเล็กๆ ที่หลุดออกมาจากตัวหลัก เกือบจะถูกทิ้งขว้างไปแล้วแต่พอรวมตัวกันหลายชิ้นก็กลับกลายเป็นของใหม่ได้อีกครั้ง มันไม่ได้เบาเพราะเล็ก แต่เพราะเบานั่นแหละจึงเดินทางไปได้ไกล เป็นส่วนหนึ่งของบางสิ่งบางอย่าง"},"ICON-1186":{"nm":"เชือกเส้นใหญ่","de":"ต้องบิดหลายเส้นเข้าด้วยกันจึงจะกลายเป็นเชือกเส้นเดียวได้ ลำพังเส้นเดียวคลายง่ายดาย แต่เมื่อสานกันแล้วก็ลากเรือได้ ผูกสัมภาระได้ เป็นปมเก่าแก่แห่งความร่วมมือที่หยาบกร้านในฝ่ามือ ยิ่งบิดพันกันมากเท่าไหร่ก็ยิ่งเหนียวแน่นเท่านั้น"},"ICON-1187":{"nm":"ผ้าใบเรือ","de":"มันไม่เกลียดชังลม แต่โอบรับไว้เต็มอก ต้องตึงพองจึงจะส่งเรือไปได้ไกล แม้แต่ลมปะทะก็ยังกลายเป็นแรงให้ฉัน วิธีก้าวไปข้างหน้าด้วยการโอบกอดสิ่งรุนแรงแทนที่จะต้านทานมันนั้น ฉันเรียนรู้มาจากท้องทะเล"},"ICON-1188":{"nm":"เศษสมอเรือ","de":"มันเป็นเพียงมุมหนึ่งของสมอเรือ แต่กลับจดจำน้ำหนักนั้นได้อย่างครบถ้วน ยุคสมัยที่มันเคยยึดพื้นทะเลลึกไว้จนเรือหยุดนิ่งได้ แม้ตอนนี้จะหลุดออกมาแล้ว มันก็ยังเป็นเศษชิ้นหนักแน่นที่รู้จักน้ำหนักของการอยู่นิ่งกับที่"},"ICON-1189":{"nm":"ตะปูตัวเรือ","de":"มันคือตะปูที่ยึดดาดฟ้าที่โคลงเคลงไปตามคลื่นไว้ทีละจุด แม้เป็นสนิมแดงจากไอเกลือ ก็ไม่เคยปล่อยที่ของตัวเองไปจนถึงที่สุด แม้แต่การยึดสิ่งที่ล่องลอยไว้ให้มั่นคงก็ยังต้องอาศัยความอดทนไม่ย่อท้อ"},"ICON-1190":{"nm":"ผ้ากันน้ำ","de":"มันทำหน้าที่กันฝนโดยไม่บ่นสักคำ รับสิ่งที่เทลงมาจากเบื้องบนไว้อย่างเงียบๆ และปกป้องสิ่งที่อยู่ข้างล่างให้แห้งอยู่เสมอ แม้ไม่หรูหราแต่ก็เป็นชั้นผ้าที่มั่นคง คอยคลุมสัมภาระของใครสักคนไม่ให้เปียกปอน"},"ICON-1191":{"nm":"สีย้อมผ้า","de":"เมื่อซึมเข้าไปในผ้าฝ้ายเปล่าอย่างเงียบๆ มันจึงกลายเป็นสีสันในที่สุด ไม่ว่าจะสีคราม หรือสีจากรากตะขบ แม่ๆ สมัยก่อนย้อมปลายนิ้วของตัวเองไปด้วยขณะแต่งแต้มสีให้ผืนผ้า แม้แต่การจมและซึมซาบเข้าไปนั้น ก็ยังมีความลึกที่แทบไม่มีวันจางหาย"},"ICON-1192":{"nm":"น้ำมันหอมระเหย","de":"เพียงหยดเดียวก็ทำให้ทุ่งกว้างแผ่ขยายเต็มห้องได้ในทันที เป็นแขกที่มาถึงก่อนใครแม้จะมองไม่เห็นด้วยตา มันดึงชายเสื้อของความทรงจำที่หลับใหลอยู่อย่างแอบแฝง เป็นทิวทัศน์ที่มาถึงปลายจมูกก่อนสิ่งใด"},"ICON-1193":{"nm":"ขี้ผึ้ง","de":"ได้รับความร้อนก็ไหลลื่น เย็นลงก็แข็งตัวรักษารูปทรงของมันไว้ มันแปรเปลี่ยนไปมาระหว่างความอ่อนนุ่มกับความแข็งกร้าว หล่อขึ้นรูปสิ่งใดก็ได้อย่างเงียบๆ เป็นวัตถุดิบอ่อนโยนที่ปิดผนึก ขัดเงา และเปลี่ยนสีหน้าไปตามอุณหภูมิ"},"ICON-1194":{"nm":"เทียนไข","de":"มันหลอมละลายร่างของตัวเองอย่างช้าๆ เพื่อส่องสว่างความมืดสักหนึ่งช่อง เมื่อเผาไหม้จนหมดแล้วก็เหลือเพียงความสูงที่สั้นลง แต่ช่วงเวลาที่มันเคยให้ความอบอุ่นแก่ค่ำคืนของใครสักคนนั้นไม่มีวันหายไป มันคือไส้เทียนตั้งตรงที่รู้จักวิธีเปล่งประกายไปพร้อมกับการเล็กลงเรื่อยๆ"},"ICON-1195":{"nm":"ปุ๋ยหมัก","de":"สิ่งที่กำลังเน่าเปื่อยมารวมตัวกันจนกลายเป็นดินที่อุดมสมบูรณ์ที่สุด เปลือกที่ถูกทิ้งและใบไม้แห้งกลายเป็นอาหารมื้อหนึ่งของหน่ออ่อนในฤดูใบไม้ผลิ ในจุดที่เราคิดว่าจบสิ้นไปแล้วนั่นแหละ ชีวิตถัดไปกำลังปรับลมหายใจแรกอย่างเงียบๆ"},"ICON-1196":{"nm":"ข้าวสาร","de":"กว่าจะได้ข้าวเพียงเมล็ดเดียวมาอยู่ในมือ ต้องผ่านมือถึงแปดสิบแปดครั้ง ตั้งแต่การปักดำจนถึงการนวดข้าว หนึ่งปีของชาวนาถูกบรรจุไว้อย่างครบถ้วนในเมล็ดข้าวเล็กๆ เมล็ดนี้ ข้าวสวยหนึ่งถ้วยที่กำลังพวยพุ่งไอร้อนนั้น คือสี่ฤดูของใครสักคนโดยแท้"},"ICON-1197":{"nm":"ข้าวกล้อง","de":"มันเพียงลอกเปลือกนอกออกเล็กน้อย แต่ยังคงรักษาสีสันดั้งเดิมไว้อย่างครบถ้วน ยิ่งเคี้ยวยิ่งหอมกรุ่นนั้น คือรสชาติของความซื่อตรงที่ไม่เร่งรีบ ความดื้อรั้นอันหนักแน่นของเมล็ดข้าวที่ปฏิเสธจะถูกขัดจนเรียบมัน และยังคงรักษาความหยาบกร้านของตัวเองไว้"},"ICON-1198":{"nm":"ข้าวสาลี","de":"มันจดจำท้องทุ่งสีทองที่ก้มหัวพร้อมกันเมื่อต้องลม กลายเป็นขนมปัง เป็นเส้นก๋วยเตี๋ยว เป็นแป้งซุปก้อน มันให้ความอบอุ่นแก่โต๊ะอาหารทั่วทุกมุมโลก เพราะเป็นสิ่งที่พบเห็นได้ทั่วไปนั่นเอง มันจึงซึมลึกเข้าไปในวิถีชีวิตของผู้คนยิ่งกว่าสิ่งใด"},"ICON-1199":{"nm":"แป้งสาลี","de":"ก็ต่อเมื่อกลายเป็นผงสีขาวละเอียดแล้วเท่านั้น มันจึงเตรียมพร้อมที่จะเป็นอะไรก็ได้ในที่สุด พบน้ำก็พองฟู พบไฟก็สุกงอม เพราะไม่มีรูปทรงตายตัว มันจึงเป็นวัตถุดิบอันอ่อนโยนที่รับรูปทรงตามมือที่นวดปั้นมันขึ้นมา"},"ICON-1200":{"nm":"แป้งนวด","de":"แป้งและน้ำผสมกลมกลืนเป็นก้อนเดียวใต้ฝ่ามือ ยิ่งนวดมากก็ยิ่งเหนียวนุ่ม ยิ่งรอนานก็ยิ่งพองฟูขึ้น หากรีบร้อนมันก็จะเหนียวแข็ง ร้านขนมปังเก่าแก่จึงบอกว่าเวลาแห่งการหมักนั้นเร่งรีบไม่ได้เลยแม้แต่น้อย"},"ICON-1201":{"nm":"เศษขนมปัง","de":"ปัดฝุ่นขาวที่เกาะปลายนิ้วไปเรื่อยๆ ไม่ทันไรแขนเสื้อก็ขาวไปด้วย ถ้าเป็นเกล็ดชุบทอดก็กรอบ ถ้ากองพูนขึ้นก็เหมือนหิมะแรกของปี เป็นรอยเบาที่สุดที่ขนมปังก้อนหนึ่งทิ้งไว้หลังอบ แต่แม้สิ่งเล็กน้อยก็ยังเติบโตเป็นประโยชน์ได้"},"ICON-1202":{"nm":"เส้นพาสต้า","de":"ในวินาทีที่โรยเส้นกำมือหนึ่งลงน้ำเดือดคล้ายกางพัด แสงแดดจากแดนไกลก็ราวกับลอยข้ามมาถึงในครัว เส้นยาวคืองานของข้อมือ ส่วนอัลเดนเต้คือหัวใจที่รู้จักรอคอยในความไม่สุกเต็มที่นิดหนึ่ง ลองดูความเงางามที่พันเป็นวงรอบส้อมนั่นสิ"},"ICON-1203":{"nm":"บะหมี่กึ่งสำเร็จรูป","de":"ยามเช้ามืดหลังลบเครื่องแต่งหน้าบนเวทีจนหมด แอบต้มซองหนึ่งขึ้นมา สามนาทีที่เส้นค่อยๆ นิ่มลงคือช่วงเวลาส่วนตัวที่สุดของทั้งวัน ลมหายใจที่เป่าฟู่ๆ พาความตึงเครียดคลายลงไปด้วย และหลังแว่นตาที่ฝ้าไอ วันนี้ก็จบลงอย่างเงียบๆ"},"ICON-1204":{"nm":"ต๊อก","de":"ข้าวต้องทนแรงกระแทกของครกก่อนจึงจะกลายเป็นต๊อกได้ ไม่ว่าจะเป็นเมทัก อินจอลมี หรือซงพยอน—ธัญพืชชนิดเดียวกันได้รับชื่อนับร้อยตามฝีมือของมือที่ปั้นมัน เมื่อขึ้นโต๊ะงานเลี้ยง มันเรียกความรักก่อนปาก และอร่อยที่สุดเมื่อได้แบ่งกันกิน"},"ICON-1205":{"nm":"ต๊อกซุป","de":"หั่นแท่งต๊อกทรงกระบอกเฉียงๆ ออกมาก็กลมเหมือนเหรียญเล็กๆ สิ่งที่ลอยอยู่ในน้ำซุปสีขาวนั้นคือต๊อก หรือคือความปรารถนากลมๆ กันแน่ พอกินหมดชามแรกของเช้าวันปีใหม่ อายุก็เพิ่มขึ้นอีกหนึ่งปี นี่แหละวิธีนับอายุอันอ่อนโยนแบบฉบับประเทศนี้"},"ICON-1206":{"nm":"มันฝรั่ง","de":"เคาะดินออกเบาๆ ใบหน้ากลมๆ ก็ปรากฏขึ้นมา หัวมันที่โตขึ้นอย่างเงียบๆ ท่ามกลางลมจากเนินเขากังวอน นึ่งแล้วร่วนนุ่ม ทอดแล้วหอมมัน แม้ในวันที่กระเป๋าเงินแบนราบ มันก็ยังทำให้ท้องของทุกคนในครอบครัวอิ่มอย่างซื่อสัตย์เสมอ"},"ICON-1207":{"nm":"มันเทศ","de":"เมื่อถังเผามันเทศตั้งขึ้นที่ปากตรอก นั่นคือสัญญาณว่าฤดูหนาวเริ่มต้นแล้ว ลอกฟอยล์ออก ไอสีเหลืองก็อุ่นปลายนิ้วก่อนใคร ความหวานนั้นคือรางวัลของรากที่ทนหนาวมาทั้งฤดู เหมาะจะเป่าฟู่ๆ แบ่งครึ่ง แล้วแบ่งความอุ่นกันกิน"},"ICON-1208":{"nm":"แครอท","de":"หัวสีส้มหนึ่งแท่งที่พุ่งตรงลงไปในดิน เคยคิดว่ามีแต่กระต่ายเท่านั้นที่ชอบ แต่พอผัดความหวานที่ซ่อนอยู่ก็ตื่นขึ้นมา ใส่ในซุปก็ยังเพิ่มสีสันให้ด้วย คำพูดของคนรุ่นก่อนที่ว่ามันดีต่อสายตานั้น โดยรวมแล้วก็ถูกต้อง"},"ICON-1209":{"nm":"หัวไช้เท้า","de":"มีรากขาวหนักแน่นหัวเดียวก็ทำให้โต๊ะอาหารฤดูหนาวอุ่นใจได้ เป็นทงชิมี (กิมจิหัวไช้เท้าน้ำ) ที่เย็นเจี๊ยบ เป็นซุปหัวไช้เท้าที่สดชื่น เป็นกักตุกิที่กรุบกรอบ ไม่มีส่วนไหนต้องทิ้งเลย แม้แต่ใบเขียวก็ยังนำไปตากไว้ใต้ชายคาเก็บเป็นชีแรกิ ผักที่ประหยัดที่สุด"},"ICON-1210":{"nm":"หัวหอมใหญ่","de":"ปอกเปลือกไป น้ำตาก็ไหลลงมาหยดหนึ่ง เนื้อในที่เผ็ดแสบพอเจอน้ำมันร้อนกลับหวานขึ้นราวกับโกหก ชื่อของมันถูกเขียนไว้เป็นบรรทัดแรกของอาหารเกาหลีแทบทุกจาน เป็นพระเอกเงียบๆ ที่ปูพื้นรสชาติไว้อย่างไม่ปริปาก"},"ICON-1211":{"nm":"ต้นหอมใหญ่","de":"โรยโคนขาวหั่นซอยกับใบเขียวลงบนน้ำซุป ตอนนั้นแหละที่ชามหนึ่งดูเหมือนจะสมบูรณ์จริงๆ เสียบโคนที่เหลือไว้ในแก้วน้ำ มันก็แตกยอดขึ้นมาใหม่ได้อีก เป็นสวนเล็กๆ ริมหน้าต่างของแม่บ้านที่รักการดูแลบ้าน"},"ICON-1212":{"nm":"กระเทียม","de":"กลีบทั้งหกเรียงตัวเป็นวงกลมรวมกันเป็นหัวเดียว รากเผ็ดที่ว่ากันว่าเคยเปลี่ยนหมีให้กลายเป็นคน สับด้วยสันมีดโป๊กๆ กลิ่นหอมก็ตื่นขึ้นทันที ทั้งกิมจิและสตูว์จะขาดกระเทียมกำมือหนึ่งไปไม่ได้เลย"},"ICON-1213":{"nm":"ขิง","de":"รากเล็กๆ ขรุขระราวกับปมเชือกผูก แค่ชิ้นเดียวก็ระงับกลิ่นคาวและอุ่นร่างกายที่เย็นชืดจากภายในได้ คืนที่ครางเจ็บด้วยไข้หวัด แก้วชาอุ่นที่ชงกับน้ำผึ้งนั้นเริ่มต้นจากความเผ็ดร้อนเล็กๆ นี้เอง"},"ICON-1214":{"nm":"กะหล่ำปลีจีน","de":"หมักใบที่อัดแน่นด้วยเกลือ นั่นแหละคือบทแรกของกิมจิที่เปิดออก ปลายฤดูใบไม้ร่วงมันเคยกองสูงเป็นภูเขาในทุกลานบ้าน การที่ทั้งครอบครัวนั่งล้อมวงกันดองกิมจิหนึ่งไห คือคำสัญญาว่าจะผ่านฤดูหนาวอันยาวนานไปด้วยกัน"},"ICON-1215":{"nm":"กะหล่ำปลี","de":"ลอกใบที่ม้วนซ้อนเป็นชั้นๆ ออกทีละแผ่นไม่มีวันหมด จนใจค่อยๆ ผ่อนคลายลงโดยไม่รู้ตัว ลวกแล้วนุ่มนวล ผัดแล้วหวานอ่อนๆ ผักที่แม้ภายนอกจะดูหยาบกระด้าง แต่กลับซ่อนความอ่อนโยนที่คาดไม่ถึงเอาไว้ข้างใน"},"ICON-1216":{"nm":"ผักกาดหอมห่อ","de":"วางเนื้อชิ้นหนึ่งลงบนใบเว้าโค้ง แต้มซัมจังแล้วยัดเข้าปากจนเต็มคำ ในวงล้อมที่ห่อกินกันนั้น ไม่ว่าใครก็แอบวางพิธีรีตองลงได้เสมอ นี่ไม่ใช่อะไรอื่นนอกจากการต้อนรับสีเขียว"},"ICON-1217":{"nm":"ผักกาดหอมใบ","de":"ใบแรกที่แทงยอดขึ้นในมุมสวนครัว เด็ดไปก็แตกใหม่ ผลิใบเต็มโต๊ะอาหารตลอดฤดูร้อน กลิ่นเขียวสดที่ล้างในน้ำเย็นแล้วห่อกินด้วยมือ สำหรับใครหลายคนคือรสชาติบ้านเกิดทั้งหมดในคำเดียว"},"ICON-1218":{"nm":"ผักโขม","de":"สีเขียวจากการ์ตูนที่กินกระป๋องหมดแล้วพลังพุ่งพล่าน ลวกแล้วหดเหลือแค่กำมือเดียวแต่กลิ่นและพลังยังคงเดิม จะคลุกมือเบาๆ หรือใส่ในซุปเต้าเจี้ยวก็อร่อย—ผักที่พบเจอได้ทั่วไปแบบนี้ไม่ควรถูกมองข้ามเลย"},"ICON-1219":{"nm":"เฟิร์นโกซารี","de":"หักยอดอ่อนที่ภูเขาฤดูใบไม้ผลิมอบให้ นำไปต้มแล้วตากแห้ง ต้องผ่านความเหนื่อยยากอันยาวนานนั้นก่อนจึงจะได้ขึ้นโต๊ะพิธีบรรพบุรุษหรือบิบิมบับ ยิ่งต้องใช้มือมากเท่าไหร่ ความตั้งใจก็ยิ่งซึมเข้าไปเป็นชั้นๆ เป็นผักล้ำค่าที่ภูเขาปลูกเลี้ยงมาหนึ่งฤดู"},"ICON-1220":{"nm":"ผักป่า","de":"ดูเหมือนไม่มีชื่อแต่แต่ละต้นกลับมีกลิ่นเฉพาะตัว ของขวัญแห่งฤดูใบไม้ผลิ มือของคุณยายรู้ในทันทีว่าใบไหนบนทางเขากินได้ ในตะกร้าผักป่าหนึ่งใบ ฤดูกาลทั้งฤดูตามมาพร้อมกลิ่นหอมครบถ้วน"},"ICON-1221":{"nm":"บอระเพ็ดเกาหลี","de":"หญ้าขมแต่หอมที่แทงยอดผ่านดินแข็งเป็นสิ่งแรก เมื่อปั้นเป็นต๊อก แสงฤดูใบไม้ผลิก็เข้าปากทั้งดวง เชื่อกันว่าเดือนแรกของปีต้องต้มซุปจากมันเพื่อป้องกันโชคร้ายตลอดปี ฤดูใบไม้ผลิจึงมาถึงจากกลิ่นนี้เสมอมา"},"ICON-1222":{"nm":"ใบงาเกาหลี","de":"แค่ใบเดียวก็ทำให้ทั้งปากอบอวลไปด้วยกลิ่นหอมเข้มข้น จะกินคู่กับหมูสามชั้นย่างเหลืองอร่ามหรือดองซ้อนกันในซีอิ๊วก็ทำให้ข้าวหนึ่งถ้วยหมดในพริบตา กลิ่นเฉพาะตัวนี้เข้ากันได้ดีเฉพาะกับโต๊ะอาหารของแผ่นดินนี้เท่านั้น"},"ICON-1223":{"nm":"พริกหยวกเขียว","de":"ผลไม้สีเขียวกลวงในที่แตกกรอบเมื่อกัด รสขมแผ่วๆ ปลุกลิ้นที่เฉื่อยชาให้ตื่น พอผัดในน้ำมันสีก็สดใสขึ้นอีก แค่หั่นซอยโรยหน้าก็ทำให้อาหารจานไหนก็สดชื่นขึ้นทันที"},"ICON-1224":{"nm":"พริกหวาน","de":"แดง เหลือง ส้ม สีสันดั่งไฟจราจรเต็มตะกร้า กัดสดๆ น้ำหวานก็ไหลย้อย แค่สีสันก็ทำให้โต๊ะอาหารสว่างไสว คำที่ว่าผักหน้าตาดีช่วยเจริญอาหารนั้น เหมาะกับมันที่สุด"},"ICON-1225":{"nm":"มะเขือเทศ","de":"สีแดงกลมที่ถกเถียงกันมาตลอดว่าเป็นผลไม้หรือผัก ต้มนานๆ รสจะเข้มขึ้น กินสดก็สดชื่นไม่มีที่ติ เป็นผลไม้ที่เก็บกักแดดกลางฤดูร้อนไว้อย่างซื่อตรงที่สุด กัดคำเดียวก็เหมือนกลางวันทั้งวันแตกกระจายออกมา"},"ICON-1226":{"nm":"แตงกวา","de":"สีเขียวที่คลายร้อนฤดูร้อนได้เย็นสดชื่นที่สุด ลอยในซุปเย็นก็ทำให้ปากเย็นฉ่ำ ดองเป็นโซบากิความกรอบก็มีชีวิตขึ้นมา วันร้อนจัดจะฝานบางๆ วางบนดวงตาก็ยังดี เป็นผักที่เย็นทั้งข้างในข้างนอก"},"ICON-1227":{"nm":"ฟักทอง","de":"ห้อยกลมอยู่ปลายเถาวัลย์ ค่อยๆ สะสมความหวานไปจนถึงปลายฤดูใบไม้ร่วง ต้มนุ่มๆ กลายเป็นโจ๊กสีเหลืองที่ปลอบท้อง ทอดก็กลายเป็นแป้งทอดสีเหลืองอร่าม แขวนไว้ใต้ชายคาก็ทำหน้าที่เป็นคลังอาหารที่พึ่งพาได้ตลอดฤดูหนาว"},"ICON-1228":{"nm":"บวบเขียวอ่อน","de":"สีเขียวอ่อนที่โตวันโตคืนในสวนครัวฤดูร้อน หั่นชิ้นใหญ่ใส่ซุปเต้าเจี้ยว ทอดเป็นแป้งทอดเหลืองอร่าม—นุ่มจนแม้ปากเด็กเล็กก็กินได้อย่างอ่อนโยน ยิ่งพบเจอได้ทั่วไปยิ่งน่าขอบคุณ เป็นแขกประจำของโต๊ะอาหารกลางฤดูร้อน"},"ICON-1229":{"nm":"มะเขือยาว","de":"ผลยาวเรียวเคลือบเงาสีม่วงวับ ซับน้ำมันแล้วนุ่มไม่มีที่สิ้นสุด นึ่งจนสุกทั่วเนื้อก็ละเอียดดั่งผ้าไหม แม้ดูธรรมดาแต่กลับเข้ากันได้ดีกับทุกสิ่ง เป็นตัวประกอบแสนอ่อนโยนของโต๊ะอาหาร"},"ICON-1230":{"nm":"ข้าวโพด","de":"เมล็ดสีเหลืองเรียงแถวเป็นระเบียบทีละเม็ด ของว่างฤดูร้อนที่นึ่งในหม้อแล้วเป่าฟู่ๆ กัดกิน และยังเป็นสัญญาณอันน่ายินดีว่าท้องทุ่งสุกแล้วทั้งหมด ในกระจุกไหมนุ่มฟูนั้นแฝงความหวานไว้เต็มเปี่ยม"},"ICON-1231":{"nm":"ถั่วเหลือง","de":"เมล็ดเล็กแข็งดื่มน้ำข้ามคืนจนอวบอิ่ม บดละเอียดกลายเป็นนมถั่วเหลือง หมักนานกลายเป็นจัง—โปรตีนบนโต๊ะอาหารของแผ่นดินนี้ส่วนใหญ่เริ่มต้นจากตรงนี้ ฝังเมล็ดหนึ่งลงดินมันก็กลับมาเป็นต้นใหม่อีกครั้ง"},"ICON-1232":{"nm":"เต้าหู้","de":"เมื่อถั่วเหลืองดื่มน้ำ ถูกบดและจับตัวแข็ง มันก็กลายเป็นก้อนขาวเหลี่ยมมุมเรียบ นุ่มและอ่อนโยนจนไม่ยืนกรานสีของตัวเองในซุปไหนเลย แม้ตักด้วยช้อนก็ยังยุบตัวเบาๆ เป็นอาหารที่ความจืดชืดคือคุณธรรมในตัวมันเอง"},"ICON-1233":{"nm":"ถั่วแดง","de":"ต้มเมล็ดแดงเล็กๆ จนนุ่มทั่ว ความหวานสีแดงเข้มก็ไหลออกมาอย่างเข้มข้น คืนที่ยาวที่สุดของปี โจ๊กถั่วแดงร้อนๆ หนึ่งชามเคยขับไล่ทั้งความหนาวและวิญญาณร้ายไปพร้อมกัน หัวใจนั้นยังคงสถิตอยู่ในนี้ สีแดงที่แทรกอยู่ในเค้กนึ่งทีละชั้นนั้น คือความตั้งใจนั่นเอง"},"ICON-1234":{"nm":"ไส้ถั่วแดงกวน","de":"ถั่วแดงต้มบดละเอียดแล้วเคี่ยวแล้วเคี่ยวอีกจนกลายเป็นไส้เนื้อนุ่ม ช้อนหนึ่งระหว่างขนมปัง ในต๊อก บนน้ำแข็งไส—สายความหวานเส้นเดียวยังอุ่นความทรงจำเก่าได้ เวลาอันยาวนานของการกรองและเคี่ยวนั้น กลายเป็นความหวานนั่นเอง"},"ICON-1235":{"nm":"เห็ด","de":"หลังฝนหยุด มันโผล่หัวขึ้นอย่างเงียบเชียบในร่มเงามืดของป่า ฝีมือของดินที่เลี้ยงกลิ่นหอมของตัวเองขึ้นมาได้โดยไม่ต้องพึ่งแสงแดดสักกำมือ ใส่แค่หยิบมือเดียวในซุปก็ให้รสอูมามิลึกล้ำโดยไม่ต้องมีเนื้อสัตว์เลย เป็นความลับที่ป่าซ่อนไว้"},"ICON-1236":{"nm":"เห็ดหอม","de":"ร่มสีน้ำตาลที่กางหมวกออกเต็มที่ ตากแดดจนแห้งสนิท กลิ่นหอมจะเข้มขึ้นหลายเท่า ดอกแห้งดอกเดียวก็รับผิดชอบน้ำซุปได้ทั้งหม้ออย่างสบายๆ เป็นเสาหลักมั่นคงของโต๊ะอาหารมังสวิรัติ และเป็นขาประจำของคนที่รู้จักรสชาติล้ำลึกมานาน"},"ICON-1237":{"nm":"เห็ดซองอี","de":"ลึกเข้าไปในป่าสนฤดูใบไม้ร่วง มันแอบยกหัวขึ้นเฉพาะข้างต้นสนเท่านั้น ปลูกเลี้ยงไม่ได้ ต้องออกเดินหาด้วยเท้าเท่านั้น กลิ่นหอมจึงยิ่งล้ำค่า ย่างเบาๆ จิ้มเกลือนิดเดียวก็ทำให้ผืนป่าทั้งผืนเข้ามาอยู่ในปาก"},"ICON-1238":{"nm":"เห็ดออรินจิ","de":"ฉีกก้านหนาตามแนวเสี้ยน ความเหนียวนุ่มก็จับต้องได้ในมือทันที มันเติบโตอย่างมั่นคงทุกฤดูกาล จึงไม่เคยห่างหายจากโต๊ะอาหาร ย่างก็ดี ผัดก็ดี—ในเนื้อหนาแน่นนั้นอัดแน่นไปด้วยความอิ่มท้องที่ไม่หนักใจเลย"},"ICON-1239":{"nm":"สตรอว์เบอร์รี","de":"ที่ปลายเรือนกระจกที่ทนฤดูหนาวมาได้ มันสุกแดงเป็นชิ้นแรก กัดคำเดียวเปรี้ยวหวาน ราวกับคำทักทายแรกของต้นฤดูใบไม้ผลิ วางผลกลมหนึ่งลูกบนเค้ก แม้วันธรรมดาที่สุดก็กลายเป็นวันครบรอบได้ในพริบตา"},"ICON-1240":{"nm":"บลูเบอร์รี","de":"ป๊อปแตกออก ความเปรี้ยวสดใสก็แผ่กระจายเต็มปาก หยิบลูกกลมสีม่วงทีละลูกไปเรื่อยๆ ไม่ทันไรกล่องก็ว่างเปล่า โรยบนนมสีขาว ท้องฟ้ายามค่ำคืนเล็กๆ ก็ปรากฏขึ้นตรงนั้นเลย"},"ICON-1241":{"nm":"แอปเปิล","de":"กัดคำเดียวกร๊อบ ฤดูใบไม้ร่วงก็แตกกระจาย สีแดงที่คุณยายสวนผลไม้เช็ดด้วยผ้ากันเปื้อนแล้วยื่นให้ เป็นสีที่ต้องอุ้มแดดไว้นานจึงจะติด ยิ่งแข็งเท่าไหร่ ยิ่งรู้วิธีคงความหวานไว้จนถึงคำสุดท้าย"},"ICON-1242":{"nm":"สาลี่เกาหลี","de":"ปอกเปลือก ปลายนิ้วเย็นวาบก่อนใคร แถวหน้าสุดของโต๊ะไหว้บรรพบุรุษวันชูซอก วินาทีที่น้ำหวานเย็นเจี๊ยบไหลเต็มปาก สายลมยามค่ำฤดูใบไม้ร่วงก็แอบมานั่งเคียงข้างเบาๆ"},"ICON-1243":{"nm":"ลูกพีช","de":"ทุกจุดที่ดอกพีชร่วงโรย ฤดูร้อนขนนุ่มก็ก่อตัวขึ้น กดเบาๆ กลิ่นหอมก็แผ่ก่อนใคร วินาทีที่กัดคำแรก ฤดูกาลทั้งฤดูก็ตามเข้าไปในปาก"},"ICON-1244":{"nm":"องุ่น","de":"เม็ดสีม่วงห้อยเป็นพวงเดียวกัน พิงบ่ากันและกัน ป๊อปแตกออก ความเปรี้ยวมาก่อน ความหวานตามมาช้ากว่าครึ่งจังหวะ—ราวกับคอรัสที่เรียบร้อยของปลายฤดูร้อน"},"ICON-1245":{"nm":"องุ่นเขียว","de":"สีเขียวอ่อนปล่อยให้แสงแดดทะลุผ่านตรงๆ จุดไฟให้ทุกเม็ดเหมือนโคมไฟ ไม่มีเมล็ด สดชื่นสะอาดตา ความหวานที่ไม่มีส่วนเกินแม้แต่น้อย ราวกับท่อนแรกที่เพิ่งดึงออกมาสดๆ"},"ICON-1246":{"nm":"เลมอน","de":"ขูดเปลือกสีเหลืองด้วยเล็บ กลิ่นหอมก็แตะปลายจมูกให้ตื่นทันที หยดเดียวมุมปากก็ยู่ขึ้นเองโดยไม่ตั้งใจ แต่ปลายรสเปรี้ยวนั้นกลับมีมุมแปลกๆ ที่ทำให้ทั้งวันสว่างไสวขึ้นมา"},"ICON-1247":{"nm":"มะนาวไลม์","de":"เม็ดนี้เล็กกว่าเลมอนและเขียวเข้มกว่า ทักทายด้วยกลิ่นฉุนซ่าเป็นอันดับแรก แค่ชิ้นเดียวน้ำอุ่นๆ ก็ตื่นขึ้นทันที—ความสดชื่นกำมือเล็กแต่เอาจริง"},"ICON-1248":{"nm":"ส้ม","de":"วินาทีที่ปอกเปลือก กลิ่นแสงแดดก็เกาะติดนิ้วมือ ใส่แต่ละกลีบเข้าปาก ป๊อก ป๊อก ลูกโป่งน้ำหวานเล็กๆ ก็แตกออก—ของกลมๆ ทำให้แม้แต่อารมณ์ก็กลิ้งกลมไปด้วย"},"ICON-1249":{"nm":"ส้มเขียวหวาน","de":"จำรสนั้นได้ไหม ฝังเท้าไว้ใต้ผ้าห่มบนพื้นอุ่นแล้วปอกกินในฤดูหนาว กลิ่นที่แผ่ออกมาจากซอกเล็บย้อมทั้งห้องให้เป็นสีเหลือง ถุงเดียวก็เป็นข้ออ้างให้ทั้งครอบครัวมานั่งล้อมวงกัน"},"ICON-1250":{"nm":"กล้วย","de":"เคยมีวันที่หิวโหยในห้องซ้อมยามเช้ามืด กล้วยลูกสีเหลืองที่กลิ้งออกมาจากกระเป๋ามุมห้องกลายเป็นมื้ออาหารทั้งมื้อ นุ่ม หวาน และอิ่มท้อง—ทางออกชั่วคราวที่แสนอ่อนโยนที่สุด"},"ICON-1251":{"nm":"สับปะรด","de":"ต้องผ่านเปลือกหนามชั้นหนึ่งก่อน เนื้อสีเหลืองข้างในจึงจะปรากฏ อมชิ้นหนึ่งไว้ในปาก ความเปรี้ยวหวานก็แสบลิ้นเบาๆ และกลิ่นทะเลใต้ก็ลอยวนอยู่ที่ริมฝีปากโดยไม่รู้ตัว"},"ICON-1252":{"nm":"มะม่วง","de":"แยกเนื้อที่สุกดีด้วยมือ กลิ่นหวานเหนียวก็เปียกชื้นปลายนิ้ว เมื่อสีเหลืองเข้มละลายหายไปในปาก ความฝันหวานราวกับงีบหลับสั้นๆ กลางฤดูร้อนก็ผ่านเข้ามา"},"ICON-1253":{"nm":"มะพร้าว","de":"เขย่าเปลือกแข็งดู ก็ได้ยินเสียงน้ำกระฉอกอยู่ข้างใน ผ่าออกมา เนื้อขาวและน้ำเย็นฉ่ำ—ไหน้ำใบเล็กๆ ที่บรรจุทะเลไกลโพ้นไว้ทั้งผืน แกว่งไกวอยู่ข้างใน"},"ICON-1254":{"nm":"แก้วมังกร","de":"รูปลักษณ์เกล็ดชมพูทำให้แรกเห็นต้องชะงักไปนิด แต่พอผ่าออกมา เนื้อขาวข้างในกลับเต็มไปด้วยเมล็ดดำเล็กๆ ทีละเม็ด รสชาติธรรมดาแต่การแต่งตัวหรูหรา—นักหลอกลวงที่ภายนอกกับภายในตรงข้ามกันโดยสิ้นเชิง"},"ICON-1255":{"nm":"กีวี","de":"ผ่าครึ่งเปลือกสีน้ำตาลมีขน อัญมณีสีเขียวก็ปรากฏขึ้น ตักหน้าตัดที่มีเมล็ดดำฝังอยู่ราวกับดวงดาวเข้าปากหนึ่งช้อน ความเปรี้ยวหนึ่งคำก็เขย่าให้ตื่นจากหลับใหล"},"ICON-1256":{"nm":"เนื้อไก่","de":"วางลงบนกระทะทาน้ำมัน เสียงจี๊ดเหลืองอร่ามสุกขึ้นก่อนสิ่งใด จืดสนิทและนุ่มนวล เข้ากันได้ง่ายๆ กับโต๊ะอาหารของทุกคน—ขาประจำของมื้ออาหารสบายๆ"},"ICON-1257":{"nm":"เนื้อหมู","de":"บนตะแกรงย่างเสียงจี๊ดๆ น้ำมันกระเด็นป๊อกๆ สุกเหลืองขึ้นเรื่อยๆ คืนงานเลี้ยงบริษัทที่ห่อผักกาดหอมแต้มซัมจังยัดเข้าปากจนเต็มคำ ความหอมมันอบอุ่นทั่วทั้งวง"},"ICON-1258":{"nm":"เนื้อวัว","de":"ในทุกเส้นลายสีแดง มันเคลือบเนื้ออย่างประณีตจนเป็นประกาย วางบนแผ่นหินร้อน กลิ่นหอมเข้าครองพื้นที่ก่อนใคร วินาทีที่ชิ้นหนึ่งเข้าปาก ความเหนื่อยล้าของทั้งวันก็คลายลงอย่างเงียบๆ"},"ICON-1259":{"nm":"เบคอน","de":"บนกระทะยามเช้า มันกรอบขึ้นและน้ำมันก็เต้นระบำ กลิ่นหอมเค็มนั้นแค่กลิ่นเดียวก็ดึงแม้คนในครอบครัวที่ยังนอนตื่นสายให้ขยี้ตาเดินมารวมกันที่ครัว—มื้ออาหารที่กลิ่นเรียกก่อนใคร"},"ICON-1260":{"nm":"ไส้กรอก","de":"รอยบากที่กรีดไว้แตกออกกว้าง น้ำเนื้อก็พุ่งออกมาป๊อก รูปทรงปลาหมึกสีแดงที่รับผิดชอบช่องหนึ่งในกล่องข้าว เคยเป็นความหรูหราเล็กๆ ที่เวลาพักเที่ยงในวัยเด็กได้เสพสุข"},"ICON-1261":{"nm":"เปปเปอโรนี","de":"ชิ้นกลมรสเผ็ดม้วนงอขึ้นจากขอบก่อนบนชีสร้อนๆ พอน้ำมันเริ่มขังนิดหน่อย นั่นแหละคือจุดสุดยอดของพิซซ่าทั้งถาด—ตัวเล็กแต่การมีตัวตนกลมและเข้มข้นไม่แพ้ใคร"},"ICON-1262":{"nm":"แพตตี้","de":"ปั้นให้หนา วางบนตะแกรง มันก็สุกเป็นสีน้ำตาลจากขอบเข้าสู่กลาง สอดผักไว้ระหว่างแผ่นที่กดย่างจนแบน ความอิ่มท้องที่จับได้พอดีมือหนึ่งข้างก็เสร็จสมบูรณ์"},"ICON-1263":{"nm":"ไข่ไก่","de":"เคาะแตกออก ไข่แดงก็ไหลลื่นออกมาเหมือนดวงอาทิตย์ดวงกลม คลุกกับข้าวสวยร้อนๆ ก็ดี เป็นเส้นสีเหลืองในกิมบับก็ดี—โปรตีนที่พบเจอได้ง่ายที่สุดจึงเป็นที่รักที่สุด"},"ICON-1264":{"nm":"นม","de":"ขวดเย็นเฉียบที่วางไว้หน้าประตูยามเช้ามืด วันหนึ่งๆ มักเปิดฉากด้วยความเย็นนั้นที่สัมผัสฝ่ามือ อุ่นแล้วไอลอยฟุ้ง เย็นแล้วหอมมัน—สีขาวที่คอยอยู่เคียงข้างไม่ว่าเมื่อไหร่"},"ICON-1265":{"nm":"ชีส","de":"แผ่นสีเหลืองแผ่นหนึ่งค่อยๆ ละลายพังทลายบนขนมปังอุ่นๆ หัวใจที่เฝ้ารอวินาทีที่มันยืดยาวออกมานั้น—ยิ่งละลายมากเท่าไหร่ ความหอมมันก็ยิ่งลึกและเข้มข้นขึ้น"},"ICON-1266":{"nm":"ชีสเชดดาร์","de":"สีส้มเข้มบอกล่วงหน้าตั้งแต่แรกเห็นว่ารสชาติต้องเค็มมันแน่นอน ฝานบางสอดในขนมปังปิ้ง รสอูมามิก็แผ่เต็มปาก—สียิ่งชัด รสชาติก็ยิ่งชัดตามไปด้วย"},"ICON-1267":{"nm":"เนย","de":"หยดชิ้นหนึ่งลงกระทะร้อน มันก็ละลายหายไปพร้อมไอหอมมันลอยฟุ้งขึ้นมา ทาบนขนมปัง คลุกกับข้าว ไม่ว่าแตะสิ่งใดก็ทำให้นุ่มนวลขึ้นอีกขั้น—เวทมนตร์สีเหลือง"},"ICON-1268":{"nm":"วิปครีม","de":"ยิ่งตีตะกร้อมากเท่าไหร่ สีขาวข้นเหลวก็ค่อยๆ ฟูขึ้นเป็นเมฆแน่นหนา วินาทีที่ตักช้อนหนึ่งวางบนเค้ก บ่ายธรรมดาก็สว่างไสวราวกับวันเกิดเล็กๆ"},"ICON-1269":{"nm":"โยเกิร์ต","de":"จุ่มช้อนลงไป สีขาวเปรี้ยวก็ยกขึ้นมาอย่างเรียบลื่น ผสมผลไม้ชิ้นหนึ่งเข้าไป เช้าวันนั้นก็เบาสบายขึ้น หนึ่งถ้วยก็ทำให้ท้องเรียบร้อยสงบลง—รสชาติของการเริ่มต้นอันอ่อนโยน"},"ICON-1270":{"nm":"ปลาซาบะ","de":"วางบนตะแกรงย่าง น้ำมันก็กระเด็นป๊อกๆ ควันหอมกึ่งคาวลอยเต็มครัว มือที่แกะก้างออกแล้ววางบนข้าวให้—ความตั้งใจที่ลึกซึ้งที่สุดซ่อนอยู่ในโต๊ะอาหารธรรมดาๆ"},"ICON-1271":{"nm":"ปลาแซลมอน","de":"ลายเนื้อสีชมพูซ้อนกันเป็นชั้นๆ นอนเรียงตัวอยู่ กินเย็นๆ ก็คลายตัวนุ่มในปาก ย่างแล้วน้ำมันซึมออกมาหอมมัน—รสชาติมั่นคงที่ว่ายทวนน้ำกลับมาจากทะเลไกลโพ้น"},"ICON-1272":{"nm":"ปลาทูน่า","de":"เปิดฝากระป๋อง กลิ่นเค็มก็โชยขึ้นมาทันที คืนในห้องเช่าเล็กๆ ที่คลุกข้าวหรือห่อสาหร่ายกิน กระป๋องเดียวเคยเป็นมื้ออาหารที่อิ่มท้องในวันเวลาหนึ่ง"},"ICON-1273":{"nm":"ปลาคอด","de":"เนื้อใสจืดสนิท ต้มแล้วน้ำซุปก็สดชื่นตั้งแต่แรก ปลาขาวที่ทนลมมีดคมกริบของท่าเรือฤดูหนาวมา ซุปร้อนๆ ชามเดียวก็ทำให้มือที่เย็นเยียบละลายลงช้าๆ"},"ICON-1274":{"nm":"กุ้ง","de":"ม้วนหลังกลม พอสุกสีเทาก็เปลี่ยนเป็นสีชมพูอมแดง ความเด้งกรุบและกลิ่นหอมมัน ปอกกินทีละตัวไปเรื่อยๆ ไม่ทันไรจานก็ว่างเปล่าไปแล้ว"},"ICON-1275":{"nm":"ปู","de":"การแกะเนื้อขาวออกจากเปลือกแข็งคือช่วงเวลาแห่งความอดทนเล็กๆ ชิ้นที่ได้เข้าปากหลังความเหนื่อยยากนั้นหวานฉ่ำ ราวกับทะเลฤดูใบไม้ร่วงทั้งผืนเข้ามาอยู่ในปากทีเดียว"},"ICON-1276":{"nm":"ปลาหมึก","de":"บนตะแกรงย่างมันหดตัวเป็นวงกลม ส่งกลิ่นหอมมันลอยขึ้นมา คำเหนียวหนึบที่เคี้ยวหนึ่งคำ จิ้มซอสโชจังแล้วเข้าปาก ทะเลรสเค็มก็ตามมาด้วย"},"ICON-1277":{"nm":"หอย","de":"ในน้ำซุปใส มันอ้าปากปล่อยกลิ่นหอมของตัวเองออกมาเบาๆ เสียงเดือดปุดๆ พากลิ่นทะเลแผ่กระจาย ซดคำเดียวก็ทำให้ท้องที่เย็นเยียบอุ่นขึ้นและคลายลง"},"ICON-1278":{"nm":"โอเด้ง","de":"จุ่มทั้งไม้เสียบลงในน้ำซุปร้อนๆ ไอน้ำก็ลอยเป็นกรุ่นๆ วันหนาวหน้าร้านรถเข็นข้างถนน มือที่รองน้ำซุปในแก้วกระดาษแล้วเป่าฟู่ๆ—ความปลอบใจเล็กๆ ที่ตรอกซอยมอบให้"},"ICON-1279":{"nm":"กิมจิ","de":"ค่อยๆ สุกงอมอยู่ในไห บ่มกลิ่นเปรี้ยวลึกล้ำขึ้นเรื่อยๆ ฉีกด้วยมือแล้ววางบนข้าวสวยร้อนๆ ก็เพียงพอแล้ว รสชาติที่แตกต่างกันไปในแต่ละบ้านคือประวัติศาสตร์ของบ้านนั้นเอง"},"ICON-1280":{"nm":"หัวไช้เท้าดองเหลือง","de":"ชิ้นสีเหลืองชิ้นหนึ่งกรอบแตกอย่างสนุกสนานในปาก คู่หูที่ยืนเคียงข้างกิมบับหนึ่งม้วนหรือจานอาหารทานเล่นเสมอ—ความเปรี้ยวหวานล้างปากที่มันเยิ้มให้สดชื่นขึ้นมา"},"ICON-1281":{"nm":"แตงกวาดอง","de":"แตงกวากลั้นหายใจอยู่ในเกลือชั่วครู่ ก่อนจะลืมตาขึ้นในน้ำส้มสายชู เกรงว่าจะพลาดวินาทีที่ความกรอบกลับคืนมา ขวดแก้วจึงไม่เคยห่างจากหน้าต่างที่แดดส่อง เวลาที่ค่อยๆ ดองอย่างช้าๆ นั้นแหละที่นำรสชาติมาให้"},"ICON-1282":{"nm":"โกชูจัง","de":"สีแดงที่ทนผ่านมาหนึ่งปีเต็มอยู่ในไห หลังรสเผ็ดร้อนมีความหวานของถั่วเหลืองซ่อนอยู่แผ่วเบา ตักช้อนหนึ่งละลายลง สตูว์ก็กลายเป็นหน้าตาของบ้านเราในที่สุด เป็นความลึกซึ้งที่ไหจังในลานบ้านเลี้ยงด้วยแสงแดด"},"ICON-1283":{"nm":"เต็นจัง","de":"ก้อนเมจูโอบกอดเชื้อราไว้ผ่านฤดูหนาวทั้งฤดู ความหอมกลมกล่อมคือการเดินสายเชือกอันเสี่ยงระหว่างสุกพอดีกับสุกเกินไป คุณยายรู้เส้นแบ่งนั้นได้จากกลิ่นที่ปลายนิ้วเพียงอย่างเดียว รสชาติที่ยิ่งรอนานยิ่งลึกซึ้ง"},"ICON-1284":{"nm":"ซีอิ๊ว","de":"ยิ่งถั่วเหลืองเข้มดำขึ้นเท่าไหร่ ส่วนลึกข้างในก็ยิ่งลึกซึ้งขึ้นเท่านั้น หยดเดียวก็ทำให้ผักคืนชีพ และทำให้ของตุ๋นเป็นเงางาม สีสันทุกอย่างในครัวในที่สุดก็เริ่มต้นจากสีน้ำตาลอุ่นๆ นี้ รสอูมามิที่อยู่เหนือความเค็ม"},"ICON-1285":{"nm":"ชุนจัง","de":"แม้เป็นสีดำเหมือนกันแต่ลายเนื้อต่างกัน รสหวานเค็มปลายรสจากการผัดซ้ำด้วยคาราเมล คลุกกับเส้นแล้วความเงางามสีดำนั้นก็เขย่าความอยากอาหารให้ตื่น เป็นกระดุมเม็ดแรกที่เปิดรสชาติไฟแรงแบบจีน"},"ICON-1286":{"nm":"ผงกะหรี่","de":"ผงสีเหลืองที่เครื่องเทศหลายชนิดผสมกลมกลืนกันอย่างสงบสุขในช้อนเดียว ละลายในน้ำแล้วเดือดปุดๆ อุ่นทั้งบ้าน กลายเป็นตัวอย่างล่วงหน้าของชามอาหารที่อิ่มท้องที่สุดในเย็นวันฝนตก"},"ICON-1287":{"nm":"พริกไทย","de":"บดทั้งเม็ดถึงจะคงกลิ่นไว้ได้ บดทิ้งไว้ล่วงหน้ากลิ่นจะแอบหายไปเงียบๆ รอบสุดท้ายมักโรยก่อนดับไฟเสมอ—จุดสิ้นสุดเล็กๆ ที่มือทำอาหารแต้มไว้อย่างประหยัด"},"ICON-1288":{"nm":"ผงพริกป่น","de":"พริกแดงตากแดดฤดูใบไม้ร่วงในที่สุดก็สมบูรณ์เป็นสีแดง จะบดละเอียดหรือบดหยาบก็แบ่งบุคลิกของกิมจิ ฝีมือของแม่ครัวจึงมาจากการเลือกความหยาบละเอียดของผงนี้ในที่สุด"},"ICON-1289":{"nm":"เกลือ","de":"การปรุงรสให้พอดีคือการค่อยๆ ก้าวเข้าไปทางฝั่งที่ยังจืดอยู่ทีละหยิบมือ รสเค็มที่ใส่ไปแล้วแก้คืนไม่ได้ มือที่ช่ำชองจึงมักใส่น้อยกว่าปกตินิดหน่อยในตอนท้ายแล้วชิมดู สิ่งที่เก็บไว้คือช่องว่างให้หายใจ"},"ICON-1290":{"nm":"น้ำตาล","de":"มันปลอบขมและมนขอบเปรี้ยวให้กลมขึ้น แต่ความหวานต้องไม่ให้ใครจับได้ว่ามีตัวตนอยู่ เครื่องปรุงที่ดียิ่งขึ้นเท่าไหร่ น้ำตาลก็ยิ่งแอบหายไปจากสายตาในตอนท้ายอย่างเงียบๆ ความหวานที่รู้จักวิธีซ่อนตัว"},"ICON-1291":{"nm":"น้ำผึ้ง","de":"ขวดหนึ่งที่ผึ้งบินไปมาในทุ่งดอกไม้นับพันครั้งเพื่อเก็บมา ถ้าแข็งตัวก็นำไปตุ๋นในน้ำอุ่นให้คืนชีพ ผสมในชาก็โอบกอดลำคออย่างอ่อนโยน ช้อนสีทองหนึ่งช้อนที่เคี่ยวฤดูกาลหนึ่งฤดูทั้งฤดูลงไปทั้งหมด"},"ICON-1292":{"nm":"น้ำมันพืช","de":"หมุนรอบกระทะร้อนหนึ่งรอบ วัตถุดิบก็ลืมที่จะติดกระทะ เทเร็วไปก็ไหม้ ช้าไปก็ติดแน่น จังหวะเดียวที่ควันเพิ่งเริ่มลอยขึ้นคือหลักการของการทอด—วัดเวลาด้วยเสียง"},"ICON-1293":{"nm":"น้ำมันมะกอก","de":"ในสีเขียวของการบีบครั้งแรกมีทั้งกลิ่นหญ้าและรสเผ็ดแผ่วเบาอาศัยอยู่ด้วยกัน ควรราดตอนท้ายมากกว่าตั้งไฟ กลิ่นหอมนั้นจึงจะรอดจนถึงคำสุดท้าย การไม่ปรุงให้สุกจึงเป็นการใช้งานที่ซื่อตรงที่สุด"},"ICON-1294":{"nm":"น้ำมันงา","de":"หยดหนึ่งท้ายสุด ผักคลุกก็ประกาศความสมบูรณ์ในที่สุด ความหอมมันเป็นคุณสมบัติที่หนีหายง่ายบนไฟ จึงมักเป็นจุดจบที่เติมเข้ามาอย่างเงียบๆ หลังการปรุงทุกอย่างเสร็จสิ้นแล้วเสมอ"},"ICON-1295":{"nm":"วานิลลาบีน","de":"ผ่าฝักหนึ่งขูดเมล็ดดำออกมา ของหวานก็เปลี่ยนเสื้อผ้าเป็นกลิ่นหอม แม้เปลือกที่ใช้แล้วก็ไม่ทิ้ง แต่ฝังไว้ในน้ำตาล—ความประหยัดเก่าแก่ที่ปาติซีเยสืบทอดกันมา"},"ICON-1296":{"nm":"โกโก้","de":"เนื้อขาวและเมล็ดขมอยู่ในผล ต้องผ่านการหมักและตากแดดก่อนจึงจะแปลเป็นความหวานที่เรารู้จัก ก่อนจะกลายเป็นช็อกโกแลต มันมีใบหน้าแรกที่ใกล้เคียงความเป็นป่ามากที่สุด"},"ICON-1297":{"nm":"ช็อกโกแลต","de":"นิสัยแสนงอแงที่ละลายหายไปแค่ด้วยความอุ่นของฝ่ามือ ต้องแข็งตัวที่อุณหภูมิราว 28 องศาความเงางามที่แตกกร๊อบจึงจะมีชีวิต หลังความหวานจึงซ่อนกฎอุณหภูมิที่งอแงเกินคาดไว้"},"ICON-1298":{"nm":"เมล็ดกาแฟ","de":"ก่อนถูกบด เมล็ดหนึ่งใกล้เคียงความเงียบอันแข็งกร้าว แต่พอเจอน้ำร้อน มันก็พองฟูขึ้นและปล่อยกลิ่นหอมออกมา สัญญาณแรกที่ปลุกเช้าวันใหม่เริ่มต้นจากเมล็ดเล็กๆ นี้เสมอ"},"ICON-1299":{"nm":"ใบชา","de":"แช่ในน้ำร้อนนานเกินไปก็ฝาด สั้นเกินไปก็จืดชืด การนับเวลาที่ใบชาค่อยๆ คลี่ตัวออกอย่างเงียบๆ—การชงชาก็คือการวัดความรอคอยด้วยปลายนิ้วนั่นเอง"},"ICON-1300":{"nm":"มินต์","de":"บี้แล้วรสขมจะซึมออกมา จึงต้องทะนุถนอมเสมอ เป็นใบอ่อนที่ต้องจับเบาๆ ตบเบาๆ ปลุกกลิ่นที่หลับใหลให้ตื่น และลอยในแก้วในวันร้อนจัด ฤดูร้อนกลางฤดูก็จะจมลงเย็นสบายขึ้นอีกหนึ่งระดับ"},"ICON-1301":{"nm":"สมุนไพร","de":"ใส่ทั้งก้านจะได้กลิ่นหอมลึก ใช้แต่ใบจะได้กลิ่นที่สดใส ตากแห้งแล้วกลิ่นจะเข้มขึ้น ใช้สดจะสดชื่น ยิ่งพวงหนึ่งมีกลิ่นหอมกว้างเท่าไร สีหน้าของครัวก็ยิ่งเบิกบานกว้างขึ้นเท่านั้น"},"ICON-1302":{"nm":"เกาลัด","de":"ภายใต้เปลือกหนามซ่อนเนื้อในเป็นมันวาว กรีดรอยแล้วนำไปย่าง เปลือกจะแตกปังพร้อมกลิ่นหอมหวานโชยออกมา ไอความอุ่นจากถุงเกาลัดคั่วในตรอกที่มีลมหนาวพัดผ่าน เหมือนจับต้องได้แค่เอื้อมมือ"},"ICON-1303":{"nm":"ถั่วลิสง","de":"ความหอมมันสำเร็จขึ้นได้ด้วยไฟคั่ว เมล็ดเล็กๆ ที่แกะกินไปทีละเม็ดจนลืมเวลา เมื่อนั่งล้อมวงกันบนพื้นไม้แบ่งกันกิน เรื่องราวก็ถูกแกะเปลือกออกมาพร้อมกันไปด้วยทีละนิด"},"ICON-1304":{"nm":"อัลมอนด์","de":"ลวกเบาๆ แล้วปอกเปลือกออก เนื้อในจะขาวและนุ่มขึ้นอีก บดละเอียดก็เป็นดั่งนม คั่วทั้งเม็ดก็กรอบ ความหลากหลายในการแปรรูปที่เมล็ดหนึ่งบรรจุไว้ ช่วยขยายจินตนาการของนักทำขนมได้อย่างเต็มที่"},"ICON-1305":{"nm":"งา","de":"เขย่าเบาๆ บนไฟอ่อน แล้วในบางจังหวะมันจะเริ่มแตกป๊อกแป๊ก ช่วงเวลาก่อนเสียงนั้นจะหยุดคือช่วงที่หอมที่สุด การคั่วงาจึงกลายเป็นเรื่องที่ต้องฟังด้วยหู"},"ICON-1306":{"nm":"อ้อย","de":"เคี้ยวข้อเดียวก็มีน้ำหวานซึมออกมาพร้อมกลิ่นหญ้าสด ลำต้นที่ต้องเคี่ยวแล้วเคี่ยวอีกจึงจะกลายเป็นความหวานที่เรารู้จัก จุดเริ่มต้นของน้ำตาลนั้นช่างเขียวขจีและสูงใหญ่อย่างไม่คาดคิด"},"ICON-1307":{"nm":"น้ำตาลดิบ","de":"ความหวานหยาบที่ยังคงสีของตัวเองไว้เพราะผ่านการกลั่นน้อยกว่า มีความลึกคล้ายกลิ่นดินหลงเหลืออยู่แผ่วๆ มือที่รักความจริงใจของสิ่งของก่อนถูกขัดเกลาจนเรียบเนียน จึงตั้งใจเสาะหามันมา"},"ICON-1308":{"nm":"เมล็ดโกโก้","de":"เมล็ดที่เพิ่งแกะออกจากฝักมีรสขมและฝาด ต้องอดทนผ่านการหมักหลายวันอย่างเงียบๆ กลิ่นหอมจึงจะผลิบาน ความหวานจึงเป็นดั่งรางวัลเล็กๆ ที่เมล็ดนี้ได้รับหลังจากอดทนมานาน"},"ICON-1309":{"nm":"คาเคานิบส์","de":"ในชิ้นเมล็ดคั่วบดละเอียดไม่มีน้ำตาลแม้แต่เม็ดเดียว ใส่เข้าปากความขมจะมาก่อน แล้วความหอมมันจึงตามมาทีหลัง จึงได้พบกับโกโก้ในแบบที่ซื่อตรงที่สุด ก่อนที่จะมีความหวานใดๆ"},"ICON-1310":{"nm":"เมล็ดกาแฟดิบ","de":"เมล็ดสีเขียวที่ยังมีกลิ่นดิบอยู่ ในสภาพนี้กลิ่นหอมยังหลับใหลอยู่อย่างสงบ จนกว่าจะได้รับพิธีล้างบาปจากไฟ มันจึงยังคงเป็นความเป็นไปได้ที่ไม่รู้ว่าตัวเองจะกลายเป็นอะไร"},"ICON-1311":{"nm":"เมล็ดกาแฟคั่ว","de":"บนผิวสีน้ำตาลที่มีน้ำมันซึมออกมาเล็กน้อย กลิ่นหอมสะสมอยู่เต็มเปี่ยม ต้องบดก่อนที่มันจะเย็นลงกลิ่นหอมนั้นจึงจะสมบูรณ์ ชะตากรรมของกาแฟหนึ่งแก้วจึงถูกตัดสินอย่างเงียบๆ ภายในไม่กี่วันหลังคั่ว"},"ICON-1312":{"nm":"วานิลลาบีน","de":"กลิ่นหอมเพียงหนึ่งฝักย้อมนมทั้งหม้อให้เปลี่ยนไป แม้แต่ฝักที่ใช้แล้วเมื่อเสียบไว้ในขวดน้ำตาล อีกไม่กี่วันน้ำตาลทั้งขวดก็หอมกรุ่นไปด้วย ความหรูหราที่ไม่มีส่วนไหนต้องทิ้งไปเลยแม้แต่นิดเดียว"},"ICON-1313":{"nm":"พริกไทย","de":"กลิ่นหอมของพริกไทยเม็ดเดียวเริ่มจางลงตั้งแต่วินาทีที่ถูกบด จึงควรเก็บไว้ทั้งเม็ดบนโต๊ะอาหารแล้วบดตอนที่จะใช้จริงๆ ความสดใหม่ผลิบานจากใจที่ไม่ผัดวันประกันพรุ่ง"},"ICON-1314":{"nm":"พริกไทยขาว","de":"เม็ดที่ลอกเปลือกออกจนเรียบเนียนขึ้น มีความอ่อนโยนมากกว่าความเผ็ดร้อน เกิดจากความใส่ใจที่ไม่อยากให้มีจุดดำแม้แต่จุดเดียวหลงเหลือในซอสขาว เป็นความประณีตของตำแหน่งที่มองไม่เห็น"},"ICON-1315":{"nm":"อบเชย","de":"ชงชิ้นเดียวความเผ็ดร้อนอุ่นๆ ก็ค่อยๆ แผ่ซ่านไปทั่วถ้วยชา ใส่ทั้งแท่งแทนที่จะเป็นผงกลิ่นหอมจะอยู่ได้นานกว่า ความลึกซึ้งของเครื่องดื่มฤดูหนาวจึงมาจากความอดทนของเปลือกไม้แห้งชิ้นนี้"},"ICON-1316":{"nm":"กานพลู","de":"ในดอกตูมเล็กๆ รูปทรงคล้ายตะปูหนึ่งดอก กลิ่นหอมเข้มข้นอัดแน่นอยู่ภายใน ใส่มากเกินไปมันจะกลืนกินอาหารทั้งจาน ความยับยั้งชั่งใจของดอกเดียวจึงคอยรักษาสมดุลของรสชาติไว้อย่างเงียบๆ"},"ICON-1317":{"nm":"ลูกจันทน์เทศ","de":"เก็บเมล็ดไว้ทั้งลูกแล้วขูดใช้ทีละนิดตามแต่ละครั้ง เพราะมีธรรมชาติที่กลิ่นจะกระจายหายไปอย่างรวดเร็วหากบดไว้ล่วงหน้า สัมผัสสุดท้ายที่ขูดออกมาเพียงครั้งเดียวจึงทำให้กลิ่นนมลึกซึ้งยิ่งขึ้นไปอีก"},"ICON-1318":{"nm":"กระวาน","de":"บีบฝักสีเขียวให้แตกออก กลิ่นหอมเย็นซ่านก็พรั่งพรูออกมาจากภายใน เพียงบี้ใส่ชาสักหนึ่งหรือสองฝัก ชาแก้วธรรมดาก็ได้กลิ่นหอมจากแดนไกลขึ้นมาทันที"},"ICON-1319":{"nm":"หญ้าฝรั่น","de":"เส้นสีแดงที่เก็บได้เพียงสามเส้นจากดอกไม้หนึ่งดอก ละลายในน้ำอุ่นแสงสีเหลืองจะค่อยๆ แผ่ขยาย ความล้ำค่าจึงเป็นน้ำหนักของเวลาที่ใช้คัดเลือกด้วยมือทีละเส้นเช่นกัน"},"ICON-1320":{"nm":"ขมิ้น","de":"บดรากที่มาจากดินจะย้อมสีเหลืองไปถึงปลายนิ้ว มีธรรมชาติที่กลิ่นหอมจะตื่นขึ้นก็ต่อเมื่อผัดเบาๆ ในน้ำมัน สีทองของแกงกะหรี่จึงเป็นสีที่รากเล็กๆ นี้เบิกบานขึ้นเหนือเปลวไฟ"},"ICON-1321":{"nm":"ใบกระวาน","de":"ใบไม้ที่เล่าขานว่าเคยถูกวางไว้บนหน้าผากของผู้ชนะ ลอยใบหนึ่งลงในน้ำเดือด เสียงโห่ร้องของสนามแข่งเก่าแก่ก็ลอยขึ้นมาชั่วครู่ท่ามกลางไอน้ำ แม้ในวันที่ไม่ได้เป็นผู้ชนะ เพียงสูดกลิ่นหอมนี้เข้าไป ก็กลายเป็นความปลอบโยนสีเขียวที่โอบกอดตัวเราในวันนี้ไว้อย่างเงียบๆ"},"ICON-1322":{"nm":"กะทิ","de":"น้ำสีขาวที่จะไหลออกมาก็ต่อเมื่อทุบเปลือกแข็งให้แตกเท่านั้น ที่มุมหนึ่งของตลาดในเมืองร้อน เสียบหลอดแล้วดื่มสักอึกหนึ่ง ความกระหายยามเที่ยงวันก็เย็นลงจนหมดสิ้น กลิ่นหอมหวานเย็นที่แผ่ซ่านเต็มปากพาร่มเงาแห่งเขตร้อนมาด้วย"},"ICON-1323":{"nm":"น้ำมันมะพร้าว","de":"เมื่อแข็งตัวจะขาวดั่งหิมะแรก เมื่ออุ่นในฝ่ามือกลิ่นหอมจะค่อยๆ แผ่ซ่าน ภูมิปัญญาการดูแลบ้านอันอบอุ่นของคุณยายบนเกาะ ที่ยื่นให้พร้อมบอกว่ากระปุกเดียวก็พอสำหรับตั้งแต่หัวจรดเท้า ยังคงบรรจุอยู่เต็มเปี่ยมในกระปุกกลมใบนี้"},"ICON-1324":{"nm":"กล้วยตาก","de":"ตากแดดไว้สักสองสามวัน เนื้อสีเหลืองก็เหนียวนุ่มขึ้น กัดกินทีละชิ้นอย่างประหยัด กลิ่นหวานเหนียวของฤดูเก็บเกี่ยวที่ฝนตกก็ค่อยๆ ฟื้นคืนในปาก ความหวานที่สุกอย่างช้าๆ อุ้มฤดูกาลไว้เช่นนั้นเอง"},"ICON-1325":{"nm":"มะม่วงตาก","de":"เนื้อผลไม้เนื้อนุ่มถูกตากแดดจนเข้มข้นและกลายเป็นเยลลี่สีอำพัน รสเปรี้ยว หวาน และเหนียวหนึบทั้งสามรสอยู่ในชิ้นเดียว กลิ้งไปมาในปากช้าๆ แล้วช่วงบ่ายทั้งหมดก็ยาวนานขึ้นเพียงเพราะถุงเดียว"},"ICON-1326":{"nm":"สับปะรดตาก","de":"ต่างจากเปลือกหนามภายนอก เนื้อในเหลืองสดใสอย่างไม่มีที่ติ ตากแดดไว้ความเปรี้ยวจะเข้มข้นขึ้น เพียงกัดชิ้นเดียวมุมปากก็ยกขึ้นเองโดยไม่รู้ตัว รสชื่นใจที่หลงเหลืออยู่ปลายชิ้นสุดท้ายคงอยู่นาน"},"ICON-1327":{"nm":"ตะกร้าผลไม้เขตร้อน","de":"สีสันที่เพิ่งเก็บมาสดๆ ผสมผสานกันอยู่ในตะกร้าเดียว สีส้มของมะม่วง สีเหลืองของกล้วย สีทองของสับปะรด ก่อนที่มือจะเอื้อมไปเลือก ฤดูร้อนก็พัดมาถึงปลายจมูกก่อนแล้ว หนึ่งอ้อมกอดที่แค่มองก็ทำให้ใจสว่างไสว"},"ICON-1328":{"nm":"ห่อสาหร่ายทะเล","de":"ผมของท้องทะเลที่เก็บมาจากโขดหินยามน้ำลด เสียงคลื่นพันเกลียวอยู่ในกลิ่นทะเลเค็มๆ แช่ในน้ำเย็นเบาๆ กลิ่นทะเลคาวๆ ก็ค่อยๆ ลอยมาถึงครัว หนึ่งกำมือแผ่หาดโคลนเล็กๆ ไว้บนโต๊ะอาหาร"},"ICON-1329":{"nm":"อาหารทะเลตากแห้ง","de":"หนึ่งกำมือของท้องทะเลที่ตากแห้งจนแน่นเหนียว ฉีกตามลายเนื้อด้วยมือ ลมเค็มของท่าเรือเก่าก็คลายตัวออกมาพร้อมความเค็ม เป็นเพื่อนเก่าแก่คู่โต๊ะอาหารอบอุ่นที่ทำให้อยากดื่มมักกอลลีสักถ้วยขึ้นมาเอง"},"ICON-1330":{"nm":"ปลาหมึกตากแห้ง","de":"หนวดสิบเส้นถูกคลี่กางเรียงตากแดด ย่างไฟเบาๆ จนกลิ่นหอมมันลอยขึ้นมาแล้วฉีกตามลาย รสสัมผัสที่เหนียวหนึบนั้นยกระดับความมีคลาสของจานของกินเล่นดึกๆ ขึ้นไปอีกขั้น"},"ICON-1331":{"nm":"ปลาเค็ม","de":"ฝังไว้ในเกลือเม็ดหยาบ ปลาก็เรียนรู้วิธีอดทนต่อกาลเวลา เนื้อในรสเค็มลึกๆ เพียงคำเดียวก็ทำให้ข้าวหนึ่งชามหมดไปในพริบตา เป็นเคล็ดลับอันอบอุ่นที่คุณยายชายทะเลถ่ายทอดผ่านปลายนิ้วมือ"},"ICON-1332":{"nm":"กุ้งเค็มดอง","de":"กุ้งตัวเล็กๆ สุกงอมอย่างช้าๆ ในเกลือ กลายเป็นรสอูมามิลึกล้ำ วินาทีที่ใส่ลงไปหนึ่งช้อนในผักกาดขาวยามทำกิมจิ กลิ่นเค็มๆ ก็แผ่ไปทั่วลานบ้าน ช้อนเดียวนั้นเองที่ตัดสินรสชาติกิมจิของทั้งปี"},"ICON-1333":{"nm":"ปลาแอนโชวี่แห้ง","de":"ตัวเล็กเท่านิ้วมือรับผิดชอบความเข้มข้นของน้ำซุปทั้งหม้อ ครัวในวัยเด็กที่พูดคุยกันไปพลางแกะหัวและไส้ออก แม้ตัวเล็กแต่เป็นปลาที่ยืนหยัดมั่นคงอยู่ใจกลางของการดูแลบ้านอย่างน่าขอบคุณ"},"ICON-1334":{"nm":"สาหร่ายคอมบุ","de":"แถบสีดำยาวที่เติบโตอยู่ใต้ท้องทะเล ใส่ลงในน้ำเย็นแล้วช้อนขึ้นเบาๆ ก่อนที่จะเดือดพอดี เป็นคำสัญญาที่มือผู้ต้มน้ำซุปรักษาไว้สืบต่อกันมาหลายชั่วอายุคน ความอูมามิอันลึกซึ้งนั้นไม่เคยรีบร้อนเลยแม้แต่น้อย"},"ICON-1335":{"nm":"สาหร่ายฮิจิกิ","de":"สัมผัสขรุขระแตกป๊อกแป๊กในปาก สาหร่ายที่ย้อมโขดหินชายฝั่งให้เป็นสีเขียวในฤดูใบไม้ผลิ ปรุงคลุกเคล้าด้วยมือแล้วท้องทะเลเล็กๆ อันสดชื่นก็แผ่ขยายอยู่ที่มุมหนึ่งของโต๊ะอาหาร เป็นรสชาติของการเคี้ยวฤดูใบไม้ผลิ"},"ICON-1336":{"nm":"หอยมุก","de":"แสงกลมที่บ่มเพาะขึ้นมานานแสนนานระหว่างเปลือกแข็งสองข้าง กว่าจะเปลี่ยนความไม่สบายตัวของเม็ดทรายเม็ดเดียวให้กลายเป็นอัญมณี ทะเลไม่เคยเร่งรีบแม้แต่ครั้งเดียว วางไว้บนฝ่ามือ น้ำหนักแห่งความอดทนอันยาวนานนั้นก็แนบมาด้วย"},"ICON-1337":{"nm":"เครื่องประดับปะการัง","de":"กิ่งไม้แห่งท้องทะเลที่คลื่นขัดเกลามานับร้อยปี เมื่อแสงแดดสัมผัส สีชมพูและสีส้มก็แผ่ซ่าน เพียงวางไว้เงียบๆ บนชั้นวางของ ห้องทั้งห้องก็ย้อมเป็นเกาะที่อบอุ่น แม้แต่ลายผิวหยาบที่สัมผัสปลายนิ้วก็ยังรู้สึกอบอุ่นใจ"},"ICON-1338":{"nm":"กระดุมเปลือกหอย","de":"บริเวณที่เนื้อหอยเคยจากไป ผิวด้านในที่แวววาวถูกตัดออกมาเป็นวงกลม เมื่อติดที่คอเสื้อ ทุกครั้งที่กลัดกระดุมสายรุ้งเล็กๆ ก็ระยิบระยับที่ปลายนิ้ว เป็นของขวัญอันอบอุ่นสุดท้ายที่ทะเลทิ้งไว้ให้ ก่อนจากไปพร้อมกับมอบทุกสิ่งให้จนหมด"},"ICON-1339":{"nm":"ลูกแก้ว","de":"กลิ้งบนฝ่ามือ แสงที่ถูกกักไว้ภายในก็กลิ้งตามไปด้วย ในวันวานที่นั่งยองๆ เล่นเกมแทะกันในตรอกจนลืมพระอาทิตย์ตก กระเป๋าของเด็กที่ชนะได้อีกลูกหนึ่งนั้นหนักและภูมิใจเป็นพิเศษ"},"ICON-1340":{"nm":"ไม้แกะสลักกลิ่นหอม","de":"ตามลายที่แกะสลักแต่ละเส้น กลิ่นหอมอ่อนๆ ซึมออกมา คนโบราณเผาไม้ชนิดนี้เพื่อรวบรวมจิตใจที่กระจัดกระจาย ถือชิ้นหนึ่งไว้เงียบๆ ความสงบก็ค่อยๆ ไหลขึ้นมาจากปลายนิ้วมือ"},"ICON-1341":{"nm":"ธูปหอม","de":"ก้านเล็กเรียวหนึ่งก้านค่อยๆ ลุกไหม้ เปิดทางขึ้นสู่เบื้องบน มองตามเส้นโค้งที่ควันวาดไว้ด้วยสายตา ใจที่รีบเร่งมาทั้งวันก็ค่อยๆ ชะลอฝีเท้าและอยู่นิ่งเงียบในที่นั้น"},"ICON-1342":{"nm":"ดอกไม้ย้อมสี","de":"ปล่อยสีที่ซ่อนอยู่ในกลีบดอกลงในหม้อเดือด ผ้าใสก็ค่อยๆ ย้อมสีตามนั้น การยืมสีที่ธรรมชาติแต่งแต้มไว้ล่วงหน้ามาใช้ชั่วคราว การย้อมสีแต่เดิมจึงเป็นคำทักทายอันอบอุ่นที่ส่งให้ดอกไม้"},"ICON-1343":{"nm":"สีย้อมคราม","de":"สีน้ำเงินเข้มลึกและนุ่มนวลที่ได้จากการหมักต้นครามซ้ำแล้วซ้ำเล่า ทุกครั้งที่จุ่มแล้วยกผ้าขึ้น สีก็ค่อยๆ เปลี่ยนจากสีท้องฟ้าไปเป็นสีทะเล เป็นสีแห่งการรอคอยที่จะผลิบานได้ก็ต่อเมื่อวางความใจร้อนลงเท่านั้น"},"ICON-1344":{"nm":"สีย้อมแดง","de":"ต้มรากมาดเดอร์ แสงอาทิตย์ยามเย็นที่หลับใหลอยู่ในดินก็ตื่นขึ้นในหม้อ เป็นสีที่งดงามและรื่นเริงที่สุดในหมู่บ้าน สีที่เคยย้อมชายกระโปรงของเจ้าสาวใหม่ในวันแต่งงานให้งดงามอ่อนช้อย"},"ICON-1345":{"nm":"ด้ายทอง","de":"ดึงทองที่เรียวบางกว่าเส้นผมออกมาปั่นด้วยความพิถีพิถันทีละเส้น ทุกจุดที่ปักลวดลายจะเก็บกักแสงไว้ แม้ในห้องมืดที่ตะเกียงดับ ลวดลายนั้นก็ยังคงเปล่งประกายนุ่มนวลด้วยตัวมันเอง"},"ICON-1346":{"nm":"ผ้าไหม","de":"เส้นไหมที่หนอนไหมคายออกมาต้องทอแล้วทออีกจึงจะได้ผืนหนึ่งพอดี สัมผัสที่ลื่นไหลดั่งน้ำในฤดูใบไม้ผลิเมื่อสัมผัสหลังมือ เป็นผ้าเนื้อละเอียดที่คนโบราณอุ้มไว้ทั้งฤดูและค่อยๆ เลี้ยงดูมันขึ้นมา"},"ICON-1347":{"nm":"กระดุมมุก","de":"คัดเลือกเฉพาะแสงจากด้านในของมุกมาขัดให้เป็นทรงกลม ทุกครั้งที่กลัดที่คอเสื้อโจกอรี ปลายนิ้วก็สง่างามขึ้นชั่วครู่ แม้จะเล็ก แต่เป็นเม็ดกลมเรียบร้อยที่ค่อยๆ ยกระดับความสง่างามของเครื่องแต่งกาย"},"ICON-1348":{"nm":"เศษแผนที่เดินเรือ","de":"เหนือขอบที่ฉีกขาด แนวชายฝั่งที่ไม่รู้จักถูกตัดขาดหายไปทันที ว่ากันว่ามีเพียงผู้ที่รวบรวมชิ้นส่วนที่เหลือได้เท่านั้นจึงจะไปถึงสมบัติ แต่บางทีการเดินทางเสาะหามันตามสายลมนั่นเองอาจเป็นสมบัติอยู่แล้วก็ได้"},"ICON-1349":{"nm":"แผนที่ทะเลเก่า","de":"เส้นทางเดินเรือที่เลอะเลือนด้วยน้ำทะเล และภาพเข็มทิศที่สีซีดจาง ลากปลายนิ้วตามเส้นที่กะลาสีคนหนึ่งขีดไว้ด้วยแสงดาวเพียงอย่างเดียวในค่ำคืนมืดมิด แล้วเกาะที่หายไปนานแล้วเกาะหนึ่งก็ค่อยๆ ผุดขึ้นมาอีกครั้งบนกระดาษเก่า"},"ICON-1350":{"nm":"จดหมายในขวด","de":"ในขวดแก้วที่คลื่นซัดมาเกยฝั่ง มีกระดาษม้วนหนึ่งแผ่น คำทักทายที่ไม่รู้ว่าใครส่งมาเมื่อไหร่ ในที่สุดก็มาถึงมือของใครคนหนึ่ง หากมีใจมากพอ แม้แต่ทะเลก็กลายเป็นบุรุษไปรษณีย์ที่แสนเชื่องช้าเช่นนี้ได้"},"ICON-1351":{"nm":"หีบล่องลอย","de":"การผจญภัยดำเนินไปจนถึงวินาทีที่งัดฝาที่บวมแข็งเพราะน้ำเค็มออก ไม่ว่าสิ่งที่รออยู่ข้างในจะเป็นสมบัติหรือเพียงทรายเปล่า หีบที่ล่องลอยมาไกลมักพัดพาเรื่องราวของใครสักคนที่ไม่รู้จักหน้าตาติดมาด้วยเสมอ"},"ICON-1352":{"nm":"กุญแจดอกเล็ก","de":"เศษเหล็กเก่าชิ้นหนึ่งที่พอดีในฝ่ามือ แม้จะลืมไปหมดแล้วว่าใช้เปิดประตูบานไหน แต่น้ำหนักอันอบอุ่นที่ทำให้นึกถึงวิธีเปิดก่อนวิธีล็อกยังคงหนักอึ้งอยู่ที่ปลายนิ้ว"},"ICON-1353":{"nm":"เหรียญเงิน","de":"เหรียญเงินกลมที่ลวดลายเลือนลางไปเพราะรอยมือผู้คน เหรียญเดียวที่อาจเคยเป็นค่าโดยสารเรือหรือที่พักคืนอันแสนเหนื่อยล้าของใครสักคน ลูบผิวเย็นๆ ของมันแล้ว ความอบอุ่นของการแลกเปลี่ยนในอดีตก็ฟื้นคืนมาแผ่วเบาที่ปลายนิ้ว"},"ICON-1354":{"nm":"เหรียญทอง","de":"วางบนฝ่ามือ น้ำหนักอันหนักอึ้งจะสั่นสะเทือนหัวใจก่อนสิ่งใด เหรียญเดียวที่เปล่งประกายเหลืองอร่ามภายใต้แสงแดด ดูราวกับว่าจะทำให้ร่ำรวยได้หากครอบครองไว้ แต่ที่จริงแล้วสิ่งที่เปล่งประกายสว่างที่สุดคือความตื่นเต้นก่อนที่มันจะตกลงมาในมือต่างหาก"},"ICON-1355":{"nm":"ตราประทับกัปตัน","de":"คำสัญญาของกัปตันที่กดประทับลงบนขี้ผึ้งแดงอย่างหนักแน่น ลวดลายเดียวสามารถออกคำสั่งและกำหนดเส้นทางอันโหดร้ายได้ อำนาจในท้ายที่สุดแล้วก็เป็นเพียงตราประทับเล็กๆ แต่หนักแน่นหนึ่งดวง ที่ทุกคนบนเรือลำเดียวกันตกลงจะเชื่อมั่นร่วมกัน"},"ICON-1356":{"nm":"ไมโครโฟนมือถือ","de":"วินาทีที่กำไว้ในมือ น้ำหนักที่มั่นคงอย่างประหลาดก็เติมเต็มฝ่ามือ ไม่ว่าจะเป็นตอนทักทายครั้งแรกที่สั่นเทา หรือตอนที่เปล่งเสียงสูงในที่สุด แท่งเล็กๆ นี้เพียงแท่งเดียวก็แอบติดปีกให้กับเสียงของเธออย่างแผ่วเบา"},"ICON-1357":{"nm":"ไมโครโฟนไร้สาย","de":"เมื่อสายหายไป เวทีทั้งหมดก็กว้างขึ้นทันที แม้จะวิ่งไปจนสุดที่นั่งไกลสุด เสียงก็ไม่เคยขาดหายแม้แต่ครั้งเดียว ราวกับมีใครสักคนค่อยๆ ผลักหลังให้วิ่งไปร้องเพลงได้อย่างเต็มที่ตามใจปรารถนา"},"ICON-1358":{"nm":"ไมโครโฟนตั้งพื้น","de":"ยืนหยัดมั่นคงอยู่แทบเท้า รอคอยนักร้องอย่างเงียบๆ เมื่อมือทั้งสองเป็นอิสระ บทเพลงก็แผ่ซ่านไปทั่วร่างแทนที่จะจำกัดอยู่แค่ปลายนิ้ว การยืนหยัดในที่เดิมจนถึงที่สุดก็มีเสน่ห์ในแบบของมันเอง แท่งเหล็กนี้พูดขึ้นอย่างเงียบๆ เช่นนั้น"},"ICON-1359":{"nm":"ป็อปฟิลเตอร์","de":"ผ้าชั้นเดียวรูปวงกลมที่กั้นอยู่หน้าไมโครโฟน กรองลมหายใจแรงๆ ให้นุ่มนวลลงและปล่อยผ่านเพียงเสียงใสๆ การทำให้ใครสักคนได้ยินชัด คือการคอยกั้นบังอย่างเงียบๆ จากตำแหน่งที่มองไม่เห็นจนถึงที่สุด"},"ICON-1360":{"nm":"หูฟังอินเอียร์","de":"สอดใส่พอดีในหู เสียงเพลงของตัวเองก็ฟื้นคืนชัดเจนท่ามกลางเสียงโห่ร้องนับหมื่น เพื่อนร่วมทางที่เล็กที่สุดและลับที่สุด ที่คอยจับจังหวะไม่ให้พลาดบนเวทีที่เต็มไปด้วยแสงและเสียง"},"ICON-1361":{"nm":"หูฟังครอบหู","de":"วินาทีที่ครอบหูไว้ โลกก็เล็กลงหนึ่งช่วง และมีเพียงบทเพลงที่ดังกึกก้อง ห้องกลมเล็กๆ ห้องหนึ่งที่ไม่มีใครแทรกเข้ามาได้ ในหูฟังที่ใส่คนเดียว ประหลาดที่ไม่รู้สึกโดดเดี่ยวเลย"},"ICON-1362":{"nm":"โน้ตเพลง","de":"เมื่อจุดสีดำเรียงรายลงบนเส้นอย่างสงบ กระดาษที่เคยเงียบงันก็อุ้มเสียงไว้ ตัวอักษรที่ไม่ได้อ่านแต่ต้องฟัง วินาทีที่เปิดออก บทเพลงที่หยุดนิ่งอยู่ก็หายใจอีกครั้ง"},"ICON-1363":{"nm":"โน้ตร้อง","de":"มีวงกลมเล็กๆ วาดไว้ทุกจุดที่ต้องหายใจ หายใจเข้าตรงนี้ แล้วค่อยๆ ปล่อยตรงนั้น แผนที่อันอ่อนโยนที่เปิดทางไม่ให้เสียงบาดเจ็บ"},"ICON-1364":{"nm":"โน้ตเปียโน","de":"หน้ากระดาษที่นิ้วทั้งสิบถามหาทางไปพร้อมกัน มือซ้ายจับรากฐาน มือขวาวาดบทเพลง มือทั้งสองที่เคยเล่าเรื่องต่างกัน สุดท้ายก็ซ้อนทับเป็นหนึ่งเดียวในห้องสุดท้าย"},"ICON-1365":{"nm":"ตารางคอร์ดกีตาร์","de":"ภาษาต่างประเทศภาษาแรกที่นิ้วมือได้เรียนรู้ คำแรกของมันถูกจดไว้ที่นี่ เมื่อจุดหกจุดมารวมกันเป็นวงกลม เสียงหนึ่งจึงจะร้องออกมาได้ ทุกค่ำคืนที่กดแล้วกดอีก หนังด้านก็ค่อยๆ งอกที่ปลายนิ้ว"},"ICON-1366":{"nm":"เครื่องเคาะจังหวะ","de":"ติ๊ก ติ๊ก จังหวะที่ไม่หวั่นไหวเดินเคาะอยู่ข้างกาย เมื่อใจวิ่งนำไปก่อน มันก็คอยดึงกลับมาช้าๆ จากด้านหลังอย่างนุ่มนวล เพราะจังหวะในท้ายที่สุดแล้วคือคำสัญญาว่าจะเดินไปด้วยกัน"},"ICON-1367":{"nm":"เครื่องจูนเสียง","de":"เมื่อเข็มค่อยๆ เลื่อนมาอยู่ตรงกลาง เสียงจึงจะพบที่ทางของตัวเองในที่สุด จุดเดียวนั้นที่ไม่สูงไม่ต่ำ การเข้าคีย์พอดีคือแบบนี้เอง ไม่สั่นไหวอีกต่อไป เพียงหยุดนิ่งลงอย่างเงียบๆ"},"ICON-1368":{"nm":"การ์ดคีย์เปียโน","de":"พลิกทีละแผ่น คีย์เปียโนก็เดินเข้ามาในฝ่ามือ จากโดถึงติ จักรวาลเล็กๆ เจ็ดช่อง แม้ในคืนที่ไม่มีเปียโนจริง บทเพลงก็ยังคงเติบโตอย่างเงียบๆ ที่นี่"},"ICON-1369":{"nm":"ปิ๊กกีตาร์","de":"ชิ้นเล็กๆ ที่แข็งแรงหนีบไว้ระหว่างนิ้วโป้งกับนิ้วชี้ ทำหล่นแล้วมันจะหายไปตลอดกาลใต้เก้าอี้ แต่วินาทีที่ถือมันไว้ในมือ สายทั้งหกก็ดังกังวานขึ้นพร้อมกัน"},"ICON-1370":{"nm":"ไม้กลอง","de":"เมื่อไม้สองอันปะทะกันกลางอากาศ สัญญาณก็ตกลงตรงนั้น หนึ่ง สอง สาม สี่ หัวใจของทุกคนที่กระจัดกระจายเริ่มเต้นในจังหวะเดียวกันตามสี่จังหวะนั้น"},"ICON-1371":{"nm":"แทมบูรีน","de":"เขย่าครั้งเดียว เสียงใสๆ ก็กระจายไปทั่วทุกทิศราวกับแสงแดดแตกกระจายเป็นเสี่ยงๆ แม้ดูเบา แต่เป็นจังหวะแรกที่มือจะเอื้อมไปเมื่ออารมณ์เริ่มจืดจาง ตัวเล็กแต่ไม่มีใครมองข้ามได้"},"ICON-1372":{"nm":"รองเท้าผ้าใบเต้น","de":"สำหรับเท้าที่หมุนไปบนพื้นราวกับร่อนลื่น แรงเสียดทานคืออาวุธ ทุกการหมุนที่หมุนแล้วหมุนอีกถูกสลักไว้บนพื้นรองเท้าที่สึกกร่อน ท่วงท่าที่เจ๋งที่สุดเริ่มต้นจากรองเท้าคู่แข็งแรงหนึ่งคู่เสมอ"},"ICON-1373":{"nm":"สนับเข่า","de":"มีเพียงผู้ที่คุกเข่าลงนับครั้งไม่ถ้วนแล้วลุกขึ้นใหม่เท่านั้นที่รู้ ความซาบซึ้งของผ้าชั้นบางๆ ชิ้นนี้ สิ่งที่ทำให้พื้นไม่น่ากลัวอีกต่อไป ความกล้าหาญบางครั้งก็พันอยู่รอบหัวเข่าเช่นนี้เอง"},"ICON-1374":{"nm":"สนับข้อมือ","de":"พันไว้ล่วงหน้าตรงจุดที่งอได้ แม้ท่วงท่าที่หักโหมก็จะอ่อนโยนขึ้นอีกนิด ข้อมือไม่พูดอะไร อดทนอยู่คนเดียวจนกว่าจะเจ็บปวด ความเงียบงันอันยาวนานนั้น ผ้าชั้นเดียวนี้ช่วยกั้นแทนให้"},"ICON-1375":{"nm":"สนับข้อเท้า","de":"ปลายทางของการกระโดดสูงคือการลงพื้น และปลายทางของการลงพื้นนั้นคือข้อเท้า จุดต่ำสุดที่รองรับน้ำหนักทั้งร่างกาย แถบเล็กๆ นี้คอยเฝ้าดูแลการฝึกซ้อมของวันพรุ่งนี้อย่างเงียบๆ"},"ICON-1376":{"nm":"ยางยืดสำหรับยืดกล้ามเนื้อ","de":"ยิ่งดึงมันก็ยิ่งต้านทานเพื่อกลับสู่ที่เดิมมากเท่านั้น ระหว่างที่อดทนต่อแรงต้านนั้น ร่างกายก็ค่อยๆ ยืดยาวขึ้นทีละนิดโดยไม่รู้ตัว ความยืดหยุ่นในท้ายที่สุดคือรอยที่เวลาแห่งความอดทนทิ้งไว้"},"ICON-1377":{"nm":"เสื่อโยคะ","de":"วินาทีที่ปูออก ผืนดินสำหรับหนึ่งคนก็ปรากฏขึ้นบนพื้น ดินแดนเล็กๆ สำหรับนอนคว่ำ นอนหงาย และปรับลมหายใจให้เรียบ จุดเริ่มต้นและจุดสิ้นสุดของวันถูกเก็บงำไว้อย่างเงียบๆ บนผืนเดียวนี้"},"ICON-1378":{"nm":"โฟมโรลเลอร์","de":"กดจุดที่เกร็งตัวอย่างแน่วแน่ ตอนแรกจะเจ็บ แต่ไม่นานก็จะรู้สึกโล่งสบาย การคลายสิ่งที่แข็งเกร็งมักมีความเจ็บปวดเล็กน้อยเสมอ เพราะทั้งร่างกายและจิตใจต่างต้องถูกกดสักครั้งจึงจะคลายออกได้"},"ICON-1379":{"nm":"ดัมเบล","de":"ยกน้ำหนักเดิมแล้วยกอีกครั้ง มากกว่าเมื่อวานเพียงครั้งเดียว แค่นั้นเอง ในการทำซ้ำที่ไม่มีอะไรหวือหวา แขนก็หนาขึ้นโดยไม่ปริปาก ก้อนเหล็กหนึ่งก้อนที่ซื่อตรงอย่างเดียวเท่านั้น"},"ICON-1380":{"nm":"เคทเทิลเบล","de":"มือจับเดียวเหวี่ยงทั้งร่างกายไปทั้งตัว เมื่อน้ำหนักกลมหมุนเป็นวงกลม ความสมดุลของผู้ที่ยืนหยัดก็ถูกทดสอบ หากไม่อยากสั่นคลอน ต้องรู้จักจุดศูนย์กลางของตัวเองก่อน"},"ICON-1381":{"nm":"เชือกกระโดด","de":"กระโดดข้ามเชือกเส้นหนึ่งที่แว่บผ่านใต้เท้า แล้วกระโดดอีกครั้ง เหมือนเกมนับเลขกับเพื่อนๆ ในสนามเมื่อครั้งก่อน ยิ่งตัวเลขสะสมมากขึ้นเท่าไร ลมหายใจก็ยิ่งพร่ามัวและเสียงหัวเราะก็ยิ่งเพิ่มขึ้น"},"ICON-1382":{"nm":"รองเท้าวิ่ง","de":"รองเท้าคู่หนึ่งที่จะรู้คุณค่าที่แท้จริงก็ต่อเมื่อได้ก้าวลงบนถนนเท่านั้น วิ่งฝ่าอากาศยามเช้าตรู่บนเส้นทางเดิมอีกครั้ง มุมถนนที่เคยไกลเมื่อวานก็มาอยู่ตรงหน้าในวันนี้ ระยะทางนั้นเท้าจดจำไว้เอง"},"ICON-1383":{"nm":"ผ้าเช็ดเหงื่อ","de":"เช็ดเหงื่อที่หน้าผากออก ก็มีความพยายามของวันนี้แนบซึมอยู่หนึ่งเส้นตรงนั้น แม้ซักแล้วรอยจะหายไป แต่สิ่งที่หลั่งออกมามากเท่าไรก็สะสมอยู่ที่ไหนสักแห่งอย่างเป็นระเบียบ กำลังใจที่ซื่อตรงที่สุดมักแห้งอยู่ข้างกายเสมอ"},"ICON-1384":{"nm":"ขวดน้ำ","de":"ว่างก็เติม แห้งก็จิบสักอึก การไปกลับที่เรียบง่ายนั้นค้ำจุนทั้งวันไว้อย่างเงียบๆ เหมือนถังตักน้ำที่ขึ้นลงที่บ่อน้ำ วันใหม่เริ่มต้นอีกครั้งจากการเติมเต็มนี่เอง"},"ICON-1385":{"nm":"โปรตีนเชค","de":"เขย่าให้เข้ากันแล้วดื่มสักอึก กล้ามเนื้อที่สลายไปวันนี้ก็จะเติมเต็มอีกครั้งในวันพรุ่งนี้ แม้รสชาติจะไม่หวือหวา แต่ร่างกายรู้ดีว่านี่คือภาษาแห่งการฟื้นฟู การเติบโตมักถูกดื่มเข้าไปอย่างเงียบๆ เสมอ"},"ICON-1386":{"nm":"เอนเนอร์จีบาร์","de":"แท่งเดียวที่ถูกกดจนแบนอยู่ในกระเป๋า เสบียงฉุกเฉินที่เติมเต็มช่วงเวลาว่างเปล่าระหว่างมื้ออาหาร แม้จะไม่ใช่อะไรยิ่งใหญ่ แต่คำเล็กๆ นี้ช่วยให้ทนต่อได้อีกหนึ่งท่วงท่าในยามบ่าย"},"ICON-1387":{"nm":"ยาอมแก้เจ็บคอ","de":"กลิ้งไปในปาก มินต์เย็นซ่าจะลูบไล้คอที่แห้งกร้านอย่างแผ่วเบา วันที่พูดมาก คืนที่ร้องเพลงมาก ลูกอมเม็ดเล็กหนึ่งเม็ดปลอบประโลมเส้นทางที่แสบคัน ความหวานก็มีประโยชน์อย่างแน่นอน"},"ICON-1388":{"nm":"ชาบำรุงเสียง","de":"ไอน้ำอุ่นๆ อุ่นคอ และเพียงอึกเดียวความตึงเครียดที่ไหล่ก็คลายลง เป็นตำรับเก่าแก่เหมือนชาขิงที่คุณยายเคยต้มให้ดื่ม คำทักทายอันอบอุ่นที่มอบให้เสียงก่อนร้องเพลง"},"ICON-1389":{"nm":"น้ำผึ้งผสมน้ำอุ่น","de":"ละลายน้ำผึ้งหนึ่งช้อนลงในน้ำอุ่นๆ อย่างช้าๆ ถ้วยที่ผู้ใหญ่มักชงให้เมื่อคอแห้งแสบเสมอ ไม่ใช่ยา ไม่ใช่เครื่องดื่ม เป็นเพียงความหวานที่ลูบไล้ร่างกายอย่างเงียบๆ จากภายใน"},"ICON-1390":{"nm":"ถังน้ำเครื่องเพิ่มความชื้น","de":"ภาชนะที่ปล่อยหมอกเล็กๆ ออกมาในห้อง คืนฤดูหนาวที่อากาศแห้งข่วนลำคอ มันแบ่งปันความชุ่มชื้นให้อย่างมองไม่เห็น การดูแลใครสักคนมักไหลเวียนอย่างเงียบเชียบเช่นนี้เสมอ"},"ICON-1391":{"nm":"คูปองพักผ่อน","de":"กระดาษแผ่นหนึ่งที่เขียนไว้ว่าพักได้นะ วินาทีที่รับมาไว้ในมือ ภาระในใจก็เบาลงหนึ่งขั้น การหยุดพักก็เป็นการฝึกฝนอย่างหนึ่งเช่นกัน ตั๋วเล็กๆ ใบนี้ให้อนุญาตแทนเรา"},"ICON-1392":{"nm":"ตารางฝึกซ้อม","de":"เหนือเวลาที่เขียนไว้ในแต่ละช่อง วันหนึ่งวันก็ค่อยๆ ลงหลักปักฐานทีละนิด เช้าฝึกร้อง บ่ายฝึกเต้น เย็นพักผ่อน แม้พรุ่งนี้ที่เคยดูมืดมนไร้หนทาง เมื่อขีดเส้นแบ่งออกเป็นช่วงๆ ก็กลายเป็นสิ่งที่พอเดินไปได้"},"ICON-1393":{"nm":"ตราประทับเช็คชื่อ","de":"กดประทับเครื่องหมายที่บอกว่าวันนี้ก็มาแล้วอย่างหนักแน่น ยิ่งวงกลมที่หมึกเลอะเลือนเล็กน้อยเพิ่มขึ้นทีละช่อง ความขยันที่ดูเหมือนไม่มีอะไรก็ค่อยๆ กลายเป็นเส้นทางโดยไม่รู้ตัว หลักฐานเล็กๆ ของแต่ละวัน"},"ICON-1394":{"nm":"สติกเกอร์คำชม","de":"แทนคำว่าทำได้ดีมาก ติดดาวดวงหนึ่งไว้อย่างเงียบๆ แม้จะเป็นประกายเล็กเท่าปลายเล็บ แต่วินาทีที่มันเกาะอยู่มุมสมุด ทั้งวันก็สว่างไสวขึ้น คำชมแม้เล็ก แต่กลับส่องแสงได้นานอย่างประหลาด"},"ICON-1395":{"nm":"สมุดบันทึกใจ","de":"หน้ากระดาษที่คลายใจที่สั่นเทาอยู่หลังเวทีออกมาเป็นตัวอักษร แม้วันที่ไม่ราบรื่นก็จดไว้อย่างตรงไปตรงมา แล้วจะรู้สึกเบาลงไม่ทางใดก็ทางหนึ่ง ใจจะแข็งแกร่งขึ้นเท่าที่มองเข้าไปข้างในตัวเอง"},"ICON-1396":{"nm":"การ์ดฝึกจินตภาพ","de":"หลับตาแล้วถือไว้ในมือ เวทีก็ค่อยๆ ปรากฏขึ้นในหัวอย่างเงียบๆ การเดินสำรวจล่วงหน้าหนึ่งรอบในที่ที่ยังไม่เคยยืนอยู่ เส้นทางที่วาดขึ้นด้วยจินตนาการมาถึงก่อนปลายเท้าจริงหนึ่งก้าวเสมอ"},"ICON-1397":{"nm":"กระจกฝึกสีหน้า","de":"หน้ากระจก ยิ้มแล้วก็เกร็ง ทำหน้าเดิมซ้ำนับร้อยครั้ง ที่นี่เราเรียนรู้ว่าทั้งความสุขและความเศร้าล้วนต้องการการฝึกฝน เพราะสีหน้าคือการคัดลอกใจออกมาสู่ภายนอกนั่นเอง"},"ICON-1398":{"nm":"สมุดบันทึกท่าเต้น","de":"หน้ากระดาษที่คัดลอกเส้นทางที่เท้าและแขนจะเคลื่อนผ่านออกมาเป็นภาพวาด ลูกศรบอกอย่างเงียบๆ ว่าร่างกายควรไปทางไหนในทุกแปดจังหวะ แม้ท่าเต้นที่จำไม่ได้สักที ก็ค่อยๆ เชื่องบนหน้ากระดาษนี้"},"ICON-1399":{"nm":"ชิปวิดีโอท่าเต้น","de":"ท่วงท่านับร้อยครั้งถูกเก็บไว้ครบถ้วนในชิปเล็กๆ ชิ้นเดียว เปิดดูอีกครั้งก่อนนอน ปลายนิ้วก็เคลื่อนไหวตามเส้นทางนั้นไปเองโดยอัตโนมัติ การทำซ้ำคือบันทึกอีกชนิดหนึ่งที่คัดลอกผ่านร่างกาย"},"ICON-1400":{"nm":"แผนผังการเคลื่อนไหวบนเวที","de":"แผนที่แผ่นเดียวที่มองเวทีจากด้านบน ใครจะพบกันที่ไหนแล้วกระจายไปทางไหน ล้วนถูกสัญญาไว้ล่วงหน้าด้วยเส้นและจุด หากจะวาดภาพเดียวกันร่วมกันหลายคน ต้องแบ่งเส้นทางกันก่อนเป็นอันดับแรก"},"ICON-1401":{"nm":"บัตรผ่านซ้อม","de":"ที่นั่งผู้ชมว่างเปล่า และไฟยังคงหลับใหล บัตรใบนี้เพียงใบเดียวพาเจ้าเข้าไปในความเงียบงันนั้น เวทีในยามที่ไม่มีใครมองอยู่—จึงเป็นจุดเริ่มต้นของช่วงเวลาที่ได้พบตัวตนที่ซื่อตรงที่สุดของเจ้า"},"ICON-1402":{"nm":"สมุดสไตล์","de":"วันนี้จะแต่งตัวด้วยหัวใจแบบไหนดี แม้เสื้อเชิ้ตเพียงตัวเดียวก็มีอารมณ์ที่เหมาะกับมัน สมุดเล่มนี้ค่อยๆ บอกกล่าวอย่างเงียบๆ ยิ่งพลิกหน้าไปเท่าไร สายตาอันประณีตเล็กๆ ก็ยิ่งสั่งสมอยู่ที่ปลายนิ้วที่เคยลังเลอยู่หน้ากระจก"},"ICON-1403":{"nm":"สเปรย์จัดแต่งทรงผม","de":"ฉีดพรวดเดียว แม้แต่สายลมก็ไม่อาจทำให้ยุ่งเหยิงได้ตามใจชอบ ความทะเยอทะยานเล็กๆ ที่อยากตรึงไม่กี่นาทีบนเวทีให้สมบูรณ์แบบไร้ที่ติ ช่วงเวลาที่สมบูรณ์แบบมักสำเร็จลงได้ด้วยความดื้อรั้นเล็กๆ น้อยๆ เช่นนี้เสมอ"},"ICON-1404":{"nm":"พาเลตแต่งหน้า","de":"สีทั้งสิบสองช่องคือสิบสองอารมณ์ วันนี้จะร้องเพลงด้วยสีหน้าแบบไหนดี ปลายนิ้วเลือกก่อน แล้วหัวใจจึงตามมา ทุกช่องที่ค่อยๆ ว่างลง แฝงไว้ด้วยวันเวลาที่ทิ้งไว้บนเวทีอย่างเงียบงัน"},"ICON-1405":{"nm":"เข็มกลัดชุด","de":"ในช่วงเวลาที่งดงามที่สุด กลับมีเข็มกลัดเล็กๆ ตรึงผ้าอยู่ในจุดที่ไม่มีใครมองเห็น เพื่อไม่ให้หลุดลื่น เพื่อไม่ให้ยับยู่ยี่ ความเปล่งประกายบนเวทีเสมอยืนอยู่บนความหนักแน่นมั่นคงของใครบางคน"},"ICON-1406":{"nm":"ป้ายชื่อ","de":"วินาทีที่ชื่อมาเติมเต็มกระดานที่เคยว่างเปล่า คำมั่นสัญญาที่เคยพร่ามัวก็ชัดเจนขึ้นมา ใครจะได้ยืนอยู่ตรงจุดนี้—ตัวหนังสือเพียงหนึ่งบรรทัดเป็นผู้ตัดสิน ชื่อคือความมุ่งมั่นที่สั้นและมั่นคงที่สุด"},"ICON-1407":{"nm":"การ์ดแฟนเซอร์วิส","de":"ผู้รับมีเพียงคนเดียว แต่สำหรับคนคนนั้นคือโลกทั้งใบ การกดความขอบคุณของค่ำคืนหลายคืนลงในคำทักทายสั้นๆ เพียงบรรทัดเดียว หัวใจล้นทะลักออกมาได้ขนาดนี้ แม้บนกระดาษเพียงขนาดเท่าฝ่ามือ"},"ICON-1408":{"nm":"กระดาษฝึกลายเซ็น","de":"ตอนแรกแม้แต่ชื่อของตัวเองก็ยังดูแปลกตาเวลาขีดเขียน ผ่านรุ่งอรุณนับร้อยครั้งของการขีดและนับพันครั้งของการขัดเกลา จนมือจดจำลีลานั้นได้ก่อนหัวใจ แล้วในที่สุดชื่อหนึ่งชื่อก็กลายเป็นลายเซ็น"},"ICON-1409":{"nm":"กระดาษคำถามสัมภาษณ์","de":"\"คำถามนี้จะตอบว่าอย่างไรดี\" ปลายนิ้วที่กำกระดาษไว้สั่นเล็กน้อย ไม่ใช่การท่องจำคำตอบ แต่เป็นเวลาที่เรียงความจริงใจไว้เป็นลำดับ—เพราะการสัมภาษณ์ก็เหมือนการสารภาพรัก ท้ายที่สุดแล้วคือคำถามถึงลำดับของหัวใจ"},"ICON-1410":{"nm":"สมุดคำศัพท์ภาษาต่างประเทศ","de":"มุมที่สึกมากที่สุดบอกได้ว่าคำไหนถูกจ้องมองนานที่สุด เวลาที่ใช้ให้เสียงแปลกหูสักเสียงติดปาก เท่านั้น ระยะห่างจากโลกที่ไม่เคยไปถึงก็ค่อยๆ ใกล้เข้ามาทีละคืบ"},"ICON-1411":{"nm":"การ์ดฝึกออกเสียง","de":"เสียง 'ร' ที่รัว เสียง 'ส' ที่รั่วไหล มีรุ่งอรุณที่ใช้พลิกการ์ดทีละใบเพื่อฝึกลิ้นให้เชื่อง ยิ่งคำพูดชัดเจนขึ้นเท่าไร ใบหน้าของใครบางคนที่อยากเอื้อมถึงด้วยคำพูดเหล่านั้นก็ยิ่งชัดเจนขึ้นเท่านั้น"},"ICON-1412":{"nm":"เช็กลิสต์ไลฟ์","de":"ไมค์เปิดแล้ว ตรวจหูฟังอินเอียร์ ตรวจสอบตำแหน่งการเคลื่อนไหว ทุกครั้งที่ช่องสี่เหลี่ยมถูกเติมเต็มทีละช่อง ความกังวลในใจก็ค่อยๆ ว่างลงทีละช่องเช่นกัน ก่อนขึ้นเวที ความละเอียดรอบคอบคือความกล้าหาญที่เงียบที่สุด"},"ICON-1413":{"nm":"แผ่นแปะบำรุงร่างกาย","de":"ทันทีที่แปะลงไป มีจุดหนึ่งที่อุ่นขึ้นแผ่ซ่านทั่ว ไหล่ที่ใช้งานหนัก น่องที่แข็งเกร็ง—การปลอบโยนขนาดเท่าฝ่ามือที่ตอบรับสัญญาณเล็กๆ จากร่างกายอย่างเงียบๆ การพักผ่อนให้ดีก็เป็นส่วนหนึ่งของการฝึกซ้อมเช่นกัน"},"ICON-1414":{"nm":"เจลประคบเย็น","de":"วางลงเบาๆ บนข้อเท้าที่บวม ระหว่างที่ความเย็นค่อยๆ ซึมเข้าไปนั่นเอง ถึงได้รู้ว่าวันนี้วิ่งมามากแค่ไหน การฟื้นตัวหลังเวทีมักมาถึงอย่างเงียบเชียบเช่นนี้เสมอ"},"ICON-1415":{"nm":"กระเป๋ายาปฐมพยาบาล","de":"พลาสเตอร์ ยาแก้ปวด กระจกมือ ถุงเล็กๆ ที่บรรจุสิ่งของธรรมดาๆ เหล่านี้ กลับกลายเป็นสิ่งที่อุ่นใจที่สุดในบางช่วงเวลา ความเอื้ออาทรที่เตรียมไว้ล่วงหน้าเปล่งประกายสุกใสที่สุดเมื่อเผชิญวิกฤตที่ไม่คาดคิด"},"ICON-1416":{"nm":"คิวการ์ด","de":"มีใครบางคนยกมันขึ้นแอบๆ จากด้านหลังกล้อง ประโยคที่เกือบลืมถูกเขียนไว้ตรงนั้นอย่างเรียบร้อย เบื้องหลังรายการที่ดำเนินไปอย่างราบรื่นไม่สะดุด มักมีมือแบบนี้อยู่เสมอ มือที่ไม่เคยปรากฏในจอ"},"ICON-1417":{"nm":"ซองภารกิจ","de":"วินาทีก่อนฉีกซองออกคือช่วงที่ใจเต้นแรงที่สุด ไม่ว่าข้างในจะมีอะไร ช่วงเวลาสั้นๆ ที่ตื่นเต้นเพราะยังไม่รู้นั้นแหละ เสน่ห์ของรายการวาไรตี้มีชีวิตอยู่เต็มเปี่ยมในวินาทีที่ถูกปิดผนึกไว้นั้นเอง"},"ICON-1418":{"nm":"ป้ายชื่อติดหน้าอก","de":"ชื่อเล็กๆ ที่ติดอยู่บริเวณหน้าอกทำหน้าที่แทนคำทักทายแรก ท่ามกลางผู้คนที่ยังไม่รู้จักกัน ป้ายชื่อเพียงอันเดียวก็แง้มความอึดอัดให้ละลายไป ตั้งแต่วินาทีที่เอ่ยชื่อกันนั่นแหละ ความสัมพันธ์จึงเริ่มต้นขึ้น"},"ICON-1419":{"nm":"สติกเกอร์บทลงโทษ","de":"สติกเกอร์แผ่นเดียวที่แปะเบาๆ บนหน้าผากคนแพ้ทำให้เสียงหัวเราะระเบิดลั่น เป็นมิตรเกินกว่าจะเรียกว่าบทลงโทษ จนแม้แต่การแพ้ก็ยังกลายเป็นความทรงจำที่เก็บไว้เนิ่นนาน เป็นเครื่องหมายเล็กๆ ที่อ่อนโยน สร้างขึ้นเพื่อให้ทุกคนได้หัวเราะไปด้วยกัน"},"ICON-1420":{"nm":"การ์ดสุ่มบทลงโทษ","de":"ก่อนจับได้ไม่มีใครรู้ อาจเป็นควงงวงช้างสิบรอบ หรืออาจเป็นทำอ้อนหนึ่งครั้ง วินาทีที่ฝากชะตากรรมทั้งหมดไว้กับกระดาษเพียงแผ่นเดียว สิ่งแรกที่หลุดออกมาก่อนใครกลับเป็นเสียงหัวเราะ"},"ICON-1421":{"nm":"การ์ดคำใบ้","de":"บางอย่างที่เหมือนมือที่ยื่นมาเงียบๆ ให้จุดที่ติดขัด ไม่ได้ให้คำตอบทั้งหมด แต่ชี้ทางให้ คำใบ้ที่ดีไม่ใช่คำตอบที่ถูกต้อง แต่เป็นการมอบความกล้าที่จะลองคิดอีกครั้งอย่างเงียบๆ"},"ICON-1422":{"nm":"การ์ดโอกาส","de":"โอกาสเพียงหนึ่งเดียวที่จะพลิกกระดานที่เอียงไปให้กลับมาในพริบตา จะใช้การ์ดใบนี้เมื่อไรเป็นตัวชี้ขาดชัยชนะ โชคที่เก็บหอมรอมริบไว้อย่างพิถีพิถัน จะแสดงคุณค่าที่แท้จริงก็ในช่วงเวลาที่สำคัญที่สุดเท่านั้น"},"ICON-1423":{"nm":"การ์ดขอเวลานอก","de":"การ์ดใบนี้บอกแทนว่าหยุดพักสักครู่ก็ไม่เป็นไร การยกมือขึ้นอย่างมั่นใจเมื่อต้องการช่วงเวลาผ่อนลมหายใจ—การหยุดพักก็เป็นกลยุทธ์ที่ชอบธรรม และการพักผ่อนให้ดีก็เป็นความสามารถอีกด้านหนึ่งเช่นกัน"},"ICON-1424":{"nm":"ปุ่มเสียงหัวเราะ","de":"กด แล้ววินาทีนั้นเสียงหัวเราะกิ๊กก๊ากสดใสก็หลั่งไหลออกมาเต็มที่ ฉากที่ตลกจริงๆ มักต้องมีเสียงประกอบแบบนี้แอบช่วยเสริม ความอบอุ่นในบรรยากาศถูกทำให้ร้อนขึ้นได้จากเรื่องซนเล็กๆ แบบนี้เอง"},"ICON-1425":{"nm":"รีโมตเสียงประกอบ","de":"ปุ่มหนึ่งคือเสียงปรบมือ อีกปุ่มคือเสียงโห่ พ่อมดผู้ปั้นแต่งบรรยากาศด้วยปลายนิ้วเพียงอย่างเดียวนั่งอยู่เงียบๆ ในห้องควบคุม การกำกับที่ไม่เคยปรากฏในจอคือสิ่งที่ทำให้ฉากนั้นมีลมหายใจ"},"ICON-1426":{"nm":"กระดานสเลท","de":"แชะ พร้อมเสียงกระฉับกระเฉง ฉากหนึ่งก็เริ่มต้นขึ้น ระหว่าง NG นับสิบครั้งกับ OK เพียงหนึ่งครั้ง กระดานสีดำแผ่นนี้นับทุกวินาทีไว้อย่างเรียบร้อย มันคือจังหวะแรกที่บันทึกก้าวเข้าไป"},"ICON-1427":{"nm":"เทปมาร์คจุดถ่ายทำ","de":"วินาทีที่ปลายเท้าแตะเส้นนั้นเบาๆ ไฟก็ค่อยๆ หรี่ลงมาเหมือนรอคอยอยู่แล้ว ตำแหน่งเดียวที่ท่องจำจนคุ้นชิน—เวทีจึงสมบูรณ์ได้ในที่สุดด้วยแถบสีเล็กๆ ที่ขีดไว้บนพื้น"},"ICON-1428":{"nm":"ฟิลเตอร์ไฟ","de":"ใบหน้าเดียวกัน แต่สีของแสงเปลี่ยนไปทั้งหมด ฟิลเตอร์สีฟ้ามีรุ่งอรุณสถิตอยู่ ฟิลเตอร์สีแดงมีแสงอาทิตย์อัสดงแฝงอยู่ บรรยากาศไม่เคยอยู่ไกลเลย มันพับซ่อนอยู่เงียบๆ ในกระดาษสีบางๆ เพียงแผ่นเดียว"},"ICON-1429":{"nm":"แบตเตอรี่กล้อง","de":"พอไฟสีแดงเริ่มกะพริบ ใจก็เริ่มร้อนรนก่อนเป็นอันดับแรก เพราะฉากที่ดีที่สุดมักมาถึงตอนแบตเหลือ 1 เปอร์เซ็นต์เสมอ แบตสำรองหนึ่งก้อนในกระเป๋าจึงกลายเป็นความอุ่นใจที่ได้ผ่อนลมหายใจ"},"ICON-1430":{"nm":"การ์ดความจำ","de":"เสียงหัวเราะและหยาดเหงื่อของทั้งวันอัดแน่นอยู่ในชิปเล็กเท่าปลายเล็บ เล็กจนหายง่าย และก็ล้ำค่าเกินกว่าจะประเมินได้เช่นกัน น้ำหนักของความทรงจำที่บรรจุอยู่นั้นไม่มีทางวัดได้ด้วยขนาด"},"ICON-1431":{"nm":"ฟิล์มโพลารอยด์","de":"แชะ แล้วรอคอยอย่างเงียบๆ ไม่กี่วินาทีที่ใบหน้าค่อยๆ ปรากฏขึ้นบนพื้นผิวที่เคยขาวโพลนนั้นชวนให้ใจเต้นอย่างประหลาด แม้แต่รูปถ่ายทันใจในมือก็ยังต้องมีความอดทนสักหนึ่งช้อนเสมอ"},"ICON-1432":{"nm":"ฟิล์มโฟโต้การ์ด","de":"ภาพหน้าตาไหนจะถูกพิมพ์ลงบนแผ่นนี้ยังเป็นความลับจนถึงวินาทีก่อนพิมพ์ ใบหน้าที่จะกลายเป็นไบอัสของใครสักคนถือกำเนิดขึ้นที่นี่เอง กระดาษเล็กๆ แผ่นเดียวกลับบรรจุหัวใจอันยิ่งใหญ่ไว้ได้ขนาดนั้น"},"ICON-1433":{"nm":"ซองใส่โฟโต้การ์ด","de":"โฟโต้การ์ดไม่เคยถูกสัมผัสด้วยมือเปล่า เพียงมุมหนึ่งถูกกด รอยยิ้มของวันนั้นก็ยังปวดร้าวไปด้วย การห่อไบอัสไว้อย่างระมัดระวังในแผ่นใสเพียงแผ่นเดียว—การทะนุถนอมก็ต้องใช้ความพิถีพิถันมากขนาดนี้เช่นกัน"},"ICON-1434":{"nm":"ท็อปโหลดเดอร์","de":"สอดไว้ระหว่างแผ่นแข็งสองแผ่น แม้แต่กาลเวลาก็ไม่อาจทำให้ยับย่นได้ตามใจชอบ อย่าโค้งงอ อย่าพับ การปกป้องสิ่งล้ำค่าไว้เสมอต้องยืมความแข็งแกร่งมาห่มไว้อีกชั้นหนึ่ง"},"ICON-1435":{"nm":"แพ็กสติกเกอร์","de":"ลอกออกทีละแผ่นแปะไว้ที่มุมไดอารี่ หลังโน้ตบุ๊ก ภาพเล็กๆ เพียงภาพเดียวก็ทำให้วันที่ไร้สีสันกลายเป็นสีสันสดใส ความปรารถนาที่อยากตกแต่งสิ่งรอบตัวไม่มีข้อจำกัดเรื่องอายุ"},"ICON-1436":{"nm":"ปากกามาร์กเกอร์","de":"เสียงหมึกเสียดสีกระดาษเบาๆ ทำให้แถวคนยาวขึ้นเรื่อยๆ บนอัลบั้มที่ยื่นให้ด้วยมือสั่นระริก การพบกันเพียงไม่กี่วินาทีนั้นคงอยู่ไปอีกนาน หัวใจข้ามผ่านไปตามปลายปากกา"},"ICON-1437":{"nm":"อัลบั้มลายเซ็น","de":"เปิดปกออก ลายเซ็นเส้นโค้งที่คุ้นตาทักทายก่อนสิ่งอื่นใด ความสัมพันธ์ที่เกิดจากดนตรีใกล้ชิดขึ้นอีกคืบบนกระดาษ การเก็บรักษาไว้คือการหยุดช่วงเวลานั้นไว้อย่างเงียบๆ"},"ICON-1438":{"nm":"แบตเตอรี่ไม้ไฟ","de":"\"ติดที เถอะนะ\" มือที่กำลังเปลี่ยนถ่านก่อนเข้างานยุ่งไปหมด เพื่อไม่ให้แสงของฉันดวงเดียวดับลงท่ามกลางแสงนับหมื่นดวง—ถ่านก้อนเล็กๆ จุดค่ำคืนอันยิ่งใหญ่นั้นให้สว่างไสว"},"ICON-1439":{"nm":"กระเป๋าใส่ไม้ไฟ","de":"เก็บอย่างดีไม่ให้มีรอยขีดข่วนแม้แต่นิดเดียว เพื่อเสียงเชียร์ของคืนถัดไปด้วย แม้จุดที่เคยร้อนแรงจะเย็นลงหมดแล้ว ก็ยังใส่ใจนำกลับบ้านอย่างทะนุถนอม เครื่องมือเชียร์ก็มีที่ทางของมัน และมีหัวใจที่คอยดูแลที่ทางนั้น"},"ICON-1440":{"nm":"ป้ายสโลแกน","de":"ประโยคที่เขียนบนผ้ายาวคลี่กางข้ามที่นั่งผู้ชม วินาทีที่กำลังใจซึ่งพูดออกมาเป็นคำไม่ได้เปิดออกอย่างเต็มที่ หัวใจของคนคนเดียวก็กลายเป็นเสียงตะโกนของทุกคน ผืนผ้านั้นเองกลายเป็นเสียง"},"ICON-1441":{"nm":"มินิแบนเนอร์","de":"กำลังใจเล็กๆ ที่พอดีในฝ่ามือ ป้ายผ้าที่แขวนอยู่ไกลๆ เป็นของทุกคน แต่อันนี้โบกสะบัดอยู่แค่ที่ขอบโต๊ะของเจ้าเท่านั้น มันพิสูจน์อย่างเงียบๆ ผ่านการโบกไหวเบาๆ ว่าขนาดเล็กไม่ได้แปลว่าหัวใจจะเล็กตามไปด้วย"},"ICON-1442":{"nm":"จดหมายจากแฟนคลับ","de":"เขียนชื่อผู้รับใหม่สามครั้งและลบประโยคแรกไปเจ็ดครั้ง ปลายนิ้วที่สั่นก่อนปิดผนึกซองก็เพราะหัวใจมันซื่อตรงเกินไป ความจริงใจที่หนักกว่าแสตมป์เพียงดวงเดียวพับซ่อนอยู่ข้างใน"},"ICON-1443":{"nm":"กระดาษห่อของขวัญ","de":"กระดาษห่อรู้ดีกว่าใครว่าหนึ่งวินาทีก่อนแกะออกคือช่วงที่ตื่นเต้นที่สุด แม้จะรู้ว่าถูกลิขิตให้ถูกฉีกในไม่ช้า มันก็ยังห่อหุ้มตัวเองด้วยลวดลายที่ประณีตที่สุด คล้ายกับหัวใจของผู้ที่มอบให้"},"ICON-1444":{"nm":"ริบบิ้น","de":"ผูกแน่นไปก็อึดอัด หลวมไปก็หลุด การหาจุดตรงกลางพอดีนั่นแหละคือความพิถีพิถัน รูปทรงของหัวใจถูกบรรจุไว้ในปมเดียวที่ปลายนิ้วเลือกสรร บรรทัดสุดท้ายของของขวัญ ริบบิ้นเป็นผู้เขียนแทนเสมอ"},"ICON-1445":{"nm":"การ์ดขอบคุณ","de":"คำขอบคุณที่พูดออกมาลอยหายไปกับสายลม แต่เมื่อเขียนด้วยลายมือกลับคงอยู่ยาวนาน เป็นการส่งความอ่อนโยนที่ได้รับกลับคืนไป พร้อมเติมเข้าไปอีกนิดหน่อย ระหว่างที่กดปากกาเขียนทีละตัวอักษร หัวใจก็ลึกซึ้งขึ้นเป็นสองเท่า"},"ICON-1446":{"nm":"คูปองข้าวกล่อง","de":"กระดาษเพียงแผ่นเดียวนี้คลายความกังวลเรื่องมื้อกลางวันให้หายไป เพราะมีมื้ออาหารที่ข้าวสวยหุงใหม่ควันโขมง กับข้าวเต็มทุกช่องรอสัญญาอยู่ เครื่องรางเล็กๆ ที่ปกป้องบ่ายที่หิวโหยไว้อย่างมั่นคง"},"ICON-1447":{"nm":"คูปองขนม","de":"เกิดมาเพื่อหยิบออกมาตอนบ่ายสามโมง เมื่อความหิวเล็กๆ ส่งสัญญาณแผ่วเบา คูปองที่รู้ว่าของหวานชิ้นเล็กๆ ชิ้นเดียวยกอารมณ์ให้ดีขึ้นได้ครึ่งคืบ แม้ไม่ใช่รางวัลใหญ่โต แต่ก็มาถึงอย่างแผ่วเบาในวินาทีที่ต้องการพอดี"},"ICON-1448":{"nm":"คูปองคาเฟ่","de":"เครื่องดื่มอุ่นๆ หนึ่งแก้ว กับที่นั่งริมหน้าต่างหนึ่งที่ นั่นคือทั้งหมดที่คูปองใบนี้สัญญาไว้ ดูเหมือนไม่มีอะไร แต่สำหรับใครบางคนมันคือรางวัลเล็กๆ ที่ทำให้ผ่านวันมาได้ บัตรเชิญอันอ่อนโยนที่กลิ่นหอมมาถึงก่อนใคร"},"ICON-1449":{"nm":"บัตรทำความสะอาดหอพัก","de":"เปิดหน้าต่างกว้าง สะบัดผ้าห่ม วันที่ฝุ่นแม้แต่เม็ดเดียวก็หนีหายไป ใครจะรู้ว่าการไม่ต้องลงมือทำเองจะหรูหราได้ขนาดนี้ เมื่อห้องเปล่งประกาย หัวใจก็ค่อยๆ เป็นระเบียบไปด้วย"},"ICON-1450":{"nm":"ชุดเครื่องมือซ่อม","de":"ไขควง เทป และชิ้นส่วนไม่รู้ชื่อสักสองสามชิ้น รวมกันแล้วดูเหมือนจะไม่มีอะไรซ่อมไม่ได้ แต่พอเปิดออกมาก็มักขาดไปชิ้นหนึ่งเสมอ ถึงอย่างนั้น เมื่อถือไว้ในมือก็รู้สึกอุ่นใจขึ้นมาอย่างประหลาด กล่องแห่งความมั่นใจ"},"ICON-1451":{"nm":"ตั๋วนำโชค","de":"ตั๋วเปล่าที่ไม่มีทั้งที่นั่งและหมายเลข หัวใจสำคัญคือมันไม่ได้เขียนไว้ว่าวันนี้เรื่องดีอะไรจะมาถึง เพราะการเติมเต็มช่องว่างนั้นเป็นหน้าที่ของคนที่พกมันติดกระเป๋าไปด้วย"},"ICON-1452":{"nm":"ลูกเต๋า","de":"เพื่อนที่รู้จักคำว่าความเป็นธรรมดีที่สุด ไม่เข้าข้างใคร รักทั้งหกด้านเท่ากันหมด เพียงชั่วขณะที่มันหลุดจากฝ่ามือกลิ้งไปกลิ้งมา แม้แต่ฝีมือและเส้นสายก็ยังต้องยอมมอบที่นั่งให้โชคชะตาชั่วครู่"},"ICON-1453":{"nm":"ตั๋วเดินทาง","de":"คำสัญญาว่าจากที่นี่ไปที่นั่น เพียงก้าวเดียวก็เพียงพอ กระดาษวิเศษที่พับระยะทางไกลให้เล็กลงจนใส่กระเป๋าได้ วันที่ลังเลจะออกเดินทาง ไม่มีตัวกันข้ออ้างใดจะดีไปกว่านี้อีกแล้ว"},"ICON-1454":{"nm":"บัตรลองใหม่","de":"แทนที่จะยื่นมือให้คนที่ล้มลง มันกลับผลักหลังเบาๆ อย่างเงียบๆ ให้ลองอีกครั้ง บอกอย่างแผ่วเบาที่สุดว่าความล้มเหลวไม่ใช่จุดจบ แต่เป็นเพียงจุดจุลภาคชั่วคราว ความกล้าที่จะลองอีกครั้งเติบโตขึ้นจากตรงนี้เอง"},"ICON-1455":{"nm":"บัตรเร่งสำเร็จ","de":"กุญแจโกงที่แสนอ่อนโยนซึ่งข้ามการรอคอยไปเล็กน้อย จะมีใครกล่าวโทษหัวใจที่ทนรออีกแค่ 3 นาทีไม่ไหวได้ ที่นี่มีความสุขที่แอบล้ำกฎอยู่นิดหน่อย เหมือนใช้นิ้วดันเม็ดทรายในนาฬิกาทรายให้ไหลเร็วขึ้น"},"ICON-1456":{"nm":"บูสเตอร์เพิ่มผลผลิต","de":"มือเดิม เวลาเดิม แต่ผลงานกลับเพิ่มขึ้นเป็นสองเท่า เหมือนจะบอกว่าอย่าถามความลับ มันหมุนวี้ดอย่างสนุกสนานอยู่บนโต๊ะทำงาน อุปกรณ์เล็กๆ ที่แอบติดปีกให้มือทั้งสองข้างที่ขยันเคลื่อนไหวอยู่เสมอ"},"ICON-1457":{"nm":"ลูกอมแห่งความสนิทสนม","de":"แม้แต่ความอึดอัดที่คลี่คลายด้วยคำพูดได้ยาก ก็ละลายหายไปต่อหน้าของหวาน ความสัมพันธ์ที่ใกล้ชิดขึ้นอีกคืบกว่าเมื่อวานผ่านลูกอมเม็ดเดียวที่แกะกินด้วยกัน ข้อค้นพบเล็กๆ น่ารักที่ว่าความหวานคือความเร็วของการสนิทกัน"},"ICON-1458":{"nm":"เยลลี่ฟื้นอารมณ์","de":"วันที่เศร้าใจ ของเย็นๆ นุ่มๆ ได้ผลทันที กัดเข้าไปคำเดียว สีหน้าที่มืดหม่นก็ค่อยๆ คลี่คลาย การเยียวยาหัวใจเป็นเรื่องล้ำค่าโดยธรรมชาติ เกรด R จึงไม่ได้ติดมาโดยไร้เหตุผล"},"ICON-1459":{"nm":"ผงกากเพชร","de":"โรยเบาๆ ลงบนสิ่งธรรมดาแล้วมันก็กลายเป็นพิเศษขึ้นมาทันที แท้จริงแล้วมันก็แค่ผงกากเพชร แต่วินาทีที่โปรยลงไป โลกกลับดูตื่นเต้นขึ้นอีกนิด ช่างน่าประหลาด เหมือนเครื่องปรุงแห่งความสุขที่โรยลงบนชีวิตประจำวัน"},"ICON-1460":{"nm":"เทปมาร์คเวที","de":"ยืนบนเวที ไฟนับไม่ถ้วนต่างพร้อมใจกันค้นหาเจ้าในพริบตา เครื่องหมาย X เล็กๆ บนพื้นทำเครื่องหมายจุดนั้นไว้อย่างเงียบงัน สิ่งที่แม่นยำที่สุดในที่ที่มองไม่เห็น สุดท้ายแล้วคือสิ่งที่ค้ำจุนเวทีที่ยิ่งใหญ่ที่สุด"},"ICON-1461":{"nm":"เคเบิลไทร์","de":"วีรบุรุษตัวเล็กที่จัดสายไฟที่พันกันยุ่งให้เรียบร้อยได้ในพริบตา จุดด้อยที่ก็เป็นเสน่ห์คือครั้งเดียวที่รัดแน่นแล้วจะย้อนกลับไม่ได้ สิ่งจำเป็นที่คนจริงจังเรื่องความเป็นระเบียบเก็บติดตัวไว้อย่างเงียบๆ"},"ICON-1462":{"nm":"สายเคเบิลสำรอง","de":"สิ่งของที่ไม่มีตัวตนเวลามีอยู่ แต่กลับเป็นที่ต้องการอย่างยิ่งเมื่อไม่มี หลับใหลอยู่ก้นกระเป๋าหลังเวที แล้วตื่นขึ้นวาบเดียวในวินาทีชี้ขาด มันพิสูจน์คำว่าความพร้อมด้วยตัวมันเอง"},"ICON-1463":{"nm":"ตารางตรวจซ้อม","de":"กระดาษที่อัดแน่นไปด้วยตำแหน่งการเคลื่อนไหว คิว ไปจนถึงการเปลี่ยนชุดในทุกช่อง หากช่องตรวจสอบตรงนี้ขาดไปแม้เพียงช่องเดียว หัวใจของใครสักคนก็จะร่วงวูบ เวทีที่สมบูรณ์แบบจะเปิดม่านได้ก็ต่อเมื่อตารางนี้ถูกเติมเต็มครบถ้วนแล้วเท่านั้น"},"ICON-1464":{"nm":"ป้ายฉากถ่ายทำ","de":"ตรงนี้คือคาเฟ่ ตรงนั้นคือตรอกซอย ตามลูกศรไปก็เข้าสู่โลกที่แตกต่างไปโดยสิ้นเชิง มันคือคำโกหกที่วาดไว้บนแผ่นไม้อัด แต่หน้ากล้องกลับกลายเป็นเรื่องจริง ผู้นำทางที่ซื่อสัตย์ซึ่งอุทิศทั้งชีวิตให้กับการชี้ทิศทาง"},"ICON-1465":{"nm":"ถ้วยรางวัลจิ๋ว","de":"ชิ้นสีทองที่พอรับมาถือแล้วรู้สึกเหมือนตัวสูงขึ้นอีกคืบอย่างประหลาด มันเปล่งประกายอยู่บนโต๊ะ บอกว่าไม่เป็นอันดับหนึ่งก็ไม่เป็นไรจริงๆ และรู้ดีว่าวันนี้เจ้าพยายามมากแค่ไหน คือการปลอบโยนอันยิ่งใหญ่ที่รางวัลเล็กๆ มอบให้"},"ICON-1466":{"nm":"กระเป๋าเป้","de":"วินาทีที่สะพายขึ้นบ่า รู้สึกเหมือนจะไปที่ไหนก็ได้ แม้ข้างในจะมีของไม่มากนัก แต่ความเป็นไปได้นั้นเต็มเปี่ยม การผจญภัยเริ่มต้นเสมอจากการรัดสายสะพายบ่านี้ให้แน่น"},"ICON-1467":{"nm":"เข็มทิศ","de":"แม้หลงทางก็ไม่ตื่นตระหนก เพราะปลายเข็มชี้ไปทางทิศเหนือเสมอ ท่าทีที่สั่นไหวอยู่นานก่อนจะหาที่ทางของตัวเองเจอในที่สุดนั้น ช่างเหมือนหัวใจของคนเหลือเกิน มันบอกด้วยปลายเข็มที่สั่นไหวว่าหลงทางบ้างก็ไม่เป็นไร"},"ICON-1468":{"nm":"สมุดโน้ต","de":"หน้าแรกว่างเปล่าเสมอ มีเพียงผู้ที่ถือปากกาเท่านั้นที่รู้ว่าจะเขียนอะไร ฉันเพียงแต่รอคอย ให้ความคิดของวันนี้กลายเป็นตัวหนังสือแล้วลงมาสถิตบนตัวฉันอย่างเงียบๆ เกรด R คือน้ำหนักของความเป็นไปได้ที่จะถูกเติมเต็มในไม่ช้า"},"ICON-1469":{"nm":"ดินสอ","de":"การที่ผิดพลาดได้ก็ไม่เป็นไรคือด้านที่อ่อนโยนที่สุดของเครื่องมือชิ้นนี้ ตราบใดที่ยางลบเพื่อนคู่ใจอยู่เคียงข้าง ก็เริ่มต้นใหม่ได้กี่ครั้งก็ได้ ยิ่งเหลาก็ยิ่งสั้นลง แต่ความสั้นนั้นคือหลักฐานว่าถูกรักมานานแค่ไหน"},"ICON-1470":{"nm":"ฟิล์มถ่ายภาพ","de":"วินาทีที่แสงลอดผ่าน สีของวันนั้นก็ถูกตรึงไว้ครบถ้วน เมื่อภาพหนึ่งภาพผ่านไปแล้วไม่มีวันย้อนกลับได้อีก คือทั้งความตึงเครียดและเสน่ห์ของมัน ทางเลือกของผู้คนที่จงใจจดจำให้ช้าลงอีกจังหวะหนึ่งในยุคที่รวดเร็ว"},"ICON-1471":{"nm":"กล้องโพลารอยด์","de":"แชะ แล้วรอคอยสักครู่ ถือไว้ในมือแล้วสะบัดเบาๆ ช่วงเวลาที่เลือนรางก็ค่อยๆ ชัดเจนขึ้น เครื่องจักรที่ดูเวทมนตร์เล็กน้อย ที่จับภาพจุดนี้ไว้ครบถ้วนบนกระดาษเพียงแผ่นเดียว"},"ICON-1472":{"nm":"รูปถ่ายเก่า","de":"ยิ่งสีซีดจางเท่าไร ก็ยิ่งหมายความว่าเวลาผ่านไปนานเท่านั้น ทุกมุมที่สึกกร่อนคือรอยที่สัมผัสของใครบางคนเคยแวะเวียนมาพัก บางทีที่รูปถ่ายเก่าแก่ที่สุดกลับเก็บความทรงจำที่ชัดเจนที่สุด อาจเป็นเพราะสัมผัสเหล่านั้นนั่นเอง"},"ICON-1473":{"nm":"สมุดสะสม","de":"เศษเสี้ยวที่เสียดายเกินจะทิ้งค่อยๆ รวมกันจนกลายเป็นเล่มหนึ่ง ตั๋วหนังที่จางสี กลีบดอกไม้แห้ง บันทึกสั้นๆ หนึ่งแผ่น ในสายตาคนอื่นอาจเป็นเพียงของกระจุกกระจิก แต่สำหรับผู้ที่เปิดมันออก ทั้งช่วงเวลาหนึ่งกลับฟื้นคืนชีพขึ้นมาทั้งหมด"},"ICON-1474":{"nm":"บันทึกการเดินเรือ","de":"สายลมและคลื่นของวันนี้ พร้อมหัวใจหนึ่งบรรทัด การจดบันทึกอย่างสม่ำเสมอแม้ในวันที่ไม่มีอะไรเกิดขึ้นคือกฎของการเดินเรือ หลักฐานว่าเดินทางมาถึงอย่างปลอดภัยมักถูกจดไว้อยู่ที่ไหนสักแห่งในบันทึกหนาเล่มนี้เสมอ"},"ICON-1475":{"nm":"เศษแผนที่","de":"เป็นเพียงมุมหนึ่งของทั้งหมด แต่ถ้าไม่มีมันก็ไม่มีทางหาทางออกได้ในที่สุด ความสุขในวินาทีที่ขอบที่ฉีกขาดสอดเข้ากับเศษอีกชิ้นได้พอดีเป๊ะ เกรด R มีตัวตนเหมือนชิ้นส่วนสุดท้ายของจิ๊กซอว์"},"ICON-1476":{"nm":"จดหมายในขวด","de":"ไม่รู้ว่าใครจะได้อ่าน มันฝากตัวเองไว้กับคลื่นอย่างเงียบๆ ไม่คาดหวังคำตอบกลับ เพียงหวังว่าหัวใจนี้จะไปถึงที่ไหนสักแห่ง เป็นวิธีส่งจดหมายที่ช้าที่สุดแต่โรแมนติกที่สุด"},"ICON-1477":{"nm":"ลูกเต๋า","de":"หกด้านยิ้มกลมๆ เหมือนจะพูดว่าเจ้าอีกแล้วเหรอ รูปทรงเดียวกัน แต่ให้คำตอบต่างกันทุกครั้งที่กลิ้งไป นี่คือความเอาแน่เอานอนไม่ได้ที่ไม่เปลี่ยนแปลงของเพื่อนคนนี้ วินาทีที่หลุดจากมือ เจ้าฝากทางเลือกไว้กับโชคชะตาชั่วครู่"},"ICON-1478":{"nm":"กังหันลม","de":"ต้องมีลมพัดถึงจะมีชีวิตขึ้นมา ปล่อยไว้เฉยๆ มันก็เป็นแค่ปีกกระดาษ แต่พอมีใครสักคนเป่าลมให้ มันก็เริ่มหมุนอย่างสนุกสนาน การไม่อายที่จะรับความช่วยเหลือคือปัญญาของดอกไม้เล็กๆ ดอกนี้"},"ICON-1479":{"nm":"ตะกร้าปิกนิก","de":"เปิดฝาออก กลิ่นคิมบับทักทายก่อนสิ่งอื่นใด สนามหญ้าเขียวขจี เสื่อที่ปูไว้ และมือหลายคู่ที่แบ่งปันอาหารกัน วันที่ตะกร้าใบนี้เต็มแน่นมักเป็นวันที่ฟ้าใสเสมออย่างน่าประหลาดใจ"},"ICON-1480":{"nm":"แจกันดอกไม้","de":"เพียงปักดอกไม้ดอกเดียวก็เปลี่ยนบรรยากาศทั้งห้องได้ เวลาว่างเปล่า หน้าที่ของมันคือรอคอยอย่างเงียบๆ อุปกรณ์บนเวทีที่อ่อนน้อมที่สุดในห้อง ที่ลดทอนตัวตนของตัวเองลงเพื่อให้ดอกไม้เปล่งประกายยิ่งขึ้น"},"ICON-1481":{"nm":"กลีบดอกไม้","de":"เมื่อสายลมพัดพากลีบหนึ่งไป ฤดูใบไม้ผลิก็เบาลงเท่านั้น ต้นไม้เก่าแก่ในสวนทักทายเช่นเดิมทุกปีว่า—การร่วงหล่นก็เป็นส่วนหนึ่งของการเบ่งบานเช่นกัน การปลิวไสวไม่ใช่จุดจบ แต่เป็นจดหมายที่ส่งล่วงหน้าไปถึงฤดูใบไม้ผลิครั้งถัดไป"},"ICON-1482":{"nm":"กุหลาบ","de":"การชูหนามขึ้นก่อนคือคำมั่นว่าอย่าแตะต้องโดยไม่ระวัง ภายในนั้นซ่อนหัวใจสีแดงที่สุดเอาไว้ ใครบางคนวางดอกเดียวไว้แทบเท้าอย่างเงียบๆ แล้วจากไป เขียนหัวใจไว้ด้วยสีสันแทนชื่อ"},"ICON-1483":{"nm":"ลิลลี่","de":"ข้างเครื่องกระเบื้องขาวบริสุทธิ์ มักวางดอกไม้สีขาวดอกนี้ไว้เสมอ แม้กลิ่นหอมจะลอยไปไกล แต่ขอให้ท่วงท่าไม่แปรปรวน ในที่ที่เลือกความบริสุทธิ์แทนความหรูหรา ลิลลี่รักษาศักดิ์ศรีไว้หนึ่งช่องอย่างเงียบงัน"},"ICON-1484":{"nm":"ทิวลิป","de":"ยืนเรียงแถวก้มหน้าเล็กน้อย ดูเป็นระเบียบเรียบร้อยอย่างประหลาด ดอกไม้ที่ครองแถวหน้าของแปลงดอกไม้ฤดูใบไม้ผลิ ความซื่อตรงที่บานพร้อมกันและร่วงพร้อมกันนั้น ระบายสีฤดูกาลอันสั้นให้เข้มข้นที่สุด"},"ICON-1485":{"nm":"ไฮยาซินธ์","de":"บนก้านเดียวห้อยระฆังเล็กๆ ไว้อัดแน่น เขย่าแล้วไม่มีเสียง แต่กลิ่นหอมกลับกังวานแทนทั่วทั้งห้อง ณ จุดเริ่มต้นของฤดูใบไม้ผลิ ความหรูหราอันอ่อนโยนที่เปลี่ยนอากาศทั้งห้องด้วยแจกันเพียงใบเดียว"},"ICON-1486":{"nm":"ตัวอย่างกบสตัฟฟ์","de":"ร่างเล็กที่เวลาหยุดนิ่งอยู่ในกล่องแก้ว ป้ายเขียนไว้ว่า—'นาข้าวและอ่างเก็บน้ำ มีชีวิตชีวาที่สุดในวันหลังฝนตก' หลังจากหยุดนิ่งแล้วเท่านั้น แม้แต่อุณหภูมิของริมน้ำที่สิ่งมีชีวิตหนึ่งเคยอาศัยอยู่ก็ยังคงเหลือไว้เป็นบันทึก"},"ICON-1487":{"nm":"ตัวอย่างจิ้งจกสตัฟฟ์","de":"แม้กลายเป็นตัวอย่างสตัฟฟ์แล้ว ความเฉลียวฉลาดในการสลัดหางหนีก็ไม่อาจลบเลือนไปได้ แขกตัวน้อยที่ชื่นชอบกำแพงหินอาบแดด บันทึกข้างๆ เขียนทิศทางของมุมแดดที่มันชอบปีนไว้อย่างเรียบร้อย"},"ICON-1488":{"nm":"บันทึกตุ่น","de":"บันทึกของผู้ที่เดินทางใต้ดินถูกเขียนด้วยลายเนื้อของดิน ขุดที่ไหนและหยุดที่ไหน คือแผนที่ของเส้นทางที่มองไม่เห็น เวลาที่ใช้ชีวิตหันหลังให้แสงสว่างก็กลายเป็นบันทึกที่ขยันขันแข็งที่สุดสำหรับใครบางคน"},"ICON-1489":{"nm":"ตัวอย่างเปลือกหอย","de":"ลวดลายที่แข็งแกร่งซึ่งคลื่นขัดเกลาส่งมาให้นับพันครั้ง ชาวหาดเลนดูเพียงลายเปลือกก็รู้ว่ามาจากทะเลไหน รูปทรงของทะเลที่เคยมีชีวิตหายใจอยู่ครั้งหนึ่งถูกบรรจุไว้ครบถ้วนในตัวอย่างขนาดเท่าฝ่ามือ"},"ICON-1490":{"nm":"ตัวอย่างปะการัง","de":"ในทะเลลึก มันเติบโตได้เพียงหนึ่งคืบตลอดหลายร้อยปี แม้ดูเหมือนกิ่งไม้ แต่แท้จริงคือบ้านที่ชีวิตเล็กๆ นับไม่ถ้วนสร้างร่วมกัน ยิ่งช้าเท่าไรยิ่งคงอยู่นานเท่านั้น ปะการังพิสูจน์สิ่งนี้ด้วยความเงียบงัน"},"ICON-1491":{"nm":"เบาะแสไอด็อง","de":"เศษเสี้ยวหนึ่งของเรื่องราวที่กระจัดกระจายอยู่ที่ไหนสักแห่งบนเกาะ กระดาษเศษเล็กๆ แผ่นเดียวชี้ทางก้าวต่อไปอย่างเงียบๆ ผู้นำทางเก่าแก่กล่าวว่าการผจญภัยทุกครั้งท้ายที่สุดแล้วเริ่มต้นจากการเก็บรอยเล็กๆ น้อยๆ แบบนี้เอง"},"ICON-1492":{"nm":"ชิ้นส่วนซิกเนเจอร์","de":"เมื่อลวดลายที่กระจัดกระจายกลับมาอยู่ในตำแหน่งของมัน เครื่องหมายหนึ่งก็สมบูรณ์ในที่สุด ชิ้นส่วนที่สลักลายเฉพาะตัวของใครบางคนไว้ ซ่อนความหมายไว้จนกว่าจะประกอบเข้ากันได้ และในวินาทีที่ประกอบสำเร็จ มันจึงกลายเป็นชื่อในที่สุด"},"ICON-1493":{"nm":"เศษความทรงจำบนเวที","de":"แม้เพลงหนึ่งจบลง ความอบอุ่นที่หลงเหลือยังคงอยู่ท่ามกลางที่นั่งผู้ชม ดึงความอุ่นนั้นออกมาแล้วทำให้แข็งตัวก็กลายเป็นเศษชิ้นเล็กๆ แบบนี้ เศษเสี้ยวของเสียงปรบมือและเสียงโห่ร้องที่กระจัดกระจาย เมื่อรวบรวมมาอย่างเงียบๆ ค่ำคืนวันนั้นก็ฟื้นคืนชีพขึ้นมาทั้งหมด"},"ICON-1494":{"nm":"แสตมป์เดบิวต์","de":"วันที่ชื่อของตัวเองถูกเรียกเป็นครั้งแรก รอยหมึกที่ประทับลงบนหลังมือ แม้แต่ความใส่ใจที่ค่อยๆ เป่าให้แห้งเพื่อไม่ให้เลอะก็เป็นส่วนหนึ่งของเส้นสตาร์ท ตราประทับเล็กๆ เพียงอันเดียวทำให้บางวันไม่มีวันถูกลบเลือนไปตลอดกาล"},"ICON-1495":{"nm":"เหรียญท็อปไอดอล","de":"ความหนักที่ได้รับอนุญาตให้เฉพาะผู้ที่ก้าวขึ้นสู่ตำแหน่งสูงสุดเท่านั้น แต่เหรียญนี้หนักไม่ใช่เพราะโลหะ เป็นเพราะน้ำหนักของมือนับไม่ถ้วนที่เติมเต็มเวทีร่วมกันมารวมกันไว้ครบถ้วนในจุดเดียว"},"ICON-1496":{"nm":"กุญแจดอกเล็ก","de":"กุญแจดอกแรกของหอพักเป็นของห้องในสุดเสมอ สถานที่ที่เรียนรู้วิธีเปิดก่อนจะเรียนรู้วิธีล็อก วันที่จากไป ความอุ่นที่ฝ่ามือทิ้งไว้ยังคงอยู่บนโลหะเย็นเยียบนั้นอีกนาน"},"ICON-1497":{"nm":"กล่องสมบัติ","de":"จนกว่าจะเปิดออก ไม่มีใครรู้ว่าข้างในมีอะไร ความไม่รู้นั้นแหละคือสมบัติที่แท้จริงของกล่องสมบัติ ในวินาทีสั้นๆ ที่ยกฝาขึ้น ทุกคนต่างกลับไปสู่ความตื่นเต้นในวัยเด็กชั่วครู่"},"ICON-1498":{"nm":"พิมพ์เขียว","de":"บนเส้นที่ขีดไว้ทีละช่องๆ อาคารที่ยังไม่ถูกสร้างมีชีวิตอยู่ การคลี่แบบแปลนออกคือการเดินผ่านวันพรุ่งนี้ไปล่วงหน้าสักครั้ง เส้นหนึ่งเส้นที่ขีดไว้อย่างดีค้ำจุนวันพรุ่งนี้ที่จะไม่พังทลาย"},"ICON-1499":{"nm":"การ์ดสูตรอาหาร","de":"บนการ์ดที่มีรอยมือเปื้อนหนึ่งแผ่น ฝีมือของคุณยายถูกเขียนไว้เป็นปริมาณ คำที่คลุมเครืออย่าง 'เกลือหยิบมือหนึ่ง' คือเคล็ดลับที่แม่นยำที่สุด ยิ่งลายมือเลือนลางเท่าไร ครัวที่เคยต้มเมนูนั้นก็ยิ่งลอยขึ้นมาชัดเจนเท่านั้น"},"ICON-1500":{"nm":"ใบอนุญาตสิ่งปลูกสร้าง","de":"กระดาษเพียงแผ่นเดียวเปลี่ยนพื้นที่ว่างให้กลายเป็น \"ที่ที่ใช้ได้\" อาคารใหม่มักต้องมีตราประทับของหมู่บ้านก่อนเสมอ การอนุญาตท้ายที่สุดแล้วคือตราประทับอันอบอุ่นที่บอกว่าเริ่มต้นสิ่งใดสิ่งหนึ่งที่นี่ได้แล้ว"},"ICON-1501":{"nm":"ใบอนุญาตท่าเรือ","de":"ก่อนเรือจะทอดสมอได้ ต้องมีกระดาษแผ่นนี้เพียงแผ่นเดียวเสียก่อน ตราประทับสีซีดจางของท่าเรือคือคำทักทายแรกที่มอบให้ผู้มาเยือนจากแดนไกล ระหว่างการจากลาและการมาถึง ท่าเรือเปิดใจด้วยกระดาษเพียงแผ่นเดียวเสมอมา"},"ICON-1502":{"nm":"บัตรพลเมืองเกาะ","de":"หนังสือรับรองเล็กๆ ที่บอกว่าคุณได้กลายเป็นคนของเกาะแห่งนี้แล้ว หมู่บ้านเก่าแก่เมื่อมีเพื่อนบ้านใหม่ย้ายเข้ามา ก็จะเติมชื่อลงทะเบียนและแบ่งปันขนมข้าวอุ่นๆ ให้กัน แม้เป็นเพียงกระดาษแผ่นเดียว แต่บนนั้นจารึกคำต้อนรับอันสดใสไว้ว่า \"ตอนนี้เธอก็เป็นพวกเราแล้ว\""},"ICON-1503":{"nm":"ป้ายชื่อหน้าห้องพัก","de":"เพียงชื่อหนึ่งชื่อที่แขวนไว้ข้างประตู ห้องว่างเปล่าก็กลายเป็นบ้านของใครสักคนในที่สุด แม้แต่เรือนรับรองแขกในสมัยก่อน แผ่นป้ายสลักนามเจ้าของก็เป็นสิ่งแรกที่ถูกแขวนไว้ ป้ายชื่ออาจเล็ก แต่ในนั้นเต็มไปด้วยความอบอุ่นของคำว่า \"ที่นี่มีคนอาศัยอยู่\""},"ICON-1504":{"nm":"แสตมป์แฟนด้อม","de":"แม้แต่ความตั้งใจในการเลียแล้วกดแนบแน่นก็เป็นส่วนหนึ่งของจดหมายฉบับสมบูรณ์หนึ่งฉบับ การผนึกความรักไว้บนกระดาษแผ่นเล็กแล้วส่งไปไกลแสนไกล แม้ในยุคดิจิทัล ก็ยังมีใครบางคนที่ตั้งใจส่งใจไปด้วยมือของตัวเอง"},"ICON-1505":{"nm":"เข็มกลัดเกาะประกาย","de":"เมื่อติดไว้ที่ปกเสื้อ แสงเล็กๆ จะติดตามไปทุกที่ที่ก้าวเดิน หากพบใครที่ติดเข็มกลัดแบบเดียวกันบนถนน ก็เข้าใจกันได้โดยไม่ต้องพูดสักคำ ประกายแวววาวนี้ไม่ใช่การอวด แต่เป็นสัญญาณเงียบๆ ที่บอกว่า \"เรารักเกาะเดียวกัน\""},"ICON-1506":{"nm":"โต๊ะทำงานช่าง","de":"พื้นผิวโต๊ะที่เต็มไปด้วยรอยขีดข่วนเป็นพยานถึงมือที่สร้างสิ่งต่างๆ มากที่สุด สถานที่ที่เคยซ่อมแซม เชื่อมต่อ และขัดเกลาสิ่งของ โต๊ะทำงานที่รกกว่าโต๊ะเรียบร้อยกลับเก็บเรื่องราวไว้มากกว่าที่คิด"},"ICON-1507":{"nm":"กล่องเก็บของ","de":"สิ่งที่มีค่ามากเท่าไร ยิ่งต้องกำหนดที่อยู่ให้มันก่อนเป็นอันดับแรก คนโบราณก็เก็บเอกสารสำคัญแยกไว้ในหีบไม้พอลาวเนียเช่นกัน การเก็บรักษาอย่างดีคือการพับวันนี้ให้เรียบร้อยไว้เพื่อใครสักคนในอนาคต"},"ICON-1508":{"nm":"ลังทรัพยากร","de":"เมื่อมีเหลือก็เก็บสะสม เมื่อขาดก็หยิบออกมาใช้ ในนี้บรรจุภูมิปัญญาแห่งยุคสมัยที่ยุ้งฉางเต็มอิ่มหมายถึงใจที่มั่นคง การกักตุนคือมื้ออาหารอันอ่อนโยนที่มอบให้ตัวเองในอนาคตล่วงหน้า"},"ICON-1509":{"nm":"กล่องเย็น","de":"หีบที่เติมน้ำแข็งไว้ช่วยรักษาความเย็นได้แม้ในกลางฤดูร้อน เหมือนภูมิปัญญาโบราณของถ้ำเก็บน้ำแข็งที่ถูกย่อส่วนลงมาให้พอดีฝ่ามือ การรักษาความเย็นไว้คือการยืดช่วงเวลาที่สดใหม่ที่สุดให้อยู่นานขึ้นอีกนิด"},"ICON-1510":{"nm":"ปั๊มน้ำมือโยก","de":"โยกด้ามจับขึ้นลง น้ำที่อยู่ลึกใต้ดินก็พวยพุ่งขึ้นมา เครื่องจักรซื่อสัตย์ที่จะไหลพรวดออกมาได้ก็ต่อเมื่อมีน้ำกระตุ้นสักขันหนึ่งเทลงไปก่อน ริมบ่อน้ำรู้ความจริงข้อนี้มาแต่ไหนแต่ไรว่าต้องให้ก่อนจึงจะได้รับ"},"ICON-1511":{"nm":"เครื่องกรองน้ำ","de":"ปาฏิหาริย์เล็กๆ ที่น้ำขุ่นค่อยๆ ใสขึ้นทีละชั้น คนสมัยก่อนกรองน้ำด้วยการเรียงชั้นทรายและถ่านไว้ในโอ่งดิน ความใสไม่ใช่สิ่งที่ได้มาฟรีๆ แต่คือความตั้งใจในการกรองอย่างช้าๆ"},"ICON-1512":{"nm":"ที่วางบัวรดน้ำ","de":"เมื่อบัวรดน้ำมีที่พักของตัวเอง วันหนึ่งของแปลงดอกไม้ก็เป็นระเบียบขึ้นทันที การกำหนดที่แขวนเครื่องมือคือนิสัยของคนที่รักงานของตน เมื่อมีที่ทางหนึ่งจุดถูกกำหนดไว้ สวนทั้งหมดก็ดูเรียบร้อยขึ้นตามไปด้วย"},"ICON-1513":{"nm":"ที่วางคันเบ็ด","de":"แม้คนจะจากไปจนกว่าปลาจะกัด แต่คันเบ็ดยังคงรักษาตำแหน่งของมันไว้ ท่าทีแห่งความอดทนของการตกปลาเก็บวันเวลาริมแม่น้ำนั้นถูกตรึงไว้ที่นี่อย่างชัดเจน ที่วางนี้ท้ายที่สุดแล้วก็คือฐานรองสำหรับวางความเร่งรีบลงชั่วคราว"},"ICON-1514":{"nm":"ตะกร้าเก็บของป่า","de":"ตะกร้าที่แม่เคยถือกลับมาพร้อมผักป่ากำมือหนึ่งและดอกไม้ป่าดอกเดียว กลิ่นดินโชยออกมาแผ่วเบาผ่านช่องไม้ไผ่สานที่ถักทอไว้ ขึ้นอยู่กับว่าใส่อะไรลงไป ตะกร้าเปล่าใบนี้อาจกลายเป็นฤดูใบไม้ผลิหรือฤดูใบไม้ร่วงก็ได้"},"ICON-1515":{"nm":"ครกตำข้าว","de":"ตุ้บ ตุ้บ เสียงตำเมล็ดข้าวเป็นจังหวะสม่ำเสมอปลุกให้วันใหม่ของหมู่บ้านตื่นขึ้น เครื่องมือที่เสียงตำข้าวเหนียวเคยดังกึกก้องไปทั่วตรอกในวันเทศกาล การทำให้สิ่งแข็งกลายเป็นนุ่มนั้นต้องอาศัยจังหวะมือที่มั่นคงต่อเนื่อง"},"ICON-1516":{"nm":"เขียง","de":"รอยมีดทุกรอยที่ผ่านไปสลักประวัติศาสตร์ของมื้ออาหารหนึ่งมื้อ แผ่นไม้ที่เต็มไปด้วยรอยขีดข่วนคือเหรียญเกียรติยศของครัวที่มีมือขยันที่สุด การหั่นสิ่งใดสิ่งหนึ่งเริ่มต้นจากใจที่อยากจะรับใช้สิ่งนั้นด้วยความตั้งใจ"},"ICON-1517":{"nm":"หม้อ","de":"เสียงเดือดปุดๆ อ่อนโยนยิ่งกว่าดนตรีใดๆ ในยามเช้าตรู่ที่หิวโหย สามนาทีแห่งการรอบะหมี่สุกคือความปลอบโยนที่เป็นส่วนตัวที่สุด ทั่วก้นหม้อทรงกลม ไออุ่นแห่งความตั้งใจจะเลี้ยงดูใครสักคนกำลังค่อยๆ ร้อนขึ้น"},"ICON-1518":{"nm":"กระทะ","de":"ฝีมือในการทำให้สุกในพริบตาเดียวบนเปลวไฟฝากไว้กับกระทะใบนี้เพียงใบเดียว พื้นผิวที่ผ่านการใช้งานมาดียิ่งไม่ติดและยิ่งเป็นเงางาม กระทะเหล็กหล่อที่ใช้มานานคือหลักฐานของกาลเวลาที่ครัวนี้ผ่านมาในตัวมันเอง"},"ICON-1519":{"nm":"เตาอบ","de":"ระหว่างที่ปิดประตูรอคอย ภายในกำลังเกิดเวทมนตร์เงียบๆ ขึ้น ช่วงเวลาที่แป้งฟูขึ้นและสีเริ่มสุกงอม แม้มองไม่เห็นแต่หากเชื่อมั่นและรอคอย ผลลัพธ์อันอบอุ่นก็จะเปิดประตูก้าวออกมาเอง"},"ICON-1520":{"nm":"เครื่องปั่น","de":"แม้สิ่งที่แข็งใส่ลงมาในนี้ก็กลายเป็นเครื่องดื่มเนื้อเนียนนุ่มได้ในพริบตา วังน้ำวนเล็กๆ ที่วัตถุดิบต่างชนิดผสมกันจนเกิดรสชาติใหม่ ความกลมกลืนท้ายที่สุดแล้วคือการที่แต่ละฝ่ายยอมสละมุมคมของตัวเองไปทีละนิด"},"ICON-1521":{"nm":"ที่ตีไข่","de":"เพียงพลิกข้อมือครั้งเดียว อากาศก็ถูกกักไว้ และของเหลวก็ตั้งตัวแข็งขึ้นตามความเร็วของการตี ขณะที่ฟองอากาศพองตัวเป็นยอดแหลม สิ่งที่พองขึ้นไม่ใช่แค่แป้งเท่านั้น หัวใจที่อยากจะเลี้ยงดูใครสักคนในวันนี้ก็พองฟูตามไปด้วย"},"ICON-1522":{"nm":"เครื่องบดกาแฟ","de":"หมุนด้ามจับบนเมล็ดกาแฟกำมือหนึ่ง กลิ่นหอมแตกกระจายก่อนใครระหว่างซี่ฟันเฟือง เมื่อแขนเริ่มเมื่อยล้า ผงกาแฟจึงจะละเอียดพอดี และจิบแรกก็ยิ่งเข้มข้นตามความเหนื่อยล้านั้น ความตั้งใจเริ่มต้นที่ข้อมือเสมอ"},"ICON-1523":{"nm":"เครื่องโม่แป้ง","de":"เมล็ดข้าวลอดผ่านช่องหินแล้วออกมาเป็นแป้งสีขาว ไม่เป็นไรถ้ายังไม่ละเอียดในครั้งแรก แค่โม่ซ้ำอีกสองครั้งก็พอ แม้แต่การทำสิ่งหยาบให้ละเอียดก็มีลำดับขั้นตอนของมัน เครื่องโม่แป้งบอกเราอย่างเงียบๆ เช่นนั้น"},"ICON-1524":{"nm":"แท่นเลื่อยไม้","de":"เมื่อท่อนซุงถูกยกขึ้นมา เลื่อยจะอ่านลายไม้ก่อนเป็นอันดับแรก ต้องหลบปุ่มไม้และเลื่อยไปตามแนวตรงเท่านั้น แผ่นไม้จึงจะไม่บิดงอ การตัดไม้ท้ายที่สุดแล้วคือการคลี่กาลเวลาที่ต้นไม้ต้นหนึ่งเคยมีชีวิตอยู่ให้เรียบเสมอกัน"},"ICON-1525":{"nm":"จักรเย็บผ้า","de":"กรอบๆ—เสียงเข็มกัดผ้าวิ่งไปข้างหน้าเติมเต็มค่ำคืนอันดึกดื่น ตะเข็บเดียวเชื่อมผ้าสองผืนให้เป็นร่างเดียวกัน และในทุกรอยเย็บที่มองไม่เห็นด้านในชุดการแสดง เวลาที่ใครสักคนนอนไม่หลับก็ถูกเย็บไว้อย่างแน่นหนา"},"ICON-1526":{"nm":"แท่นย้อมสี","de":"จุ่มผ้าขาวแล้วยกขึ้นมา แรกเริ่มเป็นสีเขียวอ่อน เมื่อปะทะอากาศจึงค่อยกลายเป็นสีน้ำเงินในที่สุด สีนั้นว่ากันว่าต้องแช่ครามถึงสามครั้งจึงจะได้ ฉันเรียนรู้เป็นครั้งแรกต่อหน้าแท่นย้อมสีนี้ว่าการรอคอยนั่นเองคือสี"},"ICON-1527":{"nm":"ขาตั้งกล้อง","de":"ในวินาทีที่ขาทั้งสามกางออกแตะพื้น โลกที่กำลังสั่นไหวก็หยุดนิ่ง ภาพหนึ่งที่หากถือด้วยมือจะสั่นไหวกลับคมชัดขึ้นบนคำมั่นสัญญาของสามจุดนี้ หากต้องการจ้องมองสิ่งใดสิ่งหนึ่งนานๆ ต้องรู้จักหยุดนิ่งเสียก่อน"},"ICON-1528":{"nm":"ขาตั้งไฟ","de":"เมื่อวางแสงไฟไว้บนเสาต้นเดียว ทุกมุมในห้องก็กลายเป็นเวทีเล็กๆ เพียงปรับมุมเล็กน้อย เงาก็ยืดยาวขึ้นและสีหน้าก็มีชีวิตชีวา มันไม่ได้ลบล้างความมืด แต่จัดวางแม้แต่ความมืดไว้อย่างอ่อนโยน"},"ICON-1529":{"nm":"ขาตั้งไมโครโฟน","de":"ในวินาทีที่ปรับระดับความสูงพอดี ระยะห่างระหว่างปากกับบทเพลงก็ถูกกำหนด แม้ปล่อยมือ เสียงก็ยังคงอยู่ตรงจุดนั้น บนเวทีที่มือทั้งสองเป็นอิสระเท่านั้น บทเพลงที่ร้องด้วยทั้งร่างกายจึงจะเริ่มต้นขึ้นจริงๆ"},"ICON-1530":{"nm":"ขาตั้งโน้ตเพลง","de":"เมื่อกระดาษที่คลี่ออกพิงเอียงอยู่ ตัวโน้ตก็เรียงแถวอยู่ในระดับสายตาของผู้เล่น แม้ท่อนถัดไปจะมาถึงในพริบตาเดียว ที่วางก็ไม่หวั่นไหว เบื้องหลังการบรรเลงของใครสักคนมีที่ทางเงียบงันอยู่เสมอ"},"ICON-1531":{"nm":"แปลงผัก","de":"พรวนดินขึ้นร่อง เส้นคำมั่นสัญญาเล็กๆ ก็ปรากฏขึ้นบนผืนดิน ไม่กี่วันหลังจากฝังเมล็ดดูเหมือนไม่มีอะไรเกิดขึ้น แต่เช้าวันหนึ่งใบเลี้ยงอ่อนก็ดันดินขึ้นมา นี่คือภาพที่มองเห็นได้เฉพาะผู้ที่รอคอยเท่านั้น"},"ICON-1532":{"nm":"แปลงผักดินอุดม","de":"เมล็ดพันธุ์เดียวกัน แต่บนผืนดินนี้ใบกลับใหญ่เป็นสองเท่า จิ้มนิ้วลงไป ดินสีดำนุ่มก็ติดตามขึ้นมาถึงใต้เล็บ การเติบโตอย่างงอกงามท้ายที่สุดแล้วคือผลงานที่พื้นดินใต้เท้าซึ่งมองไม่เห็นทำสำเร็จอย่างเงียบเชียบ"},"ICON-1533":{"nm":"เรือนกระจก","de":"ใต้เพดานกระจก ฤดูกาลไหลผ่านไปช้ากว่าปกติหนึ่งจังหวะ แม้ข้างนอกน้ำค้างแข็งจับตัว แต่ข้างในกลับชุ่มชื้นด้วยไอความชื้นแห่งกลางฤดูร้อน สำหรับสิ่งที่อ่อนแอต่อความหนาว ใครสักคนได้กักแสงแดดไว้ใต้หลังคาอย่างเงียบๆ"},"ICON-1534":{"nm":"แปลงสมุนไพร","de":"เมื่อปลายนิ้วสัมผัสใบไม้ กลิ่นหอมก็ทักทายเป็นสิ่งแรก โหระพา โรสแมรี มินต์—เมื่อเรียกชื่อแต่ละชนิด กลิ่นที่ต่างกันก็ติดอยู่ที่ปลายนิ้ว แปลงเล็กๆ เพียงแปลงเดียวเปลี่ยนครัวทั้งหลังให้อบอุ่นขึ้นมาทันที"},"ICON-1535":{"nm":"สวนผลไม้","de":"ฤดูใบไม้ผลิกิ่งก้มด้วยร่มเงาดอกไม้ ฤดูใบไม้ร่วงกิ่งก้มด้วยน้ำหนักผล ปีนบันไดขึ้นไปเด็ดผลหนึ่งแล้วกัด ความหวานที่แสงแดดสะสมไว้ตลอดทั้งปีก็แตกกระจายในปาก ราวกับคำตอบที่ต้นไม้ส่งมอบให้กับผู้คน"},"ICON-1536":{"nm":"ท่อนซุงเพาะเห็ด","de":"เจาะรูในท่อนซุงที่ตัดไว้แล้วปลูกเชื้อเห็ดลงไป ต้นไม้ที่ตายแล้วก็เลี้ยงดูบางสิ่งขึ้นมาใหม่อีกครั้ง ไม่กี่วันต่อมาในเช้าที่หมวกเห็ดผุดขึ้นเป็นพวง ชีวิตใหม่ก็เริ่มต้นขึ้นอย่างเงียบๆ ในที่ที่เคยคิดว่าเป็นจุดจบ"},"ICON-1537":{"nm":"รังผึ้ง","de":"เอาหูแนบเข้าไปใกล้ๆ จะได้ยินเสียงสั่นสะเทือนต่ำๆ ที่ขยันขันแข็งอยู่ข้างใน การกระพือปีกนับพันครั้งรวมกันจึงกลายเป็นความหวานเพียงช้อนเดียว ความเหนื่อยยากของหนึ่งวันที่บินไปมาในทุ่งดอกไม้สะสมอยู่ที่นี่ เหนียวและเป็นสีทองอร่าม"},"ICON-1538":{"nm":"เล้าไก่","de":"ก่อนฟ้าสาง สิ่งที่เกาะอยู่บนคอนไก่จะขยับตัวก่อนเป็นอันดับแรก สอดมือเข้าไปในฟางอุ่นๆ จะจับได้ไข่ฟองหนึ่งที่ยังคงเหลือไออุ่นอยู่ สถานที่ที่ประกาศเช้าวันใหม่ก่อนใครคือที่แรกที่จัดโต๊ะอาหารเช้า"},"ICON-1539":{"nm":"ทุ่งเลี้ยงสัตว์","de":"ทุ่งกว้างที่กลิ่นหญ้าปนเปกับกลิ่นแสงแดด เหนือหลังของสัตว์ที่เคี้ยวเอื้องอย่างเชื่องช้าอยู่ในรั้ว เงาเมฆลอยผ่านไป ที่นี่ไม่มีอะไรต้องเร่งรีบ แม้แต่เวลาก็ไหลไปอย่างช้าๆ ราวกับกำลังกินหญ้า"},"ICON-1540":{"nm":"โรงงานชีส","de":"นมที่เพิ่งรีดใหม่ค่อยๆ แข็งตัวผ่านการจับตัวและการบ่ม รอคอยบนชั้นที่เย็นราวกับถ้ำอยู่หลายเดือน รสชาติอันล้ำลึกก็ค่อยๆ ซึมเข้าไปในก้อนสีขาวนั้น ชีสคือชื่อที่มอบให้เฉพาะนมที่ไม่เร่งรีบเท่านั้น"},"ICON-1541":{"nm":"โรงงานเต้าหู้","de":"แช่ถั่วเหลือง บด แล้วต้ม น้ำถั่วที่มีกลิ่นคาวก็กลายเป็นกลิ่นหอมมัน หยดน้ำเกลือเพียงหยดเดียวรวบรวมสิ่งที่กระจัดกระจายให้กลายเป็นเต้าหู้อ่อน และเมื่อกดทับไว้เบาๆ ก็จับเป็นรูปเหลี่ยม ที่นี่มีมือที่ปลอบประโลมหัวใจที่กระจัดกระจายให้จับเป็นรูปร่าง"},"ICON-1542":{"nm":"ลานโอ่งเครื่องปรุง","de":"มุมหนึ่งของสนามที่แสงแดดส่องถึง โอ่งดินเตี้ยๆ เรียงตัวกันเป็นกลุ่มอาบแสงแดด เปิดฝาออก กลิ่นของกาลเวลาเก่าแก่ก็โชยขึ้นมาทันที รสชาติซอสหมักที่คุณยายเคยดองไว้แท้จริงแล้วคือการกินกาลเวลาไปทีละช้อน"},"ICON-1543":{"nm":"โรงสี","de":"เมื่อหินโม่หมุนดังกึกกัก เมล็ดข้าวก็คลี่คลายกลายเป็นแป้ง ฝุ่นสีขาวล่องลอยอยู่ในแสงแดด และผู้คนที่รอปั้นข้าวเหนียวเต็มถาดก็รอคอยตามลำดับ วันเทศกาลของหมู่บ้านมักเริ่มต้นที่ธรณีประตูนี้เสมอ"},"ICON-1544":{"nm":"ร้านเบเกอรี่","de":"กลิ่นเนยและน้ำตาลโชยออกมาจากรอยแยกประตูเตาอบ เมื่อแป้งที่ฟูขึ้นเริ่มเปลี่ยนเป็นสีทอง ฝีเท้าของคนที่เดินผ่านหน้าร้านก็ช้าลงโดยไม่รู้ตัว ขนมปังอบใหม่ก้อนหนึ่งมีความอ่อนโยนที่ไม่มีใครต้านทานได้"},"ICON-1545":{"nm":"รถเข็นขายอาหารว่าง","de":"ผ้าใบพลาสติกพลิ้วไหวในสายลม น้ำซุปต๊อกบกกีเดือดปุดๆ จนงวดลง ค่ำคืนที่ซดน้ำซุปจากแก้วกระดาษพร้อมไม้เสียบโอเด้งไม้เดียว สถานที่ที่ละลายทั้งความหนาวและความหิวไปพร้อมกัน ความปลอบโยนเล็กๆ ที่ตั้งอยู่ปลายตรอก"},"ICON-1546":{"nm":"ครัวอาหารตะวันตก","de":"กระทะร้อนขึ้นและน้ำมันมะกอกส่งเสียงจี๊ดจ๊าด เพียงปรับไฟเล็กน้อย ซอสก็อาจข้นขึ้นหรือไหม้ได้ ที่นี่ที่แม้แต่ความสมดุลของสีบนจานก็ถูกคำนึงถึง มื้ออาหารหนึ่งมื้อจึงกลายเป็นการแสดงที่ถูกตกแต่งด้วยความตั้งใจ"},"ICON-1547":{"nm":"ครัวจีน","de":"เหนือเปลวไฟแรงจัด กระทะเว้าหมุนไปมาราวกับกำลังเต้นรำ ในช่วงเวลาสั้นๆ ที่เปลวไฟพวยพุ่งขึ้น กลิ่นหอมของวัตถุดิบก็ถูกกักไว้ทั้งหมด รวดเร็วและร้อนแรง หากลังเลแม้เพียงลมหายใจเดียวก็จะพลาด ความลับของอาหารจีนซ่อนอยู่ในจังหวะนั้นเอง"},"ICON-1548":{"nm":"คาเฟ่","de":"ผลักประตูเข้าไป กลิ่นเมล็ดกาแฟและเสียงเพลงเบาๆ ทักทายก่อนเป็นอันดับแรก ที่นั่งริมหน้าต่าง ลาเต้ที่กำลังเย็นลงหนึ่งแก้ว และสมุดที่เปิดค้างไว้ เพื่อให้ได้หยุดหายใจสักครู่ท่ามกลางวันที่วุ่นวาย เมืองจึงซ่อนห้องเล็กๆ แบบนี้ไว้ทั่วทุกมุม"},"ICON-1549":{"nm":"ร้านขนมหวาน","de":"ในตู้กระจก เค้กหลากสีเรียงแถวรอลูกค้าอยู่ ในวินาทีที่ปลายส้อมแหวกครีม มุมปากก็ยกขึ้นก่อนใคร แม้ในวันเศร้า เพียงชิ้นเดียวก็พอจะทนไหว ใบสั่งยาเล็กๆ ที่แสนหวาน"},"ICON-1550":{"nm":"ร้านขายเนื้อ","de":"ใต้แสงไฟสีแดง เนื้อสัตว์เรียงตัวเป็นระเบียบตามลายเนื้อ เพียงคำพูดที่ว่า \"วันนี้ชิ้นนี้ดี\" มีดก็เลื่อนผ่านด้วยความหนาที่แม่นยำ ความอิ่มท้องของโต๊ะอาหารเย็นเริ่มต้นอย่างเงียบๆ จากมือที่รักษาตำแหน่งเดิมทุกวันนี้เอง"},"ICON-1551":{"nm":"แท่นเตรียมอาหารทะเล","de":"แท่นทำงานที่กลิ่นคาวยามเช้าตรู่ปนเปกับความเย็นของน้ำแข็ง แม้เกล็ดปลากระเด็นและมือชาเย็น แต่สายตาที่คัดเลือกของสดที่สุดไม่เคยหยุดนิ่ง สิ่งที่เพิ่งขึ้นจากทะเลได้เส้นทางสู่โต๊ะอาหารที่นี่เอง"},"ICON-1552":{"nm":"นาเกลือ","de":"กักน้ำทะเลไว้ ที่เหลือแดดและลมจะจัดการเอง รอคอยไม่กี่วันให้น้ำแห้ง ผลึกสีขาวก็ผุดขึ้นบนพื้นราวกับดวงดาว รสเค็มกำมือหนึ่งแท้จริงแล้วคือของขวัญที่ทะเลกับท้องฟ้าร่วมกันสร้างขึ้นอย่างช้าๆ"},"ICON-1553":{"nm":"ราวตากสาหร่าย","de":"บนเชือกยาวเส้นหนึ่ง มิยอกและสาหร่ายทะเลถูกแขวนเรียงกันแกว่งไหวตามสายลม สิ่งที่อุ้มน้ำทะเลไว้เต็มค่อยๆ แห้งและเข้มขึ้นเป็นสีเขียวเข้ม รสชาติที่แสนประหยัดที่สุดของทะเล ซึ่งแสงแดดและลมทะเลร่วมกันปั้นแต่ง ห้อยอยู่ที่นี่"},"ICON-1554":{"nm":"ท่าเทียบเรือเล็ก","de":"แผ่นไม้ที่จมอยู่ในน้ำครึ่งหนึ่งแกว่งเบาๆ ใต้ฝ่าเท้า จุดที่เหมาะเจาะสำหรับผูกเรือลำเล็กเพียงลำเดียว ทั้งการออกเดินทางไปไกลและการกลับมาอย่างปลอดภัย ล้วนเริ่มต้นและสิ้นสุดที่ช่องเดียวนี้"},"ICON-1555":{"nm":"โกดังท่าเรือ","de":"เปิดประตูไม้ที่อาบไอลมทะเลออก อวน ถัง และเชือกกองสูงจรดเพดาน สัมภาระที่กำลังจะออกเดินเรือไกลกับสัมภาระที่เพิ่งมาถึงพักอยู่ใต้หลังคาเดียวกันชั่วครู่ สถานที่ราวกับสถานีเปลี่ยนถ่ายที่การจากลาและการกลับมาปะทะกันเพียงชั่วขณะ"},"ICON-1556":{"nm":"ประภาคาร","de":"เมื่อทะเลราตรีมืดมิดที่สุด นั่นแหละคือเวลาที่มันเริ่มทำหน้าที่ของตัวเอง แสงที่หมุนวนตัดผ่านหมอกและบอกว่า \"ที่นี่มีเส้นทาง\" ยามเฝ้าร่างสูงที่ไม่มีวันหลับ เพื่อการกลับมาอย่างปลอดภัยของใครสักคน"},"ICON-1557":{"nm":"อู่ต่อเรือ","de":"ตั้งกระดูกงูขึ้นแล้วติดโครงซี่โครงเรือ โครงร่างของเรือลำหนึ่งก็เริ่มเป็นรูปเป็นร่าง ในลานที่เสียงค้อนดังกึกก้องทั้งวัน เรือที่ยังไม่รู้จักรสชาติของน้ำใฝ่ฝันถึงการเดินทางครั้งแรก สถานที่ที่ต้องแข็งแกร่งก่อนจึงจะจากไปได้"},"ICON-1558":{"nm":"ห้องอัดเสียง","de":"เมื่อประตูปิดลง เสียงทุกอย่างจากภายนอกก็หายไปในพริบตา สิ่งที่ได้ยินผ่านหูฟังมีเพียงลมหายใจและจังหวะของตัวเอง ในความเงียบสงัดของห้องเล็กๆ นี้ เสียงที่สั่นไหวได้อย่างเต็มที่จึงถือกำเนิดขึ้นในที่สุด"},"ICON-1559":{"nm":"ห้องดนตรี","de":"เสียงประสานที่ลอดออกมาจากช่องประตูเติมเต็มโถงทางเดิน ใครบางคนกำลังฝึกบันไดเสียง ใครบางคนกำลังนับจังหวะ ที่ที่เสียงยังไม่ชำนาญกับเสียงที่คุ้นเคยปนเปกันได้โดยไม่เป็นไร ห้องเรียนอันอบอุ่นที่ทุกบทเพลงเริ่มก้าวแรกของมัน"},"ICON-1560":{"nm":"ห้องเปียโน","de":"เปิดฝาคีย์บอร์ด ฝุ่นบางๆ เกาะอยู่บนคีย์สีขาว ในวินาทีที่นิ้วสัมผัส เสียงกังวานใสก็แผ่ไปทั่วห้อง หากมีค่ำคืนที่แม้อยู่คนเดียวก็ไม่เหงา คงเป็นเพราะเปียโนหลังนี้เพียงหลังเดียว"},"ICON-1561":{"nm":"ห้องซ้อมเต้น","de":"กดปลายเท้าลง พื้นก็ดันกลับขึ้นมา ขณะที่กระจกทั้งสี่ด้านลอกเลียนท่าเดียวกันซ้ำสี่ครั้ง ร่างกายจดจำท่าเต้นล่วงหน้าไปครึ่งจังหวะก่อนเสียงเพลง ห้องที่เหงื่อและลมหายใจอยู่นานที่สุด ท่าเต้นที่เติบโตที่นี่จึงก้าวออกไปสู่เวที"},"ICON-1562":{"nm":"ห้องฟิตเนส","de":"น้ำหนักไม่เคยโกหก ผู้คนมาหาฉันทุกเช้ามืดเพราะรักความซื่อสัตย์นั้น—ยกเท่าไรก็สะสมไว้ที่บ่าเท่านั้นอย่างแม่นยำ สิ่งที่ค่อยๆ สลักลงบนกระจกไม่ใช่กล้ามเนื้อ แต่คือช่วงเวลาที่อดทนโดยไม่ยอมแพ้"},"ICON-1563":{"nm":"ห้องโยคะ","de":"สูดลมหายใจลึกๆ รู้สึกราวกับพื้นไม้พองตัวขึ้นพร้อมกัน ห้องที่พับวันหนึ่งซึ่งวิ่งเข้ามาอย่างเร่งรีบเก็บไว้อย่างช้าๆ บนเสื่อผืนเดียว ทุกคนกลับคืนสู่จังหวะลมหายใจของตัวเอง แม้แต่ใจที่เร่งรีบก็วางลงชั่วคราวที่นี่"},"ICON-1564":{"nm":"ห้องแต่งหน้า","de":"ก่อนก้าวขึ้นเวทีเพียงชั่วครู่ ผู้คนที่นี่กลายเป็นคนอื่นชั่วขณะหนึ่ง เมื่อหลอดไฟรอบกระจกให้ความอบอุ่นทั่วใบหน้า ความสั่นไหวก็ติดอยู่ที่ปลายแป้งพัฟและซ่อนตัวลอดหลังปกเสื้ออย่างเงียบๆ สถานที่ที่การเปลี่ยนแปลงเริ่มต้นและสิ้นสุด"},"ICON-1565":{"nm":"ห้องเสื้อผ้าเวที","de":"กว่าจะเสร็จสมบูรณ์เป็นชุดหนึ่งบนเวที เสื้อผ้าที่แขวนอยู่ที่นี่ถูกสวมใส่และถอดออกนับสิบครั้ง หุ่นจำลองที่หมุนอยู่พร้อมเข็มหมุดเนา เส้นตะเข็บที่ขีดด้วยชอล์ก เบื้องหลังความแวววาวมักมีรอยเข็มของใครสักคนหลงเหลืออยู่เสมอ"},"ICON-1566":{"nm":"ฉากสตูดิโอ","de":"เพียงตกแต่งด้านเดียวที่กล้องส่องเห็นให้ดูเหมือนจริงก็พอ ฉันเรียนรู้เช่นนั้นมาแต่ต้น เดินอ้อมไปด้านหลังแผ่นไม้อัด จะเห็นเพียงโครงเปล่าว่างเปล่า สิ่งที่ค้ำจุนความงดงามด้านหน้าอย่างเงียบๆ เสมอมาคือหน้าที่ของแท่งไม้ที่มองไม่เห็น"},"ICON-1567":{"nm":"สตูดิโอถ่ายภาพ","de":"เคล็ดลับข้อแรกคือการฉายแสงจากสามทิศทางเพื่อลบเงา แสงหลักดึงใบหน้าให้เด่น แสงเสริมดึงเงามืด แสงด้านหลังดึงปลายเส้นผมให้มีชีวิตชีวา ในเสี้ยววินาทีที่ชัตเตอร์กด ฉากหลังสีขาวแผ่นเดียวก็กักรอยยิ้มที่ดีที่สุดของวันนี้ไว้"},"ICON-1568":{"nm":"หอแสดงคอนเสิร์ต","de":"ในความมืดที่เพดานสูงลิบ ฉันมีคำมั่นสัญญาเดียวกันเสมอมา ว่าเมื่อม่านเปิดขึ้น แม้แต่ที่นั่งว่างเปล่าก็จะกลั้นลมหายใจเป็นหนึ่งเดียวกัน เพื่อวินาทีเดียวที่จังหวะแรกดังขึ้นนั้น ฉันยืนว่างเปล่าอย่างเงียบสงัดตลอดทั้งปี"},"ICON-1569":{"nm":"บูธแฟนมีตติ้ง","de":"ระยะห่างระหว่างมือกับมือเท่ากับความกว้างของโต๊ะเพียงตัวเดียวพอดี คำทักทายสั้นๆ ลายเซ็นที่สั่นไหว คำพูดที่ไม่มีโอกาสได้พูดสักคำเรียงแถวผ่านไป ในช่องเล็กๆ นี้เอง ความชอบที่บ่มเพาะมานานได้พบหน้ากันเป็นครั้งแรก"},"ICON-1570":{"nm":"เตียงนอน","de":"สิ่งที่รับปลายทางของวันไว้ก่อนใครเสมอมาคือฉันเอง เมื่อขาที่หนักอึ้งจากการซ้อมและความสั่นไหวที่หลงเหลือหลังเวทีจมหายไปจนหมด เช้าวันใหม่ก็เริ่มต้นด้วยปลายเท้าที่เบาสบายอีกครั้ง กล่าวราตรีสวัสดิ์แล้วโอบกอดไว้โดยไม่พูดอะไรเลย"},"ICON-1571":{"nm":"เตียงสองชั้น","de":"ระหว่างชั้นบนกับชั้นล่าง บันไดห้าขั้นเชื่อมคนสองคนเข้าด้วยกัน เสียงกระซิบเบาๆ หลังปิดไฟ ดาวเรืองแสงที่ติดไว้บนเพดาน ห้องพักแคบๆ กลับกว้างที่สุดก็เพราะเรื่องราวที่ปีนขึ้นลงบันไดทุกค่ำคืนนี่เอง"},"ICON-1572":{"nm":"ชั้นวางของ","de":"สิ่งที่วางไว้บนนี้บอกได้ว่าเจ้าของเป็นคนแบบไหน จดหมายที่ได้รับ ถ้วยรางวัลแรก ตั๋วเข้าชมที่สีซีดจางเรียงแถวกัน ฉันไม่ใช่เฟอร์นิเจอร์สำหรับอวด แต่เป็นที่ที่จัดแสดงความทรงจำที่ไม่อาจทิ้งไปได้อย่างเงียบๆ"},"ICON-1573":{"nm":"โต๊ะทำงาน","de":"สมุดเนื้อเพลงเปิดค้างไว้ เส้นใหม่ถูกขีดซ้ำอีกครั้งทับรอยลบเดิม แก้วกระดาษที่กองสูงข้ามคืนและทำนองเพียงท่อนเดียวที่กู้กลับมาได้ยากเย็น งานอันเชื่องช้าในการถ่ายทอดหัวใจให้กลายเป็นตัวอักษรเกิดขึ้นอย่างเงียบๆ บนพื้นผิวเรียบนี้เสมอ"},"ICON-1574":{"nm":"เก้าอี้","de":"คำว่า \"นั่งพักสักครู่\" นั้นอ่อนโยนอย่างไม่คาดคิด แม้การประชุมจะยืดเยื้อหรือการซ้อมจะยาวนาน พนักพิงก็รองรับน้ำหนักของคนอย่างเงียบๆ เสมอ ฉันรู้ดีว่ายิ่งใครยืนนานเท่าไร คนนั้นยิ่งต้อนรับฉันมากเท่านั้น"},"ICON-1575":{"nm":"โซฟา","de":"เพียงฉันตัวเดียวก็เพียงพอที่จะเปลี่ยนที่พักยามดึกให้กลายเป็นห้องนั่งเล่น เมื่อทุกคนเบียดกันนั่งดูรายการวาไรตี้ ไม่นานก็มีคนหลับพิงพนักวางแขนโดยไม่รู้ตัว ที่นั่งตรงกลางที่ยุบตัวลึกคือหลักฐานของความอบอุ่นในบ้านหลังนั้น"},"ICON-1576":{"nm":"โต๊ะกลม","de":"เมื่อล้อมวงนั่ง ไม่มีใครเป็นประธานที่โต๊ะ ซุปที่เพิ่งต้มร้อนๆ เสียงช้อนกระทบกัน เรื่องราวของวันนี้ต่างรวมตัวมาที่ตรงกลาง เมื่อพื้นผิวทรงกลมหนึ่งแผ่นคลี่ออก แม้วันที่กระจัดกระจายก็กลับมานั่งล้อมวงกันอีกครั้ง"},"ICON-1577":{"nm":"ตู้เสื้อผ้า","de":"ทุกครั้งที่ฤดูกาลเปลี่ยนผ่าน เรื่องราวเก่าแก่ก็หลั่งไหลออกมาจากภายใน ชุดการแสดงและเสื้อผ้าธรรมดาเบียดไหล่กันอยู่ หลังประตูที่ปิดสนิท เสื้อผ้ารอคอยลำดับถัดไปของตน เมื่อเปิดประตูเท่านั้น วันที่จะสวมใส่วันนี้จึงจะถูกกำหนด"},"ICON-1578":{"nm":"กระจกเงา","de":"ทั้งคำชมและข้อบกพร่อง ฉันสะท้อนกลับด้วยความซื่อตรงเท่ากันเสมอ สถานที่สำหรับตรวจสอบครั้งสุดท้ายก่อนก้าวขึ้นเวที ผู้คนปรับสีหน้าและยืดตัวตรงต่อหน้าฉัน เพื่อนที่ซื่อสัตย์ที่สุดไม่เคยพูดสักคำเดียว"},"ICON-1579":{"nm":"โต๊ะเครื่องแป้ง","de":"ในลิ้นชักเล็กๆ แต่ละใบมีใบหน้าที่ต่างกันหลับใหลอยู่ หลอดหนึ่งสำหรับเวที หลอดหนึ่งสำหรับวันธรรมดา และอีกหลอดรุ่นลิมิเต็ดที่เก็บไว้ทะนุถนอม เมื่อนั่งลงหน้ากระจก จึงค่อยๆ เริ่มตัดสินใจว่าวันนี้จะออกจากประตูไปในฐานะคนแบบไหน"},"ICON-1580":{"nm":"พรมปูพื้น","de":"สัมผัสแรกที่เท้าเปล่าแตะถึงกำหนดอุณหภูมิของห้องนั้น รอยที่ล้อมวงกินขนมและกลิ้งเล่นหลงเหลือเป็นขนพรม เฟอร์นิเจอร์ที่ทำงานอยู่ ณ ตำแหน่งต่ำที่สุด ให้ความอบอุ่นแก่พื้นเย็นเพิ่มขึ้นอีกหนึ่งฝ่ามือ"},"ICON-1581":{"nm":"ผ้าม่าน","de":"จะให้เช้ามาถึงมากแค่ไหนคือสิ่งที่ฉันเป็นผู้กำหนด เพียงเปิดออกเล็กน้อย แสงแดดก็สาดยาวเข้ามา หากปิดสนิท แม้แต่การตื่นสายก็กลายเป็นเรื่องที่ให้อภัยได้ การยืนอยู่ระหว่างหน้าต่างกับห้องและปรับปริมาณแสงอย่างเงียบๆ เป็นหน้าที่ที่ถูกฝากไว้กับฉันเสมอมา"},"ICON-1582":{"nm":"โคมไฟ","de":"ห้องเดียวกันกลับกลายเป็นช่วงเวลาที่แตกต่างไปโดยสิ้นเชิงตามสีของแสง แสงสีเหลืองยืดค่ำคืนให้ยาวนาน แสงสีขาวปลุกรุ่งอรุณให้แจ่มชัด นักมายากลขนาดเท่าฝ่ามือที่เปลี่ยนบรรยากาศของวันได้เพียงแค่สวิตช์เดียว"},"ICON-1583":{"nm":"นาฬิกาแขวนผนัง","de":"เสียงเข็มวินาทีได้ยินเฉพาะในห้องที่เงียบสงัดเท่านั้น ยิ่งการซ้อมลึกซึ้งขึ้นเท่าไร ก็ยิ่งลืมฉันไปเท่านั้น จนกระทั่งเงยหน้าขึ้นมองจึงพบว่านอกหน้าต่างกลายเป็นรุ่งอรุณไปแล้ว ไม่เคยตำหนิเวลาที่ผ่านไป เพียงชี้ไปยังช่องถัดไปอย่างเงียบๆ เท่านั้น"},"ICON-1584":{"nm":"แจกันดอกไม้","de":"แม้ดอกไม้จะเหี่ยวเฉา ฉันก็ไม่ปล่อยให้ที่ของมันว่างเปล่า ภาชนะที่บรรจุความรู้สึกที่ได้รับไว้ชั่วคราว ตราบใดที่ยังมีมือที่คอยเปลี่ยนน้ำ โต๊ะอาหารก็ยังคงสดใส แม้ในยามว่างเปล่า ฉันก็ยังยืนอยู่ในท่วงท่าของการรอคอยใครสักคน"},"ICON-1585":{"nm":"กรอบรูปโปสเตอร์","de":"แม้แต่การแขวนใบหน้าที่ชื่นชอบไว้บนผนังก็ต้องใช้ความตั้งใจ ตำแหน่งที่แสงแดดส่องไม่ถึงโดยตรง ตะปูเพียงตัวเดียวที่ระดับพอดิบพอดี กระดาษแผ่นหนึ่งที่นอนสงบอยู่หลังกระจกคือสิ่งแรกที่ทักทายฉันทุกเช้าเมื่อก้าวเข้าห้อง"},"ICON-1586":{"nm":"บอร์ดโฟโต้การ์ด","de":"จะเรียงตามตัวอักษรหรือเรียงตามลำดับวางจำหน่ายดี ความลำบากใจอันแสนสุขนั้นเองคือจุดเริ่มต้นของการเป็นแฟนคลับ ช่องว่างหนึ่งช่องคือที่สำหรับไบอัสที่ยังไม่ได้พบเจอ ยิ่งเติมเต็มทีละใบ บอร์ดก็ยิ่งกลายเป็นบันทึกประวัติศาสตร์เล็กๆ ของตัวเอง"},"ICON-1587":{"nm":"ที่วางแท่งไฟ","de":"ถอดแบตเตอรี่ออก หันด้ามจับขึ้น แม้แต่มุมที่เอนวางก็มีเคล็ดลับของมันเอง รอคอยเสียงเชียร์ครั้งถัดไปที่จะมาถึง แท่งไฟดับแสงและวางร่างลงอย่างเป็นระเบียบที่นี่เอง พักผ่อนให้ดี แล้วมันจะสว่างขึ้นได้มากกว่าเดิม"},"ICON-1588":{"nm":"ชั้นวางถ้วยรางวัล","de":"แถวหน้าสุดวางถ้วยรางวัลที่เก่าแก่ที่สุด ตั้งแต่รูปปั้นเล็กๆ จากการประกวดเล็กจนถึงถ้วยจากเวทีใหญ่ เรียงลำดับไม่ใช่ตามความสูง แต่ตามลำดับของหัวใจ ทุกครั้งที่เช็ดถู ความสั่นไหวบนเวทีในวันนั้นก็กลับมาติดที่ปลายนิ้วอีกครั้ง"},"ICON-1589":{"nm":"ตะกร้าปิกนิก","de":"เปิดฝาออก กลิ่นแสงแดดฤดูใบไม้ผลิโชยออกมาก่อนเป็นอันดับแรก คิมบับ กระติกน้ำร้อน และเสื่อปูนั่งหนึ่งผืนวางซ้อนกันอย่างเป็นระเบียบ พร้อมออกเดินทางไปทุ่งกว้าง ฝีเท้าของคนที่ถือฉันมักเบาขึ้นกว่าปกติเสมออย่างไม่รู้เหตุผล"},"ICON-1590":{"nm":"กระถางต้นไม้เล็ก","de":"ขอบหน้าต่างเพียงคืบเดียวก็เพียงพอสำหรับฉัน สีเขียวเล็กๆ ที่ทนได้อย่างใจกว้างแม้จะลืมรดน้ำบ่อยครั้ง ในมุมโต๊ะของคนที่ยุ่งอยู่เสมอ ฉันคลี่ใบใหม่เพิ่มขึ้นทุกวัน ส่งความคิดถึงของวันนี้ไปอย่างเงียบๆ"},"ICON-1591":{"nm":"กระถางต้นไม้ใหญ่","de":"ขณะที่ฉันเติบโตสูงขึ้น คนก็เติบโตไปพร้อมกัน เมื่อใบกว้างที่ครองมุมหนึ่งของห้องนั่งเล่นรับแสงแดดและทอดร่มเงา ฤดูกาลก็แอบเข้ามาในห้องด้วยเช่นกัน คุณค่านี้รู้ได้เฉพาะคนที่ไม่เคยลืมรดน้ำเท่านั้น"},"ICON-1592":{"nm":"ชุดเทียนหอม","de":"ในวินาทีที่จุดไฟที่ไส้เทียน อากาศในห้องก็ทรุดต่ำลงหนึ่งระดับ กลิ่นหอมค่อยๆ แผ่กระจาย ผิงและส่งความเหนื่อยล้าที่หลงเหลือจากเมื่อวานออกไป ด้วยเปลวไฟเล็กๆ เพียงดวงเดียว การปิดฉากวันที่วุ่นวายราวกับพิธีกรรมอันเงียบสงบ"},"ICON-1593":{"nm":"ตู้เย็นมินิ","de":"เปิดประตูในค่ำคืนดึกดื่น เครื่องดื่มกระป๋องเย็นๆ กระป๋องหนึ่งต้อนรับฉัน เสียงสั่นสะเทือนเบาๆ วี้ดหนึ่งช่วยให้ที่พักที่ว่างเปล่าเหงาน้อยลง แม้ทำครัวใหญ่ไม่ได้ แต่เมื่อพูดถึงการดูแลรุ่งอรุณที่หิวโหย ไม่มีใครเทียบฉันได้"},"ICON-1594":{"nm":"หมวกตาข่ายจับแมลงปอ","de":"ในวินาทีที่สวมลงบนศีรษะ ทุ่งฤดูร้อนก็ติดตามขึ้นมาบนบ่า ตาข่ายกลมกรองแสงแดดให้นุ่มนวล และทุกย่างก้าวกลิ่นหญ้าก็แกว่งไหวแผ่วเบา หมวกที่ห่มทั้งฤดูกาลไว้รอบตัว แม้จับแมลงปอไม่ได้สักตัวก็ยังดี"},"ICON-1595":{"nm":"ถุงตาข่ายเก็บของ","de":"แขวนอยู่ที่เอวกลายเป็นเพื่อนคู่ใจในการเก็บของ รัดปากถุงไว้เบาๆ สิ่งที่จับได้จะไม่หนีกลับไปได้ นี่คือเคล็ดลับแรกที่เรียนรู้จากท้องทุ่ง ถุงผ้าเบาๆ เพียงใบเดียวโอบอุ้มผลผลิตของวันนั้นไว้อย่างมั่นคง"},"ICON-1596":{"nm":"ขวดสังเกตแมลง","de":"สำหรับแขกที่แวะพักอยู่เพียงชั่วครู่ รูระบายอากาศสำคัญที่สุด ฉันรู้ดี ช่องหายใจเล็กๆ ที่เจาะไว้บนฝา ใบหญ้าใบหนึ่งปูไว้ที่ก้นขวด เมื่อสังเกตเสร็จแล้วส่งกลับคืนสู่พงหญ้าอีกครั้งก็เป็นส่วนหนึ่งของชุดนี้ด้วย"},"ICON-1597":{"nm":"กล่องเข็มหมุดตัวอย่าง","de":"แม้แต่มุมเดียวที่ปักหมุดเอียงก็มีฝีมืออยู่ในนั้น ลึกเกินไปจะแตก ตื้นเกินไปจะโยกคลอน จึงต้องแบ่งแรงที่ปลายนิ้วอย่างแม่นยำ กล่องที่บรรจุความตั้งใจของผู้ที่อยากจ้องมองชีวิตเล็กๆ ให้นานที่สุดไว้อย่างเงียบๆ"},"ICON-1598":{"nm":"ฝาตู้เลี้ยงสัตว์","de":"การดูแลเส้นแบ่งระหว่างข้างในกับข้างนอกคือหน้าที่ของฉัน ปิดแน่นเกินไปจะอึดอัด ปล่อยหลวมเกินไปจะหลงทาง จึงต้องเว้นช่องเล็กๆ ราวกับรอยขีดไว้เสมอ การปกป้องนั้นแตกต่างจากการกักขังอย่างชัดเจน"},"ICON-1599":{"nm":"จานอาหารผีเสื้อ","de":"วางสำลีชุบน้ำหวานไว้ตรงกลาง ปีกทั้งหลายก็มารวมตัวกัน เคล็ดลับคือใส่ให้ตื้นและกว้าง ลึกพอดีที่เท้าเล็กๆ จะไม่จมลงไป จานเพียงใบเดียวเรียกรวมแขกที่แวะพักในสวนที่แดดดีชั่วครู่ไว้อย่างเงียบๆ"},"ICON-1600":{"nm":"โคมไฟล่อแมลง","de":"เปิดไว้สลัวๆ ในความมืด ปีกเล็กๆ ก็มารวมตัวตามแสงไฟ ความสว่างนุ่มนวล ตำแหน่งอยู่ห่างจากผู้คนพอสมควร คนเชิญชวนแสนอ่อนโยนที่ทำให้คืนฤดูร้อนอันอึงมี่สงบลงไปมาก"},"ICON-1601":{"nm":"สติกเกอร์แมลง","de":"หกขาและหนวดคู่หนึ่งหลับใหลอยู่ในกระดาษชิ้นเล็กเท่าปลายเล็บ ชีวิตน้อย ๆ หนึ่งชีวิตนอนสงบอยู่ในนั้น แปะไว้เบา ๆ ที่มุมสมุด แล้วผืนหญ้ากว้างเท่าฝ่ามือก็ค่อย ๆ แผ่ขยายอยู่ระหว่างหน้ากระดาษอย่างเงียบงัน"},"ICON-1602":{"nm":"ป้ายอนุญาตจับแมลง","de":"ก่อนจะยกสวิงจับแมลงปอขึ้น ผู้ใหญ่จะถามก่อนเสมอว่าได้กี่ตัว ไปได้ไกลแค่ไหน ป้ายเล็ก ๆ แผ่นนี้ขีดเส้นแบ่งอันอ่อนโยนระหว่างความอยากรู้อยากเห็นที่พลุ่งพล่านกับคำสัญญาที่ต้องรักษาไว้"},"ICON-1603":{"nm":"กระปุกเหยื่อตกปลา","de":"เปิดฝาออกก็มีกลิ่นคาวเย็น ๆ ของรุ่งเช้าลอยขึ้นมา สิ่งที่เรียกปลาให้เข้ามาอาจไม่ใช่เหยื่อ แต่เป็นหัวใจที่รู้จักรอคอยอย่างสงบนิ่งจนกว่าทุ่นจะสั่นไหว"},"ICON-1604":{"nm":"กล่องเก็บทุ่นตกปลา","de":"ตู้เสื้อผ้าใบเล็กที่ทุ่นหลากสีนอนหลับเรียงรายอยู่ในแต่ละช่อง บางอันคือเช้าของทะเลสาบอันสงบนิ่ง บางอันคือบ่ายของกระแสน้ำเชี่ยวกราก คู่ที่เหมาะสมกับสีหน้าของสายน้ำแต่ละแบบถูกพับเก็บไว้อย่างเรียบร้อย"},"ICON-1605":{"nm":"แกนม้วนสายเบ็ด","de":"อย่าพันสายที่คลายออกไว้กับนิ้วมือ ม้วนกลับให้เรียบร้อยบนเครื่องมือทรงกลมนี้ทีละรอบ แล้วแม้แต่ปมพันกันก็จะค่อย ๆ คลายออกโดยไม่รู้ตัว มันคล้ายกับสัมผัสมือที่จัดระเบียบวันที่หย่อนยานให้กลับมาเรียบร้อยอีกครั้ง"},"ICON-1606":{"nm":"ที่ถอดเบ็ด","de":"มีแต่คนที่เคยเจ็บจากการถอดเบ็ดที่ติดคาด้วยมือเปล่าเท่านั้นที่จดจำเครื่องมือชิ้นนี้ได้ ทางที่เจ็บน้อยกว่าทั้งต่อชีวิตน้อย ๆ และต่อปลายนิ้วของเรา ความเอาใจใส่มักเริ่มต้นจากปลายทางเล็ก ๆ แบบนี้เสมอ"},"ICON-1607":{"nm":"ปลอกครอบพลั่วขุดหอย","de":"ผ้าคลุมชั้นบาง ๆ ที่ห่อหุ้มใบพลั่วซึ่งเพิ่งขุดขึ้นจากหาดโคลน เพื่อไม่ให้โคลนและน้ำเค็มกัดกร่อนคมใบ มันจึงสอดแทรกช่วงพักผ่อนอันบางเบาและนุ่มนวลไว้เบา ๆ ระหว่างทะเลกับเครื่องมือ"},"ICON-1608":{"nm":"การ์ดตารางน้ำขึ้นน้ำลง","de":"น้ำจะขึ้นเมื่อไหร่ ลงเมื่อไหร่ การ์ดขนาดเท่าฝ่ามือจะบอกไว้อย่างเงียบ ๆ ปฏิทินแผ่นเล็ก ๆ ที่มนุษย์จดบันทึกคำสัญญาเก่าแก่ซึ่งดวงจันทร์กับท้องทะเลผูกพันกันไว้"},"ICON-1609":{"nm":"แปรงล้างตู้ปลา","de":"ปัดตะไคร่เขียวที่เกาะผนังกระจกออกเบา ๆ แล้วแสงก็ค่อย ๆ ซึมกลับเข้าไปในโลกเล็ก ๆ ใต้น้ำอีกครั้ง การทำให้วันของใครสักคนสดใสขึ้นนั้น ส่วนใหญ่ก็ไหลผ่านไปอย่างเงียบงันเช่นนี้"},"ICON-1610":{"nm":"ชิปวัดอุณหภูมิตู้ปลา","de":"ตัวเลขหนึ่งกะพริบแล้วหยุดนิ่งที่องศาพอดี ปลาทั้งหลายจึงค่อยรู้สึกอุ่นใจ ความอบอุ่นในช่องเล็ก ๆ ที่ไม่หนาวไม่ร้อนเกินไป การดูแลเอาใจใส่นั้นแผ่ไปถึงแม้แต่ที่ที่มองไม่เห็น"},"ICON-1611":{"nm":"กระบอกสังเกตสิ่งมีชีวิตทางทะเล","de":"แขกตัวน้อยที่แวะพักอยู่ชั่วครู่ในกระบอกใส นับครีบหลังอย่างเงียบ ๆ แล้วปล่อยกลับคืนสู่ทะเลอีกครั้ง การสังเกตไม่ใช่การครอบครอง แต่เป็นการยืมมาดูสักพักหนึ่งเท่านั้น"},"ICON-1612":{"nm":"แปรงปัดฟอสซิล","de":"สิ่งที่ปลุกลายเนื้อหินซึ่งหลับใหลมานับสิบล้านปีให้ตื่นขึ้นไม่ใช่ค้อน แต่เป็นปลายแปรงอันอ่อนนุ่ม ต่อหน้ากาลเวลาที่จะแตกสลายหากเร่งรีบ ความระมัดระวังจึงกลายเป็นมารยาทที่ลึกซึ้งที่สุด"},"ICON-1613":{"nm":"ฝาครอบแปรงขุดค้น","de":"เมื่อปลายแปรงแห้งกรัง แม้แต่ดินก็ไม่หลุดร่วงอย่างประณีต หมวกเล็ก ๆ ใบหนึ่งช่วยรักษาลมหายใจของแปรงให้ชุ่มชื้นอยู่เสมอ มือที่ทะนุถนอมเครื่องมือคือมือที่ก้าวเท้าแรกสู่การขุดค้น"},"ICON-1614":{"nm":"แผ่นเก็บตัวอย่างชั้นดิน","de":"ในดินกว้างเท่าฝ่ามือมีเวลาหลายร้อยปีซ้อนทับกันเป็นชั้น ๆ ตักขึ้นมาวางบนแผ่นนี้เบา ๆ แล้วลวดลายของกาลเวลาที่ไม่เคยปรากฏให้เห็นก็ค่อย ๆ ขีดเส้นและลอยขึ้นมาอย่างช้า ๆ"},"ICON-1615":{"nm":"ถาดเก็บชิ้นส่วนกระดูก","de":"วางชิ้นส่วนที่กระจัดกระจายให้นอนเรียงตามช่อง แล้วชีวิตหนึ่งที่เคยปลิวไปตามลมก็ค่อย ๆ คลำหาทางกลับสู่ที่ของมันอีกครั้ง การบูรณะคือการถามไถ่ลำดับที่สูญหายไปด้วยความอ่อนโยน"},"ICON-1616":{"nm":"เทปซ่อมประสาน","de":"เส้นบาง ๆ เส้นหนึ่งที่เชื่อมรอยแตก ไม่ปิดบังรอยแผลเป็นแต่กอดรัดและยึดมันไว้อย่างอ่อนโยน มันพิสูจน์อย่างเงียบ ๆ ว่าแม้สิ่งที่เคยแตกสลายก็สามารถกลับมาสมบูรณ์ได้อีกครั้ง"},"ICON-1617":{"nm":"ฝาครอบป้ายชื่อจัดแสดง","de":"แผ่นหนึ่งที่ปิดคลุมป้ายชื่อหลังกระจกไว้เบา ๆ เพื่อไม่ให้สีจางลง มันบรรจุความปรารถนาที่อยากให้ประโยคสั้น ๆ ว่าใครเคยมีชีวิตอยู่ที่ไหน ยังคงอ่านได้ชัดเจนแม้ในอนาคตอันไกล"},"ICON-1618":{"nm":"ป้ายห้องเก็บสมบัติ","de":"ห้องลึกที่สมบัติซึ่งไม่เคยก้าวออกสู่แสงไฟหลับใหลอยู่ ทุกสิ่งภายในนั้นมีป้ายชื่อเล็ก ๆ แขวนอยู่ เพื่อว่าแม้ไม่ได้ยืนอยู่ในที่สว่างไสว มันก็จะไม่มีวันถูกลืม"},"ICON-1619":{"nm":"ซองบริจาคพิพิธภัณฑ์","de":"ใครสักคนยื่นสิ่งที่สะสมมาทั้งชีวิตให้โดยไม่พูดอะไร สิ่งที่บรรจุอยู่ในซองนี้ไม่ใช่วัตถุ แต่เป็นหัวใจที่โอบอุ้มมานาน การแบ่งปันกลายเป็นนิทรรศการที่คงอยู่ยาวนานที่สุด ส่องประกายให้ใครสักคน"},"ICON-1620":{"nm":"ชิปหมายเลขตัวอย่าง","de":"ตรงจุดที่เก็บมาได้นั้นเอง เราค่อย ๆ กำหนดตัวเลขเล็ก ๆ หนึ่งตัวลงไป ว่าเมื่อไหร่ ที่ไหนที่ได้พบกันเป็นครั้งแรก เพราะการค้นพบที่ไม่ได้จดบันทึกไว้จะสลายหายไปดั่งหมอกยามเช้าในไม่ช้า"},"ICON-1621":{"nm":"ขวดเศษดาวตก","de":"เศษชิ้นที่ตกลงมาพาดผ่านท้องฟ้ายามค่ำคืนถูกกักไว้ในขวดแก้ว แสงเส้นหนึ่งที่เลือนหายไปก่อนจะทันได้อธิษฐาน บัดนี้กลับมาระยิบระยับอีกครั้งอย่างแผ่วเบาอยู่ในอุ้งมือ"},"ICON-1622":{"nm":"เชือกกระดิ่งลมเปลือกหอย","de":"ร้อยเปลือกหอยที่เก็บมาทีละชิ้นจากชายหาดเข้ากับเส้นด้าย แล้วแขวนไว้ที่ชายคา ทุกครั้งที่ลมพัดผ่าน เสียงกรุ๊งกริ๊งดังขึ้น ทะเลของฤดูร้อนปีนั้นก็ค่อย ๆ ตามเข้ามาถึงในบ้านอย่างเงียบ ๆ"},"ICON-1623":{"nm":"หยดน้ำค้างสายรุ้ง","de":"หยดน้ำหนึ่งหยดที่กลิ้งเกาะอยู่ปลายใบไม้หลังฝนหยุด ภายในทรงกลมนั้นบรรจุท้องฟ้าทั้งผืนและสีทั้งเจ็ดไว้เป็นวงกลม บางครั้งสิ่งที่เล็กที่สุดก็โอบอุ้มทัศนียภาพที่กว้างไกลที่สุดเอาไว้ได้"},"ICON-1624":{"nm":"ขวดเก็บหมอก","de":"ฉันนำหมอกจากเชิงเขายามรุ่งอรุณกลับมาเต็มขวดหนึ่งใบ กำไว้ในมือแล้วรู้สึกเย็นและพร่ามัวเป็นสีขาวขุ่น ความโลภเล็ก ๆ ที่อ่อนโยน อยากเก็บสิ่งที่จับต้องไม่ได้ไว้ข้างกายสักครู่หนึ่ง"},"ICON-1625":{"nm":"ถ้วยรองน้ำค้าง","de":"แก้วใบเล็กที่รองรับน้ำค้างซึ่งใบหญ้าเก็บสะสมไว้ทีละหยดตลอดคืน แม้จะไม่ถึงหนึ่งอึกด้วยซ้ำ แต่ส่วนที่ใสสะอาดที่สุดของยามเช้าก็ขังอยู่ที่นั่นอย่างสงบนิ่ง"},"ICON-1626":{"nm":"กิ๊บริบบิ้นสายลม","de":"ริบบิ้นที่ผูกขึ้นตามลายที่ลมทิ้งไว้ขณะพัดผ่าน กลัดไว้บนผมแล้วทุกย่างก้าวจะมีสายลมอ่อน ๆ พลิ้วตามมาอย่างแผ่วเบา ความเบาสบายของวันฤดูใบไม้ผลิถูกผูกไว้อย่างเงียบ ๆ ในกิ๊บเพียงอันเดียว"},"ICON-1627":{"nm":"แคปซูลเสียงคลื่น","de":"แนบไว้ที่หูเบา ๆ แล้วคลื่นจากทะเลไกลก็ซัดเข้ามา ราวกับใครสักคนได้ผนึกเสียงที่เคยเก็บไว้ในเปลือกหอยสังข์สมัยเด็ก ๆ ลงในเม็ดเล็ก ๆ เม็ดหนึ่งอย่างทะนุถนอม"},"ICON-1628":{"nm":"เศษดาวในเม็ดทราย","de":"กำทรายบนหาดยามค่ำคืนสักกำมือ แล้วจะพบเศษดาวปะปนอยู่ระยิบระยับ จะตกลงมาจากฟ้าหรือคลื่นบดจนละเอียดกันแน่ ไม่มีใครอยากถามให้แน่ชัดนัก"},"ICON-1629":{"nm":"ชิปบันทึกสภาพอากาศเกาะ","de":"ท้องฟ้าของเกาะเปลี่ยนใจได้หลายครั้งในหนึ่งวัน จดบันทึกแดดจ้า หมอก และฝนซู่ลงในชิปเล็ก ๆ อย่างเป็นระเบียบ แล้ววันนี้ก็สามารถเปิดดูท้องฟ้าของเมื่อวานได้อีกครั้ง"},"ICON-1630":{"nm":"ชุดบันไดหน้าผา","de":"อีกขั้นหนึ่ง แล้วอีกขั้นหนึ่ง สำหรับขึ้นลงเนินชัน ประกอบชิ้นส่วนที่กระจัดกระจายเข้าด้วยกัน แล้วแม้แต่หน้าผาก็กลายเป็นทางเดินเล่นอันสบาย ๆ การสร้างทางเดินคือการวางก้าวต่อไปของใครสักคนไว้ล่วงหน้า"},"ICON-1631":{"nm":"ม้วนลายทางเดินดิน","de":"ม้วนกระดาษที่จำลองลายเนื้อของทางเดินดินอันนุ่มนวลไว้ทั้งหมด คลี่ออกด้วยเสียงซู่หนึ่งครั้ง แล้วทางเดินชนบทที่อยากให้เดินเท้าเปล่าก็ปูอยู่ใต้ฝ่าเท้าอย่างเงียบ ๆ"},"ICON-1632":{"nm":"ชิปลายทางเดินหินปู","de":"ลวดลายของแผ่นหินปูที่เคยปูตรอกซอกซอยเก่าแก่ถูกเก็บไว้ครบถ้วนในชิปเล็ก ๆ เม็ดหนึ่ง ทุกครั้งที่เหยียบลงไป เสียงก๊อกแก๊ก ฝีเท้าของหมู่บ้านเก่าแก่ก็ฟื้นคืนชีวิตขึ้นที่ปลายเท้า"},"ICON-1633":{"nm":"ชิ้นส่วนรั้วชายหาด","de":"รั้วเตี้ย ๆ ท่อนหนึ่งที่ปักไว้บนผืนทรายเพื่อไม่ให้คลื่นข้ามเข้ามา ผู้พิทักษ์แนวเขตแดนตัวเล็กและเงียบขรึม ยืนขีดเส้นอันอ่อนโยนระหว่างทะเลกับผืนทราย"},"ICON-1634":{"nm":"แผ่นซ่อมสนามหญ้า","de":"ชิ้นสีเขียวชิ้นหนึ่งที่ปูคลุมไว้เบา ๆ บนพื้นที่ถูกเหยียบย่ำจนโล่งเตียน ผ่านไปไม่กี่วันหญ้าก็จับมือกันเติมเต็มพื้นที่ว่างนั้นจนเต็ม ธรรมชาติรู้วิธีเยียวยาตัวเองอยู่เสมอ"},"ICON-1635":{"nm":"หลักปักบอกทางน้ำ","de":"หลักที่บอกล่วงหน้าว่าน้ำจะไหลไปทางไหน เพื่อไม่ให้น้ำฝนหลงทางว่าจะไปที่ใด ป้ายบอกทางเล็ก ๆ ที่ปักอยู่ในดินยืนตระหง่านอย่างเงียบขรึมแม้ในวันฝนตก"},"ICON-1636":{"nm":"ชิ้นส่วนสะพานเล็ก","de":"ชิ้นส่วนหนึ่งของสะพานเล็ก ๆ ที่เชื่อมสองฝั่งลำธารเข้าด้วยกัน คำสัญญาว่าจะข้ามไปมาได้ทุกเมื่อระหว่างฝั่งนี้กับฝั่งนั้น เริ่มต้นขึ้นอย่างเงียบ ๆ จากชิ้นส่วนเล็ก ๆ ชิ้นนี้เพียงชิ้นเดียว"},"ICON-1637":{"nm":"ฝาครอบราวจุดชมวิว","de":"จุดที่สูงที่สุดบนเกาะ ปลายชิ้นตกแต่งชิ้นหนึ่งที่หุ้มปลายราวกันตกไว้ มันคอยรองรับและปกป้องจุดที่มือของผู้คนที่มารวมตัวกันมองไปไกล ๆ สัมผัสบ่อยที่สุดอย่างเงียบ ๆ"},"ICON-1638":{"nm":"ฐานรองกองไฟแคมป์","de":"ก่อนวางฟืน จุดหนึ่งที่รองรับไม่ให้ประกายไฟกระจัดกระจาย เหนือมันคือค่ำคืนที่เคยเงยหน้าดูดาวและพูดคุยกันอย่างอบอุ่น ที่ยังคงเผาไหม้อย่างอบอุ่นต่อไปอีกยาวนาน"},"ICON-1639":{"nm":"ม้วนตัวอย่างวอลเปเปอร์","de":"บรรยากาศของห้องเริ่มต้นจากผนังเพียงด้านเดียว การคลี่ม้วนเล็ก ๆ ออกมาเลือกสีคือการวาดภาพล่วงหน้าอย่างเงียบ ๆ ว่าอยากใช้ชีวิตแบบไหนต่อจากนี้ไป"},"ICON-1640":{"nm":"ชิปตัวอย่างพื้น","de":"ลองสัมผัสสัมผัสของพื้นที่เท้าเปล่าจะแตะด้วยปลายนิ้วก่อน จะอุ่นหรือเย็น ความอบอุ่นของวันเวลาที่จะใช้ชีวิตต่อจากนี้แขวนอยู่กับชิปเล็ก ๆ แผ่นนี้เพียงแผ่นเดียว"},"ICON-1641":{"nm":"ชุดตะขอเพดาน","de":"ทันทีที่แขวนตะขอหนึ่งอันไว้บนคาน เพดานที่เคยว่างเปล่าก็กลายเป็นที่ที่รอคอยใครสักคน จะแขวนกระดิ่งลมดีหรือแขวนกระถางต้นไม้ดี ตะขอเหล็กเล็ก ๆ นี้แบกรับน้ำหนักได้ แต่จะแขวนอะไรนั้นขึ้นอยู่กับใจของผู้อยู่อาศัยเป็นผู้ตัดสิน"},"ICON-1642":{"nm":"ฟิล์มบังแดดหน้าต่าง","de":"แสงยามเที่ยงวันตรงเกินไป จึงเคลือบฟิล์มบาง ๆ ชั้นหนึ่งไว้ที่หน้าต่าง แสงแดดยังคงส่องเข้ามาเหมือนเดิม แต่ขอบมันอ่อนลง และทุกสิ่งในห้องก็นุ่มนวลเป็นสีส้มอมชมพู ไม่ใช่การปิดกั้น แต่เป็นการทำให้แสงกระจายไปอย่างอ่อนโยน"},"ICON-1643":{"nm":"ฝาครอบกริ่งประตู","de":"บอกว่าแม้แต่กริ่งที่แขกกดก็ต้องมีเสื้อผ้าสวมใส่ ใครสักคนจึงสวมฝาครอบทรงกลมให้มัน มันกันฝน กันฝุ่น และเหนือสิ่งอื่นใด มันคือปากกลมเล็ก ๆ ปากแรกที่ส่งคำทักทายว่า \"ที่นี่มีคนอาศัยอยู่\""},"ICON-1644":{"nm":"ขาตั้งสมุดเยี่ยม","de":"ขาตั้งที่ตั้งไว้ให้ทุกคนที่มาเยือนเขียนชื่อทิ้งไว้ก่อนจากไป ก่อนหมึกจะแห้ง ข้อความทักทายหนึ่งบรรทัดไหลออกมาจากปลายปากกา เมื่อรอยเท้าของผู้มาเยือนสะสมทีละบรรทัด สมุดว่างเปล่าก็กลายเป็นอัลบั้มที่หนาที่สุดของบ้านหลังนี้โดยไม่รู้ตัว"},"ICON-1645":{"nm":"หมุดจัดวางเฟอร์นิเจอร์","de":"ตำแหน่งโต๊ะที่ลังเลอยู่นานว่าจะย้ายดีไหม หมุดอันเดียวปักลงพื้นแล้วตัดสินใจให้ ตะปูเล็ก ๆ ที่ยึดปลายขาเฟอร์นิเจอร์ไว้เบา ๆ ตำแหน่งเมื่อกำหนดแล้วครั้งหนึ่ง ก็จะเกิดความผูกพัน พื้นไม้พยักหน้าเห็นด้วยอย่างเงียบ ๆ"},"ICON-1646":{"nm":"กรอบป้ายจัดเก็บ","de":"อะไรอยู่ตรงไหน ลิ้นชักไม่มีวันพูดออกมาได้ จึงสอดป้ายชื่อลงในกรอบสี่เหลี่ยมให้พูดแทน ทันทีที่ป้ายแผ่นหนึ่งลงตัว ช่องที่เคยรกรุงรังก็ได้ชื่อของตัวเองคืนมาและสงบลง"},"ICON-1647":{"nm":"แท่งกระจายกลิ่นห้อง","de":"กลิ่นหอมที่ชุ่มปลายแท่งค่อย ๆ แผ่ขึ้นด้านบนอย่างช้า ๆ บางครั้งเป็นลาเวนเดอร์ บางครั้งเป็นทุ่งหญ้าหลังฝนหยุด เมื่อกลิ่นที่มองไม่เห็นดั่งเส้นด้ายบาง ๆ เปลี่ยนอากาศในห้องไป ความเหนื่อยล้าของวันก็ค่อย ๆ คลายจากไหล่ของคนที่เพิ่งกลับบ้าน"},"ICON-1648":{"nm":"คลิปหนีบซองเมล็ดพันธุ์","de":"เมล็ดพันธุ์ที่ซื้อไว้ตั้งแต่ฤดูใบไม้ผลิแต่ปลูกไม่ทันหมด ถูกหนีบไว้แน่นหนาทั้งซองด้วยคลิป เพราะแม้แต่เมล็ดเดียวหลุดรอดออกไป ฤดูกาลหน้าก็จะลดลงไปหนึ่งแถว ในตัวล็อกเล็ก ๆ นั้น สวนผักของปีหน้าทั้งสวนกำลังหลับใหลอยู่"},"ICON-1649":{"nm":"ถาดเพาะกล้า","de":"เติมดินลงในแต่ละช่องเพื่อสร้างห้องแรกให้กับต้นกล้าน้อย ๆ หนึ่งชีวิตต่อหนึ่งหลุม นักเรียนใหม่ที่เติบโตเรียงแถวเป็นระเบียบ มองลงไปแล้วจะเห็นเช้าวันที่สีเขียวเรียกชื่อกันเป็นกลุ่ม ๆ เริ่มต้นใหม่ทุกวันบนถาดใบนี้"},"ICON-1650":{"nm":"หมุดสัญญาณรดน้ำ","de":"\"ฉันกระหายน้ำ\" กระถางต้นไม้พูดไม่ได้ ป้ายเล็ก ๆ ที่ปักอยู่ในดินจึงส่งสัญญาณแทน เมื่อสีเปลี่ยนคือถึงเวลารดน้ำ ล่ามที่เล็กที่สุดระหว่างพืชกับคนบรรจุอยู่ทั้งหมดในแท่งเล็ก ๆ ขนาดเท่าฝ่ามือนี้"},"ICON-1651":{"nm":"เชือกผูกค้ำต้นไม้","de":"ลำต้นที่กำลังสูงขึ้นอาจโอนเอนเพราะน้ำหนักตัวเอง จึงผูกไว้กับหลักค้ำด้วยเชือกอ่อนนุ่มอย่างเบามือ ผูกแน่นไปก็หายใจไม่ออก หลวมไปก็ล้ม มือที่ผูกจึงต้องการความอ่อนโยนพอเหมาะ แม้แต่การเติบโตก็ต้องการใครสักคนอยู่เคียงข้าง"},"ICON-1652":{"nm":"ตาข่ายกันแมลง","de":"ปากเล็ก ๆ ที่หมายตาใบอ่อน ถูกตาข่ายที่ถักไว้อย่างประณีตกั้นไว้เบา ๆ ปล่อยให้ลมและแสงแดดผ่านเข้ามาได้ กีดกันแต่สิ่งที่จะทำร้ายเท่านั้น ผู้เฝ้าประตูที่มองไม่เห็น สวนผักสงบสุขได้ก็เพราะความเอาใจใส่ที่ถักทอไว้ในตาข่ายถี่ ๆ นี้"},"ICON-1653":{"nm":"การ์ดวัดแสงแดด","de":"แดดส่องมาแค่ไหน การ์ดแผ่นหนึ่งที่ปักไว้ในแปลงดอกไม้จะถามอย่างเงียบ ๆ ยิ่งสีเข้มขึ้นเท่าไหร่ก็ยิ่งหมายถึงแสงที่ได้รับวันนี้มากเท่านั้น กระดาษแผ่นเล็ก ๆ นี้แบ่งพื้นที่ให้เด็กที่ชอบแดดกับเด็กที่สบายใจในร่มเงา"},"ICON-1654":{"nm":"แถบทดสอบความเป็นกรดด่างของดิน","de":"แตะแถบทดสอบลงบนดิน จากสีชมพูไปจนถึงสีฟ้า ผืนดินก็เผยความในใจออกมาเป็นสี ในจุดที่ไม่เปรี้ยวหรือขมเกินไป รากจะหายใจได้สบายที่สุด หัวใจของผืนดินที่เคยมองไม่เห็นถูกอ่านออกทีละช่อง"},"ICON-1655":{"nm":"ป้ายตะกร้าเก็บเกี่ยว","de":"สิ่งที่เก็บมาวันนี้เป็นผักกาดหอมหรือมะเขือเทศเชอร์รี ติดป้ายชื่อไว้ที่ตะกร้าแต่ละใบ เช้าวันเก็บเกี่ยวที่กลิ่นดินและกลิ่นเขียวปะปนกัน ทันทีที่ป้ายแผ่นหนึ่งติดลงไป ตะกร้าใบนั้นก็กลายเป็นหมุดหมายแรกบนเส้นทางสู่โต๊ะอาหาร"},"ICON-1656":{"nm":"ขวดเก็บเมล็ดพันธุ์","de":"เก็บเมล็ดพันธุ์ที่เก็บเกี่ยวได้ในปีนี้ใส่ขวดแก้วแล้วส่งไปให้ฤดูใบไม้ผลิถัดไป ปิดฝาแล้วเวลาก็หยุดนิ่งลงชั่วคราว เม็ดเล็ก ๆ รอคอยตาของตนอยู่ในความมืด มันคือขวดที่เหมือนจดหมายที่ส่งข้ามฤดูกาลไปทั้งฤดู"},"ICON-1657":{"nm":"เทปต่อกิ่ง","de":"ประกบกิ่งที่ถูกตัดเข้ากับกิ่งใหม่แล้วพันด้วยเทป ทั้งสองก็ค่อย ๆ กลายเป็นเนื้อเดียวกัน น้ำเลี้ยงไหลกลับมาอีกครั้งตรงรอยขาด บาดแผลค่อย ๆ หายไปทีละน้อย การต่อกิ่งในที่สุดแล้วก็คือการยอมรับลายเนื้อของกันและกัน"},"ICON-1658":{"nm":"ฝาครอบกรรไกรตัดกิ่ง","de":"สวมหมวกเล็ก ๆ ไว้ที่ปลายคมกรรไกรที่แหลมคม ระหว่างที่มือที่เคยตัดแต่งกิ่งพักผ่อน ใบมีดจะไม่ทื่อลงและมือจะไม่บาดเจ็บ บอกว่าแม้แต่เครื่องมือที่เสร็จงานแล้วก็ต้องการชุดนอน สวนผักจึงกล่อมเครื่องมือให้หลับอย่างทะนุถนอม"},"ICON-1659":{"nm":"กล่องแยกเมล็ดดอกไม้","de":"เทียนดัด แซงแซง ดอกไม้บ่าย เมล็ดที่ต่างชื่อต่างสีต่างได้ห้องของตัวเองในแต่ละช่อง เพราะถ้าปะปนกันแล้วพอถึงฤดูใบไม้ผลิก็จะแยกไม่ออกว่าใครเป็นใคร ผนังกั้นเล็ก ๆ ในกล่องวาดผังของสวนที่ยังไม่บานไว้ล่วงหน้า"},"ICON-1660":{"nm":"ล้อเลื่อนรองกระถาง","de":"ติดล้อสี่ล้อแล้วแม้แต่กระถางหนักก็ออกเดินตามแสงแดดไป หน้าต่างฝั่งตะวันออกในตอนเช้า ร่มเงาในตอนเที่ยง สีเขียวที่เคยติดตรึงอยู่กับที่ด้วยน้ำหนักก็กลิ้งเคลื่อนไปตลอดวัน ตามหาแสงและตำแหน่งที่ดีที่สุด"},"ICON-1661":{"nm":"เชือกนำทางเถาวัลย์","de":"มือเกาะของเถาวัลย์ที่คลำหาอากาศว่างเปล่าอย่างไม่รู้ว่าจะไปทางไหน เชือกจะค่อย ๆ นำมันไปสู่ทางที่ถูกต้อง ขึ้นไป และสูงขึ้นไปอีก กำหนดที่ให้เกาะแล้วต้นไม้ก็จะจับมือนั้นไว้อย่างน่าอัศจรรย์ แม้แต่การเติบโตก็ต้องการผู้นำทางสักคน"},"ICON-1662":{"nm":"ที่ตั้งการ์ดภาษาดอกไม้","de":"การ์ดที่ปักไว้ข้างดอกไม้บันทึกคำพูดที่ดอกไม้นั้นส่งมาให้ ไฮเดรนเยียบอกว่าจริงใจ เดซี่บอกว่าบริสุทธิ์ เพื่อให้การเดินชมแปลงดอกไม้กลายเป็นการเดินเล่นอ่านจดหมาย ที่ตั้งการ์ดเล็ก ๆ จึงยืมปากของดอกไม้ที่พูดไม่ได้มาใช้เบา ๆ"},"ICON-1663":{"nm":"ฝาครอบป้ายสวน","de":"กลัวว่าลมฝนจะทำให้ตัวหนังสือเลอะเลือน จึงสวมหมวกใสไว้บนป้ายสวน \"มะเขือเทศตรงนี้\" \"โหระพาตรงนี้\" ชื่อที่เกือบจะเลือนหายยังคงชัดเจนอยู่ แม้ผ่านไปหนึ่งปี สวนผักก็ไม่ลืมสมาชิกของตนแม้แต่คนเดียว"},"ICON-1664":{"nm":"ช้อนตวงปุ๋ย","de":"เวลาเติมสารอาหารลงในดิน ความโลภกลับทำให้รากไหม้เกรียม จึงให้แค่หนึ่งช้อน แค่นั้นพอดี ช้อนเล็ก ๆ ตักปริมาณที่พอเหมาะขึ้นมาบอกเรา หัวใจที่เลี้ยงดูเก่งมักมาจากปลายนิ้วที่รู้จักความพอดีเสมอ"},"ICON-1665":{"nm":"หัวฉีดพ่นละอองน้ำ","de":"หมุนหัวฉีดแล้วสายน้ำจะกระจายลงมาเป็นละอองดั่งหมอก ใบอ่อนที่เคยถูกสายน้ำแรงกล้าซัดจนช้ำ ค่อย ๆ เงยหน้าขึ้นอย่างอ่อนโยนใต้หยดน้ำดั่งน้ำค้าง น้ำแบบเดียวกันแต่ให้ไปต่างวิธีกัน กลับกลายเป็นคำทักทายที่แตกต่างกันโดยสิ้นเชิง"},"ICON-1666":{"nm":"ถ้วยตวงอาหารสัตว์","de":"หนึ่งถ้วย สองถ้วย ตวงหนึ่งมื้อของเพื่อนด้วยความใส่ใจ ไม่ใช่การกะเอา มากไปก็เหลือทิ้ง น้อยไปก็น้อยใจ จึงต้องคำนวณปริมาณที่พอดี บางครั้งความรักก็มาในรูปของการตวงอย่างพิถีพิถันเช่นนี้"},"ICON-1667":{"nm":"ฝาครอบหวีขนช่วงผลัดขน","de":"ฤดูผลัดขน ฝาครอบห่อหุ้มขนอ่อนนุ่มที่พันอยู่บนหวีไว้อย่างทะนุถนอม สวมหมวกให้หวีหลังแปรงเสร็จแล้ว วันรุ่งขึ้นก็เริ่มต้นสดใสฟูนุ่มอีกครั้ง ความเงางามของสมาชิกในบ้านที่อยู่ด้วยกันเติบโตขึ้นอย่างเงียบ ๆ จากการจัดเก็บเล็ก ๆ เช่นนี้"},"ICON-1668":{"nm":"ฝาครอบกรรไกรตัดเล็บ","de":"สวมฝาเล็ก ๆ ไว้ที่ปลายกรรไกรตัดเล็บอันแหลมคม เพื่อไม่ให้เครื่องมือที่เสร็จงานแล้วไปข่วนสิ่งของอื่นในลิ้นชัก หลังจากช่วงเวลาแห่งการดูแลจบลง การปลอบเครื่องมือให้หลับพักคือส่วนสุดท้ายของวงจรการดูแลเอาใจใส่"},"ICON-1669":{"nm":"จี้ประดับปลอกคอ","de":"แขวนจี้ระยิบระยับหนึ่งชิ้นไว้ที่ปลอกคอ แล้วเส้นทางเดินเล่นเดิม ๆ ก็พิเศษขึ้นอีกนิด เครื่องประดับเล็ก ๆ ที่ระยิบระยับในแสงแดด แม้ไม่หรูหรา แต่ก็เพียงพอที่จะเป็นเครื่องหมายว่าเจ้าตัวนี้คือสมาชิกในครอบครัวที่ใครสักคนรักมาก"},"ICON-1670":{"nm":"การ์ดสุขภาพสัตว์เลี้ยง","de":"วันนี้กินดีไหม มีตรงไหนเจ็บป่วยหรือเปล่า จดวันหนึ่งของเพื่อนที่อยู่ด้วยกันลงในการ์ดทีละบรรทัด เมื่ออาการของสมาชิกในครอบครัวที่พูดไม่ได้ถูกบันทึกเป็นลายลักษณ์อักษร หัวใจที่ดูแลก็ยิ่งละเอียดรอบคอบและมั่นคงขึ้นตามไปด้วย"},"ICON-1671":{"nm":"ปลอกเบาะที่นอน","de":"สวมเสื้อผ้าใหม่ที่นุ่มฟูให้เบาะที่นอน ถอดผ้าเก่าที่สึกหรอจากการกลิ้งไปมาออก แล้วกลิ่นขนฟูที่ตากแดดจะลอยฟุ้งขึ้นมา การดูแลตำแหน่งที่นอนบ่อยที่สุดให้สะอาดที่สุด คือความใส่ใจในทุก ๆ วันเพื่อสมาชิกที่อยู่ด้วยกัน"},"ICON-1672":{"nm":"หมุดรั้วเล็ก","de":"ปักหมุดเล็ก ๆ เรียงรายไว้ตามขอบแปลงดอกไม้เพื่อสร้างรั้วเตี้ย ๆ ไม่ใช่คำขู่ว่าห้ามข้าม แต่เป็นเขตแดนอันอ่อนโยนที่บอกว่าตรงนี้คือที่ของดอกไม้ ต่อเมื่อมีเส้นที่ปกป้อง ดอกไม้จึงเติบโตได้อย่างสบายใจภายในนั้น"},"ICON-1673":{"nm":"กระปุกขนมสร้างความคุ้นเคย","de":"แม้แต่เด็กขี้อายก็เงี่ยหูฟังเสียงเขย่ากระปุกใบนี้ ข้างในบรรจุขนมกำมือหนึ่งที่เปิดใจได้ การจะสนิทสนมกันนั้น คำสัญญาเล็ก ๆ เร็วกว่าคำพูดเสียอีก เสียงกรุ๊งกริ๊งจึงก้าวเข้าไปหาก่อนใคร"},"ICON-1674":{"nm":"แท็กบันทึกเดินเล่น","de":"วันนี้เดินทางไหนไปไกลแค่ไหน ผูกบันทึกไว้ที่แท็กดั่งปมเชือก รอยเท้าที่สะสมกันกลายเป็นแผนที่ แผนที่ที่สะสมกันกลายเป็นความทรงจำ ทุกวันที่เดินไปด้วยกันสะสมอยู่บนป้ายเล็ก ๆ นี้อย่างเรียบร้อย"},"ICON-1675":{"nm":"จานให้อาหารนก","de":"วางจานไว้ที่ขอบหน้าต่างแล้วโรยเมล็ดข้าวฟ่างสักหยิบมือ แขกไม่ทราบชื่อก็บินเข้ามาทีละตัว เสียงจิกอาหารก๊อกแก๊ก เสียงกระพือปีกพรืดพราด กำมือที่ให้ไปกลายเป็นคอนเสิร์ตเล็ก ๆ ทุกเช้า มันคือโต๊ะอาหารตัวจิ๋ว"},"ICON-1676":{"nm":"กล่องส่องดูกระรอก","de":"ในกล่องใสเราสบตากับดวงตากลมโตของกระรอก แก้มยัดเต็มไปด้วยลูกโอ๊กพลางเอียงคอมอง ช่างเป็นภาพที่น่ารัก บนคำสัญญาว่าจะแอบดูสักครู่แล้วปล่อยกลับไป เราแลกทักทายสั้น ๆ กับธรรมชาติป่าเถื่อนตัวจิ๋ว"},"ICON-1677":{"nm":"แม่พิมพ์ปูนรอยเท้า","de":"เทปูนปลาสเตอร์ที่นิ่มลงไปเพื่อหล่อรอยเท้าเล็ก ๆ ระหว่างรอให้แข็งตัว เวลาของสนามหญ้าก็หยุดนิ่งไปชั่วครู่ รอยประทับเท้าขนาดเท่าฝ่ามือที่จะหายไปเมื่อโตขึ้น แม่พิมพ์สีขาวยกมันขึ้นดั่งความเป็นนิรันดร์แล้ววางไว้ในมือทั้งสองอย่างเบามือ"},"ICON-1678":{"nm":"ฝาปิดเลนส์กล้องส่องกลางคืน","de":"ปิดฝาเล็ก ๆ ไว้ที่ปลายเลนส์ที่จ้องมองยามค่ำคืน เพื่อให้ผิวแก้วที่เคยมองเห็นดวงดาวและรังนกรอคอยค่ำคืนถัดไปโดยไม่มีฝุ่นแม้แต่เม็ดเดียว แม้แต่ดวงตาที่มองเห็นความมืดอย่างชัดเจนก็ต้องการเครื่องหมายจุลภาคแห่งการพักผ่อนสักหนึ่งจุดในยามกลางวัน"},"ICON-1679":{"nm":"ป้ายปกป้องรังนก","de":"พบรังนกอยู่ท่ามกลางกิ่งไม้ แทนที่จะเข้าไปใกล้ ให้ปักป้ายไว้แทน \"ที่นี่มีครอบครัวนกอาศัยอยู่ กรุณาเงียบ ๆ\" การเฝ้ามองโดยไม่ล่วงล้ำ ระยะห่างอันอ่อนโยนหนึ่งก้าวนั้นเองที่ทำให้รังปลอดภัยที่สุด"},"ICON-1680":{"nm":"ชิปบันทึกเสียงสัตว์","de":"บทเพลงจากพุ่มหญ้า เสียงจิ๊บจ๊อยใต้ชายคา เสียงแมลงกลางคืน แทนที่จะกักขังไว้ในชิป เรากลับยืมมันมาไว้สักพัก เปิดฟังอีกครั้งแล้วแม้แต่อากาศของช่วงเวลานั้นก็ฟื้นคืนชีวิตขึ้นมา กล่องเสียงเล็ก ๆ ที่ทำให้ทุกสิ่งที่เคยได้ยินไม่มีวันเลือนหายไป"},"ICON-1681":{"nm":"ผ้าคลุมกล้องส่องทางไกล","de":"ก่อนที่นกตัวหนึ่งจะบินขึ้นสู่ท้องฟ้า ป่าไม้จะหยุดหายใจไว้ชั่วครู่ ในช่วงเวลาแห่งความเงียบงันนั้น ผ้าผืนหนึ่งที่คลุมเลนส์ไว้ ปกป้องความคมชัดของที่ไกลไว้โดยไม่ให้แม้แต่รอยนิ้วมือมาแตะต้อง"},"ICON-1682":{"nm":"สายกล้องเส้นทางป่า","de":"ทุกครั้งที่ไต่ทางป่าอันชันขึ้น กล้องจะกระทบหน้าอกเบา ๆ เป็นจังหวะ จังหวะหัวใจที่เต้นตึกตักกับเสียงชัตเตอร์แกว่งไกวไปในจังหวะเดียวกัน สายเส้นนี้ยึดช่วงเวลาเหล่านั้นไว้ที่หน้าอกอย่างมั่นคง"},"ICON-1683":{"nm":"การ์ดคำอธิบายธรรมชาติ","de":"แม้แต่ต้นหญ้าเพียงกอเดียวก็มีชื่อ การ์ดจะบอกไว้อย่างเงียบ ๆ เมื่อสิ่งที่เคยเดินผ่านโดยไม่รู้จักได้รับชื่อเรียก เส้นทางบนภูเขาก็เริ่มคึกคักไปด้วยใบหน้าคุ้นเคยอย่างอบอุ่นในทันใด"},"ICON-1684":{"nm":"แผ่นปะซ่อมใบเรือ","de":"แม้แต่ผืนผ้าที่รับแรงลมด้วยทั้งตัวก็ยังมีรอยแผลเป็น ด้วยผ้าปะเล็ก ๆ ชิ้นหนึ่งที่แปะไว้เบา ๆ ตรงจุดที่ฉีกขาด ใบเรือจึงได้รับสิทธิ์อีกครั้งในการโอบอุ้มทะเลกว้างไกล"},"ICON-1685":{"nm":"กระดานฝึกผูกเงื่อน","de":"ขึ้น ลง แล้วพันอีกรอบหนึ่ง—ลำดับที่มือจดจำไว้กลายเป็นเงื่อน ในค่ำคืนที่พายุกระหน่ำดาดฟ้าเรือ ขั้นตอนเดียวนั้นเองที่ผูกคนกับเรือเข้าไว้ด้วยกันเป็นหนึ่งเดียว"},"ICON-1686":{"nm":"ฝาครอบโซ่สมอเรือ","de":"อย่าดูแคลนหมวกเล็ก ๆ ใบนี้ที่สวมไว้ที่ปลายโซ่เหล็ก สนิมเติบโตขึ้นอย่างเงียบ ๆ อยู่ภายใน ฝาครอบเพียงชิ้นเดียวที่ยืนต้านลมทะเลจึงยืดอายุการใช้งานของสมอเรือได้อย่างเงียบ ๆ"},"ICON-1687":{"nm":"ธงบอกเส้นทางเดินเรือ","de":"วันที่หมอกหนาจนมองไม่เห็นทางข้างหน้า ธงผืนหนึ่งจะบอกทางแทน จุดสีหนึ่งจุดที่พลิ้วไสวในสายลม ในที่สุดก็คลายบ่าที่เกร็งของนายท้ายเรือที่หลงทางให้ผ่อนคลายลง"},"ICON-1688":{"nm":"พวงกุญแจห้องโดยสารเรือ","de":"เหนือทะเลที่โคลงเคลง ห่วงเล็ก ๆ ห่วงหนึ่งแขวนอยู่ที่ประตูห้องโดยสารแคบ ๆ ตราบใดที่กุญแจยังอยู่ในที่ของมัน ห้องหนึ่งที่จะกลับไปก็จะไม่มีวันถูกล็อกไว้จากเธอ"},"ICON-1689":{"nm":"ซองแผนที่กันน้ำ","de":"ในสายฝน แผนที่กระดาษจะลบเส้นทางไปก่อนสิ่งอื่นใด ขณะที่แผ่นหนึ่งยังคงแห้งสนิทอยู่ในซองใส แม้แต่การเดินทางที่เปียกโชกก็จะไม่มีวันหลงทิศทาง"},"ICON-1690":{"nm":"ไส้ตะเกียงเรือ","de":"น้ำมันที่ไส้ตะเกียงค่อย ๆ ดูดขึ้นมาในที่สุดก็ผลิบานเป็นเปลวไฟ แสงหนึ่งจุดบนดาดฟ้าเรือ กับการสั่นไหวเล็ก ๆ นั้นเอง ระยะทางอันไกลโพ้นของทะเลยามค่ำคืนก็ค่อย ๆ เข้ามาใกล้ขึ้นอย่างแผ่วเบา"},"ICON-1691":{"nm":"ผ้าสัญญาณขอความช่วยเหลือ","de":"ในระยะทางที่เสียงไม่อาจไปถึง มือที่โบกผ้าสีแดงขึ้นสูงเดินทางได้ไกลกว่าคำพูด ผ้าผืนนี้ตัดผ่านสายลม ร้องตะโกนแทนว่าที่นี่ยังมีใครบางคนมีชีวิตอยู่"},"ICON-1692":{"nm":"หมุดบอกทิศลมทะเล","de":"ผู้ที่รู้ว่าลมพัดมาจากทิศใดคือผู้กำหนดเส้นทางเดินเรือ ทิศทางเดียวที่หมุดเล็ก ๆ ชี้ไว้อย่างเงียบ ๆ นั้น โชคชะตาของการเดินเรือตลอดทั้งวันนี้พลันเอนเอียงเข้ามาพึ่งพา"},"ICON-1693":{"nm":"ปลอกครอบพลั่วพับ","de":"พับใบพลั่วแล้วปิดคลุมไว้ แม้แต่พลั่วที่ขยันขันแข็งก็ได้พักหายใจสักครู่ สิ่งสุดท้ายที่มือซึ่งขุดดินมาตลอดทำ คือการดูแลใบมีดของวันพรุ่งนี้ไม่ให้ทื่อลง"},"ICON-1694":{"nm":"ซองเข็มทิศพกพา","de":"เข็มชี้ไปทางเหนือเสมอโดยไม่สั่นไหว แต่สิ่งที่ปกป้องเข็มนั้นไว้คือซองที่แข็งแรง คนที่เคยหลงทางมาแล้วสักครั้ง ยิ่งโอบกอดทิศทางไว้อย่างล้ำค่ามากขึ้นเท่านั้น"},"ICON-1695":{"nm":"ตาข่ายผึ่งจานแคมป์","de":"แขวนจานที่ล้างแล้วไว้ในตาข่ายให้แห้งในแดดยามเช้า วันหนึ่งของค่ายพักแรมเริ่มต้นด้วยเสียงน้ำแห้งไป และความเล็กน้อยนั้นเองที่เติมเต็มภายในเต็นท์ให้อบอุ่นมั่นคง"},"ICON-1696":{"nm":"บัตรอนุญาตตั้งแคมป์","de":"การอนุญาตให้พักค้างคืนบนภูเขาแห่งนี้ได้ ทันทีที่กระดาษแผ่นหนึ่งอยู่ในมือ แม้แต่ป่าที่แปลกหน้าก็กลายเป็นพวกพ้องของเราชั่วคราว และรับเต็นท์เล็ก ๆ ไว้อย่างอ่อนโยน"},"ICON-1697":{"nm":"เชือกธงเส้นทางสำรวจ","de":"ผูกธงไว้ที่ทางแยกทุกแห่ง แล้วทางกลับจะไม่กระจัดกระจายหายไปในความมืด สัญลักษณ์เล็ก ๆ ที่คนซึ่งเดินนำหน้าทิ้งไว้ ผลักหลังของฝีเท้าที่ตามมาให้ก้าวต่อไปอย่างเงียบ ๆ"},"ICON-1698":{"nm":"กระปุกไม้ขีดกันน้ำ","de":"ไม้ขีดเปียกเพียงหยดเดียวก็เงียบงันไปตลอดกาล ในกระปุกที่ปิดผนึกไม่ให้น้ำแม้แต่หยดเดียวเล็ดลอดเข้าไปได้ ประกายไฟรอคอยอยู่อย่างแห้งสนิทและนิ่งเงียบ เพื่อค่ำคืนที่หนาวเหน็บที่สุดเท่านั้น"},"ICON-1699":{"nm":"ที่กรองน้ำพกพา","de":"แม้แต่น้ำขุ่นที่ทำให้ลังเล เมื่อผ่านตัวกรองนี้ก็จะใสสะอาดขึ้น อุปกรณ์เล็ก ๆ ที่วางความสงสัยลงก่อนความกระหาย ความเชื่อว่าดื่มได้นั้นเองคือการพักใจในหนึ่งอึก"},"ICON-1700":{"nm":"ผ้าห่มฉุกเฉินแบบพับเก็บ","de":"พับแล้วเล็กเท่าฝ่ามือ คลี่ออกแล้วกลายเป็นความอบอุ่นของคนหนึ่งคน เพื่อให้คำว่า \"ฉุกเฉิน\" ไม่หนักหนาเกินไป ผ้าห่มจึงรอคอยพร้อมที่จะอบอุ่นอยู่เสมอในมุมหนึ่งของกระเป๋า"},"ICON-1701":{"nm":"สร้อยข้อมือส่องสัญญาณยามค่ำคืน","de":"บนเส้นทางภูเขาที่ความมืดปกคลุม ข้อมือข้างหนึ่งเปล่งแสงสงบนิ่งอยู่เบาๆ แถบเล็กๆ ที่บอกตำแหน่งของกันและกันนั้น ผูกโยงผู้ที่เดินไปด้วยกันไว้ด้วยเส้นด้ายล่องหนอันอ่อนโยน"},"ICON-1702":{"nm":"สติกเกอร์หมวกคนงานเหมือง","de":"สติกเกอร์ที่ติดอยู่บนหมวกคือป้ายชื่ออีกใบหนึ่งของคนงานเหมือง ในอุโมงค์ลึกที่แม้แต่แสงสว่างยังหายาก เขาจดจำเพื่อนร่วมงานได้อย่างอบอุ่นใจจากภาพเล็กๆ ที่สะท้อนแสงตะเกียงนั้น"},"ICON-1703":{"nm":"เข็มหมุดปักบอกสายแร่","de":"ตรงจุดที่พบสายแร่ เขาค่อยๆ ปักเข็มหมุดไว้เบาๆ จุดสว่างเพียงจุดเดียวที่ส่องประกายอยู่ท่ามกลางความมืด บอกกล่าวอย่างอ่อนโยนแก่ผู้ที่จะมาถึงต่อไปว่าให้เริ่มขุดจากตรงนี้"},"ICON-1704":{"nm":"ไม้บรรทัดวัดรอยร้าว","de":"การวัดรอยแตกที่แยกผนังคือความอดทนอันเชื่องช้าและไม่ย่อท้อ รอยนั้นถ่างกว้างขึ้นอีกหนึ่งฝ่ามือจากเมื่อวานหรือไม่ ตัวเลขเล็กๆ ที่ไม้บรรทัดบอกไว้ ช่วยจับสัญญาณการถล่มไว้ได้ล่วงหน้า"},"ICON-1705":{"nm":"กระดาษถูลายโบราณสถาน","de":"วางกระดาษทาบลงบนลวดลายที่สลักไว้บนหิน แล้วค่อยๆ เคาะหมึกลงเบาๆ ในวินาทีที่สัมผัสมือจากพันปีก่อนปรากฏขึ้นเป็นลายเส้นสีดำ การถูลายจึงเชื้อเชิญให้กาลเวลาที่ล่วงเลยไปแล้วมานั่งประจันหน้ากับเราชั่วขณะหนึ่ง"},"ICON-1706":{"nm":"กล่องเหรียญโบราณ","de":"โลหะชิ้นเล็กๆ ที่หลับใหลอย่างสงบโดยไม่เป็นสนิมนี้ เก็บรักษาเสียงสุดท้ายของชาติที่สาบสูญไปแล้วไว้ในตัว เหรียญเพียงเหรียญเดียวบรรจุยุคสมัยหนึ่งเอาไว้ทั้งหมด ค่อยๆ แก่เฒ่าลงอย่างช้าๆ ภายในกล่องใส"},"ICON-1707":{"nm":"ฐานวางเศษคริสตัล","de":"แม้แต่คริสตัลที่กักแสงไว้ภายในตัวเองก็ยังต้องการที่พึ่งพิง ในวินาทีที่มันถูกวางลงเบาๆ บนฐานเล็กๆ สิ่งที่แตกหักง่ายจึงได้เผยความงามอันแวววาวของตนออกมาอย่างเต็มที่เป็นครั้งแรก"},"ICON-1708":{"nm":"เศษแผนที่ถ้ำ","de":"แผนที่ที่ฉีกขาดเผยให้เห็นความลับเพียงครึ่งเดียวอย่างแอบแฝง จนกว่าจะถึงวันที่พบชิ้นส่วนที่เหลือ กระดาษแผ่นนี้จะเก็บเส้นทางที่ยังเหลืออยู่ไว้ครึ่งหนึ่งในที่ใดที่หนึ่งของถ้ำ"},"ICON-1709":{"nm":"ห่วงเหล็กโรยตัว","de":"หากจะปล่อยกายลงจากหน้าผา ต้องเชื่อใจห่วงเหล็กนี้อย่างเต็มที่เสียก่อน การฝากน้ำหนักทั้งหมดไว้กับเหล็กเย็นชิ้นเดียว—ความไว้วางใจโดยธรรมชาติแล้วก็หนักแน่นเช่นนี้เอง"},"ICON-1710":{"nm":"ใบอนุญาตขุดค้น","de":"กระดาษแผ่นเดียวที่ประทับตราชัดเจนว่าอนุญาตให้ขุดดินได้ หากจะปลุกสิ่งที่ถูกฝังไว้ให้ตื่นขึ้น จงขออนุญาตก่อนเป็นอันดับแรก การขุดค้นสอนอย่างเงียบๆ ว่าทุกสิ่งควรเริ่มต้นด้วยความสุภาพ"},"ICON-1711":{"nm":"แผงกันลมพกพา","de":"กางออกโดยหันหลังให้ลม แล้วพื้นที่สงบขนาดหนึ่งตารางก็ผุดขึ้นกลางทุ่งที่ลมพัดกระหน่ำ หลังชั้นบางๆ นี้ปกป้องประกายไฟเล็กๆ ไว้ และให้คนที่เหนื่อยล้าได้พักสักครู่"},"ICON-1712":{"nm":"ฝาครอบแว่นกันพายุทราย","de":"แม้ทรายจะพัดกระหน่ำอย่างดุร้ายเพียงใด อย่างน้อยที่สุดการมองเห็นก็ต้องรักษาไว้ให้ถึงที่สุด ฝาครอบบางๆ ที่คลุมแว่นตาแผ่นเดียว กลายเป็นความกล้าหาญที่ทำให้ยังลืมตาเดินหน้าต่อไปได้ แม้ท่ามกลางพายุ"},"ICON-1713":{"nm":"ถาดรับรองแขกยามฝนตก","de":"หยดน้ำฝนหยดลงจากปลายรองเท้าของแขกที่มาเยือน ถาดใบหนึ่งที่วางไว้เงียบๆ หน้าประตูบ้าน รองรับปลายเท้าที่เปียกและเย็นเยียบไว้อย่างอบอุ่นโดยไม่ต้องเอ่ยคำใด"},"ICON-1714":{"nm":"ป้ายเย็นคลายร้อน","de":"ป้ายเล็กๆ ที่คอยคลายความร้อนยามเที่ยงวันอย่างแผ่วเบา ห้อยอยู่ที่กระเป๋าพร้อมเก็บความเย็นไว้ในตัว แล้วเมื่อหยาดเหงื่อเริ่มผุดขึ้น มันก็แอบยื่นร่มเงาเล็กๆ กำมือหนึ่งมาให้"},"ICON-1715":{"nm":"เข็มขัดกระเป๋าไฟรอบเอว","de":"เข็มขัดอุ่นๆ ที่พันรอบเอวเพียงรอบเดียว เมื่อความร้อนจากกระเป๋าไฟค่อยๆ แผ่ซ่านขึ้นไปตามแผ่นหลัง แม้แต่ทุ่งกลางฤดูหนาวอันหนาวเหน็บก็พอจะทนได้มากขึ้นสักหน่อย"},"ICON-1716":{"nm":"ซองดูดความชื้น","de":"ความอับชื้นกัดกินสิ่งของโดยไม่มีแม้แต่เสียงเตือน ขณะที่ซองเล็กๆ ในกล่องคอยดูดซับความชื้นไว้อย่างเงียบๆ สิ่งของที่รักและหวงแหนก็ยังคงรูปลักษณ์แห้งสนิทของตนไว้ได้"},"ICON-1717":{"nm":"ผ้าคลุมรองเท้ากันโคลน","de":"บางครั้งแม้ต้องเดินย่ำโคลน รองเท้าก็ยังต้องสะอาดอยู่เสมอ ผ้าคลุมบางๆ ที่กันโคลนไว้แผ่นนี้ ทำให้ฝีก้าวที่ก้าวข้ามธรณีประตูกลับบ้านเบาสบายขึ้นอีกมาก"},"ICON-1718":{"nm":"ฝาครอบตะเกียงกันหมอกทะเล","de":"เมื่อหมอกทะเลพยายามกลืนกินแสงตะเกียงทั้งดวง ฝาครอบนี้จะรวบรวมริ้วแสงที่กระจัดกระจายไว้อย่างเงียบๆ แม้ในยามรุ่งสางอันพร่ามัว แสงไฟท่าเรือดวงหนึ่งก็ไม่มีวันดับลงจนถึงที่สุด"},"ICON-1719":{"nm":"เข็มกลัดเตือนภัยฟ้าผ่า","de":"เมื่อเมฆดำลอยต่ำลงมา เข็มกลัดเพียงตัวเดียวจะส่งสัญญาณเตือนก่อนใคร คำเตือนให้ก้มตัวลงต่ำก่อนที่ฟ้าจะผ่า—ความอ่อนน้อมต่อธรรมชาตินั้นเรียนรู้ไว้ล่วงหน้าเสมอย่อมดีกว่า"},"ICON-1720":{"nm":"ที่คั่นหนังสือสูตรอาหาร","de":"ที่คั่นหนังสือเล็กๆ ที่สอดไว้ระหว่างหน้าตำราอาหารที่เปิดค้างอยู่ เมื่อคลำหาบรรทัดที่พลาดไปตอนยืนอยู่หน้าเตาอีกครั้ง รสมือแม่ก็ตื่นขึ้นพร้อมกันบนหน้ากระดาษนั้นด้วย"},"ICON-1721":{"nm":"แท่งตวงเครื่องปรุง","de":"แม่มักพูดแค่ว่า \"หยิบมือหนึ่ง\" เสมอ ทั้งที่การกะด้วยสายตาไม่มีทางแม่นยำได้ แต่รสมือนั้นกลับไม่เคยผิดเพี้ยนเลยสักครั้ง เมื่อใช้แท่งนี้ตวงเกลือดู จะพบว่าสิ่งที่บ่มมานานยิ่งกว่าการตวงวัดคือความรักนั่นเอง ไม่ใช่การกะประมาณ"},"ICON-1722":{"nm":"สายรัดฝาไหหมัก","de":"รู้ไหมว่าไหก็หายใจได้เหมือนกัน เมื่อสายรัดนี้โอบกอดฝาไหไว้แน่นพอดี ภายในกับภายนอกก็ค่อยๆ เริ่มพูดคุยกัน ต่อเมื่อวันเวลาที่ไม่เร่งรีบเหล่านั้นผ่านไปหลายวัน การรอคอยจึงได้ชื่อว่ารสชาติในที่สุด"},"ICON-1723":{"nm":"ป้ายชิปบันทึกวันหมักบ่ม","de":"ชิปเล็กๆ ที่เขียนวันที่หมักดองไว้อย่างเรียบร้อย ตัวหนังสือค่อยๆ จางลงในขณะที่สิ่งที่อยู่ภายในกลับยิ่งลึกซึ้งขึ้น จดไว้ราวกับแกล้งลืม แล้ววันหนึ่งก็หยิบมันออกมาดูอีกครั้งโดยไม่ทันตั้งตัว การหมักบ่มคือคำสัญญาที่รักษาไว้เช่นนั้นเอง"},"ICON-1724":{"nm":"ตะแกรงกรองน้ำซุป","de":"น้ำซุปใสสะอาดมาได้ก็ต่อเมื่อกรองแล้วกรองอีก มองตะแกรงที่กักเก็บเศษวัตถุดิบไว้และปล่อยให้ไหลผ่านแต่เพียงส่วนที่เป็นแก่นแท้ คำกล่าวเก่าแก่ของครัวโบราณที่ว่าความล้ำลึกจะสะสมอยู่ตรงจุดที่ตัดทิ้งไปนั้น ก็ส่งผ่านมาถึงปลายนิ้ว"},"ICON-1725":{"nm":"ผ้าคลุมหมักแป้ง","de":"คลุมผ้าผืนหนึ่งไว้เบาๆ บนก้อนแป้ง ขณะที่ยีสต์ค่อยๆ พองฟูขึ้นอย่างขยันขันแข็งใต้ความมืดครึ้มนั้น เราจึงได้เรียนรู้ความอ่อนโยนของสิ่งที่เติบโตอย่างเงียบๆ ในที่ที่มองไม่เห็นเป็นครั้งแรก"},"ICON-1726":{"nm":"เข็มหมุดเตรียมวัตถุดิบ","de":"เข็มหมุดเล็กๆ ที่แยกเส้นใยต้นหอมและจับกระเทียมไว้อย่างมั่นคง การเตรียมวัตถุดิบเปรียบดั่งคำทักทายแรกที่มอบให้แก่วัตถุดิบ ยิ่งตกแต่งอย่างพิถีพิถันมากเท่าไร แสงบนโต๊ะอาหารมื้อเย็นก็ยิ่งสว่างขึ้นอีกหนึ่งเฉด"},"ICON-1727":{"nm":"คีมจัดจานอาหาร","de":"จะวางชิ้นสุดท้ายบนจานตรงไหนดี สุดท้ายแล้วคีมนี้คือผู้ตัดสิน ในช่วงเวลาสั้นๆ ที่มือผู้ชำนาญลังเลอยู่กลางอากาศครึ่งจังหวะ มื้ออาหารมื้อหนึ่งก็แปรเปลี่ยนเป็นภาพวาดหนึ่งภาพอย่างแนบเนียน"},"ICON-1728":{"nm":"ผ้าห่อกล่องข้าวเก็บความอุ่น","de":"กล่องข้าวที่รับมาหน้าประตูโรงเรียนต้องอุ่นอยู่จนกว่าจะถึงเวลากระดิ่งพักเที่ยง ความอบอุ่นที่ถูกกักไว้ในผ้าห่อนี้ ไม่เย็นลงเลย มากเท่ากับความหนาแน่นของหัวใจของใครบางคนที่ยืนอยู่หน้าเตาไฟตั้งแต่ฟ้ายังไม่สาง"},"ICON-1729":{"nm":"บัตรเชิญร่วมโต๊ะอาหาร","de":"\"มากินข้าวที่บ้านเราสักครั้งสิ\" มีคำพูดใดจะอบอุ่นไปกว่านี้อีกหรือ ไม่มีคำสัญญาอันยิ่งใหญ่ใดๆ เพียงแค่ชวนมานั่งโต๊ะเดียวกัน คำเชื้อเชิญที่เก่าแก่ที่สุดที่ภาษาเกาหลีมอบให้ได้นั้น บรรจุอยู่ในบัตรใบเดียวนี้"},"ICON-1730":{"nm":"ชิปจองโต๊ะ","de":"เขียนชื่อไว้แล้วจองที่นั่งเก็บไว้ ในขณะที่ชิปเล็กๆ ผูกโต๊ะที่ว่างเปล่าไว้ให้เป็นของใครสักคนชั่วคราว เวลาที่นัดหมายไว้ก็ค่อยๆ ใกล้เข้ามาช้าๆ ราวกับเสียงฝีเท้า"},"ICON-1731":{"nm":"การ์ดให้คะแนนชิมอาหาร","de":"ใบหน้าที่กัดคำเดียวแล้วให้คะแนนดาวอย่างจริงจังสุดขีด บรรทัดเดียวที่เขียนไว้อย่างตรงไปตรงมาบนการ์ดใบนี้ คือคำบ่นที่อบอุ่นที่สุดที่ช่วยให้จานต่อไปอร่อยยิ่งขึ้น"},"ICON-1732":{"nm":"ริบบิ้นขอบคุณติดกล่องข้าว","de":"พันริบบิ้นเส้นหนึ่งรอบกล่องข้าวที่ว่างเปล่าสะอาดหมดจดแล้วส่งคืน แม้แต่คนที่ไม่เคยพูดคำขอบคุณออกมาได้เลย ก็ยังผูกปมนี้แทนหัวใจที่ไม่อาจเอ่ยออกมาได้และส่งต่อไป"},"ICON-1733":{"nm":"ป้ายเตือนอาการแพ้","de":"ป้ายเล็กๆ ใบนี้เพียงใบเดียวปกป้องโต๊ะอาหารของใครสักคนไว้อย่างเงียบๆ การเขียนบอกอย่างชัดเจนว่ามีอะไรอยู่ข้างในนั้น คือชื่ออีกชื่อหนึ่งของการต้อนรับที่ใส่ใจไปถึงจุดที่มองไม่เห็น"},"ICON-1734":{"nm":"ช้อนแห่งความทรงจำรสชาติ","de":"รสชาตินั้นที่ค้างอยู่ที่ปลายลิ้นมานาน แท้จริงแล้วคือทัศนียภาพของวันนั้นนั่นเอง เมื่อเห็นว่าเพียงช้อนเดียวพาเราย้อนกลับไปยังครัวในวัยเด็กได้ในพริบตา ดูเหมือนความทรงจำจะเป็นสิ่งที่หัวใจ ไม่ใช่กระเพาะอาหาร เป็นผู้ตักเก็บไว้"},"ICON-1735":{"nm":"เหรียญสุ่มเมนูวันนี้","de":"วันนี้กินอะไรดี คำถามที่ยากที่สุดในโลกที่เราแพ้ทุกครั้งไป เมื่อพลิกเหรียญนี้และฝากเมนูไว้ให้โชคชะตาตัดสิน ใจกลับเบาสบายและมีความสุขขึ้นอย่างไม่คาดคิด"},"ICON-1736":{"nm":"กระดิ่งเรียกโต๊ะอาหารรวม","de":"สั่นกระดิ่งเพียงครั้งเดียว สมาชิกครอบครัวที่กระจัดกระจายอยู่ตามห้องต่างๆ ก็มารวมตัวกันที่เดียว เสียงกระดิ่งเหนือโต๊ะกลมนั้นคือคำแปลที่อบอุ่นที่สุดของคำว่า \"เสร็จแล้ว มาเร็วเข้า\""},"ICON-1737":{"nm":"ป้ายลำดับของหวาน","de":"ของหวานต้องมาทีหลังสุดเสมอ คำสัญญาที่ไม่มีใครรู้ว่าใครเป็นคนตั้งไว้นี้ ป้ายใบนี้ช่วยรักษาไว้แทน ผู้ดำเนินรายการโต๊ะอาหารตัวเล็กแสนอบอุ่น ที่เก็บจุดสูงสุดของรสชาติไว้ให้ถึงคำสุดท้ายของของหวาน"},"ICON-1738":{"nm":"เหรียญต่อรองราคา","de":"ท่ามกลางตลาดที่คึกคัก \"ลดหน่อยได้ไหม\" กับ \"ขาดทุนอยู่แล้วนะ\" ปะทะกันอย่างเป็นมิตร เหรียญนี้คือใบเสร็จของลูกค้าประจำมานาน ที่การต่อรองนั้นจบลงด้วยเสียงหัวเราะในที่สุด"},"ICON-1739":{"nm":"เข็มหมุดเช็คสต็อก","de":"กวาดสายตามองชั้นวางของในโกดังอย่างเงียบๆ หาช่องว่างแล้วปักเข็มหมุดลงไป การรู้ว่าอะไรเหลืออยู่และอะไรหมดไปแล้วนั้น งานใหญ่อย่างการดูแลบ้านเรือนเริ่มต้นจากการตรวจตราเล็กๆ น้อยๆ เช่นนี้เสมอ"},"ICON-1740":{"nm":"แปรงทำความสะอาดแผงขาย","de":"เย็นวันที่ตลาดวายแล้ว เสียงแปรงกวาดแผงว่างเปล่าดังแผ่วเบาปกคลุมทั่วร้าน ที่ปลายนิ้วที่เช็ดทำความสะอาดจุดที่จะเติมของใหม่ในวันพรุ่งนี้ มีความขยันหมั่นเพียรที่ผูกปมวันหนึ่งวันให้จบลงอย่างเรียบร้อยแฝงอยู่"},"ICON-1741":{"nm":"การ์ดแนะนำประจำวัน","de":"\"วันนี้อันนี้ดีนะ\" การ์ดใบหนึ่งที่เจ้าของร้านแอบยื่นให้ ในคำแนะนำที่ค่อยๆ ผลักไหล่ลูกค้าที่ลังเลใจว่าจะเลือกอะไรนั้น มีความภาคภูมิใจของวันหนึ่งวันบรรจุอยู่อย่างเรียบร้อย"},"ICON-1742":{"nm":"การ์ดสะสมแต้มลูกค้าประจำ","de":"สะสมครบสิบครั้งแล้วครั้งที่สิบเอ็ดฟรี การ์ดใบนี้ที่ช่องประทับตราค่อยๆ เต็มไปทีละช่อง คือใบหน้าอีกด้านหนึ่งของคำว่า \"ลูกค้าประจำ\" และการมาบ่อยๆ นั้น สุดท้ายแล้วก็หมายถึงความรักนั่นเอง"},"ICON-1743":{"nm":"คลิปสมุดบัญชีแลกเปลี่ยน","de":"คลิปที่รวบรวมและยึดบันทึกของสิ่งที่แลกเปลี่ยนและส่งคืนไว้ด้วยกัน ยิ่งมีสิ่งที่ไปมาหากันมากเท่าไร สมุดบัญชีก็ยิ่งหนาขึ้น และความหนานั้นเองที่ทำให้ความไว้วางใจที่สั่งสมกับเพื่อนบ้านหนาแน่นขึ้นตามไปด้วย"},"ICON-1744":{"nm":"ป้ายขายหมดแล้ว","de":"วินาทีที่ป้ายนี้ติดลงบนชิ้นสุดท้าย หัวใจกลับพองโตขึ้นอย่างประหลาด มันคือคำอำลาสั้นๆ ราวกับ \"ไปดีๆ นะ\" ที่มอบให้แก่สิ่งของที่กำลังจะจากไปยังโต๊ะอาหารของใครสักคน ยังมุมห้องมุมหนึ่งที่ใดที่หนึ่ง"},"ICON-1745":{"nm":"ตะกร้าสินค้าจอง","de":"ตะกร้าที่มีป้ายชื่อของเธอติดอยู่ครองพื้นที่หนึ่งช่องบนชั้นวาง พื้นที่ตรงนั้นที่จองไว้ล่วงหน้าเพียงจุดเดียว กระซิบบอกเธอที่เดินเข้ามาอย่างเงียบๆ ว่า \"รอเธออยู่มาตลอดเลยนะ\""},"ICON-1746":{"nm":"แผ่นรองโต๊ะห่อของ","de":"แผ่นรองที่ปูอยู่บนโต๊ะห่อของคือเวทีของมือที่ขยับไปมาอย่างวุ่นวาย ในช่วงเวลาสั้นๆ ที่กระดาษถูกพับและเชือกถูกผูกอย่างเรียบร้อย สิ่งของธรรมดาก็ค่อยๆ กลายเป็นของขวัญของใครบางคนอย่างแนบเนียน"},"ICON-1747":{"nm":"จดหมายน้อยนัดหมายเยี่ยมเยียน","de":"\"พรุ่งนี้จะแวะไปนะ\" จดหมายน้อยที่เขียนไว้บรรทัดเดียวแล้วสอดไว้ที่ช่องประตูเบาๆ แม้ในยามที่ไม่ทันได้พบหน้ากัน คำสัญญาก็ยังลอยมากับกระดาษแผ่นเดียว มาถึงก่อนตัวคนแล้วรอคอยอยู่อย่างเงียบๆ"},"ICON-1748":{"nm":"ตะกร้าของฝากเพื่อนบ้าน","de":"ตะกร้าที่ยื่นข้ามรั้วไปให้เสมอมาพร้อมข้ออ้างว่า \"ทำเยอะไปหน่อยน่ะ\" ความอบอุ่นแบบเกาหลีข้ามมาถึงฝั่งนี้เช่นนี้เอง แสร้งทำเป็นเฉยเมยภายใต้ข้ออ้างว่ามีเหลือเฟือ"},"ICON-1749":{"nm":"กล่องข่าวสารหมู่บ้าน","de":"ข่าวสารเล็กใหญ่ของหมู่บ้านสั่งสมอยู่ในกล่องนี้ทีละอย่าง ใครเพิ่งย้ายเข้ามาใหม่ บ้านใครกำลังจัดงานฉลอง กระดาษไม่กี่แผ่นรวมตัวกันถ่ายทอดจังหวะชีพจรอันเงียบสงบของย่านนี้"},"ICON-1750":{"nm":"ตราประทับขอบคุณผู้มาเยือน","de":"กดใจที่ขอบคุณที่มีคนมาเยี่ยมเยียนลงไปด้วยตราประทับเพียงดวงเดียว รอยหมึกที่ซึมลงบนกระดาษเพียงจุดเดียวนั้น หลงเหลืออยู่ ณ ที่นั้นนานยิ่งกว่าคำว่า \"จะไม่มีวันลืม\" เสียอีก"},"ICON-1751":{"nm":"การ์ดชื่นชมความมีน้ำใจ","de":"การ์ดที่เขียนความมีน้ำใจที่ใครสักคนมอบให้ในวันนี้ไว้อย่างเงียบๆ แล้วส่งต่อคืนกลับไป ในหมู่บ้านที่ยอมลำบากจดบันทึกความอ่อนโยนเล็กๆ น้อยๆ เป็นตัวอักษรเช่นนี้ สิ่งดีๆ ก็หมุนเวียนกลับมาอยู่ร่ำไป"},"ICON-1752":{"nm":"ตราปิดผนึกจดหมายขอโทษ","de":"เหมือนแอปเปิ้ลที่สุกแดงงดงาม คำขอโทษก็สามารถส่งมอบได้ก็ต่อเมื่อสุกงอมเพียงพอแล้วเท่านั้น ตราปิดผนึกที่กดลงบนซองจดหมายอย่างหนักแน่นนี้ คือรอยแห่งความกล้าหาญที่โอบอุ้มคำขอโทษที่พูดไม่ออกไว้จนถึงที่สุด"},"ICON-1753":{"nm":"ตารางแบ่งงานร่วมกัน","de":"ตารางแผ่นเดียวที่เขียนแบ่งไว้เป็นช่องๆ ว่าใครรับผิดชอบอะไร งานที่หนักเกินไปสำหรับคนเดียวจะเบาลงมากเพียงใดเมื่อแบ่งชื่อกันรับผิดชอบ คนที่เคยทำงานเคียงบ่าเคียงไหล่กันมาเท่านั้นที่จะรู้"},"ICON-1754":{"nm":"ริบบิ้นบันทึกรสนิยมเพื่อนบ้าน","de":"ทำเครื่องหมายไว้เบาๆ ด้วยริบบิ้นหลากสีว่าเพื่อนบ้านชอบอะไร การจดจำรสนิยมของใครสักคนไว้ คือคำสารภาพที่เงียบที่สุดว่ารักและหวงแหนคนคนนั้น โดยไม่ต้องพูดออกมาให้เอิกเกริก"},"ICON-1755":{"nm":"ห่วงป้ายชื่อเชิญแขก","de":"ห่วงเพียงวงเดียวที่แขวนไว้ที่ป้ายชื่อบอกว่า \"วันนี้ต้อนรับแขก\" เป็นเครื่องหมายขนาดเท่าฝ่ามือ แต่ในนั้นแขวนไว้ด้วยหัวใจที่เปิดกว้างพร้อมต้อนรับใครสักคนอย่างเสร็จสรรพแล้ว"},"ICON-1756":{"nm":"สายรัดข้อมือเข้างานเทศกาล","de":"แถบสีซีดจางเส้นหนึ่งที่สวมใส่ไว้หลายวันเพราะเสียดายเกินกว่าจะถอดออก ในวินาทีที่มันถูกรัดเข้ากับข้อมือนั่นเอง เทศกาลจึงเริ่มต้นขึ้นอย่างแท้จริง ภายในนั้นมีวันหนึ่งวันที่แม้จบไปแล้วก็ยังไม่เคยจบลงจริงๆ หลับใหลอยู่อย่างสงบ"},"ICON-1757":{"nm":"ที่เก็บตั๋วชมพลุ","de":"ก่อนที่ท้องฟ้ายามค่ำคืนจะระเบิดออกไม่กี่วินาที ตั๋วในที่เก็บนี้กุมความตื่นเต้นไว้แน่น มันคือคำสัญญาที่กำไว้จนฝ่ามือชุ่มเหงื่อ เพื่อวินาทีเดียวที่พลุดอกแรกจะผลิบานพร้อมเสียงปัง"},"ICON-1758":{"nm":"จานไหว้พระจันทร์","de":"เคยมีค่ำคืนที่รู้สึกราวกับได้ตักพระจันทร์เต็มดวงทั้งดวงขึ้นมาใส่ในภาชนะ วางผลไม้สดและซงพย็อนไว้บนจานใบนี้อย่างสวยงามแล้วไหว้พระจันทร์ หัวใจดวงกลมดวงหนึ่งก็เอื้อมไปถึงปลายฟ้าได้"},"ICON-1759":{"nm":"เข็มกลัดถุงมือเทศกาลฤดูหนาว","de":"แม้มือจะแข็งเกร็งอยู่ในหิมะ ถุงมือก็ยังคงหลุดออกจากข้อมือเรื่อยๆ ต่อเมื่อเข็มกลัดนี้ถูกกลัดไว้ที่ปลายแขนเสื้ออย่างมั่นคงแล้วเท่านั้น จึงจะสามารถวิ่งเล่นในเทศกาลฤดูหนาวได้อย่างเต็มที่"},"ICON-1760":{"nm":"การ์ดเมล็ดพันธุ์ต้อนรับฤดูใบไม้ผลิ","de":"เมล็ดพันธุ์ไม่กี่เม็ดที่หลับใหลอยู่ในการ์ดต่างรอคอยฤดูใบไม้ผลิของตนเอง เมื่อฝังลงในดินแล้วมันจะแตกหน่อขึ้นมาอย่างไม่ผิดคำสัญญา ดูเหมือนว่าจุดเริ่มต้นทุกอย่างล้วนมาจากจุดเล็กๆ ที่แข็งแกร่งเพียงจุดเดียว"},"ICON-1761":{"nm":"ตราประทับหาดทรายฤดูร้อน","de":"คลื่นลูกหนึ่งกดตราประทับลงบนผืนทรายอย่างหนักแน่นแล้วถอยกลับไปอย่างช้าๆ แม้จะรู้ว่าอีกไม่นานมันจะถูกลบเลือนไป แต่ก็ยังทิ้งรอยเล็กๆ ไว้บอกว่าครั้งหนึ่งมีใครเคยมาที่นี่ ฤดูร้อนเป็นเช่นนี้เสมอ ประทับตราไว้อย่างชัดเจนเพียงครั้งเดียว แล้วก็ลอยจากไปพร้อมกลิ่นไอทะเล"},"ICON-1762":{"nm":"ริบบิ้นเก็บเกี่ยวฤดูใบไม้ร่วง","de":"มือที่มัดรวงข้าวสุดท้ายผูกริบบิ้นไว้อย่างสวยงาม ปมเดียวที่รวบรวมหยาดเหงื่อตลอดทั้งปีไว้อย่างพิถีพิถัน แม้ทุ่งนาจะว่างเปล่าลง ฤดูใบไม้ร่วงก็ยังส่งคำทักทายอีกครั้งด้วยสีสันที่งดงามที่สุด ราวกับแสงอาทิตย์ยามเย็น"},"ICON-1763":{"nm":"บับเบิลคำพูดถ่ายภาพที่ระลึก","de":"\"ขอบคุณที่มาถึงที่นี่นะ\" คำทักทายที่ไม่อาจเอ่ยออกมาเป็นคำพูดได้ ค่อยๆ พองโตเป็นวงกลมบนแผ่นกระดาษ ชิ้นส่วนหัวใจดวงกลมเล็กๆ ที่ยืมเสียงให้แก่ความเงียบงันที่หยุดนิ่งอยู่ในภาพถ่ายอย่างอ่อนโยน"},"ICON-1764":{"nm":"หมุดแผนที่งานเทศกาล","de":"เครื่องหมายที่ใครสักคนปักไว้เพื่อไม่ให้หลงทางในลานกว้างใหญ่ แม้เท้าจะวิ่งพุ่งไปก่อนตามเสียงดนตรีพื้นบ้าน หมุดตัวนี้เพียงตัวเดียวก็ยังพาเธอที่กำลังหลงทางไปยังจุดนัดหมายอย่างอ่อนโยน"},"ICON-1765":{"nm":"กุญแจต้นฉบับอัลบั้ม","de":"สิ่งที่ถูกล็อกไว้ไม่ใช่แผ่นเสียง แต่คือกาลเวลาที่ผนึกไว้ภายใน ความสั่นไหวของการอัดเสียงครั้งแรก รุ่งอรุณของการมิกซ์เสียงครั้งสุดท้าย เมื่อหมุนกุญแจอย่างช้าๆ ประตูห้องที่มีเพียงผู้สร้างสรรค์เท่านั้นที่รู้จัก ก็เปิดออกพร้อมเสียงเอี๊ยด"},"ICON-1766":{"nm":"การ์ดลำดับเพลง","de":"ลำดับเพลงที่เขียนไว้บนแผ่นเดียวนั้น แท้จริงแล้วคือลำดับของหัวใจ จะสะอื้นตรงไหน จะหายใจเข้าลึกๆ ตรงไหน กระดาษแผ่นนี้รู้ดีอยู่แล้วทุกอย่าง ความตื่นเต้นที่พลุ่งพล่านขึ้นมาก่อนจะได้ยินโน้ตแรกด้วยซ้ำ"},"ICON-1767":{"nm":"ป้ายตรวจสอบเสียงเพลง","de":"มีเพียงคนที่กรอกลับฟังช่วงเดียวกันมาเป็นร้อยครั้งเท่านั้นที่จะติดป้ายนี้ อีกสักครั้ง แค่อีกครั้งเดียวเท่านั้น ข้างตราผ่านนั้นซ่อนค่ำคืนของใครสักคนที่สงสัยในหูของตัวเองจนถึงรุ่งสาง"},"ICON-1768":{"nm":"ป้ายสั่งจองล่วงหน้า","de":"คำสัญญาที่จะรอคอยสิ่งที่ยังไม่ได้ออกสู่โลกด้วยซ้ำ วินาทีที่ป้ายนี้ถูกติดลงไป ที่ว่างเปล่าหนึ่งช่องก็ถูกจองไว้อย่างเงียบๆ ในนามของใครบางคน แม้แต่การรอคอยด้วยความตื่นเต้นก็ยังมีบัตรคิว"},"ICON-1769":{"nm":"สติกเกอร์ผนึกฉบับพิมพ์ครั้งแรก","de":"มันคล้ายกับสัมผัสมือในอดีตที่คลุมไหด้วยกระดาษฮันจีแล้วปิดผนึกด้วยแป้งเปียก แผ่นเดียวที่ปฏิญาณจะรักษาสภาพดั้งเดิมไว้ให้คงเดิม เพราะรู้ว่ามันจะหายไปในวินาทีที่ลอกออก จึงเฝ้ามองรูปลักษณ์นั้นนานขึ้นเรื่อยๆ"},"ICON-1770":{"nm":"ชิปปฏิทินคัมแบ็ก","de":"เมื่อวงกลมบนปฏิทินเพิ่มขึ้นอีกหนึ่งวง คืนที่เหลืออยู่จนถึงวันนั้นก็สั้นลงอีกหนึ่งช่อง วันที่กลับมาปรากฏชัดเจนอยู่บนชิปเล็กๆ ในมือ สำหรับคนที่รอคอย เวลาคือสิ่งที่นับด้วยมือเช่นนี้เอง"},"ICON-1771":{"nm":"ซองใส่ภาพคอนเซปต์","de":"ก่อนที่สีสันของคอนเซปต์หนึ่งจะถูกคอนเซปต์ถัดไปผลักออกไป แผ่นใสแผ่นหนึ่งจะสอดเก็บลายผิวนั้นไว้อย่างทะนุถนอม เพื่อไม่ให้ถูกลืมเลือนไปแม้ฤดูกาลจะเปลี่ยน มันปกป้องเฉดสีของวันวานไว้อย่างเบามือ แม้กระทั่งขอบมุม"},"ICON-1772":{"nm":"เหรียญเปิดตัวทีเซอร์","de":"ก่อนจะเปิดม่านลง เหรียญเล็กๆ เหรียญหนึ่งที่กำไว้ในฝ่ามือ วินาทีที่ยื่นเหรียญนี้ออกไป ฉากแรกที่ถูกล็อกไว้ก็เปิดออกสู่โลกอีกหนึ่งฝ่ามือ การเปิดตัวสุดท้ายแล้วก็คือเรื่องของใครจะยื่นมือออกมาก่อน"},"ICON-1773":{"nm":"ฐานวางแสดงแผ่นเสียง","de":"วินาทีที่ฐานเตี้ยๆ อันหนึ่งยกแผ่นเสียงขึ้นเพียงเล็กน้อย แผ่นธรรมดาแผ่นหนึ่งก็กลายเป็นตัวเอกของชั้นวาง นักแสดงสมทบผู้อ่อนโยนที่คอยค้ำมุมองศาที่แสงตกกระทบงดงามที่สุดไว้จากด้านหลังอย่างเงียบๆ โดยไม่พูดอะไรเลย"},"ICON-1774":{"nm":"บัตรผ่านโชว์เคสเดบิวต์","de":"บัตรผ่านใบเดียวที่สลักคำว่า \"ขอนำเสนอเป็นครั้งแรก\" ไว้ จากทางเดินยาวหลังเวทีไปจนถึงเสียงปรบมือแรกจากที่นั่งผู้ชม บัตรผ่านนี้ช่วยให้ข้ามธรณีประตูอันสั่นไหวของการเดบิวต์ไปได้"},"ICON-1775":{"nm":"ชิปตำแหน่งเวทีครั้งแรก","de":"คลำหาชิปที่ติดไว้บนพื้นด้วยปลายเท้าอย่างเงียบๆ ช่องหนึ่งที่ร่างกายรู้จักก่อนแม้ไม่ได้มอง ในวินาทีที่เท้าเหยียบตรงจุดที่จดจำไว้ได้อย่างแม่นยำ ความสั่นไหวที่ปลายนิ้วก็กลายเป็นท่าทางที่ชัดเจนในที่สุด"},"ICON-1776":{"nm":"การ์ดคำกล่าวขอบคุณ","de":"แม้แต่คำธรรมดาอย่าง \"ทั้งหมดนี้เป็นเพราะพวกคุณทุกคน\" เมื่อเขียนด้วยลายมือที่สั่นไหว ก็ไม่ธรรมดาอีกต่อไป ไม่กี่บรรทัดที่จดไว้ล่วงหน้าเพราะกลัวว่าจะลืมด้วยความตื้นตัน บางครั้งความจริงใจก็พึ่งพาการ์ดใบเดียวเช่นนี้"},"ICON-1777":{"nm":"ตารางนัดถ่ายภาพโปรไฟล์","de":"แผ่นหนึ่งที่เขียนวันที่จะยืนหน้าเลนส์ไว้อย่างเรียบร้อย ตารางเวลาสำหรับเตรียมใบหน้าที่ดีที่สุดอย่างช้าๆ ยิ่งช่องว่างถูกเติมเต็มไปทีละช่อง คืนที่ใช้อยู่หน้ากระจกก็ยิ่งยาวนานขึ้นตามไปด้วย"},"ICON-1778":{"nm":"ใบสมัครสมาชิกแฟนคลับ","de":"ใบสมัครที่เขียนชื่อและหัวใจไว้ในบรรทัดเดียวแล้วยื่นให้ด้วยความเขินอาย คำว่ารักมักเป็นคำที่ยากเสมอ แต่ใบสมัครใบนี้ช่วยเขียนคำนั้นแทนอย่างเรียบร้อย ลายเซ็นแรกของการตัดสินใจอยู่เคียงข้างกัน"},"ICON-1779":{"nm":"ใบตรวจสอบของขวัญเดบิวต์","de":"สัมผัสที่ตรวจสอบทีละชิ้น พลางนึกถึงหน้าคนที่จะได้รับ มุมบุบหรือเปล่า หัวใจหล่นหายไปหรือไม่ ของขวัญได้รับความรักไปแล้วครั้งหนึ่งก่อนที่จะถูกส่งมอบเสียอีก แล้วจึงออกเดินทาง"},"ICON-1780":{"nm":"เครื่องหมายจบเวที","de":"ก่อนม่านจะปิดลงไม่กี่วินาที เครื่องหมายที่วางไว้ตรงจุดที่ท่าทางสุดท้ายหยุดนิ่งอยู่ ไม่ใช่สัญญาณบอกจุดจบ แต่เป็นจุดเล็กๆ ที่ผูกปมจุดจบไว้อย่างสวยงาม มีเพียงเวทีที่ปิดฉากลงอย่างดีเท่านั้นที่จะเปิดเวทีถัดไปได้"},"ICON-1781":{"nm":"เข็มกลัดรอสัมภาษณ์","de":"เข็มกลัดที่คอยปกป้องความเงียบสงบก่อนคำถามจะเริ่มต้นขึ้นอย่างเงียบๆ ในช่วงความเงียบสั้นๆ ที่กำลังเลือกคำตอบอยู่ในหัว เครื่องหมายเล็กๆ นี้พูดแทนอย่างอ่อนโยนว่า \"ยังไม่ใช่ตอนนี้ อีกสักครู่นะ\""},"ICON-1782":{"nm":"ซองที่ระลึกวันเดบิวต์","de":"เหมือนหัวใจในอดีตที่มอบจดหมายอันล้ำค่าพร้อมทั้งซองใส่ไว้ในมือของผู้ที่กำลังออกเดินทาง ชั้นเดียวนี้เก็บบันทึกเวทีแรกไว้อย่างทะนุถนอม วันที่เปิดออกดูในอนาคตอันไกลโพ้น ความสั่นไหวของวันนั้นก็หลั่งไหลออกมาพร้อมกันด้วย"},"ICON-1783":{"nm":"หลอดฝึกหายใจสำหรับร้องเพลง","de":"ฝึกส่งลมหายใจออกยาวๆ เป็นสายเดียวผ่านปลายหลอดเล็กๆ การร้องเพลง สุดท้ายแล้วคือลมหายใจที่ควบคุมได้ดี หลอดเล็กๆ นี้บอกอย่างเงียบๆ ทุกเช้า ลมก่อนเสียง"},"ICON-1784":{"nm":"ชิปคลิกฝึกจังหวะ","de":"ติ๊ก ติ๊ก ติ๊ก—เพื่อนที่ซื่อสัตย์ที่สุดในโลก เมื่อเร่งเร็วไปก็ดึงรั้งไว้ เมื่อช้าไปก็ผลักหลังให้ การฝังจังหวะลงในร่างกาย เปรียบดั่งบทสนทนายาวนานกับชิปแข็งแกร่งชิ้นนี้"},"ICON-1785":{"nm":"ริบบิ้นตรวจสอบเส้นลีลาท่าเต้น","de":"ปลายนิ้วหยุดตรงไหน ไหล่เปิดตรงไหน ลากเส้นของท่าทางด้วยริบบิ้นเส้นเดียวอย่างเงียบๆ เส้นลีลาท่าเต้นที่ขีดไว้อย่างดี ยังคงตรงและเรียบร้อยแม้ในจุดที่มองไม่เห็นจากที่นั่งผู้ชม"},"ICON-1786":{"nm":"การ์ดฟีดแบ็กสีหน้า","de":"คำพูดที่ว่าแม้แต่การยิ้มก็ต้องเรียนรู้ แผ่นหนึ่งที่จดมุมตาและความสูงของมุมปากไว้ทีละอย่าง สีหน้าที่กระจกไม่ทันได้บอก การ์ดใบนี้บอกแทนอย่างอ่อนโยน"},"ICON-1787":{"nm":"บันทึกโฟลว์แร็พ","de":"\"ตรงนี้พักหายใจสักหน่อย ตรงนั้นระเบิดออกมาให้หมด\"—บันทึกที่วาดสายธารของคำพูดไว้ล่วงหน้า ยิ่งช่วงเร็วเท่าไร เส้นทางลมหายใจก็ยิ่งต้องชัดเจนเท่านั้น ในลูกศรที่ขีดไว้อย่างรวดเร็วนั้น จังหวะของท่อนหนึ่งมีชีวิตหายใจอยู่"},"ICON-1788":{"nm":"สติกเกอร์อุณหภูมิเสียงร้อง","de":"แม้แต่เสียงก็มีวันที่อบอุ่นและวันที่หนาวเย็น เครื่องหมายเล็กๆ ที่เลือกด้วยสีติดไว้สำหรับลายผิวของวันนี้ อุ่นแล้วก็เย็น สลับกันไป เสียงตื่นขึ้นในแต่ละวันด้วยอุณหภูมิที่ต่างกันเล็กน้อยเสมอ"},"ICON-1789":{"nm":"เหรียญประจำการพักผ่อน","de":"เหรียญเหรียญหนึ่งที่ยื่นให้พร้อมคำพูดว่าการพักผ่อนให้ดีก็เป็นความสามารถอย่างหนึ่ง ยื่นเหรียญนี้ออกมาแล้วจะหยุดพักได้ชั่วครู่โดยไม่รู้สึกผิด สำหรับคนที่วิ่งไม่หยุดมาตลอด การหยุดพักคือทางเลือกที่กล้าหาญที่สุด"},"ICON-1790":{"nm":"เข็มหมุดเป้าหมายการเติบโต","de":"เข็มหมุดเล็กๆ ที่ปักไว้ด้วยคำว่า \"ลองไปให้ถึงตรงนี้กันเถอะ\" แม้จะดูไกลราวกับเอื้อมไม่ถึง แต่ทุกวันก็ยังเติบโตไปในทิศทางนั้นทีละก้าว เป้าหมายเปรียบดั่งคำสัญญาอันอ่อนโยนที่โบกมือเรียกอยู่แต่ไกล"},"ICON-1791":{"nm":"ซองประเมินผลรายสัปดาห์","de":"รวบรวมหยาดเหงื่อและน้ำตาของสัปดาห์หนึ่งใส่ในซองเดียวอย่างเรียบร้อยแล้วส่งให้ สิ่งที่ทำได้ดีและสิ่งที่ยังเสียดายอยู่วางเคียงข้างกันภายใน การเปิดดูคือการบ้านเล็กๆ ที่ส่งมอบให้แก่ตัวเองของสัปดาห์หน้า"},"ICON-1792":{"nm":"กระปุกชิ้นส่วนตกแต่งเวที","de":"เบื้องหลังเวทีที่ระยิบระยับนั้นมีชิ้นส่วนไร้ชื่ออาศัยอยู่ สกรูตัวหนึ่ง ห่วงวงหนึ่งรวมตัวกันลอยดาวไว้บนเพดาน เปิดกระปุกออกมาก็จะพบความเอาใจใส่เล็กจิ๋วที่ค้ำจุนความงดงามอยู่อย่างเงียบๆ เต็มไปหมด"},"ICON-1793":{"nm":"บอร์ดคอนเซปต์เครื่องแต่งกาย","de":"ติดชิ้นผ้าและสีทีละชิ้น ลองสวมเสื้อผ้าที่ยังไม่มีอยู่ในโลกนี้ไว้ล่วงหน้า เครื่องแต่งกายบนเวทีที่เสร็จสมบูรณ์บนบอร์ดก่อนใคร จินตนาการเดินนำหน้าเข็มด้ายอยู่เสมอหนึ่งก้าว"},"ICON-1794":{"nm":"ชิปทดสอบสี","de":"เสื้อผ้าชิ้นเดียวกันก็มีใบหน้าที่แตกต่างไปสิ้นเชิงตามแสง สีไหนที่ยิ้มสดใสที่สุดกับคนคนนั้น ค้นหาด้วยการทาบชิปทีละแผ่น ความเข้ากันคือการค้นพบหลังจากเปรียบเทียบมานาน"},"ICON-1795":{"nm":"แผ่นตัวอย่างเชือกรองเท้า","de":"สิ่งที่รับผิดชอบก้าวที่มั่นคงบนเวทีนั้น น่าแปลกที่กลับเป็นเชือกเส้นเล็กๆ ไม่ให้หลุด แต่ก็ไม่รัดจนอึดอัด ความกังวลอันอ่อนโยนที่สุด ณ จุดต่ำที่สุด ที่วางลายเชือกหลากแบบเรียงไว้ให้เลือก"},"ICON-1796":{"nm":"ซองตรวจสอบเครื่องประดับ","de":"ยิ่งของสิ่งใดระยิบระยับมากเท่าไร รอยตำหนิเพียงจุดเดียวก็ยิ่งดูเด่นชัดมากเท่านั้น สัมผัสที่ยกเครื่องประดับจากซองส่องกับแสงแล้วตรวจดูอย่างละเอียดถี่ถ้วน หัวใจที่มองสิ่งเล็กๆ จนถึงที่สุดนี้เองที่ปกป้องเวทีไว้"},"ICON-1797":{"nm":"แผ่นทดสอบสีผม","de":"ตัวอย่างเล็กๆ สำหรับลองสวมฤดูกาลใหม่ไว้บนเส้นผมล่วงหน้า สีที่แต้มลงบนเส้นผมเพียงเส้นเดียวนั้น กระซิบบอกความประทับใจแรกของคอนเซปต์ถัดไปอย่างเงียบๆ การเปลี่ยนแปลงเริ่มต้นจากที่ที่มีขนาดเท่าฝ่ามือเสมอ"},"ICON-1798":{"nm":"การ์ดคอนเซปต์เล็บ","de":"แผ่นหนึ่งที่กำหนดภาพเล็กๆ ที่จะวาดลงบนปลายนิ้วทั้งสิบไว้ล่วงหน้า เพื่อให้คอนเซปต์แผ่วเบาซึมออกมาแม้ในท่าทางเพียงครั้งเดียว จึงสวมเรื่องราวไว้อย่างพิถีพิถันแม้ในรายละเอียดเล็กที่สุด"},"ICON-1799":{"nm":"บัตรเปลี่ยนสไตล์","de":"\"วันนี้ลองเป็นตัวเองที่ต่างจากเมื่อวานสักหน่อยดีไหม\"—บัตรใบเดียวที่ทำให้ประโยคนั้นเป็นจริงได้ ไม่ว่าจะผม เสื้อผ้า หรือบรรยากาศ บัตรใบนี้เปิดประตูอันตื่นเต้นไปสู่ภาพลักษณ์ใหม่"},"ICON-1800":{"nm":"ป้ายปรับขนาด","de":"ป้ายที่จดไว้อย่างพิถีพิถันว่าจะย่อและขยายตรงไหนจนกว่าจะพอดีกับร่างกาย เหมือนสัมผัสมือในอดีตที่ปะชุนเสื้อผ้าลูกทีละเข็ม การปรับแต่งเล็กๆ นี้ทำให้เวทีสบายขึ้นอีกหนึ่งฝ่ามือ"},"ICON-1801":{"nm":"การ์ดภาพร่างธัมบ์เนล","de":"กระดาษหนึ่งแผ่นที่สีสันยังไปไม่ถึง เหนือเส้นดินสอหยาบ ๆ มันค่อย ๆ คาดเดาว่าฉากต่อไปจะไหลไปทางไหน สิ่งที่ตื่นเต้นยิ่งกว่าความสมบูรณ์แบบคือบรรทัดแรกที่ยังไม่เสร็จนี้เสมอ ห้องตัดต่ออันเงียบงันกระซิบบอกเราเช่นนั้น"},"ICON-1802":{"nm":"สติกเกอร์ยินยอมถ่ายทำ","de":"\"ที่นี่จะถูกบันทึกไว้ได้ไหม\" แทนคำพูด เธอแปะเครื่องหมายวงกลมเล็ก ๆ ไว้ตรงหน้าอก สติกเกอร์แผ่นน้อยแผ่นเดียวตั้งคำสัญญาอันอ่อนโยนไว้ระหว่างกล้องกับหัวใจ"},"ICON-1803":{"nm":"หมุดจุดยืนโฟโต้วอลล์","de":"หมุดเล็ก ๆ ปักอยู่ที่มุมกำแพง เป็นตำแหน่งที่กำหนดไว้ล่วงหน้าว่าใครจะยืนตรงไหน ทุกจุดที่ปักหมุดไว้ รอยยิ้มหนึ่งจะหยุดนิ่งอยู่ตรงนั้นและกลายเป็นภาพถ่ายหนึ่งใบ"},"ICON-1804":{"nm":"ชิปเลือกคัตภาพ","de":"นิ้วที่ชี้ลงบนภาพเพียงหนึ่งเดียวท่ามกลางภาพนับร้อย เมื่อวางชิปนี้ลงในวินาทีนั้น สีหน้าทุกแบบที่ถูกพับเก็บไปก็เหมือนมีชีวิตอยู่เพื่อภาพเดียวนี้เท่านั้น การเลือกจึงคล้ายกับการอำลาอันเงียบงันเสมอ"},"ICON-1805":{"nm":"ซองเบื้องหลังกล้อง","de":"ทุกสิ่งที่เกิดขึ้นหลังกล้องถูกเก็บไว้ในนี้ พับปากซองแล้วเสียงหัวเราะ ฉาก NG และหาวง่วงนอนก็นอนหลับปะปนกันอยู่ข้างใน สิ่งที่มักกลายเป็นของรักยิ่งกว่าตัวงานจริง มักเป็นสิ่งที่ซ่อนอยู่ข้างในนี้เอง"},"ICON-1806":{"nm":"โน้ตขอแก้ไขงานตัดต่อ","de":"\"ตรงนี้อีกหนึ่งวินาที แล้วลดเสียงเพลงลงนิดหน่อย\" กระดาษโน้ตที่แน่นไปด้วยตัวหนังสือสีแดง ความจู้จี้ของใครบางคนช่วยปรับจังหวะลมหายใจของวิดีโอไปทีละจังหวะ ความสมบูรณ์แบบเติบโตขึ้นบนรอยมือเล็ก ๆ เหล่านี้เอง"},"ICON-1807":{"nm":"ป้ายนัดหมายอัปโหลด","de":"ป้ายเล็ก ๆ ติดอยู่กับวิดีโอที่จะออกไปพบโลกเองในเจ็ดโมงเช้าของวันพรุ่งนี้ แม้ทุกคนจะหลับใหล แต่คำสัญญานั้นยังคงตื่นอยู่ เวลาที่ตั้งไว้ล่วงหน้าไม่เคยรู้จักคำว่าสาย"},"ICON-1808":{"nm":"ปกกรอบภาพธัมบ์เนล","de":"ฝาครอบที่ห่อหุ้มฉากแรกที่ออกมาดีที่สุด พับมุมอย่างเรียบร้อยไม่ให้รอยนิ้วมือหรือฝุ่นแตะต้องได้ ก่อนจะเผยให้ใครเห็น ความประทับใจแรกจึงถูกเก็บรักษาไว้อย่างประณีตเช่นนี้"},"ICON-1809":{"nm":"ชิปวัดความยาวคลิป","de":"ชิปเล็ก ๆ ที่คะเนว่าวันนี้ถ่ายไว้กี่นาที ยาวก็ใช่ว่าจะดี สั้นก็ใช่ว่าจะเบา หัวใจที่รู้จักความยาวที่พอดี คือกระดุมเม็ดแรกของการตัดต่อ"},"ICON-1810":{"nm":"ใบตรวจคำขวัญเชียร์","de":"กระดาษที่ต้องตรวจอีกครั้งก่อนจะตะโกนสุดเสียง เพราะตัวอักษรผิดไปเพียงตัวเดียว เสียงนับพันก็อาจกระจัดกระจาย เบื้องหลังเสียงเชียร์นั้น มีมือของการพิสูจน์อักษรที่มองไม่เห็นเดินผ่านมาก่อนแล้ว"},"ICON-1811":{"nm":"ซองเก็บภาพแฟนอาร์ต","de":"ภาพวาดหนึ่งภาพที่ใครบางคนวาดมาทั้งคืน ซองใสมอบบ้านเล็ก ๆ ให้เพื่อไม่ให้มันยับยู่ยี่ ราวกับว่าสิ่งที่วาดด้วยหัวใจต้องถูกโอบกอดด้วยหัวใจจึงจะอยู่ได้นาน ซองใบนี้จึงกอดมันไว้โดยไม่พูดอะไรสักคำ"},"ICON-1812":{"nm":"เชือกจัดหมวดจดหมายแฟน","de":"เชือกที่มัดจดหมายกองโตให้เรียงเป็นระเบียบตามผู้ส่ง ทุกปมที่ผูกคือความคิดถึงของหนึ่งวันที่ถูกจัดเก็บให้เป็นที่ทาง แม้จะตอบกลับไม่ได้ทุกฉบับ แต่มือที่ไม่ยอมปล่อยให้ฉบับใดหลุดลอยไปก็อยู่ตรงนี้"},"ICON-1813":{"nm":"ใบนัดแลกเปลี่ยนกู๊ดส์","de":"\"มีใครอยากแลกกับของฉันไหมคะ\" กระดาษที่เขียนหัวใจที่สั่นเบา ๆ ยื่นออกไป เพียงเพราะชอบสิ่งเดียวกัน คนแปลกหน้าก็กลายเป็นเพื่อนกันชั่วครู่"},"ICON-1814":{"nm":"ชิปจองที่นั่งเชียร์กลุ่ม","de":"ชิปที่กำหนดที่นั่งให้คนที่สวมเสื้อสีเดียวกันได้นั่งเรียงกัน เมื่อหัวใจที่กระจัดกระจายมารวมกันในโซนเดียว อัฒจันทร์ก็เริ่มร้องเพลงราวกับเป็นคนคนเดียวที่ยิ่งใหญ่"},"ICON-1815":{"nm":"ใบเสร็จป้ายโฆษณาวันเกิด","de":"ใบเสร็จหนึ่งใบที่ได้รับหลังจากส่งความรักขึ้นจอโฆษณา สิ่งที่ไม่ได้เขียนไว้ข้างจำนวนเงินคือความตั้งใจที่สะสมมาทั้งคืน กระดาษแผ่นนี้จึงหลงเหลืออยู่เป็นหลักฐานของการเฉลิมฉลองที่มุ่งไปหาคนคนเดียวเท่านั้น"},"ICON-1816":{"nm":"ปกสมุดข้อความ","de":"ปกที่ห่อหุ้มสมุดซึ่งรวบรวมลายมือของหลายคนไว้ด้วยกัน เปิดออกแล้วลายมือที่ต่างกันก็ซ้อนทับกันด้วยหัวใจดวงเดียว ภายนอกดูเรียบร้อย แต่ภายในเต็มไปด้วยความอบอุ่นอึกทึก"},"ICON-1817":{"nm":"เข็มกลัดสมาชิกแฟนคลับ","de":"หมุดเล็ก ๆ ที่มอบให้เฉพาะคนที่เรียกชื่อเดียวกัน ในวินาทีที่ปักลงบนอก ความชื่นชอบที่เคยโดดเดี่ยวก็กลายเป็นคำสัญญาของคนหมู่มาก ความรู้สึกเป็นส่วนหนึ่งมีรูปทรงกลมเช่นนี้เอง"},"ICON-1818":{"nm":"โทเคนเชียร์ออนไลน์","de":"แสงจุดหนึ่งที่มือจากแดนไกลโบกไหวผ่านหน้าจอ ระยะทางไกลแสนไกล แต่จังหวะยังคงเหมือนเดิม นี่คือเครื่องพิสูจน์ว่าแม้จะนั่งอยู่ในที่มองไม่เห็น เสียงเชียร์ก็ยังมาถึงเสมอไม่เคยขาด"},"ICON-1819":{"nm":"เศษกุญแจเก่า","de":"เศษโลหะบิ่นเล็ก ๆ ชิ้นหนึ่ง ตอนนี้ไม่มีใครจำได้อีกแล้วว่ามันเคยไขประตูบานไหน สิ่งที่มีชีวิตอยู่ได้นานกว่าสถานที่ที่เคยถูกล็อกไว้ มักเป็นครึ่งหนึ่งของกุญแจที่หมดประโยชน์เช่นนี้เสมอ"},"ICON-1820":{"nm":"แผนที่ทางลับ","de":"กระดาษเก่าที่วาดเส้นทางซ่อนอยู่หลังไม้เลื้อยไว้ ทางลัดนี้มีแต่คนที่รู้เท่านั้นจึงจะรู้ ในวินาทีที่คลี่ออก เกาะธรรมดา ๆ ก็แอบเปลี่ยนหน้าตาเป็นเวทีแห่งการผจญภัยทันที"},"ICON-1821":{"nm":"การ์ดถอดรหัสลับ","de":"การ์ดที่คืนตัวอักษรที่กระจัดกระจายสับสนให้กลับไปอยู่ในตำแหน่งเดิม เมื่อบรรทัดหนึ่งเข้าที่ ความลับถัดไปก็กวักมือเรียก แม้ปมที่ดูเหมือนจะแก้ไม่ได้เลย สุดท้ายก็เริ่มต้นจากตัวอักษรตัวแรกเสมอ"},"ICON-1822":{"nm":"เชือกผนึกกล่อง","de":"เชือกที่มัดแน่นราวกับจะบอกว่าอย่าเปิด มีแต่คนที่ผูกเท่านั้นที่รู้ว่าอะไรหลับใหลอยู่ในปม ความอยากแก้และความอยากปกป้อง ถูกผูกเรียงเคียงกันไว้ในเส้นเดียวนี้"},"ICON-1823":{"nm":"ชิปปริศนาซากปรักหักพัง","de":"เศษชิ้นเล็ก ๆ ที่หลุดออกมาจากกำแพงหินเก่าแก่ เมื่อประกอบกลับเข้าที่เดิม ฝีมือของใครบางคนเมื่อพันปีก่อนก็ฟื้นคืนชีพขึ้นที่ปลายนิ้ว การรวบรวมสิ่งที่กระจัดกระจาย คือการเชื่อมต่อกาลเวลาขึ้นใหม่อีกครั้ง"},"ICON-1824":{"nm":"สมุดตัดข่าวตำนานเกาะ","de":"กระดาษที่คัดลอกเรื่องเล่าเก่าแก่ที่ล่องลอยอยู่ทั่วเกาะไว้ด้วยมือ จะจริงหรือไม่จริงนั้นไม่สำคัญนัก เรื่องเล่าที่ส่งต่อจากปากสู่ปาก กลายเป็นวงปีของเกาะแห่งนี้ในตัวมันเอง"},"ICON-1825":{"nm":"หินสัญลักษณ์ลับ","de":"ก้อนหินก้อนหนึ่งที่ดูราวกับวางทิ้งไว้เฉย ๆ ข้างทาง มีเพียงสายตาของคนที่รู้เท่านั้นที่มันจะชี้ทิศทางให้อย่างเงียบ ๆ ยิ่งเป็นความลับที่อยากฝังลึกเท่าไหร่ มันก็ยิ่งยืนอยู่ตรงนั้นด้วยหน้าตาธรรมดาที่สุดเท่านั้น"},"ICON-1826":{"nm":"ซองปริศนา","de":"ไม่มีคำใดเขียนไว้บนซองเลย ช่วงเวลาสั้น ๆ ก่อนฉีกผนึกออกนี่แหละที่ใจเต้นแรงที่สุด จนกว่าคำตอบจะอยู่ในมือ ความเป็นไปได้ทุกอย่างยังคงมีชีวิตอยู่ในซองใบนี้"},"ICON-1827":{"nm":"ฝาครอบแว่นขยายนักสืบ","de":"ฝาเล็ก ๆ ที่สวมปิดปลายแว่นขยายไว้เงียบ ๆ เมื่อไม่ได้ใช้ส่องดู มันปล่อยให้เลนส์ได้พักผ่อนอย่างเงียบสงบ การจะมองเห็นได้ดี ต้องรู้จักปกป้องให้ดีก่อน นักสืบเรียนรู้บทเรียนนี้เร็วเสมอ"},"ICON-1828":{"nm":"ตั๋วรถบัสวนรอบเกาะ","de":"ตั๋วหนึ่งใบสำหรับขึ้นรถบัสที่วิ่งวนรอบเกาะ ป้ายสุดท้ายคือจุดเริ่มต้นอีกครั้ง บนเส้นทางที่วนกลับมายังจุดเดิมซ้ำแล้วซ้ำเล่า ทิวทัศน์กลับดูใหม่ขึ้นทีละนิดในทุกครั้งไป"},"ICON-1829":{"nm":"ป้ายเช่าจักรยาน","de":"ป้ายหนึ่งใบที่แขวนอยู่ที่มือจับจักรยานเช่า อิสรภาพชั่วครู่ได้รับอนุญาตจนกว่าจะคืน เมื่อเวลาแห่งการฝ่าสายลมจบลง ป้ายนี้จะเก็บคำสัญญานั้นกลับไปอย่างเงียบ ๆ"},"ICON-1830":{"nm":"ตั๋วขึ้นเรือลำเล็ก","de":"ตั๋วสำหรับขึ้นเรือลำเล็กหนึ่งลำ บนดาดฟ้าที่โคลงเคลง เกาะกับเกาะเริ่มขยับเข้าใกล้กัน การข้ามเส้นทางน้ำมักพาความตื่นเต้นเล็กน้อยและอาการเมาคลื่นเล็กน้อยมาด้วยกันเสมอ"},"ICON-1831":{"nm":"หมุดล้อรถเข็นสัมภาระ","de":"หมุดที่ยึดล้อรถเข็นให้แน่นหนา โลหะชิ้นเล็ก ๆ ชิ้นนี้เองที่ทำให้ของหนักหมุนเคลื่อนไปได้ ชิ้นส่วนที่ดูไม่เด่นที่สุดมักเป็นชิ้นที่แบกรับน้ำหนักมากที่สุดอย่างเงียบเชียบเสมอ"},"ICON-1832":{"nm":"โทเคนกระเช้าลอยฟ้า","de":"โทเคนกลมที่หย่อนลงในกระเช้าที่แล่นผ่ากลางอากาศ ในวินาทีที่เท้าลอยพ้นพื้นดิน เกาะทั้งเกาะก็ถูกโอบไว้ในสายตาเดียว ยิ่งขึ้นสูงเท่าไร ทิวทัศน์ก็ยิ่งกว้างใหญ่ใจดีขึ้นเท่านั้น"},"ICON-1833":{"nm":"สายรัดขึ้นบอลลูน","de":"สายที่รัดรอบข้อมือก่อนปีนขึ้นตะกร้า เมื่อเปลวไฟพองตัวและพื้นดินเริ่มห่างออกไป หัวใจก็เบาโหวงตามไปด้วย การลอยขึ้นหมายถึงการวางน้ำหนักลงชั่วครู่"},"ICON-1834":{"nm":"ชิปเรียกแท็กซี่ทางน้ำ","de":"ชิปเล็ก ๆ สำหรับเรียกแท็กซี่ที่วิ่งอยู่บนผืนน้ำ ยกมือขึ้นเรือก็แล่นฝ่าคลื่นเข้ามาใกล้ สิ่งที่สร้างเส้นทางขึ้นในที่ที่ไม่มีทางได้ สุดท้ายแล้วก็คือความกล้าของคนที่เรียกก่อนนั่นเอง"},"ICON-1835":{"nm":"บัตรผ่านทางเข้าเส้นทางเดินป่า","de":"บัตรผ่านที่ได้รับที่ประตูแรกสู่ภูเขา จากจุดนี้ไป ปลายเท้าจะเป็นผู้กำหนดเส้นทางเอง ยอดเขาอาจยังไกล แต่มีเพียงผู้ที่ผ่านด่านทางเข้าเท่านั้นที่จะได้รับสัญญาว่าจะได้เห็นทิวทัศน์นั้น"},"ICON-1836":{"nm":"กุญแจตู้เก็บของท่าเรือ","de":"กุญแจเล็ก ๆ ที่ไขตู้เก็บของริมท่าเรือ ฝากสัมภาระไว้แล้วมองทะเลด้วยมือที่เบาลง การมีที่วางของลงชั่วคราวสักที่หนึ่ง คือการยืมความกล้าเพื่อออกเดินทางไกล"},"ICON-1837":{"nm":"ฝาโหลดองผัก","de":"ฝาโหลที่กักเก็บของเปรี้ยวทั้งหลายไว้ ปิดให้แน่นแล้วแตงกวาแห่งฤดูร้อนก็ยังคงความกรอบไปจนถึงฤดูหนาว เคล็ดลับที่จะเอาชนะกาลเวลาได้ แท้จริงแล้วเริ่มต้นจากการปิดให้ดีนี่เอง"},"ICON-1838":{"nm":"ป้ายชื่อตะแกรงตากแห้ง","de":"ป้ายชื่อที่ติดกับสิ่งของที่วางตากบนตะแกรง เขียนไว้ว่าตากอะไรไว้เมื่อไร การรอคอยก็จะไม่ยุ่งเหยิง แม้ในช่วงเวลาของแดดและลม ก็ยังต้องมีสิ่งที่เรียกว่าลำดับก่อนหลังเช่นกัน"},"ICON-1839":{"nm":"ซองชิปไม้รมควัน","de":"ซองที่บรรจุเศษไม้หอมไว้ เปิดปากซองแล้วกลิ่นเหมือนกองไฟจะทักทายปลายจมูกก่อนสิ่งอื่นใด รสชาติที่ลึกซึ้งขึ้นด้วยควันจะเผยตัวออกมาอย่างช้า ๆ เฉพาะกับผู้ที่รู้จักการรอคอยเท่านั้น"},"ICON-1840":{"nm":"สติกเกอร์อาหารหมักดอง","de":"สติกเกอร์ที่ติดบนโหลเพื่ออวยพรให้ผ่านพ้นทั้งปีไปได้ดี วันที่ดองและความตั้งใจถูกเขียนไว้บนนั้น อาหารที่เก็บไว้กินนาน ๆ มักมาพร้อมโน้ตเล็ก ๆ ที่พยายามจดจำรสมือของวันนั้นเสมอ"},"ICON-1841":{"nm":"ป้ายนาฬิกาการหมัก","de":"การหมักไม่เชื่อนาฬิกา เพราะมันวัดเวลาด้วยกลิ่นแทนเข็มนาที ในวินาทีที่กลิ่นเปรี้ยวโชยมาถึงปลายจมูก ป้ายนี้จะพยักหน้าเงียบ ๆ ว่า \"ได้แล้วนะ\" แม้แต่การรอคอยก็ยังมีขีดวัดของตัวเอง"},"ICON-1842":{"nm":"หมุดจัดชั้นตู้เย็น","de":"ตำรวจจราจรตัวจิ๋วของตู้เย็นอยู่ตรงนี้ ผักไว้ชั้นบน กับข้าวไว้ชั้นล่าง ของเหลือเมื่อวานไว้แถวหน้า ปักหมุดหนึ่งอันไว้ มือที่เคยหลงทางทุกครั้งที่เปิดประตูก็รู้ทางในไม่ช้า"},"ICON-1843":{"nm":"สายรัดกล่องข้าวเก็บอุ่น","de":"แม่พันสายรัดรอบกล่องข้าวไว้ เพื่อไม่ให้ความอุ่นหนีไปก่อนถึงมื้อเที่ยง แก้สายออกแล้วใต้ฝากล่องที่มีไอน้ำเกาะ ความตั้งใจของยามเช้ายังคงนอนอุ่นรอฉันอยู่"},"ICON-1844":{"nm":"ขวดหมักบ่มซอส","de":"เครื่องปรุงที่ดีไม่เคยรีบร้อน มันมอบเวลาให้ซีอิ๊วกับกระเทียมค่อย ๆ ซึมซาบเข้าหากันอย่างเงียบ ๆ ในความมืดของขวด รสชาติค่อย ๆ ลึกซึ้งขึ้น และภูมิปัญญาอันเชื่องช้าของลานโอ่งก็ย้ายมาอยู่ในขวดใบเล็กนี้"},"ICON-1845":{"nm":"ป้ายแยมตามฤดูกาล","de":"สตรอว์เบอร์รีในฤดูใบไม้ผลิ แอปริคอตในฤดูร้อน มะเดื่อในฤดูใบไม้ร่วง ป้ายเพียงแผ่นเดียวจดฤดูกาลไว้บนขวดอย่างเป็นระเบียบ เปิดฝาในกลางฤดูหนาว แสงแดดของปีที่แล้วก็ค่อย ๆ ละลายออกมาทีละช้อน"},"ICON-1846":{"nm":"กระดานเข็มกลัดอัตราสะสม","de":"ไม่ต้องเสียเวลานับก็ได้ว่าสะสมไว้กี่ชิ้นแล้ว เพราะกระดานเข็มกลัดจะอวดแทนเราเอง ทุกครั้งที่ช่องว่างถูกเติมเต็ม ไหล่ก็ยกขึ้นด้วยความภูมิใจ นี่ไม่ใช่ตัวเลข แต่คือรอยเท้าที่ย่ำมาด้วยปลายเท้า"},"ICON-1847":{"nm":"การ์ดช่องที่ยังไม่พบ","de":"ตำแหน่งหนึ่งที่ยังไม่เคยพบเจอ เงาดำในการ์ดมอบคำสัญญาด้วยเค้าโครงที่พร่าเลือน ว่างเปล่าหมายถึงจะถูกเติมเต็มในไม่ช้า ความตื่นเต้นจึงรอคุณอยู่เสมอในรูปทรงของเครื่องหมายคำถาม"},"ICON-1848":{"nm":"ตราประทับสมบูรณ์สมุดภาพ","de":"เสียง \"ปัง\" ของตราประทับที่ลงบนช่องสุดท้ายนั้น ปิดสมุดภาพแล้วแบมือออกดู หมึกแดงจุดหนึ่งติดอยู่ราวกับเหรียญตราแห่งความสำเร็จ ความโล่งใจอันลึกซึ้งนั้น มีเพียงผู้ที่สะสมจนครบเท่านั้นที่จะรู้จัก"},"ICON-1849":{"nm":"ชิปสีระดับความหายาก","de":"แม้รูปทรงจะเหมือนกัน แต่ถ้าสีต่างกัน เรื่องราวก็ต่างไปด้วย ชิปเพียงชิ้นเดียวขีดเส้นแบ่งอย่างเงียบ ๆ ระหว่างความธรรมดากับความล้ำค่า สายตาของนักสะสมมักหยุดนิ่งอยู่นานเสมอต่อหน้าความแตกต่างของเฉดสีที่แสนละเอียดอ่อนนั้น"},"ICON-1850":{"nm":"บัตรแลกของสะสมซ้ำ","de":"อีกแล้วเหรอ อีกแล้ว ในวันที่เก็บของชิ้นเดิมได้เป็นชิ้นที่สาม บัตรแลกนี้ก็ยื่นมือมาให้อย่างแผ่วเบา ราวกับคำปลอบใจอันอ่อนโยนว่า หากไม่ทิ้งของซ้ำแต่โอบกอดมันไว้ วันหนึ่งมันจะกลับมาเป็นสิ่งล้ำค่า"},"ICON-1851":{"nm":"ป้ายเลขกล่องสะสม","de":"ติดหมายเลขไว้ที่กล่องแต่ละใบ แล้วห้องเก็บของก็กลายเป็นห้องสมุดเล็ก ๆ กล่องเลข 17 เก็บของที่รวบรวมในฤดูใบไม้ผลิ กล่องเลข 23 เก็บของที่เก็บได้จากชายทะเล ฉันคือดัชนีเงียบงันที่จัดเรียงความทรงจำที่กระจัดกระจายไว้ทีละบรรทัด"},"ICON-1852":{"nm":"คู่มือจัดวางตำแหน่งจัดแสดง","de":"การจัดแสดงครึ่งหนึ่งถูกสร้างขึ้นด้วยตำแหน่ง ของที่สูงไว้ด้านหลัง ของที่แวววาวไว้ตรงกลาง เคลื่อนมือตามคู่มือไปเรื่อย ๆ ชั้นวางที่เคยรกรุงรังก็ค่อย ๆ ผ่อนลมหายใจราวกับกลายเป็นแกลเลอรีเล็ก ๆ"},"ICON-1853":{"nm":"แปรงปัดฝุ่นของสะสม","de":"ยิ่งเป็นของที่รักมากเท่าไร ฝุ่นก็ยิ่งเกาะได้ดีเท่านั้น ปลายแปรงนุ่ม ๆ ค่อย ๆ ปัดออก พร้อมกวาดความรู้สึกผิดที่ไม่ได้มองมันมานานออกไปด้วย ระหว่างที่เช็ดอยู่นั้น ความทรงจำที่เคยหลับใหลก็เปล่งประกายขึ้นอีกครั้งชั่วครู่"},"ICON-1854":{"nm":"บัตรขยายขีดจำกัดพื้นที่เก็บ","de":"สะสมไปเรื่อย ๆ จนที่เก็บไม่พอ ก็กลายเป็นความกังวลที่มีความสุข หัวใจที่โล่งใจเงียบ ๆ เมื่อเห็นชั้นวางเพิ่มขึ้นอีกหนึ่งช่อง นี่ไม่ใช่ความโลภ แต่เป็นหลักฐานว่ามีสิ่งที่รักมากมายเพียงนั้น"},"ICON-1855":{"nm":"การ์ดโค้ดชวนเพื่อน","de":"การยื่นโค้ดนี้ให้คือคำเชิญที่อ่อนโยนที่สุดว่า \"มาเล่นด้วยกันนะ\" หัวใจที่บรรจุอยู่ในตัวเลขไม่กี่ตัว เมื่อเพื่อนที่ได้รับก้าวเท้าแรกลงบนเกาะ เรื่องราวของสองคนก็เพิ่งจะเริ่มต้นขึ้น"},"ICON-1856":{"nm":"กุญแจโกดังร่วม","de":"ประตูโกดังไม่เคยเปิดออกเพียงลำพัง เป็นกุญแจที่จะหมุนได้ก็ต่อเมื่อมือสองข้าง ของเธอและของฉันมารวมกันเท่านั้น พื้นที่ที่ใช้ร่วมกันมักมีคำสัญญาที่รักษาไว้ด้วยกันเสมอ แขวนอยู่ในรูปทรงของกุญแจเช่นนี้"},"ICON-1857":{"nm":"ป้ายแจ้งของหาย","de":"แม้แต่ของที่หายไปก็ยังมีค่าสำหรับใครสักคน การเขียนบรรทัดเดียวว่า \"อยู่ที่นี่นะ\" แล้วแขวนไว้ ป้ายนี้คือเชือกเล็ก ๆ ที่เชื่อมหัวใจที่หลงทางไปชั่วครู่กับเจ้าของกลับมาหากันอีกครั้งอย่างเงียบ ๆ"},"ICON-1858":{"nm":"ธงขอความช่วยเหลือ","de":"คำว่าช่วยด้วยไม่ใช่ความอ่อนแอ แต่คือความกล้าหาญ เมื่อธงถูกชักขึ้น ใครสักคนก็จะวิ่งมาจากที่ใดที่หนึ่งเสมอ สิ่งที่แพร่กระจายเร็วที่สุดบนเกาะนี้ไม่ใช่ข่าวลือ แต่คือมือที่ยื่นออกไปหากันและกัน"},"ICON-1859":{"nm":"กำไลข้อมือติดต่อฉุกเฉิน","de":"ความอุ่นใจเล็ก ๆ หนึ่งอย่างที่พันรอบข้อมือ ไม่ว่าจะเกิดอะไรขึ้น หมายเลขที่เขียนไว้ตรงนี้จะวิ่งมาถึงก่อนใคร มันคือเพื่อนร่วมทางเงียบ ๆ ที่มักถูกลืมในวันปกติ แต่กลับกลายเป็นที่พึ่งที่มั่นคงที่สุดในยามจำเป็น"},"ICON-1860":{"nm":"ชิปแบ่งหน้าที่","de":"ใครไปจ่ายตลาด ใครทำอาหาร แบ่งชิปกันไปก็ไม่มีเรื่องทะเลาะ ก้าวแรกของการสร้างสิ่งใดสิ่งหนึ่งด้วยกัน เริ่มต้นจากการกำหนดส่วนของแต่ละคนให้กันอย่างอ่อนโยน"},"ICON-1861":{"nm":"ตารางผลิตร่วมมือ","de":"สิ่งที่คนเดียวไม่กล้าแม้แต่จะคิด กลับเป็นไปได้อย่างน่าอัศจรรย์เมื่อหลายคนมารวมกัน ยิ่งชื่อถูกเติมลงในตารางทีละชื่อ ช่องว่างก็ยิ่งลดลงและเสียงหัวเราะก็ยิ่งเพิ่มขึ้น ความร่วมมือเติบโตขึ้นอย่างเงียบ ๆ ในช่องว่างระหว่างแต่ละช่อง"},"ICON-1862":{"nm":"การ์ดมารยาทการมาเยือน","de":"เมื่อก้าวเข้าไปในบ้านของคนอื่น ปลายเท้าก็เริ่มระมัดระวังขึ้นทันที สิ่งที่เขียนไว้ในการ์ดไม่ใช่กฎเกณฑ์อันยิ่งใหญ่ มีเพียงคำสัญญาเล็ก ๆ ที่อบอุ่น อย่างเช่น \"วางรองเท้าให้เรียบร้อย ทักทายก่อนเสมอ\""},"ICON-1863":{"nm":"กระดิ่งเลิกงานปาร์ตี้","de":"แม้แต่ความสนุกก็ต้องมีจุดจบ ครั้งต่อไปจึงจะน่ารอคอย เมื่อกระดิ่งดัง \"กริ๊ง\" ทุกคนก็เก็บของด้วยสีหน้าอาลัยอาวรณ์ ปาร์ตี้ที่รู้จักวิธีจากลาอย่างดี คือปาร์ตี้ที่ฝังอยู่ในใจนานที่สุด"},"ICON-1864":{"nm":"สายรัดมุมที่นอน","de":"ไม่ว่าจะปูผ้าปูเรียบแค่ไหน มุมก็มักจะหลุดลอยขึ้นเสมอ ด้วยสายรัดที่จับมุมทั้งสี่ไว้อย่างแน่นหนา เตียงในทุกเช้าจึงตื่นขึ้นเรียบร้อยราวกับห้องพักโรงแรม"},"ICON-1865":{"nm":"เชือกกระดุมปกผ้าห่ม","de":"ฉันคือเชือกกระดุมที่ยึดปกผ้าห่มไว้ ไม่ว่าจะพลิกตัวมากแค่ไหนตลอดคืน ฉันก็กำแน่นไม่ให้ปกหลุดหนีไปไหน ผ้าห่มที่ไม่ยับสักนิดเมื่อตื่นนอน นั่นคือรางวัลของกะเวรทั้งคืนของฉัน"},"ICON-1866":{"nm":"คลิปยึดท็อปเปอร์ที่นอน","de":"ท็อปเปอร์พยายามจะเลื่อนหลุดออกทันทีที่มีโอกาส ทุกครั้งที่เป็นเช่นนั้น คลิปจะกัดมุมไว้แน่นและรักษาตำแหน่งไว้ นักดื้อรั้นเงียบ ๆ ที่คอยยึดที่นอนไว้จากมุมที่มองไม่เห็น"},"ICON-1867":{"nm":"ที่รีดรอยยับผ้าปูที่นอน","de":"รอยยับเล็ก ๆ ที่เกิดขึ้นบนผ้าปูที่นอนระหว่างคืนช่างคล้ายกับรอยยับในใจอย่างประหลาด เหมือนผ้าที่เรียบเนียนขึ้นด้วยการปาดหนึ่งครั้งของที่รีดนี้ ฉันหวังว่าวันที่ยุ่งเหยิงจะถูกรีดให้เรียบร้อยอย่างอ่อนโยนเช่นนั้นเหมือนกัน"},"ICON-1868":{"nm":"ฐานระบายอากาศที่นอน","de":"แม้แต่ที่นอนก็ต้องการช่องหายใจ เมื่อฐานเปิดทางลมด้านล่าง ความอับชื้นก็ระบายออกและความแห้งสบายก็แทรกซึมเข้ามา การนอนหลับที่ดีเริ่มต้นขึ้นอย่างเงียบ ๆ จากอากาศที่รองรับแผ่นหลังนั้นเอง"},"ICON-1869":{"nm":"ฝาปิดซิปปลอกผ้าห่ม","de":"ความวุ่นวายกลางดึกที่นุ่นชอบโผล่ออกมาทุกครั้งที่เปลี่ยนปลอกผ้าห่ม ปิดซิปด้วยฝาครอบเพียงครั้งเดียว ก็ไม่ต้องตื่นเพราะเท้าไปเกี่ยวเข้าอีก ความสงบอันยิ่งใหญ่ที่ฝาเล็ก ๆ ใบเดียวพามาให้"},"ICON-1870":{"nm":"แผ่นกันนุ่นจับตัวเป็นก้อน","de":"นุ่นในหมอนไม่นานก็มักจะไปกองอยู่ด้านเดียว จนกลายเป็นเนินเล็ก ๆ เมื่อแผ่นนี้ยืนหยัดคั่นไว้ระหว่างช่องว่างอย่างเงียบ ๆ ความเรียบก็คงอยู่ไปจนสุดท้าย ด้วยเหตุนี้ ทุกคืนความฟูนุ่มราวกับใหม่จึงกลับมาโดยไม่เคยขาด"},"ICON-1871":{"nm":"ตะขอยางยืดผ้าปูเตียง","de":"ผ้าปูที่นอนมักพยายามลอกหลุดไปด้านใดด้านหนึ่งอยู่เสมอ เกี่ยวตะขอที่มุมแล้วดึงให้ตึง แม้จะพลิกตัวไปมาทั้งคืนก็ไม่ขยับเลยสักนิด ความตึงจึงกลายเป็นรากฐานของการหลับลึกอย่างเงียบ ๆ เช่นนี้"},"ICON-1872":{"nm":"ป้ายเปลี่ยนปลอกหมอน","de":"เมื่อจู่ ๆ ก็สับสนว่าวันนี้ซักปลอกหมอนไปแล้วหรือยัง ป้ายแผ่นเดียวจะตอบให้ชัดเจน ตารางที่มักถูกลืมเพราะนอนแล้วนอนอีก ป้ายเล็ก ๆ นี้จำแทนให้อย่างขยันขันแข็ง"},"ICON-1873":{"nm":"ที่คั่นหนังสือบันทึกความฝัน","de":"ความฝันที่กระจัดกระจายหายไปตามช่องนิ้วมือทันทีที่ตื่น ถูกที่คั่นหนังสือตรึงไว้บนหน้าที่มันคั่นไว้ เปิดออกมาแล้วทะเลและท้องฟ้าของเมื่อคืนก็ยังคงอยู่ที่เดิม เป็นสะพานเล็ก ๆ ที่วางไว้อย่างแผ่วเบาระหว่างการนอนหลับกับการเขียน"},"ICON-1874":{"nm":"หินกรวดเสียงไวท์นอยส์","de":"คืนที่เงียบเกินไปมักจะปลุกให้ตื่นแทนที่จะช่วยให้หลับ เมื่อหินกรวดปล่อยเสียงกรอบแกรบราวกับเสียงฝนโปรยปราย หัวใจก็ค่อย ๆ จมดิ่งลงตามลายเสียงนั้น หินเล็ก ๆ ที่ปลอบประโลมความเงียบไว้อย่างอ่อนโยน"},"ICON-1875":{"nm":"ชิปตรวจอุณหภูมิการนอน","de":"ไม่ว่าหน้าผากจะร้อนหรือปลายเท้าจะเย็นระหว่างหลับ ชิปนี้จะเฝ้าดูอยู่ข้าง ๆ อย่างเงียบ ๆ ด้วยยามเฝ้ายามค่ำคืนที่ค่อย ๆ หาอุณหภูมิที่พอดีกับร่างกาย การนอนหลับจึงไหลลื่นไปจนถึงรุ่งเช้าโดยไม่สะดุ้งตื่น"},"ICON-1876":{"nm":"คลิปหนีบผ้าม่านทึบแสง","de":"แสงแดดยามเช้าช่างขยันเสียจริง คอยแทรกผ่านช่องม่านเข้ามาเสมอ หนีบปลายทั้งสองข้างด้วยคลิปให้แน่น ห้องก็จะมืดสนิทราวกับกลางดึกอีกครั้ง เป็นผู้สมรู้ร่วมคิดที่ไว้ใจได้สำหรับการนอนตื่นสายอีกสักวัน"},"ICON-1877":{"nm":"โคมฉายแสงจันทร์","de":"ปิดไฟแล้วดวงจันทร์ก็ลอยขึ้นเหนือเพดาน แสงนวลที่โคมฉายขึ้นไปเปลี่ยนห้องให้กลายเป็นท้องฟ้ายามค่ำคืนเล็ก ๆ ความรู้สึกของการหลับตาไปพร้อมกับมองดวงจันทร์นั้น ถูกวางไว้ที่หัวเตียงพอดี"},"ICON-1878":{"nm":"ที่แขวนถุงหอมช่วยนอนหลับ","de":"ถุงเล็ก ๆ ที่บรรจุกลิ่นลาเวนเดอร์และกลิ่นหญ้าไหวเบา ๆ อยู่ที่หัวเตียง กลิ่นหอมที่ซึมเข้าปลายจมูกทำให้ไหล่ค่อย ๆ คลายลง ถุงหอมเพียงใบเดียวชักชวนให้หลับก่อนแม้แต่หมอน"},"ICON-1879":{"nm":"เข็มกล่องดนตรีเพลงกล่อมเด็ก","de":"หมุนลานเบา ๆ แล้วทำนองเล็ก ๆ ก็คลี่ออกมา เพลงกล่อมเด็กที่หมุนออกมาจากปลายเข็มนี้ ช่างคล้ายกับจังหวะที่คุณยายเคยตบหลังกล่อมนอนไม่ผิดเพี้ยน ทุกโน้ตค่อย ๆ ทำให้เปลือกตาหนักลงทีละนิด"},"ICON-1880":{"nm":"แก้วปลูกพืชเพิ่มความชื้น","de":"ฉันคือแก้วที่เลี้ยงต้นไม้ด้วยน้ำใสแทนดิน มองรากฝอยที่ลอยอยู่ในน้ำไปเรื่อย ๆ อากาศในห้องก็ดูจะชื้นขึ้นมาอีกนิด บ่อน้ำสีเขียวเล็ก ๆ ที่ขังอยู่บนโต๊ะทำงาน"},"ICON-1881":{"nm":"ขวดเก็บเศษเสี้ยวความฝัน","de":"ความฝันที่รั่วไหลออกมาระหว่างหลับไม่มีรูปทรง พอตื่นขึ้นก็รั่วหายไปตามช่องนิ้วมือ การกักเศษเสี้ยวที่กำลังจะสูญหายไว้ด้วยฝาขวดเงียบ ๆ จนถึงเช้า ความปรารถนาที่อยากจดจำเริ่มต้นจากจุดเล็ก ๆ เช่นนี้เอง"},"ICON-1882":{"nm":"ถาดวางแว่นข้างเตียง","de":"ในวินาทีที่ถอดแว่นวางลง อย่างน่าประหลาด ความเหนื่อยล้าของทั้งวันก็วางลงไปด้วย มุมเล็ก ๆ ข้างหัวเตียงนี้มีอยู่เพื่อรองรับการเคลื่อนไหวนั้นเพียงครั้งเดียว ถาดที่ทำให้โลกพร่ามัวลงอย่างเงียบ ๆ ก่อนหลับใหล"},"ICON-1883":{"nm":"วงแหวนรองแก้วน้ำโต๊ะข้างเตียง","de":"รอยกลมที่แก้วน้ำทิ้งไว้หนึ่งรอยอาจดูเล็กน้อย แต่สำหรับลายไม้ของโต๊ะข้างเตียงแล้วมันคือรอยตำหนิ วงแหวนเล็ก ๆ นี้สวมไว้เพื่อป้องกันมัน หัวใจที่รักและถนอมมักทำงานอย่างเงียบ ๆ ในมุมที่มองไม่เห็นเช่นนี้เสมอ"},"ICON-1884":{"nm":"เครื่องมือตั้งมุมพับผ้าห่ม","de":"แม้แต่การพับผ้าห่มให้เป็นสี่เหลี่ยมเรียบร้อยก็ยังมีลายเฉพาะของมัน จัดมุมให้ตรงตามเครื่องมือตั้งมุมนี้ แม้แต่หัวใจที่ยุ่งเหยิงก็ถูกคลี่ให้เรียบไปด้วยครั้งหนึ่ง มุมที่จัดเป็นระเบียบคือคำทักทายที่สุภาพที่สุดในการเริ่มต้นวันใหม่"},"ICON-1885":{"nm":"ตะขอแขวนสายชาร์จข้างเตียง","de":"ตะขอที่แขวนไว้ข้างหัวเตียงเพราะเกลียดที่สายชาร์จมักลื่นไถลลงพื้นตลอดทั้งคืน สายที่ค่อย ๆ เติมพลังอย่างเงียบ ๆ ระหว่างที่เรานอนหลับ พอถึงเช้าก็รอปลายนิ้วเราอยู่ด้วยพลังเต็มเปี่ยม"},"ICON-1886":{"nm":"ตะกร้าขนมข้างเตียง","de":"ตะกร้าที่รวบรวมขนมโปรดไว้ในระยะที่เอื้อมถึง เป็นการเตรียมพร้อมอันอ่อนโยนที่คาดการณ์ล่วงหน้าว่าความหิวยามดึกจะมาเยือน เสียงกรอบแกรบที่หยิบขึ้นมากัดสักชิ้นท่ามกลางความมืดนั้นช่างอบอุ่นใจอย่างบอกไม่ถูก"},"ICON-1887":{"nm":"ปีกที่วางหนังสือก่อนนอน","de":"ปีกที่ค่อย ๆ พยุงหน้าหนังสือที่เปิดค้างไว้ให้ไม่หลงบรรทัดที่อ่าน แม้ความง่วงจะถาโถมเข้ามา หน้าเดียวที่ปิดไว้ก่อนดวงตาจะหลับสนิท จะรอคุณอยู่ที่เดิมในคืนพรุ่งนี้"},"ICON-1888":{"nm":"ฐานหินนาฬิกาปลุกข้างเตียง","de":"แม้แต่นาฬิกาปลุกที่ปลุกยามเช้าก็ต้องการที่ทางของตัวเองที่ไม่โคลงเคลง ฐานหินทรงกลมรองรับน้ำหนักนั้นไว้อย่างหนักแน่น และรักษาตำแหน่งนั้นไว้ราวกับคำสัญญาที่ไม่มีวันลื่นไถล แม้รุ่งอรุณจะมาเยือนก็ตาม"},"ICON-1889":{"nm":"ตะปูแขวนที่ปิดตานอนหลับ","de":"ตะปูสำหรับแขวนผ้าปิดตาที่บังแสงให้ทั้งคืน เพื่อให้มันได้หายใจในช่วงกลางวัน การมอบที่แห้งให้ผ้าที่ทำหน้าที่ของมันจนครบ การดูแลเล็ก ๆ เช่นนี้ซึมซาบเข้ามาอย่างไร้ที่ติ"},"ICON-1890":{"nm":"คลิปหนีบไฟฉายข้างเตียง","de":"คลิปที่จับแสงเล็ก ๆ ที่ต้องการยามดึกให้หันไปทางที่ต้องการ หนีบไฟฉายไว้ที่ขอบเตียง มือที่เคยคลำหาในความมืดก็สบายขึ้นมาก สัมผัสที่กำหนดทิศทางของแสงไว้ให้"},"ICON-1891":{"nm":"เชือกรั้งม่านกั้นห้อง","de":"เชือกรั้งที่จับม่านซึ่งกั้นพื้นที่ส่วนรวมไว้ แม้จะเป็นเพียงผ้าบางแผ่นเดียว แต่เหนือกว่านั้นคือค่ำคืนส่วนตัวของใครสักคน เส้นแบ่งอันอ่อนโยนที่ปกป้องการนอนหลับของกันและกันในห้องที่อยู่ร่วมกัน"},"ICON-1892":{"nm":"แผ่นไม้แบ่งปลั๊กไฟร่วม","de":"แผ่นไม้ที่ทำขึ้นเพื่อให้หลายคนแบ่งกันใช้ปลั๊กเดียว มันกระจายไฟฟ้าอย่างทั่วถึงเพื่อไม่ให้ค่ำคืนของใครมืดมิด การอยู่ร่วมกันสุดท้ายแล้วก็เริ่มต้นจากการแบ่งปันสิ่งเล็ก ๆ เช่นนี้เอง"},"ICON-1893":{"nm":"หินขอลดแสงไฟ","de":"เมื่อแสงไฟสว่างเกินไป แทนคำพูด เธอเลื่อนหินก้อนนี้ไปให้แทน \"หรี่ลงหน่อยได้ไหม\" ของเล็ก ๆ ชิ้นนี้ส่งคำพูดประโยคเดียวนั้นแทนเธอ เป็นคำขอที่อ่อนโยนที่สุดในห้องที่อยู่ร่วมกัน"},"ICON-1894":{"nm":"โทเคนขอผลัดเวลาตื่นนอน","de":"แผ่นเล็ก ๆ ที่ส่งต่อไปยังฝ่ามือของคนที่จะตื่นก่อน ใครจะได้นอนต่อในยามเช้าและใครจะตื่นก่อน โทเคนนี้ตัดสินให้โดยไม่มีการทะเลาะกัน หัวใจที่กำหนดลำดับของการเสียสละด้วยปลายนิ้ว"},"ICON-1895":{"nm":"วงแหวนเลขไม้แขวนเสื้อร่วม","de":"วงแหวนเลขที่ติดไว้บนไม้แขวนเสื้อที่ใช้ร่วมกันหลายคน เพื่อไม่ให้สับสนว่าที่ของใครเป็นของใคร ตัวเลขเล็ก ๆ เพียงตัวเดียวสร้างระเบียบขึ้นอย่างเงียบ ๆ เส้นแบ่งอันอ่อนโยนที่ขีดไว้ในชีวิตประจำวันที่ปะปนกันได้ง่าย"},"ICON-1896":{"nm":"ฝาครอบขั้นบันไดเตียงสองชั้น","de":"ฝาที่สวมครอบบันไดที่ปีนขึ้นชั้นบน เพื่อไม่ให้เท้าเปล่าที่แตะสัมผัสรู้สึกเย็นหรือลื่น มันดูแลความปลอดภัยของหนึ่งขั้นนั้นไว้ ความใส่ใจเล็ก ๆ ที่ปลายบันไดนี้ค้ำจุนความฝันของชั้นบนไว้อย่างมั่นคง"},"ICON-1897":{"nm":"แขนแขวนกระดาษทิชชูร่วม","de":"ที่แขวนรูปแขนสำหรับแขวนกระดาษทิชชูของห้องน้ำรวม ถูกจัดวางตำแหน่งให้ใครก็ดึงกระดาษออกได้ง่าย ๆ ด้วยมือข้างเดียว แม้จะดูเป็นเรื่องเล็กน้อย แต่ก็คือสัมผัสที่ทำให้เช้าของหลายคนราบรื่นขึ้น"},"ICON-1898":{"nm":"ชิปลำดับเติมน้ำหอมปรับอากาศ","de":"ชิปที่จดไว้ว่าถึงตาใครที่จะเติมน้ำหอมปรับอากาศ แม้แต่กลิ่นหอมโรยรินสักเส้นก็เป็นคำสัญญาที่จะรับผิดชอบผลัดกันไป กลิ่นหอมดี ๆ ไม่ได้มาฟรี แต่บานสะพรั่งขึ้นจากตาของใครสักคน"},"ICON-1899":{"nm":"ที่จับโคมไฟนอนหลับร่วม","de":"ด้ามจับของโคมไฟนอนหลับที่หลายคนเปิดปิดร่วมกัน มือที่ตื่นอยู่ดึกที่สุดจะเป็นคนเก็บแสงนั้นเป็นคนสุดท้าย คำสัญญาเงียบ ๆ ของผู้ที่อยู่ห้องเดียวกัน ที่แบ่งปันแสงไฟนวล ๆ ให้แก่กัน"},"ICON-1900":{"nm":"ร่องวางแก้วที่ท้าวแขนโซฟา","de":"ร่องวางแก้วทรงกลมที่เจาะไว้บนที่ท้าวแขนโซฟา วางแก้วลงจากมือชั่วครู่ก็ไม่ต้องกังวลว่าจะหก มุมพักผ่อนต้องมีที่วางแก้วสักที่หนึ่ง หัวใจจึงจะยืดเหยียดได้อย่างสบายใจอย่างแท้จริง"},"ICON-1901":{"nm":"ห่วงดึงซิปไส้เบาะ","de":"ห่วงเล็กๆ ที่ติดอยู่กับซิปสำหรับเปิดปิดไส้เบาะ ห่วงเดียวนี้ช่วยลดความยุ่งยากในการเปลี่ยนผ้าซัก ปลายนิ้วที่ใส่ใจแม้กระทั่งด้านในที่มองไม่เห็น—ความอ่อนโยนของงานบ้านมักซ่อนอยู่ตรงนั้นเสมอ"},"ICON-1902":{"nm":"เบาะเสริมพนักพิงโซฟา","de":"เบาะที่เข้าไปเติมเต็มช่องว่างของพนักพิง คอยประคองแผ่นหลังให้ไม่ปวดเมื่อยแม้นั่งนาน มันเติมเต็มที่ว่างเพื่อไม่ให้หลังต้องเมื่อยล้า ความสบายที่ร่างกายรับรู้ได้ก่อนใคร พร้อมถอนใจว่า \"อ๊ะ ใช่เลย\" ในวินาทีที่เอนหลังพิง"},"ICON-1903":{"nm":"แถบยึดมุมเบาะรองนั่ง","de":"แถบที่จับยึดเบาะรองนั่งไว้ตรงมุม เบาะที่เคยเลื่อนไถลตามทุกครั้งที่นั่งลง มันตรึงไว้ในที่เดียวไม่ให้ลื่นไถล ความเรียบร้อยเริ่มต้นจากการยึดติดเล็กๆ ที่ดื้อรั้นเช่นนี้เอง"},"ICON-1904":{"nm":"แถบกันตะเข็บเบาะ","de":"จุดแรกที่เบาะมักจะสึกหรอเสมอคือตะเข็บตรงมุม แถบกันตะเข็บนี้พันรอบจุดนั้นไว้ล่วงหน้า ปกป้องไม่ให้มันปริแตก หัวใจที่อยากเก็บมันไว้ข้างกายนานๆ นั้นแน่นหนาราวกับรอยเย็บ"},"ICON-1905":{"nm":"กระเป๋าเก็บรีโมทซอกโซฟา","de":"รีโมทที่เคยหายลับไปตามซอกเบาะในที่สุดก็มีบ้านเป็นของตัวเองแล้ว กระเป๋าเล็กๆ ที่สอดไว้ในซอกโซฟา การรู้ว่าสิ่งที่คิดว่าหายไปนั้นอยู่ตรงนั้นเสมอ คือความอุ่นใจที่ยิ่งใหญ่กว่าที่คิด"},"ICON-1906":{"nm":"เชือกม้วนผ้าห่มตัก","de":"เชือกสำหรับม้วนและมัดผ้าห่มตักให้เป็นก้อน ความอบอุ่นที่กระจัดกระจายเมื่อคลี่ทิ้งไว้ ถูกเก็บให้เป็นระเบียบเพื่อค่ำคืนถัดไป หากเก็บความอบอุ่นไว้แบบนี้ พรุ่งนี้ก็หยิบมาห่มได้อีกครั้ง"},"ICON-1907":{"nm":"กระดุมปลอกที่วางเท้า","de":"กระดุมที่ยึดปลอกที่วางเท้า ส่วนที่สึกเร็วที่สุดเพราะเท้าสัมผัสตลอด ให้ถอดเปลี่ยนได้ง่าย การกดกระดุมเพียงครั้งเดียวช่วยยืดอายุผ้าออกไป หัวใจที่อยากใช้ของให้นานนั้นละเอียดถี่ถ้วนในจุดเล็กๆ"},"ICON-1908":{"nm":"ฝาครอบกันลื่นขาโซฟา","de":"ต่อให้โซฟาหนักแค่ไหนก็ต้องไม่ขูดพื้น ฝาครอบนุ่มที่สวมปลายขาทั้งสี่ค่อยๆ ย่องเบาถนอมพื้นไม้เอาไว้ เฟอร์นิเจอร์ที่ระมัดระวังไปถึงปลายเท้านั้น ไม่รู้ทำไมถึงยิ่งน่ารักน่าเอ็นดู"},"ICON-1909":{"nm":"ที่วางรวมรีโมท","de":"ที่วางที่จัดเรียงรีโมทซึ่งเคยกลิ้งกระจัดกระจายไปทั่วให้เรียงแถวอยู่ในที่เดียวกัน เมื่อแท่งยาวสั้นตั้งเรียงเป็นแถวเป็นแนว เพียงเท่านั้นบรรยากาศในห้องก็สงบลงไปอีกระดับ"},"ICON-1910":{"nm":"ตะขอแขวนชาร์จเกมแพด","de":"ตะขอสำหรับแขวนชาร์จเกมแพดหลังจบเกมสนุกๆ มาหนึ่งยก ขณะที่มันแขวนนิ่งเติมพลังอย่างเงียบๆ มือของเราก็ได้พักไปด้วย จุดพักสั้นๆ นี้เตรียมพร้อมเราสำหรับยกต่อไปอย่างมั่นคง"},"ICON-1911":{"nm":"ถุงเก็บตัวหมากบอร์ดเกม","de":"ถุงเล็กๆ ที่เก็บตัวหมากหลากสี ชิ้นส่วนที่รอคอยยกถัดไปอยู่ในถุงเดียวกัน ส่งเสียงกรุ๊งกริ๊งทุกครั้งที่เขย่า เสียงนั้นปลุกความตื่นเต้นที่ว่า \"เล่นอีกยกไหม?\" ให้ตื่นขึ้นก่อนใคร"},"ICON-1912":{"nm":"ถาดทอยลูกเต๋า","de":"ถาดที่สร้างมาเพื่อทอยลูกเต๋าโดยเฉพาะ โชคที่เคยกระเด็นออกนอกโต๊ะหายไป ถูกขอบถาดกักไว้ข้างใน ในช่วงเวลาสั้นๆ ที่ลูกเต๋ากลิ้งแล้วหยุดนิ่ง ลมหายใจของทุกคนก็หยุดชะงักพร้อมกันชั่วขณะ"},"ICON-1913":{"nm":"แถบรัดสำรับไพ่","de":"แถบที่รัดสำรับไพ่ไว้ไม่ให้กระจัดกระจาย ก่อนจะสับไพ่ ลำดับนั้นเองคือคำมั่นสัญญา ในท่าทางที่ปลดแถบออกแล้วคลี่ไพ่ เรื่องราวของหนึ่งเกมจึงเริ่มต้นขึ้นในที่สุด"},"ICON-1914":{"nm":"คลิปจัดสายคอนโซล","de":"คลิปที่จับและหวีสายไฟที่พันกันยุ่งเหยิงหลังเครื่องคอนโซลให้เรียบร้อย มันจัดระเบียบความรกในจุดที่แทบมองไม่เห็นอย่างเงียบๆ ความเรียบร้อยเสร็จสมบูรณ์อย่างเงียบเชียบจากด้านหลังเช่นนี้เสมอ"},"ICON-1915":{"nm":"หน้าปัดหมุนนับคะแนน","de":"หน้าปัดเล็กๆ ที่หมุนเพื่อแสดงคะแนน คลิก ทุกครั้งที่ตัวเลขขยับขึ้นทีละช่อง เสียงเชียร์ก็ตามมาติดๆ แม้ไม่ได้นับในหัว ปลายนิ้วก็จดจำผลการแข่งขันของวันนั้นได้ก่อนใคร"},"ICON-1916":{"nm":"ขาตั้งกระดานเกม","de":"ขาตั้งที่พยุงกระดานเกมให้เอียงเป็นมุม เพื่อให้ทุกคนที่นั่งล้อมวงมองเห็นกระดานได้ในสายตาเดียว เพื่อไม่ให้ใครต้องยื่นคอออกไปมอง มันจึงคลี่มุมมองที่เป็นธรรมให้ทุกคนอย่างเงียบๆ"},"ICON-1917":{"nm":"กระบอกจับฉลากลำดับเกม","de":"กระบอกที่ยื่นมือลงไปจับฉลากเพื่อกำหนดลำดับการเล่น แท่งไม้หนึ่งอันที่คลำจับได้ตัดสินว่าใครจะได้เล่นก่อน ในช่วงเวลาสั้นๆ ที่ฝากความหวังไว้กับโชคชะตา ทุกคนใจเต้นระทึกไปด้วยกันในกระบอกกลมใบนั้น"},"ICON-1918":{"nm":"จานแบ่งช่องขนมแบ่งกัน","de":"จานแบ่งช่องสำหรับจัดขนมแยกตามประเภท เมื่อแบ่งพื้นที่ไว้ มือก็ไม่ต้องชนกัน เลือกหยิบสิ่งที่ชอบได้อย่างสบายใจ ความใส่ใจที่คิดถึงคนที่จะแบ่งกินด้วยนั้นบรรจุอยู่ในทุกช่อง"},"ICON-1919":{"nm":"ผ้าคลุมรักษาความอุ่นกาน้ำชา","de":"ผ้าคลุมที่ห่อหุ้มไหล่กาน้ำชาไว้เพื่อรักษาความอุ่น มันห่อกาไว้ไม่ให้ชาเย็นลงระหว่างที่ค่อยๆ ชงจนได้ที่ นี่คือหัวใจของปลายนิ้วที่อยากเสิร์ฟชาอุ่นสักถ้วยให้อุ่นไปจนวินาทีสุดท้าย"},"ICON-1920":{"nm":"ที่วางถุงชาที่ชงเสร็จแล้ว","de":"ที่วางสำหรับยกถุงชาที่ชงจนได้ที่ขึ้นมาพักสักครู่ มันรองรับไว้ไม่ให้แม้แต่หยดสุดท้ายหยดหล่นหาย ที่แห่งนี้มอบบทสรุปที่เรียบร้อยให้แม้กับใบชาที่ทำหน้าที่ของตนจนครบถ้วนแล้ว"},"ICON-1921":{"nm":"ห่วงแบ่งแยกแก้วมัคใช้ร่วม","de":"แก้วมัคเหมือนกันหกใบบนชั้นห้องพักผ่อน แทนที่จะถามว่าใครเป็นเจ้าของ เราสวมห่วงสีสันต่างๆ ให้แต่ละใบ เครื่องหมายเล็กๆ หนึ่งชิ้นผูกโยงคนหกคนที่รสมือรสปากต่างกัน ให้อยู่ ณ ที่เดียวกันบนโต๊ะเดียวกันอย่างสงบ"},"ICON-1922":{"nm":"ตะกร้าแบ่งป๊อปคอร์น","de":"ขณะที่มันส่งต่อจากมือสู่มือ ไอหอมกรุ่นทักทายก่อนใคร ถ้ามีสิ่งใดที่ยิ่งตักออกทีละกำกลับไม่ยิ่งลดลงอย่างประหลาด สิ่งนั้นคงเป็นหัวใจของค่ำคืนที่นั่งล้อมวงแบ่งกันกิน"},"ICON-1923":{"nm":"กระปุกคีมคีบน้ำตาลก้อน","de":"คีบน้ำตาลก้อนเหลี่ยมหนึ่งก้อนแล้วปล่อยลงในถ้วยชา เฝ้ามองมุมสีขาวค่อยๆ ละลายหายไป—นี่คือมารยาทของความหวานที่ไม่เร่งรีบ ซึ่งเรียนรู้ครั้งแรกที่โต๊ะน้ำชาของคุณยาย"},"ICON-1924":{"nm":"แผ่นรองกันลื่นถาด","de":"ต่อให้ถาดเอียง แก้วก็ยังอยู่ในตำแหน่งเดิม เหมือนกับสิ่งที่คอยประคองอยู่เบื้องล่างอย่างเงียบๆ เสมอมา แผ่นรองนี้อดทนต่อวินาทีที่เกือบจะลื่นไถลอยู่เพียงลำพัง แล้วสุดท้ายก็ปิดปากเงียบไว้เช่นเคย"},"ICON-1925":{"nm":"แก้วตั้งหลอดดูดเครื่องดื่ม","de":"ตั้งหลอดดูดให้ตรง ทั้งเครื่องดื่มและใจก็ไม่กระจัดกระจาย ในบ่ายวันที่โต๊ะทำงานเป็นระเบียบขึ้นด้วยความตั้งตรงเล็กๆ เพียงหนึ่งเดียว แก้วก็โอบอุ้มเสาเล็กๆ ไว้ และค่อยๆ ประคองเวลาอันเนิบช้าอย่างเงียบงัน"},"ICON-1926":{"nm":"ที่รองเศษคุกกี้","de":"กรอบ! วินาทีที่คุกกี้แตกออก เศษที่ร่วงหล่นก็มารวมกันตรงนี้ การรองรับแม้แต่ร่องรอยที่หลงเหลือจากคำที่อร่อยที่สุด คือบทสรุปอันเงียบสงบของโต๊ะอาหาร ที่อ่อนโยนแม้กระทั่งกับเศษสุดท้าย"},"ICON-1927":{"nm":"เชือกแขวนรูปคลิปหนีบ","de":"หนีบรูปโพลารอยด์ทีละใบด้วยคลิปแขวนบนเชือกที่ขึงไว้เหมือนราวตากผ้า ขณะที่รอยยิ้มของวันนี้พลิ้วไหวแห้งไปกับสายลม มุมผนังหนึ่งก็กลายเป็นนิทรรศการความทรงจำเล็กๆ ที่สดใส"},"ICON-1928":{"nm":"หลอดด้ายม้วนความทรงจำ","de":"หลอดด้ายที่คลี่เส้นด้ายที่พันกันยุ่งเหยิงออกแล้วม้วนกลับให้เรียบร้อย สิ่งต่างๆ ที่สานต่อมาด้วยปมผูกในทุกจุดที่ขาด หากค่อยๆ ม้วนความทรงจำกลับทีละรอบแบบนี้ เส้นทางที่คิดว่าสั้นลงก็จะยืดยาวขึ้นอีกครั้ง"},"ICON-1929":{"nm":"ฝาครอบรอยตะปูขอแขวนผนัง","de":"ฝาครอบกลมเล็กๆ ที่ปิดรอยตะปู แม้แต่แผลเป็นเล็กๆ ที่เหลืออยู่หลังถอดสิ่งที่เคยแขวนไว้ออกไป เมื่อปิดคลุมไว้อย่างเบามือ ผนังก็กลับมาเรียบเนียนราวกับไม่มีอะไรเกิดขึ้น"},"ICON-1930":{"nm":"กรอบสอดรูปถ่ายหมู่","de":"ภาพถ่ายหมู่ของหกคนที่ถ่ายด้วยไหล่แนบชิดกัน วินาทีที่สอดใส่ลงในกรอบ เสียงหัวเราะและไออุ่นของวันนั้นก็ถูกผนึกไว้ด้วยกัน กรอบรูปคือมือที่หยุดวันเวลาที่ล่วงเลยไปได้อย่างเงียบที่สุด"},"ICON-1931":{"nm":"กระดานคอร์กปักโน้ต","de":"กระดานสีน้ำตาลที่เต็มไปด้วยรอยเข็มหมุด คำสัญญาที่ห้ามลืม โน้ตให้กำลังใจที่ใครสักคนแปะไว้ สิ่งที่ต้องทำวันนี้ ต่างปักซ้อนทับกันเป็นชั้นๆ นี่คือกำแพงที่พึ่งพาได้ข้างโต๊ะทำงาน ที่จดจำแทนหัวสมองของเรา"},"ICON-1932":{"nm":"ปมผูกแขวนพวงมาลัยประดับ","de":"แม้แต่พวงมาลัยที่แขวนบนประตูก็ต้องใช้ฝีมือปลายนิ้ว ต้องผูกปมให้แน่นเพื่อไม่ให้หล่นในฤดูลมแรง หัวใจที่ต้อนรับใครสักคนนั้น มักแข็งแรงขึ้นจากจุดที่มองไม่เห็นเสมอ"},"ICON-1933":{"nm":"ผ้าคลุมลูกตุ้มนาฬิกาแขวน","de":"ผ้าคลุมที่ห่อลูกตุ้มที่แกว่งเดินติ๊กต่อกกันฝุ่นละออง แม้แต่การจับเวลาก็ยังได้รับการดูแลเช่นนี้ หากปกป้องไว้เบาๆ ไม่ให้เก่าเสีย นาฬิกาแขวนผนังก็จะอยู่เคียงข้างเรานานขึ้นอีกสักหน่อย"},"ICON-1934":{"nm":"กระดานรวมสติกเกอร์","de":"สติกเกอร์ที่เคยกระจัดกระจายอยู่ในทุกลิ้นชักมารวมกันเรียงแถวบนกระดานเดียว ตัวการ์ตูนตัวโปรด ดาวประกาย กระดาษลายมือหนึ่งแผ่น เมื่อความสุขเล็กๆ จากการสะสมถูกจัดเรียงอย่างเป็นระเบียบ แม้แต่หัวใจก็เป็นระเบียบขึ้นตามไปด้วย"},"ICON-1935":{"nm":"เชือกร้อยธงประดับ","de":"เชือกที่ร้อยธงหลากสีให้เป็นเส้นเดียวกัน ไม่ว่าจะวันเกิดหรือวันต้อนรับ วินาทีที่เชือกพาดข้ามเพดาน ห้องธรรมดาก็เปลี่ยนเป็นบ้านแห่งงานเลี้ยง การเฉลิมฉลองคือการเชื่อมต่อและปะติดปะต่อหัวใจที่เคยขาดหายไป"},"ICON-1936":{"nm":"แผ่นรองคอร์กรองกาต้มน้ำไฟฟ้า","de":"แผ่นคอร์กแผ่นเดียวที่รองรับก้นกาที่ร้อนจัด เพื่อไม่ให้โต๊ะไหม้เกรียม มันโอบรับความร้อนนั้นไว้แต่เพียงผู้เดียว เป็นความใส่ใจเล็กๆ ที่คอยประคองอยู่อย่างเงียบๆ เพื่อไม่ให้ไออุ่นของใครสักคนทิ้งรอยไว้"},"ICON-1937":{"nm":"ถาดรองเศษขนมปังปิ้ง","de":"เศษที่ร่วงหล่นจากขนมปังปิ้งสีเหลืองทองกลิ้งลงมาบนถาด แค่ดึงออกมาเคาะทิ้งก็จบ มันรับเช้าวันที่วุ่นวายไว้โดยไม่ปริปาก และเตรียมพร้อมสะอาดอีกครั้งสำหรับมื้ออาหารถัดไป"},"ICON-1938":{"nm":"วงล้อจานหมุนไมโครเวฟ","de":"บนวงแหวนที่หมุนวนไปมา จานค่อยๆ วาดวงกลมหนึ่งรอบอย่างช้าๆ การหมุนนั้นที่หมุนเพื่อให้ร้อนทั่วถึง ช่วยชุบชีวิตข้าวเมื่อวานที่เย็นชืดให้กลับมาเป็นมื้ออาหารที่ควันร้อนกรุ่นอีกครั้ง"},"ICON-1939":{"nm":"ฝาครอบเตาแม่เหล็กไฟฟ้าขนาดจิ๋ว","de":"ไม่ว่าน้ำมันจะกระเด็นไปทางไหน หัวเตาก็ยังสะอาดเสมอ ฝาครอบแผ่นเดียวคั่นกลางระหว่างความร้อนแรงกับมือของเรา สิ่งที่ยืนกั้นไว้อย่างมองไม่เห็นนั้น ปกป้องครัวให้เป็นที่ที่ไม่ถูกลวกเสมอ"},"ICON-1940":{"nm":"ฝาปล่อยไอหม้อหุงข้าวไฟฟ้า","de":"เสียงไอน้ำปล่อยออกมา ฟู่~ ต้องขอบคุณฝาเล็กๆ ที่ค่อยๆ ปล่อยแรงดันที่อัดไว้ออกมาอย่างเบามือ ข้าวที่เพิ่งหุงเสร็จจึงเปิดฝาด้วยใบหน้าที่นุ่มนวลที่สุด ในช่วงเวลาของการอบไอนั้นไม่มีการเร่งรีบ"},"ICON-1941":{"nm":"ที่ตั้งทัพพีคนซุป","de":"ตั้งทัพพีที่ใช้คนซุปให้ตรงตั้ง หัวใจเล็กๆ ที่ไม่อยากให้เคาน์เตอร์เปื้อนแม้แต่จุดเดียว ความเรียบร้อยของครัวมักเริ่มต้นจากมุมเล็กๆ ที่ไม่สะดุดตาเหล่านี้เสมอ"},"ICON-1942":{"nm":"ปลอกซิลิโคนหุ้มด้ามหม้อ","de":"สวมซิลิโคนที่ด้ามหม้อที่ร้อนจัดแล้วมือก็ไม่ไหม้ ชั้นบางๆ ที่แทรกอยู่ระหว่างความร้อนกับฝ่ามือ มันปกป้องคนที่กำลังปรุงอาหารอุ่นๆ อยู่ในระยะที่ใกล้ที่สุด"},"ICON-1943":{"nm":"ตะแกรงกรองคราบตะกรันกาต้มน้ำไฟฟ้า","de":"แม้แต่น้ำที่ต้มทุกวันก็ยังสะสมคราบจางๆ ตะแกรงถี่ๆ กรองคราบตะกรันไว้อย่างเงียบๆ รินออกมาเป็นเพียงถ้วยที่ใสสะอาด นี่คือมือที่ขยันขันแข็งซึ่งปกป้องจิบแรกของชาไว้จากที่ที่มองไม่เห็น"},"ICON-1944":{"nm":"ขาคีบตัวจับเวลาทำอาหาร","de":"อีกสามนาทีเท่านั้น ตัวจับเวลากัดขอบโต๊ะไว้แน่นด้วยขาคีบ ขณะที่เส้นก๋วยเตี๋ยวกำลังสุก มันยืนทรงตัวด้วยขาเล็กๆ ของมัน นับติ๊กต่อกไปพร้อมกับช่วงเวลาที่รอคอยที่สุดของวัน"},"ICON-1945":{"nm":"ถ้วยรองน้ำหยดช้อนส้อม","de":"น้ำหยดไหลลงมาจากช้อนส้อมที่เพิ่งล้างเสร็จ เมื่อถ้วยรองรวบรวมความชื้นนั้นไว้อย่างเงียบๆ โต๊ะอาหารก็แห้งสนิทในไม่ช้า ความเรียบร้อยคือความขยันที่อ่อนโยน ซึ่งดูแลแม้กระทั่งน้ำหยดเดียว"},"ICON-1946":{"nm":"ที่วางแบ่งช่องตั้งจาน","de":"ตั้งจานในแนวตั้งแบ่งเป็นช่องๆ จานที่เคยขีดข่วนกันเมื่อวางซ้อนกัน ต่างก็ได้ที่ของตัวเองคนละช่อง การจัดระเบียบท้ายที่สุดแล้วคือการมอบช่องของตัวเองให้ทุกคนโดยไม่ชนกัน"},"ICON-1947":{"nm":"ห่วงจับคู่ตะเกียบ","de":"ร้อยตะเกียบที่เหลืออยู่เดียวดายเพราะพลัดคู่เข้ากับห่วงเพื่อจับคู่ทั้งสองอีกครั้ง เพราะเหลือแค่ข้างเดียวก็หมดประโยชน์ไปในไม่ช้า ห่วงเล็กๆ ที่มัดไว้เคียงข้างกันนี้จึงรักษาระเบียบในลิ้นชักไว้ได้"},"ICON-1948":{"nm":"ราวแขวนแก้วกิ่งก้าน","de":"แขวนแก้วทีละใบบนขาตั้งที่แตกกิ่งก้านออกไปหลายทาง ขณะที่ความชื้นค่อยๆ แห้งไปบนแก้วแต่ละใบที่คว่ำอยู่ มุมหนึ่งของครัวก็ยืนนิ่งเงียบราวกับต้นไม้เล็กๆ ที่เรียบร้อยต้นหนึ่ง"},"ICON-1949":{"nm":"หูจับถาดแบ่งช่องช้อนส้อม","de":"ถาดที่ช้อน ตะเกียบ ส้อม นอนเรียงกันเป็นช่องๆ จับหูแล้วยกทั้งถาดออกมาได้เลย ทำให้จัดโต๊ะอาหารง่ายขึ้นมาก แม้แต่ในลิ้นชักก็ยังมีสุนทรียะแห่งความเป็นระเบียบอาศัยอยู่อย่างไม่ผิดเพี้ยน"},"ICON-1950":{"nm":"แผ่นคว่ำแก้วผึ่งแห้ง","de":"คว่ำแก้วที่ล้างแล้วไว้ หยดน้ำก็ค่อยๆ หยดลงมาทีละหยด ขณะที่แก้วค่อยๆ แห้งอยู่ริมหน้าต่างที่แดดส่อง แก้วใสก็ค่อยๆ กลับมาใสสะอาดดังเดิมอย่างสงบ พร้อมสำหรับจิบต่อไป"},"ICON-1951":{"nm":"หวีทำความสะอาดซี่ส้อม","de":"ซี่หวีเล็กๆ ค่อยๆ กวาดเศษอาหารที่ติดอยู่ระหว่างซี่ส้อมออกอย่างละเอียด ต้องขอบคุณสัมผัสที่ดูแลไปถึงซอกแคบๆ มื้ออาหารถัดไปจึงเริ่มต้นด้วยคำแรกที่สะอาดไร้ที่ติเสมอ"},"ICON-1952":{"nm":"แผ่นสักหลาดกันลื่นซ้อนชาม","de":"ซ้อนชามเข้าด้วยกันแล้วเกิดเสียงกระทบกันดังแหลมของเครื่องเคลือบ แผ่นสักหลาดแผ่นหนึ่งที่สอดคั่นไว้ระหว่างกันช่วยให้เสียงเสียดสีนั้นเงียบลง เคล็ดลับของการอยู่ด้วยกันไปนานๆ คือการปล่อยให้กันและกันนุ่มนวลขึ้นสักนิด"},"ICON-1953":{"nm":"เชือกห่วงแขวนช้อนชา","de":"แขวนช้อนชาน่ารักไว้กับห่วงแล้วติดผนัง ไม่จมหายอยู่ในลิ้นชัก แต่เปล่งประกายอยู่ในที่ที่มือเอื้อมถึงเสมอ—เครื่องมือเล็กๆ ที่ครองที่ของตัวเองอย่างภาคภูมิ แม้แต่งานบ้านก็ยังมีตำแหน่งที่แน่นอนของมันเอง"},"ICON-1954":{"nm":"ถาดแบ่งช่องตู้เย็น","de":"แบ่งช่องตู้เย็นออกเป็นส่วนๆ แล้ววัตถุดิบแต่ละอย่างก็มีบ้านเล็กๆ เป็นของตัวเอง สิ่งที่เคยปะปนกันจนถูกลืมก็ได้ที่ของตัวเอง และทุกครั้งที่เปิดประตู ก็มองเห็นได้ในทันทีว่าอะไรอยู่ตรงไหน"},"ICON-1955":{"nm":"คลิปตั้งถุงซิปแช่แข็ง","de":"คีบถุงซิปแช่แข็งที่เหลือครึ่งถุงด้วยคลิปแล้วตั้งให้ตรง เพื่อไม่ให้ล้มหกและหาเจอง่ายในครั้งต่อไป แม้ในช่องแช่แข็งที่หนาวเย็นก็ยังมีปัญญาอันเฉียบแหลมของแม่บ้านผู้เอาการเอางานสิงสถิตอยู่"},"ICON-1956":{"nm":"ที่ขันฝาขวดให้แน่น","de":"ขวดที่ปิดไม่สนิทก็ค่อยๆ หมดกลิ่นไปในไม่ช้า แรงบิดข้อมือหนึ่งครั้งที่ขันฝาให้แน่น กักกลิ่นหอมและฟองอากาศไว้ในขวดครบถ้วนจนถึงเช้าวันพรุ่งนี้ ความเอาการเอางานเปล่งประกายในสิ่งเล็กๆ เสมอ"},"ICON-1957":{"nm":"แผ่นรองกันลื่นช่องไข่","de":"แผ่นรองที่ประคองไข่กลมๆ ไว้เป็นช่องๆ ไม่ให้กลิ้งแตก หัวใจที่อยากทะนุถนอมสิ่งที่เปราะบางที่สุดด้วยความระมัดระวังที่สุด อยู่เล็กๆ อย่างอ่อนโยนในมุมหนึ่งของประตูตู้เย็น"},"ICON-1958":{"nm":"แถบขยายช่องเก็บของประตูตู้เย็น","de":"ยืดช่องเก็บของที่ประตูตู้เย็นออกด้านข้างเล็กน้อยเพื่อสร้างอีกหนึ่งช่อง เพราะเมื่อของในบ้านเพิ่มขึ้น พื้นที่ก็ต้องเพิ่มขึ้นตามไปด้วย ในฝีมือของการขยายพื้นที่แคบให้ใช้งานได้นั้น สะท้อนหัวใจของแม่บ้านผู้เอาการเอางาน"},"ICON-1959":{"nm":"ฝากดปิดกับข้าวที่เหลือ","de":"ฝาที่กดปิดเบาๆ อยู่เหนือกับข้าวที่เหลือ คอยดูแลอย่างเงียบๆ ไม่ให้แห้งและไม่ให้ติดกลิ่นอื่น มือที่ทะนุถนอมนั้นเก็บรักษาแม้กระทั่งของที่เหลือจากมื้ออาหารหนึ่งมื้ออย่างทะนุถนอม"},"ICON-1960":{"nm":"ครีบปรับทิศทางลมเย็น","de":"ลมเย็นจะไหลไปทางไหน ครีบเล็กๆ กำหนดทิศทางไว้อย่างเงียบๆ เพียงปรับเส้นทางลมที่มองไม่เห็นด้วยปลายนิ้วเบาๆ ความเย็นก็ไปถึงมุมลึกที่สุดด้านในได้"},"ICON-1961":{"nm":"แผ่นดูดความชื้นช่องผัก","de":"ที่มุมมืดที่สุดของช่องผักในตู้เย็น ฉันเก็บกักความชื้นไว้อย่างเงียบๆ โดยไม่พูดอะไร ปาฏิหาริย์เล็กๆ ที่ใบผักซึ่งเหี่ยวเมื่อวานกลับกรุบกรอบอีกครั้งในยามเช้า แม้ไม่มีใครรู้จัก ความสดใหม่ก็เป็นหน้าที่ของฉันเสมอ"},"ICON-1962":{"nm":"ขอบกันกลิ้งกระป๋องเครื่องดื่ม","de":"เกาะอยู่นิ่งๆ ที่ขอบโต๊ะ คอยจับเท้าของกระป๋องที่กำลังจะกลิ้งไป เครื่องดื่มที่เกือบจะหกเลอะ โต๊ะที่เกือบต้องเช็ด ความอุ่นใจในงานบ้านเริ่มต้นจากขอบเล็กๆ ที่ไม่สะดุดตาเช่นนี้เอง"},"ICON-1963":{"nm":"จานหมุนแบ่งเวรทำงานบ้าน","de":"วันนี้ใครล้างจาน ใครแยกขยะ หมุนลูกศรหนึ่งครั้งแล้วเรื่องทะเลาะเบาะแว้งก็คลี่คลายไปอย่างกลมกล่อม ในบ้านที่ห้าคนอยู่เบียดเสียดกัน การผลัดเวรกันคือสันติภาพที่อ่อนโยนที่สุด"},"ICON-1964":{"nm":"แถบซิลิโคนแยกแก้วสมาชิก","de":"แก้วห้าใบที่หน้าตาคล้ายกัน เช้าที่ปนกันจนแยกไม่ออกว่าใบไหนของใคร สวมแถบสีขนาดเท่าข้อมือเข้าไปหนึ่งเส้น คำมั่นเล็กๆ ที่ว่า \"นี่ของฉัน\" ก็ชัดเจนขึ้น มอบความเป็นระเบียบที่อ่อนโยนให้กับโต๊ะอาหารเช้าอย่างงดงาม"},"ICON-1965":{"nm":"ห่วงกำหนดปริมาณชามอาหาร","de":"ในวันที่ยุ่ง ขีดในชามกลายเป็นเพื่อนที่พึ่งพาได้ ช่องหนึ่งสำหรับข้าว ช่องหนึ่งสำหรับกับข้าว ไม่มากไม่น้อยเกินไป เส้นอ่อนโยนที่บอกปริมาณที่ควรกินในวันนี้อย่างเงียบๆ"},"ICON-1966":{"nm":"กระปุกคีมแบ่งขนม","de":"ยื่นถุงทั้งถุงให้กันแล้วรอยมือที่สัมผัสก็หลงเหลืออยู่ ดูกระอักกระอ่วน แบ่งออกทีละชิ้นด้วยคีมแล้วส่วนแบ่งของทุกคนถึงจะเท่ากันจริงๆ การแบ่งปันเข้ากันได้ดีกับมือที่เรียบร้อยมากกว่าการยื่นทั้งกำมือ"},"ICON-1967":{"nm":"ที่เสียบป้ายชื่อเวรต้มน้ำ","de":"การต้มน้ำมักตกเป็นหน้าที่ของมือคนเดิมเสมอ นับตั้งแต่เริ่มแขวนป้ายชื่อสลับกันที่ที่เสียบข้างกาน้ำ ชาอุ่นสักถ้วยก็กลายเป็นความรักที่ผลัดกันชงขึ้นมาเรื่อยๆ"},"ICON-1968":{"nm":"ชิปเตือนอย่าเหลืออาหารติดตะหลิว","de":"คำว่า \"อย่าเหลือนะ\" ห้อยอยู่เล็กๆ ที่ปลายตะหลิว ฟังดูเหมือนบ่นก็จริง แต่ไม่มีมุมไหนที่น่ารำคาญเลย เพราะหัวใจของโต๊ะอาหารในสมัยก่อนที่ทะนุถนอมทุกมื้อ ยังคงสิงสถิตอยู่ตรงนี้"},"ICON-1969":{"nm":"ตะขอแขวนถุงช้อนส้อมส่วนตัว","de":"ช้อนส้อมไม่กลิ้งอยู่ในลิ้นชักอีกต่อไป วินาทีที่แต่ละชุดเข้าไปอยู่ในถุงของตัวเองแล้วแขวนบนผนัง ที่ของสมาชิกทั้งห้าคนก็เรียงแถวกันอย่างเป็นระเบียบ ความเรียบร้อยเล็กๆ นี้ค้ำจุนความสงบสุขของทุกวันไว้"},"ICON-1970":{"nm":"ชิปคอร์กกำหนดที่นั่งโต๊ะอาหาร","de":"วางชิ้นคอร์กบนโต๊ะแล้วก็ชัดเจนว่าใครนั่งตรงไหน ที่นั่งที่นั่งเป็นประจำ ใบหน้าด้านข้างที่มองเห็นกันเป็นประจำ ที่นั่งที่กำหนดไว้คือหลักฐานที่เงียบที่สุดของคำว่า \"อยู่ด้วยกัน\""},"ICON-1971":{"nm":"ตะขอม้วนผ้ากันเปื้อนเวร","de":"ผ้ากันเปื้อนที่ล้างจานเสร็จแล้วจะไม่ถูกโยนทิ้งไว้เฉยๆ ม้วนให้เป็นก้อนแล้วแขวนไว้กับตะขอ พรุ่งนี้เช้าก็หยิบมาใช้ได้สะอาดสะอ้านอีกครั้ง หัวใจที่คิดถึงคนถัดไปอาศัยอยู่ในปมเล็กๆ นี้"},"ICON-1972":{"nm":"ถุงพับรองเท้าแตะแบบใช้แล้วทิ้ง","de":"วันที่มีแขกมาเยือน ฉันจะคลี่ตัวเองออกทั้งถุง รองเท้าแตะแบบใช้แล้วทิ้งที่จัดเรียงอย่างเป็นระเบียบต้อนรับเท้าที่เพิ่งมาถึงด้วยความนุ่มสบาย การต้อนรับเริ่มต้นอย่างเงียบๆ จากทางเข้าเสมอ"},"ICON-1973":{"nm":"กระเป๋าเก็บก้านกระดาษไม้พันสำลี","de":"เมื่อไม้พันสำลีถูกใช้จนหมดเหลือแต่ก้านกระดาษ ฉันเก็บปลายของมันไว้อย่างทะนุถนอม การให้ที่แม้กับสิ่งที่กำลังจะถูกทิ้ง ฉันรู้ว่าความลับของโต๊ะทำงานที่เรียบร้อยคือความอ่อนโยนเล็กๆ เช่นนี้เอง"},"ICON-1974":{"nm":"มัดหลอดด้ายชุดเย็บผ้า","de":"มัดเส้นด้ายหลากสีไว้ด้วยกันไม่ให้หลอดคลายพันกัน กระดุมที่หลุด ปลายแขนเสื้อที่หลวม เพียงมัดหนึ่งมัดนี้ก็แก้ไขได้ในพริบตา งานเย็บผ้าด้วยมือที่ช่วยกอบกู้ค่ำคืนก่อนวันสำคัญไว้อย่างเงียบๆ"},"ICON-1975":{"nm":"สบู่ห่อเดี่ยวชิ้นเล็ก","de":"สบู่ห่อเดี่ยวอย่างประณีตหนึ่งก้อนถูกวางไว้ในทุกห้องพักแขก ร่างกายขนาดเท่าฝ่ามือชะล้างฝุ่นละอองของวันไปด้วยฟองสบู่เพียงกำมือเดียว ความสะอาดเริ่มต้นจากจุดเล็กๆ เช่นนี้เสมอ"},"ICON-1976":{"nm":"แคปซูลพับหมวกอาบน้ำจีบ","de":"พับรอยจีบแล้วเก็บลงฝ่ามือได้พอดี คลี่ออกก็ห่อหุ้มเส้นผมได้มิดชิด เพื่อไม่ให้ทรงผมที่จัดไว้พังทลายไปกับการอาบน้ำเพียงครั้งเดียว ความเรียบร้อยของเช้าวันพรุ่งนี้ถูกปกป้องไว้ด้วยชั้นบางๆ นี้"},"ICON-1977":{"nm":"ปลอกป้องกันหัวแปรงสีฟัน","de":"ขนแปรงสีฟันบอบบางกว่าที่คิด ปลอกหนึ่งชิ้นที่ปิดคลุมปลายขนไว้ ทำให้แม้แต่ฝุ่นในกระเป๋าก็แตะต้องไม่ได้ การปกป้องจุดที่มองไม่เห็น—คืองานอนามัยที่แท้จริงซึ่งเรียนรู้ในทุกการเดินทาง"},"ICON-1978":{"nm":"คีมดึงสำลีแผ่นทีละแผ่น","de":"สำลีแต่งหน้าจะออกมาสวยงามก็ต่อเมื่อหยิบทีละแผ่น เพราะหากเทออกมาทั้งหมด ของที่ต้องทิ้งก็จะยิ่งมากขึ้น \"ทีละแผ่น ด้วยความตั้งใจ\"—นี่คือกฎเงียบๆ บนโต๊ะเครื่องแป้ง"},"ICON-1979":{"nm":"ที่สวมรองเท้าพับมินิ","de":"พับแล้วอยู่ในกระเป๋า คลี่ออกก็อยู่ที่ส้นเท้า ฉันภาคภูมิใจที่ทำงานใหญ่ได้ด้วยร่างเล็กๆ แม้ในเช้าวันที่ตื่นสาย ฉันก็เป็นคนที่ช่วยให้สวมรองเท้าได้โดยไม่ทำรองเท้าเสียรูปเสมอมา"},"ICON-1980":{"nm":"แกนม้วนไหมขัดฟันเส้นเดียว","de":"ม้วนไหมขัดฟันเส้นหนึ่งไว้อย่างเรียบร้อยแล้วตัดใช้พอดีเมื่อถึงเวลา แกนม้วนขนาดเท่าเล็บมือ แต่ไม่เคยขาดหายไปจากงานปกป้องรอยยิ้มที่สดใส แม้แต่รอยยิ้มก็ยังมีการเตรียมพร้อมที่มองไม่เห็น"},"ICON-1981":{"nm":"หูจับฝากาต้มน้ำไฟฟ้า","de":"เพื่อไม่ให้มือถูกไอน้ำเดือดลวก ฉันสวมตัวเองไว้บนฝา ระยะห่างหนึ่งฝ่ามือระหว่างความร้อนกับฝ่ามือ ระยะห่างเล็กๆ นั้นทำให้เช้าวันที่วุ่นวายของใครสักคนอุ่นขึ้นอย่างปลอดภัย"},"ICON-1982":{"nm":"แผ่นซิลิโคนรองเตารีด","de":"วินาทีที่วางมือจากเตารีดชั่วครู่ระหว่างรีดผ้า คือช่วงเวลาที่อันตรายที่สุด ตั้งเตารีดไว้บนแผ่นซิลิโคนแล้วทั้งโต๊ะและเสื้อผ้าก็ไม่ไหม้เกรียม การรีดรอยยับให้เรียบจะเสร็จสมบูรณ์ก็ต่อเมื่ออยู่บนแผ่นรองนี้เท่านั้น"},"ICON-1983":{"nm":"ตะขอไม้แขวนเสื้อกันขโมย","de":"เพื่อไม่ให้เสื้อผ้าที่แขวนอยู่หลุดร่วงลงมาโดยไม่ตั้งใจ ตะขอจึงปิดปากแน่นสนิท ยามเล็กๆ ที่เฝ้าดูแลเสื้อผ้าตัวโปรดในตู้เสื้อผ้า การปกป้องคือสิ่งที่เงียบสงบเช่นนี้เอง"},"ICON-1984":{"nm":"ตะแกรงกรองตะกรันกาต้มน้ำ","de":"หน้าที่ของฉันคือกรองคราบตะกรันที่ล่องลอยอยู่ในน้ำเดือดออกอย่างเงียบๆ ต่อเมื่อกรองแม้แต่ตะกอนที่มองไม่เห็นแล้วเท่านั้น ชาสักถ้วยจึงจะใสสะอาด ความตั้งใจมักบ่มเพาะขึ้นในที่ที่ไม่มีใครมองเห็นเสมอ"},"ICON-1985":{"nm":"แถบกันลื่นไม้แขวนเสื้อ","de":"ไม้แขวนเสื้อที่พันด้วยแถบกันลื่น แม้แต่ผ้าไหมเบาบางก็ไม่หลุดร่วง ใครก็ตามที่เคยเห็นเสื้อผ้าร่วงลงพื้นแล้วยับย่นสักครั้ง ย่อมรู้ซึ้งถึงความขอบคุณของเส้นบางๆ เส้นนี้"},"ICON-1986":{"nm":"คลิปจัดสายไฟเตารีด","de":"สายไฟที่ปล่อยหลวมๆ ไว้เกี่ยวเท้าจนใครสักคนเซถลา สัมผัสมือหนึ่งครั้งที่มัดสายให้เรียบร้อยด้วยคลิป การป้องกันอุบัติเหตุมักเริ่มต้นจากการจัดระเบียบเล็กๆ น้อยๆ เช่นนี้เสมอ"},"ICON-1987":{"nm":"ร่องฐานวางกาต้มน้ำไฟฟ้า","de":"ฉันวางกาให้พอดีกับร่องของฉันเพื่อไม่ให้โคลงเคลง การอยู่ในตำแหน่งที่เหมาะสมก็คือความอุ่นใจนั่นเอง มีเหตุผลที่น้ำอุ่นถูกต้มขึ้นในจุดเดียวกันทุกเช้า"},"ICON-1988":{"nm":"ขาคีบไม้แขวนกางเกง","de":"เมื่อขาคีบกัดชายกางเกงไว้อย่างมั่นคง ก็ไม่มีรอยยับเกิดขึ้นแม้แต่เส้นเดียว ชุดที่รีดมาอย่างดีได้รับการดูแลอย่างดีตั้งแต่วินาทีที่แขวนบนไม้แขวน ทรงที่เรียบร้อยเสร็จสมบูรณ์ในตู้เสื้อผ้า"},"ICON-1989":{"nm":"ตะขอแขวนไดร์เป่าผม","de":"วางไดร์เป่าผมไว้ตามใจแล้วสายไฟก็พันกันยุ่งในไม่ช้า แขวนไว้กับตะขอแล้วอ่างล้างหน้าก็กว้างขึ้น เช้าวันพรุ่งนี้ก็เบาสบายขึ้น ที่ที่จัดเก็บเป็นระเบียบช่วยผ่อนคลายวันที่วุ่นวายลงเล็กน้อย"},"ICON-1990":{"nm":"ที่รองแก้วมินิบาร์","de":"รองไว้ใต้แก้วอย่างเงียบๆ แล้วหยดน้ำก็ไม่กระจายไปทั่วโต๊ะ ความใส่ใจของที่รองแก้วแผ่นเดียวไม่ทิ้งรอยวงกลมไว้ ความเรียบร้อยคือความอ่อนโยนที่ไม่ทิ้งร่องรอยใดๆ"},"ICON-1991":{"nm":"ป้ายแขวนห้ามรบกวน","de":"ป้ายหนึ่งใบที่แขวนอยู่ที่ลูกบิดประตูกระซิบเบาๆ ว่า \"ตอนนี้กำลังพักอยู่\" การเฝ้าดูแลลมหายใจแห่งการงีบหลับหนึ่งครั้งในตอนท้ายวันอันยาวนาน แม้แต่จุดพักก็ยังต้องมีใครสักคนคอยดูแลด้วยความตั้งใจ"},"ICON-1992":{"nm":"ฝาครอบปุ่มเรียกรูมเซอร์วิส","de":"ต้องขอบคุณฝาที่ห่อหุ้มปุ่มไว้ แม้ชายเสื้อจะปัดผ่านก็ไม่ถูกกดโดยไม่ตั้งใจ เพื่อให้เรียกได้อย่างชัดเจนเฉพาะยามที่จำเป็นจริงๆ เท่านั้น ฝาครอบเล็กๆ ชิ้นเดียวทำให้ห้องพักที่วุ่นวายเป็นระเบียบขึ้นอีกระดับ"},"ICON-1993":{"nm":"ขาคีมคีบน้ำแข็งมินิบาร์","de":"หยิบน้ำแข็งด้วยมือเปล่าก็ทั้งเย็นทั้งลื่นหลุดตลอด งานนั้นขาคีมรับหน้าที่แทนอย่างมั่นคง ที่จุดเริ่มต้นของเครื่องดื่มเย็นสักแก้ว มีมือช่วยที่มองไม่เห็นซ่อนอยู่เสมอ"},"ICON-1994":{"nm":"ช่องเสียบคีย์การ์ดห้องพัก","de":"เสียบการ์ดลงในช่องแล้วไฟในห้องก็สว่างขึ้นทันที ฉันเป็นเพียงช่องเล็กๆ แต่ก็เป็นท่าทางแรกที่เปิดพื้นที่สำหรับวางความเหนื่อยล้าของวันลงได้ ไฟสว่างขึ้นอีกครั้งในที่ที่จะได้กลับมา"},"ICON-1995":{"nm":"ห่วงผนึกคอขวดน้ำ","de":"หากห่วงผนึกที่คอขวดยังคงสภาพสมบูรณ์ นั่นหมายความว่ายังไม่มีใครแตะต้อง คำมั่นสัญญาเล็กๆ ที่พิสูจน์ว่ายังคงเป็นเหมือนตอนแรกเริ่ม ความไว้วางใจเริ่มต้นจากผนึกที่ไม่ถูกทำลาย"},"ICON-1996":{"nm":"ที่ตั้งโบรชัวร์แนะนำ","de":"ตั้งโบรชัวร์เอียงไว้แล้วสายตาที่เดินผ่านก็หยุดมองเองโดยธรรมชาติ ท่าทางที่สงบเสงี่ยมของข้อมูลที่รอคอยให้ถูกเปิดอ่าน เพียงแค่วางไว้ให้เห็นชัด เส้นทางของใครสักคนก็สะดวกขึ้นอีกมาก"},"ICON-1997":{"nm":"ชิปแบนที่เปิดขวดมินิบาร์","de":"ในมุมหนึ่งของร่างแบนราบซ่อนร่องสำหรับเปิดฝาขวดไว้อย่างแนบเนียน ตัวเล็กก็จริง แต่ทำหน้าที่ของตัวเองได้อย่างเฉียบขาด จิบแรกอันเย็นฉ่ำของเครื่องดื่มหนึ่งขวดเปิดขึ้นด้วยชิปเล็กๆ ชิ้นนี้เสมอ"},"ICON-1998":{"nm":"ฝาครอบปุ่มหมุนปรับไฟ","de":"หมุนปุ่มที่ห่อด้วยฝาครอบเบาๆ แล้วความสว่างของห้องก็ค่อยๆ เปลี่ยนไป สว่างขึ้น แล้วก็นวลลง การเลือกแสงในยามใกล้หลับคือพิธีกรรมที่ปิดท้ายวันด้วยความอ่อนโยน"},"ICON-1999":{"nm":"ลิ่มหยุดล้อกระเป๋าเดินทาง","de":"สอดไว้ใต้ล้อเบาๆ แล้วกระเป๋าเดินทางก็ไม่กลิ้งไปตามใจตัวเอง แม้บนชานชาลาสถานีที่ลาดเอียง สัมภาระก็ยังคงอยู่ในที่ของมัน ความอุ่นใจในเส้นทางที่กำลังจะออกเดินทางแน่นหนาขึ้นจากลิ่มเล็กๆ ชิ้นนี้"},"ICON-2000":{"nm":"แผ่นพับจัดกระเป๋าเดินทาง","de":"คลี่แล้ววางเสื้อหรือกางเกงลงไปก็พับเป็นทรงเรียบร้อยสวยงาม เพื่อไม่ให้ในกระเป๋ายับเยิน เพื่อให้ก้าวออกไปในเมืองที่มาถึงได้โดยไม่มีรอยยับ กระเป๋าที่จัดมาอย่างดีช่วยการเดินทางไว้ตั้งแต่ก่อนออกเดินทางเสียอีก"},"ICON-2001":{"nm":"ปุ่มหมุนล็อกตู้เซฟในห้องพัก","de":"หมุนปุ่มแล้วสลักเล็กๆ จะเลื่อนเข้าด้านใน การฝากของมีค่าไว้คือคำสัญญาว่าจะปล่อยใจให้สบายเต็มที่สักคืนหนึ่ง กุญแจล็อกไม่ใช่ความกังวล แต่เป็นอีกชื่อหนึ่งของความอุ่นใจที่อยู่ตรงนั้นเสมอ"},"ICON-2002":{"nm":"ผ้าหุ้มด้ามจับกระเป๋าเดินทาง","de":"ในทุกรอยเปื้อนมือที่ผ่านการใช้งาน มีการจากลาของใครสักคนถูกจารึกไว้ เมื่อกำผ้าหุ้มที่สึกไปตามระยะทางที่เคยลากผ่านมา จะค่อยๆ เข้าใจว่าการจากไปนั้น แท้จริงแล้วคือคำที่แฝงการกลับมาไว้เสมอ"},"ICON-2003":{"nm":"คลิปแขวนกระเป๋าซองเดินทาง","de":"แขวนกระเป๋าซองไว้ที่ขอบอ่างล้างหน้า ห้องพักแคบๆ ก็กว้างขึ้นอีกหนึ่งฝ่ามือ มือที่เคยเดินทางไกลรู้ดีอยู่แล้วว่า ความเป็นระเบียบในกระเป๋าเริ่มต้นจากคลิปเล็กๆ เพียงตัวเดียว"},"ICON-2004":{"nm":"คลิปรวมสายชาร์จปลั๊กพ่วง","de":"รวมสายเคเบิลหลายเส้นไว้ในปลั๊กเดียว ในคืนที่รอให้แบตเตอรี่ชาร์จเต็ม มีมือเล็กๆ ที่คอยกอดรวมสายที่กระจัดกระจายไว้ด้วยกันอย่างอ่อนโยน"},"ICON-2005":{"nm":"สายห่วงป้ายชื่อกระเป๋าเดินทาง","de":"ท่ามกลางกระเป๋าสีดำที่เหมือนกันไปหมด สายเส้นเดียวช่วยให้มองเห็นกระเป๋าของตัวเอง การแขวนชื่อไว้คือเครื่องหมายอันอ่อนโยนว่า สัมภาระใบนี้มีทางกลับไปหาใครสักคนเสมอ"},"ICON-2006":{"nm":"แผ่นยึดสายชาร์จติดผนังห้องพัก","de":"แผ่นเล็กๆ ที่ติดผนังข้างหัวเตียงช่วยรองรับสายชาร์จให้เป็นระเบียบ ในคืนแรกที่ต้องนอนในห้องแปลกถิ่น เมื่อแสงไฟที่คุ้นเคยดวงหนึ่งสว่างขึ้น ที่แห่งนั้นก็กลายเป็นบ้านชั่วคราวไปด้วย"},"ICON-2007":{"nm":"ขาพับที่วางกระเป๋าเดินทาง","de":"กางขาที่พับไว้ออก กระเป๋าก็ลอยพ้นจากฝุ่นพื้นขึ้นมาหนึ่งฝ่ามือ กระเป๋าเดินทางที่ยังไม่ได้แกะออกวางอยู่นั้น เก็บงำการเดินทางที่ยังไม่จบไว้อย่างเงียบๆ และรอคอยเช้าวันถัดไป"},"ICON-2008":{"nm":"ช่องเสียบคีย์การ์ด","de":"ต้องเสียบบัตรก่อนไฟในห้องพักจึงจะสว่างขึ้น แสงที่ส่องเฉพาะช่วงที่พักอยู่เท่านั้น—วันหนึ่งของนักเดินทางอบอุ่นขึ้นด้วยความสว่างเพียงเท่าที่ช่องเล็กๆ นี้อนุญาตให้มี"},"ICON-2009":{"nm":"สายคล้องคอคีย์การ์ด","de":"แขวนบัตรใบเดียวไว้ที่คอ มือทั้งสองข้างก็ว่างเบาขึ้น ความฉลาดเล็กๆ ที่ผูกความกังวลว่าจะทำหายไว้กับสายเส้นเดียว คือภูมิปัญญาที่นักเดินทางผู้แบกสัมภาระมากมายส่งต่อกันมายาวนาน"},"ICON-2010":{"nm":"ปุ่มกริ่งเรียกพนักงานต้อนรับ","de":"กดแล้วเสียงกริ่งใสจะดังก้องอยู่ที่เคาน์เตอร์ต้อนรับ เพื่อไม่ให้การขอความช่วยเหลือเป็นเรื่องน่าอาย กริ่งจึงวางอยู่อย่างอ่อนโยนในระยะเอื้อมมือถึงเสมอ"},"ICON-2011":{"nm":"คลิปหนีบบัตรคิวเช็คอิน","de":"หยิบตั๋วเลขคิวที่ได้รับจากปลายแถวมาหนีบให้อยู่กับที่ การที่แม้แต่การรอคอยยังมีลำดับก่อนหลัง—ระเบียบเติบโตขึ้นจากคำสัญญาเล็กๆ ที่ถนอมเวลาของกันและกันไว้อย่างเงียบๆ"},"ICON-2012":{"nm":"พู่ห้อยกุญแจห้องพัก","de":"พู่ที่ห้อยอยู่ปลายกุญแจแกว่งไกวไปตามทุกย่างก้าว หัวใจที่แอบเติมความสวยงามลงไปในสิ่งที่มีประโยชน์ มีเพียงคนที่รู้จักความสุขของปลายนิ้วเท่านั้นที่จะแสดงออกมาได้"},"ICON-2013":{"nm":"ฝาครอบกริ่งประตูแผนกต้อนรับ","de":"สวมฝาครอบไว้บนกริ่งประตู ความเงียบสงบยามบ่ายก็ไม่ถูกทำลาย ความใส่ใจเล็กๆ ที่อยากปกป้องการหลับใหลของใครสักคน—แม้แต่ความเงียบก็เป็นสิ่งที่ใครบางคนสร้างขึ้นด้วยความตั้งใจ"},"ICON-2014":{"nm":"ป้ายเลขห้องแขวนประตู","de":"กระดาษที่แขวนไว้บนลูกบิดประตูเขียนเลขห้องไว้อย่างชัดเจน ตัวเลขไม่กี่ตัวกำหนดที่ที่ฉันจะกลับมาในคืนนี้ ในทางเดินที่แปลกถิ่น มันจึงกลายเป็นประภาคารดวงเล็กๆ"},"ICON-2015":{"nm":"แถบแม่เหล็กคีย์การ์ด","de":"แตะแถบสีดำเข้ากับขอบประตู กุญแจก็ค่อยๆ ปลดล็อก ยุคสมัยที่สัญญาณมองไม่เห็นเปิดประตูได้—สิ่งที่เคยดูเหมือนเวทมนตร์ในอดีต บัดนี้กลายเป็นเรื่องธรรมดาในอุ้งมือ"},"ICON-2016":{"nm":"ที่รองตราประทับเช็คอิน","de":"ทุกครั้งที่ประทับตรา ที่รองจะซับหมึกให้เรียบสม่ำเสมอ เพื่อให้รอยยืนยันแต่ละเส้นชัดเจนคงทน มีมือหนึ่งที่คอยรองรับอยู่อย่างเงียบๆ ในตำแหน่งที่ไม่มีใครมองเห็น"},"ICON-2017":{"nm":"ราวแขวนรถเข็นสัมภาระ","de":"ราวเหล็กแท่งหนึ่งที่ติดอยู่บนรถเข็นสัมภาระ ช่วยรองรับกระเป๋าเสื้อผ้าให้ไม่ยับ อยากส่งคำขอบคุณสักคำให้กับสิ่งของที่ช่วยแบกรับวันอันหนักอึ้งแทนเราบ้างในบางครั้ง"},"ICON-2018":{"nm":"ป้ายห้อยด้ามจับกระเป๋าเดินทางใบใหญ่","de":"แขวนป้ายเล็กๆ ไว้ที่ด้ามจับกระเป๋าเดินทาง ตราบใดที่ช่องเขียนชื่อยังว่างเปล่า ความตื่นเต้นก็ยังคงอยู่ว่าจุดหมายต่อไปของกระเป๋าใบนี้ยังไม่ถูกกำหนด"},"ICON-2019":{"nm":"ลิ่มล็อกล้อรถเข็นสัมภาระ","de":"วางลิ่มไว้ใต้ล้อเพื่อไม่ให้รถเข็นไหลลงทางลาด การรักษาความนิ่งไว้ให้ได้นั้น บางครั้งก็เป็นอีกใบหน้าหนึ่งของความปลอดภัยที่น่าเชื่อถือที่สุด"},"ICON-2020":{"nm":"หัวเข็มขัดรัดสายกระเป๋าเดินทาง","de":"ขันสายให้แน่นเพื่อไม่ให้กระเป๋าที่บวมเป่งไปด้วยของจากการเดินทางแตกออก แม้เส้นทางจะสิ้นสุดลง แต่ปริมาตรของความทรงจำไม่เคยลดลง หัวเข็มขัดจึงยึดน้ำหนักนั้นไว้จนถึงที่สุด"},"ICON-2021":{"nm":"ฝาครอบตะขอรถเข็นสัมภาระ","de":"ฝาครอบที่สวมไว้บนตะขอรถเข็นไม่ทิ้งรอยใดๆ ไว้บนเสื้อผ้าเลยแม้แต่น้อย หัวใจที่คิดล่วงหน้าถึงรอยขีดข่วนที่มองไม่เห็น—การต้อนรับที่ดีสมบูรณ์ขึ้นจากรายละเอียดเล็กๆ เช่นนี้เอง"},"ICON-2022":{"nm":"กระเป๋าใส่ป้ายชื่อกระเป๋าเดินทาง","de":"กระเป๋าเล็กๆ ที่ติดอยู่ข้างกระเป๋าเดินทางโอบอุ้มป้ายชื่อเอาไว้ การเขียนบอกว่าเป็นของใคร ก็เหมือนการสลักสิทธิ์ที่จะได้พบกันอีกครั้งไว้ล่วงหน้า แม้จะพลัดหลงไปก็ตาม"},"ICON-2023":{"nm":"คลิปหนีบถุงมือขนสัมภาระ","de":"เวลาขนของหนัก คลิปจะหนีบถุงมือไว้อย่างแน่นหนาไม่ให้หลุดลื่นออก การปกป้องมือและการทำงานให้ดีนั้น สุดท้ายแล้วก็มาจากหัวใจดวงเดียวกัน"},"ICON-2024":{"nm":"ตาข่ายคลุมสัมภาระ","de":"คลุมตาข่ายไว้ ของชิ้นเล็กชิ้นน้อยก็จะไม่กระจัดกระจายไปทั่ว ตาข่ายแต่ละช่องที่ถักแน่นช่วยยึดของชิ้นเล็กๆ ไว้ไม่ให้พลัดหายไปท่ามกลางความวุ่นวายของการเคลื่อนย้าย"},"ICON-2025":{"nm":"ที่หนีบโน้ตรถเข็นสัมภาระ","de":"โน้ตที่เสียบไว้ที่ด้ามจับรถเข็นเขียนหมายเลขห้องพักไว้ นิสัยที่จดบันทึกว่าต้องไปที่ไหน—ยิ่งมือยุ่งเท่าไหร่ ก็ยิ่งพึ่งพาตัวหนังสือเพียงบรรทัดเดียวอย่างเงียบๆ มากเท่านั้น"},"ICON-2026":{"nm":"ฝาครอบโดมจานเสิร์ฟ","de":"ยกฝาโดมสีเงินขึ้น ไอน้ำก็ลอยพวยพุ่งขึ้นมาในทันที หัวใจที่ปิดอาหารไว้เพื่อไม่ให้เย็นชืด คือความตั้งใจที่อยากส่งต่อความอบอุ่นให้คงอยู่ครบถ้วนนั่นเอง"},"ICON-2027":{"nm":"ป้ายห้ามรบกวนแขวนลูกบิดประตู","de":"แขวนป้ายนี้ไว้ที่ลูกบิดประตู แม้แต่เสียงฝีเท้าในทางเดินก็ยังต้องระมัดระวังขึ้น คำเพียงคำเดียวว่า \"อย่าปลุกฉัน\"—การพักผ่อนก็จะสมบูรณ์ได้ก็ต่อเมื่อมีใครสักคนคอยปกป้องมัน"},"ICON-2028":{"nm":"ห่วงผ้าเช็ดปากกระดาษรูมเซอร์วิส","de":"สอดผ้าเช็ดปากกระดาษเข้าไปในห่วงกลม จัดรูปทรงให้เรียบร้อย ความประณีตของมื้ออาหารเริ่มต้นจากห่วงเล็กๆ นี้ ความใส่ใจปรากฏชัดที่สุดในสิ่งเล็กน้อยเสมอ"},"ICON-2029":{"nm":"แผ่นรองกันลื่นถาด","de":"วางแผ่นรองไว้บนถาด จานชามก็จะไม่ลื่นไถล การรักษาให้อยู่กับที่แม้ท่ามกลางการสั่นไหว—แม้แต่ความมั่นคงอันสงบก็ยังมีการออกแบบอย่างพิถีพิถันของใครสักคนซ่อนอยู่"},"ICON-2030":{"nm":"ป้ายสั่งอาหารเช้าแขวนประตู","de":"แขวนป้ายสั่งอาหารเช้าไว้ที่ลูกบิดประตู เช้าวันพรุ่งนี้ก็ถูกสัญญาไว้ล่วงหน้า การเขียนบอกมื้อแรกไว้ตั้งแต่คืนนี้ คืออีกใบหน้าหนึ่งของการรอคอยอันอ่อนโยน"},"ICON-2031":{"nm":"ขาตั้งถาดอาหาร","de":"กางขาตั้งของถาดออก แม้บนเตียงก็กลายเป็นโต๊ะอาหารที่สมบูรณ์แบบ มื้อเช้าที่ได้รับในท่านอน—ขาตั้งเล็กๆ เปลี่ยนห้องธรรมดาให้กลายเป็นบรรยากาศแสนหรูหรา"},"ICON-2032":{"nm":"ผ้าคลุมอุ่นกาน้ำชา","de":"สวมผ้าคลุมความอุ่นไว้บนกาน้ำชา ความอุ่นของน้ำก็คงอยู่ได้นานขึ้น เหมือนคืนเก่าก่อนที่ผู้คนนั่งล้อมเตาไฟ หัวใจที่อยากรักษาความอบอุ่นไว้ไม่เคยเปลี่ยนไปตามยุคสมัย"},"ICON-2033":{"nm":"ป้ายหางขอทำความสะอาดแขวนประตู","de":"แขวนป้ายหางขอทำความสะอาดไว้ที่ลูกบิดประตู เพื่อทิ้งสัญญาณไว้โดยไม่ต้องเอ่ยปาก คำขอที่ส่งถึงกันได้โดยไม่ต้องเปิดปาก—เบื้องหลังห้องที่สะอาดเรียบร้อยมีคำสัญญาของมือที่มองไม่เห็นซ่อนอยู่"},"ICON-2034":{"nm":"ที่ยึดขวดเครื่องปรุงบนถาด","de":"ที่ยึดกอดขวดเครื่องปรุงไว้อย่างแน่นหนาไม่ให้ล้ม การรักษาสมดุลของรสชาติไว้ได้แม้บนถาดที่โคลงเคลง คือหน้าที่อันเงียบงันของตัวยึดเล็กๆ ชิ้นนี้เพียงชิ้นเดียว"},"ICON-2035":{"nm":"ที่ตั้งโน้ตรายการจอง","de":"ตั้งโน้ตรายการจองไว้ให้ตรง ลำดับก็อ่านเข้าใจได้ในพริบตา เพื่อไม่ให้มือที่ยุ่งอยู่สับสน มันคือเครื่องมือแห่งระเบียบเล็กๆ ที่ตั้งกระดาษแผ่นเดียวไว้อย่างชัดเจน"},"ICON-2036":{"nm":"แผนที่ปักหมุดสถานที่ท่องเที่ยว","de":"ปักหมุดลงบนแผนที่ ทำเครื่องหมายสถานที่ที่อยากไปทีละจุด หมุดแต่ละอันคือความตื่นเต้นของที่ที่ยังไม่เคยไปเยือน—การเดินทางเริ่มต้นขึ้นแล้วตั้งแต่วินาทีที่กางแผนที่ออก"},"ICON-2037":{"nm":"คลิปตั้งธงเรียกแท็กซี่","de":"เวลาเรียกแท็กซี่ คลิปจะตั้งธงเล็กๆ ให้ยืนตรง สัญญาณที่ธงตะโกนแทนมือที่ยกขึ้น—แม้บนท้องถนน การเรียกก็ต้องชัดเจนจึงจะไปถึง"},"ICON-2038":{"nm":"มือจับกริ่งเรียกคอนเซียร์จ","de":"กดมือจับ เสียงกริ่งใสก็ดังไปถึงเคาน์เตอร์คอนเซียร์จ สัญญาณแห่งการต้อนรับที่บอกว่าถามอะไรก็ได้—ในเมืองแปลกถิ่น นี่คือเสียงเรียกครั้งเดียวที่อุ่นใจที่สุด"},"ICON-2039":{"nm":"กระดานคลิปเลขที่จอง","de":"หนีบกระดาษเลขที่จองไว้ที่กระดานคลิปให้มองเห็นชัดเจน เพื่อไม่ให้ที่นั่งที่จองไว้สับสน มันคือความพิถีพิถันเล็กๆ ที่ยึดตัวเลขบรรทัดเดียวไว้อย่างเป็นระเบียบ"},"ICON-2040":{"nm":"กรอบวางแผ่นพับทัวร์","de":"วางแผ่นพับทัวร์ไว้ มือของนักเดินทางก็หยุดลงเองโดยไม่รู้ตัว ในกระดาษแต่ละแผ่นที่หยิบขึ้นมาดูทีละแผ่น ทิวทัศน์ของเส้นทางที่ยังไม่ได้ออกเดินทางถูกพับเก็บไว้อย่างเงียบสงบ"},"ICON-2041":{"nm":"ที่รองตราประทับแผนที่","de":"สำหรับก้าวแรกที่เดินเข้ามาในทางเข้า มันช่วยรองรับกล่องตราประทับบนแผนที่ให้มั่นคงไม่สั่นไหว เมื่อหมึกไม่เลอะเทอะ เส้นทางก็จะไม่สับสนตามไปด้วย เป็นตำแหน่งที่แบกรับน้ำหนักไว้อย่างเงียบๆ เพื่อให้คำแนะนำเล็กๆ ยืนตรงได้"},"ICON-2042":{"nm":"ป้ายฝากร่ม","de":"บ่ายวันที่หยดฝนหยดติ๋งๆ จากชายคา แขวนหมายเลขไว้บนร่มแต่ละคัน เมื่อคนที่กลับมาหลังฝนหยุดมาตามหาของตัวเอง ป้ายจะเรียกความทรงจำที่ยังเปียกชื้นนั้นกลับมาอย่างชัดเจนทุกตัวอักษร"},"ICON-2043":{"nm":"ที่แขวนกระดิ่งเรียกเคาน์เตอร์ประชาสัมพันธ์","de":"กริ๊งดังขึ้นเพียงครั้งเดียว ใครสักคนก็รีบวิ่งมาด้วยรอยยิ้มสดใสจากอีกฝั่ง กระดิ่งเล็กๆ ที่แขวนอยู่มุมเคาน์เตอร์คือล่ามที่อ่อนโยนที่สุด ถ่ายทอดแม้กระทั่งคำพูดที่พูดออกมาไม่ได้"},"ICON-2044":{"nm":"หัวปั๊มขวดแชมพู","de":"แบมือแล้วกดเบาๆ ฟองก็พวยพุ่งขึ้นมาปุ๊บ กลิ่นหอมกระจายไปทั่วห้องน้ำในการกดเพียงครั้งเดียวนั้น เสียงปลุกที่ปลุกเช้าวันง่วงนอนได้อ่อนโยนที่สุดเริ่มต้นขึ้นที่นี่เอง"},"ICON-2045":{"nm":"ถาดระบายน้ำที่วางสบู่","de":"ถาดที่ระบายน้ำที่ขังอยู่ใต้ก้อนสบู่ให้ไหลออกไปอย่างเงียบๆ เพื่อไม่ให้เยิ้ม ไม่ให้เละ เป็นความใส่ใจเล็กๆ ที่อ่อนโยน ที่อยากเก็บสิ่งที่ค่อยๆ สึกกร่อนไปทุกวันให้อยู่เคียงข้างนานขึ้นอีกหนึ่งฝ่ามือ"},"ICON-2046":{"nm":"ช้อนตักเกลืออาบน้ำ","de":"ตักผงหนึ่งช้อนละลายลงในน้ำอุ่น สีสันและกลิ่นหอมก็ค่อยๆ กระจายออกไปช้าๆ ระหว่างที่คนด้วยข้อมือ อ่างอาบน้ำก็กลายเป็นทะเลสาบเล็กๆ และความเหนื่อยล้าของทั้งวันก็จมลงอย่างเงียบสงบในนั้น"},"ICON-2047":{"nm":"ถุงตาข่ายทำฟองสบู่","de":"กักก้อนสบู่ไว้ในตาข่ายแล้วถูไปมา ฟองนุ่มๆ ก็จะเอ่อขึ้นเต็มฝ่ามือ มันคือนักเล่นแร่แปรธาตุผู้เงียบสงบมุมหนึ่งของห้องน้ำ ที่เปลี่ยนความหยาบให้กลายเป็นความอ่อนโยน"},"ICON-2048":{"nm":"ฝาครอบฆ่าเชื้อหัวแปรงสีฟัน","de":"หัวใจที่อยากให้สิ่งที่สัมผัสปากสะอาดอยู่เสมอ ฝาเล็กๆ ที่ห่อหุ้มปลายขนแปรงไว้อย่างอ่อนโยน ดูแลไปถึงจุดที่มองไม่เห็นด้วย ความสะอาดคือสิ่งที่ก่อร่างขึ้นจากรายละเอียดเล็กๆ เช่นนี้สะสมกัน"},"ICON-2049":{"nm":"ฝากระปุกก้านสำลี","de":"กระปุกที่ก้านสีขาวเรียงตัวอยู่อย่างเป็นระเบียบ และฝากลมที่ปิดครอบไว้ด้านบน เปิดก็ป๊อก ปิดก็แต๊ก เสียงเล็กๆ ที่ปิดท้ายความเป็นระเบียบของห้องน้ำอย่างอ่อนโยน"},"ICON-2050":{"nm":"ขวดหยดน้ำมันอาบน้ำ","de":"เอียงเบาๆ น้ำมันหอมก็หยดลงทีละหยด ความมันเงาและกลิ่นหอมอ่อนๆ ที่กระจายไปทั่วอ่างอาบน้ำ จะเรียกว่าฟุ่มเฟือยก็เรียบง่ายเกินไป จะเรียกว่าธรรมดาก็อ่อนโยนเกินไป—เพียงหยดเดียวเท่านั้น"},"ICON-2051":{"nm":"ช่องแบ่งถาดของใช้ในห้องน้ำ","de":"บนถาดที่แบ่งเป็นช่องๆ ขวดเล็กๆ แต่ละขวดต่างหาที่ทางของตัวเอง สิ่งที่กระจัดกระจายก็ดูรกรุงรัง แต่เมื่อรวมกันก็ดูเรียบร้อย ตัวแบ่งช่องเพียงชิ้นเดียวรักษาความเป็นระเบียบของเช้าวันที่วุ่นวายไว้ได้"},"ICON-2052":{"nm":"ที่ตั้งนาฬิกาทรายซาวน่า","de":"เป็นคำสัญญาอันอ่อนโยนว่าจะอบอุ่นแผ่นหลังไว้อย่างน้อยก็ในช่วงเวลาที่ทรายไหลลงจนหมด เมื่อนาฬิกาทรายที่พิงเอียงอยู่บนที่ตั้งค่อยๆ นับเวลาลงไปทีละเม็ด ท่ามกลางไอน้ำที่คลุ้งไปทั่ว ผู้คนก็ได้พักสักครู่โดยไม่เป็นใครเลย"},"ICON-2053":{"nm":"ผ้าขนหนูม้วนหูแกะเข้าซาวน่า","de":"ม้วนปลายผ้าขนหนูให้ตั้งชันขึ้นเหมือนหูสองข้าง ใบหน้าในกระจกก็ค่อยๆ ผ่อนคลายลงโดยไม่รู้ตัว ท่ามกลางไอน้ำร้อนๆ นี่คือพิธีกรรมเล็กๆ ของห้องซาวน่าที่ทำให้ทุกคนได้กลับไปเป็นเด็กอีกครั้งชั่วครู่"},"ICON-2054":{"nm":"กระบวยตักน้ำซาวน่า","de":"ตักน้ำเต็มกระบวยแล้วราดลงบนก้อนหินร้อนๆ ซ่า—ไอน้ำพวยพุ่งขึ้นไปถึงเพดาน ในวินาทีนั้นทั้งร่างกายจมดิ่งลงในหมอกอุ่นๆ และความเหนื่อยล้าเก่าแก่ก็ค่อยๆ คลายออกมาเป็นหยาดเหงื่อ"},"ICON-2055":{"nm":"แท่งวัดอุณหภูมิอ่างแช่เท้า","de":"จุ่มแท่งลงในน้ำ ขีดวัดก็ค่อยๆ บอกกล่าวเบาๆ ไม่ร้อนเกินไป ไม่เย็นชืดเกินไป เป็นอุณหภูมิที่พอดีเป๊ะ ก่อนจะจุ่มปลายเท้าลงไป มันคือนิ้วที่ถามไถ่ความเป็นไปของน้ำก่อนใครเสมอ"},"ICON-2056":{"nm":"คีมคีบก้อนหินร้อนซาวน่า","de":"ก้อนหินที่เพิ่งอุ่นร้อนใหม่ๆ จะจับด้วยมือเปล่าไม่ได้ เมื่อคีมคีบมันขึ้นมาอย่างแน่นหนา ความร้อนก็ถูกย้ายไปสู่ระยะที่ปลอดภัย ความระมัดระวังก็คือฝีมืออย่างหนึ่งเช่นกัน ห้องซาวน่าบอกไว้อย่างเงียบๆ"},"ICON-2057":{"nm":"เบาะรองนั่งซาวน่า","de":"ปูไว้บนพื้นร้อนๆ หนึ่งผืน จุดที่แผ่นหลังสัมผัสก็นุ่มขึ้นทันที เบาะที่รองรับวันหนึ่งอันชุ่มเหงื่อไว้โดยไม่ปริปาก การพักผ่อนแท้จริงแล้วมาจากระยะห่างที่พอดีจากพื้น"},"ICON-2058":{"nm":"ถุงเกลือแช่เท้า","de":"บรรจุเกลือเม็ดหยาบกำมือหนึ่งละลายลงในน้ำอุ่น ความอ่อนล้าก็ค่อยๆ ละลายหายไปตั้งแต่ปลายเท้า เมื่อไอน้ำเค็มๆ กรุ่นขึ้นห่อหุ้มน่อง วันที่เดินมาทั้งวันก็หยุดนิ่งลงในที่สุด"},"ICON-2059":{"nm":"จานหินหยดน้ำหอมซาวน่า","de":"หยดน้ำหอมสักไม่กี่หยดลงบนก้อนหินที่อุ่นร้อน กลิ่นหอมที่อุ่นขึ้นจะค่อยๆ กระจายไปทั่วห้องซาวน่า หลับตาลงแล้วนี่คือป่าหรือทุ่งดอกไม้กันแน่ เป็นการเดินทางที่สั้นที่สุด ผ่านปลายจมูก"},"ICON-2060":{"nm":"ผ้าคลุมกันความร้อนแผ่นประคบ","de":"ผ้าที่ห่อหุ้มแผ่นประคบที่อุ่นแล้วไว้อย่างแนบสนิท เพื่อรักษาความอุ่นไว้ให้นานขึ้น เหมือนหัวใจที่กอดไว้แน่นเพราะกลัวมันจะเย็นลง ความอบอุ่นที่วางอยู่บนหน้าท้องจะอยู่เคียงข้างไปตลอดคืน"},"ICON-2061":{"nm":"ก้านไม้กระจายกลิ่นอโรมา","de":"ก้านไม้เรียวๆ ดูดซับกลิ่นหอมแล้วปล่อยให้ไหลซึมไปทั่วห้องอย่างช้าๆ กลิ่นหอมจางๆ ที่ซึมเข้ามาในทุกลมหายใจ เป็นวิธีที่พื้นที่ที่พำนักค่อยๆ กลายเป็นเหมือนกลิ่นของคนคนนั้น"},"ICON-2062":{"nm":"มือหมุนปรับองศาเตียงอาบแดด","de":"หมุนมือจับช้าๆ พนักพิงก็ค่อยๆ เอนลงอย่างนุ่มนวล เอนไปทางแดดนิดหนึ่ง เอนไปทางร่มเงานิดหนึ่ง การค่อยๆ คลำหาองศาที่สบายที่สุด คือการคำนวณส่วนตัวของแต่ละคนโดยแท้"},"ICON-2063":{"nm":"แถบกันลื่นขอบสระว่ายน้ำ","de":"แถบกันลื่นที่พาดวนรอบขอบน้ำ เพื่อให้เท้าเล็กๆ ที่วิ่งเข้ามาอย่างสนุกสนานพร้อมเสียงกระเซ็นน้ำหยุดได้อย่างปลอดภัย มันคือเส้นชัยแห่งความปลอดภัยที่ปูไว้อย่างเงียบๆ ในที่ที่มองไม่เห็น"},"ICON-2064":{"nm":"ห่วงจุกลมยางลอยน้ำ","de":"ผูกห่วงไว้อย่างพิถีพิถันกับจุกเล็กๆ ที่กักลมไว้ เพื่อไม่ให้จุกที่หลุดออกจากยางลอยน้ำลอยหายไปกับน้ำ เป็นภูมิปัญญาที่ป้องกันการทำของหายเล็กๆ น้อยๆ ในวันฤดูร้อนไว้ล่วงหน้า"},"ICON-2065":{"nm":"ฝาครอบขั้นบันไดลงสระว่ายน้ำ","de":"ฝาครอบที่ห่อหุ้มปลายบันไดที่ลงสู่ในน้ำไว้อย่างนุ่มนวล เพื่อไม่ให้ฝ่าเท้าเปล่าถูกขีดข่วน มันรองรับก้าวแรกของการลงน้ำให้นุ่มนวลขึ้น เพราะจุดเริ่มต้นของทุกสิ่งควรระมัดระวังเสมอ"},"ICON-2066":{"nm":"ห่วงสายรัดเบาะเตียงอาบแดด","de":"ห่วงที่คล้องผูกสายไว้เพื่อไม่ให้เบาะลื่นไถลหลุดออก คำสัญญาเล็กๆ ที่จะรักษาตำแหน่งของมันไว้แม้ลมจะพัดแรง ปมเดียวนี้ยึดความเนิบช้าของยามบ่ายไว้ให้อยู่กับที่"},"ICON-2067":{"nm":"แผ่นเสียบแก้วเครื่องดื่มริมสระ","de":"แผ่นเสียบแก้วเครื่องดื่มไว้ที่ขอบสระอย่างพอดี เป็นจุดหนึ่งที่ไม่สั่นคลอนแม้จะกระโดดเล่นน้ำสนุกสนานแค่ไหน การวางความเย็นสดชื่นไว้ในระยะเอื้อมมือถึง ช่วยยืดยามบ่ายฤดูร้อนให้ยาวนานขึ้น"},"ICON-2068":{"nm":"คลิปแขวนชุดว่ายน้ำเปียก","de":"หยิบชุดว่ายน้ำที่หยดน้ำเป็นสายมาแขวนไว้ให้ลมพัดผ่านอย่างเงียบๆ ระหว่างที่แห้งอยู่ใต้แสงแดด คลิปยืนยึดมันไว้อย่างไม่ปริปาก เป็นการรอคอยที่เงียบสงบและอ่อนโยน เพื่อการเล่นน้ำครั้งต่อไป"},"ICON-2069":{"nm":"ตุ้มถ่วงฐานเสาร่มชายหาด","de":"ตุ้มถ่วงหนักๆ ที่วางไว้ใต้ฐานเสา เพื่อไม่ให้ร่มโยกเอนไปตามแรงลม ร่มเงาที่อยู่ประจำที่ได้นานล้วนเป็นเพราะน้ำหนักนี้ ความน่าเชื่อถือมักซ่อนตัวอยู่ในที่ต่ำที่สุดเสมอ"},"ICON-2070":{"nm":"ชิปลอยน้ำวัดอุณหภูมิสระ","de":"ชิปเล็กๆ ที่ลอยอยู่บนผิวน้ำ คอยบอกอุณหภูมิให้รู้อย่างเงียบๆ ถ้าเย็นเกินไปก็จะออกสีแดงเรื่อ ถ้าพอดีก็จะนุ่มนวล เป็นหมอดูตัวน้อยแสนน่ารักที่อ่านอารมณ์ของน้ำผ่านสีสันเพียงสีเดียว"},"ICON-2071":{"nm":"พู่ดึงซิปเต็นท์","de":"ดึงพู่เล็กๆ ที่ห้อยอยู่ปลายซิปเบาๆ ประตูเต็นท์ก็เลื่อนเปิดออกอย่างนุ่มนวล มือจับที่จับได้ทันทีแม้ปลายนิ้วจะคลำหาไม่เจอ มันนำทางการเข้าออกในค่ำคืนอันลึกล้ำอย่างอ่อนโยน"},"ICON-2072":{"nm":"กิ๊บผีเสื้อยึดเชือกเต็นท์","de":"กิ๊บที่กัดเชือกให้เป็นรูปผีเสื้อยึดไว้อย่างแน่นหนา ผ้าที่เคยพลิ้วไหวตามลมในที่สุดก็นิ่งสงบลง คืนแคมป์ปิ้งถูกปกป้องไว้อย่างเงียบๆ ด้วยปมเล็กๆ แต่แน่นหนาเช่นนี้"},"ICON-2073":{"nm":"จุกลมเบาะลมกลามปิ้ง","de":"เอาปากประกบแล้วเป่าฟู่ ฟู่ เบาะก็ค่อยๆ พองขึ้นทีละนิด เติมจนเต็มแล้วปิดจุกให้แน่น พื้นก็นุ่มฟู และที่ที่จะเอนกายลงใต้แสงดาวก็เสร็จสมบูรณ์ในที่สุด"},"ICON-2074":{"nm":"ตะขอแขวนเพดานเต็นท์","de":"ตะขอที่แขวนอยู่บนเพดานเต็นท์ไว้แขวนตะเกียงหรือผ้าเช็ดหน้า ภูมิปัญญาการดูแลบ้านที่ใช้ประโยชน์แม้แต่พื้นที่เล็กๆ เหนือศีรษะอย่างประหยัด ก็เหมือนกับการแขวนดาวดวงหนึ่งไว้บนเพดานแทนท้องฟ้า"},"ICON-2075":{"nm":"สายรัดม้วนถุงนอน","de":"สายที่พันรัดถุงนอนที่ม้วนไว้ไม่ให้คลายออก ที่นอนที่เล็กลงอีกครั้งเมื่อถึงเช้า การเตรียมตัวออกเดินทางคือการพับเก็บความอบอุ่นของคืนที่ผ่านมาให้เป็นระเบียบเรียบร้อย"},"ICON-2076":{"nm":"แผ่นวางรองเท้าหน้าเต็นท์","de":"แผ่นที่วางไว้หน้าทางเข้าเต็นท์เพื่อรองรับรองเท้าให้เป็นระเบียบ ดินอยู่ข้างนอก ด้านในสะอาดสะอ้าน ธรณีประตูเพียงหนึ่งเดียวแบ่งข้างในกับข้างนอกไว้อย่างอ่อนโยน เป็นมารยาทเล็กๆ ของการแคมป์ปิ้ง"},"ICON-2077":{"nm":"ตะขอแขวนตะเกียงกลามปิ้ง","de":"ตะขอโค้งสำหรับแขวนตะเกียง แขวนไว้ตรงนี้แสงก็จะกระจายเป็นวงกลมเข้าไปในเต็นท์ จุดที่แขวนแสงสว่างดวงหนึ่งไว้ท่ามกลางความมืด กลายเป็นห้องนั่งเล่นของเราในคืนนี้"},"ICON-2078":{"nm":"คลิปม้วนช่องระบายอากาศเต็นท์","de":"คลิปที่ม้วนเก็บช่องระบายอากาศไว้ เปิดทางลมไว้เล็กน้อย อากาศในเต็นท์ก็แจ่มชื่นขึ้นมาก ช่องว่างเล็กๆ ช่องเดียวสร้างพื้นที่หายใจตลอดทั้งคืนไว้อย่างเงียบๆ"},"ICON-2079":{"nm":"แผ่นรองพื้นเต็นท์","de":"แผ่นที่ปูไว้บนพื้นเต็นท์เพื่อกันดินและความชื้น เป็นหนึ่งชั้นที่ปูที่นอนแห้งสบายไว้แม้บนพื้นหญ้า เพื่อให้ได้อยู่ท่ามกลางธรรมชาติโดยไม่เปียกชื้นไปกับมัน มันคอยช่วยเหลืออยู่เคียงข้างอย่างเงียบๆ"},"ICON-2080":{"nm":"ห่วงล็อกแผ่นน้ำหนักบาร์เบล","de":"ห่วงที่ยึดไว้ปลายทั้งสองข้างของบาร์เบล เพื่อไม่ให้แผ่นน้ำหนักหลุดออก เป็นตัวล็อกเล็กๆ ที่ไว้วางใจน้ำหนักของผู้ยกอย่างเต็มที่ เมื่อความปลอดภัยรองรับไว้อย่างมั่นคง ขีดจำกัดจึงถูกยกระดับขึ้นอีกหนึ่งขั้นในที่สุด"},"ICON-2081":{"nm":"ฝาครอบด้ามจับเคทเทิลเบล","de":"เซตสุดท้ายที่เหล็กบาดกัดฝ่ามือ ฝาเล็กๆ ชิ้นนี้ทำให้ความเจ็บปวดหายไป การจับให้มั่นจนถึงที่สุดยากกว่าการยกน้ำหนักเสียอีก มือจะรู้ก่อนใครในช่วงสุดท้ายของการฝึก"},"ICON-2082":{"nm":"ลิ่มสอดยึดแผ่นน้ำหนัก","de":"หากแผ่นน้ำหนักโคลงเคลงเพียงเล็กน้อย ท่าทางก็พังทลายลงตั้งแต่ก่อนจะยกด้วยซ้ำ ลิ่มบางๆ ที่สอดเข้าไปในช่องว่างจะยึดจุดศูนย์กลางไว้อย่างไร้เสียง ความมั่นคงเริ่มต้นขึ้นอย่างเงียบๆ ในที่ที่มองไม่เห็นเสมอ"},"ICON-2083":{"nm":"คลิปล็อกบาร์เบล","de":"ปลายนิ้วที่ล็อกตัวยึดต้องไม่มีความลังเลแม้แต่น้อย เสียงล็อกเล็กๆ แค่ \"แคล็ก\" หนึ่งครั้งนั้น ค้ำจุนการเคลื่อนไหวทั้งหมดที่จะตามมา ร่างกายเรียนรู้ที่จะฝากความไว้วางใจไว้กับคลิปเพียงตัวเดียวก่อนใคร"},"ICON-2084":{"nm":"ชิปสีบอกน้ำหนักแผ่นเวท","de":"ชิปที่มีสีต่างกันไปตามน้ำหนัก แม้อ่านตัวเลขไม่ออกมือก็จำได้ก่อน สีแดงหนัก สีฟ้าเบา จดจำน้ำหนักด้วยสีสัน ร่างกายวัดกำลังผ่านสายตาได้อย่างน่าประหลาดใจ"},"ICON-2085":{"nm":"ที่รองพื้นเคทเทิลเบล","de":"เพราะมีที่รองที่ขยายพื้นผิวที่สัมผัสพื้นให้กว้างขึ้น พื้นไม้จึงไม่เป็นรอยบุบ ร่องรอยของการออกกำลังกายควรอยู่แค่ในเหงื่อและกล้ามเนื้อเท่านั้น หัวใจเล็กๆ ที่ไม่อยากทิ้งบาดแผลไว้แม้แต่ใต้เท้าซ่อนอยู่ตรงนี้"},"ICON-2086":{"nm":"เครื่องหมายกึ่งกลางบาร์เบล","de":"เครื่องหมายที่สลักไว้กึ่งกลางแท่งเหล็กคือจุดอ้างอิงของสมดุลซ้ายขวา มือที่จับตรงกึ่งกลางได้แม่นยำจะลดการโคลงเคลงลงครึ่งหนึ่ง เมื่อรู้ว่าจุดศูนย์กลางอยู่ตรงไหน จึงจะยกได้อย่างปลอดภัยในที่สุด"},"ICON-2087":{"nm":"ชั้นเก็บแผ่นน้ำหนัก","de":"แผ่นน้ำหนักที่ใช้เสร็จแล้วกลับไปยังที่ของมัน ภาพที่แผ่นน้ำหนักเรียงแขวนไว้อย่างเป็นระเบียบตามน้ำหนักบนชั้น คือความใส่ใจอันเงียบสงบสำหรับคนต่อไป พื้นที่ที่เป็นระเบียบคืออุปกรณ์ความปลอดภัยที่น่าเชื่อถือที่สุด ใครสักคนเชื่อเช่นนั้น"},"ICON-2088":{"nm":"ขอบกันแผ่นน้ำหนักกลิ้ง","de":"อุบัติเหตุที่แผ่นน้ำหนักบนพื้นกลิ้งไปทับหลังเท้ามักเกิดขึ้นในวินาทีที่เผลอเรอเสมอ ขอบกันการกลิ้งจะสกัดกั้นเสี้ยววินาทีนั้นไว้อย่างเงียบๆ เรื่องใหญ่ไม่ได้มาจากที่ใหญ่ แต่กลิ้งมาจากช่องว่างเล็กๆ เสมอ"},"ICON-2089":{"nm":"เบาะพนักพิงม้านั่งออกกำลังกาย","de":"หากเบาะที่รองแผ่นหลังแข็งเกินไป แม้แต่ลมหายใจก็จะตื้นขึ้นทันที เส้นแบ่งระหว่างความแข็งที่พอดีกับความนุ่มที่พอดีนั้น มีเพียงผู้ที่เคยนั่งนานเท่านั้นที่จะคลำหาจุดสมดุลนั้นเจอด้วยปลายนิ้ว"},"ICON-2090":{"nm":"หมุดปรับความสูงราคบาร์เบล","de":"เพียงหมุดตัวเดียวที่กำหนดความสูง บาร์ก็จะพอดีกับไหล่ของใครก็ได้ คนที่มีส่วนสูงต่างกันแบ่งปันอุปกรณ์ชิ้นเดียวกันได้อย่างกลมเกลียว—รูปรับระดับเล็กๆ เพียงรูเดียวสร้างความเท่าเทียมอันอ่อนโยนนั้นขึ้นมา"},"ICON-2091":{"nm":"ฝาครอบรอกเครื่องออกกำลังกาย","de":"ภายในฝาครอบที่หุ้มรอกไว้ สายเคเบิลหมุนวนไปมาโดยไม่มีเสียงใดๆ ชิ้นส่วนที่ซ่อนแรงเสียดทานไว้ข้างในและมอบเพียงความลื่นไหลให้แก่มือ อุปกรณ์ที่ดีไม่เคยเปิดเผยความเหนื่อยยากที่มันแบกรับไว้เลยจนถึงที่สุด"},"ICON-2092":{"nm":"ยางกันลื่นขาม้านั่งออกกำลังกาย","de":"ยางกันลื่นที่สวมไว้ที่ปลายขาทั้งสี่ยึดม้านั่งไว้กับพื้นอย่างมั่นคง ต้องไม่โคลงเคลงเสียก่อน จึงจะทุ่มกำลังทั้งหมดลงไปได้อย่างวางใจ ความมั่นคงแท้จริงแล้วเริ่มต้นจากแรงเสียดทานเล็กๆ ที่ปลายเท้า"},"ICON-2093":{"nm":"ตะขอวางบาร์เบลบนราค","de":"ตะขอสำหรับวางบาร์ต้องอยู่ในระดับที่มือเอื้อมถึงเสมอ ตำแหน่งที่แขนอันเหนื่อยล้าวางบาร์ลงอย่างเบามือเป็นครั้งสุดท้าย ตำแหน่งเพียงหนึ่งฝ่ามือนั้นปิดฉากการออกกำลังกายวันนี้ไว้อย่างปลอดภัย"},"ICON-2094":{"nm":"มือจับหมุดปรับน้ำหนักเครื่องออกกำลังกาย","de":"มือจับสำหรับเสียบหมุดเลือกน้ำหนักต้องเรียบลื่น เพื่อไม่ให้เล็บเสียหาย แม้ในการเคลื่อนไหวเล็กๆ ชั่วพริบตาของการเปลี่ยนน้ำหนัก ก็รู้สึกได้ว่ามีการเก็บรายละเอียดที่คำนึงถึงปลายนิ้วของมนุษย์ซ่อนอยู่อย่างเงียบๆ"},"ICON-2095":{"nm":"คันโยกล็อกองศาม้านั่ง","de":"หากคันโยกที่ล็อกองศาพนักพิงหลวม ท่าทางก็จะพังทลายลงอย่างไม่รู้ตัว ความมั่นใจในวินาทีที่มันล็อกเข้าที่ด้วยเสียงแคล็ก ผู้ดูแลจะตรวจสอบเสียงนี้ก่อนเป็นอันดับแรกอย่างเงียบๆ ทุกเช้าที่เปิดประตู"},"ICON-2096":{"nm":"ที่รองแท่งเซฟตี้บาร์ราค","de":"ในวินาทีที่เลวร้ายที่สุดที่บาร์เบลหลุดจากมือ ที่รองแท่งเซฟตี้จะรับน้ำหนักนั้นไว้แทน เพราะมีที่รองที่คอยรอรับอยู่เบื้องล่างเสมออย่างมองไม่เห็น คนเราจึงกล้าผลักดันตัวเองไปจนถึงขีดจำกัดได้ในที่สุด"},"ICON-2097":{"nm":"ปลอกปิดปลายสายเคเบิลเครื่องออกกำลังกาย","de":"ฝาเล็กๆ ที่รวบปลายสายเคเบิลไว้คือปมสุดท้ายที่ป้องกันการคลายออก การมัดให้เรียบร้อยไม่ให้เส้นสายกระจาย—ความประณีตของการเก็บงานมักอยู่ที่จุดปลายเล็กๆ ที่ไม่มีใครสังเกตเห็นเสมอ"},"ICON-2098":{"nm":"ถุงผงชอล์กจับยก","de":"ผงสีขาวกำมือหนึ่งที่ทาลงบนมือเพื่อลบล้างความลื่น แม้จะมองไม่เห็นเหมือนเครื่องแต่งหน้าหลังเวที ความมั่นคงของทุกท่าทางในวันนี้เริ่มต้นจากกำมือนี้เอง การเตรียมตัวเริ่มต้นที่ปลายนิ้วเสมอ"},"ICON-2099":{"nm":"คลิปฝึกแรงกำมือ","de":"คลิปเล็กๆ ที่ทำซ้ำการกำแล้วคลายอย่างเงียบๆ ช่วยเสริมสร้างพลังของอุ้งมือ แรงกำมือเติบโตช้ากว่ากล้ามเนื้อมัดใหญ่ ดังนั้นนี่จึงเป็นการฝึกวางความใจร้อนลงอย่างเงียบๆ ไปในตัวด้วย"},"ICON-2100":{"nm":"แถบยางถ่างนิ้วมือ","de":"แถบยางที่สอดระหว่างนิ้วมือแล้วค่อยๆ ถ่างออกด้านนอก มือที่เคยใช้แต่กล้ามเนื้อกำจะค่อยๆ ได้แรงกางคืนกลับมา มือบอกว่าการปล่อยวางอย่างนุ่มนวลก็ต้องฝึกฝนพอๆ กับการกำให้แน่น"},"ICON-2101":{"nm":"ฝาหลอดผงชอล์ก","de":"แม้ฝาหลอดผงจะหลวมเพียงนิดเดียว ก้นกระเป๋าทั้งใบก็จะขาวโพลนไปหมด ฝาเล็กๆ ที่ปิดสนิทพอดีเพียงชิ้นเดียวช่วยป้องกันความเสียหายเล็กๆ น้อยๆ นั้นไว้ล่วงหน้า ความสำเร็จของการเก็บกักมักตัดสินกันที่จุกปิดเสมอ"},"ICON-2102":{"nm":"ผ้าพันเข่าพยุงข้อ","de":"ผ้าพันที่พันรอบเข่าเพื่อพยุงต้องหยุดที่แรงกดพอดีเท่านั้น ถ้าแน่นเกินไปเลือดจะไหลเวียนไม่สะดวก หลวมเกินไปก็ไร้ประโยชน์ มือที่คุ้นเคยจึงค่อยๆ กะระยะพอดีนั้นด้วยความทรงจำอย่างเงียบๆ"},"ICON-2103":{"nm":"สายยางยืดฝึกแรงต้าน","de":"สายยางยืดที่ยืดออกแล้วหดกลับปลุกกล้ามเนื้อที่หลับใหลได้โดยไม่ต้องใช้เหล็กหนักแม้แต่ชิ้นเดียว แรงต้านไม่จำเป็นต้องหนักเสมอไป แม้เผชิญแรงดึงที่อ่อนโยน ร่างกายก็ยังคงตอบสนองอย่างซื่อสัตย์เสมอ"},"ICON-2104":{"nm":"ถุงทรายถ่วงข้อเท้า","de":"ถุงทรายที่คาดไว้ที่ข้อเท้าดึงแต่ละก้าวให้หนักอึ้งอย่างน่าพอใจ เพียงเพิ่มน้ำหนักอีกนิด แม้แต่การเดินธรรมดาก็กลายเป็นการฝึกซ้อมที่จริงจัง มันคือปัญญาเล็กๆ ที่แอบเติมภาระนิดหน่อยลงในชีวิตประจำวัน"},"ICON-2105":{"nm":"แท่งม้วนเสริมแรงข้อมือ","de":"แท่งม้วนที่ค่อยๆ หมุนดึงตุ้มน้ำหนักที่ผูกไว้กับเชือกขึ้นมาด้วยข้อมือ ข้อมือเป็นข้อต่อที่เล็กที่สุดและมักถูกลืมบ่อยที่สุด แต่เครื่องมือเรียบง่ายชิ้นนี้ค่อยๆ ปลุกพลังที่ถูกลืมนั้นให้ฟื้นคืนมาอย่างเงียบๆ"},"ICON-2106":{"nm":"ลูกบอลยางบริหารแรงกำมือ","de":"ลูกบอลยางที่บีบแล้วคลายในมือช่วยให้การฝึกซ้อมดำเนินต่อไปอย่างเงียบๆ แม้กระทั่งขณะนั่งอยู่หน้าโต๊ะทำงาน พลังที่สะสมทีละน้อยในยามว่างอยู่ได้นานกว่าพลังที่ทุ่มลงไปในคราวเดียว ความสม่ำเสมอเติบโตมาจากสิ่งเล็กๆ แบบนี้เสมอ"},"ICON-2107":{"nm":"หัวเข็มขัดสายวัดชีพจร","de":"หากหัวเข็มขัดของสายรัดหน้าอกเบี้ยวไปเพียงนิดเดียว ตัวเลขก็จะกระโดดผิดเพี้ยน แม้แต่การฟังเสียงหัวใจของตัวเองก็ต้องเริ่มจากการรัดให้แน่นหนาเสียก่อน ทุกการวัดผลท้ายที่สุดแล้วเริ่มต้นจากความแนบสนิทไร้ช่องว่างเสมอ"},"ICON-2108":{"nm":"คลิปหนีบวัดชีพจรปลายนิ้ว","de":"คลิปที่เบาๆ กัดปลายนิ้วเพื่อนับจังหวะชีพจรอย่างเงียบๆ เพียงสวมแล้วปรับลมหายใจให้เรียบ จังหวะหัวใจก็ปรากฏขึ้นชัดเจนบนหน้าจอเล็กๆ ร่างกายบอกเล่าสภาพที่แท้จริงของตัวเองอย่างไม่เคยโกหก"},"ICON-2109":{"nm":"กล่องเก็บสายรัดข้อมือวัดชีพจร","de":"กล่องที่ใส่เครื่องวัดข้อมือแม้เล็กแต่ก็จำครอบครัวของตัวเองได้ ยิ่งเป็นอุปกรณ์ชิ้นเล็กที่ทำหายง่ายเท่าไร ก็ยิ่งต้องการบ้านให้กลับไปมากเท่านั้น การเก็บรักษาสิ่งของให้ดีก็เป็นความอ่อนโยนอีกรูปแบบหนึ่ง"},"ICON-2110":{"nm":"หมุดธงกำหนดจังหวะวิ่ง","de":"หมุดธงเล็กๆ ที่ปักบอกจุดหมายของนักวิ่ง จุดเดียวที่กำหนดไว้ล่วงหน้าว่า \"แค่นี้พอ\" พาเท้าที่หนักอึ้งไปจนถึงปลายทางได้ เส้นชัยในใจนั้นเป็นสิ่งที่เราต้องปักด้วยมือของตัวเองเสมอ"},"ICON-2111":{"nm":"ฝาไฟกะพริบจังหวะหัวใจ","de":"ดวงไฟดวงเล็กที่กะพริบเบาๆ ตามจังหวะการเต้นของหัวใจ เมื่อจ้องมองจังหวะที่ติดๆ ดับๆ นั้นเนิ่นนาน หัวใจก็พลันหวั่นไหว ด้วยความคิดว่าการมีชีวิตอยู่นั้นเป็นสิ่งที่สม่ำเสมอได้ถึงเพียงนี้เชียวหรือ"},"ICON-2112":{"nm":"สายลูกปัดนับรอบ","de":"นับจำนวนครั้งด้วยลูกปัดที่เขี่ยเลื่อนทีละเม็ด ไม่ต้องจำตัวเลขไว้ในหัว เพราะนิ้วมือจดจำแทนให้ เมื่อมอบการนับให้มือทำหน้าที่ ใจก็สามารถจดจ่ออยู่กับการเคลื่อนไหวได้อย่างเต็มที่"},"ICON-2113":{"nm":"แผ่นหนีบวัดออกซิเจนปลายนิ้ว","de":"แผ่นหนีบที่สวมปลายนิ้วอ่านปริมาณออกซิเจนในเลือดอย่างเงียบๆ เมื่อความลึกของลมหายใจที่มองไม่เห็นปรากฏเป็นตัวเลข ก็ตระหนักขึ้นมาอีกครั้งว่าการดูแลร่างกายนั้น ท้ายที่สุดแล้วคือการมองให้ลึกซึ้งนั่นเอง"},"ICON-2114":{"nm":"แถบสีโซนอัตราการเต้นหัวใจ","de":"แถบที่แบ่งความหนักของการออกกำลังกายด้วยสีบอกให้รู้ในพริบตาว่าตอนนี้กำลังพยายามมากแค่ไหน สีฟ้าคือผ่อนคลาย สีแดงคือขีดจำกัด สีจึงกลายเป็นภาษาที่อ่อนโยน เป็นคำสัญญาเงียบๆ ที่สื่อสารกันด้วยสีเพียงสีเดียว"},"ICON-2115":{"nm":"แคปซูลเจลลี่วัดผลร่างกาย","de":"แคปซูลเจลลี่เล็กๆ ที่วัดสภาพร่างกายบรรจุข้อมูลของทั้งวันไว้ในเม็ดเดียวอย่างประณีต ไม่ว่าสิ่งที่อยู่ในเปลือกใสนั้นจะเป็นอะไร ความปรารถนาที่อยากรู้จักตัวเองให้มากขึ้นอีกนิดก็ถูกบรรจุไว้ในนั้นด้วยเช่นกัน"},"ICON-2116":{"nm":"ตะขอแขวนผ้าเช็ดเหงื่อ","de":"นิสัยเล็กๆ ที่ไม่วางผ้าทิ้งไว้ตามใจ แต่แขวนไว้บนตะขอของตัวเองเสมอ ช่วยรักษาความเป็นระเบียบของทั้งพื้นที่เอาไว้ได้ เช่นเดียวกับสิ่งนี้ที่กำหนดที่ทางให้ผ้าเช็ดตัวได้กลับไปอยู่ล่วงหน้า ความเป็นระเบียบเรียบร้อยมักส่องประกายจากเรื่องเล็กๆ น้อยๆ เสมอ"},"ICON-2117":{"nm":"สายรัดฝาขวดน้ำ","de":"เชือกสั้นๆ ที่ผูกติดกับฝาขวดน้ำป้องกันอุบัติเหตุฝาตกกลิ้งหายไป ปัญญาแห่งการผูกสิ่งที่ทำหายง่ายไว้กับตัว เชือกเส้นเล็กๆ เพียงเส้นเดียวช่วยขจัดความยุ่งยากทั้งวันออกไปอย่างเงียบๆ"},"ICON-2118":{"nm":"ใบพัดพัดลมมือ","de":"ใบพัดที่กางออกเต็มที่แล้วก่อให้เกิดสายลม เหมือนพัดโบราณที่เคยระบายเหงื่อในวันร้อน เครื่องมือที่เรียบง่ายที่สุดมอบความเย็นสบายที่สุดเสมอ สายลมเพียงหนึ่งสายผลิบานจากปลายนิ้วมือเสมอมา"},"ICON-2119":{"nm":"ถุงใส่ผ้าเย็น","de":"ถุงเล็กๆ ที่เก็บผ้าเช็ดตัวซึ่งเย็นฉ่ำเมื่อชุบน้ำ ผ้าผืนเดียวที่ช่วยระบายความร้อนนอนหลับสงบอยู่ในนั้นอย่างเรียบร้อย ก่อนจะลงมาแตะต้นคออันเหนื่อยล้าอย่างแผ่วเบา แล้วค่อยๆ พาความร้อนของยามบ่ายจากไปอย่างเงียบๆ"},"ICON-2120":{"nm":"จานรองหยดน้ำ","de":"จานรองที่เตรียมพื้นที่ไว้ล่วงหน้าสำหรับหยดน้ำที่เกาะตัวจะร่วงหล่นลงมา แทนที่จะตำหนิสิ่งที่ไหลย้อย กลับมอบพื้นที่รองรับให้ก่อน ความอ่อนโยนของครัวมักแฝงอยู่อย่างเงียบเชียบเช่นนี้เสมอ"},"ICON-2121":{"nm":"ใบปรับทิศทางลมพัดลม","de":"ในวินาทีที่ลมซึ่งพัดตรงมาปะทะเบี่ยงเบนไปเล็กน้อยตามใบพัดเล็กๆ นั้น อากาศอบอ้าวในห้องซ้อมก็ได้พักหายใจในที่สุด การเปลี่ยนทิศทางการไหลมักขึ้นอยู่กับมุมเล็กๆ แบบนี้เสมอ"},"ICON-2122":{"nm":"ผ้าคาดหน้าผาก","de":"ถ้าผมหน้าม้าเปียกน้ำตอนล้างหน้า ทั้งวันก็จะยุ่งเหยิงไปหมด ผ้าคาดเส้นนี้ที่รวบผมขึ้นจากหน้าผากเบาๆ มอบเวลาห้านาทีที่แห้งสนิทให้กับคนตรงหน้ากระจก จะรู้ค่าของมันก็ต่อเมื่อมันหายไปเท่านั้น"},"ICON-2123":{"nm":"ที่หนีบตั้งแก้วน้ำ","de":"เมื่อแก้วน้ำโคลงเคลงอย่างล่อแหลมที่ขอบโต๊ะ ที่หนีบนี้จะจับด้านหนึ่งไว้อย่างเงียบๆ วันที่ผ่านไปโดยไม่มีน้ำหกเลยนั้น น้ำหนึ่งจิบเตือนให้รู้ว่าเป็นเพราะมีใครสักคนช่วยจับขอบไว้แทนเรา"},"ICON-2124":{"nm":"ที่ล็อกหน้าต่างระบายอากาศ","de":"หน้าต่างที่ปิดสนิทก็อึดอัด หน้าต่างที่เปิดโล่งก็หนาวเย็น ที่ล็อกนี้จดจำช่องว่างที่พอเหมาะระหว่างสองสิ่งนั้นไว้เสมอ การระบายอากาศท้ายที่สุดแล้วคือเรื่องของหัวใจ ที่รู้จักเปิดไว้แต่พอดี"},"ICON-2125":{"nm":"ฝาครอบมุมบล็อกคอร์ก","de":"มุมแหลมคมมักเป็นสิ่งที่ทำร้ายเราเสมอเมื่อชนเข้า จึงต้องเหลาคอร์กชิ้นหนึ่งมาครอบไว้ทุกมุม ที่ที่ถูกห่อหุ้มไว้อย่างนุ่มนวลแล้วจะไม่ทำร้ายหัวเข่าของใครอีกต่อไป"},"ICON-2126":{"nm":"หูหิ้วสายหมอนข้าง","de":"การขนย้ายหมอนข้างชิ้นยาวนั้นน่ารำคาญกว่าที่คิด เพียงติดสายเส้นเดียว มันก็จะพอดีในมือข้างเดียว เคล็ดลับในการยกของหนักให้เบาขึ้นอยู่ที่ว่าจะติดหูหิ้วไว้ตรงไหน"},"ICON-2127":{"nm":"หัวเข็มขัดรัด","de":"มีทั้งวันที่ต้องรัดเอวแน่นขึ้นอีกช่อง และวันที่ต้องผ่อนออกอีกช่อง สิ่งที่รู้สภาพร่างกายวันนั้นได้ซื่อตรงที่สุดคือหัวเข็มขัดเล็กๆ นี้ ชิ้นโลหะที่บันทึกความจริงใจของร่างกายไว้โดยไม่ปริปาก"},"ICON-2128":{"nm":"ฐานรองบล็อกสี่ส่วน","de":"บล็อกที่ตัดแบ่งเป็นสี่ส่วนช่วยค้ำพื้นให้มั่นคง ไม่สูงไม่ต่ำเกินไป ด้วยความสมดุลพอดีเท่านั้น มันแสดงให้เห็นอย่างเงียบๆ ว่าการค้ำจุนคือการก้มตัวลงเพื่อยกสิ่งที่อยู่เบื้องบนขึ้น"},"ICON-2129":{"nm":"ปลอกหมอนข้างทรงไข่","de":"สวมเสื้อผ้าที่พอดีตัวให้กับหมอนทรงกลมดังไข่ ถึงจะซึมเหงื่อก็แค่ถอดออกซักได้ งานบ้านรู้ดีว่ายิ่งเป็นสิ่งที่สัมผัสผิวกายทุกวัน ยิ่งต้องมีอีกผืนไว้ผลัดเปลี่ยน"},"ICON-2130":{"nm":"ลิ่มปรับระดับบล็อก","de":"หากพื้นเอียงเพียงเล็กน้อย สิ่งที่อุตส่าห์เรียงซ้อนไว้ก็จะโคลงเคลงไปหมด เพียงสอดลิ่มบางๆ ชิ้นเดียวเข้าไปในช่องว่างนั้น โลกก็กลับมาได้ระดับอีกครั้ง การทำให้ตรงไม่จำเป็นต้องอาศัยสิ่งยิ่งใหญ่เลย"},"ICON-2131":{"nm":"ลูกปมกันปลายสาย","de":"ผูกปมแน่นๆ ไว้เพื่อไม่ให้ปลายสายคลี่ลุ่ยหลุดออกมา สายที่มัดปลายไว้เรียบร้อยจะอยู่ทนนาน ปมเล็กๆ ปมเดียวสอนให้รู้ว่าการปิดท้ายให้ดีนั้นยากกว่าการเริ่มต้นเสียอีก"},"ICON-2132":{"nm":"เบาะรองเข่าแบบพับ","de":"ความเจ็บแปลบที่แล่นขึ้นทุกครั้งที่เข่าแตะพื้นแข็ง แผ่นเบาะที่พับกางได้แผ่นเดียวแทรกตัวเข้ามาเบาๆ ระหว่างเข่ากับพื้น มันคือความอ่อนโยนที่คอยรองรับหัวเข่าของใครสักคนแทนตัวเขาเอง"},"ICON-2133":{"nm":"แผ่นรองกันลื่นใต้บล็อก","de":"ต่อให้บล็อกแข็งแรงแค่ไหน หากลื่นไถลก็ไร้ประโยชน์ ร่องเล็กๆ ที่สลักไว้บนแผ่นรองยึดพื้นไว้แน่น ความลับของสิ่งที่ไม่โคลงเคลงมักซ่อนอยู่ด้านล่างที่มองไม่เห็นเสมอ"},"ICON-2134":{"nm":"คลิปจัดแนวแท่งไม้","de":"จัดแท่งไม้ให้เรียงตรงแล้วหนีบไว้ด้วยคลิป คนที่คุ้นเคยกับการจัดแถวย่อมรู้ดี ถึงความพึงพอใจเล็กๆ ที่แปลกประหลาดซึ่งเอ่อล้นขึ้นมาจากการจัดสิ่งที่เบี้ยวให้เรียงเคียงข้างกัน"},"ICON-2135":{"nm":"ห่วงสายยืดกล้ามเนื้อต้นขาหลัง","de":"เมื่อต้นขาด้านหลังดึงจนแทบร้องออกมา ห่วงนี้จะเอื้อมไปถึงปลายเท้าที่มือเราเองเอื้อมไม่ถึงแทน ในที่ที่ลำพังไปไม่ถึง เชือกเส้นเดียวก็ทอดสะพานให้กับขาของเรา"},"ICON-2136":{"nm":"แผ่นถ่างนิ้วเท้า","de":"แม้แต่นิ้วเท้าที่ถูกขังไว้ในรองเท้าทั้งวันก็ต้องการเวลาพัก บนแผ่นที่ถ่างนิ้วให้แยกออกจากกัน เท้าได้ยืดตัวอย่างสบายเสียที ค่ำคืนที่ผ่อนคลายเริ่มต้นจากที่ไกลที่สุดก่อนเสมอ"},"ICON-2137":{"nm":"มาตรวัดมุมท่าทาง","de":"ด้วยตาเปล่าไม่มีทางกะได้เลยว่าท่าทางของเราเอียงไปกี่องศา เมื่อมาตรวัดบอกมุมให้อย่างเงียบๆ ร่างกายจึงยืนตรงได้ในที่สุด มาตราส่วนที่แสดงความเอียงที่มองไม่เห็นให้ปรากฏ"},"ICON-2138":{"nm":"ลิ่มปรับแนวกระดูกเชิงกราน","de":"ยามบ่ายอันเงื่องหงอยที่กระดูกเชิงกรานเอียงไปข้างหนึ่งจนแข็งค้าง วางลิ่มชิ้นหนึ่งรองไว้แล้วค่อยๆ กลับคืนสู่จุดศูนย์กลาง มันไม่ใช่การฝืนดัดให้ตรง แต่เป็นการช่วยให้กลับไปหาตำแหน่งที่เหมาะสมอีกครั้ง"},"ICON-2139":{"nm":"หัวเข็มขัดแถบเปิดไหล่","de":"แถบที่ค่อยๆ ยืดไหล่ที่หดงอให้ผ่อนคลาย เมื่อรัดหัวเข็มขัดให้แน่น หลังที่โก่งงอก็ค่อยๆ เปิดออก สูดหายใจลึกด้วยไหล่ที่เปิดกว้างเต็มที่ แล้วท่าทางสำหรับการโค้งคำนับบนเวทีก็ปรากฏขึ้นในที่สุด"},"ICON-2140":{"nm":"ลิ่มรองรับกระดูกสันหลัง","de":"นอนหงายลงแล้วกระดูกสันหลังก็ทอดเป็นเส้นโค้งตามธรรมชาติของมัน ลิ่มที่รองรับเส้นโค้งนั้นไว้อย่างเงียบๆ โดยไม่ฝืน วิธีพักผ่อนที่ดีเริ่มต้นจากการยอมรับเส้นโค้งที่ร่างกายมีมาแต่กำเนิด"},"ICON-2141":{"nm":"ลิ่มยืดหลังเท้า","de":"การยืดหลังเท้าดูจะขาดอะไรบางอย่างไปเสมอ เมื่อรองลิ่มที่พอเหมาะ ก็สามารถยืดไปได้ลึกถึงจุดที่เคยเอื้อมไม่ถึงอย่างสดชื่น เนินลาดเล็กๆ ที่ช่วยให้เอื้อมไปได้ไกลขึ้นอีกนิด"},"ICON-2142":{"nm":"ที่รองข้อมือจัดแนว","de":"เมื่อข้อมือที่หักงอหน้าคีย์บอร์ดเริ่มชาวูบวาบ ที่รองนี้จะเลื่อนเข้ามาแทรกอยู่ใต้ข้อมืออย่างเงียบๆ สิ่งของที่คอยดูแลมือที่ทำงานหนักเป็นเวลานานก่อนใครเสมอ ก็คือของชิ้นเล็กที่วางอยู่ในตำแหน่งต่ำต้อยเช่นนี้"},"ICON-2143":{"nm":"ผ้าพันข้อมือ","de":"ก่อนจะยกของหนัก พันผ้าพันรอบข้อมือไว้หนึ่งรอบ ความอุ่นใจที่เพิ่มขึ้นตามจำนวนรอบที่พัน นิสัยที่คอยห่อหุ้มไว้ก่อนที่จะบาดเจ็บคือเคล็ดลับเงียบๆ ของคนที่ออกกำลังกายมาอย่างยาวนาน"},"ICON-2144":{"nm":"ปลอกแขนใส่โทรศัพท์","de":"จะเก็บโทรศัพท์ไว้ตรงไหนระหว่างวิ่งเป็นเรื่องที่กังวลอยู่เสมอ ถุงคาดต้นแขนนี้พาความกังวลนั้นไปด้วย วิ่งไปพร้อมเพลงโปรดที่คาดไว้ที่แขน แล้วเส้นทางก็รู้สึกสั้นลงไปมาก"},"ICON-2145":{"nm":"ฝาครอบสปริงที่บีบมือ","de":"ฝาที่ครอบปลายสปริงของเครื่องบริหารแรงกำมือไม่ให้ทิ่มแทงฝ่ามือ ตลอดเวลาที่บีบแล้วคลายซ้ำไปมา จุกเล็กๆ นี้รักษาความสงบสุขระหว่างมือกับโลหะไว้เสมอ เป็นความใส่ใจในที่ที่มองไม่เห็น"},"ICON-2146":{"nm":"ปลอกนิ้วถุงมือ","de":"นิ้วมือของคุณยายที่ชำนาญการเย็บผ้ามักมีปลอกนิ้วติดอยู่เสมอ ปลอกนิ้วที่สวมไว้ปลายถุงมือนี้ปกป้องปลายนิ้วเช่นกัน ความปรารถนาที่อยากถนอมมือที่ทำงานมายาวนานนั้นเหมือนกันอย่างประหลาด แม้จะข้ามผ่านหลายชั่วอายุคน"},"ICON-2147":{"nm":"แผ่นรองหนังด้านฝ่ามือ","de":"ปุ่มหนังด้านที่ขึ้นบนฝ่ามือคือลายนิ้วมือที่ความพยายามทิ้งไว้ แผ่นที่ปะทับซ้อนบนนั้นทำให้การทำซ้ำครั้งต่อไปเป็นไปได้ ห่อหุ้มจุดที่แข็งกร้านนั้นไว้อีกครั้ง แล้วคนเราก็เกาะยึดต่อไปอีกครั้ง"},"ICON-2148":{"nm":"เทปกันลื่นฝ่ามือ","de":"หากฝ่ามือลื่นไถลอยู่เรื่อยๆ สิ่งที่อุตส่าห์จับไว้ก็จะหลุดมือไป พันเทปผิวหยาบเข้าไป มือกับอุปกรณ์ก็กลายเป็นหนึ่งเดียวกัน พลังที่ไม่ปล่อยให้หลุดมือนั้น น่าแปลกที่มาจากแรงเสียดทาน"},"ICON-2149":{"nm":"ผ้าซับเหงื่อต้นแขน","de":"ก่อนที่เหงื่อซึ่งไหลย้อยระหว่างออกกำลังกายจะไปถึงข้อมือ แถบผ้านี้ที่ต้นแขนจะซับไว้ก่อน เหงื่อไม่ใช่เรื่องน่าอาย ผ้าที่เปียกชุ่มเป็นพยานยืนยันโดยไม่ปริปาก"},"ICON-2150":{"nm":"ราวตากถุงมือ","de":"หากโยนทิ้งไว้เฉยๆ เช้าวันรุ่งขึ้นจะทรมานมาก แต่ถ้าแขวนไว้อย่างเรียบร้อย สายลมก็จะทำให้แห้งสนิทเองตลอดคืน กลิ่นสะอาดของถุงมือที่แห้งดีเปิดวันพรุ่งนี้ให้สดชื่น"},"ICON-2151":{"nm":"หูรูดซิปชุดกีฬา","de":"ด้วยมือที่เปียกชุ่มไปหมด ไม่มีทางจับซิปเส้นเล็กจิ๋วได้เลย เพียงติดหูจับหนึ่งชิ้น ก็รูดได้ในทีเดียวฉับไว ห่วงเล็กๆ ที่ดูไม่สำคัญนี้ช่วยกอบกู้หนึ่งนาทีที่วุ่นวายไว้ได้ทั้งหมด"},"ICON-2152":{"nm":"แผ่นระบายเหงื่อ","de":"ติดแผ่นระบายอากาศไว้ตรงจุดที่ร้อนที่สุดของร่างกาย ความร้อนที่ถูกขังไว้ค่อยๆ ลอดหนีออกไปทางช่องแผ่นนั้น การเปิดรูหายใจเล็กๆ รูหนึ่งไว้กลางใจที่อึดอัดที่สุด"},"ICON-2153":{"nm":"ชิ้นเบาะเสริมพื้นรองเท้า","de":"ตัดเอาเฉพาะส่วนที่สึกของพื้นรองเท้าเก่าออกแล้วใส่ชิ้นใหม่เข้าไปแทน มือที่ไม่ทิ้งทั้งชิ้นแต่ซ่อมเฉพาะจุดที่เจ็บ การซ่อมแซมเล็กๆ ใต้ฝ่าเท้าเปลี่ยนก้าวเดินของทั้งวันให้เบาสบายขึ้น"},"ICON-2154":{"nm":"แผ่นรีดติดหมายเลขชุดกีฬา","de":"รีดหมายเลขหลังเสื้อให้ติดแน่นบนผ้าด้วยเตารีด ระหว่างที่ความร้อนค่อยๆ เย็นลง ตัวเลขก็ยึดติดแน่นบนผืนผ้า ตราประทับแห่งจุดเริ่มต้นที่ทำให้คนสวมหมายเลขเดียวกันกลายเป็นทีมเดียวกัน"},"ICON-2155":{"nm":"ฝาเสริมหัวรองเท้า","de":"ชะตากรรมของรองเท้าที่ปลายเท้ามักชนซ้ำแล้วซ้ำเล่า ฝาเสริมที่ครอบไว้ที่หัวรองเท้าจะป้องกันไว้อย่างเงียบๆ จุดที่สึกก่อนใครถูกทำให้แข็งแรงที่สุด ยิ่งเป็นรองเท้าที่ใส่ทนนาน ยิ่งแข็งแกร่งตั้งแต่ปลายหัวรองเท้าเลยทีเดียว"},"ICON-2156":{"nm":"ปมเชือกรูดเอวชุดกีฬา","de":"ในวินาทีที่ดึงเชือกรูดเอวชุดกีฬาแล้วผูกปมไว้ ชุดที่หลวมโพรกก็รัดพอดีตัวขึ้นมาทันที ปมที่แน่นหนาไม่คลายง่ายนี้ยึดทุกอย่างให้เข้าที่ตลอดช่วงเวลาที่เคลื่อนไหวอย่างหนักหน่วง"},"ICON-2157":{"nm":"แถบกันถุงเท้าข้อสั้นเลื่อน","de":"ความยุ่งยากที่ถุงเท้าข้อสั้นมักม้วนตกลงไปในรองเท้าอยู่เรื่อยๆ แถบเส้นเดียวยึดการเลื่อนไถลนั้นไว้ ถุงเท้าคู่เล็กๆ ที่เคยถูกมองข้ามในที่สุดก็รักษาตำแหน่งของตัวเองไว้ได้"},"ICON-2158":{"nm":"แผ่นซับเหงื่อรักแร้ชุดกีฬา","de":"แผ่นที่ติดไว้ล่วงหน้าตรงจุดที่เหงื่อออกมากที่สุด แม้จะเปียกชุ่มก็ไม่มีร่องรอยปรากฏบนผิวเสื้อเลยแม้แต่น้อย สิ่งที่ทำงานเงียบๆ อยู่ในที่มองไม่เห็นนั้นเองที่รักษาความสะอาดบนเวทีไว้ได้"},"ICON-2159":{"nm":"ห่วงดึงส้นรองเท้า","de":"หลังจากสวมรองเท้าแล้วดึงห่วงที่ส้นเบาๆ เท้าก็เลื่อนเข้าไปพอดี ความสะดวกสั้นๆ ที่ไม่ต้องนั่งยองๆ ในเช้าที่เร่งรีบ ห่วงเล็กๆ แบบนี้เพียงชิ้นเดียวช่วยได้มาก"},"ICON-2160":{"nm":"หัวปืนนวด","de":"เปลี่ยนหัวให้เข้ากับจุดที่จะเคาะ กล้ามเนื้อที่เป็นปมแต่ละแห่งมีรูปทรงที่เหมาะสมของตัวเองต่างกันไป ค่ำคืนที่เลือกความเข้มข้นของความอบอุ่นใจที่พอเหมาะให้กับไหล่ที่อดทนผ่านวันมาได้"},"ICON-2161":{"nm":"แท่นชาร์จปืนนวด","de":"แม้แต่มือที่จะคอยผ่อนคลายร่างกายทั้งวันก็ตื่นขึ้นได้ก็ต่อเมื่อชาร์จเสร็จแล้วเท่านั้น ระหว่างที่ไฟสีแดงเปลี่ยนเป็นสีเขียว เราก็พักผ่อนได้สักครู่ เมื่อไฟกะพริบหยุดลง คราวที่จะกลับมาบรรเทาไหล่ที่แข็งเกร็งก็เวียนมาถึงอย่างเงียบๆ อีกครั้ง"},"ICON-2162":{"nm":"ปุ่มปรับความแรงปืนนวด","de":"เบาหน่อย อีกนิด แค่นั้นแหละ ขณะหมุนปุ่ม ปลายนิ้วต่อรองกับร่างกายของตัวเองอย่างเงียบๆ คำสัญญาของวันนี้ที่ว่าจะแข็งแรงขึ้นเท่าที่เจ็บพอดี ถูกจารึกไว้อย่างชัดเจนระหว่างขีดเล็กๆ นั้น"},"ICON-2163":{"nm":"วงแหวนรองลูกบอลสั่นสะเทือน","de":"แม้แต่ลูกบอลที่กลิ้งได้ดีก็ต้องการที่หยุดพักสักครู่ ที่รองทรงกลมนี้โอบอุ้มใจที่อยากจะกลิ้งจากไปไว้อย่างเงียบๆ รักษาตำแหน่งไว้จนกว่าจะถึงคราวถัดไป การพักก็เป็นส่วนหนึ่งของการออกกำลังกายเช่นกัน"},"ICON-2164":{"nm":"ฝาครอบด้ามไม้กดจุด","de":"เพียงหมวกเล็กๆ ที่สวมไว้ปลายด้าม ความเจ็บปวดในฝ่ามือก็ค่อยๆ จางหายไป ระหว่างความแข็งกับผิวหนังจำเป็นต้องมีชั้นนุ่มนวลอยู่เสมอ เป็นระยะทางอันอ่อนโยนที่ปรับจุดสัมผัสให้กลมมนก่อนเป็นอันดับแรก"},"ICON-2165":{"nm":"ถุงใส่ลูกกลิ้งรูปถั่ว","de":"ถุงเล็กๆ ที่เก็บแผ่นกลิ้งรูปทรงเมล็ดถั่ว เมื่อมันกลิ้งออกมาจากมุมหนึ่งของกระเป๋า ความตั้งใจของเมื่อวานที่ว่าวันนี้จะดูแลร่างกายบ้างก็กลิ้งตามออกมาด้วย ถุงเล็กๆ จดจำคำสัญญานั้นไว้"},"ICON-2166":{"nm":"ขาตั้งลูกกลิ้งนวดเท้า","de":"หากที่ที่ฝากเท้าไว้โคลงเคลง การผ่อนคลายก็โคลงเคลงตามไปด้วย ขาตั้งที่รองลูกกลิ้งไว้นี้ยึดพื้นไว้อย่างมั่นคง เตรียมที่ให้เท้าทั้งสองที่เหนื่อยล้าได้พิงพักอย่างวางใจ ความมั่นคงมาจากการไม่โคลงเคลงเสมอ"},"ICON-2167":{"nm":"จุกอุดแกนกลางลูกกลิ้ง","de":"จุกเล็กๆ ที่อุดแกนกลวงไว้ ด้านในที่มองไม่เห็นต้องเต็มอยู่เสมอ ด้านนอกจึงจะไม่บิดเบี้ยว ตำแหน่งที่ไม่มีใครมองเห็นระหว่างที่มันกลิ้งอยู่นั้น ชิ้นส่วนเงียบๆ นี้ค้ำจุนไว้อย่างไม่ปริปาก"},"ICON-2168":{"nm":"ฝาปลายไม้นวด","de":"ฝาที่ครอบกลมมนไว้ปลายด้าม เพื่อไม่ให้สึก ไม่ให้ขีดข่วน การปกป้องปลายด้ามคือหนทางที่จะเก็บไว้ข้างกายได้นานในที่สุด เป็นความตั้งใจที่ห่อหุ้มจุดที่กระทบก่อนใครไว้อย่างนุ่มนวลที่สุด"},"ICON-2169":{"nm":"ใบมีดตัดเทปพัน","de":"เพียงดึงด้วยมือเดียว เทปก็ถูกตัดขาดอย่างเรียบร้อย การผูกปมและปิดท้ายก็มีเคล็ดลับเล็กๆ อยู่เช่นกัน ใบมีดนี้จึงรู้จักความรู้สึกของการปิดท้ายอย่างเรียบร้อย การปิดท้ายที่สะอาดตาทำให้เรื่องถัดไปเบาสบายขึ้น"},"ICON-2170":{"nm":"ฝากดปลายเทปติด","de":"ฝาที่กดปลายเทปไว้อย่างเงียบๆ ไม่ให้คลี่หลุด ใครๆ ก็เริ่มต้นได้ แต่การติดแน่นอยู่จนถึงที่สุดนั้นยากเสมอ มือเล็กๆ ที่จับช่วงสุดท้ายไว้นี้รับผิดชอบการปิดท้ายของวันนี้ไว้อย่างเงียบๆ"},"ICON-2171":{"nm":"ปลอกรัดข้อมือ","de":"เพียงพันชั้นหนึ่งรอบข้อมือที่ใช้งานหนักเกินไป ความเจ็บปวดก็มาถึงช้าลงหนึ่งจังหวะ เหมือนมือที่จับไว้เงียบๆ ของใครสักคน การรัดแน่นบางครั้งก็เป็นการปกป้องที่อ่อนโยนที่สุด มันไม่ใช่การบีบรัด แต่เป็นการประคองไว้ต่างหาก"},"ICON-2172":{"nm":"หัวเข็มขัดสนับข้อเท้า","de":"เสียงคลิกสั้นๆ ของการล็อกเข็มขัดทำให้ใจสงบลง เมื่อพันข้อเท้าไว้แน่นหนา ความกล้าที่จะก้าวไปไกลอีกก้าวก็ค่อยๆ เอ่อล้นขึ้นมาอย่างแผ่วเบา เสียงเล็กๆ เพียงเสียงเดียวกลายเป็นจุดเริ่มต้นที่มั่นคง"},"ICON-2173":{"nm":"ตัวรัดสายพันเข่า","de":"ยิ่งดึงสายให้แน่นเท่าไร เข่าก็ยิ่งมั่นคงเท่านั้น ไม่หลุดง่ายแต่ก็ไม่เจ็บ ระหว่างสองสิ่งนั้นมีช่องพอดีอยู่ตรงกลางเสมอ ตัวรัดนี้ไม่เคยลืมจดจำตำแหน่งนั้นได้ทุกครั้งไป"},"ICON-2174":{"nm":"กรรไกรตัดเทปพันนิ้ว","de":"กรรไกรเล็กๆ ที่ตัดเทปที่พันรอบข้อนิ้วอย่างประณีต ปลายมนไม่ทำร้ายผิวหนัง ยิ่งเป็นเครื่องมือที่ใช้ดูแล ยิ่งลับคมด้วยความอ่อนโยนมากขึ้น กรรไกรนี้แสดงให้เห็นอย่างเงียบๆ"},"ICON-2175":{"nm":"แกนม้วนแถบรัด","de":"แกนที่ม้วนแถบรัดที่คลี่ออกให้กลับมาเรียบร้อยเป็นระเบียบ มือที่ม้วนสิ่งที่ใช้เสร็จแล้วอย่างพิถีพิถัน จะไม่ยุ่งเหยิงเมื่อคลี่ออกใช้ครั้งต่อไปเช่นกัน ในแต่ละชั้นที่ม้วนไว้อย่างเป็นระเบียบนั้น ซึมซับความเรียบร้อยของวันนี้ไว้"},"ICON-2176":{"nm":"สายรัดสนับแข้ง","de":"สายที่ผูกแผ่นป้องกันหน้าแข้งไว้ ใจที่คอยตรวจสอบจุดที่อาจถูกกระแทกล่วงหน้าคือการเตรียมพร้อมในตัวมันเอง ก้าวเข้าสู่สนามด้วยขาที่ผูกปมไว้แน่นหนา ความกลัวในใจก็ลดลงไปครึ่งหนึ่ง"},"ICON-2177":{"nm":"คลิปยึดสนับข้อศอก","de":"คลิปเล็กๆ ที่กัดแน่นเพื่อไม่ให้สนับข้อศอกไหลลง เล็กน้อยราวกับหนีบกระดาษแผ่นเดียว แต่ถ้ามันหลุดออก ทุกอย่างก็จะหลวมโพรกไปหมด การยึดเล็กๆ เพียงจุดเดียวยึดความอุ่นใจของทั้งวันไว้ได้อย่างมั่นคง"},"ICON-2178":{"nm":"ห่วงจับยืดกล้ามเนื้อ","de":"จับห่วงแล้วยืดร่างกายให้ยาวออก จะเห็นปลายนิ้วที่ไปไกลกว่าเมื่อวานหนึ่งฝ่ามือ ไม่ใช่แค่กล้ามเนื้อเท่านั้นที่ยืดออกตามแรงดึง ใจที่แข็งค้างก็คลายตัวออกทีละนิดในระหว่างนั้นเช่นกัน"},"ICON-2179":{"nm":"ตัวถ่างนิ้วเท้า","de":"ถ่างนิ้วเท้าที่ถูกขังไว้ในรองเท้าทั้งวันให้แยกออกจากกัน แล้วสายลมก็พัดเข้ามาในที่แคบนั้น บางสิ่งในโลกนี้จะสบายขึ้นก็ต่อเมื่อได้แยกจากกันสักพักเท่านั้น แม้แต่ปลายเท้าก็ต้องการช่องว่างให้หายใจ"},"ICON-2180":{"nm":"แผ่นลิ่มผ่อนคลายน่อง","de":"สอดไว้ใต้น่องดังลิ่ม แล้วขาก็ค่อยๆ คลายตัวออก มุมเอียงเพียงมุมเดียวปล่อยให้น้ำหนักของทั้งวันไหลผ่านไปอย่างเงียบๆ การเอนตัวลงนอนพิงเบาๆ นั้น บางครั้งก็เป็นท่าทางที่สบายที่สุด"},"ICON-2181":{"nm":"ที่รองคอผ่อนคลาย","de":"วางคอพาดไว้แล้วหลับตาลงสักครู่ ที่รองเล็กๆ นี้กระซิบเบาๆ กับไหล่จากตำแหน่งเดิมเสมอ ว่าวางศีรษะที่หนักอึ้งลงชั่วครู่ก็ได้ แม้แต่การพิงพักก็ยังต้องใช้ความกล้าเช่นกัน"},"ICON-2182":{"nm":"ฝาปลายไม้ยืดกล้ามเนื้อ","de":"ฝาชิ้นหนึ่งที่ครอบปลายไม้ที่ยืดออกไปยาวไกล เมื่อปลายนุ่มนวล ไม่ว่าจะสัมผัสตรงไหนก็วางใจได้ ไม่ว่าจะเอื้อมไปหาใคร ก็ปรับมุมให้กลมมนไว้ก่อนเสมอ ความใส่ใจมักเริ่มต้นอย่างเงียบๆ เช่นนี้เสมอ"},"ICON-2183":{"nm":"แผ่นเบาะปุ่มกดจุด","de":"เอนกายลงบนปุ่มนูนขรุขระ วันทั้งวันก็ไหลออกไปจากทุกจุดที่ถูกกดลง ณ เส้นแบ่งระหว่างความเจ็บกับความสบายนั้น ไหล่ที่แข็งเกร็งมาทั้งวันค่อยๆ คลายตัวลงราวกับยอมจำนน"},"ICON-2184":{"nm":"นาฬิกาทรายหายใจผ่อนคลาย","de":"คำสัญญาเงียบๆ ที่จะหายใจยาวๆ ไปจนกว่าเม็ดทรายเม็ดสุดท้ายจะร่วงลงจนหมด สายทรายบางๆ นับจังหวะของลมหายใจเข้าออกอย่างเงียบๆ ใจที่วุ่นวายก็สงบลงชั่วครู่ในระหว่างนั้นเช่นกัน"},"ICON-2185":{"nm":"ที่รองลูกบอลกดจุดฝ่าเท้า","de":"วางลูกบอลไว้กลางฝ่าเท้าแล้วกดลงเบาๆ อย่างมั่นคง ที่รองเล็กๆ นี้มอบตำแหน่งของตัวเองให้กับเท้าที่แบกรับทั้งร่างกายมาทั้งวันอย่างเงียบๆ บอกว่าถึงคราวที่มันจะได้รับการประคองบ้างแล้ว แม้แต่สิ่งที่ค้ำจุนก็มีเวลาได้พักเช่นกัน"},"ICON-2186":{"nm":"สายห่วงคล้องผ่อนคลายไหล่","de":"สายห่วงที่คล้องไหล่แล้วดึง เมื่อยืดเชือกไปยังจุดที่แข็งค้าง ข้อที่เกร็งเป็นปมก็คลายตัวออกทีละช่อง มันบอกให้รู้ว่าแม้แต่การเป็นอิสระก็ต้องการบางสิ่งที่ยื่นมือมาจับไว้เช่นกัน"},"ICON-2187":{"nm":"แผ่นดิสก์เชือกกั้นเลน","de":"ปมกลมเม็ดหนึ่งของเชือกที่กั้นแบ่งสายน้ำเป็นเลน เป็นเส้นแบ่งอันอ่อนโยนที่ขีดไว้เหนือผืนน้ำเพื่อไม่ให้ชนกับคนข้างๆ ฉากกั้นเล็กๆ ที่คอยปกป้องเส้นทางของแต่ละคนนี้เองที่พาทุกคนก้าวไปข้างหน้าเคียงข้างกันจนถึงที่สุด"},"ICON-2188":{"nm":"ตะขอปรับความตึงเชือกกั้นเลน","de":"ตะขอที่ดึงเชือกกั้นเลนให้ตึงแล้วยึดไว้ หลวมไปก็โค้งงอไปตามคลื่น ตึงไปก็ขาด การหาความตึงที่พอเหมาะนั้นคล้ายกับการควบคุมสติใจให้มั่นคง จึงต้องคลำหาจุดตรงกลางระหว่างสองสิ่งนั้นอยู่เสมอ"},"ICON-2189":{"nm":"ฝาสีเลนว่ายน้ำ","de":"จุกเล็กๆ ที่ทาสีแตกต่างกันไปในแต่ละเลน เป็นเครื่องหมายที่ทาไว้ให้มองเห็นเส้นทางของตัวเองได้ในพริบตาแม้จากระยะไกล ไม่ให้หลงทางด้วยสีเพียงสีเดียว การนำทางโดยแท้จริงแล้วเริ่มต้นจากความเมตตาเล็กๆ เช่นนี้เสมอ"},"ICON-2190":{"nm":"แผงแขวนเชือกกั้นเลน","de":"แผงสำหรับแขวนเชือกกั้นเลนให้เป็นระเบียบเมื่อไม่ได้ใช้งาน ในมือที่จัดเรียงเชือกอย่างประณีตเพื่อการเริ่มต้นครั้งต่อไป มีความตั้งใจอันสงบนิ่งที่จะปิดวันนี้ให้ดีซ่อนอยู่อย่างเงียบๆ"},"ICON-2191":{"nm":"มือหมุนม้วนเชือกกั้นเลน","de":"หมุนมือจับวนไปวนมาเพื่อม้วนเก็บเชือกที่คลี่ยาวออกไป การเก็บกวาดสิ่งที่กระจัดกระจายไว้นั้นต้องอาศัยความอดทนเสมอ หนึ่งรอบ แล้วอีกหนึ่งรอบ การปิดท้ายสำเร็จลงอย่างช้าๆ โดยไม่เร่งรีบเช่นนี้เอง"},"ICON-2192":{"nm":"คีมหนีบปมปลายเชือกเลน","de":"คีมที่กัดแน่นเพื่อไม่ให้ปมที่ปลายเชือกคลายหลุด ไม่ปล่อยให้แม้แต่เศษปมเล็กน้อยหลุดลอยไป ต้องมีมือที่คอยควบคุมดูแลไปจนถึงที่สุด เชือกเส้นยาวจึงจะรักษารูปทรงอันเรียบร้อยไว้ได้โดยไม่ยุ่งเหยิง"},"ICON-2193":{"nm":"ลูกทุ่นเชือกกั้นเลน","de":"ลูกทุ่นของเชือกกั้นเลนที่ลอยตัวอยู่เหนือผืนน้ำ เพื่อไม่ให้จม มันจึงกักอากาศไว้เต็มที่ภายในตัวเอง ความเบาบางบางอย่างมาจากใจที่ว่างเปล่าซึ่งเติมเต็มด้วยความพยายาม คลื่นน้ำที่กระเพื่อมไหวแสดงให้เห็นเช่นนั้นทุกครั้งไป"},"ICON-2194":{"nm":"ธงหมายเลขเลน","de":"ธงเล็กๆ ที่บอกหมายเลขเลน ผ้าชิ้นเดียวที่พลิ้วไสวตามลมบอกอย่างชัดเจนว่า \"ตรงนี้คือที่ของเจ้า\" เป็นป้ายบอกทางเล็กๆ แต่ชัดเจนที่พาเข้าสู่เส้นทางของตัวเองได้ทันทีโดยไม่หลงทาง"},"ICON-2195":{"nm":"ตะขอเชื่อมเชือกกั้นเลน","de":"ตะขอที่เชื่อมเชือกกั้นเลนแต่ละเส้นเข้าด้วยกัน ด้วยตะขอเพียงตัวเดียวที่ต่อเส้นทางที่ขาดหายให้กลับมาเชื่อมกัน สายน้ำก็สมบูรณ์ในที่สุด การเชื่อมโยงท้ายที่สุดแล้วคืองานของชิ้นโลหะเล็กๆ ที่ยื่นมือเข้าไปอย่างเงียบๆ ระหว่างสิ่งที่แยกจากกัน"},"ICON-2196":{"nm":"แท่นเหยียบบล็อกออกตัว","de":"แท่นเหยียบบนเส้นออกตัวรองรับน้ำหนักของการกระโดดครั้งแรกไว้ทั้งหมด 0.1 วินาทีที่ถีบตัวออกไปอย่างสุดแรง ความมั่นคงที่ปลายเท้าเหยียบอยู่นั้นเองที่ผลักดันการเริ่มต้นของการแข่งขันทั้งหมด การทะยานทุกครั้งเริ่มต้นจากที่ที่เหยียบได้มั่นคงเสมอ"},"ICON-2197":{"nm":"ราวจับออกตัว","de":"ราวที่มือกำแน่นก่อนสัญญาณออกตัวเพียงเสี้ยววินาที ต้องยึดใจที่สั่นไหวไว้กับบางสิ่งเสียก่อน การออกตัวจึงจะไม่สั่นคลอน เพียงมีที่ให้จับ การเคลื่อนไหวครั้งต่อไปก็ชัดเจนและมั่นคงขึ้นมาก"},"ICON-2198":{"nm":"สายธงว่ายกรรเชียง","de":"สายธงที่บอกให้คนที่ว่ายหงายหน้ามองเพดานรู้ว่ากำแพงใกล้เข้ามาแล้ว เป็นความอ่อนโยนที่บอกล่วงหน้าในจุดที่มองไม่เห็น ด้วยสัญญาณเพียงหนึ่งเดียวที่คอยดูแลด้านหลังอย่างใส่ใจ จังหวะสุดท้ายจึงปลอดภัย"},"ICON-2199":{"nm":"เบาะกำแพงกลับตัว","de":"เบาะนุ่มที่บุติดไว้บนกำแพงที่ใช้เปลี่ยนทิศทาง เพื่อไม่ให้เจ็บแม้จะชนแรง มันหุ้มจุดที่ใช้กลับตัวไว้อย่างนุ่มนวล บนเส้นทางกลับมักมีความใส่ใจอันเงียบงันของใครสักคนปูรองไว้ล่วงหน้าเสมอ"},"ICON-2200":{"nm":"แผ่นสัมผัสเส้นชัย","de":"ในวินาทีที่ปลายนิ้วแตะถึง ทุกอย่างก็จบลง จุดสิ้นสุดของเส้นทางอันยาวไกลและหอบหายใจนั้น ท้ายที่สุดก็คือการแตะเบาๆ เพียงครั้งเดียวนี้เอง แผ่นตอบอย่างเงียบๆ ว่าการมาถึงไม่ใช่เรื่องยิ่งใหญ่อะไร แต่คือการแตะให้ตรงตำแหน่งที่แน่นอนต่างหาก"},"ICON-2201":{"nm":"แถบลื่นจุดเริ่มสไลด์","de":"ทุกคนที่ยืนอยู่ปลายทางลาดชันย่อมกลั้นหายใจสักครั้งเสมอ ผ่านความกลัวสั้นๆ นั้นไปแล้วไถลลงมา—พลั่ก—เสียงหัวเราะก็ดังพร้อมกับละอองน้ำที่กระเซ็น การเริ่มต้นเสมอเริ่มขึ้นที่อีกฟากหนึ่งของความกลัวเล็กๆ เพียงก้าวเดียว"},"ICON-2202":{"nm":"กรวยบอกระยะจุดเลี้ยว","de":"เมื่อลังเลอยู่ตรงทางแยก จุดเล็กๆ นี้จะเอ่ยขึ้นก่อนใคร มันบอกว่าให้เลี้ยวกลับตรงนี้นะ อย่าหลงทางเลย บางคนมองเห็นสีสันเพียงหนึ่งเดียวนี้แล้วพบทิศทางของตัวเองอีกครั้ง แล้วก็เดินต่อไป"},"ICON-2203":{"nm":"ลิ่มปรับมุมแท่นสตาร์ท","de":"จังหวะครึ่งบีตก่อนกระโดด ที่ร่างกายย่อตัวต่ำที่สุด มีที่ยันเล็กๆ อยู่ตรงนั้นคอยรองรับมุม ไม่ให้ปลายเท้าลื่นไถล ทุกช่วงเวลาแห่งการทะยานสูงล้วนถือกำเนิดจากความเอียงนี้"},"ICON-2204":{"nm":"ฝาครอบกันกระแทกมุมผนัง","de":"เพื่อไม่ให้เจ็บแม้จะชนขณะวิ่งเล่น มุมผนังจึงยอมสละความแหลมคมของตนให้มนกลม ความห่วงใยที่ไม่อยากให้ใครเจ็บนั้นถูกขัดแล้วขัดเล่าจนติดแน่นอยู่กับผนัง การปกป้องที่อ่อนโยนที่สุดมักจะเงียบงันเช่นนี้เสมอ"},"ICON-2205":{"nm":"ตะขอแขวนห่วงชูชีพ","de":"ยามปกติมันก็เป็นเพียงจุดที่มีของแขวนอยู่เฉยๆ แต่ในวินาทีที่ใครสักคนตกลงไปในน้ำ ที่นี่คือจุดแรกที่มือจะเอื้อมไปหา ในโลกนี้ยังมีความมั่นคงบางแบบที่ยิ่งไม่ได้ถูกใช้ยิ่งดี"},"ICON-2206":{"nm":"เสาตะขอกู้ภัย","de":"แขนยาวที่ย่นระยะทางที่เอื้อมไม่ถึงให้แคบลงได้ในพริบตา เมื่อมือสั้นเกินไป ตะขอนี้จะกลายเป็นมือแทน การช่วยชีวิตท้ายที่สุดแล้วคือการยื่นปลายนิ้วของตนไปให้ใครสักคนที่อยู่ไกลออกไป"},"ICON-2207":{"nm":"หัวฝักบัวข้างสระ","de":"\"ก่อนลงน้ำอย่าลืมล้างตัวก่อนนะ\" เหมือนประโยคติดปากของเจ้าหน้าที่ประจำเลน สายน้ำก็หลั่งรดลงมาเหนือศีรษะ เพียงแค่เย็นวาบครั้งเดียว ฝุ่นของทั้งวันก็ไหลหลุดร่วงไปจนหมด"},"ICON-2208":{"nm":"กระเบื้องพื้นกันลื่น","de":"ลวดลายนูนเล็กๆ ที่ทำให้เท้าเปล่าไม่ลื่นไถล จากมุมที่ไม่มีใครเห็น มันคอยประคองฝ่าเท้าไว้อย่างเงียบๆ ความปลอดภัยที่มั่นคงที่สุดมักซ่อนตัวอยู่ในที่ที่ไม่ฉูดฉาดเสมอ"},"ICON-2209":{"nm":"ป้ายบอกความลึกน้ำ","de":"ก่อนจะก้าวเท้าลงไป ตัวเลขจะบอกความลึกให้รู้ก่อน จุดที่หากไม่รู้แล้วเข้าไปจะน่ากลัว พออ่านครั้งเดียวใจก็กะระยะได้ สิ่งที่ป้ายนี้ทำคือช่วยเตรียมใจเพียงเล็กน้อยเท่านั้นเอง"},"ICON-2210":{"nm":"เชือกทุ่นเส้นความปลอดภัย","de":"เชือกหลากสีที่ลอยตัวอยู่บนผิวน้ำ แบ่งเขตพื้นที่ออกจากกัน ทุ่นเหล่านั้นจับมือกันสัญญาว่าแค่นี้ยังปลอดภัย เพราะมีเส้นแบ่งเขตอยู่ จึงว่ายน้ำได้อย่างสบายใจและเต็มที่ในที่สุด"},"ICON-2211":{"nm":"อ่างแช่เท้าฆ่าเชื้อ","de":"อ่างเล็กๆ ที่เท้าเปล่าแวะพักชั่วครู่ก่อนลงน้ำ พิธีกรรมสั้นๆ ที่ความสะอาดเริ่มต้นจากปลายเท้าถูกบรรจุอยู่ตรงนั้น ความสะอาดเสมอเริ่มต้นจากความใส่ใจในก้าวเล็กๆ เช่นนี้"},"ICON-2212":{"nm":"กรวยเตือนพื้นเปียก","de":"กรวยสีเหลืองใบเดียวค่อยๆ ทำให้ฝีเท้าช้าลง \"ตรงนี้เปียกนะ ระวังด้วย\" ความใส่ใจที่ส่งผ่านสีสันแทนคำพูด คำเตือนเล็กๆ นี้เงียบๆ คอยปกป้องวันของใครสักคนที่เกือบลื่นล้ม"},"ICON-2213":{"nm":"ตู้ปฐมพยาบาลติดผนัง","de":"ตู้สีขาวข้างผนังแทบไม่เคยถูกเปิดเลย แต่ในวินาทีที่มันถูกเปิดออกนั่นแหละ มันจะกลายเป็นความโล่งใจของใครสักคน สถานการณ์ฉุกเฉินมักรอคอยอยู่อย่างเงียบๆ ในจุดที่ใกล้ที่สุดเสมอ"},"ICON-2214":{"nm":"สวิงตักผิวน้ำ","de":"มันช้อนใบไม้และฝุ่นละอองที่ล่องลอยอยู่บนผิวน้ำขึ้นมาอย่างเงียบๆ ความใสสะอาดไม่ได้มาเองโดยธรรมชาติ จึงต้องมีมือใครสักคนคอยช้อนขึ้นวันละครั้ง เบื้องหลังน้ำนิ่งสงบมีสวิงที่ขยันขันแข็งอยู่เสมอ"},"ICON-2215":{"nm":"ท่อหุ่นยนต์ทำความสะอาดพื้น","de":"แม้ในคืนที่ทุกคนหลับใหล มันก็ยังคลำไปตามพื้นอย่างช้าๆ คนงานที่ขยันที่สุดในยามที่ไม่มีใครมองเห็น ความใสสะอาดยามเช้าคือรอยทางที่ท่อนี้วาดไว้ตลอดทั้งคืน"},"ICON-2216":{"nm":"ถังจ่ายคลอรีน","de":"แม้แต่การรักษาน้ำให้ใสสะอาดก็ยังมีปริมาณที่พอดีของมัน มากไปก็รุนแรง น้อยไปก็ขุ่นมัว สมดุลอยู่ระหว่างนั้น มือที่มองไม่เห็นคอยปรับขีดวัดนั้นอย่างเงียบๆ ทุกวัน"},"ICON-2217":{"nm":"ขวดตรวจคุณภาพน้ำ","de":"ตักน้ำเพียงอึกเดียวใส่ขวดเล็กๆ เพื่อถามไถ่ความเป็นไปของวันนี้ แม้ตาจะมองเห็นเหมือนเดิม แต่ตัวเลขไม่เคยโกหก ความอุ่นใจคือสิ่งที่ถูกยืนยันวันละครั้งเช่นนี้เอง"},"ICON-2218":{"nm":"คราดช้อนแผ่นลอยน้ำ","de":"คราดด้ามยาวที่รวบรวมแผ่นไม้และเศษลอยน้ำที่ล่องลอยอยู่บนผิวน้ำเข้าด้วยกัน มือที่คราดสิ่งกระจัดกระจายกลับมารวมกันนั้นช่างละม้ายคล้ายหัวใจ แม้ความยุ่งเหยิงก็จะเรียบร้อยขึ้นเมื่อกวาดสักครั้ง"},"ICON-2219":{"nm":"ตะแกรงฝาท่อระบายน้ำ","de":"ตะแกรงถี่ที่เฝ้าทางผ่านที่น้ำไหลออกไป มันคัดแยกอย่างเงียบๆ ว่าอะไรควรปล่อยไปและอะไรควรเก็บไว้ แม้แต่การปล่อยให้สิ่งใดจากไปก็ยังต้องมีตัวกรอง ตะแกรงเล็กๆ นี้บอกไว้โดยไม่พูดอะไรสักคำ"},"ICON-2220":{"nm":"ทุ่นวัดอุณหภูมิน้ำ","de":"หน่วยลาดตระเวนตัวน้อยที่ลอยอยู่บนผิวน้ำคอยอ่านอุณหภูมิ ไม่ว่าจะเย็นหรือพอดี มันบอกให้รู้ก่อนที่ร่างกายจะสัมผัส ความอุ่นใจแรกของการลงน้ำเสมอเริ่มต้นจากทุ่นนี้"},"ICON-2221":{"nm":"แกนม้วนผ้าคลุมสระ","de":"ด้ามจับที่ม้วนผ้าคลุมผืนกว้างเก็บไว้ข้างหนึ่ง เครื่องมือที่รู้ว่าเมื่อไหร่ควรคลี่ออกและเมื่อไหร่ควรเก็บเข้านั้นช่างน่าเชื่อถือ ยามพักผ่อนก็เหมือนกับห่มผ้านวมผืนหนึ่งให้แก่ผืนน้ำเช่นกัน"},"ICON-2222":{"nm":"ตะกร้ากรองสกิมเมอร์","de":"ตะกร้าที่เศษลอยน้ำบนผิวน้ำมารวมตัวกันเป็นจุดสุดท้าย เพราะมีภาชนะที่คอยรับตะกอนไว้ในมุมที่มองไม่เห็น น้ำด้านบนจึงใสสะอาดอยู่เสมอ เบื้องหลังความสะอาดคือความเหนื่อยยากที่สั่งสมอยู่"},"ICON-2223":{"nm":"ราวตากหมวกว่ายน้ำ","de":"แขวนหมวกว่ายน้ำที่ชุ่มน้ำไว้กลับหัวลง ขณะที่หยดน้ำหยดลงทีละหยด หมวกก็ค่อยๆ ปรับลมหายใจของตัวเองอย่างช้าๆ การแห้งท้ายที่สุดแล้วก็คืออีกชื่อหนึ่งของการรอคอย"},"ICON-2224":{"nm":"ห่วงยึดสายเดี่ยวชุดว่ายน้ำ","de":"ห่วงเล็กๆ ที่จับสายไว้ไม่ให้ไหลหลุดจากไหล่ จากมุมที่มองไม่เห็น มันคอยดูแลความเรียบร้อยของทรวดทรงอย่างเงียบๆ ความเรียบร้อยเสมอสำเร็จลุล่วงบนจุดค้ำยันเล็กๆ เช่นนี้"},"ICON-2225":{"nm":"ถุงจัดเก็บหมวกว่ายน้ำ","de":"ถุงที่หมวกว่ายน้ำเปียกๆ ค่อยๆ หาที่ของตัวเองทีละใบ ที่พักพิงเล็กๆ ที่โอบกอดสิ่งที่กระจัดกระจายง่ายไว้ในอ้อมกอดเดียว การจัดระเบียบคือนิสัยอันอ่อนโยนของการพยายามไม่ทำสิ่งใดสูญหาย"},"ICON-2226":{"nm":"แผ่นเสริมอกชุดว่ายน้ำ","de":"แผ่นเดียวที่แอบซ่อนอยู่ด้านในเสื้อผ้าอย่างเงียบๆ แม้จากภายนอกจะมองไม่เห็น แต่มันช่วยยืดไหล่ของผู้สวมใส่ให้ตรงขึ้นอย่างแผ่วเบา ความมั่นใจบางอย่างถูกเติมเต็มอย่างเงียบงันจากภายใน ไม่ใช่จากภายนอก"},"ICON-2227":{"nm":"คลิปติดป้ายชื่อหมวกว่ายน้ำ","de":"คลิปเล็กๆ ที่หนีบป้ายชื่อไว้ที่ขอบหมวกว่ายน้ำ ท่ามกลางสิ่งของหน้าตาเหมือนกัน มันบอกอย่างชัดเจนว่า \"นี่คือของฉัน\" เพียงเครื่องหมายเดียวความสับสนก็จบลงในทันที"},"ICON-2228":{"nm":"ห่วงดึงซิปชุดว่ายน้ำ","de":"\"ช่วยรูดซิปหลังให้หน่อยได้ไหม\" ตำแหน่งที่มือเดียวไม่อาจเอื้อมถึง ห่วงเล็กๆ นี้ดึงขึ้นแทนมือให้ ระยะเอื้อมอันอ่อนโยนที่ช่วยเหลือในช่องสุดท้าย"},"ICON-2229":{"nm":"แผ่นกันหมวกว่ายน้ำม้วนงอ","de":"ยืดหมวกว่ายน้ำที่ม้วนงอจนติดเป็นนิสัยให้ตรงแล้ววางพิง แท่นรองที่ช่วยให้สิ่งที่บิดเบี้ยวกลับคืนสู่รูปทรงเดิมอย่างเงียบๆ ต้องมีมือที่คอยยืดให้ตรง สิ่งใดสิ่งหนึ่งจึงจะกลับมาเรียบร้อยได้อีกครั้ง"},"ICON-2230":{"nm":"ตัวรัดเชือกเอวชุดว่ายน้ำ","de":"ตัวรัดที่โอบรอบเอวพอดีไม่ให้หลุดลื่นลงมา ไม่แน่นเกินไปและไม่หลวมเกินไป พอดีเพียงเท่านั้น ความสบายเสมออาศัยอยู่ตรงกลางระหว่างนั้น"},"ICON-2231":{"nm":"คีมพลิกกลับหมวกว่ายน้ำ","de":"คีมที่จับหมวกว่ายน้ำที่กลับด้านในนอกให้ถูกต้องได้ในทีเดียว สัมผัสมือที่พลิกสิ่งที่กลับด้านให้ถูกทางนั้นให้ความรู้สึกโล่งใจไม่น้อย ความสุขเล็กๆ ของการจัดระเบียบมาจากเรื่องเล็กน้อยเช่นนี้เอง"},"ICON-2232":{"nm":"สายจับแป้นเตะ","de":"สายที่พันรอบมือไม่ให้ทำแป้นเตะหลุดหาย แม้ถูกกระแสน้ำผลักไสก็ยังมีที่ให้จับ นั่นคือความอุ่นใจอันยิ่งใหญ่ ความสั่นไหวของวันแรกที่หัดเตะขาน้ำยังคงหลงเหลืออยู่ในสายเส้นนี้"},"ICON-2233":{"nm":"สายรัดทุ่นหนีบขา","de":"สายที่รัดทุ่นซึ่งหนีบไว้ระหว่างขาทั้งสองให้แน่นหนา ต้องไม่หลุดคลายเท่านั้นจึงจะมุ่งความสนใจไปที่ท่าทางได้อย่างเต็มที่ บนสิ่งที่ยึดไว้อย่างมั่นคง การฝึกซ้อมของวันนั้นจึงลึกซึ้งขึ้นทีละคืบ"},"ICON-2234":{"nm":"ราวแขวนตีนกบ","de":"เมื่อตีนกบแขวนเรียงกันอยู่บนผนัง มันช่างดูเหมือนฝูงเป็ดที่พักผ่อนอยู่ริมน้ำ เท้าที่ว่ายน้ำเสร็จแล้วสะบัดหยดน้ำเบาๆ รอคอยวันพรุ่งนี้ แม้แต่ช่วงพักก็ยังดูกลมมนและน่ารักอยู่ตรงไหนสักแห่ง"},"ICON-2235":{"nm":"ฝาครอบมุมแป้นเตะ","de":"ฝาครอบเล็กๆ ใบหนึ่งที่สวมไว้ที่มุมแป้นเตะ เพื่อไม่ให้เจ็บเมื่อกระแทกและไม่ให้เสียหายเมื่อสึกกร่อน มันห่อหุ้มปลายมุมไว้ เคล็ดลับของการเก็บสิ่งใดไว้ข้างกายนานๆ อยู่ที่การถนอมตั้งแต่มุมนั้นเอง"},"ICON-2236":{"nm":"ตาข่ายเก็บตีนกบ","de":"ตีนกบที่มีรูปร่างคล้ายพังผืดเท้าเป็ดผึ่งแดดอยู่ในตาข่าย เหมือนฝูงเป็ดที่เพิ่งขึ้นจากน้ำผึ่งขนให้แห้ง มันก็ค่อยๆ แห้งอยู่ในตาข่ายอย่างช้าๆ เป็นการงีบหลับอย่างสบายใจก่อนการว่ายน้ำครั้งต่อไป"},"ICON-2237":{"nm":"ป้ายจัดระเบียบทุ่นหนีบขา","de":"ติดป้ายชื่อไว้บนทุ่นแต่ละอันเพื่อบอกเจ้าของให้ชัดเจน ยิ่งเป็นที่ที่หลายคนใช้ร่วมกัน ยิ่งต้องชัดเจนว่า \"ของใคร\" ใจจึงจะสบาย ป้ายเล็กๆ เพียงแผ่นเดียวสร้างระเบียบขึ้นมาได้"},"ICON-2238":{"nm":"ที่วางระบายน้ำแป้นเตะ","de":"ที่วางเอียงให้น้ำที่ขังอยู่ในแป้นเตะไหลรินลงมา ต้องปล่อยสิ่งที่ซึมซับไว้ให้ว่างเปล่าจึงจะเบาขึ้น ที่วางนี้บอกไว้อย่างเงียบๆ ก้าวแรกของการทำให้แห้งคือการวางพิงให้ดี"},"ICON-2239":{"nm":"ตัวรัดสายตีนกบ","de":"ชิ้นส่วนเล็กๆ ที่รัดสายตีนกบให้พอดีกับเท้า หลวมไปก็หลุด แน่นไปก็เจ็บ ช่องว่างละเอียดอ่อนนั้นเอง เพื่อจะแหวกว่ายไปข้างหน้าอย่างเบาสบายดั่งเป็ดที่มีพังผืดเท้า จำเป็นต้องมีจุดพอดีเพียงหนึ่งเดียวนี้"},"ICON-2240":{"nm":"ชิปจับจังหวะการเตะขา","de":"ชิปเล็กๆ ที่บอกจังหวะทุกครั้งที่เตะขา หนึ่ง สอง สาม—เมื่อจังหวะซึมซับเข้าสู่ร่างกาย น้ำก็กลายเป็นบทเพลงโดยไม่ทันรู้ตัว ชิปนี้สอนอย่างแผ่วเบาว่าแม้แต่การว่ายน้ำก็มีจังหวะเช่นกัน"},"ICON-2241":{"nm":"ถุงใส่ชุดว่ายน้ำเปียก","de":"ในกระเป๋าที่ออกจากสระว่ายน้ำ คนที่จองที่ก่อนใครเสมอคือฉันเอง แม้ของอื่นจะทำหน้าบูดใส่ก็ช่วยไม่ได้ ของเปียกต้องแยกเก็บต่างหาก ทุกอย่างจึงจะแห้งสบายพร้อมกันได้ ห้องกักกันของความชื้น นั่นคือหน้าที่อันอ่อนโยนที่ฉันรับผิดชอบ"},"ICON-2242":{"nm":"แผ่นบีบน้ำ","de":"ความชื้นมีนิสัยหลบหนีไปเงียบๆ ทันทีที่ถูกกด บีบครั้งหนึ่ง สองครั้ง—ต้องวางลงบนแผ่นและถ่ายน้ำหนักลงไปเท่านั้นมันจึงจะยอมแพ้ สำหรับคนที่ไม่เคยได้ใช้แรงข้อมือ นี่คือเวทีที่หาได้ยาก"},"ICON-2243":{"nm":"แผ่นกั้นกระเป๋าว่ายน้ำ","de":"ใส่รวมกันในถุงเดียวของเปียกกับของแห้งก็จะเปื้อนกัน หน้าที่ของการแทรกเข้าไปตรงกลางแล้วขีดเส้นแบ่งอย่างเงียบๆ หากแผ่นกั้นเพียงแผ่นเดียวนำความสงบมาได้ การประนีประนอมก็อาจเป็นเรื่องง่ายอย่างไม่น่าเชื่อก็ได้"},"ICON-2244":{"nm":"ถุงกันน้ำใส่รองเท้า","de":"มันกลืนรองเท้าที่เปื้อนทรายเข้าไปทั้งคู่โดยไม่เปลี่ยนสีหน้าแม้แต่น้อย ไม่ว่าข้างในจะเกิดอะไรขึ้น ข้างนอกยังคงแห้งสนิท นั่นคือมารยาทที่การกันน้ำรักษาไว้ ถุงที่ปากหนักย่อมเป็นที่ต้อนรับได้ทุกแห่ง"},"ICON-2245":{"nm":"ฝาระบายน้ำกระเป๋าว่ายน้ำ","de":"บิดฝาแล้ววันที่ขังอยู่ก้นกระเป๋าก็ไหลออกไปจนหมด การเก็บกวาดหลังจากเล่นสนุกจนเต็มที่เสมอขึ้นอยู่กับรูเล็กๆ รูนี้เพียงรูเดียว แม้แต่การรู้จักปล่อยให้สิ่งใดไหลไปก็ยังต้องมีการออกแบบ"},"ICON-2246":{"nm":"พรมซับน้ำหน้าประตู","de":"มันนอนราบเงียบๆ อยู่หน้าประตู รับความชื้นจากทุกฝ่าเท้าที่เดินเข้ามา แม้ไม่มีใครรับรู้ แต่พื้นไม้รู้ดี—วันนี้ก็ไม่มีใครลื่นล้มเช่นกัน ในที่เงียบงันมีคุณค่าอันเงียบงันสถิตอยู่"},"ICON-2247":{"nm":"จานรองหมวกว่ายน้ำเปียก","de":"เมื่อหมวกว่ายน้ำที่ถูกถอดโยนทิ้งไม่มีที่ไป ฉันจะรองรับมันไว้ แม้ถูกเรียกว่าจาน แต่กลับต้องรองรับหยดน้ำแทนอาหาร ทว่าหากเป็นงานที่จัดหาที่ทางให้ใครสักคน แม้แต่แท่นรองก็ยังยืดอกได้อย่างภาคภูมิ"},"ICON-2248":{"nm":"คลิปหนีบตากผ้าเช็ดตัว","de":"หน้าที่ของการกัดผ้าเช็ดตัวหนึ่งผืนไว้แน่นบนราวตากผ้า ไม่ว่าลมจะแกล้งยั่วยุแค่ไหน ความดื้อรั้นที่ไม่ยอมปล่อยคือความภาคภูมิใจของฉัน จนกว่าจะแห้งสนิทเบาสบายภายใต้แสงแดด มือที่จับไว้ครั้งหนึ่งจะไม่มีวันปล่อยก่อน"},"ICON-2249":{"nm":"ตะขอแขวนกระเป๋ากันน้ำ","de":"วินาทีที่แขวนบนตะขอ กระเป๋าที่เคยล่องลอยไร้จุดหมายก็ได้ที่อยู่ในที่สุด แม้จะเป็นเพียงการห้อยอยู่โดยขอยืมผนังสักช่องหนึ่ง แต่ยังมีอะไรที่มั่นคงไปกว่าที่ที่ไม่ต้องกังวลว่าจะสูญหายอีกหรือ"},"ICON-2250":{"nm":"สายรัดข้อมือเข้าคิวสไลด์","de":"ความตื่นเต้นที่รอคอยคิวอย่างเงียบๆ ถูกผูกไว้อย่างครบถ้วนในสายรัดเล็กๆ เส้นนี้ ต่อเมื่อถูกรัดที่ข้อมือแล้วเท่านั้น แถวรอสไลด์จึงจะเริ่มเคลื่อนไหว การเข้าคิวอาจเป็นเพียงการผูกคำสัญญาไว้รอบข้อมือก็ได้"},"ICON-2251":{"nm":"เศษแผ่นพื้นสไลด์น้ำ","de":"ผู้คนวิ่งเล่นสนุกสนานโดยไม่รู้ตัวว่ามันแตกอยู่ใต้ฝ่าเท้า ที่ปูไว้เพื่อไม่ให้ใครลื่น การมีอยู่ของมันจะปรากฏชัดก็ต่อเมื่อชิ้นส่วนนั้นหายไปเท่านั้น สิ่งของในโลกนี้มีอยู่ไม่น้อยที่ถูกจดจำได้ก็เพียงเพราะที่ว่างที่มันทิ้งไว้"},"ICON-2252":{"nm":"สายรัดกันน้ำกุญแจล็อกเกอร์","de":"การปกป้องกุญแจล็อกเกอร์จากน้ำคืองานตลอดชีวิตของฉัน แม้จะพันรอบข้อมือและกระเซ็นเล่นน้ำไปด้วยกัน แต่กุญแจดวงเดียวนั้นฉันรักษาให้แห้งสนิทเสมอ หากทำหายก็หาเสื้อผ้าไม่เจอด้วย เพียงเท่านี้ก็นับว่าเป็นผู้รับผิดชอบที่หนักหนาแล้ว"},"ICON-2253":{"nm":"ป้ายไฟสัญญาณปล่อยตัวสไลด์","de":"วินาทีสั้นๆ ที่ไฟแดงเปลี่ยนเป็นไฟเขียว หัวใจของทุกคนบนสไลด์ก็เต้นแรงพร้อมกัน อำนาจในการอนุญาตให้ออกตัว—ใครจะคิดว่าป้ายสัญญาณเล็กๆ นี้จะบรรจุความตื่นเต้นไว้ได้มากมายเพียงนี้"},"ICON-2254":{"nm":"หัวเข็มขัดเสื้อชูชีพสระน้ำวน","de":"หัวเข็มขัดที่ยึดร่างที่ล่องลอยไปตามสระน้ำวนไว้อย่างแน่นหนา ต้องได้ยินเสียงคลิกนั้นก่อน จึงจะปล่อยใจไปตามกระแสน้ำได้อย่างสบาย ความอุ่นใจบางครั้งเริ่มต้นจากตัวล็อกเล็กๆ เช่นนี้เอง"},"ICON-2255":{"nm":"ธงบอกสัญญาณสระคลื่น","de":"มันบอกล่วงหน้าให้ทุกคนรู้ว่าคลื่นกำลังจะมาถึง ธงขึ้นคือเสียงเชียร์ ธงลงคือช่วงเวลาพักหายใจสักครู่ แปลกดีที่สิ่งที่คุมจังหวะอยู่ริมสระที่คลื่นซัดไปมากลับเป็นผ้าเพียงชิ้นเดียว"},"ICON-2256":{"nm":"สร้อยคอเบอร์คิวสไลด์","de":"แขวนไว้รอบคอว่าตนเองอยู่แถวลำดับที่เท่าไหร่ก็ไม่มีวันสับสน ทัศนียภาพที่ป้ายเบอร์เพียงแผ่นเดียวกำหนดลำดับก่อนหลัง—ระเบียบมักเริ่มต้นจากสร้อยคอเล็กๆ เช่นนี้เสมอ"},"ICON-2257":{"nm":"เหรียญเติมเงินสายรัดข้อมือ","de":"แตะเบาๆ ที่สายรัดข้อมือ การเติมเงินก็เสร็จสิ้น ยุคที่ท่องไปในสายน้ำโดยไม่ต้องพกเงินสดหรือบัตร โทเคนเล็กๆ นี้ทำหน้าที่แทนกระเป๋าเงินทั้งใบ ข้อมือที่เบาขึ้นเท่าไหร่ ใจก็เบาสบายขึ้นเท่านั้น"},"ICON-2258":{"nm":"ฝาครอบด้ามจับปืนฉีดน้ำ","de":"ด้ามจับปืนฉีดน้ำที่ต้องกำแน่นจึงจะได้อรรถรส หากฝาครอบหลุดไปแม้แต่ชิ้นเดียว ไม่ต้องพูดถึงการเล็งเลย มันหมุนติ้วอยู่ในมือ ผลแพ้ชนะของสงครามน้ำกลางฤดูร้อนขึ้นอยู่กับชิ้นส่วนปิดท้ายเล็กๆ ชิ้นนี้เพียงชิ้นเดียว"},"ICON-2259":{"nm":"ถ้วยพิมพ์หอคอยปราสาททราย","de":"อัดทรายเปียกลงไปแน่นแล้วคว่ำกลับ หอคอยเล็กๆ หนึ่งหลังก็ผุดขึ้นมา ไม่มีใครเข้าใจหัวใจที่ยังคงก่อสร้างต่อไปแม้รู้ว่ามันจะพังทลายได้ดีไปกว่าฉันแล้ว สำหรับสถาปนิกแห่งเม็ดทราย พิมพ์คือพิมพ์เขียวนั่นเอง"},"ICON-2260":{"nm":"ซี่คราดหวีทราย","de":"ลากผ่านราวกับหวีทราย ก็เหลือร่องรอยเป็นแนวเรียบเสมอ แม้รู้ว่าคลื่นจะลบลวดลายนี้ในไม่ช้า ซี่คราดก็ยังขยันขันแข็งขีดเส้นสายของมันต่อไป การสร้างสิ่งที่จะสูญสลายไปอย่างตั้งใจก็มีเสน่ห์ในแบบของมันเอง"},"ICON-2261":{"nm":"ตุ้มถ่วงเสาร่มชายหาด","de":"มันยืนนิ่งอยู่ที่โคนเสาอย่างเงียบๆ เพื่อไม่ให้ร่มปลิวไปกับลม การรักษาร่มเงาไว้ไม่ใช่หน้าที่ของผ้าที่ฉูดฉาด แต่เป็นหน้าที่ของตุ้มถ่วงที่ปักลงหนักแน่น น้ำหนักที่มองไม่เห็นคือสิ่งที่ไว้ใจได้มากที่สุดเสมอ"},"ICON-2262":{"nm":"ด้ามจับตะแกรงร่อนทราย","de":"เขย่าร่อนทรายแล้วก็เหลือเพียงเปลือกหอยและสมบัติเล็กๆ อยู่ในมือ จับด้ามแล้วเขย่าเบาๆ ครึ่งหนึ่งของการล่าสมบัติชายหาดตัดสินกันด้วยตะแกรงชิ้นเดียวนี้"},"ICON-2263":{"nm":"พิมพ์ทรายรูปหอย","de":"อัดทรายเปียกลงไปแล้วเคาะเบาๆ หอยขนาดเท่าฝ่ามือก็ผุดขึ้นเรียงรายบนชายหาด แม้จะกินหอยจริงไม่ได้ แต่รูปทรงนี้ใครก็สร้างได้ เวทมนตร์เรียบง่ายแห่งฤดูร้อน"},"ICON-2264":{"nm":"หมุดปรับมุมร่มชายหาด","de":"ทุกครั้งที่ดวงอาทิตย์เคลื่อนย้าย ร่มก็ต้องหันหน้าตามไปด้วย ดึงหมุดออกแล้วเสียบใหม่ ร่มเงาก็ย้ายที่ไปอย่างเงียบๆ หัวใจของเทคนิคหลบแสงแดดอยู่ที่มุมเล็กๆ นี้เอง"},"ICON-2265":{"nm":"ฝาครอบปลายพลั่วตักทราย","de":"สวมไว้ที่ปลายใบพลั่วอันแหลมคม ในกระเป๋าก็ปลอดภัย พักความห้าวหาญของการขุดทรายไว้ชั่วคราว เพียงฝาครอบชิ้นเดียวมันก็กลายเป็นของเล่นที่อ่อนโยน การรู้จักซ่อนความคมของตัวเองก็เป็นความใส่ใจอย่างหนึ่งเช่นกัน"},"ICON-2266":{"nm":"คลิปหนีบมุมเสื่อชายหาด","de":"เมื่อลมพยายามยกมุมเสื่อขึ้น ฉันจะกัดมันไว้แน่น การรักษาพื้นที่หนึ่งจุดบนผืนทรายท้ายที่สุดขึ้นอยู่กับความดื้อรั้นของมุมทั้งสี่ ช่วงบ่ายที่ไม่มีการปลิวไสวคือผลงานของคลิปเล็กๆ เหล่านี้"},"ICON-2267":{"nm":"ตะขอแขวนเสื้อผ้าใต้ร่มชายหาด","de":"แขวนไว้ที่เสาร่มเบาๆ เสื้อผ้าเปียกก็แห้งอยู่ในร่มเงา หลบแดดรับลม ราวตากผ้าชั่วคราวที่จัดขึ้นด้วยตะขอเพียงอันเดียว แม้แต่ที่ชายหาดก็ยังมีภูมิปัญญาของการดูแลบ้านสถิตอยู่"},"ICON-2268":{"nm":"ถุงคล้องคอกันน้ำใส่โทรศัพท์","de":"โอบโทรศัพท์ไว้แล้วคล้องคอ ก็เกิดความกล้าที่จะถ่ายรูปได้แม้อยู่ใต้น้ำ การปกป้องความปรารถนาที่อยากเก็บภาพไว้อีกสักภาพให้ปลอดภัยและแห้งสนิท ในฐานะบอดี้การ์ดแห่งความทรงจำ มันทำหน้าที่ได้อย่างเข้มแข็งทีเดียว"},"ICON-2269":{"nm":"ถุงกันน้ำใส่เสื้อผ้าเปียก","de":"มันรับเสื้อผ้าเปียกที่เปลี่ยนแล้วไว้ทั้งชุดโดยไม่บ่นสักคำ ความภาคภูมิใจของมันคือไม่ให้น้ำแม้แต่หยดเดียวเปื้อนสัมภาระชิ้นอื่น จึงปิดปากแน่นสนิทเฝ้ามุมหนึ่งของกระเป๋าไว้ตลอด การจบงานอย่างเรียบร้อยเริ่มต้นจากฉันเอง"},"ICON-2270":{"nm":"สายรัดหลังเท้ารองเท้าแตะเล่นน้ำ","de":"มันโอบหลังเท้าไว้เบาๆ เพื่อไม่ให้รองเท้าแตะเท้าเปล่าหลุดออก แม้จะวิ่งเล่นบนผืนทรายทั้งวันก็อุ่นใจได้ด้วยสายเพียงเส้นเดียว เพื่อนร่วมทางที่มั่นคงของทุกย่างก้าว แม้ไม่เด่นแต่อยู่เคียงข้างเสมอ"},"ICON-2271":{"nm":"ซองคล้องคอกันน้ำใส่บัตร","de":"โอบบัตรผ่านและบัตรต่างๆ ไว้แล้วคล้องคอร่วมเล่นน้ำไปด้วยกัน เชิญกระโดดเล่นน้ำได้อย่างเต็มที่โดยไม่ต้องกลัวว่าจะทำหาย เพราะมันใช้ร่างกายตัวเองเป็นโล่ปกป้องบัตรไว้ นี่คือท่าทีของบอดี้การ์ดที่ไว้ใจได้"},"ICON-2272":{"nm":"ถุงผ้าเช็ดกันฝ้าแว่นตาว่ายน้ำ","de":"เช็ดด้านในแว่นตาว่ายน้ำที่ขุ่นมัวด้วยผ้าเพียงครั้งเดียว โลกใต้น้ำก็คมชัดขึ้นอีกครั้ง ถุงผ้าเล็กๆ ใบเดียวจึงเป็นกุญแจที่เปิดทัศนวิสัยอันขุ่นมัวให้กระจ่างใส"},"ICON-2273":{"nm":"แปรงปัดทรายเปียก","de":"มันปัดทรายแม้กระทั่งระหว่างซอกนิ้วเท้าออกอย่างนุ่มนวล มือสุดท้ายที่จัดการรอยเปื้อนจากการวิ่งเล่นในทะเลอย่างสนุกสนาน ทันทีที่ก้าวถึงหน้าบ้าน แปรงปัดผ่านไปเพียงครั้งเดียว ทรายของทั้งวันก็อำลาไปในที่สุด"},"ICON-2274":{"nm":"ถุงซิปกันน้ำใส่เหรียญ","de":"มันขังเหรียญไม่กี่เหรียญไว้แน่นหลังซิป ไม่ว่าจะเปียกหรือไม่ เสียงกรุ๊งกริ๊งก็ยังคงเดิม เงินสำรองฉุกเฉินสำหรับซื้อของที่ร้านค้าจึงถูกปกป้องไว้จนถึงที่สุด ถุงเล็กๆ แต่จัดการเรื่องเงินได้อย่างเก่งกาจ"},"ICON-2275":{"nm":"สายมัดม้วนผ้าเช็ดตัวเล่นน้ำ","de":"ม้วนผ้าเช็ดตัวแล้วมัดด้วยสายเพียงเส้นเดียว มันก็ห้อยติดกับสายกระเป๋าได้ทันที มือทั้งสองข้างว่าง ผ้าเช็ดตัวอยู่บนไหล่ เคล็ดลับของการเล่นน้ำแบบพกของน้อยแอบซ่อนอยู่ในมัดเล็กๆ นี้เอง"},"ICON-2276":{"nm":"ฝาปิดพวงกุญแจสายรัดกันน้ำ","de":"กระดุมปิดท้ายของสายรัดที่ปกป้องกุญแจจากน้ำ ต้องได้ยินเสียงคลิกปิดของฝาครอบก่อน จึงจะกระโดดลงสระได้อย่างสบายใจ จุดสุดท้ายเล็กๆ ที่รับผิดชอบการปิดล็อก เล็กแต่ไม่มีช่องโหว่แม้แต่นิดเดียว"},"ICON-2277":{"nm":"ปากกัดท่อหายใจดำน้ำตื้น","de":"กัดไว้ในปากแล้วทางเดินหายใจก็เปิดออก ทัศนียภาพใต้ทะเลก็เข้ามาใกล้แค่เอื้อม ปลั๊กเล็กๆ ที่ทำให้หายใจได้แม้อยู่ใต้น้ำ ใครจะคิดว่าการยืมลมหายใจจะสนุกได้ถึงเพียงนี้"},"ICON-2278":{"nm":"แผ่นกันฝ้าหน้ากากดำน้ำ","de":"เมื่อด้านในหน้ากากขุ่นมัว การชมวิวใต้น้ำก็หมดสนุกไปด้วย แผ่นเดียวช่วยกั้นความขุ่นมัวนั้นไว้ ทัศนวิสัยที่คมชัดจึงเป็นผลงานของชั้นบางๆ ที่มองไม่เห็นนี้เอง"},"ICON-2279":{"nm":"คลิปรัดปลายตีนกบ","de":"มันรัดปลายตีนกบให้พอดีกับเท้า เตะน้ำได้โดยไม่มีความหลวมเหลือ เพื่อไม่ให้แรงจากการเตะแต่ละครั้งรั่วไหลไป คลิปนี้ผูกปมเล็กๆ ที่แน่นหนาไว้ที่ปลายเท้าอย่างเงียบๆ"},"ICON-2280":{"nm":"ปลอกหุ้มสายรัดหน้ากากดำน้ำ","de":"มันโอบสายรัดหน้ากากไว้อย่างนุ่มนวลไม่ให้ดึงเส้นผม ชั้นแห่งความใส่ใจหนึ่งชั้นที่ลบเลือนความเจ็บแปลบทุกครั้งที่ถอดออก สิ่งที่ปลอกเล็กๆ นี้ดูแลกลับกลายเป็นความอ่อนโยนอย่างไม่น่าเชื่อ"},"ICON-2281":{"nm":"ฝาวาล์วระบายน้ำท่อหายใจดำน้ำตื้น","de":"แม้ในการกลั้นลมหายใจก็ยังมีช่องว่างที่น้ำแอบรั่วไหลเข้ามาอย่างเงียบๆ วาล์วเล็กๆ หนึ่งตัวคอยผันน้ำหยดนั้นให้ไหลกลับออกไปเบาๆ และปกป้องพื้นที่สำหรับหายใจเข้าจนถึงวินาทีสุดท้าย ทะเลจดจำความใส่ใจเล็กๆ นี้ด้วยความขอบคุณมากที่สุด"},"ICON-2282":{"nm":"ตะขอแขวนเก็บตีนกบ","de":"เมื่อตีนกบแขวนเรียงเป็นระเบียบอยู่บนตะขอที่ตอกไว้กับผนัง แม้แต่ห้องเก็บอุปกรณ์ที่เคยรกรุงรังก็มีความสงบเข้ามาปกคลุมใจ การวางไว้ในที่ของมันคือคำสัญญาอันเงียบที่สุดต่อการดำน้ำครั้งต่อไป"},"ICON-2283":{"nm":"แผ่นหนีบจมูกหน้ากากดำน้ำ","de":"แผ่นเดียวที่กดจมูกไว้เบาๆ ด้วยความอ่อนโยนเล็กๆ ที่คอยกั้นไม่ให้น้ำไหลเข้ามานี้เอง ใบหน้าจึงไม่สูญเสียสีหน้าของตัวเองแม้อยู่ในทะเลอันหนาวเย็น"},"ICON-2284":{"nm":"การ์ดปลายบนท่อหายใจดำน้ำตื้น","de":"การ์ดที่โอบปลายท่อหายใจไว้เป็นวงกลม คอยผลักน้ำออกอย่างเงียบๆ เมื่อคลื่นซัดผ่านเข้ามา ยิ่งเป็นชิ้นส่วนที่ทำงานอย่างไม่มีใครเห็น ยิ่งค้ำจุนความปลอดภัยของลมหายใจหนึ่งครั้งได้ลึกซึ้งที่สุด"},"ICON-2285":{"nm":"แถบกันลื่นพื้นตีนกบ","de":"แถบบางที่ติดอยู่ที่พื้นตีนกบ คือเส้นแรงเสียดทานเพียงเส้นเดียวที่ปลายเท้ายึดเกาะไว้ไม่ให้ลื่นบนดาดฟ้าเปียก ความปลอดภัยเสมอเริ่มต้นอย่างเงียบๆ จากพื้นผิวเล็กๆ เช่นนี้"},"ICON-2286":{"nm":"ฝาครอบวาล์วถังออกซิเจน","de":"หมวกที่ปิดวาล์วของถังที่บรรจุอากาศไว้เต็มเปี่ยม เพื่อไม่ให้ฝุ่นเกาะ เพื่อไม่ให้ทางเดินลมหายใจแปดเปื้อน การปิดไว้คือการดูแลล่วงหน้า ไปจนถึงลมหายใจแรกของคนต่อไปด้วย"},"ICON-2287":{"nm":"ฝาครอบปากกัดเครื่องช่วยหายใจ","de":"จุดที่สัมผัสริมฝีปากต้องสะอาดที่สุดเสมอ ฝาครอบเพียงชิ้นเดียวที่สวมไว้บนปากกัดนี้ ปกป้องประตูแห่งลมหายใจจากลมทะเลเค็มและเม็ดทรายอย่างเงียบงัน"},"ICON-2288":{"nm":"ห่วงดึงซิปชุดดำน้ำ","de":"ห่วงดึงสั้นๆ ที่ผูกไว้กับซิปชุดดำน้ำ เป็นความใส่ใจที่ติดไว้ให้แม้มือที่แข็งชาจากน้ำเย็นก็ยังดึงขึ้นได้ในทีเดียว แม้แต่การรูดซิปเสื้อผ้าก็ยังแฝงความคิดคำนึงของใครสักคนไว้"},"ICON-2289":{"nm":"ฝาครอบป้องกันเกจวัดอากาศ","de":"ฝาครอบที่ปกป้องกระจกของเกจที่บอกปริมาณอากาศที่เหลืออยู่ เพราะตัวเลขเหล่านั้นต้องไม่มัวเลือนเด็ดขาด ยิ่งเป็นขีดวัดที่อ่านค่าชีวิต ยิ่งต้องเช็ดและปิดไว้อย่างพิถีพิถัน"},"ICON-2290":{"nm":"หัวเข็มขัดถ่วงน้ำหนัก","de":"ผู้คนพันน้ำหนักไว้รอบเอวเพื่อดำดิ่งลงสู่ความลึก ในเสี้ยววินาทีที่หัวเข็มขัดเพียงตัวเดียวปลดล็อกและล็อกลง ทางเลือกระหว่างการลอยขึ้นและการจมลงก็มารวมกันอย่างเงียบสงบที่ปลายนิ้ว"},"ICON-2291":{"nm":"สายรัดข้อมือไฟฉายดำน้ำ","de":"ในความมืดมิดใต้น้ำ สายเส้นเดียวที่ผูกไว้กับข้อมือยึดไฟฉายไว้อย่างมั่นคง แม้ปล่อยมือ แสงไฟก็ยังตามมาด้วย การไม่สูญเสียแสงเล็กๆ ท่ามกลางความมืดจึงให้ความรู้สึกอุ่นใจด้วยเหตุนี้เอง"},"ICON-2292":{"nm":"คลิปจัดระเบียบท่อหายใจ","de":"คลิปเล็กๆ ที่รวบรวมท่อที่กระจัดกระจายให้เป็นระเบียบเดียวกัน ป้องกันการพันกันไว้ล่วงหน้า มือก็จะไม่สับสนแม้ในยามคับขัน การจัดระเบียบคือความเมตตาอันเงียบงันที่มีต่อตัวเองในอนาคต"},"ICON-2293":{"nm":"ผ้าเสริมปลายนิ้วถุงมือดำน้ำ","de":"ผ้าเสริมที่ปะไว้ทุกปลายนิ้ว จุดที่ดึงเชือกและจับหินย่อมสึกหรอก่อนที่อื่นเสมอ จึงเสริมอีกชั้นหนึ่งไว้ล่วงหน้าเพื่อโอบรับความสึกหรอนั้น"},"ICON-2294":{"nm":"ห่วงฐานถังออกซิเจน","de":"ห่วงฐานเพียงวงเดียวที่ประคองถังหนักให้ตั้งตรง มันโอบน้ำหนักที่เกือบจะล้มไว้เป็นวงกลม มอบความสมดุลให้ การประคองคือหัวใจที่ยื่นข้างกายให้เพื่อไม่ให้สิ่งใดล้มลง"},"ICON-2295":{"nm":"ฝาครอบครีบเซิร์ฟบอร์ด","de":"ฝาครอบที่โอบปลายแหลมคมของครีบใต้บอร์ดไว้ เพื่อไม่ให้เจ็บแม้จะเดินบนผืนทราย มันพักปลายมีดที่เคยผ่าคลื่นไว้ชั่วคราว ในยามพักผ่อนใครก็ทื่อลงได้บ้าง"},"ICON-2296":{"nm":"ฝาครอบปลายใบพาย","de":"ฝาครอบที่ปกป้องปลายใบพาย มันกั้นไม่ให้รอยขีดข่วนจากโขดหินมารบกวนการไหลของสายน้ำ ถนอมปลายใบพายไว้ การพายแต่ละครั้งก็จะพาไปได้ไกลขึ้น"},"ICON-2297":{"nm":"กริปด้ามพายเรือคายัค","de":"กริปที่พันไว้ตรงจุดที่ฝ่ามือสัมผัสกับด้ามพาย มันรองรับจุดที่เคยเกิดแผลพองอย่างนุ่มนวล เพื่อให้มือไม่เกลียดพายแม้ในระหว่างการพายทวนกระแสน้ำขึ้นไป"},"ICON-2298":{"nm":"กระป๋องเก็บแว็กซ์เซิร์ฟ","de":"กระป๋องสังกะสีเล็กๆ ที่เก็บแว็กซ์ก้อนหนึ่งไว้ เวทมนตร์ที่ยึดเท้าไว้กับบอร์ดนั้นถูกหยิบออกมาจากกล่องขนาดเท่าฝ่ามือนี้เสมอ การเตรียมตัวของวันนี้เริ่มต้นจากกระป๋องเรียบร้อยเพียงใบเดียว"},"ICON-2299":{"nm":"ห่วงรัดข้อเท้าสายลีช","de":"ห่วงที่รัดสายลีชซึ่งเชื่อมข้อเท้ากับบอร์ดไว้ ปมเดียวที่สาบานว่าจะไม่ปล่อยมือแม้ถูกคลื่นลูกใหญ่ซัดกวาดไป การเชื่อมต่อคือคำสัญญาที่จะยึดไว้ไม่ให้ลอยไปไกลเกินไป"},"ICON-2300":{"nm":"ปลั๊กลมบอร์ดยืนพาย","de":"บอร์ดที่แข็งแรงขึ้นเมื่อเติมลม และปลั๊กที่กักลมหายใจนั้นไว้ เปิดมันก็พับแบนราบ ปิดมันก็ตั้งอยู่บนผิวน้ำได้ ปลั๊กเล็กๆ เพียงตัวเดียวบรรจุวันเวลาที่พองและแฟบไว้"},"ICON-2301":{"nm":"สายรัดเบาะที่นั่งเรือคายัค","de":"สายที่รัดเบาะไว้กับที่นั่ง สำหรับหลังและเอวที่พายเรืออยู่นานๆ มันยึดความนุ่มไว้ไม่ให้เลื่อนหลุด แม้แต่ความสบายก็ยังต้องการปมที่ผูกไว้แน่น"},"ICON-2302":{"nm":"กันชนหัวกระดานโต้คลื่น","de":"กันชนที่หุ้มหัวเรือของกระดาน เป็นเนื้อเสริมที่เพิ่มไว้ตรงปลายจมูกซึ่งกระทบบ่อยที่สุด ให้มันทื่อลงก่อนใคร การวางความนุ่มนวลไว้ในตำแหน่งที่นำหน้า คือคำสัญญาว่าจะใช้กันไปอีกนาน"},"ICON-2303":{"nm":"หัวเข็มขัดล็อกกระเป๋ากันน้ำ","de":"หัวเข็มขัดที่ต้องพับแล้วรัดซ้ำสองสามครั้งเพื่อไม่ให้น้ำสักหยดผ่านเข้าไปได้ การรักษาสิ่งล้ำค่าให้แห้งอยู่เสมอนั้น ต้องใช้มืออีกครั้งเสมอ การรัดให้แน่นหนาเพียงครั้งเดียวนั้นแหละที่ทำให้อุ่นใจ"},"ICON-2304":{"nm":"เศษตาข่ายประตูฟุตซอล","de":"เศษตาข่ายชิ้นหนึ่งที่เคยสั่นไหวอยู่หน้าประตู มันจดจำเสียงเชียร์ในวินาทีที่ลูกบอลพุ่งเข้ามาไว้ทีละเส้นด้าย ในทุกปมมีประตูซ่อนอยู่ และในทุกจุดที่ขาดรุ่ย เกมวันนั้นยังคงมีชีวิตอยู่"},"ICON-2305":{"nm":"หัวฉีดสูบลมลูกฟุตบอล","de":"หัวฉีดปั๊มที่เป่าลมหายใจกลับเข้าไปในลูกบอลที่แบนแฟบ หนังที่เคยกลิ้งอยู่อย่างไร้เรี่ยวแรงกลับเด้งดึ๋งขึ้นมาอีกครั้ง การเติมลมเข้าไปคือการปลุกเกมที่หยุดนิ่งให้ลุกขึ้นยืนอีกครั้ง"},"ICON-2306":{"nm":"ฐานธงมุมสนาม","de":"ฐานที่ปักธงให้ตั้งตรงอยู่ที่มุมสนาม เป็นเพียงสัญลักษณ์เล็กๆ ที่บอกขอบเขต แต่ด้วยจุดเดียวนั้น พื้นดินธรรมดาจึงกลายเป็นรูปร่างของสนามแข่งขันได้ในที่สุด"},"ICON-2307":{"nm":"สายรัดสนับแข้ง","de":"สายที่รัดสนับแข้งไว้กับน่อง มันยึดจุดที่ถูกกระแทกบ่อยที่สุดไว้ให้แน่น เพื่อให้ทุกก้าวไม่หวาดกลัวแม้ท่ามกลางการปะทะที่รุนแรง"},"ICON-2308":{"nm":"หมุดเปลี่ยนปุ่มรองเท้า","de":"หมุดสำหรับถอดปุ่มที่สึกออกแล้วใส่อันใหม่เข้าไปแทน ฟันเล็กๆ ที่ปลายเท้าซึ่งเกาะยึดสนามหญ้าไว้ ถ้าจะไม่ให้ลื่นไถล บางครั้งก็ต้องสร้างใหม่ตั้งแต่ใต้ฝ่าเท้า"},"ICON-2309":{"nm":"ฝาปิดลิ้นลูกฟุตบอล","de":"ฝาลิ้นเล็กๆ ที่ปิดรูหายใจของลูกบอล มันคอยเฝ้าทางเข้าไม่ให้ลมที่เติมไว้รั่วออกไป การรักษาความตึงไว้ให้ได้นั้น ก็คล้ายกับการไม่ปล่อยให้ความมุ่งมั่นหย่อนยานจนถึงเกมถัดไป"},"ICON-2310":{"nm":"กรวยตีเส้นแบ่งสนาม","de":"กรวยที่ขีดเส้นบนพื้นเพื่อแบ่งทาง ถึงตรงนี้คือฝ่ายเรา จากตรงนั้นคือฝ่ายเขา กรวยเล็กๆ เพียงอันเดียวเปลี่ยนที่ว่างรกๆ ให้กลายเป็นสนามเด็กเล่นที่มีกติกา"},"ICON-2311":{"nm":"แปรงปัดฝุ่นรองเท้าฟุตซอล","de":"แปรงที่ปัดฝุ่นดินซึ่งติดอยู่ตามซอกของรองเท้าฟุตซอล เมื่อการแข่งขันจบลง ฝุ่นดินของทั้งวันก็มาสะสมอยู่ที่รองเท้าด้วยเช่นกัน มือที่ปัดมันออกคือคำขอบคุณเงียบๆ ที่มอบให้เท้าซึ่งวิ่งมาอย่างสุดกำลัง"},"ICON-2312":{"nm":"ที่แขวนถุงมือผู้รักษาประตู","de":"ที่แขวนสำหรับตากถุงมือของผู้รักษาประตูให้แห้ง เป็นที่พักของมือที่เปียกเหงื่อ มากเท่ากับจำนวนลูกยิงที่ปัดออกไปได้ เพื่อการแข่งขันครั้งถัดไป สิ่งที่เปียกก็แห้งลง และหัวใจที่แข็งเกร็งก็ค่อยๆ คลายตัว"},"ICON-2313":{"nm":"ตะขอแขวนตาข่ายห่วงบาสเกตบอล","de":"ตะขอเล็กๆ ที่แขวนตาข่ายไว้กับห่วง เพราะสิ่งเหล่านี้ จึงมีเสียงซ่าเบาๆ ในตอนที่ลูกบอลหลุดผ่านลงไป เสียงทำคะแนนที่แจ่มใสนั้น แท้จริงแล้วเริ่มต้นจากตะขอเล็กๆ นี่เอง"},"ICON-2314":{"nm":"เครื่องมือปล่อยลมลูกบาสเกตบอล","de":"เครื่องมือที่ปล่อยลมออกจากลูกบอลที่แข็งเกินไปทีละนิด ความตึงที่มากเกินไปทำให้การเด้งดูดุดัน การผ่อนคลายให้พอเหมาะ ลูกบอลที่สัมผัสดีมักเกิดจากความพอดีเช่นนี้เสมอ"},"ICON-2315":{"nm":"แผ่นเซนเซอร์แป้นหลัง","de":"แผ่นเซนเซอร์ที่ติดอยู่หลังแป้นบาส มันอ่านช่วงเวลาที่ลูกบอลสัมผัสได้อย่างชัดเจนเป็นตัวเลข แม้แต่ช่วงเวลาที่สายตาพลาดไป ความรู้สึกเล็กๆ นี้ก็ยังจดจำไว้ การตัดสินจึงยุติธรรมขึ้นอีกขั้น"},"ICON-2316":{"nm":"กรวยฝึกเลี้ยงบอล","de":"กรวยกีดขวางที่เรียงแถวอยู่ตลอดทางฝึกเลี้ยงบอล การหลบหลีกไปมาระหว่างกรวยเหล่านี้เองที่ทำให้ฝีเท้าเติบโตขึ้น การขวางทางก็เป็นความเมตตาชนิดหนึ่ง ที่สอนให้รู้จักหลบหลีกให้เก่งขึ้น"},"ICON-2317":{"nm":"แปรงทำความสะอาดลิ้นลูกบาสเกตบอล","de":"แปรงเล็กๆ ที่ทำความสะอาดรูลิ้นของลูกบอล ถ้าฝุ่นอุดตัน เข็มก็สอดเข้าไปไม่ได้ จึงต้องทำความสะอาดจากทางเข้าที่มองไม่เห็นก่อน ก่อนจะเติมสิ่งใด เราต้องเทออกและเช็ดให้สะอาดเสมอ"},"ICON-2318":{"nm":"ม้วนเทปพันนิ้ว","de":"เทปพันนิ้วหนึ่งม้วน มันยึดข้อที่แพลงไว้อย่างมั่นคง มอบความกล้าที่จะจับลูกบอลอีกครั้ง การพันแผลที่บาดเจ็บไว้คือคำประกาศเล็กๆ ว่าจะไม่หยุด"},"ICON-2319":{"nm":"คลิปหนีบเบอร์เสื้อ","de":"คลิปที่ยึดเบอร์หลังไว้กับเสื้อ แทนที่จะเป็นชื่อของเธอ ตัวเลขต่างหากที่วิ่งไปทั่วสนาม ในการหนีบแน่นเพียงครั้งเดียวไม่ให้หลุด ใครกำลังลงเล่นในวันนี้ก็ถูกจารึกไว้อย่างชัดเจน"},"ICON-2320":{"nm":"ห่วงเป้าฝึกช็อต","de":"ห่วงเป้าที่สวมไว้ในห่วงบาสเพื่อให้เป้าหมายแคบลง มันย่อพื้นที่ที่ลูกบอลต้องลอดผ่านให้เล็กลง ฝึกให้ทนต่อการพลาดเป้า โยนไปยังประตูแคบๆ นั้นนานพอ ปลายนิ้วก็ค่อยๆ เรียนรู้ความแม่นยำโดยไม่รู้ตัว"},"ICON-2321":{"nm":"แผ่นเช็ดพื้นรองเท้าบาสเกตบอล","de":"ก่อนก้าวเข้าสนาม เธอย่อเข่าลงเช็ดพื้นรองเท้าก่อนเป็นอันดับแรก เพราะไม่อยากทิ้งรอยลื่นแม้เพียงจุดเดียวไว้บนพื้นไม้ ก้าวแรกด้วยปลายเท้าที่สะอาด ทำให้ตัวเธอในวันนี้มั่นคงกว่าเมื่อวานเล็กน้อย"},"ICON-2322":{"nm":"ห่วงปรับความตึงตาข่ายวอลเลย์บอล","de":"ความตึงนั้นมองไม่เห็นด้วยตา แต่ในวินาทีที่ห่วงดึงเชือกจนสุดแล้วหยุดนิ่ง ตาข่ายก็แบ่งสนามเป็นสองฝั่งด้วยความตึงเพียงคืบเดียว สมดุลที่มือที่มองไม่เห็นคอยจับไว้นั้นเองที่ปลุกเกมให้ตื่นขึ้น"},"ICON-2323":{"nm":"คลิปยึดเสาอากาศ","de":"เสาอากาศที่สั่นไหวไปมาตามลมกลับยืนตรงได้ด้วยคลิปเพียงตัวเดียว สิ่งเล็กๆ ที่ยึดความสั่นไหวใหญ่ๆ ไว้ได้ มือที่คอยยึดสายเคเบิลเส้นหนึ่งไว้อย่างเงียบๆ หลังเวที ก็เคลื่อนไหวด้วยหัวใจขนาดนี้เช่นกัน"},"ICON-2324":{"nm":"ที่แขวนเสื้อกั๊กลิเบโร่","de":"เสื้อกั๊กสีต่างของผู้เชี่ยวชาญด้านรับ แขวนอยู่บนผนังรอการแข่งขันครั้งถัดไป แม้ไม่หรูหรา แต่ก็เป็นชื่อที่ค้ำจุนสนามทั้งสนามไว้ นั่นคือลิเบโร่ ดวงตาที่มองไกลที่สุดอยู่ตรงตำแหน่งที่ต่ำที่สุดนั่นเอง"},"ICON-2325":{"nm":"ถุงเก็บสนับเข่า","de":"ยิ่งกลิ้งตัวไปบนพื้นมากเท่าไร หัวเข่าก็ยิ่งกระแทกบ่อยขึ้นเท่านั้น ถุงเล็กๆ ที่จัดเก็บสนับเข่าอย่างเรียบร้อยรู้ดีว่า มีเพียงคนที่เรียนรู้วิธีล้มลงอย่างสวยงามก่อนเท่านั้น ที่ในที่สุดจะโบยบินไปได้ไกลที่สุด"},"ICON-2326":{"nm":"เกจวัดแรงดันลูกวอลเลย์บอล","de":"เพียงแค่ใช้ปลายนิ้วเคาะเบาๆ ไม่มีทางรู้ได้ เข็มเกจสั่นไหวเบาๆ แล้วชี้ไปที่ขีดเดียว การวัดลมหายใจของลูกบอลลูกหนึ่งคือกระดุมเม็ดแรกของการแข่งขัน จากแรงดันที่ซื่อตรง วิถีที่ซื่อตรงจึงถือกำเนิดขึ้น"},"ICON-2327":{"nm":"เทปตีเส้นสนามโดดจ์บอล","de":"วงกลมหนึ่งวงที่ขีดด้วยเทปบนพื้นดินของสนาม ด้านในและด้านนอกของมันแบ่งจักรวาลแห่งการไล่จับของครึ่งวันไว้เป็นสองฝั่ง มือที่ขีดเส้นรู้ดีว่า กติกาคือจุดเริ่มต้นของการเล่นนั่นเอง"},"ICON-2328":{"nm":"ที่วางนกหวีดกรรมการ","de":"เมื่อเสียงนกหวีดอันแหลมคมเงียบลง มันก็ถูกวางกลับไปยังที่ของมันอย่างสงบบนที่วาง ตำแหน่งที่ได้ยินลมหายใจของกรรมการใกล้ที่สุด ความยุติธรรมเริ่มต้นเสมอจากงานเล็กๆ ของการรักษาที่ทางของตนเอง"},"ICON-2329":{"nm":"เป้าฝึกโทสติดผนัง","de":"ในยามเช้ามืดที่ไม่มีใครคอยรับ เธอโยนปลายนิ้วนับพันครั้งไปยังเป้าที่ติดอยู่บนผนัง ผนังคือเพื่อนร่วมทีมที่ใจกว้างที่สุด ลูกบอลที่สะท้อนกลับมาช่วยพยุงตัวเธอที่เหนื่อยล้าให้ลุกขึ้นอีกครั้ง"},"ICON-2330":{"nm":"ไม้วัดความสูงตาข่าย","de":"แม้ตาข่ายจะต่ำไปเพียงนิ้วเดียว การแข่งขันก็คลาดเคลื่อนไปแล้ว ในวินาทีที่ยกไม้วัดขึ้น ความยุติธรรมก็ไม่ใช่แค่ตัวเลข แต่กลายเป็นนิสัยประจำวัน ความแม่นยำที่มองไม่เห็นคอยปกป้องสนามไว้"},"ICON-2331":{"nm":"หมุดปรับมุมบล็อกออกตัว","de":"จากท่านั่งโน้มตัวลง มุมที่ปลายเท้าสัมผัสบล็อก องศาเดียวนั้นตัดสินการออกตัวทั้งหมด ด้วยหมุดเพียงตัวเดียวเธอยึดบล็อกให้อยู่กับที่แล้วปรับลมหายใจให้สม่ำเสมอ ท่วงท่าของการเริ่มต้นจะติดตามเธอไปอย่างเงียบๆ จนถึงเส้นชัย"},"ICON-2332":{"nm":"ธงหมายเลขเลนลู่วิ่ง","de":"ธงเล็กๆ ที่ปักไว้ในแต่ละเลนโบกตัวเลขไปตามสายลม ทุกคนวิ่งไปในทิศทางเดียวกัน แต่ต่างก็มีเส้นทางของตัวเอง ลู่วิ่งโอบรับทั้งความเสมอกันและความแตกต่างไว้ในเวลาเดียวกัน"},"ICON-2333":{"nm":"จุกปลายไม้ผลัด","de":"เพื่อวินาทีที่จะไปสัมผัสมือของนักวิ่งคนสุดท้าย จุกปลายไม้จึงโค้งมนหุ้มมุมเหลี่ยมไว้ ในการวิ่งผลัด สิ่งล้ำค่าที่สุดไม่ใช่ความเร็ว แต่คือมือที่ส่งต่อให้คนถัดไป"},"ICON-2334":{"nm":"ที่แขวนสายวัดบันทึกผล","de":"แขวนสายวัดที่บันทึกผลไว้บนผนังเพื่อไม่ให้พันกัน คือตำแหน่งที่ระยะทางของเมื่อวานและวันนี้แขวนเรียงกันอยู่ ความเติบโตมักมาเยือนก่อนในรูปของตัวเลขที่ต่างกันเพียงเล็กน้อยเสมอ"},"ICON-2335":{"nm":"กรวยหมายทางโค้งลู่วิ่ง","de":"กรวยเล็กๆ ที่วางไว้ด้านในของทางโค้งบอกใจของเส้นทางให้รู้ อย่าตัดเข้าในลึกเกินไป และอย่ากระจายออกนอกเกินไป คนที่วิ่งโค้งได้ดีในที่สุดจะนำหน้าที่สุด"},"ICON-2336":{"nm":"คลิปหนีบริบบิ้นเส้นชัย","de":"ริบบิ้นที่จะสัมผัสอกของใครสักคนเป็นคนแรก คลิปยึดมันไว้ให้ตึงและรอคอย เส้นสายที่มีไว้เพื่อให้ขาด มันทนต่อสายลมตลอดทั้งวันเพื่อวินาทีเดียวของใครสักคน"},"ICON-2337":{"nm":"ฝาครอบปืนสตาร์ท","de":"จนกว่าเสียงสัญญาณ \"ปัง\" จะดังขึ้น ปากกระบอกปืนก็หลับใหลอยู่ใต้ฝาครอบ ภาชนะที่บรรจุเสียงแห่งการเริ่มต้นไว้ ยิ่งความเงียบลึกมากเท่าไร เสียงก้องของนัดแรกก็ยิ่งแผ่ไปไกลมากเท่านั้น"},"ICON-2338":{"nm":"หมุดปรับความสูงรั้ว","de":"ทุกครั้งที่ยกความสูงขึ้นอีกหนึ่งขั้น ตำแหน่งของหมุดก็เปลี่ยนตามไปด้วย และความกลัวก็เติบโตขึ้นเท่านั้นพอดี แต่ถึงอย่างนั้น เท้าก็ยังกะระยะจุดที่สูงขึ้นเล็กน้อยในทุกครั้งแล้ววิ่งต่อไป"},"ICON-2339":{"nm":"แป้นหมุนนับรอบ","de":"เมื่อสับสนว่าเหลืออีกกี่รอบ เธอหมุนแป้นไปอีกหนึ่งขีด เสียงคลิกเบาๆ ของตัวเลขที่ลดลงเติมแรงกลับเข้าไปในขาอีกครั้ง มือที่นับระยะทางที่เหลืออยู่คอยรักษาจังหวะให้เธอ"},"ICON-2340":{"nm":"แท่นตั้งเก็บไม้ค้ำกระโดด","de":"ไม้ค้ำที่ยาวและโค้งงอต้องการที่พักพิงของตัวเอง เพราะมันคือเครื่องมือที่ต้องโค้งงอก่อนจึงจะพุ่งทะยานขึ้นได้ จึงต้องตั้งไว้อย่างระมัดระวังเป็นพิเศษ ความยืดหยุ่นที่เก็บรักษาไว้อย่างดีนั้นโอบอุ้มการกระโดดที่สูงที่สุดไว้"},"ICON-2341":{"nm":"คราดปรับพื้นบ่อทราย","de":"เธอค่อยๆ คราดปรับรอยเท้าที่นักกีฬาคนก่อนทิ้งไว้ให้เรียบ บ่อทรายจึงราบเรียบขึ้นใหม่ราวกับเป็นครั้งแรกในทุกๆ รอบ มือที่ลบรอยเพื่อการกระโดดของใครสักคนนั้นอยู่ตรงนั้นอย่างเงียบสงบ"},"ICON-2342":{"nm":"แถบหมายระยะวิ่งเข้า","de":"ก้าวสั้นไปหนึ่งก้าวก็ไม่ได้ ก้าวเกินไปอีกก้าวก็ไม่ได้เช่นกัน แถบหมายระยะทางบนพื้นบอกอย่างซื่อตรงว่าจุดที่ควรกระโดดอยู่ตรงไหน การวิ่งเข้าที่ดีไม่ใช่ความโลภที่ทำไปตามอำเภอใจ แต่เกิดจากการคำนวณอย่างสุขุมรอบคอบ"},"ICON-2343":{"nm":"กริปจับจานขว้าง","de":"ถ้านิ้วลื่นไถล การขว้างก็ถูกขว้างออกไปแล้วก่อนที่จะได้ขว้างเสียด้วยซ้ำ พื้นผิวหยาบของกริปที่โอบจานขว้างไว้คอยยึดการหมุนให้อยู่ในกำมือ จังหวะการปล่อยเริ่มต้นจากความรู้สึกของการจับเสมอ"},"ICON-2344":{"nm":"ห่วงรองรับลูกทุ่มน้ำหนัก","de":"ห่วงรองรับโอบลูกเหล็กหนักไว้อย่างสงบไม่ให้กลิ้งหนี รังเล็กๆ ที่รักษาความนิ่งสงบก่อนการขว้างไว้ ยิ่งเป็นพลังที่จะระเบิดออกมามากเท่าไร ที่พักของมันก็ยิ่งต้องมั่นคงมากเท่านั้น"},"ICON-2345":{"nm":"ฝาครอบปลายหอก","de":"ฝาที่สวมคลุมปลายหอกอันแหลมคมปกคลุมความเงียบอันอ่อนโยนไว้ เมื่อเครื่องมือที่จะพุ่งทะยานไปไกลนอนนิ่งอยู่เงียบๆ อันตรายก็ถูกกล่อมเกลาด้วยความใส่ใจ ความปลอดภัยมีชีวิตอยู่แม้ในยามเก็บรักษา"},"ICON-2346":{"nm":"ตะขอรองรับคานกระโดดสูง","de":"เพื่อไม่ให้คานร่วงหล่นแม้ถูกแตะเพียงเบาๆ ตะขอจึงรองรับไว้ด้วยสมดุลที่ประณีต ตำแหน่งที่รับผิดชอบเส้นแบ่งอันสั่นไหวระหว่างข้ามผ่านได้หรือไม่ได้ ความยุติธรรมสิงสถิตอยู่ในรายละเอียดเล็กๆ เช่นนี้"},"ICON-2347":{"nm":"ตัวยึดมุมเบาะรองรับ","de":"ถ้ามุมของเบาะรองรับยกตัวขึ้น ก็อาจทำให้บาดเจ็บได้ ตัวยึดกดมุมทั้งสี่ไว้อย่างมั่นคง เพื่อให้ร่างกายที่พุ่งขึ้นสูงที่สุดลงจอดอย่างปลอดภัยที่สุด มันค้ำยันไว้อย่างเงียบๆ โดยไม่มีใครมองเห็น"},"ICON-2348":{"nm":"เทปขีดเส้นวงกลมขว้าง","de":"ขอบเขตของจุดขว้างถูกขีดไว้ด้วยเทปเส้นเดียว การจะเหยียบเส้นนั้นหรือไม่ ตัดสินว่าสถิติจะมีชีวิตหรือดับสูญ เส้นบางๆ เพียงเส้นเดียวที่เสรีภาพกับกติกามาบรรจบกัน คือคำสัญญาที่ผูกไว้ด้วยกัน"},"ICON-2349":{"nm":"ฐานยางรองคานทรงตัว","de":"เพื่อไม่ให้คานทรงตัวแคบๆ สั่นไหว ฐานยางกัดยึดพื้นไว้อย่างแน่นหนา สมดุลที่ปราศจากการสั่นไหวซึ่งจะเผยออกมาบนคานนั้น แท้จริงแล้วเกิดจากความมั่นคงที่มองไม่เห็นอยู่ข้างใต้"},"ICON-2350":{"nm":"ผ้าพันมือจับบาร์เดี่ยว","de":"เพื่อไม่ให้ฝ่ามือลื่น เธอพันผ้าพันมือรอบด้ามจับบาร์เดี่ยว ความลับของการหมุนตัวอันหวือหวานั้นไม่ได้อยู่ที่ความสวยงาม แต่อยู่ที่มือที่กำแน่น เหงื่อที่หยดลงบนเบาะรองรู้ดีถึงสิ่งนั้น"},"ICON-2351":{"nm":"ตัวล็อกปรับความสูงสายห่วง","de":"หากความสูงของสายทั้งสองเส้นต่างกันเพียงเท่าฝ่ามือ ท่วงท่าก็พังทลายลง ตัวล็อกยึดสมดุลนั้นไว้อย่างเงียบเชียบ มีเพียงบนความสูงที่ปรับให้ตรงกันอย่างแม่นยำเท่านั้น การโบยบินอย่างเสรีจึงจะเริ่มต้นได้"},"ICON-2352":{"nm":"ปลอกหุ้มด้ามจับม้ากระโดด","de":"ปลอกที่หุ้มด้ามจับป้องกันไม่ให้เกิดแผลพองบนฝ่ามือ ใต้ท่าหมุนวนหวือหวานั้น มีมือที่ถลอกแล้วสมานตัวซ้ำแล้วซ้ำเล่านับไม่ถ้วน การปกป้องคือคำสัญญาอันอ่อนโยนที่มีต่อการฝึกซ้อมครั้งถัดไป"},"ICON-2353":{"nm":"หมุดปรับระยะบาร์คู่ต่างระดับ","de":"เธอปรับระยะห่างระหว่างบาร์ทั้งสองให้แม่นยำด้วยหมุด พื้นที่ว่างที่ร่างกายจะโลดแล่นผ่านไปมานั้นกลายเป็นเวทีทันที ปลายนิ้วรู้ก่อนใครว่า บนระยะที่แม่นยำนั้นเองที่การกระโดดอันกล้าหาญที่สุดถือกำเนิดขึ้น"},"ICON-2354":{"nm":"ฝาครอบสปริงกระดานสปริงบอร์ด","de":"ในวินาทีที่ถีบกระดาน สปริงดันร่างกายพุ่งขึ้นสู่ท้องฟ้า ฝาครอบห่อหุ้มแรงกระเด้งนั้นไว้อย่างแน่นหนา การวิ่งเข้าที่สั้นที่สุด สร้างการลอยตัวกลางอากาศที่ยาวนานที่สุด"},"ICON-2355":{"nm":"ถุงผงแมกนีเซียม","de":"ผงสีขาวที่ทาลงบนมือคือเครื่องรางเล็กๆ ที่ลบล้างความลื่นไถล พิธีกรรมสั้นๆ ของการจุ่มมือลงในถุงแล้วดึงออกมาช่วยระงับความกลัว ในที่สุดแล้วแม้แต่ความตึงเครียดก็ถูกสงบลงได้ที่ปลายนิ้วนี่เอง"},"ICON-2356":{"nm":"ผ้าพันข้อมือยิมนาสติก","de":"ขณะพันผ้ารอบข้อมือ เชือกในใจก็ถูกรัดตึงไปพร้อมกัน คือการยึดข้อต่อที่จะสั่นไหวไว้ล่วงหน้า ข้อมือที่ผูกไว้อย่างดีเพียงข้างเดียวเงียบๆ อนุญาตให้เกิดการหมุนตัวที่กล้าหาญยิ่งขึ้นได้"},"ICON-2357":{"nm":"ห่วงนิรภัยชิงช้าลอยฟ้า","de":"ก่อนจะทุ่มร่างกายลงสู่อากาศ ห่วงนิรภัยกลายเป็นมือที่มองไม่เห็น เมื่อความกลัวที่จะร่วงหล่นหายไป จึงจะโบยบินไปได้ไกลที่สุด ความไว้วางใจนั้นทำให้การบินสมบูรณ์แบบ"},"ICON-2358":{"nm":"ฝาปิดกระป๋องเก็บลูกเทนนิส","de":"ใต้ฝาที่ปิดปากกระป๋อง ลูกบอลใหม่หลับใหลอยู่พร้อมกักเก็บแรงดันไว้ในตัว เสียง \"ป๊อก\" เล็กๆ ตอนเปิดกระป๋องปลุกความตื่นเต้นของการแข่งขันให้ตื่นขึ้น การปิดผนึกคือคำสัญญาที่รักษาความสดใหม่เอาไว้"},"ICON-2359":{"nm":"คีมหนีบความตึงเอ็นแร็กเกต","de":"คีมกัดความตึงของเอ็นไว้อย่างแน่นและไม่ปล่อยจนถึงที่สุด เพราะแรงตึงของเส้นเอ็นเพียงเส้นเดียวเป็นตัวกำหนดแรงสะท้อนของลูกบอล สัมผัสที่มองไม่เห็นนั้นเริ่มต้นจากคีมเล็กๆ นี้เอง"},"ICON-2360":{"nm":"แปรงกวาดเส้นสนามเทนนิส","de":"เมื่อการแข่งขันจบลง เธอค่อยๆ กวาดไปตามเส้นสีขาวของสนาม เมื่อกวาดฝุ่นดินออกไป เส้นก็คมชัดขึ้นอีกครั้ง การปูทางสำหรับการแข่งขันครั้งถัดไป ความใส่ใจในตอนท้ายนั้นเองที่ทำให้สนามมีชีวิตชีวา"},"ICON-2361":{"nm":"เทปกันกระแทกหัวแร็กเกต","de":"พันรอบขอบแร็กเกตหนึ่งรอบ แม้แต่การกระแทกที่รุนแรงก็ถูกรับไว้อย่างนุ่มนวล ฉันรู้ดีว่ามุมนี้คือจุดที่สึกหรอก่อนใคร เพราะการรับหน้าที่สึกหรอแทนคือส่วนของฉัน วันนี้ฉันจึงยังคงยืนอยู่ที่ขอบนอกสุดเช่นเคย"},"ICON-2362":{"nm":"ชิปวัดอุณหภูมิในร่ม","de":"ลมหนาวยามรุ่งสางที่พัดเข้ามาเมื่อประตูเปิด ชิปขนาดเท่าฝ่ามือรับรู้ได้ก่อนคนเสียอีก การรับรู้ได้ก่อนที่ปลายจมูกจะรู้สึกหนาว คือคำทักทายที่เงียบที่สุดซึ่งเปิดวันใหม่ให้ยิมที่ว่างเปล่า"},"ICON-2363":{"nm":"แผ่นวางเท้าเส้นหลัง","de":"สำหรับนักกีฬาที่ลังเลว่าจะวางปลายเท้าตรงไหนดี เพียงแค่เส้นหนึ่งเส้นที่ขีดไว้บนพื้นก็เพียงพอแล้ว เส้นที่ไม่ควรข้ามนั่นแหละกลายเป็นเส้นเริ่มต้นของการกระโดดที่ไกลที่สุด แผ่นรองบอกไว้อย่างเงียบๆ เช่นนั้น"},"ICON-2364":{"nm":"ที่แขวนตะกร้าลูกเทนนิส","de":"มันอมลูกบอลไว้นับสิบลูกในคำเดียวโดยไม่ทำหล่นแม้แต่ลูกเดียว การรวบรวมสิ่งที่กระจัดกระจายอยู่ทั่วสนามส่งต่อไปยังการฝึกซ้อมครั้งถัดไป มือที่ยุ่งอยู่อย่างเงียบๆ ตรงมุมนั้น วันนี้ก็ยังคงแขวนอยู่ตรงนี้เช่นเคย"},"ICON-2365":{"nm":"จุกปลายด้ามแร็กเกต","de":"ในวินาทีที่สวมเข้าที่ปลายด้ามจับพอดี แร็กเกตจึงจะแนบสนิทอยู่ในฝ่ามือเสียที จุกเล็กๆ เพียงชิ้นเดียวแบ่งเส้นระหว่างความลื่นไถลกับความอุ่นใจไว้ ปิดปลายให้แน่นหนาไว้ก่อน การสวิงครั้งแรกจึงจะมั่นคง"},"ICON-2366":{"nm":"คลิปหนีบผ้าเช็ดตัวข้างสนาม","de":"แม้ลมจะพัดแรงเพียงใด มันก็ยังคงปิดปากแน่นและยืนหยัดอยู่ข้างสนาม ไม่ให้ผ้าเช็ดตัวที่บิดผึ่งอย่างตั้งใจปลิวหายไป แม้แต่การพักหายใจสั้นๆ ก็ยังมีปลายนิ้วเก่งกาจของใครสักคนคอยดูแลอยู่"},"ICON-2367":{"nm":"คีมจัดขนลูกขนไก่","de":"แม้ขนเพียงเส้นเดียวจะยับ การบินก็สั่นคลอนไปแล้ว ค่อยๆ คลี่ปีกที่ยับยู่ยี่ให้เรียบ ลูกขนไก่ก็พร้อมที่จะบินตรงอีกครั้ง การไปได้ไกลนั้นเริ่มต้นจากการจัดแต่งเล็กๆ เช่นนี้เสมอ"},"ICON-2368":{"nm":"จุกปิดหลอดลูกขนไก่","de":"เพื่อไม่ให้ลูกขนไก่ที่เรียงกันอยู่ข้างในอ่อนตัวลง จึงบิดปิดปลายหลอดให้แน่นหนา ฉันเฝ้าดูมานานพอจะรู้ว่าความชื้นเพียงนิดเดียวก็ทำให้ขนยุบตัวได้ การเก็บรักษาให้ดีก็เป็นส่วนหนึ่งของการแข่งขันไปแล้ว"},"ICON-2369":{"nm":"ที่รองลูกปิงปองกลิ้ง","de":"ลูกบอลเล็กๆ ที่กลิ้งมาอย่างช้าๆ พักลมหายใจอยู่บนตัวฉันสักครู่ การรองรับไว้อย่างเงียบๆ ไม่ให้กลิ้งหล่นหาย คือความใส่ใจที่มีรูปทรงกลมที่สุด มอบให้อยู่ข้างโต๊ะปิงปอง"},"ICON-2370":{"nm":"ลูกกลิ้งทำความสะอาดยางแร็กเกตปิงปอง","de":"กลิ้งลูกกลิ้งเบาๆ ไปบนหน้ายาง ฝุ่นเก่าก็ลอยขึ้นและความเหนียวก็ฟื้นคืนชีพ การหมุนต้องมีชีวิตอยู่ ลูกบอลจึงจะโค้งงอได้ สภาพของแร็กเกตในวันนี้ตื่นขึ้นจากการดูแลอย่างอ่อนโยนเพียงครั้งนี้เอง"},"ICON-2371":{"nm":"ไม้วัดความสูงตาข่าย","de":"แม้ตาข่ายจะสูงกว่าเพียงคืบเดียว เนื้อสัมผัสของเกมก็เปลี่ยนไปแล้ว คนที่ปฏิเสธจะเชื่อสายตาจนถึงที่สุดจึงนำฉันมาทาบวัด ดูเหมือนว่าความยุติธรรมนั้นมาจากความสูงที่วัดด้วยไม้บรรทัดอย่างเที่ยงตรงเช่นนี้เท่านั้น"},"ICON-2372":{"nm":"ชิปวัดความเร็วลูกขนไก่","de":"ความเร็วของลูกขนไก่ที่ตัดผ่านอากาศ ฉันคำนวณไว้อย่างเงียบๆ เมื่อความเร็วที่มองไม่เห็นเคยกลายเป็นตัวเลขที่ชัดเจน คำพูดถัดไปของโค้ชก็ชัดเจนขึ้นอีกขั้น มันคืองานของการเปลี่ยนสัญชาตญาณให้กลายเป็นข้อเท็จจริง"},"ICON-2373":{"nm":"แคปซูลเก็บลูกปิงปอง","de":"วางลูกบอลกลมๆ หนึ่งลูกลงในแคปซูลอย่างแผ่วเบา รอยขีดข่วนและฝุ่นก็ถอยห่างออกไป เพียงหวังให้มันปลอดภัยจนถึงการแข่งขันครั้งถัดไป คือหัวใจที่มอบห้องเล็กๆ ทั้งห้องให้เพียงเพื่อสิ่งนั้น"},"ICON-2374":{"nm":"ที่แขวนเอ็นแร็กเกตแบดมินตัน","de":"แขวนเอ็นที่หย่อนยานให้เรียงเป็นระเบียบ มือของคนถัดไปจะได้ไม่ต้องคลำหา การจัดระเบียบก็เหมือนโน้ตข้อความอันอ่อนโยนที่เขียนไว้ล่วงหน้าให้กับตัวเองในวันพรุ่งนี้ วันนี้ช่วยให้วันพรุ่งนี้ง่ายขึ้น"},"ICON-2375":{"nm":"เทปกันขอบแร็กเกตปิงปอง","de":"ขอบที่ยางมักจะยกตัวขึ้นได้ง่าย ฉันโอบกอดไว้อย่างเงียบๆ ด้วยเส้นเดียว ถ้าขอบแตกออก แม้แต่เนื้อสัมผัสของลูกบอลก็จะแปรปรวนไปด้วย การปกป้องขอบจึงกลายเป็นการปกป้องแต้มเดียวในที่สุด"},"ICON-2376":{"nm":"ถุงอุ่นลูกสควอช","de":"ลูกบอลที่เย็นแทบจะไม่เด้งเลย ก่อนการแข่งขัน ถุงที่อุ่นและโอบกอดมันไว้อบอุ่นดั่งฝ่ามือ ความอบอุ่นเล็กๆ ที่ส่งผ่านมาถึงมือนั้น กำหนดจังหวะลมหายใจของแต่ละรอบไว้ล่วงหน้า"},"ICON-2377":{"nm":"คลิปยึดตาข่ายไม้ลาครอส","de":"เมื่อปมตาข่ายเริ่มคลายตัวออกอย่างเงียบๆ ฉันกัดปมนั้นไว้แน่นโดยไม่พูดอะไร ตาข่ายต้องตึงจึงจะทำให้ลูกบอลอยู่กับที่ได้ มือที่ยึดทั้งเกมไว้จากตำแหน่งที่มองไม่เห็นนั้นอยู่ตรงนี้นี่เอง"},"ICON-2378":{"nm":"เทปกันปลายแร็กเกตสควอช","de":"ยิ่งเหวี่ยงแรงเข้าใส่ผนัง แร็กเกตก็ยิ่งร้องไห้จากปลายก่อนที่ใด เมื่อห่อหุ้มปลายที่ร้องไห้นั้นไว้เบาๆ มันก็จะเล่นเคียงข้างเธอไปได้อีกหนึ่งฤดูกาล คนที่รู้จักถนอมปลายไว้ ในที่สุดแล้วจะถือแร็กเกตไปได้นาน"},"ICON-2379":{"nm":"ฝาครอบใบไม้ฮอกกี้","de":"เมื่อสวมฝาครอบไว้บนใบมีดอันแหลมคม ทั้งในกระเป๋าและปลายนิ้วก็สบายใจได้เสียที การกล่อมสิ่งอันตรายให้หลับใหลอย่างเงียบๆ คือมารยาทเก่าแก่ที่ทำเป็นอันดับแรกเมื่อจัดเก็บไม้"},"ICON-2380":{"nm":"ผ้าขัดเงาลูกคริกเก็ต","de":"ถูลูกบอลสีแดงด้วยผ้า ด้านหนึ่งก็เก็บแสงไว้ราวกับกระจกเงา นักขว้างรู้ด้วยความรู้สึกที่ปลายนิ้วว่าลูกบอลจะโค้งได้ก็ต่อเมื่อความเงามีชีวิตอยู่ กลยุทธ์อันเงียบงันสิงอยู่แม้ในการขัดถูอย่างพิถีพิถัน"},"ICON-2381":{"nm":"ฝาปิดหลอดเก็บลูกลาครอส","de":"เพื่อไม่ให้ลูกบอลแข็งๆ กลิ้งหนีไปตามใจชอบ จึงบิดปิดปากหลอดให้แน่นหนา การโอบรวมสิ่งที่มักกระจัดกระจายไว้ในที่เดียว พื้นฐานของการบริหารจัดการนั้นเล็กน้อยเช่นนี้เสมอ"},"ICON-2382":{"nm":"ชิ้นเป้าติดผนังสควอช","de":"เป้าหมายเล็กๆ ชิ้นหนึ่งที่ฝังอยู่บนผนัง ดึงสายตาที่สั่นไหวของนักกีฬาให้มารวมกันที่จุดเดียว จุดเดียวที่บอกว่าจะเล็งไปทางไหน แม้แต่ผนังที่กว้างใหญ่นั้นก็ยังแคบลงเป็นเป้าที่ชัดเจนต่อหน้าชิ้นเล็กๆ นี้"},"ICON-2383":{"nm":"ปลอกเปลี่ยนกริปไม้ฮอกกี้","de":"ย้ายกริปที่มือคุ้นเคยไปสวมไว้บนไม้ใหม่ที่ยังไม่คุ้นเคย ในวินาทีนั้นเครื่องมือก็กลายเป็นของเธอในทันที ปลอกเล็กๆ ที่ให้สวมความคุ้นเคยเข้าไปโดยตรง นี่แหละคือทางลัดสู่การปรับตัว"},"ICON-2384":{"nm":"ตะขอแขวนตาข่ายประตูสนาม","de":"ต้องแขวนตาข่ายไว้กับประตูเสียก่อน ประตูจึงจะดูเป็นประตูอย่างแท้จริง สิ่งที่ยึดวินาทีสั้นๆ ที่ลูกบอลพุ่งเข้ามาเต็มตัวไว้จนถึงที่สุดเสมอมาคือตาข่าย ในตำแหน่งที่รองรับรูปทรงของเสียงเชียร์ที่ระเบิดออกมานั้น มีฉันอยู่ตรงนั้น"},"ICON-2385":{"nm":"ฝาครอบใบสเก็ต","de":"ขณะที่ใบยังคมกริบอยู่ ไม่อาจวางใจได้แม้เพียงก้าวเดียวนอกลานน้ำแข็ง เมื่อออกจากลานน้ำแข็งแล้ว โปรดสวมฉันไว้ด้วย การกล่อมความคมกริบให้หลับใหลอย่างเงียบๆ ก็เป็นมารยาทที่นักสเก็ตยึดถือมาอย่างยาวนานเช่นกัน"},"ICON-2386":{"nm":"ที่แขวนเชือกรองเท้าสเก็ต","de":"เชือกยาวๆ ของบูตที่ถอดวางไว้ เธอแขวนไว้อย่างเรียบร้อยทีละเส้น เชือกที่คลี่ไว้ไม่ให้พันกันเปิดทางสู่ลานน้ำแข็งครั้งถัดไปได้อย่างราบรื่น การจบวันนี้อย่างเรียบร้อยกลายเป็นการเตรียมตัวสำหรับวันพรุ่งนี้พอดี"},"ICON-2387":{"nm":"ผ้าเช็ดใบสเก็ต","de":"ใบมีดที่เพิ่งออกจากลานน้ำแข็งจะมีหยดน้ำเล็กๆ เกาะเป็นเม็ดๆ อยู่ เมื่อเช็ดความชื้นนั้นออกอย่างประณีต สนิมก็จะผ่านเลยไป การเก็บกวาดร่องรอยที่ความเย็นทิ้งไว้อย่างเงียบๆ นั่นแหละคือวันของฉัน"},"ICON-2388":{"nm":"แผ่นรองข้อเท้ารองเท้าสเก็ต","de":"หากข้อเท้าสั่นไหวเพียงครั้งเดียว การไถลทั้งหมดก็พังทลายลงทันที แผ่นรองที่โอบยึดไว้อย่างแน่นหนาช่วยจับการวางเท้าไว้ให้มั่นคง สมดุลอันสง่างามบนลานน้ำแข็งนั้นเริ่มต้นก่อนใครในตำแหน่งที่มองไม่เห็นเสมอ"},"ICON-2389":{"nm":"ถุงเก็บการ์ดใบสเก็ต","de":"มีถุงเล็กๆ อยู่มุมหนึ่งของกระเป๋าสำหรับเก็บการ์ดใบมีดไว้อย่างเรียบร้อย นิสัยของการจัดเตรียมสิ่งที่จำเป็นโดยไม่ตกหล่นนั้นช่วยยืดอายุอุปกรณ์ให้อยู่ได้นานแสนนาน กระเป๋าที่จัดเป็นระเบียบคือฉากแรกของการไถลที่ดี"},"ICON-2390":{"nm":"คลิปยึดพื้นรองในรองเท้าสเก็ต","de":"เพื่อไม่ให้แผ่นรองในบูตเลื่อนหลุดออกอย่างเงียบๆ มันยึดไว้แน่นใต้ฝ่าเท้า หากตำแหน่งที่วางเท้าเบี้ยวไป การกระโดดก็จะเบี้ยวตามไปด้วย มือที่ยึดตำแหน่งต่ำที่สุดไว้นั้น ในที่สุดแล้วช่วยการกระโดดที่สูงที่สุด"},"ICON-2391":{"nm":"ห่วงล็อกฝาครอบใบสเก็ต","de":"เพื่อไม่ให้ฝาครอบลื่นหลุดออกไป จึงล็อกให้แน่นหนาด้วยห่วง ฉันรู้ดีว่าการปกป้องที่หย่อนยานนั้นในที่สุดก็ไม่ใช่การปกป้องเลย ห่วงที่ล็อกไว้อย่างดีเพียงห่วงเดียวปกป้องใบมีดนั้นไว้จนถึงที่สุด"},"ICON-2392":{"nm":"ฝาล็อกเชือกรัดรองเท้าสเก็ต","de":"ดึงเชือกให้แน่นแล้วล็อกด้วยฝา ตอนนี้ก็ไม่มีวันคลายหลุดอีกแล้ว การรัดให้กระชับอย่างเรียบร้อยไม่มีช่องว่างตั้งแต่ปลายเท้า คือปมที่ผูกไว้อย่างมั่นคงที่สุด ก่อนก้าวแรกลงบนลานน้ำแข็ง"},"ICON-2393":{"nm":"ผ้าเช็ดน้ำใบสเก็ต","de":"จากใบมีดที่เพิ่งไถลจบไปหนึ่งรอบ เธอค่อยๆ เก็บความชื้นที่เกาะอยู่ออกอย่างเงียบๆ ฉันรู้ดีว่าถ้าปล่อยให้เปียกไว้ ใบมีดจะร้องไห้ มีเพียงใบมีดที่แห้งนุ่มเท่านั้น ที่จะวาดเส้นโค้งถัดไปได้อย่างชัดเจนบนลานน้ำแข็ง"},"ICON-2394":{"nm":"ฝาครอบด้ามจับไม้เท้าสกี","de":"ห่อหุ้มปลายด้ามจับไม้เท้าไว้อย่างนุ่มนวล ฝ่ามือที่กำอยู่ก็สบายขึ้นอีกขั้น พลังที่ตัดผ่านลานหิมะนั้น ในที่สุดแล้วเกิดจากตำแหน่งที่กำไว้อย่างมั่นคงนั่นเอง ฝาเล็กๆ เพียงชิ้นเดียวค้ำจุนการไถลอันยาวนานไว้จนถึงที่สุด"},"ICON-2395":{"nm":"หมุดยึดบายดิ้งสโนว์บอร์ด","de":"ในวินาทีที่หมุดเล็กๆ ที่เชื่อมกระดานกับเท้าเข้าด้วยกันหลุดออก ภูเขาที่อยู่ตรงหน้าก็หยุดนิ่งทันที ชิ้นส่วนที่ต้องตรวจสอบก่อนใครแม้จะสังเกตเห็นได้ยาก การเชื่อมต่ออันมั่นคงนี้เองที่กลายเป็นอิสรภาพบนลานหิมะ"},"ICON-2396":{"nm":"คลิปกันปลายขอบสกี","de":"เพื่อไม่ให้ขอบที่คมบาดในกระเป๋า จึงกัดปลายไว้อย่างเบามือ การกล่อมความคมให้สงบหลับใหล คือการจบท้ายอย่างอ่อนโยนที่มอบให้หลังจากลงจากภูเขามาอย่างเต็มอิ่ม"},"ICON-2397":{"nm":"การ์ดกันกระแทกหัวสโนว์บอร์ด","de":"เมื่อโอบหุ้มหัวกระดานไว้พอดี แม้การปะทะที่มาจากด้านหน้าก็กระจายไปอย่างนุ่มนวล การปกป้องตำแหน่งที่กระแทกก่อนใครไว้อย่างเงียบๆ ความกล้าที่จะเผชิญทางลาดชันนั้นเริ่มต้นตรงนี้เอง"},"ICON-2398":{"nm":"ฝาครอบหัวเข็มขัดรองเท้าสกี","de":"เพื่อไม่ให้หัวเข็มขัดเสียหายจากการกระทบกับหิมะเย็นๆ จึงคลุมไว้อย่างเบามือ กลไกล็อกอีกชั้นหนึ่งที่ปกป้องกลไกล็อก ฝาครอบเล็กๆ เพียงชิ้นเดียวนี้ยืดฤดูกาลของบูตออกไปได้อีกนิดอย่างเงียบๆ"},"ICON-2399":{"nm":"ห่วงสายรัดสโนว์บอร์ด","de":"เพื่อไม่ให้กระดานหนีไปไกลแม้หลุดจากมือ ฉันเชื่อมข้อเท้ากับกระดานไว้ด้วยเส้นเดียว แม้จะพลาดมือไป ก็ไม่สูญเสียไปในที่สุด คือห่วงแห่งความอุ่นใจอันเงียบสงบที่แขวนอยู่ปลายสายยาว"},"ICON-2400":{"nm":"ปลายที่ขูดแว็กซ์พื้นสกี","de":"แว็กซ์เก่าที่แข็งติดอยู่บนพื้น เธอรูดขูดออกอย่างเรียบเนียน ต้องขจัดสิ่งเก่าๆ ออกให้หมดจดก่อน การไถลใหม่จึงจะมีชีวิต พื้นที่ทะนุถนอมอย่างพิถีพิถันเปิดลานหิมะครั้งถัดไปให้เร็วขึ้นอีกขั้น"},"ICON-2401":{"nm":"กันกระแทกหัวสโนว์บอร์ด","de":"ก่อนที่แผ่นกระดานจะกรีดผ่านผืนหิมะ ปลายจมูกบอร์ดคือส่วนแรกที่ได้สัมผัสโลก แรงกระแทกทุกครั้งถูกยางชิ้นเล็กนี้รับไว้ก่อนใคร มันสึกกร่อนอยู่แถวหน้าสุดโดยไม่เคยโอ้อวด การไถลลงเขาของใครสักคนจึงเลื่อนไหลผ่านความเสียสละอันทื่อๆ นี้ไปอย่างเงียบงัน"},"ICON-2402":{"nm":"ห่วงตะกร้าปลายไม้สกี","de":"ในชั่ววินาทีที่ไม้เท้าเกือบจมลึกลงในหิมะ ห่วงกลมวงนี้คลำหาพื้นแทน มันประคองก้าวที่เกือบพลาดไว้อย่างเงียบๆ แม้ไม่มีใครเห็น แต่มันอยู่เคียงข้างราวมือที่คอยกันไม่ให้ลื่นไถล"},"ICON-2403":{"nm":"ฝาครอบแปรงขัดแวกซ์ขอบเลื่อน","de":"เมื่อขัดเสร็จ ก็ค่อยๆ ปิดฝาไว้ก่อนที่ผงจะแห้งกรัง เพื่อไม่ให้เส้นขนแม้แต่เส้นเดียวยุ่งเหยิง ผนึกความนุ่มนวลของวันนี้เก็บไว้ ให้ครั้งหน้าที่เปิดออกอีกครั้ง ความเอาใจใส่ของเมื่อวานยังคงรอคอยอยู่เหมือนเดิม"},"ICON-2404":{"nm":"ตะขอแขวนที่ปิดหูกันหนาว","de":"จำได้ไหม ที่ปิดหูที่เคยถูกลืมไว้ข้างกระเป๋าเมื่อฤดูใบไม้ผลิมาเยือน แต่พอคืนที่ได้ยินข่าวหิมะแรกตก มันกลับเป็นสิ่งแรกที่ถูกเรียกหา มีที่ทางเฉพาะไว้แขวนฤดูกาล และตะขอวงนี้ไม่เคยลืมคำสัญญานั้น"},"ICON-2405":{"nm":"ที่เก็บหินลับมีด","de":"จะลับมีดให้คมต้องแช่หินให้ชุ่มน้ำก่อนเสมอ ลำดับขั้นที่ซึมลึกราวกับฝีมือของยาย แม้เครื่องมือที่คอยปราบความทื่อยังต้องมีที่พักของตัวเอง กล่องเล็กๆ ใบนี้จึงโอบอุ้มหินลับไว้ รอการดูแลครั้งต่อไป"},"ICON-2406":{"nm":"ถุงเก็บก้อนแวกซ์","de":"วัตถุดิบที่สร้างการไถลอันเจิดจรัส กลับหลับนิ่งจับตัวแข็งอยู่ภายในของตัวเอง ความหนักแน่นที่โอบก้อนแวกซ์แข็งไว้ การไถลลื่นเสมอคลี่คลายออกมาจากน้ำหนักอันสงบนี้ แผ่ซ่านไปทั่วลานหิมะ"},"ICON-2407":{"nm":"ห่วงคล้องถุงใส่กระเป๋าไฟ","de":"ระหว่างเดินเล่นยามหนาว นิ้วมือมักคลำหาตำแหน่งนี้เป็นที่แรกในกระเป๋า มันมอบบ้านที่แน่นอนให้ความอุ่นเล็กๆ ที่คอยละลายมือที่แข็งเย็น ยิ่งวันหนาวเท่าไร ห่วงเล็กๆ วงนี้ก็ยิ่งอ่อนโยนขึ้นเท่านั้น"},"ICON-2408":{"nm":"ฐานรองหินลับปลายใบมีด","de":"หากสั่นไหวใบมีดก็จะเบี้ยว มันจึงยึดตัวเองให้มั่นคงก่อนเป็นอันดับแรก ฐานที่ไม่เคยขยับแม้แต่น้อย เพื่อรับผิดชอบความแม่นยำของผู้อื่น ปลายมีดที่ตรงเป๊ะของใครสักคนจึงยืนอยู่บนความสงบนิ่งนี้"},"ICON-2409":{"nm":"คลิปหนีบปลอกคอกันหนาว","de":"ระหว่างเดินไปโรงเรียนในลมหนาว ทันทีที่ปลอกคอกันหนาวเริ่มจะเลื่อนหลุด เสียงคลิกก็ดังขึ้นที่ปกเสื้อ แม้แต่ความอบอุ่นก็ต้องรักษาตำแหน่งของตัวเองไว้ให้ได้ก่อน จึงจะอุ่นได้อย่างแท้จริง เสียงเล็กๆ เพียงครั้งเดียวช่วยกักเก็บไอความอุ่นของเช้าวันนั้นไว้"},"ICON-2410":{"nm":"ผ้าคลุมเตารีดแวกซ์","de":"ขณะที่พื้นผิวซึ่งทำงานร้อนจัดค่อยๆ เย็นลง ผ้าผืนหนึ่งเฝ้าปกป้องมันจากฝุ่นละอองอย่างเงียบๆ เครื่องมือชิ้นหนึ่งดูแลอีกชิ้นที่เตรียมการไถลไว้ให้ ความเอาใจใส่จึงดำเนินต่อไปอย่างเงียบเชียบเช่นนี้"},"ICON-2411":{"nm":"ฝาปากกาน้ำมันหล่อลื่นขอบใบมีด","de":"เปิดใช้เพียงครั้งเดียวแล้วแห้งแข็ง ก็ไม่อาจขีดเส้นต่อไปได้อีก ดังนั้นการปิดฝาจึงเท่ากับการเปิดครั้งต่อไป ฝาเล็กๆ ใบนี้ผนึกความชุ่มชื้นที่ปลายปากกาไว้ เป็นดั่งคำสัญญาล่วงหน้าถึงเส้นขีดของวันพรุ่งนี้"},"ICON-2412":{"nm":"หัวพู่ปอมปอมเชียร์","de":"เส้นพู่นับร้อยเส้นเริ่มต้นจากจุดเดียวนี้ แล้วสะบัดพร้อมกันไปตามจังหวะ ความอลังการของการโบกไสวเริ่มต้นจากจุดที่ผูกแน่นเสมอ ใต้เวที คือปมแรกที่ทำให้อัฒจันทร์เป็นคลื่น"},"ICON-2413":{"nm":"สายคล้องมือแท่งไฟเชียร์","de":"หลังโห่ร้องมาสองชั่วโมงจนแท่งไฟเกือบหลุดมือ สายเส้นนี้จะดึงมันกลับคืนสู่ฝ่ามือ ความปรารถนาที่ไม่อยากทำหายแม้จะร่วงหล่นไป ความกระวนกระวายอันอ่อนโยนนั้นก่อเป็นห่วงคล้องอยู่บนข้อมือ"},"ICON-2414":{"nm":"ตัวล็อกพับเบาะรองนั่งอัฒจันทร์","de":"ลุกขึ้นเชียร์แล้วนั่งลงซ้ำแล้วซ้ำเล่านับสิบครั้ง ระหว่างนั้นตัวล็อกเล็กๆ นี้พับเบาะให้เรียบร้อยและรักษาที่นั่งไว้ให้ แม้ในอัฒจันทร์ที่คึกคักก็ยังมีมือที่คอยดูแลที่นั่งของใครสักคนซ่อนอยู่"},"ICON-2415":{"nm":"ห่วงผ้าพันคอเชียร์","de":"ในวันที่ลวดลายเดียวกันแผ่ปกคลุมทั่วอัฒจันทร์ ผ้าผืนเดียวผูกใจนับหมื่นดวงให้เป็นสีเดียวกัน จุดแรกที่คลื่นนั้นเริ่มต้นคือห่วงเล็กๆ วงนี้ เป็นจุดที่การเชียร์อันโดดเดี่ยวกลายเป็น \"พวกเรา\""},"ICON-2416":{"nm":"แผ่นตบมือเชียร์","de":"ตบเพียงลำพังเสียงย่อมเบา แต่เมื่อรวมกันทั่วอัฒจันทร์กลับกลายเป็นคลื่น หนึ่งในสองแผ่นที่รู้ความจริงอย่างซื่อตรงที่สุดว่า มันจะดังขึ้นก็ต่อเมื่อได้พบกับอีกฝ่าย เมื่อเสียงปรบมือของเธอมาพบกับของฉัน การเชียร์จึงยิ่งใหญ่ขึ้น"},"ICON-2417":{"nm":"ฝาครอบมุมป้ายเชียร์","de":"มันห่อหุ้มมุมแหลมให้มนขึ้น เพื่อไม่ให้คนข้างๆ ได้รับบาดเจ็บ แม้ในใจที่โบกป้ายอย่างเร่าร้อนก็ยังแฝงความเอื้ออาทรต่อกันไว้ การเชียร์จะยิ่งอบอุ่นขึ้นในความมนกลมเช่นนี้"},"ICON-2418":{"nm":"ที่เสียบด้ามธงริบบิ้นเชียร์","de":"แม้ในวินาทีที่การโบกสะบัดหยุดลง ด้ามธงยังคงยืนตรง รอคอยเสียงโห่ร้องครั้งต่อไป คือที่พักชั่วครู่อันสงบนิ่งก่อนจะโบกไสวอีกครั้ง ระหว่างเสียงเชียร์แต่ละครั้ง คือความเงียบสั้นๆ ที่ริบบิ้นได้พักหายใจ"},"ICON-2419":{"nm":"พัดขยายเสียงเชียร์","de":"เพื่อให้เสียงตะโกนของคนเพียงคนเดียวไปถึงสุดขอบเวที รูปทรงพัดช่วยรวมทางเดินของเสียงให้แคบลง ปากที่ครุ่นคิดถึงวิธีส่งสารมากกว่าขนาดของหัวใจเสมอ เป็นรูปทรงที่เกิดจากความปรารถนาอยากไปให้ไกลกว่านี้อีกสักนิด"},"ICON-2420":{"nm":"ที่เก็บเข็มกลัดหลังตราเชียร์","de":"ก่อนติดที่หน้าอกและหลังจากถอดออก การพักผ่อนของตราเข็มกลัดเริ่มต้นและสิ้นสุดที่นี่ กล่องเล็กๆ ที่กักเก็บเข็มแหลมด้านหลังไว้อย่างปลอดภัย แม้แต่จุดแวววาวจุดหนึ่งก็ยังต้องการที่ให้นอนพักสักครู่"},"ICON-2421":{"nm":"แผ่นตัวเลขป้ายคะแนน","de":"มันซึมซับความเอาใจใส่ของยุคที่ต้องสับเปลี่ยนด้วยมือทุกครั้งที่ทำประตูได้ ก่อนยุคดิจิทัล ผลการแข่งขันถูกสลักทีละช่องด้วยปลายนิ้วมนุษย์ แผ่นที่แม้แต่ตัวเลขเดียวก็บรรจุความตื่นเต้นของใครสักคนไว้"},"ICON-2422":{"nm":"หมากแม่เหล็กกระดานแผนการเล่น","de":"ตามปลายนิ้วโค้ช ฝ่ายรับและฝ่ายรุกสลับตำแหน่งกัน ภาพทุกภาพในหัวก่อนการแข่งขันถูกวาดขึ้นก่อนในการเคลื่อนไหวของจุดเล็กๆ เหล่านี้ ผลแพ้ชนะถูกคลี่คลายไว้ล่วงหน้าครั้งหนึ่งบนกระดานนี้"},"ICON-2423":{"nm":"กันแดดบังแสงป้ายคะแนน","de":"เพื่อไม่ให้ตัวเลขที่แสบตาบดบังสายตานักกีฬา กันแดดจึงตัดแสงนั้นออกไป แม้แต่ความสว่างบางครั้งก็ต้องถูกบังพอเหมาะจึงจะทำหน้าที่ของมันได้ ในที่ที่สว่างที่สุด คือเงาที่ทำงานเงียบที่สุด"},"ICON-2424":{"nm":"ห่วงพลิกแผ่นคะแนน","de":"ทุกครั้งที่พลิกแผ่นทีละแผ่น ตัวเลขก็เปลี่ยนไปและเสียงเชียร์ก็ดังตามขึ้นมา ร่องรอยของยุคอนาล็อกที่บันทึกผลด้วยสัมผัสของมือ ยุคที่หัวใจพลิกตามไปพร้อมกับเสียงคะแนนที่พลิกผ่าน"},"ICON-2425":{"nm":"ที่เก็บปากกาวาดเส้นแผนการเล่น","de":"เส้นทางที่วาดไว้บนไวท์บอร์ดในห้องล็อกเกอร์ล้วนมาจากปากกาด้ามนี้ กล่องเก็บเล็กแต่แข็งแรงที่โอบภาพร่างของชัยชนะไว้ ในความเงียบก่อนศึกใหญ่ นี่คือจุดที่อุ้มคำพูดไว้มากที่สุด"},"ICON-2426":{"nm":"ตัวนับคะแนนคลิก","de":"ทุกครั้งที่กด ตัวเลขจะเพิ่มขึ้นทีละช่องพร้อมเสียงคลิกที่ชัดเจน เมื่อฝากตัวเลขไว้กับนิ้วมือ หัวใจก็จะมุ่งไปที่การแข่งขันได้อย่างเต็มที่ เป็นจังหวะเล็กๆ ที่ช่วยปลดภาระของการนับ"},"ICON-2427":{"nm":"ฝาปิดสายไฟป้ายคะแนน","de":"เบื้องหลังแสงไฟอันตระการตามักมีสายไฟยุ่งเหยิงไม่เป็นระเบียบซ่อนอยู่เสมอ งานของการปิดคลุมความยุ่งเหยิงนั้นให้เรียบร้อย ต้องจัดที่มองไม่เห็นให้เป็นระเบียบก่อน ที่ที่มองเห็นจึงจะส่องประกายได้อย่างแท้จริง"},"ICON-2428":{"nm":"แปรงลบกระดานแผนการเล่น","de":"เมื่อจบเกมหนึ่ง พื้นผิวก็ถูกเช็ดให้ว่างเปล่าเพื่อภาพต่อไป กลยุทธ์ใหม่จะเริ่มต้นได้ก็บนพื้นที่ว่างเปล่าเท่านั้นเสมอ แปรงที่ลบนั้นแท้จริงแล้วคือพู่กันแรกของแผนการเล่นครั้งต่อไป"},"ICON-2429":{"nm":"คลิปหนีบธงบอกคะแนน","de":"มันกัดธงที่กำลังจะปลิวไปตามลมไว้อย่างมั่นคงไม่ปล่อย เพื่อให้ผ้าที่สะบัดไสวยังคงอยู่ที่เดิม แม้แต่การประกาศผลบันทึกให้โลกรู้ก็ยังต้องอาศัยมือหนึ่งที่คอยยึดไว้ให้มั่นก่อน"},"ICON-2430":{"nm":"คลิปหนีบสายนกหวีดกรรมการ","de":"เพียงเสียงนกหวีดครั้งเดียว เกมก็หยุดและไหลต่อไปอีกครั้ง ปมเล็กๆ ที่ผูกอำนาจนั้นไว้แน่นกับลำคอ ก่อนเสียงนกหวีดจะดังขึ้น การผูกความเงียบให้เป็นระเบียบก็เป็นหน้าที่ของคลิปตัวนี้เช่นกัน"},"ICON-2431":{"nm":"แกนม้วนสายวัด","de":"มันม้วนเก็บความยาวที่วัดไว้กลับเข้าสู่ตัวมันเอง การวัดคือการทำซ้ำของการคลี่ออกและม้วนกลับในที่สุด ด้ามจับที่ช่วยการเดินทางไปกลับอันเรียบง่ายนั้นโดยไม่บ่นสักคำ หมุนอยู่เบื้องหลังความแม่นยำทุกครั้ง"},"ICON-2432":{"nm":"ที่เก็บพับธงตัดสิน","de":"ธงที่เคยแบ่งเส้นในและนอกอย่างเด็ดขาด เมื่อเกมจบลงก็พับเก็บอย่างเรียบร้อยและพักผ่อน แม้สัญญาณที่ชัดเจนนั้นก็ยังต้องหายใจสักครู่ก่อนครั้งต่อไป แม้แต่ความเด็ดขาดก็ยังมีการพักผ่อนอันเงียบสงบ"},"ICON-2433":{"nm":"ห่วงแขวนนาฬิกาจับเวลา","de":"มันแขวนเวลาที่ไหลผ่านไว้ ณ ที่แห่งเดียว ไม่ใช่บนข้อมือ นิ่งสงบก่อนการจับเวลา แล้ววิ่งออกทันทีเมื่อถูกเรียก คือสถานีของเวลา บ้านเล็กๆ ของวินาทีที่กลั้นลมหายใจรอสัญญาณเริ่มต้น"},"ICON-2434":{"nm":"ล้อขีดเส้นสนามแข่ง","de":"ทุกที่ที่มันหมุนผ่าน เส้นสีขาวจะปรากฏชัดเจน ขอบเขตของกฎกติกาถูกสลักลงบนพื้นดินทีละรอบเช่นนี้อย่างเป็นระเบียบ ก่อนเกมจะเริ่มขึ้น คือล้อที่ทิ้งรอยเท้าแรกไว้บนสนาม"},"ICON-2435":{"nm":"กระเป๋าใส่การ์ดกรรมการ","de":"ในวินาทีแห่งการตัดสิน การ์ดใบที่หยิบออกจากอกเสื้อเคยหลับใหลอยู่ที่นี่ ห้องรอของคำตัดสินที่นิ่งเงียบจนถึงวินาทีสุดท้ายก่อนถูกเปิดเผย กระเป๋าที่พร้อมและรอคอยเสมอ พร้อมหวังว่าจะไม่มีวันถูกหยิบออกมา"},"ICON-2436":{"nm":"ฐานรองตุ้มน้ำหนักตาชั่ง","de":"งานชั่งน้ำหนักจะซื่อตรงได้ก็บนพื้นที่ไม่สั่นไหวเท่านั้น ฐานที่รองรับตุ้มน้ำหนักไว้พร้อมมอบตัวเองให้เรียบเสมอ ก้าวแรกของการวัดที่แม่นยำเริ่มต้นจากที่ที่สงบนิ่งเสมอ"},"ICON-2437":{"nm":"เครื่องดีดสัญญาณเริ่มวิ่ง","de":"เพียงเสียงเดียว เท้าทุกคู่ก็พุ่งออกจากพื้นพร้อมกัน จุดเริ่มต้นสั้นมาก แต่มือที่สร้างความสั้นนั้นกลับสงบนิ่งกว่าใคร มือที่คลี่คลายความสั่นสะเทือนของเส้นสตาร์ทด้วยเสียงคลิกเพียงครั้งเดียว"},"ICON-2438":{"nm":"ฐานตั้งกรวยสนามแข่ง","de":"ชื่ออาจไม่คุ้นหู แต่หน้าที่ชัดเจน มันแบกรับใจกลางสนามที่เหมือนเวทีไว้อย่างหนักแน่น ณ ใจกลางที่ทุกคนต่างเปล่งประกาย มักมีขาที่มองไม่เห็นข้างหนึ่งคอยทานทนอยู่อย่างเงียบๆ เสมอ"},"ICON-2439":{"nm":"หัวเข็มขัดฝึกหายใจกระบังลม","de":"เสียงที่ดีไม่ได้มาจากลำคอแต่มาจากลมหายใจลึกๆ เอวรู้เรื่องนี้ก่อนใคร หัวเข็มขัดที่ให้ฝ่ามือได้สัมผัสท้องที่พองและยุบ จุดเริ่มต้นของบทเพลงอยู่ใต้ลมหายใจครั้งนี้เสมอ"},"ICON-2440":{"nm":"แผ่นขนนกฝึกหายใจ","de":"เมื่อขนนกไหวเอนไปตามลมหายใจ นั่นคือสัญญาณว่าลมหายใจสม่ำเสมอแล้ว มันค่อยๆ ให้รูปทรงกับลมหายใจที่มองไม่เห็น สอนพื้นฐานของบทเพลง เป็นการฝึกที่เรียนรู้ลมหายใจก่อนโน้ตแรกด้วยดวงตา"},"ICON-2441":{"nm":"นาฬิกาทรายฝึกหายใจเข้า","de":"ในหลอดแก้ว เม็ดทรายไหลลงมาราวกับลมหายใจ หายใจเข้า หยุดชั่วครู่ แล้วค่อยๆ ผ่อนออก เม็ดทรายนับจังหวะแทนให้ เฝ้ามองเม็ดทรายที่ร่วงลงอย่างไร้เสียงสักพัก แล้วจู่ๆ ลมหายใจที่เคยยุ่งเหยิงก็เรียบเรียงเข้าที่"},"ICON-2442":{"nm":"ฐานวางเทียนฝึกร้อง","de":"จุดไส้เทียนแล้วเปลวไฟที่ไหวสั่น เสียงร้องก็สั่นไหวตามไปด้วย ใครสักคนแกะสลักที่แห่งนี้ไว้อย่างพิถีพิถัน เพื่อรองรับความสั่นไหวเล็กๆ นั้นไว้สักครู่ หยดขี้ผึ้งที่แข็งตัวสะสมหนาขึ้นเท่าไร ที่นี่ก็ยิ่งขังคืนที่ร้องเพลงอยู่คนเดียวไว้มากเท่านั้น"},"ICON-2443":{"nm":"สายรัดเบาะกดหน้าท้อง","de":"แทนที่จะวางมือบนท้อง สายเส้นหนึ่งกดตำแหน่งนั้นไว้อย่างเงียบๆ เมื่อลมหายใจพองขึ้นก็ดึงตึง เมื่อปล่อยออกหมดก็ค่อยๆ คลายลง เพื่อนตัวเล็กไร้เสียงที่คอยช่วยให้ร่างกายจดจำจังหวะได้ก่อนใคร"},"ICON-2444":{"nm":"ฝาลูกโป่งฝึกกลั้นลมหายใจ","de":"อย่าเป่าลูกโป่งจนหมดในครั้งเดียว ลองเป่ายาวๆ ช้าๆ ไปจนสุด ขณะกัดฝาไว้แล้วปล่อยลมออก อากาศจะเข้าไปถึงส่วนลึกที่สุดของปอด สุดท้ายแล้วบทเพลงจะโบยบินไปได้ไกลเท่ากับความยาวของลมหายใจที่คุณอดทนกลั้นไว้"},"ICON-2445":{"nm":"ที่จับฝึกปรับลมหายใจ","de":"ยิ่งใจสั่นไหว มือก็ยิ่งอยากกำอะไรสักอย่างไว้แน่นๆ กำที่จับนี้แล้วไหล่จะค่อยๆ ผ่อนลง ลมหายใจเข้าจะยาวขึ้นอีกหนึ่งคืบ การเรียนรู้วิธีกำมือก็คือการเรียนรู้วิธีสงบสติของตนเอง ฝ่ามือรู้เรื่องนี้ก่อนใคร"},"ICON-2446":{"nm":"ห่วงสายสั่นสะเทือนกล้ามท้อง","de":"คล้องสายเข้ากับห่วงแล้วแรงสั่นสะเทือนแผ่วเบาจะแผ่ไปทั่วกลางท้อง แรงจะค่อยๆ รวมตัวอย่างเงียบๆ ตรงจุดเดียวกับที่สั่นไหวเวลาหัวเราะดังๆ แกนกลางที่แข็งแรงเติบโตอย่างช้าๆ เช่นนี้เสมอ ในที่ที่ไม่มีใครมองเห็น"},"ICON-2447":{"nm":"หน้าปัดนับลมหายใจเข้า","de":"หนึ่ง สอง สาม ทุกครั้งที่หน้าปัดหมุนไปทีละช่อง ความลึกของลมหายใจที่สูดเข้าก็ถูกจารึกไว้ เมื่อตัวเลขเพิ่มขึ้นอีกหนึ่งช่อง บทเพลงก็ยืนหยัดได้อีกหนึ่งวรรค บนหน้าปัดเล็กๆ นี้ ความจุปอดที่ฝึกฝนมาในวันนี้ถูกบันทึกไว้อย่างเงียบๆ"},"ICON-2448":{"nm":"แผ่นช้อนฝึกลิ้น","de":"ตำแหน่งที่ปลายลิ้นควรแตะถูกสลักไว้บนแผ่นอย่างชัดเจนทีละจุด วิธีกลิ้ง ดีด และหยุดชั่วครู่ เบื้องหลังการออกเสียงที่ไหลลื่นราบรื่น ซ่อนรุ่งอรุณนับไม่ถ้วนที่ลิ้นได้จดจำเส้นทางไว้เช่นนี้"},"ICON-2449":{"nm":"คลิปหนีบกระจกฝึกรูปปาก","de":"คลิปจับรูปปากที่สะท้อนในกระจกไว้อย่างแผ่วเบา \"อา\" กลม \"อี\" ยืดยาวออกไปสองข้าง บทเรียนเงียบๆ ที่มีแค่กระจกกับตัวเอง เผชิญหน้ากับใบหน้าของตนเองตรงๆ เพื่อขัดเกลารูปทรงของเสียง"},"ICON-2450":{"nm":"แมวน้ำไม้ก๊อกฝึกออกเสียง","de":"แมวน้ำตัวเล็กที่แกะจากไม้ก๊อกนั่งอยู่มุมโต๊ะ คอยฟังการออกเสียง ในคืนที่เสียง \"ร\" ลื่นหลุดซ้ำแล้วซ้ำเล่าจนท้อใจ ดวงตากลมโตของแมวน้ำเอ่ยขึ้นเบาๆ ว่า ไม่เป็นไร ลองอีกสักครั้งนะ"},"ICON-2451":{"nm":"เข็มหมุดทำเครื่องหมายจุดหายใจในเนื้อเพลง","de":"เข็มหมุดนี้บอกก่อนใครว่าจะหายใจตรงไหนในเนื้อเพลง ปักไว้ที่ท้ายบรรทัดแล้วตำแหน่งนั้นก็กลายเป็นเครื่องหมายจุลภาคอันอ่อนโยนของบทเพลง หากอยากร้องอย่างเต็มที่ แม้แต่ประโยคก็ต้องมีช่องว่างเว้นวรรคไว้หายใจสักหนึ่งช่อง"},"ICON-2452":{"nm":"ที่รองคางฝึกออกเสียง","de":"เพียงพยุงคางไว้เบาๆ การออกเสียงที่กำลังจะกระจัดกระจายก็กลับเข้าที่ การพูดให้ชัดเจนไม่ใช่งานของปากเพียงอย่างเดียว แต่เป็นงานที่คาง ลำคอ และลมหายใจร่วมกันสร้าง ที่รองเล็กๆ ชิ้นนี้ช่วยประคองความสมดุลอันยากเย็นนั้นอย่างเงียบๆ"},"ICON-2453":{"nm":"ขาตั้งแม่พิมพ์รูปปากสระ","de":"อา เอ อี โอ อู ห้าเสียงสระ กรอบที่ตั้งเส้นทางที่เสียงเหล่านี้ผ่านออกจากปากไว้อย่างครบถ้วน วางไว้ข้างกระจกเงียบๆ แล้วขึ้นโครงเสียงทุกวัน ไม่ว่าบทเพลงใด โครงสร้างของมันเริ่มต้นจากห้าสระนี้เสมอ"},"ICON-2454":{"nm":"การ์ดฝึกลิ้นพันกัน","de":"การ์ดที่อ่านแล้วลิ้นพันจนหัวเราะออกมาในที่สุด ผิดพลาดก็ไม่เป็นไรจริงๆ เพราะความผิดพลาดคือการฝึกฝนนั่นเอง ทุกครั้งที่ผ่านประโยคแสนซนใบนี้ไปได้ เสียงหนึ่งจะตื่นขึ้นอย่างชัดเจนอีกครั้ง"},"ICON-2455":{"nm":"ปลั๊กคลายกล้ามปาก","de":"การวอร์มอัพที่สั่นริมฝีปากปลุกมุมปากที่แข็งค้าง กัดปลั๊กแล้วปล่อยลมออกยาวๆ ริมฝีปากที่หลับใหลก็คลายตัวนุ่มนวลขึ้น เป็นการวอร์มอัพเล็กที่สุดและอ่อนโยนที่สุดเพื่อเปิดวรรคแรกอย่างนุ่มนวล"},"ICON-2456":{"nm":"ยางรัดจุดยากในเนื้อเพลง","de":"พันยางรัดไว้ตรงช่วงที่ติดขัดซ้ำๆ ทุกครั้งที่เห็นจุดนั้นบนข้อมือ ภูเขาที่ต้องข้ามผ่านในวันนี้ก็ผุดขึ้นในใจ ยิ่งท่อนยาก ยิ่งมองบ่อยขึ้น และยิ่งเก็บไว้ในใจนานขึ้น"},"ICON-2457":{"nm":"ห่วงแขวนผ้าพันคออุ่นคอ","de":"เพื่อไม่ให้เสียงแหบในอากาศยามเช้าตรู่ของฤดูเปลี่ยน ผ้าพันคอจึงถูกแขวนไว้แน่นหนากับห่วงนี้ เสียงใสจะคลี่คลายออกมาได้ก็จากลำคอที่ห่มอุ่นเท่านั้น การรักษาเสียงเริ่มจากการทะนุถนอมลำคอก่อนเสมอ"},"ICON-2458":{"nm":"หัวโรลเลอร์สั่นสะเทือนสายเสียง","de":"เมื่อปลายโรลเลอร์กลิ้งช้าๆ ไปตามข้างลำคอ สายเสียงที่หลับใหลทั้งคืนก็ค่อยๆ ตื่นขึ้น แรงสั่นสะเทือนเบาๆ คลายความตึงเครียดที่แข็งค้าง โน้ตแรกที่เคยลังเลก็นุ่มนวลขึ้น สัมผัสที่อุ่นร่างกายก่อนร้องเพลง"},"ICON-2459":{"nm":"จานรองแก้วฮัมเพลงวอร์มเสียง","de":"หุบปากฮัมเบาๆ กอบแก้วอุ่นที่มีไอลอยฟุ้งไว้ในสองมือ ลำคอก็อุ่นขึ้นตามไปด้วย เสียงฮัมแผ่วเบากระจายเป็นวงกลมบนจานรองแก้ว บทเพลงเริ่มต้นเช่นนี้ จากไออุ่นอ่อนๆ เพียงหนึ่งจิบ"},"ICON-2460":{"nm":"แคปซูลเก็บลูกอมบำรุงคอ","de":"สำหรับวันที่ลำคอแห้งคันจนแสบ ลูกอมถูกเก็บรวมไว้อย่างเงียบๆ ในแคปซูล อมสักเม็ดก่อนขึ้นเวที กลิ่นมินต์เย็นซ่าจะเปิดลำคอที่อุดตันให้โล่งสบาย ความปลอบใจฉุกเฉินส่วนตัวที่บรรจุไว้ในกระปุกใบเล็ก"},"ICON-2461":{"nm":"ถุงประคบไอน้ำอุ่นคอ","de":"พันถุงที่ซึมซาบไอน้ำอุ่นไว้รอบคอ จุดที่แข็งเกร็งจากการฝึกซ้อมนานก็ค่อยๆ ละลายลงอย่างนุ่มนวล ด้วยความอบอุ่นเหมือนผ้าขนหนูที่เพิ่งอุ่นใหม่ๆ มันมอบจังหวะพักผ่อนให้สายเสียงที่อ่อนล้าอย่างแผ่วเบา"},"ICON-2462":{"nm":"นาฬิกาทรายพักสายเสียง","de":"คำสัญญาที่ตั้งใจไว้เงียบๆ ว่าวันนี้จะไม่พูด ถูกนับให้อย่างแผ่วเบาโดยเม็ดทรายละเอียด การหุบปากสักครู่และถนอมเสียงไว้ ช่วงเวลาอันสงบนิ่งนั้นซึ่งก็คือการดูแลที่ดีที่สุดเช่นกัน ไหลผ่านไปอย่างช้าๆ ที่นี่"},"ICON-2463":{"nm":"ปลั๊กฝึกสั่นริมฝีปากวอร์มเสียง","de":"ลิปทริลที่สั่นริมฝีปากเบาๆ ไล่ขึ้นลงตามโน้ต กัดปลั๊กไว้เบาๆ แล้วความสั่นที่เคยไร้ทิศทางก็นิ่งขึ้นสม่ำเสมอ เครื่องมือชิ้นเล็กขนาดเท่าฝ่ามือที่ติดกระดุมเม็ดแรกของการเปล่งเสียงให้อย่างนุ่มนวล"},"ICON-2464":{"nm":"ฝาสเปรย์เพิ่มความชุ่มชื้นคอ","de":"เพื่อไม่ให้ลำคอแห้งผากบนเวทีที่แห้งแล้ง กดฝาแล้วพ่นละอองน้ำละเอียดออกมาหนึ่งสาย สูดอากาศชื้นเข้าไปลึกๆ สักครั้ง เสียงที่เคยแห้งกร้านก็กลับมาเป็นประกายใสอีกครั้ง"},"ICON-2465":{"nm":"ลูกบอลสั่นสะเทือนคลายเสียง","de":"กำลูกบอลที่สั่นสะเทือนเบาๆ ไว้นิ่งๆ บนฝ่ามือ แรงสั่นนั้นจะไหลขึ้นตามแขนไปถึงลำคออย่างนุ่มนวล เพื่อนวอร์มอัพทรงกลมแสนอ่อนโยนที่ค่อยๆ เขย่าปลุกอวัยวะเปล่งเสียงที่แข็งค้างจากความตึงเครียด"},"ICON-2466":{"nm":"หมุดจุดฟอร์เมชั่น","de":"หมุดเล็กๆ ปักลงบนพื้นเวทีจุดหนึ่ง ที่ตรงนี้คือของเธอ ที่ตรงนั้นคือของฉัน เมื่อหลายคนมารวมกันวาดภาพเดียวกัน มันยึดทุกคนไว้อย่างเงียบๆ ไม่ให้ใครกระจัดกระจาย คือคำสัญญาที่มองไม่เห็น"},"ICON-2467":{"nm":"ชิปหัวลูกศรบอกทิศทางเดิน","de":"ชิปรูปหัวลูกศรชี้ทิศทางของก้าวต่อไปอย่างชัดเจน จะหมุนที่ไหน จะหยุดตรงไหน พื้นเวทีบอกก่อนเสมอเพื่อไม่ให้หลงทาง เส้นทางเดินคือแผนที่ที่ปลายเท้าจดจำไว้จากการเหยียบย่ำนับครั้งไม่ถ้วน"},"ICON-2468":{"nm":"เข็มหมุดจุดศูนย์กลางฟอร์เมชั่น","de":"จุดเดียวที่กลายเป็นหลักอ้างอิงอย่างเงียบๆ เมื่อหลายคนมารวมตัวกัน รอบเข็มหมุดนี้วงกลมถูกวาดขึ้นเป็นวงกลม และฟอร์เมชั่นก็คลี่กว้างออก แม้การเคลื่อนไหวที่กระจัดกระจายก็ยังพบระเบียบของตัวเองได้เพียงมีจุดศูนย์กลางจุดเดียว"},"ICON-2469":{"nm":"ลิ่มจุดตัดทางเดิน","de":"ตรงจุดที่เส้นทางสองสายมาบรรจบกัน ลิ่มถูกตอกลงอย่างมั่นคง เพื่อไม่ให้ชนกัน เพื่อไม่ให้พลาดสวนทางกัน แม้ในวินาทีสั้นๆ ที่สวนผ่านกันอย่างหอบหายใจ ก็ไม่มีใครหลงทาง"},"ICON-2470":{"nm":"ธงบอกทิศทางออกจากเวที","de":"เมื่อเสียงสะท้อนของโน้ตสุดท้ายจางหายไป ก็ค่อยๆ เดินออกไปทางที่ธงชี้อย่างเงียบๆ เพราะตอนออกก็ต้องไม่ยุ่งเหยิงพอๆ กับตอนเข้า แม้แต่ตอนจบของเวทีก็ยังมีทิศทางที่ตกลงกันไว้ล่วงหน้า"},"ICON-2471":{"nm":"คลิปหนีบสายวัดระยะห่าง","de":"หนีบปลายสายวัดไว้แน่นด้วยคลิป แล้วคืบแล้วคืบเล่าก็แม่นยำไม่มีพลาด แม้แต่ระยะห่างระหว่างคนกับคนก็ถูกจัดให้เป็นระเบียบราวกับวัดด้วยไม้บรรทัด ภาพที่ดูสวยงามหนึ่งภาพเกิดจากปลายนิ้วที่พิถีพิถันเช่นนี้เสมอ"},"ICON-2472":{"nm":"ห่วงเชือกอ้างอิงจัดแถว","de":"คล้องเชือกกับห่วงแล้วดึงให้ตึงเป็นเส้นเดียว เส้นเล็กๆ นั้นกลายเป็นมาตรฐานให้ทุกคนยืนเรียงเคียงกัน ภาพที่ยืนเรียงแถวดูเป็นระเบียบขนาดนั้น ก็เพราะเส้นตรงที่มองไม่เห็นเส้นนี้เพียงเส้นเดียว"},"ICON-2473":{"nm":"ชิ้นเส้นประบอกเส้นทางเคลื่อนที่","de":"ชิ้นส่วนที่ค่อยๆ วาดเส้นทางเป็นเส้นประไว้บนพื้นอย่างเงียบๆ เดินตามรอยจางๆ เหล่านี้ไปแล้วจะไม่หลงแม้ในความมืด ระหว่างที่เชื่อมจุดต่อจุดไปทีละจุด ก้าวเท้าที่กระจัดกระจายก็ร้อยเรียงเป็นกระแสเดียวกัน"},"ICON-2474":{"nm":"หมุดปักพื้นบอกตำแหน่ง","de":"หมุดที่กดปักลงบนพื้นเพื่อไม่ให้ลืมตำแหน่งของตัวเอง แม้ในความมืดมิด ปลายเท้าก็คลำหาปุ่มเล็กนั้นจนพบได้เสมอ เมื่อหยุดยืนตรงจุดนั้นพอดี แสงไฟจึงจะสาดส่องลงมาเหนือศีรษะในที่สุด"},"ICON-2475":{"nm":"แถบฝึกแยกการเคลื่อนไหวคอ","de":"หากคางส่ายตาม เสียงก็จะสั่นและกระจัดกระจายไปด้วย เพื่อฝึกให้ศีรษะนิ่งและขยับเฉพาะลำคอ จึงพันแถบนี้ไว้ เบื้องหลังท่วงท่าที่ดูอิสระเสรีที่สุด มีการฝึกแยกส่วนอย่างเงียบๆ เช่นนี้ซ่อนอยู่"},"ICON-2476":{"nm":"คลิปหนีบเบาะยึดไหล่","de":"เพื่อไม่ให้ไหล่ยกขึ้นตามใจตัวเอง เบาะจึงถูกคลิปยึดไว้นิ่งๆ เพื่อให้ร่างกายแยกแยะได้ชัดเจนว่าที่ไหนควรไหวและที่ไหนควรนิ่ง เส้นสายที่สง่างามมักถือกำเนิดจากการควบคุมเล็กๆ เช่นนี้เสมอ"},"ICON-2477":{"nm":"หัวเข็มขัดรับรู้การขยายซี่โครง","de":"เข็มขัดนี้อ่านลายละเอียดของซี่โครงที่ขยายออกและหุบกลับเข้ามาอย่างเงียบๆ รัดหัวเข็มขัดแล้วการเคลื่อนไหวของลมหายใจจะส่งผ่านไปถึงปลายนิ้วอย่างชัดเจน การเปล่งเสียงที่ลึกและหนักแน่นเกิดจากการเคลื่อนไหวของกระดูกที่มองไม่เห็นนี้"},"ICON-2478":{"nm":"ลูกตุ้มแกว่งสะโพก","de":"ลูกตุ้มแกว่งไปมาซ้ายขวาช้าๆ บอกจังหวะที่สะโพกวาดขึ้นอย่างเงียบๆ น้ำหนักเล็กๆ ขนาดเท่าฝ่ามือสอนโดยไม่พูดว่าศูนย์กลางร่างกายถ่ายน้ำหนักอย่างไร ว่าแม้แต่การแกว่งไหวก็ยังมีลายเส้นของมันเอง"},"ICON-2479":{"nm":"ห่วงหมุนข้อมือ","de":"คล้องห่วงที่ข้อมือแล้วหมุนเข้าและออกช้าๆ ข้อต่อที่แข็งค้างมาทั้งคืนก็คลายตัวนุ่มนวล เพื่อท่วงท่าที่มีชีวิตไปจนถึงปลายนิ้ว ข้อมือต้องยืดหยุ่นก่อนเป็นอันดับแรก การหมุนเล็กๆ นี้เปิดทางสู่การแสดงออกที่ยิ่งใหญ่กว่า"},"ICON-2480":{"nm":"สายห่วงถ่วงต้านข้อเท้า","de":"สวมห่วงที่ข้อเท้าแล้วดึงสาย ทุกก้าวที่ก้าวออกไปจะมีแรงต้านแผ่วเบาเกาะที่ปลายเท้า ยิ่งย่ำหนักเท่าไร ขาก็ยิ่งสะสมพลังอย่างเงียบๆ เท่านั้น การกระโดดที่เบาราวขนนกยืนอยู่บนการฝึกซ้อมอันหนักหน่วงเช่นนี้เสมอ"},"ICON-2481":{"nm":"ถุงทรายฝึกแกนกลางร่างกาย","de":"พันรอบท้องแล้วจึงจะรู้ว่าใจกลางร่างกายของตัวเองอยู่ตรงไหน ขณะที่น้ำหนักดึงไหล่ลง ศูนย์กลางที่เคยโคลงเคลงก็ค่อยๆ กลับเข้าที่ และเมื่อคลายออก ท่าทางที่ยืนตรงหนึ่งท่าก็หลงเหลืออยู่"},"ICON-2482":{"nm":"ฝาแท่งจัดแนวกระดูกสันหลัง","de":"เมื่อฝาเล็กๆ แตะหลังที่ก้มโค้งมาทั้งวัน ราวกับมีใครสักคนค่อยๆ ยืดไหล่ให้ แม้จะอยู่ได้ทั้งที่หลังค่อม แต่การยืนตรงคือทักษะอ่อนโยนที่ต้องค่อยๆ เรียนรู้ใหม่อีกครั้ง"},"ICON-2483":{"nm":"ลูกกดนวดคลายกล้ามเนื้อ","de":"กดจุดที่เกร็งแน่นให้แรงๆ ตอนแรกจะปวดจี๊ด แล้วไม่นานก็สบายขึ้น เหมือนความอุ่นจากหลังมือของยายที่เคยนวดหลังให้ตอนเด็ก การคลายให้คนอื่น คือการเจ็บแทนอีกสักหน่อยในขณะที่ยังอยู่เคียงข้าง"},"ICON-2484":{"nm":"สกรูปรับมุมกระจก","de":"บิดเพียงนิดเท่าฝ่ามือ กระจกก็สะท้อนใบหน้าที่แตกต่างไปโดยสิ้นเชิง หมุนสกรูรอบเดียว โลกก็เอียงแล้วตั้งตรงขึ้นใหม่ การเผชิญหน้ากับตัวเองจึงดูเหมือนจะต้องอาศัยการเล็งอย่างนิ่งสงบเช่นกัน"},"ICON-2485":{"nm":"แผ่นเช็ดฝ้ากระจก","de":"หน้ากระจกที่พร่ามัวด้วยไอน้ำร้อน คนเราจะสูญเสียใบหน้าของตัวเองไปชั่วขณะ ปาดครั้งเดียวใบหน้าก็กลับคืนมา ด้วยสัมผัสที่ปัดความพร่ามัวออกไปนี้ ทุกเช้าฉันจึงได้พบตัวเองอีกครั้ง"},"ICON-2486":{"nm":"ยางรองขาตั้งกล้อง","de":"ปลายขาตั้งกล้อง ยางชิ้นเล็กขนาดเท่าเล็บมือชิ้นหนึ่งกำหนดชะตากรรมของภาพทั้งหมด แรงยึดที่กัดพื้นไว้แน่นสงบความสั่นไหวลง ภาพที่ไร้การสั่นไหวจึงเริ่มต้นอย่างเงียบๆ จากแรงเสียดทานที่มองไม่เห็นเสมอ"},"ICON-2487":{"nm":"ฟิล์มเส้นกริดอ้างอิงมุมกล้อง","de":"เส้นกริดบางๆ บนฟิล์มเปรียบเสมือนล้อฝึกหัดสำหรับดวงตา ยิ่งองค์ประกอบภาพคุ้นมือมากเท่าไร เส้นเหล่านั้นก็ยิ่งค่อยๆ จางหายไป เหลือไว้เพียงสัญชาตญาณ ร่องรอยของการเรียนรู้จะมองไม่เห็นยิ่งขึ้นเมื่อสุกงอมมากขึ้น"},"ICON-2488":{"nm":"แป้นเหยียบเริ่มบันทึกภาพ","de":"สำหรับคนที่มือทั้งสองเต็มไปด้วยของ นิ้วสุดท้ายที่เหลือใช้มักเป็นปลายเท้าเสมอ แตะเบาๆ การบันทึกก็เริ่มขึ้น งานเบื้องหลังเวทีจึงทำหน้าที่ของตัวเองอย่างเรียบร้อยไปจนถึงปลายเท้าเช่นนี้"},"ICON-2489":{"nm":"คลิปปรับทิศทางไฟส่องสว่าง","de":"แสงจะตกลงตรงไหนขึ้นอยู่กับปลายนิ้วของคลิปขนาดเท่าเล็บมือตัวนี้ งานของการขยับเงาไปหนึ่งคืบเพื่อขับเน้นเส้นสายให้ชัดขึ้น ความแตกต่างเล็กน้อยนั้นทำให้ใครสักคนต้องลังเลครุ่นคิดอยู่นาน"},"ICON-2490":{"nm":"ม่านบังเปรียบเทียบภาพวิดีโอ","de":"วางเมื่อวานกับวันนี้ไว้เคียงกัน การเปลี่ยนแปลงจึงจะเริ่มเอ่ยปาก ในวินาทีที่ม่านค่อยๆ เลื่อนลง ระยะห่างของเวลาที่ข้ามผ่านมาระหว่างนั้นก็ปรากฏขึ้นบนจอภาพอย่างซื่อตรง"},"ICON-2491":{"nm":"สายคล้องข้อมือรีโมท","de":"พันเชือกเส้นหนึ่งรอบข้อมือ ความกังวลว่าจะทำหล่นก็คลายลง อุปกรณ์ป้องกันเล็กๆ กลับทำให้มือเป็นอิสระมากขึ้น เป็นความย้อนแย้งอันอ่อนโยนที่การถูกผูกไว้กลับทำให้ใจสบายขึ้น"},"ICON-2492":{"nm":"ฝาปิดเลนส์กล้อง","de":"ขณะกล้องพักผ่อน เลนส์ก็ค่อยๆ หลับตาลงอย่างเงียบๆ เช่นกัน ในโลกที่ฝุ่นแม้เพียงเม็ดเดียวทิ้งรอยแผลไว้บนภาพ การปิดคลุมไว้เบาๆ จึงเป็นความปรารถนาที่อยากทะนุถนอมมันไว้นานๆ"},"ICON-2493":{"nm":"แถบดึงมุมปาก","de":"ยกมุมปากขึ้นเล็กน้อย สีหน้าที่เคยแข็งค้างก็ค่อยๆ คลายลง รอยยิ้มก็คือกล้ามเนื้อในที่สุด ตอนแรกต้องยืมแรงจากเครื่องมือ แล้วเช้าวันหนึ่งก็จะยิ้มสดใสได้ด้วยแรงของตัวเอง"},"ICON-2494":{"nm":"โรลนวดกล้ามเนื้อแก้ม","de":"กลิ้งด้านในแก้มช้าๆ เพื่อคลายกล้ามเนื้อ คำพูดก็จะไหลลื่นออกมาราบรื่นยิ่งขึ้น การเตรียมตัวอันเงียบสงบที่ปลุกใบหน้าให้ตื่นเบาๆ ก่อนร้องเพลง เมื่ออุ่นสีหน้าแล้วมันก็จะอบอุ่นยิ่งขึ้น"},"ICON-2495":{"nm":"ไม้วัดมุมรอยยิ้ม","de":"กล้องรู้ว่าแม้แต่รอยยิ้มก็มีมุมที่เหมาะสม วัดไปวัดมาด้วยไม้วัดนี้แล้วในที่สุดก็เข้าใจว่า รอยยิ้มที่งดงามที่สุดผลิบานจากความจริงใจที่ไม่มีทางวัดได้เลย"},"ICON-2496":{"nm":"คลิปหนีบฝึกขยับคิ้ว","de":"เพียงคิ้วขยับไปเพียง 1 มิลลิเมตร ลายเส้นของหัวใจทั้งหมดก็เปลี่ยนไป คลิปที่จับชิ้นส่วนเล็กที่สุดของสีหน้าไว้อย่างแผ่วเบา การแสดงคืองานของปลายนิ้วที่บังคับความละเอียดอ่อนเช่นนี้"},"ICON-2497":{"nm":"สติกเกอร์ยกกระดูกโหนกแก้ม","de":"ยกโหนกแก้มขึ้นเล็กน้อยแล้วแปะไว้ จุดที่แสงจะเอ่ออยู่บนใบหน้าก็ปรากฏขึ้น มิติที่เกิดจากสติกเกอร์แผ่นเดียวขนาดเท่าเล็บมือ การแต่งหน้าเวทีซ่อนความลับที่มองไม่เห็นเช่นนี้อยู่"},"ICON-2498":{"nm":"ผ้าปิดตาฝึกขยิบตา","de":"ปิดตาข้างหนึ่งแล้วหัวใจจะรวมศูนย์ที่ตาข้างที่เหลืออยู่อย่างเต็มที่ การฝึกขยิบตาในที่สุดคือการเรียนรู้วิธีซ่อนครึ่งหนึ่งอย่างสง่างาม มีสีหน้าบางอย่างที่ยิ่งชัดเจนขึ้นเพราะถูกปิดบังไว้เช่นกัน"},"ICON-2499":{"nm":"คลิปแม่พิมพ์รูปปาก","de":"กา กยา กอ... ปรับรูปปากให้เข้ากับแม่พิมพ์ การออกเสียงที่เคยพร่ามัวก็คมชัดขึ้น สระแต่ละตัวคือท่วงท่าของใบหน้า ค่อยๆ สลักลงในร่างกายทีละน้อยหน้ากระจกเงา"},"ICON-2500":{"nm":"ถุงอุ่นสีหน้าก่อนขึ้นเวที","de":"ก่อนขึ้นเวที ถุงอุ่นๆ ที่ค่อยๆ ให้ความร้อนแก่ใบหน้าอย่างแผ่วเบา เหมือนมือที่เย็นจะทำให้การเล่นดนตรีแข็งค้าง สีหน้าก็เช่นกัน แม้แต่รอยยิ้มก็ต้องการการอุ่นเครื่องล่วงหน้า นี่คือความจริงเล็กๆ เบื้องหลังเวที"},"ICON-2501":{"nm":"แถบคลายรอยย่นหน้าผาก","de":"พันแถบรอบหน้าผาก แล้วรอยย่นที่ขมวดลึกก็ค่อยๆ คลายออกอย่างเงียบๆ เป็นสิ่งที่ให้รอยย่นซึ่งเกิดจากความกังวลได้พักสักครู่ ใต้หน้าผากที่เรียบเนียนนั้น ผู้คนดูอ่อนวัยลงอีกนิด"},"ICON-2502":{"nm":"ปลอกนิ้วพลิกบท","de":"ปลอกนิ้วเล็กๆ ที่สวมไว้ที่ปลายนิ้วเวลาพลิกหน้ากระดาษ จังหวะการพลิกบทหนาๆ ทีละหน้ากลายเป็นจังหวะของเรื่องราวโดยไม่รู้ตัว แม้แต่การอ่านก็ยังมีนิสัยมือที่อ่อนโยนแฝงอยู่"},"ICON-2503":{"nm":"ธงระบายสีอารมณ์","de":"ความสุขคือสีเหลือง ความเศร้าคือสีฟ้า เมื่อระบายสีลงในใจแล้วชูธงขึ้น อารมณ์ที่มองไม่เห็นก็ค่อยๆ ปรากฏรูปร่างพลิ้วไหวไปตามสายลม ความรู้สึกก็สามารถวาดออกมาด้วยมือได้เช่นนี้"},"ICON-2504":{"nm":"คลิปเน้นเสียงบทพูด","de":"\"ลงน้ำหนักที่คำนี้นะ\" คลิปกระซิบบอกอย่างเงียบๆ บทพูดเดียวกันสามารถเปลี่ยนความหมายทั้งหมดได้ด้วยการเน้นเสียงเพียงจุดเดียว จึงเป็นเครื่องหมายเล็กๆ ที่คอยยึดจุดศูนย์ถ่วงของคำพูดเอาไว้"},"ICON-2505":{"nm":"บล็อกจุดหยุดพักการอ่าน","de":"บล็อกที่วางไว้เพื่อบอกว่า \"หยุดพักหนึ่งจังหวะตรงนี้นะ\" เครื่องหมายจุลภาคในบทพูดไม่ใช่การหยุดนิ่ง แต่เป็นลมหายใจที่สูดเข้าเพื่อคำพูดถัดไป คนที่รู้จักพักได้ดี ในที่สุดแล้วจะพูดได้ดีเช่นกัน"},"ICON-2506":{"nm":"แถบคลิปแสดงลมหายใจ","de":"แถบเลื่อนขึ้นลงไปตามคลิป วาดความยาวของลมหายใจให้เห็นตรงหน้า การมองและเลียนแบบจังหวะของการหายใจเข้าออก จุดเริ่มต้นของบทเพลงมักเริ่มจากการควบคุมลมหายใจเสมอ"},"ICON-2507":{"nm":"ถุงลูกเต๋าอารมณ์","de":"ลูกเต๋ากลิ้งออกมาจากถุงแล้วกำหนดอารมณ์ของวันนี้ ถ้าออกมาเป็นความสุขก็ลองมีความสุขดู ถ้าออกมาเป็นความโกรธก็ลองโกรธดู การฝึกแสดงกลายเป็นเกมที่มอบหัวใจให้กับโชคชะตา"},"ICON-2508":{"nm":"แท่นเอียงวางบท","de":"วางบทไว้บนแท่นเอียงแล้วไม่ต้องก้มหน้าลงอีก ความลาดเอียงเล็กๆ ที่รักษาระดับสายตานี้ คอยดูแลต้นคออันตึงเมื่อยจากการฝึกซ้อมอันยาวนานอย่างเงียบๆ"},"ICON-2509":{"nm":"ฉากกระซิบ","de":"เครื่องหมายบอกว่าให้กระซิบตั้งแต่ตรงนี้เป็นต้นไป เมื่อลดเสียงลงหลังฉากกั้น ผู้ชมกลับกลั้นลมหายใจและเงี่ยหูฟังมากขึ้น เป็นความขัดแย้งอันอ่อนโยนของเวที ยิ่งพูดเบาเท่าไร ยิ่งไปถึงใจคนได้กว้างไกลเท่านั้น"},"ICON-2510":{"nm":"กล่องโทเคนสลับบทบาท","de":"พลิกโทเคนเบาๆ บทบาทที่รับก็เปลี่ยนไป วันนี้เป็นตัวเอก พรุ่งนี้เป็นเพื่อนที่คอยอยู่เคียงข้าง บนเกาะที่เติบโตไปด้วยกันนี้ ทุกคนจะได้ผลัดกันยืนอยู่กลางเวทีในที่สุด"},"ICON-2511":{"nm":"สติกเกอร์จุดตรึงสายตา","de":"วางสายตาไว้นิ่งๆ ที่จุดเล็กๆ ข้างกล้อง เมื่อสายตาที่เคยสั่นไหวมาหยุดนิ่งอยู่ที่จุดเดียว แววตาในจอก็จะมีชีวิตชีวาขึ้นอย่างชัดเจน การจ้องมองที่มั่นคงเริ่มต้นจากการหยุดนิ่งในที่สุด"},"ICON-2512":{"nm":"ไม้ฉากวัดมุมกล้อง","de":"เมื่อมุมหนึ่งของจอดูเอียงอย่างประหลาด แค่ยกไม้ฉากขึ้นทาบดูก็จะได้คำตอบ งานของการจัดสิ่งที่คดเคี้ยวให้ตรง ก่อนจะเชื่อสายตาตนเอง ลองเชื่อไม้บรรทัดดูสักครู่ก่อน"},"ICON-2513":{"nm":"ฐานปรับระดับสายตาเลนส์","de":"ปรับเลนส์ให้อยู่ในระดับสายตาคน แล้วภาพบนจอจะโกหกน้อยลง ไม่ใช่จากด้านบน ไม่ใช่จากด้านล่าง มีเพียงเมื่อสบตากันในระดับเดียวกันเท่านั้นที่จะจับภาพสีหน้าอันแท้จริงไร้การปรุงแต่งได้"},"ICON-2514":{"nm":"ขนนกลูกศรนำสายตา","de":"สายตาจะไหลตามไปยังทิศทางที่ขนลูกศรชี้อย่างแผ่วเบา ลูกศรเล็กๆ ที่ค่อยๆ นำสายตาของผู้ชมไปอย่างแนบเนียน ภาพที่ดีจะชี้บอกอย่างอ่อนโยนว่าควรมองไปทางไหน"},"ICON-2515":{"nm":"ชิปพื้นเส้นทางเดินถ่ายทำ","de":"เพียงเหยียบจุดหนึ่งของเส้นทางที่จดจำจนขึ้นใจ ตำแหน่งถัดไปก็อยู่ในมือทันที ฝีเท้าที่เดินไปทั่วเวทีคือเส้นทางที่มองไม่เห็น ซึ่งเกิดจากการเชื่อมโยงเครื่องหมายเล็กๆ เหล่านี้ที่ปักอยู่ทั่วพื้น"},"ICON-2516":{"nm":"แถบสายวัดระยะกล้อง","de":"วัดระยะห่างระหว่างตัวแบบกับกล้องด้วยแถบสายวัด ในโลกที่ระยะเพียงคืบเดียวแบ่งแยกความใกล้ไกล สายวัดจึงกลายเป็นยามเฝ้าอันเงียบงันที่คอยพิทักษ์เส้นแบ่งระหว่างความเบลอกับความคมชัด"},"ICON-2517":{"nm":"ไกด์เอียงศีรษะ","de":"ควรเอียงศีรษะมากแค่ไหนจึงจะดูอ่อนโยนที่สุด เมื่อทำตามไกด์ไปเรื่อยๆ ก็จะค่อยๆ เข้าใจอย่างแผ่วเบาว่า มุมของการเอียงนั้นคล้ายคลึงกับระดับของการเปิดใจในที่สุด"},"ICON-2518":{"nm":"คลิปกระจกมือสบตา","de":"หนีบกระจกมือไว้ข้างกล้องด้วยคลิป แล้วมองตาตัวเองไปพร้อมกับสบตาเธอ อุปกรณ์เล็กๆ ที่วางสะพานแห่งสายตาเชื่อมระหว่างตัวฉันในกระจกกับเธอในจอภาพอย่างแผ่วเบา"},"ICON-2519":{"nm":"ไฟสัญญาณกำลังถ่ายทำ","de":"เมื่อไฟติดขึ้นคือสัญญาณว่ากำลังถ่ายทำอยู่ โคมเล็กๆ ดวงหนึ่งรวมความตึงเครียดของกองถ่ายที่คึกคักไว้เป็นหนึ่งเดียว นับตั้งแต่วินาทีที่ไฟสว่างขึ้น ลมหายใจของทุกคนก็เรียงเป็นจังหวะเดียวกันอย่างเป็นระเบียบ"},"ICON-2520":{"nm":"ปุ่มกระดิ่งรีแอคชั่น","de":"กดปุ่มแล้วเสียงกระดิ่งใสกังวานดังขึ้น เหมือนเสียงปรบมือที่ดังกึกก้องหลังฉากที่ดี คำชมอันอบอุ่นสักคำว่า \"เก่งมาก\" จากใครสักคนถูกบรรจุอยู่ในกระดิ่งเล็กๆ นี้"},"ICON-2521":{"nm":"กระบอกจับฉลากไหวพริบ","de":"เขย่าแล้วไม้เล็กๆ จะกระทบกันดังกรุ๊งกริ๊ง ปลุกบรรยากาศให้ตื่นตัวก่อนใคร ใครจะเปิดเวทีถูกตัดสินด้วยการสะบัดข้อมือเพียงครั้งเดียว คนที่ถูกจับได้ยิ้มเขินๆ ส่วนคนที่เหลือก็โล่งอกลูบหน้าอก แม้แต่การแบ่งโชคก็ยังมีกติกาอันอ่อนโยน"},"ICON-2522":{"nm":"กระดิ่งเขย่าเอฟเฟกต์เสียง","de":"สะบัดข้อมือเพียงเบาๆ ก็มีเสียงกรุ๊งกริ๊งแทรกเข้ามาเป็นคำอุทาน กระดิ่งเล็กๆ นี้เติมเต็มช่องว่างก่อนที่ความเงียบจะกลายเป็นความอึดอัด การนับจังหวะของเสียงหัวเราะ ฝ่ายนี้มักจะเร็วกว่าเสมอหนึ่งก้าว"},"ICON-2523":{"nm":"ฝากล่องเซอร์ไพรส์","de":"ก่อนจะเปิด ไม่มีใครเดาได้ว่าข้างในมีอะไร นั่นคือหน้าที่เพียงหนึ่งเดียวที่ฝานี้แบกรับไว้ เพื่อให้เสียงกรีดร้องและเสียงหัวเราะปะทุขึ้นพร้อมกันในชั่วขณะที่มันกระดกเปิดออก มันฝากความตื่นเต้นไว้กับบานพับเพียงจุดเดียว"},"ICON-2524":{"nm":"พัดพับรีแอคชั่น","de":"เสียงกางออกฉับพลันกลายเป็นคำตอบในตัวมันเอง ซี่พัดโบกส่งความประทับใจที่พูดไม่ทันแทน ระหว่างท่าทางการพับและกางนั้น ความสนุกสนานส่งผ่านไปมา และมุมหนึ่งของหัวใจก็แกว่งไหวไปตามสายลมด้วย"},"ICON-2525":{"nm":"วงล้อรูเล็ตลงโทษ","de":"ไม่มีใครรู้ล่วงหน้าว่าเข็มจะหยุดที่ช่องไหน ยิ่งวงล้อหมุนช้าลงเท่าไร หัวใจก็ยิ่งเต้นเร็วขึ้นสวนทางกัน—คลิก แล้วชะตากรรมสุดฮาของวันนี้ก็ถูกจารึกไว้ตรงจุดที่มันหยุด เป็นไม่กี่วินาทีที่แม้แต่ความสั่นระทึกก็ยังสนุกสนาน"},"ICON-2526":{"nm":"ป้ายบับเบิลคำอุทาน","de":"ยกขึ้นเหนือหัวแวบหนึ่ง คำว่า \"ว้าว\" ก็ลอยขึ้นเป็นตัวอักษร กระดาษแผ่นเดียวแซงหน้าหัวใจ ตะโกนแทนสิ่งที่ปากยังตามไม่ทัน เพราะแม้แต่รีแอคชั่นก็ยังต้องการการกำกับเวทีเช่นกัน"},"ICON-2527":{"nm":"ธงมือหยุดนิ่งฉับพลัน","de":"วินาทีที่ธงถูกชูขึ้น ทุกคนแข็งค้างอยู่ตรงจุดนั้นทันที สัญญาณที่ขังแม้กระทั่งเสียงลมหายใจไว้ในภาพนิ่ง เมื่อลดธงลงอีกครั้ง เสียงหัวเราะที่หยุดค้างไว้ก็หลั่งไหลออกมาพร้อมกันทั้งหมด"},"ICON-2528":{"nm":"ถังคลิปคำตอบแปลกๆ","de":"คำตอบยิ่งแปลกเท่าไร ยิ่งถูกหนีบแขวนไว้อย่างขะมักเขม้น เมื่อคำตอบผิดที่แขวนตากไว้บนราวสั่นไหวไปตามลม กลายเป็นเวทีที่ความผิดพลาดได้รับความรักมากกว่าคำตอบที่ถูก เป็นภาพของวันที่ผิดก็ไม่เป็นไร"},"ICON-2529":{"nm":"ลิ่มพนักพิงจัดท่าทาง","de":"วินาทีที่พิงหลังลง กระดูกสันหลังที่งอค้อมก็ค่อยๆ คลำหาทางของตัวเองอย่างแผ่วเบา ลิ่มเล็กๆ ชิ้นหนึ่งที่คอยรองรับโดยไม่ปริปาก ท่าทางที่ดีจะสบายได้ก็ต่อเมื่อมีใครสักคนคอยรองรับอยู่ มันบอกอย่างเงียบๆ จากด้านหลัง"},"ICON-2530":{"nm":"บล็อกรองปรับแนวสะโพก","de":"ความแข็งแรงเล็กๆ ที่รองไว้ใต้เท้ายามที่จุดศูนย์ถ่วงสั่นคลอน สมดุลของร่างกายในที่สุดแล้วค่อยๆ ไต่ขึ้นมาจากพื้นอย่างช้าๆ เป็นตัวประกอบไร้ชื่อที่คอยค้ำยันท่าทางจากตำแหน่งที่มองไม่เห็น"},"ICON-2531":{"nm":"ลูกบอลรัดหน้าท้องสร้างสมดุล","de":"สอดไว้ที่ท้องแล้วเกร็งเบาๆ จุดศูนย์กลางที่เคยกระจัดกระจายก็รวมเป็นจุดเดียว ยิ่งควบคุมลมหายใจให้ลึกขึ้นเท่าไร ลูกบอลก็ยิ่งแน่นขึ้นเท่านั้น และร่างกายก็ค่อยๆ ทวงคืนแกนของตัวเองที่เคยลืมเลือนไปทีละลมหายใจ"},"ICON-2532":{"nm":"ไม้บรรทัดตรวจแนวโค้งกระดูกสันหลัง","de":"ทาบไม้บรรทัดไปตามหลัง ความโค้งที่มองไม่เห็นก็ปรากฏขึ้นบนขีดสเกล การยืนตรงไม่ใช่การลบความโค้งทิ้ง แต่คืองานที่อ่านแม้กระทั่งความโค้งงอเล็กๆ นั้นด้วยความอ่อนโยน"},"ICON-2533":{"nm":"ห่วงยางยืดเหยียดไหล่","de":"คล้องไว้ที่ไหล่แล้วดึงช้าๆ หน้าอกที่เคยหดเกร็งก็เปิดกว้างออก ความยืดหยุ่นกระซิบเสมอว่าให้กลับมาสู่ที่เดิม และหลังที่งอค้อมมาทั้งวันก็ค่อยๆ เหยียดตรงตามเสียงเรียกอันอ่อนโยนนั้นทีละนิด"},"ICON-2534":{"nm":"ถุงทรายกระตุ้นแกนกลาง","de":"พันรอบเอวแล้วเม็ดทรายหนักอึ้งจะปลุกแกนกลางที่หลับใหลให้ตื่นขึ้น แม้แต่การเคลื่อนไหวเบาๆ ก็กลายเป็นเรื่องจริงจังในชั่วพริบตาต่อหน้าน้ำหนักนี้ ยิ่งอดทนมากเท่าไรก็ยิ่งแข็งแรงขึ้นเท่านั้น เม็ดทรายแต่ละเม็ดบอกอย่างเงียบๆ"},"ICON-2535":{"nm":"แท็กเบาะรองก้นกบ","de":"เบาะที่รองรับใต้ก้นกบอย่างแผ่วเบา มีป้ายเล็กๆ ห้อยอยู่ที่ปลาย เป็นเครื่องมือเหมือนจดหมายน้อยอันอ่อนโยนที่เขียนติดไว้ให้กับวันที่เหนื่อยล้าจากการนั่งนานว่า \"พิงตรงนี้สักพักก็ได้นะ\""},"ICON-2536":{"nm":"ขาตั้งสามขามุมพยุงเอว","de":"ยืนหยัดด้วยสามขา คอยจับมุมให้เอวได้พิงอย่างมั่นคง เป็นตัวค้ำยันที่แทรกเข้ามาช่วยท่าทางที่กำลังจะทรุดลง การยึดสิ่งที่สั่นคลอนไว้ให้อยู่ แค่สามจุดก็เพียงพออย่างน่าประหลาดใจ"},"ICON-2537":{"nm":"คลิปจัดท่าเก็บคาง","de":"ดึงคางเข้ามาเบาๆ แล้วรองไว้ เส้นคอที่เคยเอียงรวนก็กลับมาอยู่ในที่ของมัน คำบ่นของคลิปเล็กเท่านิ้วมือนี้ช่างอ่อนโยนอยู่ในที ว่าจะเงยหน้าให้ตรงได้อย่างไร เครื่องมือเล็กๆ ชิ้นนี้สอนไว้"},"ICON-2538":{"nm":"แถบบันไดฝึกก้าวเท้า","de":"แถบที่คลี่ไว้บนพื้นวาดช่องให้เท้าเหยียบเรียงต่อกันไปทีละช่อง เมื่อเหยียบทีละช่องอย่างซื่อตรง ในที่สุดสเต็ปก็ถูกสลักไว้ในร่างกายโดยไม่รู้ตัว หนทางยิ่งเหยียบย่ำมากเท่าไรก็ยิ่งชัดเจนขึ้นเท่านั้น"},"ICON-2539":{"nm":"กรวยชิปเปลี่ยนทิศทาง","de":"ตั้งไว้แล้วมันเป็นเครื่องหมายเล็กๆ ที่บอกว่า \"เลี้ยวตรงนี้\" มอบมุมเลี้ยวให้กับเท้าที่เคยวิ่งตรงเพียงอย่างเดียว แม้แต่เส้นทางที่เลี้ยวเข้าโค้งก็ยังมีจังหวะของตัวเองซ่อนอยู่"},"ICON-2540":{"nm":"กระดานโยกยืนขาเดียว","de":"วินาทีที่ก้าวขึ้นยืนด้วยขาเดียว กระดานก็เอียงเบาๆ ไม่กี่วินาทีที่พยายามอย่างสุดกำลังเพื่อเอาชนะความโคลงเคลงนั้น คือบทเรียนที่ซื่อตรงที่สุดของสมดุล ปลายเท้าที่พยายามไม่ให้ล้มบอกทุกอย่างได้หมด"},"ICON-2541":{"nm":"ไฟกะพริบวัดความไว","de":"วินาทีที่สัญญาณสว่างขึ้น มือกับตาต่างแข่งกันว่าใครจะไวกว่ากัน แสงกะพริบไม่ให้เวลาลังเลแม้แต่น้อย มือที่ไวเสมอเคลื่อนไหวล้ำหน้าความคิดไปครึ่งจังหวะ"},"ICON-2542":{"nm":"มาร์กเกอร์พื้นซิกแซก","de":"จุดเล็กๆ ที่ติดเฉียงบนพื้น นำเท้าให้เต้นเป็นจังหวะซิกแซก สิ่งที่ยากกว่าเส้นตรงคือความสลับไปมาเสมอ เมื่อเดินตามจุดไปเรื่อยๆ ฝีเท้าที่ว่องไวก็สุกงอมขึ้นอย่างคล่องแคล่ว"},"ICON-2543":{"nm":"คานแบนไต่เชือกทรงตัว","de":"วางเท้าบนคานเรียวบางแล้วโลกก็แคบลงเหมือนเส้นเชือกเส้นเดียว เหมือนนักไต่ลวดที่เดินอยู่กลางอากาศ ทุ่มสมาธิทั้งหมดของร่างกายลงบนความกว้างเพียงคืบเดียว สมดุลยิ่งแคบลงเท่าไรกลับยิ่งชัดเจนขึ้นเท่านั้น"},"ICON-2544":{"nm":"กำไลลูกบอลสะท้อนความคล่องแคล่ว","de":"สวมไว้ที่ข้อมือแล้วลูกบอลเล็กๆ จะกระดอนกลับมาด้วยแรงสะท้อน ในวินาทีที่โยนและรับนั้น ความเร็วของปฏิกิริยาถูกสลักไว้ที่ปลายนิ้ว ความรวดเร็วในที่สุดแล้วคือการไม่พลาดสิ่งที่ย้อนกลับมา"},"ICON-2545":{"nm":"ห่วงฮูล่าคล้องเท้าคล่องแคล่ว","de":"คล้องไว้ที่เท้าแล้วหมุนวน ห่วงฮูล่าคอยกระตุ้นน่องอยู่ไม่หยุด วินาทีที่หยุดมันก็ตก เท้าจึงต้องขยับไม่ได้พัก ระหว่างที่เคลื่อนไหวราวกับกำลังเล่นสนุก ฝีเท้าก็สุกงอมขึ้นอย่างว่องไว"},"ICON-2546":{"nm":"ลูกข่างไม้ศูนย์ปลายเท้า","de":"ลูกข่างที่หมุนอยู่บนฝ่ามือหยุดนิ่งทันทีในวินาทีที่เสียศูนย์ เหมือนวันเด็กๆ ที่ตีลูกข่างเล่นในลานบ้าน สมดุลคือสิ่งที่จะยืนอยู่ได้ก็ต่อเมื่อหมุนไปเรื่อยๆ ไม่หยุดเท่านั้น"},"ICON-2547":{"nm":"เชือกรัดพยุงข้อเท้า","de":"พันรัดข้อเท้าแล้วการทรงตัวที่เคยสั่นคลอนก็มั่นคงขึ้นมาก จุดที่บาดเจ็บง่ายยิ่งต้องประคองด้วยความอ่อนโยนมากขึ้น เชือกเพียงเส้นเดียวกลายเป็นความอุ่นใจของแต่ละก้าวเดิน"},"ICON-2548":{"nm":"แถบพันอุ่นเข่า","de":"พันไว้รอบเข่าที่เย็นเฉียบแล้วไออุ่นก็ซึมเข้าไปตามข้อต่อ ข้อต่อที่แข็งเกร็งจะนุ่มขึ้นได้ก็ต่อเมื่อได้รับความอบอุ่น ก่อนจะเริ่มเคลื่อนไหว นี่คือคำทักทายยามเช้าที่อบอุ่นที่สุดที่มอบให้กับร่างกายตัวเอง"},"ICON-2549":{"nm":"ลูกบอลนวดกดจุดคลายกล้ามเนื้อ","de":"กดจุดที่เกร็งแน่นเบาๆ เม็ดตุ่มก็จะลูบไล้ปมกล้ามเนื้ออย่างแผ่วเบา ความปลอบใจแปลกๆ ที่ยิ่งเจ็บก็ยิ่งคลาย แม้แต่ความปวดตึงที่มือเอื้อมไม่ถึง ลูกบอลเล็กๆ นี้ก็ปลอบโยนแทนให้"},"ICON-2550":{"nm":"วงล้อลำดับวอร์มอัพ","de":"ปลุกร่างกายจากช่องที่วงล้อหยุดอยู่ คอ ไหล่ ข้อเท้า—ปล่อยลำดับให้เป็นไปตามโชคชะตาและทำใจให้เบาสบาย เมื่อการเล่นแทรกเข้ามาในการวอร์มอัพ ร่างกายที่แข็งเกร็งก็จะยิ้มออกมาก่อนใครอย่างแผ่วเบา"},"ICON-2551":{"nm":"แผ่นประคบร้อนอุ่นข้อต่อ","de":"วางแผ่นประคบร้อนๆ ไว้บนข้อต่อ ความโล่งใจที่เหมือนพื้นห้องอุ่นในฤดูหนาวก็แผ่กระจายไปทั่ว เป็นช่วงเวลาที่ข้อต่อซึ่งแข็งเกร็งคลายตัวลงอย่างเมื่อยล้าเบาสบาย ร่างกายที่อบอุ่นแล้วเท่านั้นจึงเตรียมพร้อมที่จะเคลื่อนไหวอย่างช้าๆ"},"ICON-2552":{"nm":"ห่วงจับดึงยืดกล้ามเนื้อ","de":"จับห่วงแล้วดึง กล้ามเนื้อที่แข็งเกร็งก็ยืดยาวออก บทสนทนาอันตึงเครียดผ่านไปมาระหว่างมือที่ยึดไว้กับร่างกายที่คลี่ออก ยิ่งยืดมากเท่าไร การเคลื่อนไหวของวันพรุ่งนี้ก็จะเบาสบายขึ้นเท่านั้น"},"ICON-2553":{"nm":"กระดานตุ่มกระตุ้นฝ่าเท้า","de":"ยืนเท้าเปล่าบนตุ่มแล้วฝ่าเท้าที่หลับใหลก็สะดุ้งตื่นขึ้น เหมือนความรู้สึกซาบซ่านจากการเดินเท้าเปล่าบนทางกรวด ความรู้สึกของการเหยียบพื้นดินไหลขึ้นมาจากปลายเท้า"},"ICON-2554":{"nm":"หมุดแม่เหล็กโน้ตอาการบาดเจ็บ","de":"เขียนว่า \"อย่าฝืนนะ\" แล้วแปะติดไว้บนแผ่นเหล็กเบาๆ ความทรงจำที่เจ็บปวดลืมง่าย จึงแขวนไว้ตรงหน้าด้วยแม่เหล็ก การถนอมร่างกายในที่สุดแล้วก็เริ่มต้นจากบันทึกสั้นๆ เพียงบรรทัดเดียว"},"ICON-2555":{"nm":"แท่งกลิ้งปุ่มคลายพังผืด","de":"กลิ้งแท่งที่มีปุ่มไปอย่างช้าๆ พังผืดที่ยึดติดกันก็ค่อยๆ คลายออกทีละช่วง สัมผัสที่ค่อยๆ ดันปมออกไปอย่างแผ่วเบา วันที่จมอยู่กับความตึงเครียดก็จะเบาลงมากเช่นกันเมื่อคลี่คลายออกทีละปมแบบนี้"},"ICON-2556":{"nm":"แถบพื้นเส้นเดินตรง","de":"ปูให้ตรงบนพื้นแล้วเท้าก็จะมีเส้นเดียวให้เดินตาม แม้แต่ฝีก้าวที่เคยรวนไม่เป็นระเบียบ เมื่อวางบนเส้นนี้ก็จะเรียบร้อยขึ้นในไม่ช้า เมื่อมีคนวาดเส้นทางให้ เท้าก็จะไม่หลงทางอีกต่อไป"},"ICON-2557":{"nm":"คานปรับระดับไหล่","de":"วางพาดไว้บนไหล่แล้วความไม่สมดุลที่เอียงไปข้างหนึ่งก็ปรากฏขึ้นอย่างแผ่วเบา ความเสมอต้นเสมอปลายเสมอหมายถึงการลดข้างหนึ่งลงและยกอีกข้างขึ้น คานเพียงชิ้นเดียวชี้ให้เห็นนิสัยที่เอียงคดอย่างเงียบๆ"},"ICON-2558":{"nm":"ตุ้มถ่วงสมดุลกลางกระหม่อม","de":"เพื่อไม่ให้ตุ้มน้ำหนักที่วางบนกระหม่อมหล่นลงมา ร่างกายทั้งหมดต้องยืนตรงเป็นเส้นเดียว เหมือนภาพวันวานที่เดินทูนหม้อน้ำไว้บนศีรษะ จุดศูนย์กลางถูกจับไว้ตั้งแต่จุดสูงสุดแล้วค่อยๆ ไล่ลงมา"},"ICON-2559":{"nm":"ที่รองมุมคาง","de":"พยุงคางไว้เบาๆ แล้วศีรษะที่มักก้มลงเรื่อยๆ ก็กลับคืนสู่มุมของมันเอง การพักผ่อนสั้นๆ ที่พิงอยู่กับที่รองเพียงชิ้นเดียว เส้นตรงที่ดีจะสมบูรณ์ได้ก็ต่อเมื่อมีใครสักคนคอยรองรับจากด้านล่าง"},"ICON-2560":{"nm":"หลักปักระยะก้าวเดิน","de":"หลักที่ปักอยู่บนพื้นวัดระยะที่เท้าควรลงไว้ล่วงหน้า หนึ่งช่วงก้าวที่ไม่กว้างไม่แคบ ระยะทางอันซื่อตรงนั้น สมดุลของการเดินเริ่มต้นอย่างเงียบๆ จากเครื่องหมายเล็กๆ นี้"},"ICON-2561":{"nm":"ลิ่มชี้ทิศปลายเท้า","de":"ก้าวแรกที่ลังเล ปลายเท้าลังเลก่อนว่าจะไปทางไหน เมื่อลิ่มเล็กๆ นี้กำหนดทิศทางให้ ใจก็เอนเอียงไปทางนั้นอย่างแผ่วเบาด้วย การเลือกเส้นทางที่จะไปไม่ใช่การตัดสินใจที่ยิ่งใหญ่ แต่คือระยะเพียงคืบเดียวที่ปลายเท้าชี้ไป"},"ICON-2562":{"nm":"เข็มขัดจัดหลังตรง","de":"เสียงที่เคยพูดว่า \"ยืดหลังสิ ยืดหลัง\" ราวกับยังมีชีวิตอยู่ในเข็มขัดเส้นนี้ เมื่อยืดวันที่งอค้อมให้ตรงเบาๆ น้ำหนักที่แบกไว้บนบ่าก็เบาลงอย่างน่าประหลาดใจเล็กน้อย ท่าทางเพียงหนึ่งเดียวยังยกใจให้ลุกขึ้นตรงด้วย"},"ICON-2563":{"nm":"แผ่นเหยียบกระจายน้ำหนัก","de":"เท้าซ้ายเจ็ดส่วน เท้าขวาสามส่วน จะลงน้ำหนักตรงไหนมากกว่าเป็นตัวแบ่งสมดุล แผ่นเหยียบถามอย่างเงียบๆ ว่า ตอนนี้เธอเอียงไปทางไหนมากกว่ากัน การยืนตรงแท้จริงแล้วคือการปรับตัวอยู่ตลอดเวลาไม่หยุดนิ่ง"},"ICON-2564":{"nm":"เสาเป้าหมายระดับสายตา","de":"สายตามักหล่นลงไปที่ปลายเท้าอยู่เรื่อยๆ ยามนั้นเสาต้นหนึ่งที่ตั้งอยู่ไกลออกไปจะค่อยๆ ยกสายตาขึ้นอย่างช้าๆ การฝึกมองไกลคือการฝึกไปให้ไกล ดังนั้นวินาทีที่เงยหน้าขึ้น แม้แต่ที่ที่ดูเหมือนจะไปไม่ถึงก็ใกล้เข้ามา"},"ICON-2565":{"nm":"คลิปการ์ดมุมโค้งคำนับ","de":"สิบห้าองศา สามสิบองศา สี่สิบห้าองศา ใจโค้งลงลึกเท่ากับที่เอวพับลง มุมองศาที่เขียนไว้บนการ์ดไม่ใช่แค่ตัวเลข แต่เป็นขีดวัดเล็กๆ ที่วัดความจริงใจที่มอบให้กับอีกฝ่าย"},"ICON-2566":{"nm":"ห่วงมารยาทประนมมือ","de":"ประนมสองมือให้เรียบร้อยแล้วใจที่เต้นระริกก็ค่อยๆ สงบลงมาอยู่ที่จุดเดียว ห่วงเล็กๆ นี้จับปลายนิ้วที่กระวนกระวายไม่รู้จะทำอย่างไรไว้อย่างอ่อนโยน จัดท่าทางแรกของการทักทายไว้อย่างเงียบๆ"},"ICON-2567":{"nm":"แม่เหล็กลูกศรเส้นทางเดิน","de":"สิ่งแรกที่เท้าซึ่งหลงทางมองหาด้วยสายตาที่ส่ายไปมาคือลูกศร ทิศทางเดียวที่ติดแม่เหล็กไว้ตัดความลังเลทิ้ง และดึงฝีเท้าไปยังที่ที่ต้องไปอย่างแผ่วเบา แม้แต่ใจที่หลงทางก็ในที่สุดได้ทิศทางเดียวเช่นกัน"},"ICON-2568":{"nm":"หมุดเครื่องหมายทิศทางออกเวที","de":"ทางออกยากกว่าทางเข้าเสมอ แม้ในความมืดที่ไฟดับ หมุดที่เรืองแสงชัดเจนนี้ชี้บอกเส้นทางสุดท้ายอย่างเงียบๆ การจากไปให้ดีก็เป็นส่วนหนึ่งของเวทีเช่นกัน สิ่งนี้เพิ่งจะรู้เมื่อถึงตอนจบ"},"ICON-2569":{"nm":"แถบการ์ดลำดับการคำนับ","de":"เคยมียุคที่ลำดับของผู้ที่คำนับก่อนและผู้ที่คำนับทีหลังชัดเจน เมื่อค้อมตัวลงตามลำดับที่เขียนไว้บนแถบ แม้แต่ความสุภาพก็มีลายเนื้อ และมารยาทก็มีกระแสไหลลื่น มันคือการรักษาลำดับของหัวใจ"},"ICON-2570":{"nm":"ชิปแม่เหล็กจัดแนวก้าวเท้า","de":"ถ้าคนหนึ่งก้าวผิดจังหวะ ทั้งแถวก็สั่นคลอน เหมือนชิปที่คลิกติดกันเมื่อปลายเท้าตรงกัน การยืนอยู่ด้วยกันคือการค่อยๆ ยอมเผื่อช่วงก้าวของตัวเองให้กับคนข้างๆ เสียงฝีเท้าที่ก้าวลงในจังหวะเดียวกันมั่นคงที่สุด"},"ICON-2571":{"nm":"เครื่องหมายรูปเกือกม้าตำแหน่งคำนับบนเวที","de":"แม้แต่การคำนับบนเวทีเพียงครั้งเดียวก็มีที่ยืนของมัน วางเท้าลงบนรอยที่แผ่ขยายเป็นวงกลมเหมือนเกือกม้า การทักทายครั้งแรกที่มักผิดพลาดเพราะความประหม่าก็จะพบรูปแบบของตัวเองในที่สุด เมื่อรู้ตำแหน่งแล้ว ความสั่นก็จะสงบลงเล็กน้อยด้วย"},"ICON-2572":{"nm":"การ์ดท่าทางขอบคุณ","de":"ความขอบคุณที่คำพูดไม่อาจถ่ายทอดได้หมดไหลออกมาทางปลายนิ้ว วาดรูปหัวใจ วางมือลงบนอก—ท่าทางแต่ละอย่างที่เขียนไว้บนการ์ดกลายเป็นคำแปลของหัวใจที่ถูกถอดความออกมาเป็นการเคลื่อนไหว ความจริงใจที่อยากไปให้ถึงมักมีรูปร่างเสมอ"},"ICON-2573":{"nm":"หลักการ์ดระยะห่างแถวรอ","de":"แม้แต่การยืนต่อแถวก็มีมารยาทอันอ่อนโยน เหมือนหลักที่รักษาระยะห่างจากคนข้างหน้าไว้พอดีหนึ่งคืบ การรอคอยเริ่มต้นจากความใส่ใจเล็กๆ ที่ไม่อยากเบียดกัน การยืนห่างออกไปนิดหน่อยก็เป็นการเอาใจใส่เช่นกัน"},"ICON-2574":{"nm":"ห่วงพลิกคิวการ์ดคำพูด","de":"เมื่อคำพูดถัดไปวนเวียนอยู่ที่ริมฝีปากอยู่เรื่อยๆ นิ้วมือก็ค่อยๆ พลิกไปหนึ่งแผ่น กระดาษเล็กๆ ที่ร้อยไว้บนห่วงกดหัวใจที่เต้นระริกไว้อย่างแผ่วเบา และคลี่ช่องของสิ่งที่จะพูดต่อไปออกมาอย่างสงบ แม้จะสั่นแต่กระแสก็ไม่ขาดตอน"},"ICON-2575":{"nm":"นาฬิกาทรายลำดับรายการ","de":"จ้องมองเม็ดทรายที่ไหลลงเรื่อยๆ อย่างนิ่งเงียบ ลำดับถัดไปก็ค่อยๆ จัดระเบียบขึ้นในใจอย่างสงบ ก่อนเม็ดทรายเม็ดสุดท้ายจะร่วงลง นาฬิกาเล็กๆ นี้สอนวิธีอ่านเวลาด้วยสายตาโดยไม่รีบร้อน"},"ICON-2576":{"nm":"แท่งฝึกจับไมโครโฟน","de":"ก่อนจะคุ้นมือ แท่งเปล่าๆ อันเดียวก็หนักอึ้งราวกับพันตัน มุมจับ ระยะห่างจากปาก แรงที่ให้กับข้อมือ—การฝึกซ้อมจับแล้วปล่อยซ้ำแล้วซ้ำเล่านับครั้งไม่ถ้วน วันหนึ่งจะผลิบานเป็นการเคลื่อนไหวเดียวที่เป็นธรรมชาติอย่างไม่รู้ตัว"},"ICON-2577":{"nm":"แท่งลิ้นฝึกออกเสียงชัด","de":"กอ ขอ คอ งอ กัดแท่งไว้ในปากแล้วกลิ้งเสียงจนกว่าปลายลิ้นจะชัดเจน คำพูดที่ข้ามผ่านมาอย่างชัดถ้อยชัดคำนั้น เหมือนดอกไม้ที่ผลิบานอย่างเงียบๆ อยู่เหนือช่วงเวลาหลายร้อยครั้งของการพูดติดๆ ขัดๆ ไม่ชัดเจน"},"ICON-2578":{"nm":"ธงมือสัญญาณคิว","de":"เริ่ม หยุด พักหนึ่งจังหวะ ธงเพียงผืนเดียวที่ไร้คำพูดกำกับลมหายใจของเวที มือที่โบกอยู่นิ่งๆ ในตำแหน่งที่ผู้ชมมองไม่เห็น ยึดจังหวะทุกจังหวะไว้อย่างไม่มีช่องว่าง"},"ICON-2579":{"nm":"กระดิ่งเปลี่ยนช่วงรายการ","de":"ดังกริ๊งใสกังวานแล้วฉากก็เปลี่ยนไป เหมือนเสียงกระดิ่งที่แผ่กระจายไปทั่วตลาดยามพลบค่ำ เสียงกังวานเล็กๆ นี้พาใจที่ลังเลข้ามไปยังช่วงต่อไปอย่างแผ่วเบา การเปลี่ยนผ่านเริ่มต้นจากเสียงเสมอ"},"ICON-2580":{"nm":"ลูกตุ้มจังหวะลมหายใจคำพูด","de":"สูดหายใจเข้า—หนึ่ง สอง—แล้วค่อยๆ หายใจออก เมื่อควบคุมลมหายใจตามลูกตุ้มที่แกว่งไปมาซ้ายขวา คำพูดที่เคยหลั่งไหลออกมาเร็วเกินไปก็จะค้นพบจังหวะของตัวเองอีกครั้งในไม่ช้า ความเร็วของคำพูดในที่สุดแล้วก็คือความเร็วของลมหายใจนั่นเอง"},"ICON-2581":{"nm":"แผ่นพับบทดำเนินรายการ","de":"ในการเคลื่อนไหวเพียงครั้งเดียวของการพับแล้วคลี่ ลำดับของวันนี้ถูกบรรจุไว้อย่างครบถ้วน วินาทีที่คลี่แผ่นที่มีรอยมือจับติดลึกออก ใจที่สับสนว่าจะหยิบอะไรขึ้นมาก่อนก็เรียงแถวอย่างสงบ การคลี่เพียงครั้งเดียวจัดระเบียบทั้งวัน"},"ICON-2582":{"nm":"นาฬิกาทรายจังหวะลมหายใจ","de":"หายใจเข้าสาม กลั้นสี่ หายใจออกหก ระหว่างที่ทรายไหล ลมหายใจของฉันก็ไหลตามไปอย่างนิ่งสงบ การนับลมหายใจทีละครั้งคือวิธีที่เก่าแก่และอ่อนโยนที่สุดในการดูแลตัวเองที่ยุ่งอยู่เสมอให้ช้าลง"},"ICON-2583":{"nm":"พู่ประดับเบาะสมาธิ","de":"พู่ที่ห้อยอยู่ปลายเบาะแกว่งไหวอย่างแผ่วเบาแม้ไม่มีลม เมื่อนั่งขัดสมาธิ ความสงบของคนโบราณที่นั่งอยู่บนระเบียงไม้เพื่อสงบใจก็ล่องลอยมาอยู่เคียงข้างอย่างแผ่วเบา แวะพักสักครู่แล้วจากไป"},"ICON-2584":{"nm":"ระฆังลมมือปรับลมหายใจ","de":"เมื่อสายลมพัดผ่านมาสักหนึ่งครั้ง เสียงใสก็ร้องไห้อย่างแผ่วเบา สิ่งนี้ที่ห้อยอยู่เหมือนระฆังลมที่ชายคา หยดหยดหนึ่งอันเย็นสดชื่นลงบนใจที่ปั่นป่วนวุ่นวาย แม้แต่เสียงก็มีพลังในการทำให้เย็นลง"},"ICON-2585":{"nm":"จานรองควันธูป","de":"ควันที่เหลือจากการเผาธูปค่อยๆ ตกลงมาบนจาน เหมือนกลิ่นหอมที่ลอยขึ้นหน้าโต๊ะบูชาในเช้าวันเทศกาล ควันเพียงสายเดียวค่อยๆ ทำให้อากาศที่วุ่นวายสงบลงและเติมเต็มห้องด้วยความเงียบสงบ"},"ICON-2586":{"nm":"ลูกตุ้มแกว่งหายใจเข้าออก","de":"ลมหายใจของฉันขี่อยู่บนลูกตุ้มเพียงลูกเดียวที่ค่อยๆ ลอยขึ้นแล้วจมลงอีกครั้ง ลอยขึ้นตอนหายใจเข้า จมลงตอนหายใจออก—ในวันที่ร่างกายลืมวิธีหายใจ นาฬิกาเล็กๆ นี้จะสอนใหม่ตั้งแต่ต้น"},"ICON-2587":{"nm":"ไม้ตีระฆังสมาธิ","de":"ตีระฆังเบาๆ เพียงครั้งเดียว เสียงก้องก็แผ่กระจายยาวนาน เหมือนเสียงระฆังลมที่ดังก้องอยู่ในวัดบนภูเขา เพียงแค่ฟังอย่างนิ่งเงียบจนกว่าเสียงก้องนั้นจะหายลับไปในอากาศจนหมดสิ้น มุมหนึ่งของหัวใจก็ถูกชะล้างจนใสสะอาด"},"ICON-2588":{"nm":"ขนนกนำทางลมหายใจ","de":"วางขนนกไว้นิ่งๆ ตรงหน้าจมูก เส้นทางลมหายใจที่มองไม่เห็นก็ในที่สุดปรากฏให้เห็น ถ้าไหวเบาๆ แปลว่าหายใจได้ดี ถ้านิ่งแปลว่ากลั้นไว้นานเกินไป สิ่งที่เบาที่สุดบางครั้งก็เป็นผู้นำทางที่ซื่อตรงที่สุด"},"ICON-2589":{"nm":"หินกรวดสงบจิตใจ","de":"ก้อนกรวดที่กำไว้ในฝ่ามือเย็นและเรียบลื่น เหมือนก้อนหินที่กลิ้งอยู่ริมแม่น้ำมานาน จนสละมุมคมทั้งหมดไปหมดแล้ว เมื่อลูบคลำที่ปลายนิ้วไปเรื่อยๆ ส่วนคมของใจที่ปั่นป่วนก็ค่อยๆ สึกกร่อนกลมมนไปทีละนิด"},"ICON-2590":{"nm":"คลิปวัดอุณหภูมิลมหายใจจมูก","de":"อุณหภูมิที่ปลายจมูกบอกความลึกของลมหายใจอย่างเงียบๆ คลิปอ่านอากาศที่เข้ามาเย็นและออกไปอุ่นอย่างเงียบๆ แสดงให้เห็นการหายใจที่ปกติแล้วไม่เคยรู้สึกได้อย่างชัดเจนตรงหน้า แม้แต่ลมหายใจก็มีสีหน้าของมันเอง"},"ICON-2591":{"nm":"ป้ายสติกเกอร์อากาศอารมณ์","de":"วันนี้ใจของฉันจะแจ่มใสหรือมีเมฆครึ้ม วินาทีที่เลือกสติกเกอร์เล็กๆ แปะลงบนป้าย อารมณ์ที่ยากจะเอ่ยเป็นคำพูดก็กลายเป็นสภาพอากาศชนิดหนึ่งที่มีรูปร่างชัดเจน แม้แต่ใจก็ต้องการพยากรณ์อากาศเช่นกัน"},"ICON-2592":{"nm":"ตราปั๊มมือสีอารมณ์","de":"ความสุขคือสีเหลือง ความเศร้าคือสีฟ้า เลือกสีแล้วกดลงบนกระดาษแน่นๆ สีสันของใจก็หลงเหลือเป็นรอยประทับ แม้แต่อารมณ์ที่ตั้งชื่อไม่ถูก สีก็เข้ามาก่อนและรับรู้มันไว้อย่างแผ่วเบา"},"ICON-2593":{"nm":"ชิปกลีบดอกไม้หัวใจวันนี้","de":"ลองวางใจของทั้งวันนี้ไว้เบาๆ บนกลีบดอกไม้กลีบหนึ่ง เหมือนดอกอาซาเลียที่ปลิวไสวในวันฤดูใบไม้ผลิ ชิปเบาบางอ่อนโยนชิ้นหนึ่งถามไถ่เบาๆ ที่ปลายวันอันเลือนราง ว่าเป็นอย่างไรบ้าง"},"ICON-2594":{"nm":"แม่เหล็กบับเบิลคำให้กำลังใจ","de":"คำที่อยากพูดวนเวียนอยู่ที่ริมฝีปากอยู่เรื่อยๆ วินาทีที่แปะแม่เหล็กบับเบิลคำพูดลง คำให้กำลังใจสักคำที่ไม่กล้าเปล่งเสียงออกมาก็ไปถึงวันอันเหนื่อยล้าของใครสักคนอย่างแผ่วเบา ใจถูกส่งต่อไปเช่นนั้นเอง"},"ICON-2595":{"nm":"ตราซีลซองจดหมายใจ","de":"คำพูดที่ยังพูดออกมาไม่ได้ถูกใส่ไว้ในซองจดหมายอย่างเรียบร้อยแล้วปิดผนึก เหมือนคนโบราณที่ทาแป้งเปียกปิดจดหมายด้วยปลายนิ้ว ตราซีลเพียงดวงเดียวปกป้องใจข้างในไว้อย่างปลอดภัย รอคอยวันที่จะหยิบออกมาคลี่อ่านอย่างเงียบๆ"},"ICON-2596":{"nm":"ดอกตูมอุณหภูมิอารมณ์","de":"ดอกตูมที่หุบอยู่ เมื่อสัมผัสความอบอุ่นก็ค่อยๆ คลี่บานออกทีละกลีบอย่างระมัดระวัง บานขึ้นเมื่ออุณหภูมิของใจสูงขึ้น—ว่าวันนี้ฉันอุ่นขึ้นแค่ไหน ดอกไม้นี้รู้ก่อนคำพูดเสียอีก ฤดูใบไม้ผลิมาเยือนใจได้เช่นกัน"},"ICON-2597":{"nm":"สายกระจกมือชมตัวเอง","de":"ยกกระจกขึ้นแล้วสบตากับตัวเองที่สะท้อนอยู่ในนั้นอย่างนิ่งเงียบ สิ่งที่หน้ากระจกเล็กๆ ที่ห้อยอยู่กับสายสะท้อนให้เห็นไม่ใช่ใบหน้า แต่คือฉันของเมื่อวานที่สมควรได้รับคำพูดสักคำว่าอดทนมาได้ดีแล้ว การปลอบใจไม่เคยอยู่ไกลเลย"},"ICON-2598":{"nm":"ชุดตราปั๊มสีหน้าอารมณ์","de":"รอยยิ้มสดใส น้ำตาคลอเบ้า ริมฝีปากบึ้งตึง กดตราปั๊มสีหน้าแน่นๆ เขียนไดอารี่ของหัวใจ ในวันที่ท่วมท้นเกินกว่าจะเขียนเป็นตัวอักษร ใบหน้าเล็กๆ ใบหนึ่งบอกอารมณ์ของวันนั้นแทนฉันอย่างเงียบๆ"},"ICON-2599":{"nm":"ห่วงจัดระเบียบด้ายพันอารมณ์","de":"ไม่ว่าเส้นด้ายจะพันกันยุ่งเหยิงแค่ไหน หากค่อยๆ คลี่ออกทีละเส้นอย่างใจเย็นในที่สุดก็จะกลับมาเป็นเส้นเดียว เมื่อแขวนอารมณ์ที่สับสนอึดอัดไว้บนห่วงทีละเส้น แม้แต่ใจที่ไม่เข้าใจตัวเองเลยก็จับปลายด้ายเส้นเล็กๆ ได้"},"ICON-2600":{"nm":"เชือกถุงหอมก่อนนอน","de":"จากถุงหอมที่แขวนไว้หัวหมอน กลิ่นหอมอ่อนๆ ของสมุนไพรค่อยๆ แผ่กระจายอย่างแผ่วเบา เหมือนกลิ่นที่คุณยายเคยเก็บไว้ลึกในตู้เสื้อผ้า ระหว่างที่สัมผัสเชือกเบาๆ ความตึงเครียดที่เกร็งอยู่ตลอดทั้งวันก็ค่อยๆ หลับใหลไป"},"ICON-2601":{"nm":"กระดานพลิกท่านอน","de":"คืนที่นอนพลิกไปมาจนหลับได้ก็ปาเข้าไปใกล้รุ่ง เมื่อค่อย ๆ พลิกท่านอนให้เบา ๆ ความกระสับกระส่ายของเมื่อวานก็ค่อย ๆ กลายเป็นความสดชื่นของเช้าวันนี้อย่างแผ่วเบา การพักผ่อนก็ต้องฝึกฝนเหมือนกัน แผ่นเล็ก ๆ แผ่นนี้จึงคอยช่วยอยู่เงียบ ๆ โดยไม่ปริปากสักคำ"},"ICON-2602":{"nm":"ที่แขวนแสงจันทร์ข้างหมอน","de":"แขวนเสี้ยวแสงที่ลอดผ่านช่องม่านเข้ามาไว้ที่ข้างหมอนสักชิ้น สายธารแสงอันแผ่วเบาก็ไหลรินเหนือใบหน้าที่หลับใหล และค่ำคืนของเด็กฝึกที่เคยหวาดกลัวความมืดก็อ่อนโยนลงในที่สุด นี่คือความอุ่นใจเล็ก ๆ ชิ้นแรกที่เธอเคยมี"},"ICON-2603":{"nm":"ชิปดอกไม้ตูมบอกสภาพร่างกาย","de":"สภาพร่างกายของวันนี้หุบอยู่เหมือนดอกไม้ตูม เมื่อกดชิปเบา ๆ มันก็ค่อย ๆ คลี่บาน ราวกับร่างกายรู้ก่อนใครว่าคืนที่ผ่านมาหลับสบายหรือไม่ แม้แต่ความลังเลก่อนจะบานเต็มที่ก็ยังน่ารักอย่างเงียบสงบ"},"ICON-2604":{"nm":"ฝาครอบไส้ตะเกียงก่อนนอน","de":"\"อย่าปิดไฟนะ\" เพื่อน้องคนสุดท้องที่กลัวความมืด ใครสักคนจึงค่อย ๆ สวมฝาครอบไว้เหนือไส้ตะเกียง ไม่ให้สว่างเกินไปและไม่ให้มืดเกินไป เป็นคำสัญญาเล็ก ๆ ที่อ่อนโยน คอยอยู่เป็นเพื่อนแค่จนกว่าจะหลับไป"},"ICON-2605":{"nm":"เข็มกลัดทานตะวันปลุกยามเช้า","de":"เสียบไว้ข้างหัวนอน แล้วมันจะค่อย ๆ หันหน้าไปทางแสงแดดแรกยามเช้าเหมือนดอกทานตะวัน แม้ในวันที่ไม่อยากตื่น แสงที่เรียกหาก็ย่อมมีเหตุผลของมันเสมอ มันจึงพาเช้าวันใหม่มุ่งไปในทิศทางเดียวกัน"},"ICON-2606":{"nm":"แปรงหอมกล่อมนอนสำหรับหมอน","de":"จุ่มปลายแปรงลงในลาเวนเดอร์และคาโมมายล์แล้วปาดผ่านหมอนสักครั้ง ระหว่างที่กลิ่นหอมค่อย ๆ ซึมเข้าไปในปลอกหมอน ความตึงเครียดของวันหนึ่งก็ค่อย ๆ คลายลงจากบ่าไหล่ การนอนหลับที่ดีเริ่มต้นจากกลิ่นหอมเล็ก ๆ นี้เอง"},"ICON-2607":{"nm":"คลิปหนีบมุมผ้าห่มยามนอน","de":"พอใกล้รุ่ง ปลายเท้าก็มักจะแอบหนีออกไปนอกผ้าห่มเสมอ หากใช้คลิปหนีบมุมผ้าไว้ให้แน่นหนา ความอบอุ่นก็จะไม่มีวันหนีไปได้ตลอดทั้งคืน มันคือมาตรการเล็ก ๆ ที่ใช้แทนคำว่า \"ฝันดีนะ\""},"ICON-2608":{"nm":"ตะกร้าเก็บก้อนกรวดวัดสภาพใจ","de":"วันละหนึ่งเรื่องดี ก้อนกรวดขนาดเท่าฝ่ามือหนึ่งก้อน ยิ่งก้อนหินในตะกร้าถ่วงหนักขึ้นเท่าไร หัวใจก็ยิ่งรู้สึกมั่นคงขึ้นเท่านั้น การกำเก็บช่วงเวลาธรรมดา ๆ ไว้ในมือ นี่แหละคือวิธีนับความสุขมาแต่ไหนแต่ไร"},"ICON-2609":{"nm":"โถรวมดาวแห่งคำมั่นสัญญา","de":"ทุกคืน ปั้นคำมั่นสัญญาของวันนี้ให้เป็นรูปดาวแล้วหย่อนลงในโถเบา ๆ เมื่อเต็มโถก็จะกลายเป็นท้องฟ้ายามค่ำคืนใบเล็ก ปากโถที่เคยว่างเปล่ารู้ดีว่า คำสัญญาจะเปล่งประกายได้ก็ต่อเมื่อสะสมไว้ด้วยกัน"},"ICON-2610":{"nm":"ที่แขวนลูกอมรางวัลเล็ก ๆ","de":"ลูกอมหนึ่งเม็ดที่มอบให้ตัวเองในตอนท้ายของวันอันแสนเหนื่อยล้า พอหยิบมาจากที่แขวนแล้วอมไว้ในปาก ต่อให้ไม่มีใครมองเห็นก็ไม่เป็นไรอีกต่อไป เพราะรางวัลเล็ก ๆ คือเสียงเชียร์ที่ซื่อตรงที่สุดแล้ว"},"ICON-2611":{"nm":"ตรายางประทับ \"วันนี้ทำได้แล้ว\"","de":"จุ่มหมึกแล้วกดลงบนสมุดหนึ่งครั้ง \"วันนี้ทำสำเร็จแล้ว\" ไม่ว่าจะเป็นวันที่ทำได้ดีหรือวันที่แค่ฝืนอดทนผ่านมา ก็เติมเต็มช่องหนึ่งได้เหมือนกัน ไม่จำเป็นต้องสมบูรณ์แบบทุกวัน เพียงแค่อย่าหยุดประทับตราก็พอแล้ว"},"ICON-2612":{"nm":"ฐานปักธงให้กำลังใจ","de":"ปักลงกับพื้นให้แน่นหนา ยิ่งลมแรงเท่าไร ธงก็ยิ่งโบกสะบัดอย่างมีพลังมากขึ้นเท่านั้น แม้แต่สิ่งที่สั่นไหวก็ยังต้องการมือที่คอยค้ำจุน หัวใจที่คอยเชียร์ใครสักคนก็ยืนหยัดอยู่เบื้องล่างเช่นนี้เอง"},"ICON-2613":{"nm":"กระถางปลูกเมล็ดพันธุ์เป้าหมาย","de":"เป้าหมายไม่ใช่สิ่งที่ท่องจำด้วยคำพูด แต่เป็นสิ่งที่ฝังลงในดิน ระหว่างที่ปลูกเมล็ดพันธุ์หนึ่งเม็ด รดน้ำ และเฝ้ารอ ความใจร้อนก็ค่อย ๆ กลายเป็นรากที่หยั่งลึก สิ่งที่เติบโตอยู่ในกระถางนั้นไม่ใช่แค่หน่ออ่อนเท่านั้น"},"ICON-2614":{"nm":"กระดานติดสติกเกอร์คำชม","de":"สติกเกอร์หนึ่งแผ่นสำหรับทุกเรื่องที่ทำได้ดี ยิ่งกระดานเต็มไปด้วยสีสันมากเท่าไร วันเวลาที่เคยผ่านไปโดยไม่ทันสังเกตก็ยิ่งฟื้นคืนชีวิตขึ้นมาเป็นสีสัน ตอนเด็ก ๆ เรารู้ดีว่า คำชมยิ่งแปะไว้มากเท่าไรก็ยิ่งเด่นชัดขึ้นเท่านั้น"},"ICON-2615":{"nm":"ห่วงผูกโบว์แห่งคำมั่นสัญญา","de":"มือที่ร้อยริบบิ้นผ่านห่วงแล้วผูกเป็นปม แน่นหนาพอไม่ให้หลุด แต่ก็ไม่แน่นจนเกินไป คำมั่นสัญญาก็เหมือนปมนี้เอง หากรัดแน่นเกินไปก็ขาด หากหลวมเกินไปก็ค่อย ๆ ลื่นไถลหลุดไป"},"ICON-2616":{"nm":"ชิปเปลือกหอยแห่งความสำเร็จเล็ก ๆ","de":"เขียนความสำเร็จเล็ก ๆ ลงบนเปลือกหอยที่เก็บมาจากชายหาด เหมือนเศษเปลือกหอยชิ้นหนึ่งที่ถูกคลื่นขัดเกลามาจนถึงตรงนี้ วันเวลาของเธอก็หมุนกลิ้งมานานจนเป็นเงาวาว สิ่งใดก็ตามที่ทนผ่านกาลเวลามาได้ ล้วนเปล่งประกายเสมอ"},"ICON-2617":{"nm":"ตะขอแขวนเหรียญรางวัล","de":"เหรียญที่พากเพียรได้มาไม่ควรเก็บไว้ในลิ้นชัก แต่ควรแขวนไว้ในระดับสายตา น้ำหนักที่แขวนอยู่บนตะขอนั้นช่วยให้ผายบ่ายืดตรงได้ทุกเช้า รางวัลไม่ใช่สิ่งที่ต้องซ่อน แต่เป็นสิ่งที่แขวนไว้ตรงนั้นเพื่อให้มองเห็น"},"ICON-2618":{"nm":"ถ้วยรองน้ำหยดจากร่มหน้าฝน","de":"สายฝนหน้ามรสุมไหลรินลงมาตามปลายร่ม เมื่อวางถ้วยไว้รองสักใบ หน้าประตูก็ไม่เปียก แม้จะหยุดสิ่งที่หลั่งไหลลงมาไม่ได้ แต่ก็ยังกำหนดที่ที่มันจะตกลงได้"},"ICON-2619":{"nm":"ถุงประคบเย็นคลายร้อน","de":"หลังเวทีในกลางฤดูร้อน ถุงเย็นถูกแตะเบา ๆ ที่ต้นคอ ความร้อนที่พลุ่งขึ้นมาก็สงบลงไปหนึ่งจังหวะ \"พักหายใจสักครู่นะ\" มือที่คอยดูแลฉันก่อนแม้แต่ความร้อนเองนั้นช่างอุ่นใจเหลือเกิน"},"ICON-2620":{"nm":"คลิปล็อกใบพัดพัดลม","de":"แม้แต่ใบพัดที่หมุนแรง ก็หยุดนิ่งลงได้ด้วยคลิปเพียงตัวเดียว ยิ่งลมแรงมากเท่าไร ก็ยิ่งต้องการบางสิ่งที่จับยึดไว้ให้มั่นคงมากเท่านั้น สิ่งที่หมุนเร็วจะปลอดภัยได้ก็ขึ้นอยู่กับว่าใครเป็นคนจับมันไว้"},"ICON-2621":{"nm":"แท่งอบแห้งรองเท้าเปียก","de":"รองเท้าที่เปียกฝนทำให้แม้แต่หัวใจชื้นแฉะไปด้วยตลอดทั้งคืน หากสอดแท่งนี้ไว้ข้างใน พอถึงเช้าก็จะแห้งสนิทพร้อมสวมใส่ได้อีกครั้ง สิ่งที่เปียกไม่ใช่สิ่งที่ต้องทิ้งไป แต่เป็นสิ่งที่ต้องผึ่งให้แห้งอย่างทะนุถนอมต่างหาก"},"ICON-2622":{"nm":"แผ่นขูดโคลนรองเท้าบูท","de":"รองเท้าบูทที่เปื้อนโคลนจากคันนามาเต็มคู่ ต้องถูไถบนแผ่นนี้จนสะอาดเสียก่อนจึงจะก้าวขึ้นบ้านได้ การทิ้งโคลนตมจากภายนอกไว้หน้าประตูก่อนเข้าบ้าน คือมารยาทเก่าแก่ที่ช่วยรักษาบ้านให้สะอาดเรียบร้อยเสมอ"},"ICON-2623":{"nm":"แผ่นกระเบื้องเย็นปูพื้นหน้าร้อน","de":"เท้าเปล่ารู้ก่อนใคร เมื่อวางฝ่าเท้าลงบนแผ่นกระเบื้องที่ปูไว้บนพื้นในหน้าร้อน ความร้อนของกลางวันก็มลายหายไปกับความเย็นเพียงหยิบมือ เพียงความเย็นเล็ก ๆ หนึ่งจุด ก็ทำให้ฤดูอันยาวนานพอทนได้แล้ว"},"ICON-2624":{"nm":"แถบกันน้ำฝนที่ธรณีประตู","de":"เพียงพันแถบเส้นหนึ่งรอบธรณีประตู น้ำฝนก็ไม่อาจไหลข้ามเข้ามาข้างในได้อีก เส้นบาง ๆ ที่แบ่งข้างในกับข้างนอก สถานที่ที่ต้องปกป้องนั้นเหมาะกับขอบเขตที่แน่นหนามากกว่ากำแพงใหญ่โต"},"ICON-2625":{"nm":"จานรองยากันยุงแบบขด","de":"ในคืนฤดูร้อน เมื่อวางยากันยุงไว้บนจานรอง ควันฉุนแต่คุ้นเคยก็ลอยขึ้นมา คืนก็ค่อย ๆ ลึกลงเหมือนธูปที่มอดไหม้ไปทีละวง นี่คือกลิ่นของวันวานที่เคยนอนนับดาวอยู่บนแคร่ไม้"},"ICON-2626":{"nm":"ห่วงยึดปลอกแขนคลายร้อน","de":"ปกปิดแขนที่แสบร้อนจากแดดด้วยปลอกแขน เมื่อยึดติดกับแขนเสื้อไว้ให้มั่นด้วยห่วง งานกลางแดดจ้าก็พอทนไหว ความเย็นสบายคือน้ำใจเล็ก ๆ ที่คอยบังแดดในจุดที่มันสัมผัสไว้เพียงคืบเดียว"},"ICON-2627":{"nm":"ไม้กวาดมือกวาดใบไม้ร่วง","de":"กวาดใบไม้ร่วงที่เต็มลานบ้านให้มารวมกันด้วยไม้กวาดมือ ฤดูกาลหนึ่งส่งเสียงกรอบแกรบอยู่ใต้ฝ่าเท้า การจัดเก็บสิ่งใดสิ่งหนึ่งให้เป็นระเบียบ ก็คือการส่งสิ่งที่ต้องจากไปด้วยความอ่อนโยนเช่นกัน"},"ICON-2628":{"nm":"แท่งค้ำหน้าต่างระบายอากาศ","de":"สอดแท่งไม้ไว้ในห้องที่อึดอัดเพื่อเปิดหน้าต่างไว้เพียงเล็กน้อย ลมฤดูใบไม้ร่วงก็ลอดเข้ามาพัดพาอากาศเก่าที่คั่งค้างออกไป การระบายอากาศคือช่องหายใจเล็ก ๆ ที่คอยแลกเปลี่ยนสิ่งที่คั่งอยู่ข้างในกับข้างนอกอย่างเงียบ ๆ"},"ICON-2629":{"nm":"จุกปิดถุงเก็บลูกโอ๊ก","de":"เติมลูกโอ๊กจนเต็มถุงเหมือนกระรอก แล้วปิดปากถุงด้วยจุก ปิดให้แน่นเผื่อมันจะกลิ้งหลุดออกไป หัวใจที่ต้องการปกป้องสิ่งที่สะสมไว้ คือสัญชาตญาณเก่าแก่ของสิ่งเล็ก ๆ ที่ต้องฝ่าฟันฤดูหนาวให้ผ่านพ้นไป"},"ICON-2630":{"nm":"ไม้ตีฝุ่นผ้าห่มฤดูใบไม้ร่วง","de":"นำผ้าห่มที่ใช้มาตลอดฤดูร้อนไปตากที่ลานบ้านแล้วตีปัดฝุ่นด้วยไม้ตีดังตุบตับ กลิ่นแดดโชยแทรกอยู่ในกลุ่มฝุ่นละออง ต้องปัดฤดูกาลเก่าออกไปเสียก่อนจึงจะห่มฤดูกาลใหม่ได้ ข้อมือจดจำเรื่องนี้ได้ก่อนใคร"},"ICON-2631":{"nm":"เชือกกันลมโกรกช่องหน้าต่าง","de":"กั้นลมหนาวที่ลอดผ่านช่องหน้าต่างด้วยเชือกเส้นเดียวอย่างแน่นหนา เส้นบาง ๆ เพียงเส้นเดียวนี้ปกป้องความอบอุ่นในห้องไว้จนถึงที่สุด ความหนาวเหน็บอันยิ่งใหญ่มักเริ่มต้นจากช่องว่างเล็ก ๆ เสมอ การเตรียมพร้อมรับฤดูหนาวรู้ดีถึงเรื่องนี้"},"ICON-2632":{"nm":"ฝาตะแกรงกรองใบไม้รางน้ำ","de":"ตะแกรงที่ปิดไว้เหนือรางรับน้ำฝน กรองใบไม้ออกอย่างเรียบร้อยแล้วปล่อยให้เฉพาะน้ำไหลผ่าน ชายคาในฤดูใบไม้ร่วงบอกว่า หากอยากให้ไหลลื่นไม่ติดขัด ต้องกำหนดให้ชัดว่าจะปล่อยอะไรผ่านไปและจะกักสิ่งใดไว้"},"ICON-2633":{"nm":"คลิปมัดฟ่อนหญ้าแห้ง","de":"รัดฟ่อนหญ้าที่แห้งกรอบให้แน่นด้วยคลิป มือที่มัดรวมสิ่งที่กำลังจะกระจัดกระจายให้เป็นหนึ่งเดียว แม้ในที่ที่สีเขียวของฤดูร้อนจางหายไปหมดแล้ว หากเก็บรวมไว้ ประโยชน์ก็ยังคงอยู่ครบถ้วน"},"ICON-2634":{"nm":"ลูกแกว่งวัดอุณหภูมิลมใบไม้ร่วง","de":"เมื่อลมพัดมา ลูกแกว่งก็แกว่งไกวเบา ๆ วัดได้จากช่วงกว้างของการแกว่งไกวนั้นว่าฤดูใบไม้ร่วงวันนี้ลึกซึ้งเพียงใด อุณหภูมิไม่ใช่ตัวเลข แต่เป็นสิ่งที่แกว่งไกวสัมผัสมือเราได้ก่อนสิ่งใด"},"ICON-2635":{"nm":"ที่ใส่กระเป๋าไฟร้อนในกระเป๋าเสื้อโค้ท","de":"\"มือเย็นใช่ไหม\" ที่ใส่กระเป๋าไฟร้อนที่สอดไว้ในกระเป๋าเสื้อโค้ทค่อย ๆ อุ่นนิ้วมือที่เย็นเฉียบให้อบอุ่นขึ้น หัวใจที่คิดถึงความหนาวของใครสักคนก่อนใคร มักซ่อนอยู่เงียบ ๆ ในกระเป๋าเสื้อเสมอ"},"ICON-2636":{"nm":"ขอบรองน้ำหยดไอน้ำหน้าต่าง","de":"ขอบเล็ก ๆ นี้เงียบ ๆ รองรับหยาดน้ำตาที่หน้าต่างในฤดูหนาวหลั่งไหลตลอดทั้งคืน เป็นทางน้ำเล็ก ๆ ที่เกิดจากความต่างของอุณหภูมิระหว่างในบ้านกับนอกบ้าน หน้าต่างยามรุ่งอรุณแสดงให้เห็นทุกวันว่า ยิ่งที่ใดมีความต่างมาก สิ่งที่ไหลก็ยิ่งมากตามไปด้วย"},"ICON-2637":{"nm":"ตะแกรงกันไฟเตาผิง","de":"ตั้งตะแกรงนิรภัยไว้หน้าเตาผิงที่ลุกโชนอยู่ ให้ความอบอุ่นอยู่ใกล้ ส่วนอันตรายอยู่ห่างออกไปเพียงคืบเดียว การมีไฟอยู่ข้างกายโดยไม่ถูกไฟไหม้ คือระยะห่างพื้นฐานที่สุดของการดูแลใครสักคน"},"ICON-2638":{"nm":"คลิปกดยึดผ้าห่มหนาฤดูหนาว","de":"เมื่อผ้าห่มหนาของฤดูหนาวเลื่อนหลุดอยู่บ่อย ๆ คลิปนี้จะกดไว้และช่วยยึดตำแหน่งให้มั่นคง ความอบอุ่นที่หนักอึ้งต้องยึดไว้ให้แน่นจึงจะคุ้มค่า ความอบอุ่นสบายของค่ำคืนฤดูหนาวถูกปกป้องไว้อย่างแน่นหนาเช่นนี้เอง"},"ICON-2639":{"nm":"ไม้ขูดน้ำค้างแข็งกระจกรถ","de":"ขูดคราบน้ำค้างแข็งสีขาวที่จับกระจกรถยามเช้าตรู่ด้วยไม้ขูดนี้ ทัศนวิสัยที่มัวหมองก็เปิดกว้างขึ้นทีละเส้น ปลายนิ้วในเช้าฤดูหนาวบอกเราว่า แม้แต่สิ่งที่แข็งตัวอยู่ ในที่สุดก็ขูดออกได้เสมอ"},"ICON-2640":{"nm":"ปลอกคลุมฝากระติกน้ำร้อน","de":"สวมปลอกคลุมไว้บนกระติกที่บรรจุน้ำร้อน เพื่อไม่ให้เย็นลงตลอดทั้งคืน มันห่อหุ้มความอบอุ่นไว้อีกหนึ่งชั้น วิธีรักษาความอบอุ่นให้อยู่นานคือ ท้ายที่สุดแล้วต้องโอบกอดมันไว้ด้วยบางสิ่งอย่างตั้งใจ"},"ICON-2641":{"nm":"แท่งกดขอบกระดาษกันลมประตู","de":"สายลมเยือกเย็นดั่งมีดที่เจาะลึกผ่านช่องประตูสะดุดหยุดชะงักในทันทีที่พบเธอ แท่งไม้เพียงแท่งเดียวที่กดขอบล่างของกระดาษบานประตูไว้ให้แน่น ทำให้ความอบอุ่นในห้องปกป้องคนของตนได้ในที่สุด ฤดูหนาวจึงอบอุ่นได้ด้วยความดื้อรั้นเล็ก ๆ เช่นนี้"},"ICON-2642":{"nm":"จานรองเตาอุ่นเท้า","de":"จานกลมที่ปูรองอยู่ใต้เตาอุ่นเท้า รับความร้อนไว้เพียงลำพังโดยไม่ทิ้งรอยไหม้เกรียมไว้บนพื้นแม้แต่นิดเดียว เมื่อปลายเท้าของใครสักคนอุ่นขึ้นจนเคลิ้มหลับ วันของฉันในส่วนที่รับผิดชอบก็จบลงอย่างเงียบ ๆ"},"ICON-2643":{"nm":"ห่วงแขวนผ้าซับไอน้ำหน้าต่าง","de":"เพื่อไม่ให้ผ้าที่เช็ดหยดน้ำบนหน้าต่างยามรุ่งอรุณหมดที่ไป ห่วงหนึ่งจึงแขวนอยู่บนผนังรอคอย มากกว่าการซับน้ำจนชุ่มโชก การรอคอยเช้าวันพรุ่งนี้ในสภาพที่แห้งสนิทอีกครั้งต่างหาก คือหัวใจที่แท้จริงของการดูดซับ"},"ICON-2644":{"nm":"ที่แขวนตากถุงมือฤดูหนาว","de":"ถุงมือที่ผ่านศึกปาหิมะมาแล้วกางนิ้วออกเต็มที่อยู่ข้างเครื่องทำความร้อน ภาพที่มันห้อยอยู่บนที่แขวนพร้อมไอน้ำลอยกรุ่น เป็นสิ่งที่มาเยือนในช่วงท้ายของบ่ายวันที่ปลายจมูกแดงก่ำ คือการซักผ้าที่สงบสุขที่สุดของฤดูหนาว"},"ICON-2645":{"nm":"ขนไก่เปลี่ยนที่ปัดฝุ่น","de":"เมื่อขนไก่สึกหรอก็เปลี่ยนใส่ขนไก่ชุดใหม่ คือช่วงเวลาที่ปลายไม้ปัดฝุ่นกลับมานุ่มฟูอีกครั้ง อุปกรณ์ทำความสะอาดก็มีฤดูเปลี่ยนผ่านของมันเช่นกัน ชิ้นส่วนเล็ก ๆ นี้บอกให้เรารู้อย่างแผ่วเบาอยู่บนฝ่ามือ"},"ICON-2646":{"nm":"ด้ามบิดผ้าถูพื้น","de":"ด้ามจับที่ติดตั้งไว้เพื่อถนอมแรงข้อมือ เพียงบิดครั้งเดียว ผ้าถูก็คายน้ำออกมาเองอย่างเป็นระเบียบ ลาก่อนวันเวลาที่ต้องออกแรงสู้กับกระดานซัก ในงานบ้าน เคล็ดลับสักหยิบมือก็กลายเป็นความอ่อนโยนได้เช่นกัน"},"ICON-2647":{"nm":"หัวแปรงเปลี่ยนแปรงขัดพื้น","de":"เมื่อแปรงขัดพื้นสึกหรอก็เปลี่ยนแค่ส่วนหัวเท่านั้น ด้ามยังคงเดิม น้ำหนักที่มือคุ้นเคยก็ยังคงเดิมเช่นกัน ในสิ่งของที่ใช้มายาวนานนั้นมีความอ่อนโยนเล็ก ๆ แต่มั่นคงแฝงอยู่ ความตั้งใจที่จะไม่ทิ้งทั้งชิ้นไปทั้งหมด"},"ICON-2648":{"nm":"ไส้รีฟิลลูกกลิ้งเก็บขน","de":"พอฉีกแผ่นสุดท้ายของลูกกลิ้งกาวออกไป ก็รู้สึกว่างเปล่าขึ้นมาแปลก ๆ นั่นคือเวลาที่ใส่ไส้ใหม่เข้าไปสักม้วน มันคือคำสัญญาของรีฟิลที่ดื้อรั้นแต่อ่อนโยน ว่าจะรับผิดชอบแม้แต่ขนเส้นเดียวที่ติดอยู่บนเสื้อสเวตเตอร์จนถึงที่สุด"},"ICON-2649":{"nm":"ไม้ขูดฝุ่นซอกมุม","de":"แม้แต่มุมที่ไม้กวาดเอื้อมไม่ถึง ฝุ่นก็ยังตั้งรกรากอยู่อย่างเงียบ ๆ การขูดมุมให้สะอาดด้วยปลายเรียวเล็กนี้ หัวใจที่เอาใจใส่แม้กระทั่งจุดที่มองไม่เห็น คือศักดิ์ศรีที่แท้จริงของงานบ้าน"},"ICON-2650":{"nm":"หวีสางไม้กวาด","de":"แม้แต่ไม้กวาดที่กวาดอยู่ก็ต้องการมือที่คอยพักผ่อนให้เช่นกัน หวีเส้นผมที่พันกันอยู่ระหว่างขนไม้กวาดด้วยหวีนี้ ไม้กวาดที่เสร็จสิ้นภารกิจไปหนึ่งรอบก็พร้อมสำหรับการกวาดครั้งต่อไปในที่สุด"},"ICON-2651":{"nm":"แผ่นเคลือบแว็กซ์ตามลายไม้พื้น","de":"เมื่อเคลือบแว็กซ์หนึ่งชั้นตามลายไม้พื้น เนื้อไม้ก็ค่อย ๆ นึกถึงความเป็นเงางามที่ลืมเลือนไปนาน ฝ่าเท้าเกือบจะลื่นไถลแต่ก็ไม่ถึงกับลื่น เป็นบ่ายวันที่ทั้งบ้านยิ้มแย้มอย่างเป็นสุขด้วยความเงาวาว"},"ICON-2652":{"nm":"ไม้กวาดฝุ่นช่องประตู","de":"ฉันเล็งเป้าไปที่ฝุ่นที่อาศัยอยู่ในช่องประตู สิ่งที่แอบสะสมทุกครั้งที่ประตูเปิดปิด ฉันกวาดเก็บด้วยร่างกายบางเฉียบของฉันเอง ยิ่งช่องแคบและลึกมากเท่าไร คิวของฉันก็ยิ่งมาถึงอย่างแน่นอนเสมอ"},"ICON-2653":{"nm":"ฝาตะแกรงกันฝุ่นพรมเช็ดเท้า","de":"เพื่อไม่ให้ฝุ่นที่พรมเช็ดเท้าหน้าประตูกลืนกินไว้รั่วไหลออกไปอีก ฝาตะแกรงหนึ่งชิ้นจึงยืนเป็นยามเฝ้าประตูคนสุดท้าย ฝุ่นที่รองเท้าเปื้อนดินพามาจากโลกภายนอก จะได้รับอนุญาตให้เข้ามาได้เพียงแค่นี้เท่านั้น"},"ICON-2654":{"nm":"แปรงขัดคราบตะกรันก๊อกน้ำ","de":"แปรงเล็ก ๆ หมุนวนขัดคราบตะกรันที่แอบจับอยู่ที่คอก๊อกน้ำออกไป ยิ่งเป็นจุดที่มือสัมผัสทุกวัน ก็ยิ่งต้องเงางามมากขึ้นเท่านั้น นั่นคือมารยาทของห้องน้ำที่แปรงเล็ก ๆ นี้คอยพิทักษ์ไว้"},"ICON-2655":{"nm":"ฝาตะแกรงกันเส้นผมท่อระบายน้ำ","de":"ฉันจับเส้นผมที่กำลังไหลลงท่อระบายน้ำไว้อย่างเงียบ ๆ การป้องกันหายนะเล็ก ๆ อย่างการอุดตันด้วยฝาเพียงชิ้นเดียว วันหนึ่งของฮีโร่กลมเล็กแต่แน่นหนาผู้นี้ ไหลผ่านไปอย่างเงียบเชียบอยู่ใต้ฝ่าเท้าเสมอ"},"ICON-2656":{"nm":"ไม้ขูดร่องยาแนวกระเบื้อง","de":"ร่องยาแนวที่มีคราบดำแทรกอยู่ระหว่างกระเบื้องสีขาว ขูดกาลเวลาอันเก่าแก่นั้นออกไปเบา ๆ ด้วยปลายไม้ขูด เมื่อร่องแคบ ๆ นั้นสะอาดหมดจด ห้องน้ำทั้งห้องก็สูดลมหายใจได้เบาสบายราวกับใหม่อีกครั้ง"},"ICON-2657":{"nm":"เข็มแคะรูฝักบัวอาบน้ำ","de":"แคะรูฝักบัวที่อุดตันด้วยปลายเข็มเบา ๆ น้ำที่เคยไหลซึมเอื่อย ๆ มานานก็พุ่งกระจายสดชื่นอีกครั้ง เสียงน้ำยามเช้าที่แสนสะใจ เมื่อการอุดตันเล็ก ๆ หนึ่งจุดได้รับการปลดปล่อย"},"ICON-2658":{"nm":"ถ้วยเก็บแปรงล้างโถส้วม","de":"แปรงล้างโถส้วมก็ต้องพักในที่แห้งจึงจะถูกสุขลักษณะอย่างแท้จริง มันปักอยู่อย่างเป็นระเบียบในถ้วยเล็ก ๆ ที่คอยรองรับหยดน้ำ รอคอยรอบถัดไป ศักดิ์ศรีของเครื่องมือไม่ได้อยู่ที่การใช้งาน แต่แสดงออกมาจากวิธีการจัดเก็บต่างหาก"},"ICON-2659":{"nm":"ฟองน้ำเช็ดคราบเชื้อรา","de":"เชื้อราสีดำที่ลามอยู่ตามมุมกระเบื้อง ฟองน้ำนี้สุภาพขอเชิญแขกผู้ดื้อรั้นคนนั้นให้ออกไป เพียงเช็ดผ่านครั้งเดียว ห้องน้ำก็กลับคืนสู่สีขาวสว่างไสวดั่งเดิมอีกครั้ง"},"ICON-2660":{"nm":"ที่ปาดไอฝ้ากระจก","de":"หน้ากระจกที่พร่ามัวไปด้วยไอน้ำหลังอาบน้ำเสร็จ เมื่อที่ปาดลากผ่านไปหนึ่งเส้น ใบหน้าอันชัดเจนของฉันก็กลับคืนมา คือช่วงเวลาที่ได้เผชิญหน้ากับสีหน้าของวันนี้ที่เคยแอบซ่อนอยู่หลังไอฝ้าอีกครั้ง"},"ICON-2661":{"nm":"ที่แขวนรองเท้าแตะห้องน้ำ","de":"แขวนรองเท้าแตะที่เปียกกลับหัวลง น้ำก็ไหลออกและด้านในก็แห้งสนิท เพื่อไม่ให้เท้าของคนถัดไปต้องเย็นเฉียบ น้ำใจของที่แขวนเล็ก ๆ นี้ออกไปต้อนรับล่วงหน้าไว้เสมอหนึ่งก้าว"},"ICON-2662":{"nm":"ตลับเก็บแปรงล้างเล็บ","de":"แม้แต่แปรงเล็ก ๆ ที่ขัดคราบใต้เล็บก็มีบ้านของตัวเอง มันเข้าไปอยู่ในตลับพอดิบพอดี ค่อย ๆ แห้งสนิทปราศจากความชื้น รอคอยการล้างหน้าครั้งต่อไป ความสะอาดเรียบร้อยเริ่มต้นอย่างเงียบ ๆ จากการจัดเก็บเสมอ"},"ICON-2663":{"nm":"ฝาแก้วฆ่าเชื้อแปรงสีฟัน","de":"แม้แต่แปรงสีฟันที่ต้องพบปากวันละสองครั้งก็ต้องการที่พักพิงเล็ก ๆ ในวินาทีที่ฝาแก้วฆ่าเชื้อปิดลงสนิท ความสะอาดหนึ่งช่องก็ถูกปกป้องไว้อย่างเงียบ ๆ จากความชื้นที่ล่องลอยอยู่ในห้องน้ำ"},"ICON-2664":{"nm":"แคปซูลพกพาสำลีก้าน","de":"เพื่อไม่ให้สำลีก้านในกระเป๋าเดินทางหักหรือกระจัดกระจาย แคปซูลเล็ก ๆ นี้จึงโอบอุ้มมันไว้อย่างอบอุ่น ยิ่งเป็นสิ่งเล็ก ๆ ก็ยิ่งต้องเตรียมไว้ล่วงหน้า จึงจะไม่ตกใจตื่นเต้นบนเส้นทางที่ไม่คุ้นเคย"},"ICON-2665":{"nm":"กระดานจิ๋วเช็คลมหายใจ","de":"เป่าลมใส่ฝ่ามือแล้วแตะเบา ๆ ลงบนกระดานจิ๋ว ลมหายใจที่สัมผัสก็ทำให้มันฝ้าขุ่นเป็นสีขาวนวล หลักฐานที่น่ารักที่สุดว่าฉันยังมีชีวิตอยู่ที่นี่ในวันที่หนาวเหน็บ กระดานเล็ก ๆ นี้จดบันทึกไว้โดยไม่ปริปาก"},"ICON-2666":{"nm":"ตลับเก็บไม้แคะหู","de":"เมื่อไม้แคะหูต้องเดินทางไปกับกระเป๋า ปลายของมันก็มักจะทู่ได้ง่าย จึงมีบ้านเล็ก ๆ หลังหนึ่งเตรียมไว้ให้ ภายในที่ปลายไม้จะไม่บาดเจ็บแม้พกพาไปไหนก็ตาม เครื่องมือที่บอบบางก็หลับใหลอย่างสงบงาม"},"ICON-2667":{"nm":"คลิปหนีบผ้าเช็ดหน้าพับ","de":"คลิปคาบเบา ๆ ที่ผ้าเช็ดหน้าซึ่งพับมุมทั้งสี่ให้เรียบร้อย ป้องกันไม่ให้ยับยู่ยี่อยู่ในกระเป๋า ผ้าเช็ดหน้าหนึ่งผืนที่พับไว้อย่างเรียบร้อย ไม่ว่าจะหยิบออกมาในช่วงเวลาใดก็มอบความสง่างามอันเงียบสงบเสมอ"},"ICON-2668":{"nm":"ตลับเก็บพลาสเตอร์ปิดแผล","de":"วันที่เข่าถลอก เปิดตลับออกมาก็จะเห็นพลาสเตอร์หลากชนิดเรียงแถวรอคอยอยู่ ความอ่อนโยนที่รู้จักตื่นเต้นเป็นห่วงแม้กับบาดแผลเล็ก ๆ กล่องปฐมพยาบาลควรวางไว้ในที่ที่มือเอื้อมถึงเสมอ"},"ICON-2669":{"nm":"ที่เช็ดรอยนิ้วมือขนาดฝ่ามือ","de":"เช็ดรอยนิ้วมือที่ทิ้งไว้บนกระจกออกไป ร่องรอยของมือที่เคยลังเลก็หายไป โลกที่อยู่เลยหน้าต่างไปซึ่งพร่ามัวในทุกจุดที่สัมผัส กลับใสสว่างขึ้นอีกครั้ง คือเวทมนตร์เล็ก ๆ ขนาดเท่าฝ่ามือ"},"ICON-2670":{"nm":"แผ่นกั้นช่องแยกขยะรีไซเคิล","de":"กระดาษไว้ทางนี้ กระป๋องไว้ทางนั้น แผ่นกั้นเพียงชิ้นเดียวแบ่งแยกชะตากรรมที่เกือบจะปะปนกัน การแยกขยะคือหัวใจแห่งการแบ่งแยกด้วยความตั้งใจ และช่องเล็ก ๆ ที่แน่นหนานี้เองที่ขีดเส้นแรกไว้อย่างชัดเจน"},"ICON-2671":{"nm":"พลั่วลอกสติกเกอร์","de":"แม้แต่สติกเกอร์ที่ติดแน่นเหนียวก็ยอมแพ้อย่างเงียบ ๆ ต่อหน้าฉัน เพียงสอดใบพลั่วแบนเข้าไปที่มุมเบา ๆ มันก็หลุดออกอย่างสะอาดหมดจดไม่เหลือรอยแม้แต่นิดเดียว เป็นการอำลาที่แสนสะใจ"},"ICON-2672":{"nm":"ฟันเลื่อยตัดเทปตกแต่ง","de":"ไม่ต้องวุ่นวายหากรรไกรเพียงเพราะอยากใช้เทปตกแต่งอีกต่อไป แค่วางทาบกับฟันเลื่อยแล้วดึง มันก็ขาดตรงตามแนวทันที คือเพื่อนซี้ตัวเล็กกระฉับกระเฉงที่ปลายนิ้วนักตกแต่งสมุดรักที่สุด"},"ICON-2673":{"nm":"เหล็กยึดมุมกาว","de":"เหล็กชิ้นเล็ก ๆ ที่จับมุมที่ล่อนหลุดไว้ให้แน่นหนาจากด้านใน มันคอยรักษามุมฉากไว้อย่างเงียบเชียบในจุดที่มองไม่เห็น เบื้องหลังสิ่งที่ดูเรียบตรงจากภายนอกนั้น มักมีเสาค้ำที่ซ่อนอยู่เช่นนี้เสมอ"},"ICON-2674":{"nm":"กระบอกเก็บสติกเกอร์ซีลพร้อมฟิล์มกันรอย","de":"เพื่อไม่ให้แผ่นซีลสติกเกอร์อันล้ำค่ายับยู่ยี่หรือชื้นแฉะ มันหลับใหลอยู่ในกระบอกเคียงข้างฟิล์มปกป้อง เคียงข้างความสุขในการสะสมนั้น มักมีความตั้งใจที่จะปกป้องมันไว้อย่างทะนุถนอมตามมาเสมอ"},"ICON-2675":{"nm":"แปรงทำความสะอาดตราปั๊มหมึก","de":"แปรงปัดเบา ๆ ตามลายร่องของตราปั๊มที่ชุ่มไปด้วยหมึก ขจัดสีเก่าที่ค้างอยู่ออกไป มือเล็ก ๆ ที่ขยันหมั่นเพียรทำความสะอาดล่วงหน้า เพื่อให้รอยประทับครั้งต่อไปคมชัดเสมอ"},"ICON-2676":{"nm":"ปีกยึดแผ่นใสในแฟ้ม","de":"เพื่อไม่ให้แผ่นใสในแฟ้มเลื่อนหลุดออกไป ปีกทั้งสองข้างจึงหนีบยึดไว้แน่น ด้วยที่แต่ละแผ่นอยู่ในตำแหน่งของตัวเอง ปลายนิ้วที่พลิกหน้ากระดาษจึงไม่มีวันสับสนวุ่นวาย"},"ICON-2677":{"nm":"พลั่วตักชิ้นส่วนตกแต่ง","de":"ตักชิ้นส่วนตกแต่งเล็ก ๆ ที่กระจัดกระจายอยู่ให้รวมกันในคราวเดียวด้วยพลั่วเล็ก ๆ นี้ เมื่อความยุ่งยากในการหยิบทีละชิ้นด้วยนิ้วมือหมดไป เวลาที่ใช้สร้างสรรค์สิ่งใดสิ่งหนึ่งด้วยความตั้งใจก็สนุกสนานขึ้นอีกมาก"},"ICON-2678":{"nm":"ตัวล็อกพู่ที่คั่นหนังสือ","de":"เพื่อไม่ให้พู่ที่ห้อยอยู่ปลายที่คั่นหนังสือหลวมหลุด ตัวล็อกนี้จึงมัดไว้ให้แน่นหนา แม้แต่เข็มทิศที่นำทางกลับไปหน้าที่อ่านค้างไว้ ก็ต้องดูแลรูปลักษณ์ของตัวเองให้เรียบร้อยจึงจะวางใจได้"},"ICON-2679":{"nm":"คลิปหนีบฝาปากกาตกแต่ง","de":"คลิปที่หนีบฝาปิดไว้แน่นเพื่อไม่ให้ปลายปากกาตกแต่งแห้งกรัง มันช่วยป้องกันความผิดพลาดจากการลืมเปิดฝาจนปากกาแข็งตัว ทำให้สีไหลออกมาชุ่มฉ่ำเหมือนครั้งแรกเสมอ"},"ICON-2680":{"nm":"หัวไขควงเปลี่ยนได้","de":"ปล่อยด้ามไขควงไว้เหมือนเดิม แล้วเปลี่ยนแค่หัวปลายเท่านั้น จะเป็นหัวแฉกหรือหัวแบนก็จัดการได้ฉับไว ความเฉลียวฉลาดในการทำงานได้หลายอย่างด้วยของชิ้นเดียว บรรจุอยู่อย่างแน่นหนาในหัวปลายเล็ก ๆ นี้เอง"},"ICON-2681":{"nm":"แท่งพันกระดาษทรายขัดมุม","de":"เมื่อพันผิวหยาบให้เป็นวงกลมแล้วกำไว้ ฝ่ามือก็กลายเป็นเครื่องมือได้ทันที ถู ๆ ตามลายทุกครั้งที่ดัน มุมที่สากกร้านก็ค่อย ๆ มนขึ้น และความเรียบลื่นสุดท้ายนั้น ปลายนิ้วของคนเราจะรับรู้ได้เสมอ"},"ICON-2682":{"nm":"กรวยแยกน็อตสกรู","de":"น็อตสกรูที่กระจัดกระจายผ่านคอที่แคบแล้วกลิ้งมารวมกันที่จุดเดียว เสียงของสิ่งเล็ก ๆ ที่เคยกลิ้งอยู่บนโต๊ะทำงานพบที่ทางของตัวเอง ทำให้รู้สึกราวกับใจที่เคยยุ่งเหยิงก็ถูกจัดระเบียบให้เรียบร้อยไปด้วย"},"ICON-2683":{"nm":"ตะขอปลายตลับเมตร","de":"ตะขอที่ปลายตลับเมตรคือมือที่สองของคนที่ทำงานเพียงลำพัง เมื่อเกี่ยวไว้ที่มุมสักนิด สายก็ไม่สั่นไหว และมือกับหัวใจก็ซื่อตรงพอ ๆ กับความยาวที่วัดได้"},"ICON-2684":{"nm":"ปลอกหุ้มด้ามประแจ","de":"ชั้นหนึ่งที่สวมทับด้ามเหล็กเย็นเฉียบ ในวินาทีที่กำไว้ในมือ ความอุ่นนุ่มนวลก็สัมผัสแทนที่ความเย็นชืด เครื่องมือจะอยู่เคียงข้างได้นานกว่าเมื่อคำนึงถึงคนที่จับมันก่อนสิ่งอื่นใด"},"ICON-2685":{"nm":"กรวยครอบปลายสว่านเจาะ","de":"กรวยเล็ก ๆ สวมครอบไว้ทุกปลายแหลม ความอุ่นใจที่แม้จะคลำหาในลิ้นชักก็ไม่ถูกทิ่มแทง ยิ่งเป็นของมีคมมากเท่าไร หากห่อหุ้มไว้อย่างพิถีพิถัน ก็จะไม่มีใครได้รับบาดเจ็บ"},"ICON-2686":{"nm":"ใบมีดปอกฉนวนสายไฟ","de":"ปอกเฉพาะฉนวนออกบาง ๆ โดยไม่ให้สายไฟด้านในเสียหาย ในวินาทีที่ค่อย ๆ คลายชั้นหนึ่งออกจนเส้นทองแดงเปล่งประกายปรากฏขึ้น ใบมีดที่ดีย่อมรู้แม่นยำว่าควรหยุดตรงจุดไหน"},"ICON-2687":{"nm":"ที่เช็ดช่องฟองระดับน้ำ","de":"ต้องให้ฟองอากาศหนึ่งฟองหยุดนิ่งตรงกึ่งกลางพอดี จึงจะถือว่าได้ระดับอย่างแท้จริง การเช็ดช่องเล็ก ๆ ให้ใสสะอาดนั้น คล้ายกับการเตรียมพร้อมอันเงียบสงบด้วยการปรับลมหายใจให้สม่ำเสมอก่อนขีดเส้น"},"ICON-2688":{"nm":"ปลอกป้องกันนิ้วตอกตะปู","de":"ปลอกเล็ก ๆ ที่โอบรัดนิ้วซึ่งจับตะปูไว้อย่างมิดชิด มันบอกว่าให้ตอกลงมาโดยไม่ต้องกลัว แม้ค้อนจะพลาดเป้าก็ไม่เป็นไร เพราะมันเตรียมพร้อมรับแรงกระแทกแทนนิ้วมือไว้อย่างแน่นหนาแล้ว"},"ICON-2689":{"nm":"แผ่นยางกันลื่นชามอาหาร","de":"ยางชั้นหนึ่งที่รองรับไม่ให้ชามข้าวลื่นไถลไปตามพื้น กินอย่างสนุกสนานโดยไม่มีชามหนีหายไปไหน ความสงบสุขของมื้ออาหารหนึ่งมื้อเริ่มต้นจากตำแหน่งที่ไม่สั่นคลอน"},"ICON-2690":{"nm":"ที่แขวนทัพพีตักอาหารสัตว์","de":"แขวนทัพพีตักอาหารสัตว์ไว้บนผนังให้แห้งง่าย ๆ ระเบียบเล็ก ๆ ที่คอยต้อนรับมือเราจากจุดเดิมทุกมื้ออาหาร การมีปากท้องที่ต้องดูแล คือเรื่องอ่อนโยนเช่นนี้เอง"},"ICON-2691":{"nm":"จานรองน้ำล้นจากชามน้ำ","de":"มันเงียบ ๆ รองรับน้ำหนึ่งอึกที่กระเพื่อมล้นออกมาจากขอบชามน้ำ ด้วยจานใบกว้างที่โอบอุ้มไว้ล่วงหน้าเผื่อพื้นจะเปียก พื้นใต้ฝ่าเท้าจึงแห้งสนิทอยู่เสมอ"},"ICON-2692":{"nm":"คีมแจกขนมสัตว์เลี้ยง","de":"คีมที่คีบขนมชิ้นหนึ่งได้อย่างแม่นยำแล้วยื่นให้ แม้อยู่ต่อหน้าปากเล็ก ๆ ที่ยื่นจมูกออกมารอคอย การแบ่งปันก็ยังมีปลายนิ้วอ่อนโยนที่ไม่มีวันสับสนวุ่นวาย"},"ICON-2693":{"nm":"คลิปม้วนปิดปากถุงอาหารสัตว์","de":"คลิปเล็ก ๆ ที่ม้วนปากถุงอาหารสัตว์ที่แกะใช้แล้วให้แน่น เพียงปิดคลิกเดียว ความชื้นก็ถูกกันไว้ และอาหารกรอบหนึ่งกำมือของเช้าวันพรุ่งนี้ก็ยังคงสมบูรณ์เหมือนเดิม"},"ICON-2694":{"nm":"จุกปิดปากกระบอกน้ำ","de":"จุกหนึ่งที่พอดีเป๊ะกับปากกระบอกน้ำ ติ๊ก หยดน้ำที่เคยไหลก็หยุดลง และรอบขอบก็แห้งสนิท สิ่งที่ปิดไว้อย่างดีย่อมไม่รั่วไหล และคงความใสสะอาดอยู่ได้นาน"},"ICON-2695":{"nm":"ถ้วยตวงอาหารมีขีดวัด","de":"ตักออกมาหนึ่งถ้วยพอดีตามขีดวัด ไม่มากไม่น้อยจนเกินไป มือที่กะปริมาณมื้ออาหารของวันนี้อย่างเที่ยงธรรม บรรจุวันหนึ่งวันของสมาชิกตัวน้อยไว้อย่างพอดิบพอดี"},"ICON-2696":{"nm":"ขอบยกแผ่นรองอาหารสัตว์","de":"ขอบที่กั้นไม่ให้อาหารที่หกล้นออกไปนอกแผ่นรอง ขอบเพียงเส้นเดียวที่ยกขึ้นเบา ๆ นี้ รวบรวมเศษเล็กเศษน้อยที่เกือบจะกระจัดกระจายไว้ได้อย่างเรียบร้อย"},"ICON-2697":{"nm":"แหวนแยกชามซ้อน","de":"แหวนเล็ก ๆ ที่ค่อย ๆ แยกชามสองใบที่ซ้อนกันอยู่ออกจากกัน มือที่เคยเกร็งสู้กับชามที่ติดแน่นก็ผ่อนคลายลง การแยกออกจากกันได้ดีนั้น แท้จริงแล้วก็คือการดูแลเอาใจใส่อย่างอ่อนโยนเช่นกัน"},"ICON-2698":{"nm":"กรวยรวมลูกบอลในสนาม","de":"กรวยที่รวบรวมลูกบอลที่กลิ้งไปทั่วสนามให้มาอยู่ที่เดียวกัน ในค่ำคืนหลังการวิ่งเล่นอย่างเต็มที่ ทำให้นึกถึงมือที่คอยเก็บกวาดสิ่งของที่กระจัดกระจายอยู่ทั่วไปโดยธรรมชาติ"},"ICON-2699":{"nm":"หมวกครอบเสารั้ว","de":"สวมหมวกทรงกลมไว้บนเสารั้วทุกต้น เพื่อไม่ให้ปลายเสาแตกร้าวจากลมฝน หัวใจที่เอาใจใส่และคลุมปกป้องแม้กระทั่งสิ่งเล็ก ๆ นี้ ซึมซาบไปทั่วทั้งสนามหญ้า"},"ICON-2700":{"nm":"ตะขอแขวนพับอุโมงค์ของเล่น","de":"ตะขอสำหรับพับอุโมงค์ของเล่นที่เล่นจนสนุกสนานเต็มที่แล้วเก็บแขวนไว้อย่างเรียบร้อย เมื่อจัดเก็บวันที่เปื้อนดินไว้อย่างดีแล้วแขวนไว้ การเล่นที่ถูกจัดเก็บอย่างเป็นระเบียบย่อมสัญญาถึงวันพรุ่งนี้อย่างไม่ผิดเพี้ยนเสมอ"},"ICON-2701":{"nm":"เบาะหุ้มด้ามจับสายดึง","de":"เบาะนี้หุ้มด้ามจับสายดึงไว้อย่างนุ่มนวล ไม่ว่าจะดึงแรงแค่ไหน ฝ่ามือก็ไม่มีวันถลอก ยิ่งจับไว้นานเท่าไร มือก็ยิ่งสบายขึ้นเท่านั้น ทั้งหมดนี้เป็นเพราะความใส่ใจเล็กๆ ของใครสักคน"},"ICON-2702":{"nm":"ตะขอยึดผ้าบังแดดสนาม","de":"ตะขอที่ยึดผ้าบังแดดซึ่งขึงไว้กลางสนามให้แน่นหนา แม้แต่ความเย็นสบายยามเที่ยงวันก็ต้องมีสิ่งใดคอยรั้งไว้จึงจะอยู่กับเรา ใต้ร่มเงาที่ตะขอช่วยยึดไว้มั่น บ่ายวันหนึ่งอันเนิบช้าก็ได้พักผ่อนอย่างยาวนาน"},"ICON-2703":{"nm":"ปลอกใบพลั่วขุดดิน","de":"ปลอกที่สวมคลุมใบพลั่วขุดดินไว้อย่างแผ่วเบา หากปล่อยให้มันได้พักหลังวันทำงานอันหนักหน่วง มันก็จะไม่ทื่อลง และพร้อมพบกับผืนดินแห่งฤดูใบไม้ผลิถัดไปได้อีกครั้ง"},"ICON-2704":{"nm":"ทางลาดกลิ้งลูกบอล","de":"ทางลาดแผ่นหนึ่งที่ลูกบอลกลิ้งลงมาอย่างสนุกสนาน ตามความลาดเอียงเล็กน้อยนั้น ลูกบอลวิ่งไปด้วยความเบิกบานใจ ความเอียงเพียงน้อยนิดกลับสร้างความสนุกได้ทั้งวัน"},"ICON-2705":{"nm":"ห่วงกลอนประตูรั้ว","de":"ห่วงกลอนที่ล็อกประตูรั้วไว้ เสียงคลิกเบาๆ ยามล็อกทำให้ใจสงบลง ประตูที่ปิดสนิทเพียงบานเดียว ปกป้องสนามเล็กๆ ให้กลายเป็นโลกทั้งใบของตัวมันเอง"},"ICON-2706":{"nm":"เชือกผูกกระดิ่งของเล่น","de":"เพียงเขย่าเชือกที่ผูกกระดิ่งไว้เบาๆ เสียงใสก็แผ่กระจายไป กรุ๊งกริ๊ง กรุ๊งกริ๊ง—ห้องที่เงียบสงัดก็ตื่นขึ้นมา และเสียงกังวานเล็กๆ เพียงครั้งเดียวก็ทำให้ทั้งใจเงี่ยหูฟัง"},"ICON-2707":{"nm":"จานรองน้ำกระถางต้นไม้","de":"จานที่คอยรองรับน้ำซึมใต้กระถางต้นไม้อย่างเงียบสงบ มันเก็บน้ำที่ล้นไว้ไม่ให้ขอบหน้าต่างเปียกชื้น แม้แต่ความเอาใจใส่ที่มากเกินไป เมื่อล้นออกมาก็ยังต้องมีที่ให้พักพิง"},"ICON-2708":{"nm":"เกรียงปักย้ายกล้าไม้","de":"เกรียงเล็กๆ สำหรับย้ายต้นกล้าอ่อนลงดินและปักไว้เบาๆ ปลายนิ้วที่ค่อยๆ จัดวางต้นกล้าทีละต้นอย่างระมัดระวังนั้น ทำให้แม้แต่แปลงผักเล็กเท่าฝ่ามือ ก็ยังมีฤดูใบไม้ผลิสีเขียวชูช่อขึ้นมาได้"},"ICON-2709":{"nm":"ป้ายปักแถวแปลงผัก","de":"ป้ายที่เขียนแล้วปักไว้ในแต่ละแถวเพื่อจดจำว่าปลูกอะไร บนผืนดินที่ยังไม่มีต้นอ่อนโผล่ขึ้นมาเลย ป้ายชื่อเล็กๆ เพียงอันเดียวก็คอยจดจำอย่างเงียบๆ ว่าจะมีอะไรงอกงามขึ้นที่นี่"},"ICON-2710":{"nm":"ตะแกรงปากบัวรดน้ำ","de":"ตะแกรงละเอียดที่สวมไว้ที่ปากบัวรดน้ำ สายน้ำที่เคยไหลพุ่งเป็นเส้นเดียวถูกกระจายออกเป็นหลายสายราวกับฝนโปรย มีเพียงสายน้ำที่อ่อนโยนเท่านั้นที่จะไม่ทำร้ายใบไม้อันบอบบาง"},"ICON-2711":{"nm":"คลิปยึดลำต้นกับหลัก","de":"คลิปที่ยึดลำต้นซึ่งโอนเอนไว้กับหลักค้ำอย่างแผ่วเบา เป็นแรงพยุงที่ยืมให้ชั่วคราว จนกว่าสิ่งที่ยังอ่อนแอนั้นจะยืนตรงได้ด้วยตัวเอง—การเติบโตต้องอาศัยที่พึ่งเช่นนี้เสมอ"},"ICON-2712":{"nm":"คลิปปิดผนึกถุงเมล็ดพันธุ์","de":"คลิปที่หนีบปิดถุงเมล็ดพันธุ์ที่เหลืออยู่ให้แน่นสนิท เมื่อขบปิดเสียงดังกึก เมล็ดแม้แต่เม็ดเดียวก็ไม่รั่วไหลออกมา คำสัญญาเล็กๆ ต่อฤดูใบไม้ผลิครั้งหน้า ฝากไว้ในการหนีบเพียงครั้งนี้"},"ICON-2713":{"nm":"ทัพพีตวงดินและปุ๋ย","de":"ทัพพีเล็กๆ สำหรับตักดินและปุ๋ยในปริมาณที่พอดี ไม่มากไม่น้อยเกินไปในหนึ่งช้อน—บนปริมาณที่กะไว้อย่างแม่นยำนั้นเอง ดินจึงจะทำหน้าที่ของมันได้อย่างสมบูรณ์"},"ICON-2714":{"nm":"ตะขอแขวนกระถางต้นไม้","de":"ตะขอแขวนที่ยกกระถางต้นไม้ให้ลอยอยู่กลางอากาศอย่างแผ่วเบา สีเขียวที่ถูกยกสูงขึ้นนั้นเข้าใกล้แสงแดดและสายลมมากขึ้นอีกหนึ่งฝ่ามือ สวนเล็กๆ ริมหน้าต่างจึงล่องลอยขึ้นมา"},"ICON-2715":{"nm":"ตาข่ายคลุมป้องกันต้นอ่อน","de":"ตาข่ายคลุมที่บังต้นอ่อนที่เพิ่งแตกยอดไว้อย่างแผ่วเบา จนกว่าใบอ่อนที่ยังบอบบางจะทนต่อความหนาวเย็นแรกและแสงแดดแรงกล้าได้ สิ่งที่เปราะบางที่สุดจึงเป็นสิ่งแรกที่ได้รับการดูแล"},"ICON-2716":{"nm":"ที่แขวนหวีขนสัตว์เลี้ยง","de":"ที่ที่คอยเคาะขนหลุดออกจากหวีแล้วแขวนไว้อย่างเป็นระเบียบ หวีที่สะอาดโล่งพร้อมรอสัมผัสครั้งต่อไป ความเรียบร้อยเริ่มต้นเสมอจากนิสัยเล็กๆ ในการดูแลเครื่องมือของตน"},"ICON-2717":{"nm":"ห่วงกันลื่นอ่างล้างเท้า","de":"ห่วงที่รองอ่างล้างเท้าไม่ให้ลื่นไถล เมื่ออ่างมั่นคงอยู่ใต้เท้าน้อยๆ ที่กระโดดกระเซาะเล่นน้ำ ทั้งมือที่ล้างและใจที่ล้างก็ไม่หวั่นไหว"},"ICON-2718":{"nm":"ตะขอแขวนสายจูงเดินเล่น","de":"ตะขอเพียงอันเดียวสำหรับแขวนสายจูงไว้ที่หน้าประตู ณ ที่เดิมข้างประตูนั้น ความพร้อมที่จะออกไปรอคอยอยู่เสมอ วินาทีที่สายจูงถูกปลดลงมา ก้าวเท้าที่ตื่นเต้นดวงหนึ่งก็ออกเดินตามไปด้วย"},"ICON-2719":{"nm":"ฝาครอบป้องกันตัดเล็บ","de":"ฝาครอบที่ปกป้องเนื้ออ่อนขณะตัดเล็บ ต้องมีขอบเขตปลอดภัยที่ขีดไว้ชัดเจนว่า \"แค่นี้พอ\" มือที่จับกรรไกรจึงจะไม่สั่นและสงบนิ่งได้"},"ICON-2720":{"nm":"แถบวัดอุณหภูมิน้ำอาบ","de":"แถบที่ลอยอยู่ในน้ำอาบเพื่อบอกอุณหภูมิ ความรู้สึกเดิมที่เคยจุ่มหลังมือลงไปกะความอุ่นพอดี บัดนี้ถูกแปลออกมาอย่างชัดเจนเป็นแถบสีเดียวที่ลอยอยู่ตรงนั้น"},"ICON-2721":{"nm":"ลูกกลิ้งเก็บขนเสื้อผ้า","de":"ขนสีขาวเส้นเดียวบนเสื้อผ้าสีดำ ดูใหญ่ที่สุดเสมอในวินาทีก่อนขึ้นเวที ตามเสียงกลิ้งกลอกไปมา เศษฝุ่นทั้งวันถูกย้ายไปติดบนกระดาษเหนียวทีละชั้นอย่างเป็นระเบียบ ความสะอาดเรียบร้อยสำเร็จลงเช่นนี้ ทีละแถบ เท่ากับที่ลอกออกไป"},"ICON-2722":{"nm":"คีมหนีบถุงเก็บมูลสัตว์เลี้ยง","de":"ปลายทางเดินเล่น มีช่วงเวลาอันอ่อนโยนของการก้มตัวลง หนีบถุงไว้ที่ปลายคีม มือก็สะอาด ใจก็เบาสบาย การเดินไปด้วยกันมีมารยาทเล็กๆ ของการดูแลสิ่งที่ตามหลังมาแฝงอยู่เสมอ และคีมนี้รู้เรื่องนี้ดีเป็นคนแรก"},"ICON-2723":{"nm":"ขอบแผ่นเช็ดเท้าหน้าประตู","de":"ขอบของแผ่นเช็ดเท้าหน้าประตูคือคำทักทายต้อนรับแรกที่เท้าได้สัมผัส เมื่อปลายเท้าเปียกหยุดพักตรงนี้สักครู่ พื้นด้านในก็ยังคงแห้งสนิท เป็นจุดที่ต่ำที่สุด คอยเช็ดและต้อนรับทุกคนที่เข้ามาอย่างไร้คำพูด"},"ICON-2724":{"nm":"เชือกผูกปมกระดิ่งแต่งตัว","de":"แม้แต่การผูกกระดิ่งสักลูกก็ยังมีลำดับขั้นตอน พันเชือกสองรอบแล้วสอดผ่านหนึ่งครั้ง เสียงใสก็จะดังตามทุกย่างก้าวไป การแต่งตัวให้เรียบร้อย ท้ายที่สุดแล้วคือใจที่ไม่มีวันละเลยการเก็บรายละเอียดสุดท้ายเล็กๆ นี้"},"ICON-2725":{"nm":"ถุงรองน้ำร่มพับ","de":"ในล็อบบี้หลังฝนหยุด หยดน้ำจากปลายร่มพับหยดกระจายเป็นจุดๆ บนพื้น ถุงใบหนึ่งคอยรองรับมันไว้อย่างเงียบๆ ทำให้ไม่มีใครลื่นล้ม ความเอื้อเฟื้อมักจะอยู่เคียงข้างอย่างไร้เสียงเช่นนี้เสมอ"},"ICON-2726":{"nm":"คลิปหนีบสายกระเป๋า","de":"กระเป๋าที่แขวนไว้ที่เก้าอี้เลื่อนไถลลงเรื่อยๆ เพียงหนีบด้วยคลิปครั้งเดียว มือทั้งสองก็เป็นอิสระจากความกังวลว่ามันจะตก ความผ่อนคลายของการออกไปข้างนอก เริ่มต้นเมื่อคุณสามารถลืมสัมภาระไปได้สักพัก"},"ICON-2727":{"nm":"ถุงผ้าใส่กระเป๋าไฟร้อน","de":"ในตรอกที่ลมหนาวพัดผ่าน ถุงผ้าในกระเป๋าค่อยๆ ส่งความอบอุ่นมาสู่ฝ่ามือ ชั้นผ้านุ่มที่ห่อหุ้มความร้อนไว้และให้ความอุ่นพอดี ความอ่อนโยนของฤดูหนาวมักถูกส่งต่อผ่านผ้าเพียงผืนเดียวเสมอ"},"ICON-2728":{"nm":"ขาตั้งกระจกพับพกพา","de":"กางออกแล้วกระจกบานเล็กก็เอียงหามุมของตัวเอง เพื่อให้มองเห็นใบหน้าได้โดยไม่ต้องถือ ขาตั้งจึงยืนแทนให้ แม้ในช่วงเวลาสั้นๆ ของการแต่งหน้าให้เรียบร้อย ก็ยังมีตัวประกอบที่พึ่งพาได้อยู่เคียงข้างเสมอ"},"ICON-2729":{"nm":"ฝาปิดกล่องทิชชู่เปียกพกพา","de":"แผ่นแรกของทิชชู่เปียกมักจะแห้งอยู่เสมอ เพียงปิดฝาลงเบาๆ แผ่นสุดท้ายก็ยังคงความชุ่มชื้นไว้ได้ การรักษาให้ใช้ได้จนถึงแผ่นสุดท้าย—ความลับของการดูแลบ้านที่ยั่งยืนซ่อนอยู่ในเรื่องเล็กๆ เช่นนี้เอง"},"ICON-2730":{"nm":"ช่องแบ่งเหรียญในกระเป๋าสตางค์","de":"เมื่อเหรียญกระจัดกระจายปนกับธนบัตร หน้าเคาน์เตอร์ชำระเงินก็มักจะวุ่นวายเสมอ เพียงมีช่องแบ่งช่องเดียวรวบรวมสิ่งกลมๆ ไว้ด้านหนึ่ง ปลายนิ้วก็ไม่ต้องคลำหาอีกต่อไป การจัดระเบียบคือการตั้งชื่อให้กับที่อยู่ของทุกสิ่ง"},"ICON-2731":{"nm":"เคสพับหน้ากากอนามัยพกพา","de":"พับเก็บไว้แล้วหน้ากากก็จะไม่ยับแม้อยู่ในกระเป๋า เคสที่เก็บรักษาแผ่นที่เพิ่งถอดออกชั่วคราวไว้อย่างสะอาดสะอ้าน นิสัยอ่อนโยนอย่างหนึ่งของการเก็บรักษาไว้อย่างเรียบร้อยเพื่อใช้ในครั้งต่อไป ถูกบรรจุไว้ที่นี่"},"ICON-2732":{"nm":"ฝาครอบซี่หวีพกพา","de":"ซี่หวีในกระเป๋ามักจะไปเกี่ยวข่วนสิ่งของอื่นอยู่บ่อยๆ สวมฝาครอบซี่หวีไว้ ทั้งหวีก็ปลอดภัย ของที่ใส่มาด้วยกันก็ไม่เป็นอันตราย คนที่เคยดูแลข้าวของของตนย่อมรู้ดีว่า การป้องกันเพียงชั้นเดียวช่วยปกป้องกันและกันได้"},"ICON-2733":{"nm":"คลิปแบ่งช่องลิ้นชัก","de":"ทุกครั้งที่เปิดลิ้นชัก ข้าวของที่ปะปนกันก็หลั่งไหลออกมาราวกับเสียงถอนหายใจ เพียงแบ่งช่องด้วยคลิปเพียงอันเดียว สิ่งของเล็กๆ ก็พบเขตแดนของตัวเองในที่สุด ลิ้นชักที่เป็นระเบียบเปลี่ยนอารมณ์ของทุกเช้าไปอย่างเงียบๆ"},"ICON-2734":{"nm":"ขาตั้งโชว์เหรียญ","de":"เพียงตั้งเหรียญเก่าเหรียญหนึ่งขึ้น มันก็กลายเป็นนิทรรศการเล็กๆ ในตัวมันเอง ขาตั้งพยุงมันเอียงเล็กน้อยเพื่อโชว์ลวดลายด้านหน้าให้เห็นชัดเจน การยกเวลาที่ผ่านการสัมผัสมาแล้วขึ้นสู่ระดับสายตา—ความสุขของการสะสมลึกซึ้งขึ้นตรงนี้เอง"},"ICON-2735":{"nm":"ห่วงพันสายหูฟัง","de":"เคยมีเช้าวันหนึ่งที่เสียเวลาครึ่งเช้าไปกับการแก้สายหูฟังที่พันกันยุ่ง พันสายรอบห่วงพันสายอย่างเป็นระเบียบ ครั้งหน้าที่หยิบออกมาก็จะเรียบลื่น การจัดระเบียบเล็กๆ กลายเป็นของขวัญที่มอบให้ตัวเองในวันพรุ่งนี้อย่างเงียบๆ"},"ICON-2736":{"nm":"ตะขอแขวนสายชาร์จติดผนัง","de":"สายชาร์จที่ทอดยาวอยู่บนพื้นมักถูกเหยียบซ้ำแล้วซ้ำเล่า เพียงติดตะขออันเดียวบนผนังแล้วแขวนไว้ โต๊ะทำงานก็โปร่งขึ้นมาก การจัดการความรกรุงรังไม่ใช่เรื่องยิ่งใหญ่อะไร เป็นเพียงที่ว่างเล็กๆ ขนาดตะปูตัวเดียวเท่านั้นเอง"},"ICON-2737":{"nm":"ที่ตั้งรีโมทคอนโทรล","de":"รีโมทที่มักหายลับไปในซอกโซฟา ในที่สุดก็มีบ้านให้กลับไป ตั้งไว้ในที่ตั้งแล้วก็ไม่ต้องตามหา ไม่ต้องนั่งทับอีกต่อไป การมีที่อยู่ของตัวเองคือการพักผ่อนเล็กๆ แม้กระทั่งสำหรับสิ่งของ"},"ICON-2738":{"nm":"คลิปแขวนขาแว่นตา","de":"แว่นตาที่ถอดวางมักจะลื่นไถลไปที่ไหนสักแห่งอย่างเงียบๆ เสมอ เพียงเกี่ยวขาแว่นไว้ที่คลิปเบาๆ เลนส์ก็จะไม่แตะพื้นเลย ใจที่อยากให้แว่นไร้รอยขีดข่วนพร้อมพบวันพรุ่งนี้ ถูกบรรจุไว้ในที่แขวนเล็กๆ นี้"},"ICON-2739":{"nm":"คลิปแยกพวงกุญแจ","de":"ยิ่งพวงกุญแจหนักขึ้นเท่าไร ก็ยิ่งสับสนว่าดอกไหนเป็นของประตูบานไหน มัดรวมด้วยคลิปแยกประเภทแล้ว เพียงปลายนิ้วก็รู้จักคู่ของมันเอง เป็นผู้นำทางที่เงียบงัน คอยจัดระเบียบให้กับประตูที่เปิดปิดทุกวันอย่างเงียบๆ"},"ICON-2740":{"nm":"คลิปตั้งกระดาษโน้ต","de":"โน้ตที่จดไว้มักจะล้มคว่ำอยู่บนโต๊ะเสมอ เมื่อคลิปจับกระดาษให้ตั้งขึ้น ตัวอักษรก็สบตากับเราตรงๆ วิธีทำให้บรรทัดหนึ่งที่ไม่ควรลืม ได้อยู่ในที่ที่มองเห็นได้เสมอ"},"ICON-2741":{"nm":"ที่ตั้งปากกาแบบตั้งปลาย","de":"ก้มหลังลงหยิบปากกาที่กลิ้งตกมากี่ครั้งแล้วนับไม่ถ้วน ปักปลายปากกาลงในที่ตั้งแล้ว ระยะทางไปถึงบรรทัดถัดไปก็สั้นลงหนึ่งฝ่ามือ เป็นจุดพักเล็กๆ ที่ตื่นอยู่เสมอเคียงข้างคนที่กำลังเขียน"},"ICON-2742":{"nm":"ขาตั้งพลิกนาฬิกาทราย","de":"นาฬิกาทรายเมื่อไหลจนหมดแล้ว ต้องมีใครสักคนพลิกกลับมันจึงจะมีชีวิตขึ้นอีกครั้ง ขาตั้งรับเอาช่วงเวลาของเม็ดทรายเม็ดสุดท้ายนั้นไว้แล้วพลิกกลับขึ้นมาอย่างราบรื่น สัมผัสมือที่หมุนเวลากลับสู่จุดเริ่มต้น พักอยู่ตรงนี้ เหนือไม้ชิ้นเล็กๆ"},"ICON-2743":{"nm":"มันฝรั่งอบเนย","de":"เนยละลายช้าๆ บนมันฝรั่งที่อบทั้งเปลือก เมื่อลายสีทองซึมเข้าไปพร้อมไอร้อน เนื้อในที่ร่วนซุยก็ค่อยๆ ซึมซับความหอมมันไว้อย่างเงียบสงบ คือช่วงเวลาที่พืชหัวกลิ่นดินอบอุ่นที่สุด"},"ICON-2744":{"nm":"ข้าวโพดปิ้งเนย","de":"เมล็ดสีเหลืองที่เรียงตัวเป็นแถวส่งเสียงแตกป๊อกแป๊กบนเตาย่าง เมื่อเนยชิ้นหนึ่งไถลผ่าน กลิ่นหอมหวานก็โชยขึ้นมาทันที ความหวานของท้องทุ่งฤดูร้อนถูกส่งตรงมาในคำเดียว"},"ICON-2745":{"nm":"วาฟเฟิล","de":"ในแต่ละช่องตารางเล็กๆ น้ำเชื่อมรอที่จะขังอยู่อย่างเงียบๆ ข้างนอกกรอบ ข้างในนุ่ม—กัดคำแรกไอร้อนก็โชยออกมา ช่องสี่เหลี่ยมเหล่านั้นเหมือนภาชนะที่แบ่งความสุขเล็กๆ ไว้ในแต่ละช่อง"},"ICON-2746":{"nm":"แพนเค้ก","de":"จดจำกลิ่นแป้งที่ฟูขึ้นเป็นสีทองบนกระทะได้เสมอ เนยไหลรื้อลงมาช้าๆ บนแพนเค้กกลมที่ซ้อนกันเป็นชั้นๆ จานนุ่มนวลที่ได้รับอนุญาตอย่างแผ่วเบาเฉพาะในเช้าวันสบายๆ เท่านั้น"},"ICON-2747":{"nm":"ช็อกโกแลต","de":"อมชิ้นหนึ่งไว้ในปากแล้วมันก็ค่อยๆ ละลายไปตามอุณหภูมิร่างกาย ความหวานที่แผ่ขยายท้ายความขมช่วยคลายความตึงเครียดในใจลงเบาๆ ในวันที่เหนื่อยล้า ชิ้นสีน้ำตาลเล็กๆ ที่หยิบออกมาจากกระเป๋าเพื่อปลอบใจตัวเอง"},"ICON-2748":{"nm":"เค้กสตรอว์เบอร์รี","de":"สตรอว์เบอร์รีสีแดงวางอยู่บนวิปครีมสีขาว ประกาศฤดูใบไม้ผลิเป็นคนแรก เมื่อส้อมผ่าหน้าตัดที่นุ่มนวล กลิ่นหอมเปรี้ยวก็ค่อยๆ โชยขึ้นมา ในวันที่มีเรื่องให้เฉลิมฉลอง คือตัวเอกอันอ่อนโยนที่วางอยู่กลางโต๊ะอาหาร"},"ICON-2749":{"nm":"ชีสเค้ก","de":"ชิ้นหนักๆ ชิ้นหนึ่งละลายเข้มข้นอยู่บนลิ้น รสเค็มปลายทางจับมือกับความหวานไว้ เรียกร้องให้กัดต่ออีกคำแล้วคำเล่า ของหวานที่คนรักความเข้มข้นหนานุ่มเก็บกินอย่างค่อยเป็นค่อยไปด้วยความเงียบสงบ"},"ICON-2750":{"nm":"คุกกี้กล้วย","de":"กลิ่นกล้วยบดสุกเป็นสีเหลืองทองอยู่ในเตาอบ กัดคำหนึ่งความหวานนุ่มก็แผ่ซ่านเต็มปาก คือช่วงเวลาแห่งการเปลี่ยนแปลงอันอบอุ่น ที่ผลไม้สุกงอมชิ้นหนึ่งถือกำเนิดใหม่เป็นคุกกี้"},"ICON-2751":{"nm":"คุกกี้ช็อกโกแลตชิป","de":"เม็ดช็อกโกแลตในแป้งละลายเข้มข้นขณะอบ หักมันตอนยังอุ่นอยู่ สีน้ำตาลเข้มก็เปื้อนปลายนิ้ว ชิ้นแบบนี้แหละที่ทำให้บ่ายวันหนึ่งอบอุ่นขึ้นอีกนิด เมื่อมีนมสักแก้วอยู่ด้วย"},"ICON-2752":{"nm":"คุกกี้คาเคานิบส์","de":"ชิ้นโกโก้บดละเอียดกรุบกรอบอยู่ในเนื้อแป้ง รสขมลึกที่ไม่หวานปลอบประโลมลิ้นของผู้ใหญ่ไว้อย่างสงบ คุกกี้ที่ดูจริงจังขึ้นมาสักหน่อย เพราะเก็บกลิ่นดั้งเดิมก่อนแปรรูปไว้ครบถ้วน"},"ICON-2753":{"nm":"ชีสโทสต์","de":"ชีสยืดยาวเป็นเส้นบนขนมปังปิ้งสีทอง ความกรอบข้างนอกและความหอมมันข้างในซ้อนกันในคำเดียว มื้ออาหารที่ง่ายที่สุดแต่ก็อ่อนโยนที่สุด คอยเติมเต็มสายของเช้าวันสายให้อิ่มท้องอย่างมั่นคง"},"ICON-2754":{"nm":"แซนด์วิช","de":"ระหว่างขนมปังสองแผ่น ความตั้งใจของทั้งวันถูกอัดแน่นไว้ทีละชั้น กัดเข้าไปรสชาติที่ซ้อนกันเป็นชั้นๆ ก็ทักทายพร้อมกันทั้งหมด โต๊ะอาหารเล็กๆ บนฝ่ามือที่พร้อมพกพาไปได้ทุกที่"},"ICON-2755":{"nm":"เฟรนช์โทสต์","de":"ขนมปังที่แช่ในไข่จนชุ่มฉ่ำสุกเป็นสีทองบนกระทะ ขอบที่พองขึ้นพร้อมกลิ่นเนยกรอบเป็นที่แรก ราดน้ำเชื่อมสักเส้น ขนมปังธรรมดาก็กลายเป็นความหรูหราของวันหยุด"},"ICON-2756":{"nm":"ราเมนเห็ด","de":"กลิ่นหอมลึกของเห็ดลอยขึ้นมาพร้อมไอน้ำเหนือน้ำซุปที่เดือดพล่าน คีบดอกเห็ดเหนียวนุ่มขึ้นมาคำหนึ่ง ความหวานกลิ่นดินก็แผ่ในปาก ชามหนึ่งที่พิเศษเล็กน้อย เพราะกลิ่นหอมเติมเต็มท้องก่อนเส้นเสียอีก"},"ICON-2757":{"nm":"ราเมนผัด","de":"เส้นที่คลุกไม่มีน้ำซุปเคลือบด้วยเครื่องปรุงรสเผ็ดจนเป็นมันวาว ยกขึ้นด้วยตะเกียบ กลิ่นควันหอมก็แผ่ผ่านไอร้อน เพื่อนแท้ที่สุดในวันที่คิดถึงมื้ออาหารรวดเร็วและเข้มข้น"},"ICON-2758":{"nm":"ราเมนชีส","de":"วางชีสแผ่นหนึ่งบนเส้นร้อนๆ มันก็ค่อยๆ ยุบตัวละลายลงไป น้ำซุปเผ็ดพบกับความหอมมันนุ่มนวล ขอบความจัดจ้านก็มนขึ้น ชามหนึ่งที่เหมาะเจาะกับคืนที่อยากผ่อนความเผ็ดร้อนลงสักนิด"},"ICON-2759":{"nm":"ราเมนกะหรี่","de":"กลิ่นกะหรี่เข้มข้นพันรอบเส้น ส่งไอสีเหลืองลอยขึ้นมา ซดเข้าไปคำหนึ่งความเผ็ดอุ่นก็ทำให้ร่างกายอบอุ่นจากภายใน เส้นที่แปรผันอย่างสนุกสนาน เพิ่มกลิ่นแปลกใหม่เล็กน้อยให้กับน้ำซุปที่คุ้นเคย"},"ICON-2760":{"nm":"ราเมนทะเล","de":"เหนือน้ำซุปที่เต็มไปด้วยกลิ่นทะเล กุ้งและหอยลอยขึ้นมาอวบอ้วน ความสดชื่นแต่เข้มข้นซึมเข้าไปในทุกซอกของเส้น เวทมนตร์เล็กๆ ที่พากลิ่นอายชายทะเลมาไว้ในชามเดียวโดยไม่ต้องเดินทางไปไหนไกล"},"ICON-2761":{"nm":"คิมบับไชโป๊วเหลือง","de":"เมื่อไชโป๊วเหลืองอยู่ตรงกลางและเมล็ดข้าวล้อมรอบเป็นวงกลม สาหร่ายแผ่นหนึ่งก็มัดรวมทั้งหมดไว้ในม้วนเดียวอย่างอบอุ่น ในรุ่งเช้าของวันไปปิกนิก มื้ออาหารที่ซื่อตรงที่สุดถือกำเนิดขึ้นบนเขียง"},"ICON-2762":{"nm":"คิมบับทูน่า","de":"วินาทีที่ทูน่าคลุกมายองเนสหนึ่งช้อนซึมเข้าไปในเมล็ดข้าว แม้ใต้แสงไฟร้านสะดวกซื้อยามดึก มื้ออาหารมื้อหนึ่งก็อบอุ่นเพียงพอ ความปลอบใจที่มือที่วุ่นวายมักหยิบขึ้นมาบ่อยที่สุด"},"ICON-2763":{"nm":"สลัดผลไม้","de":"สีสันที่เก็บรวมมาตามฤดูกาลพบกันเป็นครั้งแรกในชามเดียว วิธีที่สีแดง สีเขียว และสีเหลืองอยู่ร่วมกันโดยไม่ทะเลาะกัน ผลไม้จะแสดงให้เห็นก็ต่อเมื่อถูกหั่นและรวมกันไว้ด้วยกันแล้วเท่านั้น"},"ICON-2764":{"nm":"สลัดอกไก่","de":"อกไก่ย่างที่รสอ่อนละมุนวางเรียงเป็นระเบียบบนใบผักเขียว บนโต๊ะอาหารของคนที่กำลังเตรียมตัวสำหรับเวทีวันพรุ่งนี้ มักมีจานที่เป็นระเบียบเช่นนี้วางอยู่เสมอ"},"ICON-2765":{"nm":"ยำมะเขือเทศแตงกวา","de":"มะเขือเทศสุกและแตงกวากรอบถูกยำให้มีรสเปรี้ยวสดชื่น ในวันกลางวันที่เสียงจักจั่นดังหนาแน่น ตักคำหนึ่งใส่ปาก ฤดูร้อนก็เย็นลงไปหนึ่งจังหวะในนั้น"},"ICON-2766":{"nm":"สลัดผักกาดหอม","de":"ล้างใบผักที่เพิ่งเก็บจากแปลงในน้ำเย็น ปลายนิ้วก็ตื่นขึ้นเย็นฉ่ำ ช่วงเวลาที่ผักธรรมดาที่สุด ครองที่นั่งที่เขียวสดที่สุดบนโต๊ะอาหาร"},"ICON-2767":{"nm":"สลัดข้าวโพด","de":"ทุกครั้งที่เมล็ดหวานแตกป๊อกในปาก ทุ่งกลางฤดูร้อนที่เต็มไปด้วยแสงแดดก็ปรากฏขึ้นตรงหน้า แม้อยู่ในชามสลัด ข้าวโพดสีเหลืองก็ไม่เคยลืมแสงแดดของตัวเองเลยแม้แต่น้อย"},"ICON-2768":{"nm":"โคลสลอว์","de":"เมื่อกะหล่ำปลีซอยดูดซับซอสเปรี้ยวหวานเข้าไป ความกรอบก็ลดความแข็งลงอย่างนุ่มนวลขึ้นอีกนิด คุณธรรมของเครื่องเคียง—ไม่ว่าจะวางคู่กับจานหลักไหน ก็ไม่แย่งความโดดเด่น ทำหน้าที่ของตนอย่างครบถ้วน"},"ICON-2769":{"nm":"สลัดกุ้งมะนาว","de":"บีบมะนาวลงไปเบาๆ ความหวานของกุ้งก็ตื่นขึ้นชัดเจนยิ่งกว่าเดิม หยดเปรี้ยวเพียงหยดเดียวเป่าลมหายใจให้ทั้งจาน สัมผัสสุดท้ายที่เล็กแต่เด็ดขาด"},"ICON-2770":{"nm":"แฮมเบิร์กสเต็ก","de":"ก้อนเนื้อบดหนาที่ปั้นไว้สุกเป็นสีทองบนแผ่นเหล็กร้อน น้ำเนื้อที่ซึมออกมาในวินาทีที่ปลายมีดแตะถึง—มื้ออาหารที่ได้รับความรักยาวนานที่สุดระหว่างอาหารบ้านๆ กับอาหารตะวันตก"},"ICON-2771":{"nm":"พิซซ่า","de":"คำที่ชีสยืดยาวนั้น ถูกส่งต่อจากมือสู่มือท่ามกลางคนที่นั่งล้อมวงกัน เมื่อแบ่งถาดกลมถาดหนึ่งออกเป็นชิ้นๆ ด้วยกัน การรวมตัวจึงกลายเป็นการรวมตัวที่แท้จริงในที่สุด"},"ICON-2772":{"nm":"พาสต้าครีมเห็ด","de":"กลิ่นดินลึกของเห็ดและความนุ่มนวลของครีมโอบกอดเส้นพาสต้าไว้ทุกเส้น ในค่ำคืนที่เสียงฝนโปรยเบาๆ กลิ่นหอมเข้มข้นค่อยๆ แผ่ลงไปจนถึงก้นจาน"},"ICON-2773":{"nm":"พาสต้ากุ้ง","de":"กุ้งอวบผัดเบาๆ ในน้ำมันมะกอกแล้วคลุกรวมกับเส้น เมื่อความเค็มของทะเลพบกับความอ่อนละมุนของเส้น เย็นวันธรรมดาก็พิเศษขึ้นมาอีกนิด"},"ICON-2774":{"nm":"พาสต้าน้ำมัน","de":"กระเทียม น้ำมัน และเส้น มีเพียงสามอย่างเท่านั้น มีรสชาติบางอย่างที่ยิ่งตัดทอนออกไปกลับยิ่งชัดเจนขึ้น อาลิโอ โอลิโอพิสูจน์เรื่องนี้อย่างเงียบๆ โดยไม่มีสิ่งใดเกินความจำเป็นเลย"},"ICON-2775":{"nm":"พาสต้าหอย","de":"น้ำซุปที่หอยปล่อยออกมาขณะเปิดฝาซึมลึกเข้าไปในเส้นทุกเส้น กลิ่นไวน์ขาวสักจิบยังคงอยู่บนจานนานราวกับวันฤดูใบไม้ผลิที่ไม่ยอมจางหาย"},"ICON-2776":{"nm":"พาสต้าครีม","de":"เมื่อครีมเข้มข้นโอบกอดเส้นไว้เบาๆ มุมหนึ่งในใจก็อบอุ่นตั้งแต่คำแรก ความปลอบโยนที่ความนุ่มนวลมอบให้ ยิ่งลึกซึ้งขึ้นในวันที่ลมพัดหนาว"},"ICON-2777":{"nm":"พาสต้ามะเขือเทศ","de":"ซอสมะเขือเทศที่เคี่ยวนานแผ่สีแดงบนเส้น เมื่อความหวานและความเปรี้ยวเคี่ยวช้าๆ จนสมดุลในที่สุด จานที่พื้นฐานที่สุดก็เป็นจานที่มั่นคงที่สุด"},"ICON-2778":{"nm":"ข้าวห่อไข่","de":"ไข่นุ่มคลุมข้าวร้อนไว้เบาๆ ราวกับผ้าห่ม เพียงเขียนชื่อสักตัวด้วยซอสมะเขือเทศ โต๊ะอาหารวันนั้นก็กลายเป็นจดหมายเล็กๆ ที่ใครสักคนส่งมอบให้"},"ICON-2779":{"nm":"แซลมอนย่าง","de":"ย่างช้าๆ หน้าเปลวไฟจนหนังกรอบ เนื้อสีชมพูที่แยกออกตามลายเนื้อพร้อมไอน้ำสายหนึ่งลอยขึ้น—ความอดทนรอคอยมักได้รับการตอบแทนอย่างซื่อตรงจากแซลมอนเสมอ"},"ICON-2780":{"nm":"บรุสเก็ตตา","de":"วางมะเขือเทศสับและใบโหระพาไว้อย่างล้นบนขนมปังปิ้งกรอบ ความเบาสบายของการหยิบด้วยนิ้วแล้วกัดคำหนึ่งนั้น เปิดคำทักทายแรกของงานรวมตัวอย่างอบอุ่น"},"ICON-2781":{"nm":"มะม่วงปั่น","de":"ปั่นมะม่วงสุกให้ละเอียดแล้วผสมเข้ากับน้ำแข็งอย่างเย็นฉ่ำ เมื่อหยดน้ำเกาะเป็นเม็ดเล็กๆ บนแก้วสีเหลือง บ่ายกลางฤดูร้อนอันเนิบช้าก็ไหลขึ้นมาจนถึงปลายหลอด"},"ICON-2782":{"nm":"เลมอนเนด","de":"ใส่เลมอนคั้นสด น้ำตาล และน้ำเย็นแล้วเขย่าให้เข้ากันทั้งแก้ว เมื่อความเปรี้ยวสีเหลืองไหลลงคอเย็นฉ่ำ แม้แต่ความร้อนที่รุนแรงก็ยอมแพ้ไปชั่วขณะ"},"ICON-2783":{"nm":"นมสตรอว์เบอร์รี","de":"คนสตรอว์เบอร์รีบดลงในนม เมฆสีชมพูก็ค่อยๆ จมลงในแก้ว ความตื่นเต้นที่ปลายนิ้วเคยเปิดประตูตู้เย็นตอนเด็กๆ ถูกเก็บไว้ครบถ้วนในแก้วเดียว"},"ICON-2784":{"nm":"นมกล้วย","de":"เครื่องดื่มที่เป็นความทรงจำของยุคสมัยหนึ่งไปแล้ว เพียงแค่รูปทรงกลมของขวดเล็กๆ นั้น ความทรงจำสีเหลืองของการเสียบหลอดนั่งบนม้านั่งในโรงอาบน้ำสาธารณะ กลับมามีชีวิตอย่างอบอุ่นในทุกอึก"},"ICON-2785":{"nm":"นมบลูเบอร์รี","de":"บีบเมล็ดสีม่วงลงไปแล้วบดให้แตก นมสีขาวก็ย้อมเป็นสีฟ้าท้องฟ้าอ่อนๆ ผลไม้เล็กๆ กำมือเดียวนั้น เปลี่ยนแก้วทั้งใบให้เป็นสีใหม่ทั้งหมด"},"ICON-2786":{"nm":"น้ำผลไม้รวม","de":"คั้นผลไม้หลายชนิดรวมกันเข้าไปแล้วกลายเป็นรสชาติที่ไม่อาจเรียกด้วยชื่อของผลไม้เพียงชนิดเดียวได้อีก คณะประสานเสียงเล็กๆ ของความหวาน ที่ผสมผสานและพองโตขึ้นด้วยกันอย่างล้นเหลือ"},"ICON-2787":{"nm":"โกโก้","de":"ริมหน้าต่างที่หิมะโปรยปราย กำมือแก้วอุ่นไว้ด้วยมือทั้งสองข้างอย่างเงียบๆ แก้วสีน้ำตาลที่มีไอน้ำลอยกรุ่นๆ ค่อยๆ ให้ความอบอุ่นตั้งแต่ปลายนิ้วไปจนถึงหัวใจ"},"ICON-2788":{"nm":"กาแฟ","de":"สิ่งที่เปิดไฟห้องซ้อมยามรุ่งสางเสมอมาคือแก้วนี้เอง เมื่อกลิ่นหอมขมค่อยๆ ผลักความง่วงออกไปเบาๆ อีกหนึ่งวันบนเวทีก็เริ่มต้นขึ้นอย่างเงียบสงบเช่นนั้นเอง"},"ICON-2789":{"nm":"ซูชิแซลมอน","de":"กำข้าวไว้ในมือ กะระดับความละเอียดอ่อนระหว่างความแน่นและความนุ่ม เมื่อแซลมอนแผ่นบางชิ้นหนึ่งเอนกายลงเบาๆ บนนั้น คำหนึ่งก็กลายเป็นความสำเร็จของความตั้งใจเล็กๆ"},"ICON-2790":{"nm":"โจ๊กฟักทอง","de":"ต้มฟักทองสีเหลืองจนนุ่มแล้วบดให้ละเอียด ทุกช้อนที่ตักเข้าปาก แสงแดดฤดูใบไม้ร่วงก็ละลายอุ่นอยู่ในปาก โจ๊กที่นึกถึงเป็นอันดับแรกเมื่อยามป่วยไข้"},"ICON-2791":{"nm":"แกงกะหรี่ปลา","de":"เนื้อปลาที่เคี่ยวเบาๆ ในเครื่องเทศแตกละเอียดนุ่มอยู่ในแกงกะหรี่ เติมสัมผัสของทะเลลงในชามที่คุ้นเคย เย็นวันธรรมดาก็ออกเดินทางไปไกลขึ้นอีกหนึ่งฝ่ามือ"},"ICON-2792":{"nm":"กุ้งทอด","de":"จับหางจุ่มแป้งแล้วหย่อนลงในน้ำมันเดือด วินาทีสั้นๆ นั้นแหละคือตัวตัดสินแพ้ชนะ กุ้งที่สวมชุดสีทองจะเปล่งประกายสว่างที่สุดก็ต่อเมื่อกินขณะที่ความกรอบยังไม่ทันเย็นลง"},"ICON-2793":{"nm":"ปลาหมึกทอด","de":"วงแหวนกลมพองตัวอวบอ้วนขึ้นในน้ำมันร้อน คำที่ความกรอบห่อหุ้มความเหนียวนุ่มไว้ เข้ากันดีที่สุดใต้แสงไฟสีเหลืองของแผงลอยริมทาง"},"ICON-2794":{"nm":"ไก่ย่าง","de":"ทาซอสหมักแล้วย่างช้าๆ หน้าเปลวไฟ หนังก็เป็นมันวาว อาหารที่รสชาติเปลี่ยนไปได้ด้วยการปรับไฟเพียงนิดเดียว เรียบง่ายที่สุด จึงซื่อตรงที่สุดในทางกลับกัน"},"ICON-2795":{"nm":"หมูผัดกิมจิ","de":"ผัดกิมจิที่หมักได้ที่รวมกับเนื้อหมู รสเปรี้ยวก็สุกงอมกลายเป็นรสหวาน จานที่เรียกร้องข้าวสวยสักชามโดยอัตโนมัติ คู่หูที่มั่นคงที่สุดบนโต๊ะอาหารเกาหลี"},"ICON-2796":{"nm":"หมูผัด","de":"ผัดเร็วๆ บนไฟแรงให้ผิวนอกกรอบสุก เมื่อกลิ่นน้ำมันหอมมันเต็มครัว เมนูมื้อเย็นวันนี้ก็ตัดสินใจแล้วโดยไม่ต้องถามอีก"},"ICON-2797":{"nm":"เนื้อผัดเห็ด","de":"ผัดเห็ดหอมกับเนื้อวัวด้วยกัน รสชาติของแต่ละอย่างก็ลึกซึ้งขึ้นอีกขั้น ดินและทุ่งหญ้าจับมือกันอย่างสงบบนจานเดียว มื้ออาหารที่เรียบร้อยของฤดูใบไม้ร่วง"},"ICON-2798":{"nm":"ทักคาลบี้ชีส","de":"ละลายชีสให้ล้นเหนือทักคาลบี้รสเผ็ด แล้วดึงยืดยาว เมื่อหลายคนล้อมวงรอบแผ่นเหล็กร้อนตรงกลาง แม้ความเผ็ดร้อนซ่านก็คลี่คลายกลายเป็นเสียงหัวเราะ"},"ICON-2799":{"nm":"จิเกกิมจิ","de":"ยิ่งกิมจิดองนานเท่าไร ก็ยิ่งให้น้ำซุปที่เข้มข้นและลึกซึ้งกว่าเดิม นั่งหันหน้าเข้าหากันหน้าหม้อดินที่เดือดปุดๆ คำว่า \"ครอบครัว\" ก็อุ่นขึ้นมาอีกครั้ง"},"ICON-2800":{"nm":"จิเกดวนจัง","de":"ละลายเต้าเจี้ยวหอมกรุ่น ใส่เต้าหู้และบวบเขียวแล้วเคี่ยวไฟอ่อนอย่างสม่ำเสมอ เสียงเดือดปุดๆ จนถึงคำสุดท้ายในหม้อดิน คือสัญญาณที่แน่นอนที่สุดว่าได้กลับถึงบ้านแล้ว"},"ICON-2801":{"nm":"ซุปหัวไชเท้าเนื้อวัว","de":"ครึ่งวันที่เฝ้ารออยู่หน้าไฟอ่อนอย่างเงียบงัน จนหัวไชเท้าใสกระจ่าง เมื่อน้ำซุปใสสักช้อนแตะริมฝีปาก ภาพโต๊ะอาหารเรียบง่ายในวันวานก็ลอยกลับมา สิ่งที่เรียบง่ายที่สุดคือสิ่งที่อยู่นานที่สุด"},"ICON-2802":{"nm":"ซุปหอย","de":"ในวินาทีที่หอยอ้าปาก ฤดูใบไม้ผลิก็ลึกซึ้งขึ้นในหม้อ เมื่อกลิ่นทะเลกำมือหนึ่งลอยขึ้นมาพร้อมไอน้ำ ครัวยามเช้าของหมู่บ้านชายทะเลก็ผุดขึ้นในใจ ทะเลรสเค็มปนอยู่ในทุกช่องเปลือกที่เผยอออก"},"ICON-2803":{"nm":"มันเทศฉาบน้ำตาล","de":"ระหว่างทางกลับบ้านจากโรงเรียน ก้อนสีเหลืองที่ใส่ในแก้วกระดาษถูกกำไว้ในมือราวกับกระเป๋าน้ำร้อน กัดเปลือกนอกสีทองเข้าไป ไอร้อนก็พวยพุ่งขึ้นมาจากข้างใน เปลือกนอกหวานฉ่ำกับเนื้อในร้อนๆ คือรสชาติที่ฤดูหนาวอ่อนโยนที่สุด"},"ICON-2804":{"nm":"มะเขือยาวผัด","de":"ชั่วขณะที่สีม่วงสัมผัสน้ำมันแล้วค่อยๆ อ่อนยวบลง ผักที่เคยถูกตำหนิว่าเปื่อยยุ่ย แท้จริงแล้วซึมซับเครื่องปรุงได้ดีกว่าใคร กัดคำแรกแล้วสัมผัสมือของคนปรุงที่ซึมเข้าเนื้อนุ่มๆ จะมาถึงก่อนสิ่งใด"},"ICON-2805":{"nm":"มันฝรั่งตุ๋นซีอิ๊ว","de":"ค่ำคืนที่กลิ่นหอมหวานลอยฟุ้งไปทั่วครัวขณะซีอิ๊วเคี่ยวลง มือที่หยิบมันฝรั่งสีน้ำตาลเป็นมันวาวใส่ลงในช่องกล่องข้าว ความตั้งใจที่ไม่มีบันทึกไว้ในสูตรใดซึมอยู่ในมันฝรั่งชิ้นเล็กๆ ทุกชิ้น"},"ICON-2806":{"nm":"ใบงาดอง","de":"งานดองกลิ่นหอมของฤดูร้อนไว้ทั้งใบ แล้วพาข้ามมาถึงโต๊ะอาหารในฤดูหนาว แกะใบหนึ่งวางบนข้าว ฤดูกาลที่ผ่านไปก็ผลิบานขึ้นอีกครั้งในปาก ระหว่างใบที่ซ้อนทับกันเป็นชั้นๆ นั้น แสงแดดของปีนั้นหลับใหลอยู่"},"ICON-2807":{"nm":"ผักกาดขาวคลุกสด","de":"มือที่รอไม่ไหวจนถึงวันทำกิมจังใหญ่ จึงคลุกเคล้ามันในวันนั้นเลย ความสดชื่นที่เพลิดเพลินได้เพียงชั่วขณะที่เครื่องปรุงเพิ่งเริ่มซึมเข้าใบผักกรอบๆ ความสดใหม่ก่อนการหมักคือความหรูหราของวันนี้เท่านั้น"},"ICON-2808":{"nm":"เห็ดผัด","de":"สิ่งที่ผุดขึ้นอย่างเงียบๆ ในร่มเงาป่าหลังฝนหยุด ระหว่างผัดกับน้ำมันงา กลิ่นดินก็แปรเปลี่ยนเป็นความหอมกรุ่น ยิ่งเติบโตอย่างเงียบเชียบในที่มืดมากเท่าไร กลิ่นหอมนั้นก็ยิ่งลึกและเข้มข้นมากเท่านั้น"},"ICON-2809":{"nm":"ผักโขมคลุก","de":"ผักใบเขียวที่ลวกแล้วหดเหลือเพียงกำมือเดียว ถูกคลุกเคล้าด้วยปลายนิ้วอย่างนุ่มนวล ปริมาณที่ถ่อมตนนั้นคือคุณธรรมของผักฤดูใบไม้ผลิ จานผักเขียวเพียงจานเดียวก็นำแสงแดดฤดูใบไม้ผลิเข้ามาสู่โต๊ะอาหารอีกคืบหนึ่ง"},"ICON-2810":{"nm":"สาหร่ายทะเลคลุก","de":"เส้นสาหร่ายลื่นๆ ที่เพิ่งงมขึ้นจากทะเล เข้ากันดีกับซอสน้ำส้มพริกเปรี้ยวจัด ทุกครั้งที่เคี้ยวจะมีความเค็มแตกป๊อกๆ ในปาก จานหนึ่งที่ยกเอาสัมผัสของคลื่นที่ซัดสาดมาไว้ในถ้วยได้ทั้งหมด"},"ICON-2811":{"nm":"ซูกินีผัด","de":"มีผักบางชนิดที่ยิ่งแก่ยิ่งมีความหวานเพิ่มขึ้น หั่นเป็นแผ่นบางแล้วผัดกับกุ้งแห้งดอง แม้แต่ซูกินีที่ดูจืดชืดก็ยังค่อยๆ เผยความหวานของตัวเองออกมา สีเหลืองที่ค่อยๆ ละลายนุ่มนวลในปากจนถึงคำสุดท้าย"},"ICON-2812":{"nm":"ข้าวผัดกิมจิ","de":"เมื่อกิมจิเก่าเริ่มมีรสเข้มขึ้น มันได้พบกับข้าวเย็นในกระทะเดียวกัน ของเหลือกับของเหลือมารวมกันจนกลายเป็นจานที่อิ่มท้องที่สุด ความช่วยเหลือที่อ่อนโยนที่สุดใต้แสงไฟห้องเช่าในยามดึก"},"ICON-2813":{"nm":"แกงกะหรี่ไก่","de":"เมื่อน้ำแกงสีเหลืองราดคลุมข้าวขาว โต๊ะอาหารก็สว่างไสวขึ้นทันที ในวันที่เครื่องเทศยังเป็นของแปลกใหม่ นี่คือรสชาติแรกของโลกภายนอกที่เราค่อยๆ คุ้นเคย เนื้อไก่ที่ละลายนุ่มฟูในวันอาทิตย์สักวันหนึ่ง"},"ICON-2814":{"nm":"ข้าวผัด","de":"เศษของเหลือที่ตกค้างอยู่มุมสุดตู้เย็นมารวมกันอย่างกลมเกลียวในกระทะเดียว ความใจกว้างที่โอบรับทุกสิ่งอย่างไม่รังเกียจ การรวบรวมสิ่งกระจัดกระจายให้มาอยู่ด้วยกัน นั่นคือจุดเริ่มต้นของการดูแลบ้าน"},"ICON-2815":{"nm":"ข้าวหน้าบูลโกกี","de":"เนื้อที่หมักในซอสหวานลื่นไถลลงบนข้าวที่กำลังส่งไอร้อน เมื่อพระเอกของโต๊ะรับแขกลงมาอยู่ในจานเดียวของวันธรรมดา ความพิเศษนั้นก็ยิ่งอ่อนโยนขึ้นไปอีก"},"ICON-2816":{"nm":"บิบิมบับ","de":"เหนือข้าวสวยร่วนซุย ผักนามูลห้าสีนั่งล้อมเป็นวงกลม ในปลายนิ้วที่จัดวางให้สีสันเข้ากันนั้น ไหลอยู่ด้วยสุนทรียะโบราณแห่งความใส่ใจอันประณีต รสชาติแห่งความกลมกลืนที่จะสมบูรณ์ได้ก็ต่อเมื่อคลุกเคล้าเข้าด้วยกันเท่านั้น"},"ICON-2817":{"nm":"ข้าวผัดกุ้ง","de":"กุ้งตัวอวบอ้วนโดดเด่นเป็นสีชมพูท่ามกลางเมล็ดข้าว ผัดทะเลกำมือหนึ่งลงไป มื้ออาหารธรรมดาก็แปลงร่างราวกับงานเลี้ยง ความหวานที่แผ่กระจายในวินาทีที่กัดเคี้ยวกรุบเป็นสิ่งที่น่ายินดีเสมอ"},"ICON-2818":{"nm":"ข้าวหน้าหมูผัดเผ็ด","de":"หมูที่ซึมซับเครื่องปรุงรสเผ็ดจนเข้าเนื้อพบกับข้าวที่กำลังส่งไอร้อน จานที่มักจะถูกกินจนเกลี้ยงก่อนใครในเวลาพักเที่ยง ความปลอบโยนของมื้ออาหารที่ตบเบาๆ ปลอบใจวันอันยุ่งเหยิง"},"ICON-2819":{"nm":"ข้าวหน้าทูน่ามาโย","de":"ปลากระป๋องหนึ่งกระป๋อง มายองเนสหนึ่งเส้น และข้าวอุ่นๆ หนึ่งถ้วย วัตถุดิบเรียบง่ายแต่ความอบอุ่นใจนั้นเหลือเฟือ รสชาติของค่ำคืนนั้นที่แอบคลุกกินที่โต๊ะห้องเรียนหลังเลิกติวดึก"},"ICON-2820":{"nm":"ข้าวราดแกงกะหรี่","de":"สีทองข้นเข้มเต็มจานไปทั้งใบ ความตั้งใจของการคนอย่างนานจนมันฝรั่งและแครอทนุ่มยวบ ชวนให้นึกถึงความอบอุ่นของครอบครัวในค่ำคืนนั้นที่ทุกคนมองลงไปในหม้อเดียวกัน"},"ICON-2821":{"nm":"บิบิมบับสาหร่ายทะเล","de":"เส้นสาหร่ายกลิ่นทะเลพบกับโคชูจังแล้วถูกคลุกเคล้าไปมา เมื่อสัมผัสลื่นเปรี้ยวจัดโอบล้อมเมล็ดข้าวไว้ ทะเลที่นักดำน้ำหญิงกลั้นหายใจงมขึ้นมาก็ปรากฏขึ้นเต็มถ้วยเดียว"},"ICON-2822":{"nm":"ปลาแมคเคอเรลย่าง","de":"แผ่นหลังสีเงินค่อยๆ สุกเป็นสีทองบนตะแกรงย่าง มือที่แกะก้างออกแล้ววางเนื้อปลาบนข้าวให้ ในเนื้อปลาหลังสีน้ำเงินชิ้นหนึ่งซึมซับความรักอันเงียบงันที่เลี้ยงดูมาเช่นนั้น"},"ICON-2823":{"nm":"แพนเค้กมันฝรั่ง","de":"ในวันฝนตก คือสิ่งที่ครัวหมู่บ้านภูเขาแคว้นคังวอนโดขูดแล้วทอดขึ้นมา ขอบที่เหนียวนุ่มกับปลายที่กรอบอยู่เคียงข้างกันในแผ่นเดียว แป้งที่เข้ากันได้ดีที่สุดกับเสียงฝนที่เคาะกระจกหน้าต่าง"},"ICON-2824":{"nm":"แพนเค้กกิมจิ","de":"วินาทีที่กิมจิเปรี้ยวสัมผัสกระทะที่ทาน้ำมันไว้ บ้านทั้งหลังก็เต็มไปด้วยเสียงจี่ฉ่าๆ วงกลมสีทองที่เรียกหาเหล้ามักกอลลีสักถ้วยโดยไม่ต้องบอกกล่าว เมนูประจำที่เข้าคู่กับเสียงฝนใต้ชายคาเสมอ"},"ICON-2825":{"nm":"แพนเค้กต้นหอม","de":"วางต้นหอมเรียงเป็นแถวแล้วเทแป้งราดลงไป ทอดอย่างช้าๆ แผ่นหนึ่งที่แกว่งไปมาระหว่างความกรอบและความนุ่ม เหมือนภาพบรรยากาศอบอุ่นของแผงขายในวันตลาดนัดที่มีไอน้ำลอยฟุ้งขึ้นมาไม่ผิดเพี้ยน"},"ICON-2826":{"nm":"แพนเค้กซูกินี","de":"ซูกินีหั่นบางชุบแป้งแล้วทอดจนเป็นสีทอง วงกลมสีเขียวอ่อนที่เฝ้าดูมุมหนึ่งของโต๊ะพิธีเซ่นไหว้บรรพบุรุษอย่างเป็นระเบียบ พิธีรีตองอันประณีตที่จะสำเร็จได้ก็ต่อเมื่อลงมือทำด้วยความพิถีพิถันเท่านั้น"},"ICON-2827":{"nm":"ปลาหมึกผัดเผ็ด","de":"หนวดปลาหมึกที่คลุกเครื่องปรุงสีแดงเป็นมันวาวระยิบระยับ แม้หน้าผากจะมีเหงื่อผุดเป็นเม็ดเล็กๆ จากความเผ็ด ตะเกียบก็ยังหยุดไม่ได้ จานเดียวที่หลอมรวมเหงื่อและความเพลิดเพลินเข้าไว้ด้วยกัน"},"ICON-2828":{"nm":"ต๊อกบกกี","de":"แผ่นแป้งข้าวเหนียวและโอเด้งจมลึกอยู่ในน้ำซุปโคชูจังสีแดงที่เคี่ยวข้น บรรจุเอาบ่ายทั้งบ่ายของร้านขนมทานเล่นที่รวมเหรียญแบ่งกันกินสองคนไว้ทั้งหมด รสชาติแห่งความทรงจำที่แค่ได้ยินชื่อน้ำลายก็สอ"},"ICON-2829":{"nm":"ซุปโอเด้ง","de":"แผงลอยที่โอเด้งแกว่งไกวอยู่ในน้ำซุป ไอน้ำทำให้กระจกขุ่นเป็นสีขาวนวล จับไม้เสียบไว้หนึ่งไม้ ตักน้ำซุปใส่แก้วกระดาษแล้วซดเข้าไป คืนฤดูหนาวที่หนาวเหน็บก็อุ่นขึ้นอีกมาก"},"ICON-2830":{"nm":"เต้าหู้กิมจิ","de":"ข้างเต้าหู้นุ่มนวล กิมจิผัดรสเผ็ดนั่งเคียงข้างกันอย่างสงบ ความเย็นกับความร้อน ความอ่อนโยนกับความเข้มข้น ผสมผสานกันอยู่ในจานเดียว คู่หูที่เฝ้าคืนวันของผู้ใหญ่มายาวนาน"},"ICON-2831":{"nm":"ไส้กรอกผัดผัก","de":"ไส้กรอกสีแดงกับผักผัดเข้ากันเป็นสีซอสมะเขือเทศจี่ฉ่าๆ ช่องที่ถูกกินหมดก่อนเพื่อนเมื่อเปิดฝากล่องข้าวในวันกีฬาสี สีสันของวันนั้นยังคงสดใสไม่จางแม้เวลาจะผ่านไปนานเท่าไร"},"ICON-2832":{"nm":"ลาเต้มันเทศ","de":"มันเทศบดละเอียดละลายนุ่มนวลลงในนมอุ่น ความหวานพื้นถิ่นที่เขียนเป็นภาษาเกาหลีบนป้ายเมนู ในวันที่ปลายนิ้วหนาวเหน็บ กำแก้วไว้ในสองมือ ความอบอุ่นก็จะค่อยๆ แผ่กระจายไปทั่วทั้งแก้ว"},"ICON-2833":{"nm":"มายองเนส","de":"ซอสที่ยังไปไม่ถึงครัวแห่งเกาะประกายระยิบ อีกไม่นานจะถูกวาดขึ้นเป็นไอคอนสีครีม (อยู่ระหว่างเตรียมการ)"}};